const prng_seed_lcg_mul: u64 = 6364136223846793005;
const prng_seed_lcg_inc: u64 = 1442695040888963407;
const prng_jump: [4]u64 = .{
    0x180ec6d33cfd0aba,
    0xd5a61266f0c9392c,
    0xa9582618e03fc9aa,
    0x39abdc4529b1661c,
};

const Prng = struct {
    const lane_count = 4;
    const Vec = @Vector(lane_count, u64);
    const Shift = @Vector(lane_count, u6);
    const use_vec4_kernel = zig_builtin.cpu.arch == .aarch64;

    state: [4][lane_count]u64,
    buffer: [lane_count]u64 = [_]u64{0} ** lane_count,
    buffer_index: usize = 0,

    pub fn initEntropy() Prng {
        var public_state: [4]u64 = undefined;
        while (true) {
            if (comptime zig_builtin.target.cpu.arch == .wasm32) {
                for (&public_state, 0..) |*item, idx| item.* = 0x9e3779b97f4a7c15 *% @as(u64, idx + 1);
            } else {
                for (&public_state) |*item| item.* = std.crypto.random.int(u64);
            }
            if (!allZero(public_state)) break;
        }
        var prng: Prng = undefined;
        prng.setPublicStateUnchecked(public_state);
        return prng;
    }

    fn allZero(words: [4]u64) bool {
        return words[0] == 0 and words[1] == 0 and words[2] == 0 and words[3] == 0;
    }

    fn publicState(self: *const Prng) [4]u64 {
        return .{
            self.state[0][0],
            self.state[1][0],
            self.state[2][0],
            self.state[3][0],
        };
    }

    fn seedFromInt(self: *Prng, seed: i64) void {
        var value: u64 = if (seed == 0)
            if (comptime zig_builtin.target.cpu.arch == .wasm32)
                0x6a09e667f3bcc909
            else
                @bitCast(std.time.microTimestamp())
        else
            @bitCast(seed);
        var public_state: [4]u64 = undefined;
        for (&public_state) |*item| {
            value = value *% prng_seed_lcg_mul +% prng_seed_lcg_inc;
            item.* = value;
        }
        self.setPublicStateUnchecked(public_state);
    }

    fn setPublicState(self: *Prng, words: [4]u64) KError!void {
        if (allZero(words)) return error.Type;
        self.setPublicStateUnchecked(words);
    }

    fn setPublicStateUnchecked(self: *Prng, words: [4]u64) void {
        self.state = undefined;
        inline for (0..4) |word_idx| self.state[word_idx][0] = words[word_idx];
        var jumped = words;
        var lane: usize = 1;
        while (lane < lane_count) : (lane += 1) {
            jumpState(&jumped);
            inline for (0..4) |word_idx| self.state[word_idx][lane] = jumped[word_idx];
        }
        self.buffer_index = 0;
    }

    fn random(self: *Prng) std.Random {
        return std.Random.init(self, fill);
    }

    fn nextWord(self: *Prng) u64 {
        if (self.buffer_index < lane_count) self.refill();
        self.buffer_index -= 1;
        return self.buffer[self.buffer_index];
    }

    fn nextFloat01(self: *Prng) f64 {
        const bits = (@as(u64, 1023) << 52) | (self.nextWord() & ((@as(u64, 1) << 52) - 1));
        const value: f64 = @bitCast(bits);
        return value - 1.0;
    }

    fn fill(self: *Prng, buf: []u8) void {
        var i: usize = 0;
        while (i + 8 <= buf.len) : (i += 8) {
            var chunk: [8]u8 = undefined;
            std.mem.writeInt(u64, &chunk, self.nextWord(), .little);
            @memcpy(buf[i .. i + 8], &chunk);
        }
        if (i != buf.len) {
            var word = self.nextWord();
            while (i < buf.len) : (i += 1) {
                buf[i] = @truncate(word);
                word >>= 8;
            }
        }
    }

    fn refill(self: *Prng) void {
        if (comptime use_vec4_kernel) {
            self.refillVec4();
        } else {
            self.refillScalar();
        }
        self.buffer_index = lane_count;
    }

    fn copyFreshWords(self: *Prng, out: []u64) void {
        var written: usize = 0;
        while (written < out.len) {
            self.refill();
            const chunk = @min(out.len - written, lane_count);
            @memcpy(out[written .. written + chunk], self.buffer[0..chunk]);
            written += chunk;
        }
    }

    fn refillScalar(self: *Prng) void {
        var out: [lane_count]u64 = undefined;
        var lane: usize = 0;
        while (lane < lane_count) : (lane += 1) {
            const result = nextStateWord(.{
                self.state[0][lane],
                self.state[1][lane],
                self.state[2][lane],
                self.state[3][lane],
            });
            self.state[0][lane] = result.state[0];
            self.state[1][lane] = result.state[1];
            self.state[2][lane] = result.state[2];
            self.state[3][lane] = result.state[3];
            out[lane] = result.word;
        }
        self.buffer = out;
    }

    fn refillVec4(self: *Prng) void {
        var s0: Vec = @bitCast(self.state[0]);
        var s1: Vec = @bitCast(self.state[1]);
        var s2: Vec = @bitCast(self.state[2]);
        var s3: Vec = @bitCast(self.state[3]);

        const out = rotlLeft(s0 +% s3, 23, 41) +% s0;
        const t = s1 << @as(Shift, @splat(17));

        s2 ^= s0;
        s3 ^= s1;
        s1 ^= s2;
        s0 ^= s3;
        s2 ^= t;
        s3 = rotlLeft(s3, 45, 19);

        self.state[0] = @bitCast(s0);
        self.state[1] = @bitCast(s1);
        self.state[2] = @bitCast(s2);
        self.state[3] = @bitCast(s3);
        self.buffer = @bitCast(out);
    }

    fn rotlLeft(values: Vec, comptime left_bits: u6, comptime right_bits: u6) Vec {
        const left: Shift = @splat(left_bits);
        const right: Shift = @splat(right_bits);
        return (values << left) | (values >> right);
    }

    fn nextStateWord(state: [4]u64) struct { word: u64, state: [4]u64 } {
        var next = state;
        const word = std.math.rotl(u64, next[0] +% next[3], 23) +% next[0];
        const t = next[1] << 17;
        next[2] ^= next[0];
        next[3] ^= next[1];
        next[1] ^= next[2];
        next[0] ^= next[3];
        next[2] ^= t;
        next[3] = std.math.rotl(u64, next[3], 45);
        return .{ .word = word, .state = next };
    }

    fn jumpState(state: *[4]u64) void {
        var acc = [_]u64{0} ** 4;
        for (prng_jump) |jump_word| {
            var bitset = jump_word;
            var bit: usize = 0;
            while (bit < 64) : (bit += 1) {
                if ((bitset & 1) != 0) {
                    inline for (0..4) |idx| acc[idx] ^= state[idx];
                }
                const result = nextStateWord(state.*);
                state.* = result.state;
                bitset >>= 1;
            }
        }
        state.* = acc;
    }
};

fn denseRegionKindLabel(kind: DenseRegionKind) []const u8 {
    return switch (kind) {
        .numeric_dyad => "numeric_dyad",
        .compare_mask => "compare_mask",
        .reduce => "reduce",
        .scan => "scan",
        .matmul => "matmul",
        .transpose => "transpose",
        .dense_autodiff => "dense_autodiff",
    };
}

fn denseExecBackendLabel(backend: DenseExecBackend) []const u8 {
    return switch (backend) {
        .host => "host",
        .mlx => acceleratorBackendLabel(),
    };
}

fn densePlanReasonLabel(reason: DensePlanReason) []const u8 {
    return switch (reason) {
        .no_backend_support => "no_backend_support",
        .already_backend_resident => "already_backend_resident",
        .unmaterialized_range_host => "unmaterialized_range_host",
        .packed_mask_host => "packed_mask_host",
        .host_fast_kernel => "host_fast_kernel",
        .small_problem => "small_problem",
        .large_problem => "large_problem",
        .compare_host_default => "compare_host_default",
        .matmul_requires_backend => "matmul_requires_backend",
    };
}

pub const ValueTag = enum(u8) {
    int,
    float,
    float32,
    bool,
    builtin,
    closure,
    array,
};

pub const DebugArraySubkind = Value.ArraySubkind;

pub const Value = struct {
    raw: u64,

    const payload_bits = 48;
    const payload_mask: u64 = (@as(u64, 1) << payload_bits) - 1;
    const tag_shift = payload_bits;
    pub const tag_mask: u64 = 0xffff << tag_shift;
    pub const array_payload_mask: u64 = tag_mask;
    const int_tag: u64 = 0xfff1 << tag_shift;
    const bool_tag: u64 = 0xfff2 << tag_shift;
    const builtin_tag: u64 = 0xfff3 << tag_shift;
    const closure_tag: u64 = 0xfff4 << tag_shift;
    const float32_tag: u64 = 0xfff5 << tag_shift;
    const boxed_int_tag: u64 = 0xfff6 << tag_shift;
    const array_tag: u64 = 0xfff7 << tag_shift;
    const canonical_nan_raw: u64 = 0x7ff8_0000_0000_0000;

    const ArraySubkind = enum(u8) {
        numeric_array,
        host_dense_array,
        host_boxed_array,
        host_string,
        host_symbol,
        host_string_list,
        host_symbol_list,
        host_string_view,
        host_relation,
        host_keyed_store,
        host_table_scalar,
        backend_array,
    };

    pub fn int(value: i64) KError!Value {
        if (!fitsInlineInt(value)) return error.Unsupported;
        return .{
            .raw = int_tag | (@as(u64, @bitCast(value)) & payload_mask),
        };
    }

    pub fn float(value: f64) Value {
        const raw: u64 = @bitCast(value);
        return .{ .raw = if (isReservedTag(raw)) canonical_nan_raw else raw };
    }

    pub fn float32(value: f32) Value {
        return .{
            .raw = float32_tag | @as(u64, @as(u32, @bitCast(value))),
        };
    }

    pub fn fromBool(value: bool) Value {
        return .{
            .raw = bool_tag | @as(u64, @intFromBool(value)),
        };
    }

    pub fn builtin(id: BuiltinId) Value {
        return .{
            .raw = builtin_tag | @as(u64, @intFromEnum(id)),
        };
    }

    pub fn closure(ptr: *const Closure) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & tag_mask) == 0);
        return .{ .raw = raw | closure_tag };
    }

    pub fn array(ptr: anytype) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & tag_mask) == 0);
        return .{ .raw = raw | array_tag };
    }

    fn boxedInt(ptr: *const BoxedInt) Value {
        const raw = @intFromPtr(ptr);
        std.debug.assert((raw & tag_mask) == 0);
        return .{ .raw = raw | boxed_int_tag };
    }

    pub fn tag(self: Value) ValueTag {
        return switch (self.raw & tag_mask) {
            int_tag => .int,
            bool_tag => .bool,
            builtin_tag => .builtin,
            closure_tag => .closure,
            float32_tag => .float32,
            boxed_int_tag => .int,
            array_tag => .array,
            else => .float,
        };
    }

    pub fn asInt(self: Value) i64 {
        return switch (self.raw & tag_mask) {
            int_tag => signExtendInlineInt(self.raw & payload_mask),
            boxed_int_tag => self.asBoxedInt().value,
            else => unreachable,
        };
    }

    pub fn asFloat(self: Value) f64 {
        return switch (self.raw & tag_mask) {
            float32_tag => @floatCast(self.asFloat32()),
            else => blk: {
                std.debug.assert(self.tag() == .float);
                break :blk @as(f64, @bitCast(self.raw));
            },
        };
    }

    pub fn asFloat32(self: Value) f32 {
        std.debug.assert((self.raw & tag_mask) == float32_tag);
        return @bitCast(@as(u32, @intCast(self.raw & 0xffff_ffff)));
    }

    pub fn asBool(self: Value) bool {
        std.debug.assert((self.raw & tag_mask) == bool_tag);
        return (self.raw & 1) != 0;
    }

    pub fn asBuiltin(self: Value) BuiltinId {
        std.debug.assert((self.raw & tag_mask) == builtin_tag);
        return @enumFromInt(self.raw & payload_mask);
    }

    pub fn asClosure(self: Value) *const Closure {
        std.debug.assert(self.tag() == .closure);
        const ptr: *const Closure = @ptrFromInt(rawPtr(self.raw & ~tag_mask));
        return ptr;
    }

    pub fn arrayKind(self: Value) HeapKind {
        std.debug.assert(self.tag() == .array);
        return self.arrayHeader().kind;
    }

    pub fn activeArrayKind(self: Value) HeapKind {
        std.debug.assert(self.tag() == .array);
        return switch (self.arrayKind()) {
            .numeric_array => self.asNumericArray().activeKind(),
            else => self.arrayKind(),
        };
    }

    pub fn arrayOwner(self: Value) HeapOwner {
        std.debug.assert(self.tag() == .array);
        return switch (self.arrayKind()) {
            .numeric_array => self.asNumericArray().header.owner,
            .host_dense_array => if (self.asHostDenseArray().logical_handle) |handle| handle.header.owner else self.asHostDenseArray().header.owner,
            .host_string,
            .host_symbol,
            .host_string_list,
            .host_symbol_list,
            .host_string_view,
            .host_relation,
            .host_keyed_store,
            .host_table_scalar,
            .host_boxed_array,
            => self.arrayHeader().owner,
            .backend_array => if (self.asBackendArray().logical_handle) |handle| handle.header.owner else self.asBackendArray().header.owner,
            else => unreachable,
        };
    }

    pub fn asNumericArray(self: Value) *const NumericArray {
        std.debug.assert(self.arrayKind() == .numeric_array);
        const ptr: *const NumericArray = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostDenseArray(self: Value) *const HostDenseArray {
        std.debug.assert(self.arrayKind() == .host_dense_array);
        const ptr: *const HostDenseArray = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostBoxedArray(self: Value) *const HostBoxedArray {
        std.debug.assert(self.arrayKind() == .host_boxed_array);
        const ptr: *const HostBoxedArray = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asBackendArray(self: Value) *const BackendArray {
        return switch (self.arrayKind()) {
            .numeric_array => numericBackendAttachment(self.asNumericArray()) orelse unreachable,
            .backend_array => @ptrFromInt(rawPtr(self.arrayPtrRaw())),
            else => unreachable,
        };
    }

    pub fn asHostString(self: Value) *const HostText {
        std.debug.assert(self.arrayKind() == .host_string);
        const ptr: *const HostText = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostSymbol(self: Value) *const HostText {
        std.debug.assert(self.arrayKind() == .host_symbol);
        const ptr: *const HostText = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostStringList(self: Value) *const HostStringList {
        std.debug.assert(self.arrayKind() == .host_string_list or self.arrayKind() == .host_symbol_list);
        const ptr: *const HostStringList = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostStringView(self: Value) *const HostStringView {
        std.debug.assert(self.arrayKind() == .host_string_view);
        const ptr: *const HostStringView = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostRelation(self: Value) *const HostRelation {
        std.debug.assert(self.arrayKind() == .host_relation);
        const ptr: *const HostRelation = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    pub fn asHostKeyedStore(self: Value) *const HostKeyedStore {
        std.debug.assert(self.arrayKind() == .host_keyed_store);
        const ptr: *const HostKeyedStore = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    fn asBoxedInt(self: Value) *const BoxedInt {
        std.debug.assert((self.raw & tag_mask) == boxed_int_tag);
        const ptr: *const BoxedInt = @ptrFromInt(rawPtr(self.raw & ~tag_mask));
        return ptr;
    }

    fn arraySubkind(self: Value) ArraySubkind {
        std.debug.assert(self.tag() == .array);
        return switch (self.arrayKind()) {
            .numeric_array => .numeric_array,
            .host_dense_array => .host_dense_array,
            .host_boxed_array => .host_boxed_array,
            .host_string => .host_string,
            .host_symbol => .host_symbol,
            .host_string_list => .host_string_list,
            .host_symbol_list => .host_symbol_list,
            .host_string_view => .host_string_view,
            .host_relation => .host_relation,
            .host_keyed_store => .host_keyed_store,
            .host_table_scalar => .host_table_scalar,
            .backend_array => .backend_array,
            else => unreachable,
        };
    }

    fn arrayPtrRaw(self: Value) u64 {
        std.debug.assert(self.tag() == .array);
        return self.raw & payload_mask;
    }

    fn arrayHeader(self: Value) *const HeapHeader {
        std.debug.assert(self.tag() == .array);
        const ptr: *const HeapHeader = @ptrFromInt(rawPtr(self.arrayPtrRaw()));
        return ptr;
    }

    fn fitsInlineInt(value: i64) bool {
        const min_inline = -(@as(i64, 1) << (payload_bits - 1));
        const max_inline = (@as(i64, 1) << (payload_bits - 1)) - 1;
        return value >= min_inline and value <= max_inline;
    }

    fn isReservedTag(raw: u64) bool {
        return switch (raw & tag_mask) {
            int_tag,
            bool_tag,
            builtin_tag,
            closure_tag,
            float32_tag,
            boxed_int_tag,
            array_tag,
            => true,
            else => false,
        };
    }

    fn signExtendInlineInt(payload: u64) i64 {
        const shift = 64 - payload_bits;
        return @as(i64, @bitCast(payload << shift)) >> shift;
    }
};

const ClosureKind = enum(u8) {
    plain,
    projection,
    inner_product,
    composition,
    each,
    fold,
    scan,
    each_right,
    each_left,
    each_prior,
    grad,
    valuegrad,

    fn fromDerived(kind: DerivedVerbKind) ClosureKind {
        return switch (kind) {
            .each => .each,
            .fold => .fold,
            .scan => .scan,
            .each_right => .each_right,
            .each_left => .each_left,
            .each_prior => .each_prior,
            .grad => .grad,
            .valuegrad => .valuegrad,
        };
    }

    fn derivedKind(self: ClosureKind) ?DerivedVerbKind {
        return switch (self) {
            .each => .each,
            .fold => .fold,
            .scan => .scan,
            .each_right => .each_right,
            .each_left => .each_left,
            .each_prior => .each_prior,
            .grad => .grad,
            .valuegrad => .valuegrad,
            .plain, .projection, .inner_product, .composition => null,
        };
    }
};

pub const Closure = struct {
    header: HeapHeader align(8),
    kind: ClosureKind = .plain,
    code: *const Code,
    captures: []const Value,
};

const HeapOwner = enum(u8) {
    managed,
    frozen,
    scratch,
};

const HeapKind = enum(u8) {
    boxed_int,
    closure,
    numeric_array,
    host_dense_array,
    host_boxed_array,
    host_string,
    host_symbol,
    host_string_list,
    host_symbol_list,
    host_string_view,
    host_relation,
    host_keyed_store,
    host_table_scalar,
    backend_array,
};

const HeapHeader = struct {
    kind: HeapKind,
    owner: HeapOwner,
    ref_count: u32 = 0,

    fn init(kind: HeapKind, owner: HeapOwner) HeapHeader {
        return .{
            .kind = kind,
            .owner = owner,
            .ref_count = if (owner == .managed) 1 else 0,
        };
    }
};

const BoxedInt = struct {
    header: HeapHeader align(8),
    value: i64,
};

comptime {
    if (@sizeOf(Value) != 8) @compileError("Value must remain an 8-byte runtime word.");
    if (@alignOf(Closure) < 8) @compileError("Closure must remain at least 8-byte aligned.");
    if (@alignOf(BoxedInt) < 8) @compileError("BoxedInt must remain at least 8-byte aligned.");
}

const HostText = struct {
    header: HeapHeader align(8),
    len: usize,

    pub fn slice(self: *const HostText) []const u8 {
        return hostTextBytes(self);
    }
};

const HostTextSpan = struct {
    start: usize,
    len: usize,
};

const HostStringPiece = union(enum) {
    owned: *HostText,
    view: HostTextSpan,
};

const HostStringListStorage = union(enum) {
    eager: []const HostStringPiece,
    split_scalar: struct {
        sep: u8,
    },
};

const HostStringListDisplay = enum(u8) {
    list,
    char_rows,
    split_list,
};

const HostStringList = struct {
    header: HeapHeader align(8),
    len: usize,
    bytes_len: usize,
    base: ?*HostText,
    storage: HostStringListStorage,
    display: HostStringListDisplay = .list,
};

const HostStringView = struct {
    header: HeapHeader align(8),
    base: *HostText,
    span: HostTextSpan,
};

const HostRelationParam = struct {
    name: []u8,
    value: Value,
};

const HostRelationOrigin = union(enum) {
    file: struct {
        source_kind: duckdb_runtime.SourceKind,
        path: []u8,
    },
    sql: struct {
        text: []u8,
        params: []HostRelationParam,
    },
};

const HostRelation = struct {
    header: HeapHeader align(8),
    origin: HostRelationOrigin,
    cached_row_count_known: bool = false,
    cached_row_count: usize = 0,
};

const HostTableColumnKind = enum(u8) {
    boolean,
    int,
    float,
    string,
    date,
    time,
    time_ns,
    time_tz,
    timestamp,
    timestamp_s,
    timestamp_ms,
    timestamp_ns,
    timestamp_tz,
};

const HostTableColumn = struct {
    name: Value,
    data: Value,
    validity: ?Value = null,
    kind: HostTableColumnKind,
};

const TableColumnBuilder = struct {
    name: Value,
    source_type: duckdb_runtime.TypeId,
    kind: HostTableColumnKind,
    row_count: usize = 0,
    bool_values: std.ArrayList(bool) = .empty,
    int_values: std.ArrayList(i64) = .empty,
    float32_values: std.ArrayList(f32) = .empty,
    float_values: std.ArrayList(f64) = .empty,
    string_values: std.ArrayList([]u8) = .empty,
    validity: std.ArrayList(bool) = .empty,
    saw_null: bool = false,
};

const DirectTableColumnStorage = union(enum) {
    boolean: HostBitAlloc,
    int8: HostDenseAlloc(i8),
    int16: HostDenseAlloc(i16),
    int32: HostDenseAlloc(i32),
    int64: HostDenseAlloc(i64),
    float32: HostFloat32Result,
    float64: HostFloatResult,
};

const DirectTableColumnBuilder = struct {
    name: Value,
    source_type: duckdb_runtime.TypeId,
    kind: HostTableColumnKind,
    storage: DirectTableColumnStorage,
    data: ?Value,
    validity_storage: ?HostBitAlloc = null,
    validity: ?Value = null,
    total_rows: usize,
    row_count: usize = 0,
};

const HostKeyedLayout = enum(u8) {
    dict,
    table,
};

const HostKeyedColumnMetadata = struct {
    kind: HostTableColumnKind,
    validity: ?Value = null,
};

const HostKeyedStore = struct {
    header: HeapHeader align(8),
    layout: HostKeyedLayout = .dict,
    row_count: usize = 0,
    path: []const u8,
    owns_path: bool = false,
    names: Value,
    values: Value,
    column_metadata: ?[]HostKeyedColumnMetadata = null,
    lookup: std.StringHashMapUnmanaged(usize) = .empty,
};

const HostTableScalar = struct {
    header: HeapHeader align(8),
    kind: HostTableColumnKind,
    value: Value,
    is_null: bool,
};

fn valueAsHostTableScalar(value: Value) *const HostTableScalar {
    std.debug.assert(value.arrayKind() == .host_table_scalar);
    const ptr: *const HostTableScalar = @ptrFromInt(rawPtr(value.raw & ~Value.array_payload_mask));
    return ptr;
}

fn hostTableScalar(value: Value) ?*const HostTableScalar {
    if (value.tag() != .array or value.arrayKind() != .host_table_scalar) return null;
    return valueAsHostTableScalar(value);
}

const managed_host_text_intern_limit = 32;

fn hostTextAllocLen(byte_len: usize) usize {
    return @sizeOf(HostText) + byte_len;
}

fn hostTextAllocSlice(allocator: std.mem.Allocator, byte_len: usize) ![]align(@alignOf(HostText)) u8 {
    return try allocator.alignedAlloc(u8, .of(HostText), hostTextAllocLen(byte_len));
}

fn hostTextFromAlloc(buf: []align(@alignOf(HostText)) u8) *HostText {
    std.debug.assert(buf.len >= @sizeOf(HostText));
    return @ptrCast(buf.ptr);
}

fn hostTextBytesFromAlloc(buf: []align(@alignOf(HostText)) u8, byte_len: usize) []u8 {
    return buf[@sizeOf(HostText) .. @sizeOf(HostText) + byte_len];
}

fn hostTextBytes(text: *const HostText) []const u8 {
    const raw: [*]align(@alignOf(HostText)) const u8 = @ptrCast(text);
    return raw[@sizeOf(HostText) .. @sizeOf(HostText) + text.len];
}

fn freeHostTextAlloc(allocator: std.mem.Allocator, text: *HostText) void {
    const raw: [*]align(@alignOf(HostText)) u8 = @ptrCast(text);
    allocator.free(raw[0..hostTextAllocLen(text.len)]);
}

fn hostTextSpanBytes(base: *const HostText, span: HostTextSpan) []const u8 {
    return hostTextBytes(base)[span.start .. span.start + span.len];
}

fn hostStringListItemsOffset() usize {
    return std.mem.alignForward(usize, @sizeOf(HostStringList), @alignOf(HostStringPiece));
}

fn hostStringListAllocLen(item_len: usize) usize {
    return hostStringListItemsOffset() + item_len * @sizeOf(HostStringPiece);
}

fn hostStringListAllocSlice(allocator: std.mem.Allocator, item_len: usize) ![]align(@alignOf(HostStringList)) u8 {
    return try allocator.alignedAlloc(u8, .of(HostStringList), hostStringListAllocLen(item_len));
}

fn hostStringListFromAlloc(buf: []align(@alignOf(HostStringList)) u8) *HostStringList {
    std.debug.assert(buf.len >= @sizeOf(HostStringList));
    return @ptrCast(buf.ptr);
}

fn hostStringListItemsFromAlloc(buf: []align(@alignOf(HostStringList)) u8, item_len: usize) []HostStringPiece {
    const start = hostStringListItemsOffset();
    const bytes = buf[start .. start + item_len * @sizeOf(HostStringPiece)];
    const ptr: [*]HostStringPiece = @ptrCast(@alignCast(bytes.ptr));
    return ptr[0..item_len];
}

fn freeHostStringListAlloc(allocator: std.mem.Allocator, list: *HostStringList) void {
    const raw: [*]align(@alignOf(HostStringList)) u8 = @ptrCast(list);
    allocator.free(raw[0..hostStringListAllocLen(list.len)]);
}

fn hostStringPieceBytes(base: ?*const HostText, piece: HostStringPiece) []const u8 {
    return switch (piece) {
        .owned => |text| hostTextBytes(text),
        .view => |view| hostTextSpanBytes(base orelse unreachable, view),
    };
}

fn hostStringListItemBytes(list: *const HostStringList, idx: usize) KError![]const u8 {
    if (idx >= list.len) return error.Type;
    return switch (list.storage) {
        .eager => |items| hostStringPieceBytes(list.base, items[idx]),
        .split_scalar => |lazy| blk: {
            const base = list.base orelse return error.Internal;
            const src = hostTextBytes(base);
            var piece_idx: usize = 0;
            var start: usize = 0;
            while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                if (piece_idx == idx) break :blk src[start..sep_idx];
                piece_idx += 1;
                start = sep_idx + 1;
            }
            if (piece_idx != idx) return error.Type;
            break :blk src[start..];
        },
    };
}

fn hostStringViewBytes(view: *const HostStringView) []const u8 {
    return hostTextSpanBytes(view.base, view.span);
}

const HostStringSource = struct {
    base: *HostText,
    span: HostTextSpan,
    is_vector: bool,

    fn bytes(self: HostStringSource) []const u8 {
        return hostTextSpanBytes(self.base, self.span);
    }
};

const HostStringAlloc = struct {
    value: Value,
    bytes: []u8,
};

fn stringSourceInfo(value: Value) ?HostStringSource {
    if (value.tag() != .array) return null;
    return switch (value.arrayKind()) {
        .host_string => {
            const text = value.asHostString();
            return .{
                .base = @constCast(text),
                .span = .{ .start = 0, .len = text.len },
                .is_vector = text.len != 1,
            };
        },
        .host_string_view => {
            const view = value.asHostStringView();
            return .{
                .base = view.base,
                .span = view.span,
                .is_vector = view.span.len != 1,
            };
        },
        else => null,
    };
}

fn boxedSingletonCharSourceInfo(value: Value) ?HostStringSource {
    if (value.tag() != .array or value.arrayKind() != .host_boxed_array) return null;
    const array = value.asHostBoxedArray();
    if (array.len() != 1) return null;
    const item = array.items[0];
    if (item.tag() != .array) return null;
    return switch (item.arrayKind()) {
        .host_string => {
            const text = item.asHostString();
            if (text.len != 1) return null;
            return .{
                .base = @constCast(text),
                .span = .{ .start = 0, .len = text.len },
                .is_vector = true,
            };
        },
        .host_string_view => {
            const view = item.asHostStringView();
            if (view.span.len != 1) return null;
            return .{
                .base = view.base,
                .span = view.span,
                .is_vector = true,
            };
        },
        else => null,
    };
}

fn hostStringListIsContiguousBaseViews(list: *const HostStringList) bool {
    const base = list.base orelse return false;
    return switch (list.storage) {
        .eager => |items| blk: {
            var offset: usize = 0;
            for (items) |item| switch (item) {
                .view => |view| {
                    if (view.start != offset) break :blk false;
                    offset += view.len;
                },
                .owned => break :blk false,
            };
            break :blk offset == list.bytes_len and offset == base.len;
        },
        .split_scalar => false,
    };
}

const ScalarSplitStats = struct {
    parts: usize,
    bytes_len: usize,
};

fn isGrowlerLineSeparatorBytes(sep: []const u8) bool {
    return std.mem.eql(u8, sep, "\n") or std.mem.eql(u8, sep, "\\n");
}

fn countScalarSplits(src: []const u8, sep: u8) ScalarSplitStats {
    var parts: usize = 0;
    var bytes_len: usize = 0;
    var start: usize = 0;
    while (std.mem.indexOfScalarPos(u8, src, start, sep)) |idx| {
        parts += 1;
        bytes_len += idx - start;
        start = idx + 1;
    }
    if (src.len != start or (sep != '\n' and parts != 0)) {
        parts += 1;
        bytes_len += src.len - start;
    }
    return .{ .parts = parts, .bytes_len = bytes_len };
}

comptime {
    if (@alignOf(HostText) < 8) @compileError("HostText must remain at least 8-byte aligned for tagged Value pointers.");
    if (@alignOf(HostRelation) < 8) @compileError("HostRelation must remain at least 8-byte aligned for tagged Value pointers.");
}

const HostDenseElem = enum(u8) {
    int,
    float,
};

const RenderMode = enum(u8) {
    top,
    nested,
};

const HostIntStorageKind = enum(u8) {
    bit,
    int8,
    int16,
    int32,
    int64,
};

const HostDenseStorageKind = enum(u8) {
    bit,
    int8,
    int16,
    int32,
    int64,
    float32,
    float64,
};

const HostDenseStorage = union(HostDenseStorageKind) {
    bit: []u64,
    int8: []i8,
    int16: []i16,
    int32: []i32,
    int64: []i64,
    float32: []f32,
    float64: []f64,
};

const host_dense_flag_normalized: u8 = 1 << 0;
const host_dense_flag_asc: u8 = 1 << 1;
const host_dense_flag_dsc: u8 = 1 << 2;

const HostDenseFindCacheKind = enum(u8) {
    none,
    int,
    float,
};

const HostDenseFindCache = struct {
    kind: HostDenseFindCacheKind = .none,
    keys: ?[]u64 = null,
    slots: ?[]usize = null,
    mask: usize = 0,
    float_bounds_known: bool = false,
    float_bounds_min: f64 = 0.0,
    float_bounds_max: f64 = 0.0,
};

const HostDenseArray = struct {
    header: HeapHeader align(8),
    logical_handle: ?*NumericArray = null,
    logical_len: usize,
    flags: u8 = 0,
    int_range_known: bool = false,
    int_range_min: i64 = 0,
    int_range_max: i64 = 0,
    find_cache: ?*HostDenseFindCache = null,
    storage: HostDenseStorage,

    fn len(self: *const HostDenseArray) usize {
        return self.logical_len;
    }
};

const managed_host_dense_storage_kind_count = std.meta.fields(HostDenseStorageKind).len;

const ManagedHostDenseBufferEntry = struct {
    ptr: *anyopaque,
    len: usize,
};

const HostBoxedArray = struct {
    header: HeapHeader align(8),
    logical_len: usize,
    items: []Value,
    prototype: ?Value = null,

    fn len(self: *const HostBoxedArray) usize {
        return self.logical_len;
    }
};

const host_bit_word_bits = @bitSizeOf(u64);

fn hostDenseNumericMode(array: *const HostDenseArray) HostDenseElem {
    return switch (array.storage) {
        .bit, .int8, .int16, .int32, .int64 => .int,
        .float32, .float64 => .float,
    };
}

fn hostDenseStorageCapacityLen(array: *const HostDenseArray) usize {
    return switch (array.storage) {
        .bit => |words| words.len * host_bit_word_bits,
        .int8 => |items| items.len,
        .int16 => |items| items.len,
        .int32 => |items| items.len,
        .int64 => |items| items.len,
        .float32 => |items| items.len,
        .float64 => |items| items.len,
    };
}

fn hostDenseStorageKindForIntKind(kind: HostIntStorageKind) HostDenseStorageKind {
    return switch (kind) {
        .bit => .bit,
        .int8 => .int8,
        .int16 => .int16,
        .int32 => .int32,
        .int64 => .int64,
    };
}

fn hostDenseStorageElemBytes(kind: HostDenseStorageKind) usize {
    return switch (kind) {
        .bit => @sizeOf(u64),
        .int8 => @sizeOf(i8),
        .int16 => @sizeOf(i16),
        .int32 => @sizeOf(i32),
        .int64 => @sizeOf(i64),
        .float32 => @sizeOf(f32),
        .float64 => @sizeOf(f64),
    };
}

fn hostDenseStorageBytesForLen(kind: HostDenseStorageKind, len: usize) usize {
    return switch (kind) {
        .bit => bitWordCount(len) * @sizeOf(u64),
        else => len * hostDenseStorageElemBytes(kind),
    };
}

fn hostDenseCapacityLenForBytes(kind: HostDenseStorageKind, bytes: usize) usize {
    return switch (kind) {
        .bit => (bytes / @sizeOf(u64)) * host_bit_word_bits,
        else => bytes / hostDenseStorageElemBytes(kind),
    };
}

fn hostDenseGrowCapacityLen(kind: HostDenseStorageKind, current_capacity_len: usize, required_len: usize) usize {
    if (required_len == 0) return 0;
    const min_capacity_len = hostDenseCapacityLenForBytes(kind, 64);
    const grown_capacity_len = std.math.add(usize, current_capacity_len, current_capacity_len / 2) catch std.math.maxInt(usize);
    return @max(required_len, @max(min_capacity_len, grown_capacity_len));
}

test "host dense grow capacity uses allocator-natural one and a half growth" {
    try std.testing.expectEqual(@as(usize, 64), hostDenseGrowCapacityLen(.int8, 2, 3));
    try std.testing.expectEqual(@as(usize, 96), hostDenseGrowCapacityLen(.int8, 64, 65));
    try std.testing.expectEqual(@as(usize, 8), hostDenseGrowCapacityLen(.int64, 2, 3));
    try std.testing.expectEqual(@as(usize, 12), hostDenseGrowCapacityLen(.int64, 8, 9));
    try std.testing.expectEqual(@as(usize, 200), hostDenseGrowCapacityLen(.int64, 100, 200));
    try std.testing.expectEqual(@as(usize, 512), hostDenseGrowCapacityLen(.bit, 1, 2));
    try std.testing.expectEqual(@as(usize, 768), hostDenseGrowCapacityLen(.bit, 512, 513));
}

fn hostDenseLogicalBitWords(array: *const HostDenseArray, words: []const u64) []const u64 {
    const logical_words = bitWordCount(array.logical_len);
    std.debug.assert(logical_words <= words.len);
    return words[0..logical_words];
}

fn hostDenseLogicalItems(comptime T: type, array: *const HostDenseArray, items: []const T) []const T {
    std.debug.assert(array.logical_len <= items.len);
    return items[0..array.logical_len];
}

fn hostDenseMutableLogicalItems(comptime T: type, array: *const HostDenseArray, items: []T) []T {
    std.debug.assert(array.logical_len <= items.len);
    return items[0..array.logical_len];
}

pub fn debugHostDenseFlags(value: Value) u8 {
    std.debug.assert(value.tag() == .array and value.activeArrayKind() == .host_dense_array);
    return hostDenseIfPresent(value).?.flags;
}

pub fn debugHostDenseAddress(value: Value) usize {
    std.debug.assert(value.tag() == .array and value.activeArrayKind() == .host_dense_array);
    return @intFromPtr(hostDenseIfPresent(value).?);
}

pub const DebugHostStorageTag = enum {
    bit,
    int8,
    int16,
    int32,
    int64,
    float32,
    float64,
};

pub fn debugActiveHostStorageTag(value: Value) ?DebugHostStorageTag {
    if (value.tag() != .array or value.activeArrayKind() != .host_dense_array) return null;
    return @enumFromInt(@intFromEnum(std.meta.activeTag(hostDenseIfPresent(value).?.storage)));
}

pub fn debugHostStorageTagIfPresent(value: Value) ?DebugHostStorageTag {
    const host = hostDenseIfPresent(value) orelse return null;
    return @enumFromInt(@intFromEnum(std.meta.activeTag(host.storage)));
}

pub fn debugStringBytes(value: Value) ?[]const u8 {
    if (value.tag() != .array) return null;
    return switch (value.arrayKind()) {
        .host_string => hostTextBytes(value.asHostString()),
        .host_string_view => hostStringViewBytes(value.asHostStringView()),
        else => null,
    };
}

pub fn debugActiveHostLen(value: Value) ?usize {
