const global_call_arg_consume_bit: u8 = 0x80;

fn global_call_arg_kind_byte(kind: GlobalCallArgKind, consume: bool) u8 {
    return @intFromEnum(kind) | if (consume) global_call_arg_consume_bit else 0;
}

