fn staticSamplingProfileCodeInfo(id: u16) ?SamplingProfileCodeInfo {
    return switch (id) {
        sampling_profile_code_id_derived_each => .{
            .id = id,
            .kind = .derived_each,
            .source = "'",
        },
        sampling_profile_code_id_derived_fold => .{
            .id = id,
            .kind = .derived_fold,
            .source = "/",
        },
        sampling_profile_code_id_derived_scan => .{
            .id = id,
            .kind = .derived_scan,
            .source = "\\",
        },
        sampling_profile_code_id_derived_each_right => .{
            .id = id,
            .kind = .derived_each_right,
            .source = "/:",
        },
        sampling_profile_code_id_derived_each_left => .{
            .id = id,
            .kind = .derived_each_left,
            .source = "\\:",
        },
        sampling_profile_code_id_derived_each_prior => .{
            .id = id,
            .kind = .derived_each_prior,
            .source = "':",
        },
        sampling_profile_code_id_derived_grad => .{
            .id = id,
            .kind = .derived_grad,
            .source = "grad",
        },
        sampling_profile_code_id_derived_valuegrad => .{
            .id = id,
            .kind = .derived_valuegrad,
            .source = "valuegrad",
        },
        sampling_profile_code_id_projection => .{
            .id = id,
            .kind = .projection,
            .source = "projection",
        },
        sampling_profile_code_id_inner_product => .{
            .id = id,
            .kind = .inner_product,
            .source = "inner_product",
        },
        sampling_profile_code_id_composition => .{
            .id = id,
            .kind = .composition,
            .source = "composition",
        },
        else => null,
    };
}

