fn derivedCode(kind: DerivedVerbKind) *const Code {
    return switch (kind) {
        .each => &derived_each_code,
        .fold => &derived_fold_code,
        .scan => &derived_scan_code,
        .each_right => &derived_each_right_code,
        .each_left => &derived_each_left_code,
        .each_prior => &derived_each_prior_code,
        .grad => &derived_grad_code,
        .valuegrad => &derived_valuegrad_code,
    };
}

fn closureDerivedKind(closure: *const Closure) ?DerivedVerbKind {
    return closure.kind.derivedKind();
}

fn closureMayUseDerivedApply(closure: *const Closure) bool {
    return closure.kind != .plain;
}

fn closureIsProjection(closure: *const Closure) bool {
    return closure.kind == .projection;
}

fn closureIsInnerProduct(closure: *const Closure) bool {
    return closure.kind == .inner_product;
}

fn closureIsCompactPlainGlobal(closure: *const Closure) bool {
    return closure.captures.len == 0 and closure.kind == .plain;
}

fn codeForPlainClosure(closure: *const Closure, argc: usize) ?*const Code {
    if (!closureIsCompactPlainGlobal(closure)) return null;
    if (closure.code.arity != argc) return null;
    return closure.code;
}

fn codeCanRunWithArgLen(code: *const Code, argc: usize) bool {
    if (code.arity == argc) return true;
    return code.arity == 1 and argc == 0 and code.required_arity == 0;
}

fn codeRunArgs(code: *const Code, args: []const Value) []const Value {
    if (code.arity == 0 and args.len == 1) return &[_]Value{};
    return args;
}

fn codeAcceptsArgs(compact: *const Code, args: []const Value) bool {
    return compact.arity == args.len;
}

fn codeForPlainClosureArgs(closure: *const Closure, args: []const Value) ?*const Code {
    const compact = codeForPlainClosure(closure, args.len) orelse return null;
    if (!codeAcceptsArgs(compact, args)) return null;
    return compact;
}

fn codeForRunnablePlainClosureArgs(closure: *const Closure, args: []const Value) ?*const Code {
    if (!closureIsCompactPlainGlobal(closure)) return null;
    const compact = closure.code;
    if (codeCanRunWithArgLen(compact, args.len)) return compact;
    if (compact.arity == 0 and args.len == 1) return compact;
    return null;
}

fn codeForGlobalCellCall(cell: *const GlobalCell, argc: u8) ?*const Code {
    const compact = cell.code orelse return null;
    if (compact.arity != argc) return null;
    return compact;
}

fn codeForGlobalCellCallArgs(cell: *const GlobalCell, args: []const Value) ?*const Code {
    const compact = cell.code orelse return null;
    if (!codeAcceptsArgs(compact, args)) return null;
    return compact;
}

const ScratchCode = struct {
    instructions: CodeEmitter = .{},
    code: Code = .{
        .arity = 0,
        .frame_slot_count = 0,
        .bytes = &[_]u8{},
        .constants = &[_]Value{},
    },

    fn reset(self: *ScratchCode) void {
        self.instructions = .{};
        self.code = .{
            .arity = 0,
            .frame_slot_count = 0,
            .bytes = &[_]u8{},
            .constants = &[_]Value{},
        };
    }

    fn finalize(self: *ScratchCode, arity: u8, required_arity: u8, frame_slot_count: u8) KError!*Code {
        self.code = directCodeFromEmitter(
            arity,
            required_arity,
            frame_slot_count,
            &self.instructions,
            self.instructions.constantSlice(),
        ) orelse return error.Unsupported;
        return &self.code;
    }
};

fn duplicateCodeFromEmitter(allocator: std.mem.Allocator, arity: u8, required_arity: u8, frame_slot_count: u8, instructions: *const CodeEmitter) !*Code {
    const code = try allocator.create(Code);
    const constants = try allocator.dupe(Value, instructions.constantSlice());
    const direct = directCodeFromEmitter(arity, required_arity, frame_slot_count, instructions, constants) orelse return error.Unsupported;
    code.* = direct;
    code.bytes = try allocator.dupe(u8, direct.bytes);
    code.constants = constants;
    return code;
}

fn finishCodeEmitter(out: *CodeEmitter, mode: PostCompileMode) KError!void {
    out.applyPostCompile(mode);
    try out.appendReturn();
}

fn tryCompileTinyTopLevelInto(
    session: *Session,
    source: []const u8,
    code_allocator: std.mem.Allocator,
    compile_mode: CompileMode,
    instructions: *CodeEmitter,
) KError!bool {
    var cursor: usize = 0;
    const statement = nextTopLevelStatement(source, &cursor) orelse return false;
    if (nextTopLevelStatement(source, &cursor) != null) return false;

    var compiler = try Compiler.init(session, source, code_allocator, compile_mode);
    var scope = Scope{};
    defer scope.deinit(session.allocator);

    if (!(try compiler.tryCompileTinyExprSlice(instructions, &scope, statement))) return false;
    if (scope.arity != 0) return false;
    try finishCodeEmitter(instructions, .top_level);
    return true;
}

const GlobalValueClass = enum(u8) {
    uninitialized,
    scalar,
    builtin,
    closure,
    dense_int_vector,
    dense_float_vector,
    array,

    inline fn isArray(self: GlobalValueClass) bool {
        return switch (self) {
            .dense_int_vector, .dense_float_vector, .array => true,
            else => false,
        };
    }
};

const GlobalCell = struct {
    value: Value = Value.fromBool(false),
    initialized: bool = false,
    class: GlobalValueClass = .uninitialized,
    code: ?*const Code = null,
};

