    pub fn createHostDictValue(
        self: *Session,
        store_path: []const u8,
        keys: []const []const u8,
        values: []const Value,
    ) !Value {
        const values_value = try self.makeArrayFromValues(values);
        errdefer self.releaseValue(values_value);
        return try self.createHostDictValueFromSequenceValue(store_path, keys, values_value);
    }

    fn keyedStoreNamesValueCount(names: Value) usize {
        if (stringSourceInfo(names)) |source| return source.bytes().len;
        return derivedSequenceLen(names) orelse unreachable;
    }

    fn keyedStoreNamesValueBytesAt(self: *Session, names: Value, idx: usize) KError!?[]const u8 {
        if (stringSourceInfo(names)) |source| {
            const bytes = source.bytes();
            if (idx >= bytes.len) return null;
            return bytes[idx .. idx + 1];
        }
        if (names.tag() == .array and switch (names.arrayKind()) {
            .host_string_list, .host_symbol_list => true,
            else => false,
        }) {
            if (idx >= names.asHostStringList().len) return null;
            return try hostStringListItemBytes(names.asHostStringList(), idx);
        }
        const item = try self.derivedSequenceItemValue(names, idx);
        defer self.releaseValue(item);
        return keyedLookupNameBytes(item);
    }

    fn createKeyedStoreLookupFromNamesValueOptions(
        self: *Session,
        names: Value,
        comptime allow_duplicates: bool,
    ) !std.StringHashMapUnmanaged(usize) {
        var lookup: std.StringHashMapUnmanaged(usize) = .empty;
        errdefer lookup.deinit(self.allocator);
        const len = keyedStoreNamesValueCount(names);
        try lookup.ensureTotalCapacity(self.allocator, @intCast(len));
        for (0..len) |idx| {
            const key = (try self.keyedStoreNamesValueBytesAt(names, idx)) orelse continue;
            if (lookup.contains(key)) {
                if (!allow_duplicates) return error.Name;
                continue;
            }
            lookup.putAssumeCapacity(key, idx);
        }
        return lookup;
    }

    fn createKeyedStoreLookupFromNamesValue(self: *Session, names: Value) !std.StringHashMapUnmanaged(usize) {
        return try self.createKeyedStoreLookupFromNamesValueOptions(names, false);
    }

    fn createHostDictValueFromSequenceValue(
        self: *Session,
        store_path: []const u8,
        keys: []const []const u8,
        values_value: Value,
    ) !Value {
        const value_len = derivedSequenceLen(values_value) orelse return error.Type;
        if (keys.len != value_len) return error.Type;

        const names = try self.createManagedHostStringListFromSlices(keys);
        errdefer self.releaseValue(names);

        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const owned_path = try self.allocator.dupe(u8, store_path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(owned_path, true, names, values_value, null, .dict, 0, lookup);
    }

    fn createHostDictValueFromDenseTextKeys(
        self: *Session,
        store_path: []const u8,
        key_list: *const HostStringList,
        values_value: Value,
    ) !Value {
        const value_len = derivedSequenceLen(values_value) orelse return error.Type;
        if (key_list.len != value_len) return error.Type;

        const names = try self.retainEscapedValue(Value.array(@constCast(key_list)));
        errdefer self.releaseValue(names);

        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const owned_path = try self.allocator.dupe(u8, store_path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(owned_path, true, names, values_value, null, .dict, 0, lookup);
    }

    fn createHostDictValueFromCharStringKeys(
        self: *Session,
        store_path: []const u8,
        keys_value: Value,
        values_value: Value,
    ) !Value {
        const key_source = stringSourceInfo(keys_value) orelse return error.Type;
        const value_len = derivedSequenceLen(values_value) orelse return error.Type;
        if (key_source.bytes().len != value_len) return error.Type;

        const names = try self.retainEscapedValue(keys_value);
        errdefer self.releaseValue(names);

        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const values = try self.retainEscapedValue(values_value);
        errdefer self.releaseValue(values);

        const owned_path = try self.allocator.dupe(u8, store_path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(owned_path, true, names, values, null, .dict, 0, lookup);
    }

    fn createHostDictValueFromKeySequenceValue(
        self: *Session,
        store_path: []const u8,
        keys_value: Value,
        values_value: Value,
    ) !Value {
        const key_len = derivedSequenceLen(keys_value) orelse return error.Type;
        const value_len = derivedSequenceLen(values_value) orelse return error.Type;
        if (key_len != value_len) return error.Type;

        const names = try self.retainEscapedValue(keys_value);
        errdefer self.releaseValue(names);

        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const values = try self.retainEscapedValue(values_value);
        errdefer self.releaseValue(values);

        const owned_path = try self.allocator.dupe(u8, store_path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(owned_path, true, names, values, null, .dict, 0, lookup);
    }

    pub fn setGlobalHostDict(
        self: *Session,
        name: []const u8,
        store_path: []const u8,
        keys: []const []const u8,
        values: []const Value,
    ) !void {
        const value = try self.createHostDictValue(store_path, keys, values);
        defer self.releaseValue(value);
        try self.storeGlobalSlot(try self.internGlobalSlot(name), value);
    }

    fn numericShapeSnapshotFromDims(dims: []const i32) KError!?NumericShapeSnapshot {
        if (dims.len == 0) return null;
        if (dims.len > numeric_array_max_rank) return error.Unsupported;

        var snapshot = NumericShapeSnapshot{};
        snapshot.rank = @intCast(dims.len);
        for (dims, 0..) |dim, idx| {
            if (dim < 0) return error.Type;
            snapshot.shape[idx] = dim;
        }
        return snapshot;
    }

    fn elementCountFromDims(dims: []const i32) KError!usize {
        var count: usize = 1;
        for (dims) |dim| {
            if (dim < 0) return error.Type;
            count *= @as(usize, @intCast(dim));
        }
        return count;
    }

    fn createManagedGlobalFloatValue(self: *Session, data: []const f32, dims: []const i32) KError!Value {
        const expected_len = try elementCountFromDims(dims);
        if (expected_len != data.len) return error.Type;
        if (dims.len == 0) {
            if (data.len != 1) return error.Type;
            return try self.managedFloat(data[0]);
        }

        const value = try self.createManagedHostFloat32Array(data);
        return try applyNonVectorNumericShapeToValue(self, value, try numericShapeSnapshotFromDims(dims));
    }

    fn createManagedGlobalFloat64Value(self: *Session, data: []const f64, dims: []const i32) KError!Value {
        const expected_len = try elementCountFromDims(dims);
        if (expected_len != data.len) return error.Type;
        if (dims.len == 0) {
            if (data.len != 1) return error.Type;
            return try self.floatValue(data[0]);
        }

        const value = try self.createManagedHostFloatArray(data);
        return try applyNonVectorNumericShapeToValue(self, value, try numericShapeSnapshotFromDims(dims));
    }

    fn createManagedGlobalIntValue(self: *Session, data: []const i32, dims: []const i32) KError!Value {
        const expected_len = try elementCountFromDims(dims);
        if (expected_len != data.len) return error.Type;
        if (dims.len == 0) {
            if (data.len != 1) return error.Type;
            return try self.managedInt(data[0]);
        }

        const converted = try self.allocator.alloc(i64, data.len);
        defer self.allocator.free(converted);
        for (data, 0..) |item, idx| converted[idx] = item;

        const value = try self.createManagedHostIntArray(converted);
        return try applyNonVectorNumericShapeToValue(self, value, try numericShapeSnapshotFromDims(dims));
    }

    fn createManagedGlobalBoolValue(self: *Session, data: []const bool, dims: []const i32) KError!Value {
        const expected_len = try elementCountFromDims(dims);
        if (expected_len != data.len) return error.Type;
        if (dims.len == 0) {
            if (data.len != 1) return error.Type;
            return Value.fromBool(data[0]);
        }

        const value = try self.createManagedHostBitArray(data);
        return try applyNonVectorNumericShapeToValue(self, value, try numericShapeSnapshotFromDims(dims));
    }

    fn dropStackFrom(self: *Session, start: usize) void {
        while (self.stack_len > start) {
            self.stack_len -= 1;
            self.releaseCanonicalManagedNumericValue(self.stack[self.stack_len]);
        }
    }

    const CodeState = struct {
        locals: [max_code_frame_slots]Value = undefined,
        local_live: u16 = 0,
        stack: [max_code_stack_slots]Value = undefined,
        stack_len: usize = 0,
    };

    inline fn compactLocalBit(slot: usize) u16 {
        return @as(u16, 1) << @intCast(slot);
    }

    inline fn compactLocalPrefixMask(count: usize) u16 {
        if (count == 0) return 0;
        return @intCast((@as(u32, 1) << @intCast(count)) - 1);
    }

    fn compactReleaseState(self: *Session, state: *CodeState) void {
        while (state.stack_len > 0) {
            state.stack_len -= 1;
            self.releaseValue(state.stack[state.stack_len]);
        }
        var live = state.local_live;
        while (live != 0) {
            const slot: usize = @intCast(@ctz(live));
            const bit = compactLocalBit(slot);
            self.releaseValue(state.locals[slot]);
            state.locals[slot] = Value.fromBool(false);
            state.local_live &= ~bit;
            live &= live - 1;
        }
    }

    fn compactInitOwnedArgs(state: *CodeState, code: *const Code, args: []const Value) KError!void {
        if (!codeCanRunWithArgLen(code, args.len) or args.len > max_explicit_params or code.local_count > max_code_frame_slots) return error.Arity;
        state.local_live = 0;
        state.stack_len = 0;
        for (args, 0..) |arg, idx| {
            state.locals[idx] = arg;
        }
        state.local_live = compactLocalPrefixMask(args.len);
    }

    fn compactInitBorrowedArgs(self: *Session, state: *CodeState, code: *const Code, args: []const Value) KError!void {
        if (!codeCanRunWithArgLen(code, args.len) or args.len > max_explicit_params or code.local_count > max_code_frame_slots) return error.Arity;
        state.local_live = 0;
        state.stack_len = 0;
        var initialized: usize = 0;
        errdefer {
            while (initialized > 0) {
                initialized -= 1;
                self.releaseValue(state.locals[initialized]);
            }
            state.local_live = 0;
        }
        for (args, 0..) |arg, idx| {
            state.locals[idx] = self.retainValue(arg);
            initialized += 1;
        }
        state.local_live = compactLocalPrefixMask(args.len);
    }

    inline fn compactPush(state: *CodeState, value: Value) KError!void {
        if (state.stack_len >= state.stack.len) return error.Unsupported;
        state.stack[state.stack_len] = value;
        state.stack_len += 1;
    }

    inline fn compactPop(state: *CodeState) KError!Value {
        if (state.stack_len == 0) return error.Internal;
        state.stack_len -= 1;
        return state.stack[state.stack_len];
    }

    inline fn compactPeek(state: *const CodeState) KError!Value {
        if (state.stack_len == 0) return error.Internal;
        return state.stack[state.stack_len - 1];
    }

    inline fn compactReadLocal(self: *Session, state: *const CodeState, slot: u8) KError!Value {
        if (slot >= max_code_frame_slots) return error.Internal;
        if ((state.local_live & compactLocalBit(slot)) == 0) return Value.fromBool(false);
        return self.retainValue(state.locals[slot]);
    }

    inline fn compactBorrowLocal(state: *const CodeState, slot: u8) KError!Value {
        if (slot >= max_code_frame_slots) return error.Internal;
        if ((state.local_live & compactLocalBit(slot)) == 0) return Value.fromBool(false);
        return state.locals[slot];
    }

    inline fn compactTakeLocal(state: *CodeState, slot: u8) KError!Value {
        if (slot >= max_code_frame_slots) return error.Internal;
        const bit = compactLocalBit(slot);
        if ((state.local_live & bit) == 0) return Value.fromBool(false);
        const value = state.locals[slot];
        state.locals[slot] = Value.fromBool(false);
        state.local_live &= ~bit;
        return value;
    }

    fn compactStoreLocal(self: *Session, state: *CodeState, slot: u8, value: Value) KError!void {
        if (slot >= max_code_frame_slots) return error.Internal;
        const bit = compactLocalBit(slot);
        if ((state.local_live & bit) != 0) self.releaseValue(state.locals[slot]);
        state.locals[slot] = value;
        state.local_live |= bit;
    }

    inline fn compactReadByte(code: *const Code, ip: *usize) KError!u8 {
        if (ip.* >= code.bytes.len) return error.Internal;
        const value = code.bytes[ip.*];
        ip.* += 1;
        return value;
    }

    fn compactReadI64(code: *const Code, ip: *usize) KError!i64 {
        const end = ip.* + 8;
        if (end > code.bytes.len) return error.Internal;
        var raw: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) raw |= @as(u64, code.bytes[ip.* + idx]) << @intCast(idx * 8);
        ip.* = end;
        return @bitCast(raw);
    }

    fn compactEvalArgSourceOwned(self: *Session, code: *const Code, state: *CodeState, ip: *usize) KError!Value {
        const encoded = try compactReadByte(code, ip);
        const consume = (encoded & global_call_arg_consume_bit) != 0;
        const kind: GlobalCallArgKind = std.meta.intToEnum(GlobalCallArgKind, encoded & ~global_call_arg_consume_bit) catch return error.Internal;
        return switch (kind) {
            .local => blk: {
                const slot = try compactReadByte(code, ip);
                break :blk if (consume) try compactTakeLocal(state, slot) else try self.compactReadLocal(state, slot);
            },
            .const_int => try self.intValue(try compactReadI64(code, ip)),
            .const_false => Value.fromBool(false),
            .const_true => Value.fromBool(true),
            .local_add_const, .local_sub_const, .local_mul_const => blk: {
                const slot = try compactReadByte(code, ip);
                const rhs = try compactReadI64(code, ip);
                const left = if (consume) try compactTakeLocal(state, slot) else try self.compactReadLocal(state, slot);
                errdefer self.releaseValue(left);
                const op: BuiltinId = switch (kind) {
                    .local_add_const => .add,
                    .local_sub_const => .sub,
                    .local_mul_const => .mul,
                    else => unreachable,
                };
                const result = if (try self.compactTryInlineLocalConstDyad(left, op, rhs, false)) |direct|
                    direct
                else
                    try self.applyLocalConstOpValue(left, op, rhs);
                self.releaseValue(left);
                break :blk result;
            },
            .local_local_op => blk: {
                if (consume) return error.Internal;
                const op: BuiltinId = @enumFromInt(try compactReadByte(code, ip));
                const left_slot = try compactReadByte(code, ip);
                const right_slot = try compactReadByte(code, ip);
                break :blk try self.intValue(try checkedSelectorDyad(
                    op,
                    scalarIntLikeValue(try compactBorrowLocal(state, left_slot)) orelse return error.Type,
                    scalarIntLikeValue(try compactBorrowLocal(state, right_slot)) orelse return error.Type,
                ));
            },
            .local_local_const_op => blk: {
                if (consume) return error.Internal;
                const op: BuiltinId = @enumFromInt(try compactReadByte(code, ip));
                const left_slot = try compactReadByte(code, ip);
                const right_slot = try compactReadByte(code, ip);
                const const_op: BuiltinId = @enumFromInt(try compactReadByte(code, ip));
                const const_value = try compactReadI64(code, ip);
                const base = try checkedSelectorDyad(
                    op,
                    scalarIntLikeValue(try compactBorrowLocal(state, left_slot)) orelse return error.Type,
                    scalarIntLikeValue(try compactBorrowLocal(state, right_slot)) orelse return error.Type,
                );
                break :blk try self.intValue(try checkedSelectorDyad(const_op, base, const_value));
            },
        };
    }

    fn compactReadOwnedArgs(self: *Session, code: *const Code, state: *CodeState, ip: *usize, argc: u8, out: *[max_direct_apply_args]Value) KError![]const Value {
        if (argc == 0 or argc > max_direct_apply_args) return error.Internal;
        var loaded: usize = 0;
        errdefer self.releaseOwnedValues(out[0..loaded]);
        while (loaded < argc) : (loaded += 1) out[loaded] = try self.compactEvalArgSourceOwned(code, state, ip);
        return out[0..argc];
    }

    fn compactPopOwnedStackArgs(state: *CodeState, argc: u8, out: *[max_direct_apply_args]Value) KError![]const Value {
        if (argc > max_direct_apply_args or state.stack_len < argc) return error.Internal;
        const start = state.stack_len - argc;
        var idx: usize = 0;
        while (idx < argc) : (idx += 1) out[idx] = state.stack[start + idx];
        state.stack_len = start;
        return out[0..argc];
    }

    fn compactInitOwnedStackArgs(target: *CodeState, target_code: *const Code, state: *CodeState, argc: u8) KError!void {
        if (argc != target_code.arity or argc > max_direct_apply_args or target_code.local_count > max_code_frame_slots or state.stack_len < argc) return error.Arity;
        target.local_live = 0;
        target.stack_len = 0;
        const start = state.stack_len - argc;
        var idx: usize = 0;
        while (idx < argc) : (idx += 1) {
            target.locals[idx] = state.stack[start + idx];
        }
        target.local_live = compactLocalPrefixMask(argc);
        state.stack_len = start;
    }

    fn compactInitOwnedArgSources(self: *Session, target: *CodeState, target_code: *const Code, caller_code: *const Code, caller_state: *CodeState, ip: *usize, argc: u8) KError!void {
        if (argc != target_code.arity or argc == 0 or argc > max_direct_apply_args or target_code.local_count > max_code_frame_slots) return error.Arity;
        target.local_live = 0;
        target.stack_len = 0;
        var loaded: usize = 0;
        errdefer {
            while (loaded > 0) {
                loaded -= 1;
                self.releaseValue(target.locals[loaded]);
            }
            target.local_live = 0;
        }
        while (loaded < argc) : (loaded += 1) {
            target.locals[loaded] = try self.compactEvalArgSourceOwned(caller_code, caller_state, ip);
        }
        target.local_live = compactLocalPrefixMask(argc);
    }

    fn compactMoveState(dst: *CodeState, src: *CodeState) void {
        dst.local_live = src.local_live;
        dst.stack_len = 0;
        var live = src.local_live;
        while (live != 0) {
            const slot: usize = @intCast(@ctz(live));
            dst.locals[slot] = src.locals[slot];
            live &= live - 1;
        }
        src.local_live = 0;
        src.stack_len = 0;
    }

    fn runNestedOwnedClosureArgs(self: *Session, callee: Value, closure: *const Closure, callable_slot: u16, args: []const Value) KError!Value {
        _ = callee;
        _ = callable_slot;
        if (closure.code.arity != args.len) {
            self.releaseOwnedValues(args);
            return error.Arity;
        }
        self.releaseOwnedValues(args);
        return error.Unsupported;
    }

    fn applyBorrowedValueOwnedArgs(self: *Session, callee: Value, args: []const Value, callable_slot: u16) KError!Value {
        var args_owned = true;
        errdefer if (args_owned) self.releaseOwnedValues(args);

        if (try self.tryApplyAllAxisCallableProjection(callee, args)) |projection| {
            self.releaseOwnedValues(args);
            args_owned = false;
            return projection;
        }

        switch (callee.tag()) {
            .builtin => {
                const result = try self.applyBuiltinCall(callee.asBuiltin(), args);
                self.releaseOwnedValues(args);
                args_owned = false;
                return result;
            },
            .array => {
                const result = try self.applyArrayCall(callee, args);
                self.releaseOwnedValues(args);
                args_owned = false;
                return result;
            },
            .closure => {
                const closure = callee.asClosure();
                if (try self.tryProjectPlainClosureUnderApplication(callee, closure, args)) |projection| {
                    self.releaseOwnedValues(args);
                    args_owned = false;
                    return projection;
                }
                if (codeForRunnablePlainClosureArgs(closure, args)) |compact| {
                    const run_args = codeRunArgs(compact, args);
                    if (run_args.len != args.len) {
                        self.releaseOwnedValues(args);
                        args_owned = false;
                        return try self.runCodeBorrowed(compact, run_args);
                    }
                    args_owned = false;
                    return try self.runCodeOwned(compact, run_args);
                }
                if (try self.tryApplyOwnedClosureArgs(closure, args)) |result| {
                    self.releaseOwnedValues(args);
                    args_owned = false;
                    return result;
                }
                if (closure.code.arity != args.len) return error.Arity;
                args_owned = false;
                return try self.runNestedOwnedClosureArgs(callee, closure, callable_slot, args);
            },
            else => return error.Type,
        }
    }

    fn applyOwnedValue(self: *Session, callee: Value, args: []const Value, callable_slot: u16) KError!Value {
        var callee_owned = true;
        errdefer if (callee_owned) self.releaseValue(callee);

        const result = try self.applyBorrowedValueOwnedArgs(callee, args, callable_slot);
        self.releaseValue(callee);
        callee_owned = false;
        return result;
    }

    fn compactApplyGlobalCallOwned(self: *Session, slot: u8, args: []const Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_code_global_call_count += 1;
        const cell = try self.loadGlobalCell(slot);
        if (!argsContainAllAxisSelector(args)) {
            if (codeForGlobalCellCallArgs(cell, args)) |compact| {
                if (comptime enable_probe_instrumentation) self.debug_code_global_call_direct_count += 1;
                return try self.runCodeOwned(compact, args);
            }
        }
        if (comptime enable_probe_instrumentation) self.debug_code_global_call_fallback_count += 1;
        self.noteCodeGlobalCallFallback(cell, @intCast(args.len));
        return try self.applyBorrowedValueOwnedArgs(cell.value, args, slot);
    }

    fn compactApplyGlobalDerivedCallOwned(self: *Session, slot: u8, kind: DerivedVerbKind, args: []const Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_code_global_call_count += 1;
        self.noteGlobalCall(slot);
        const base = self.retainValue(try self.loadGlobalSlot(slot));
        defer self.releaseValue(base);
        defer self.releaseOwnedValues(args);
        const captures = [_]Value{base};
        return try self.applyDerivedKind(kind, &captures, args);
    }

    fn compactApplyCallOwned(self: *Session, callee: Value, args: []const Value) KError!Value {
        return try self.applyOwnedValue(callee, args, sampling_profile_no_callable_slot);
    }

    fn compactTryApplyGlobalCompactCallSources(self: *Session, slot: u8, caller_code: *const Code, caller_state: *CodeState, ip: *usize, argc: u8) KError!?Value {
        const cell = try self.loadGlobalCell(slot);
        const compact = codeForGlobalCellCall(cell, argc) orelse return null;
        if (comptime enable_probe_instrumentation) {
            self.debug_code_global_call_count += 1;
            self.debug_code_global_call_direct_count += 1;
        }
        var callee_state = CodeState{};
        try self.compactInitOwnedArgSources(&callee_state, compact, caller_code, caller_state, ip, argc);
        return try self.runCodeWithState(compact, &callee_state);
    }

    fn compactTryTailContinueGlobalCompactCallSources(self: *Session, slot: u8, next_code_out: **const Code, code: *const Code, state: *CodeState, ip: *usize, argc: u8) KError!bool {
        const cell = try self.loadGlobalCell(slot);
        const next_code = cell.code orelse return false;
        if (next_code.arity != argc) return false;
        var next_state = CodeState{};
        try self.compactInitOwnedArgSources(&next_state, next_code, code, state, ip, argc);
        if (comptime enable_probe_instrumentation) {
            self.debug_code_global_call_count += 1;
            self.debug_code_global_call_direct_count += 1;
            self.debug_code_tail_continue_count += 1;
        }
        self.compactReleaseState(state);
        compactMoveState(state, &next_state);
        next_code_out.* = next_code;
        return true;
    }

    fn compactApplyGlobalIndexOwned(self: *Session, slot: u8, selector: Value) KError!Value {
        const cell = try self.loadGlobalCell(slot);
        const callee = cell.value;
        if (cell.class.isArray()) {
            if (try self.compactTryFastGlobalDenseScalarIndex(cell, selector)) |result| {
                self.releaseValue(selector);
                return result;
            }
            if (try self.applyGlobalIndexArrayValue(callee, selector)) |result| {
                self.releaseValue(selector);
                return result;
            }
        }
        var args = [_]Value{selector};
        return try self.compactApplyGlobalCallOwned(slot, args[0..]);
    }

    fn compactApplyLocalIndexOwned(self: *Session, state: *CodeState, slot: u8, selector: Value) KError!Value {
        defer self.releaseValue(selector);
        const callee = try compactBorrowLocal(state, slot);
        if (callee.tag() == .array) {
            if (scalarIntLikeValue(selector)) |raw_index| return try self.applyArrayCall1Scalar(callee, raw_index);
            return try self.applyArrayCall1(callee, selector);
        }
        return try self.applyValue(callee, &[_]Value{selector});
    }

    fn compactTryFastGlobalDenseScalarIndex(self: *Session, cell: *const GlobalCell, selector: Value) KError!?Value {
        const raw_index = scalarIntLikeValue(selector) orelse return null;
        const base = cell.value;
        if (base.tag() != .array or !cell.class.isArray() or valueNonVectorNumericShape(base) != null) return null;
        const array = hostDenseIfPresent(base) orelse return null;
        if (hostDenseShapeHandle(array)) |handle| {
            if (handle.rank > 1) return null;
        }
        const idx = try normalizeIndex(raw_index, array.len());
        return switch (array.storage) {
            .bit => |words| Value.fromBool(bitGet(words, idx)),
            .int8, .int16, .int32, .int64 => try self.intValue(hostIntViewItem(hostIntArrayView(array).?, idx)),
            .float32 => |items| try self.float32Value(items[idx]),
            .float64 => |items| try self.floatValue(items[idx]),
        };
    }

    fn compactModifyGlobalConst(self: *Session, slot: u8, builtin: BuiltinId, want_result: bool, rhs: i64) KError!?Value {
        const left = try self.loadGlobalSlot(slot);
        const result = try self.applyLocalConstDyadValue(left, builtin, rhs);
        var stored = false;
        errdefer if (!stored) self.releaseCanonicalManagedNumericValue(result);
        try self.storeGlobalSlot(slot, result);
        stored = true;
        if (want_result) return result;
        self.releaseCanonicalManagedNumericValue(result);
        return null;
    }

    fn compactModifyGlobalStack(self: *Session, state: *CodeState, slot: u8, builtin: BuiltinId, want_result: bool) KError!?Value {
        const rhs = try compactPop(state);
        defer self.releaseCanonicalManagedNumericValue(rhs);
        const left = try self.loadGlobalSlot(slot);
        const result = try self.applyShapedBorrowedDyadValue(builtin, left, rhs);
        var stored = false;
        errdefer if (!stored) self.releaseCanonicalManagedNumericValue(result);
        try self.storeGlobalSlot(slot, result);
        stored = true;
        if (want_result) return result;
        self.releaseCanonicalManagedNumericValue(result);
        return null;
    }

    fn compactModifyLocalConst(self: *Session, state: *CodeState, slot: u8, builtin: BuiltinId, want_result: bool, rhs: i64) KError!?Value {
        const left = try compactBorrowLocal(state, slot);
        const result = try self.applyLocalConstDyadValue(left, builtin, rhs);
        var stored = false;
        errdefer if (!stored) self.releaseCanonicalManagedNumericValue(result);
        const returned = if (want_result) self.retainValue(result) else Value.fromBool(false);
        var returned_owned = want_result;
        errdefer if (returned_owned) self.releaseValue(returned);
        try self.compactStoreLocal(state, slot, result);
        stored = true;
        if (want_result) {
            returned_owned = false;
            return returned;
        }
        return null;
    }

    fn compactModifyLocalStack(self: *Session, state: *CodeState, slot: u8, builtin: BuiltinId, want_result: bool) KError!?Value {
        const rhs = try compactPop(state);
        defer self.releaseCanonicalManagedNumericValue(rhs);
        const left = try compactBorrowLocal(state, slot);
        const result = try self.applyShapedBorrowedDyadValue(builtin, left, rhs);
        var stored = false;
        errdefer if (!stored) self.releaseCanonicalManagedNumericValue(result);
        const returned = if (want_result) self.retainValue(result) else Value.fromBool(false);
        var returned_owned = want_result;
        errdefer if (returned_owned) self.releaseValue(returned);
        try self.compactStoreLocal(state, slot, result);
        stored = true;
        if (want_result) {
            returned_owned = false;
            return returned;
        }
        return null;
    }

    fn compactIndexedAssignGlobalSources(self: *Session, code: *const Code, state: *CodeState, ip: *usize, slot: u8, mode: AmendMode, builtin: BuiltinId, want_result: bool) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_code_indexed_assign_sources_count += 1;
        if (mode == .unary) return error.Internal;
        const selector = try self.compactEvalArgSourceOwned(code, state, ip);
        defer self.releaseValue(selector);
        const rhs = try self.compactEvalArgSourceOwned(code, state, ip);
        defer self.releaseValue(rhs);
        return try self.compactIndexedAssignGlobalValues(slot, mode, builtin, want_result, selector, rhs);
    }

    fn compactIndexedAssignGlobalValues(self: *Session, slot: u8, mode: AmendMode, builtin: BuiltinId, want_result: bool, selector: Value, rhs: Value) KError!?Value {
        return try self.compactIndexedAssignValues(null, .{ .global = slot }, mode, builtin, want_result, selector, rhs);
    }

    fn compactIndexedAssignLocalSources(self: *Session, code: *const Code, state: *CodeState, ip: *usize, slot: u8, mode: AmendMode, builtin: BuiltinId, want_result: bool) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_code_indexed_assign_sources_count += 1;
        if (mode == .unary) return error.Internal;
        const selector = try self.compactEvalArgSourceOwned(code, state, ip);
        defer self.releaseValue(selector);
        const rhs = try self.compactEvalArgSourceOwned(code, state, ip);
        defer self.releaseValue(rhs);
        return try self.compactIndexedAssignLocalValues(state, slot, mode, builtin, want_result, selector, rhs);
    }

    fn compactIndexedAssignLocalValues(self: *Session, state: *CodeState, slot: u8, mode: AmendMode, builtin: BuiltinId, want_result: bool, selector: Value, rhs: Value) KError!?Value {
        return try self.compactIndexedAssignValues(state, .{ .local = slot }, mode, builtin, want_result, selector, rhs);
    }

    fn compactIndexedAssignValues(
        self: *Session,
        state: ?*CodeState,
        target: IndexedAssignTarget,
        mode: AmendMode,
        builtin: BuiltinId,
        want_result: bool,
        selector: Value,
        rhs: Value,
    ) KError!?Value {
        if (mode == .unary) return error.Internal;
        self.recordIndexedAssign(target);

        switch (target) {
            .global => |slot| {
                const global_slot = std.math.cast(u8, slot) orelse return error.Internal;
                if (try self.compactTryFastGlobalIntScalarAssignInPlace(global_slot, mode, selector, rhs, want_result)) |direct| {
                    return direct.result;
                }
                if (mode == .assign) {
                    if (try self.tryFastGlobalDenseScalarAssignInPlace(slot, selector, rhs, want_result)) |direct| {
                        return direct.result;
                    }
                }
            },
            .local => {},
        }

        const base = switch (target) {
            .global => |slot| try self.takeGlobalSlot(slot),
            .local => |slot| try compactTakeLocal(state orelse return error.Internal, slot),
        };
        const amended = switch (mode) {
            .assign => (try self.tryFastIndexedDenseScalarAssignOwned(base, selector, rhs)) orelse
                try self.applyAmendOwned(base, selector, .assign, rhs, Value.fromBool(false)),
            .binary => try self.applyAmendOwned(base, selector, .binary, Value.builtin(builtin), rhs),
            .unary => unreachable,
        };
        var amended_stored = false;
        errdefer if (!amended_stored) self.releaseCanonicalManagedNumericValue(amended);

        const result: ?Value = if (want_result) blk: {
            if (try self.materializeIndexedSelectorPath(selector)) |selectors| {
                defer self.releaseArgs(selectors);
                break :blk try self.deepIndexValue(amended, selectors);
            }
            break :blk try self.applyArrayCall1(amended, selector);
        } else null;
        errdefer if (result) |value| self.releaseValue(value);

        switch (target) {
            .global => |slot| {
                try self.storeGlobalSlot(slot, amended);
                self.releaseCanonicalManagedNumericValue(amended);
            },
            .local => |slot| try self.compactStoreLocal(state orelse return error.Internal, slot, amended),
        }
        amended_stored = true;
        return result;
    }

    fn compactTryFastGlobalIntScalarAssignInPlace(
        self: *Session,
        slot: u8,
        mode: AmendMode,
        selector: Value,
        rhs: Value,
        want_result: bool,
    ) KError!?DirectGlobalIndexedAssignResult {
        if (mode != .assign) return null;
        const raw_index = scalarIntLikeValue(selector) orelse return null;
        const rhs_int = scalarIntLikeValue(rhs) orelse return null;
        const cell = try self.loadGlobalCell(slot);
        const base = cell.value;
        if (!cell.class.isArray() or valueNonVectorNumericShape(base) != null) return null;
        const base_array = hostDenseIfPresent(base) orelse return null;
        const view = hostIntArrayView(base_array) orelse return null;
        const kind = hostIntArrayViewKind(view);
        if (!hostIntKindCanRepresent(kind, rhs_int)) return null;
        var out = self.tryReuseHostIntArrayResult(base, kind) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        if (!self.prepareReusableHostDenseForMutation(base)) {
            self.recordFastDenseAssignMiss();
            return null;
        }
        const target_idx = try normalizeIndex(raw_index, base_array.len());
        try out.set(target_idx, rhs_int);
        const host = out.arrayPtr();
        hostDenseSetFlags(host, host_dense_flag_normalized);
        self.invalidateHostDenseCachesForMutation(host);
        cell.class = classifyGlobalValue(base);
        if (comptime enable_probe_instrumentation) {
            self.recordFastDenseAssignHit(.{ .scalar = target_idx }, .{ .int_scalar = rhs_int }, true);
            self.debug_owned_amend_count += 1;
        }
        return .{
            .result = if (want_result) try self.applyArrayCall1Scalar(base, raw_index) else null,
        };
    }

    fn compactDyadBorrowed(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        if (try self.compactTryInlineIntBoolDyad(op, left, right)) |result| return result;
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            .div => try self.divValues(left, right),
            .minimum => try self.minimumValues(left, right),
            .maximum => try self.maximumValues(left, right),
            .less, .more, .equal => try self.applyShapedBorrowedDyadValue(op, left, right),
            else => try self.applyDyad(op, left, right),
        };
    }

    fn compactMonadBorrowed(self: *Session, id: u8, value: Value) KError!Value {
        if (id == ckm_argmax) return try self.argmaxValue(value);
        const op = compactMonadBuiltin(id) orelse return error.Internal;
        return try self.applyMonad(op, value);
    }

    fn compactDyadRangeBorrowed(self: *Session, id: u8, left: Value, right: Value) KError!Value {
        const op = compactDyadBuiltin(id) orelse return error.Internal;
        return try self.compactDyadBorrowed(op, left, right);
    }

    fn compactTryInlineIntBoolDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!?Value {
        const lhs = inlineIntBoolValue(left) orelse return null;
        const rhs = inlineIntBoolValue(right) orelse return null;
        return try self.compactInlineIntDyadResult(op, lhs, rhs, left.tag() == .bool and right.tag() == .bool);
    }

    fn compactTryInlineLocalConstDyad(self: *Session, left: Value, op: BuiltinId, rhs_const: i64, const_first: bool) KError!?Value {
        const left_value = inlineIntBoolValue(left) orelse return null;
        const lhs = if (const_first) rhs_const else left_value;
        const rhs = if (const_first) left_value else rhs_const;
        return try self.compactInlineIntDyadResult(op, lhs, rhs, false);
    }

    fn compactInlineIntDyadResult(self: *Session, op: BuiltinId, lhs: i64, rhs: i64, both_bool: bool) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
        const result: ?Value = switch (op) {
            .add => blk: {
                const added = @addWithOverflow(lhs, rhs);
                if (added[1] != 0) break :blk null;
                break :blk try self.intValue(added[0]);
            },
            .sub => blk: {
                const subbed = @subWithOverflow(lhs, rhs);
                if (subbed[1] != 0) break :blk null;
                break :blk try self.intValue(subbed[0]);
            },
            .mul => blk: {
                const multiplied = @mulWithOverflow(lhs, rhs);
                if (multiplied[1] != 0) break :blk null;
                break :blk try self.intValue(multiplied[0]);
            },
            .less => Value.fromBool(lhs < rhs),
            .more => Value.fromBool(lhs > rhs),
            .equal => Value.fromBool(lhs == rhs),
            .minimum => if (both_bool) Value.fromBool(lhs != 0 and rhs != 0) else try self.intValue(@min(lhs, rhs)),
            .maximum => if (both_bool) Value.fromBool(lhs != 0 or rhs != 0) else try self.intValue(@max(lhs, rhs)),
            else => null,
        };
        if (comptime enable_probe_instrumentation) {
            if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
        }
        return result;
    }

    fn compactMakeProjectionStack(self: *Session, state: *CodeState, slot_count: u8, hole_mask: u64) KError!void {
        const total_slots: usize = slot_count;
        if (total_slots > 63) return error.Unsupported;
        if ((hole_mask >> @intCast(total_slots)) != 0) return error.Internal;
        const hole_count = @popCount(hole_mask);
        if (hole_count > total_slots) return error.Internal;
        const bound_count = total_slots - hole_count;
        if (state.stack_len < bound_count + 1) return error.Internal;

        const callee_index = state.stack_len - (bound_count + 1);
        const callee = state.stack[callee_index];
        const bound_values = state.stack[callee_index + 1 .. state.stack_len];

        const slot_values = try self.scratch_arena.allocator().alloc(Value, total_slots);
        var bound_idx: usize = 0;
        for (slot_values, 0..) |*slot_value, slot_idx| {
            if (((hole_mask >> @intCast(slot_idx)) & 1) != 0) {
                slot_value.* = Value.fromBool(false);
            } else {
                if (bound_idx >= bound_values.len) return error.Internal;
                slot_value.* = bound_values[bound_idx];
                bound_idx += 1;
            }
        }
        if (bound_idx != bound_values.len) return error.Internal;

        const projection = try self.allocManagedProjectionClosure(callee, slot_count, hole_mask, slot_values);
        errdefer self.releaseValue(projection);
        while (state.stack_len > callee_index) {
            state.stack_len -= 1;
            self.releaseValue(state.stack[state.stack_len]);
        }
        try compactPush(state, projection);
    }

    fn compactApplyAmendStack(self: *Session, state: *CodeState, mode: AmendMode, deep: bool) KError!void {
        const argc: usize = switch (mode) {
            .unary, .assign => 3,
            .binary => 4,
        };
        if (state.stack_len < argc) return error.Internal;

        const base_index = state.stack_len - argc;
        const base = state.stack[base_index];
        const selector = state.stack[base_index + 1];
        const result = switch (mode) {
            .unary => try self.applyAmend(base, selector, if (deep) .deep_unary else .unary, state.stack[base_index + 2], Value.fromBool(false)),
            .assign => try self.applyAmend(base, selector, if (deep) .deep_assign else .assign, state.stack[base_index + 2], Value.fromBool(false)),
            .binary => try self.applyAmend(base, selector, if (deep) .deep_binary else .binary, state.stack[base_index + 2], state.stack[base_index + 3]),
        };
        errdefer self.releaseValue(result);
        while (state.stack_len > base_index) {
            state.stack_len -= 1;
            self.releaseValue(state.stack[state.stack_len]);
        }
        try compactPush(state, result);
    }

    fn runCodeBorrowed(self: *Session, code: *const Code, args: []const Value) KError!Value {
        var state = CodeState{};
        try self.compactInitBorrowedArgs(&state, code, args);
        return try self.runCodeWithState(code, &state);
    }

    fn runCodeOwned(self: *Session, code: *const Code, args: []const Value) KError!Value {
        var state = CodeState{};
        try compactInitOwnedArgs(&state, code, args);
        return try self.runCodeWithState(code, &state);
    }

    fn runCodeWithState(self: *Session, initial_code: *const Code, state: *CodeState) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_code_run_count += 1;
        var code = initial_code;
        var ip: usize = 0;
        errdefer self.compactReleaseState(state);

        while (true) {
            if (ip >= code.bytes.len) return error.Internal;
            const raw = code.bytes[ip];
            ip += 1;
            self.noteCodeOpcode(raw);

            if (comptime enable_sampling_profile) {
                if (self.profile_sampling_enabled.load(.unordered) != 0) {
                    self.profile_current_label.store(@intFromEnum(SamplingProfileLabel.vm_dispatch), .unordered);
                    self.profile_current_op.store(raw, .unordered);
                    self.profile_current_code_id.store(code.profile_id, .unordered);
                    self.profile_current_callable_slot.store(sampling_profile_no_callable_slot, .unordered);
                }
            }

            if (raw < ck_store_local_base) {
                if (raw < ck_dyad_base) {
                    const value = try compactPop(state);
                    defer self.releaseValue(value);
                    try compactPush(state, try self.compactMonadBorrowed(raw - ck_monad_base, value));
                } else {
                    const id = raw - ck_dyad_base;
                    const right = try compactPop(state);
                    const left = try compactPop(state);
                    const result = if (id == ckd_dot) blk: {
                        defer self.releaseCanonicalManagedNumericValue(left);
                        defer self.releaseCanonicalManagedNumericValue(right);
                        break :blk try self.dotValues(left, right);
                    } else blk: {
                        defer self.releaseValue(left);
                        defer self.releaseValue(right);
                        break :blk try self.compactDyadRangeBorrowed(id, left, right);
                    };
                    try compactPush(state, result);
                }
                continue;
            }
            if (raw >= ck_load_local_base and raw < ck_load_local_base + ck_range_width) {
                try compactPush(state, try self.compactReadLocal(state, raw - ck_load_local_base));
                continue;
            }
            if (raw >= ck_store_local_base and raw < ck_store_local_base + ck_range_width) {
                try self.compactStoreLocal(state, raw - ck_store_local_base, try compactPop(state));
                continue;
            }
            if (raw >= ck_take_local_base and raw < ck_take_local_base + ck_range_width) {
                try compactPush(state, try compactTakeLocal(state, raw - ck_take_local_base));
                continue;
            }
            if (compactIsConstValueOpcode(raw)) {
                const slot = raw - ck_const_value_base;
                if (slot >= code.constants.len) return error.Internal;
                try compactPush(state, self.shareValue(code.constants[slot]));
                continue;
            }

            switch (raw) {
                ck_const_i8 => try compactPush(state, try self.intValue(@as(i8, @bitCast(try compactReadByte(code, &ip))))),
                ck_const_i64 => try compactPush(state, try self.intValue(try compactReadI64(code, &ip))),
                ck_const_value_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    if (slot >= code.constants.len) return error.Internal;
                    try compactPush(state, self.shareValue(code.constants[slot]));
                },
                ck_const_builtin_u8 => try compactPush(state, Value.builtin(@enumFromInt(try compactReadByte(code, &ip)))),
                ck_const_false => try compactPush(state, Value.fromBool(false)),
                ck_const_true => try compactPush(state, Value.fromBool(true)),
                ck_discard => self.releaseValue(try compactPop(state)),
                ck_return => {
                    const result = try compactPop(state);
                    self.compactReleaseState(state);
                    return result;
                },
                ck_jump_u8 => ip = try compactReadByte(code, &ip),
                ck_jump_if_false_u8 => {
                    const target = try compactReadByte(code, &ip);
                    const condition = try compactPop(state);
                    if (comptime enable_probe_instrumentation) {
                        self.debug_jump_if_false_count += 1;
                        switch (condition.tag()) {
                            .bool, .int, .float => self.debug_jump_if_false_scalar_count += 1,
                            else => {},
                        }
                    }
                    const truthy = branchTruthValue(condition) orelse return error.Type;
                    self.releaseValue(condition);
                    if (!truthy) ip = target;
                },
                ck_jump_if_false_equal_local_const_i64, ck_jump_if_false_less_local_const_i64, ck_jump_if_false_more_local_const_i64 => {
                    const slot = try compactReadByte(code, &ip);
                    const rhs = try compactReadI64(code, &ip);
                    const target = try compactReadByte(code, &ip);
                    if (comptime enable_probe_instrumentation) {
                        self.debug_jump_if_false_count += 1;
                        self.debug_shaped_scalar_dyad_count += 1;
                    }
                    const left = try compactBorrowLocal(state, slot);
                    const condition_op: BuiltinId = switch (raw) {
                        ck_jump_if_false_equal_local_const_i64 => .equal,
                        ck_jump_if_false_less_local_const_i64 => .less,
                        ck_jump_if_false_more_local_const_i64 => .more,
                        else => unreachable,
                    };
                    if (scalarIntLikeValue(left)) |lhs| {
                        const condition = switch (raw) {
                            ck_jump_if_false_equal_local_const_i64 => lhs == rhs,
                            ck_jump_if_false_less_local_const_i64 => lhs < rhs,
                            ck_jump_if_false_more_local_const_i64 => lhs > rhs,
                            else => unreachable,
                        };
                        if (comptime enable_probe_instrumentation) self.debug_jump_if_false_scalar_count += 1;
                        if (!condition) ip = target;
                    } else {
                        const right = try self.intValue(rhs);
                        defer self.releaseValue(right);
                        const condition_value = try self.applyBorrowedDyadValue(condition_op, left, right);
                        defer self.releaseValue(condition_value);
                        const truthy = branchTruthValue(condition_value) orelse return error.Type;
                        if (comptime enable_probe_instrumentation) {
                            switch (condition_value.tag()) {
                                .bool, .int, .float => self.debug_jump_if_false_scalar_count += 1,
                                else => {},
                            }
                        }
                        if (!truthy) ip = target;
                    }
                },
                ck_load_global_u8 => try compactPush(state, self.retainValue(try self.loadGlobalSlot(try compactReadByte(code, &ip)))),
                ck_store_global_u8 => try self.storeGlobalSlot(try compactReadByte(code, &ip), try compactPeek(state)),
                ck_modify_global_stack_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    if (try self.compactModifyGlobalStack(state, slot, builtin, want_result)) |result| try compactPush(state, result);
                },
                ck_modify_global_const_i64 => {
                    const slot = try compactReadByte(code, &ip);
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    const rhs = try compactReadI64(code, &ip);
                    if (try self.compactModifyGlobalConst(slot, builtin, want_result, rhs)) |result| try compactPush(state, result);
                },
                ck_modify_local_stack_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    if (try self.compactModifyLocalStack(state, slot, builtin, want_result)) |result| try compactPush(state, result);
                },
                ck_modify_local_const_i64 => {
                    const slot = try compactReadByte(code, &ip);
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    const rhs = try compactReadI64(code, &ip);
                    if (try self.compactModifyLocalConst(state, slot, builtin, want_result, rhs)) |result| try compactPush(state, result);
                },
                ck_assign_index_global_sources_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const mode: AmendMode = @enumFromInt(try compactReadByte(code, &ip));
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    if (try self.compactIndexedAssignGlobalSources(code, state, &ip, slot, mode, builtin, want_result)) |result| try compactPush(state, result);
                },
                ck_assign_index_local_sources_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const mode: AmendMode = @enumFromInt(try compactReadByte(code, &ip));
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    if (try self.compactIndexedAssignLocalSources(code, state, &ip, slot, mode, builtin, want_result)) |result| try compactPush(state, result);
                },
                ck_assign_index_global_stack_u8 => {
                    if (comptime enable_probe_instrumentation) self.debug_code_indexed_assign_stack_count += 1;
                    const slot = try compactReadByte(code, &ip);
                    const mode: AmendMode = @enumFromInt(try compactReadByte(code, &ip));
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    const rhs = try compactPop(state);
                    defer self.releaseValue(rhs);
                    const selector = try compactPop(state);
                    defer self.releaseValue(selector);
                    if (try self.compactIndexedAssignGlobalValues(slot, mode, builtin, want_result, selector, rhs)) |result| try compactPush(state, result);
                },
                ck_assign_index_local_stack_u8 => {
                    if (comptime enable_probe_instrumentation) self.debug_code_indexed_assign_stack_count += 1;
                    const slot = try compactReadByte(code, &ip);
                    const mode: AmendMode = @enumFromInt(try compactReadByte(code, &ip));
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const want_result = (try compactReadByte(code, &ip)) != 0;
                    const rhs = try compactPop(state);
                    defer self.releaseValue(rhs);
                    const selector = try compactPop(state);
                    defer self.releaseValue(selector);
                    if (try self.compactIndexedAssignLocalValues(state, slot, mode, builtin, want_result, selector, rhs)) |result| try compactPush(state, result);
                },
                ck_index_global_source_u8, ck_tail_index_global_source_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const selector = try self.compactEvalArgSourceOwned(code, state, &ip);
                    const result = try self.compactApplyGlobalIndexOwned(slot, selector);
                    if (raw == ck_tail_index_global_source_u8) {
                        self.compactReleaseState(state);
                        return result;
                    }
                    try compactPush(state, result);
                },
                ck_index_global_source_store_local_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const selector = try self.compactEvalArgSourceOwned(code, state, &ip);
                    const result = try self.compactApplyGlobalIndexOwned(slot, selector);
                    try self.compactStoreLocal(state, try compactReadByte(code, &ip), result);
                },
                ck_index_local_source_u8, ck_tail_index_local_source_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const selector = try self.compactEvalArgSourceOwned(code, state, &ip);
                    const result = try self.compactApplyLocalIndexOwned(state, slot, selector);
                    if (raw == ck_tail_index_local_source_u8) {
                        self.compactReleaseState(state);
                        return result;
                    }
                    try compactPush(state, result);
                },
                ck_index_where_mask_stack_u8 => {
                    const mask = try compactPop(state);
                    const callee = try compactPop(state);
                    defer self.releaseValue(mask);
                    defer self.releaseValue(callee);
                    const result = try self.applyWhereMaskCall(callee, mask);
                    errdefer self.releaseValue(result);
                    try compactPush(state, result);
                },
                ck_call_global_slots_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const flags = try compactReadByte(code, &ip);
                    const argc = compactCallArgc(flags);
                    if (compactCallIsTail(flags) and compactCallStoresLocal(flags)) return error.Internal;
                    if (compactCallIsTail(flags)) {
                        var next_code: *const Code = undefined;
                        if (try self.compactTryTailContinueGlobalCompactCallSources(slot, &next_code, code, state, &ip, argc)) {
                            code = next_code;
                            ip = 0;
                            continue;
                        }
                        var args_buf: [max_direct_apply_args]Value = undefined;
                        const args = try self.compactReadOwnedArgs(code, state, &ip, argc, &args_buf);
                        const result = try self.compactApplyGlobalCallOwned(slot, args);
                        self.compactReleaseState(state);
                        return result;
                    }
                    const result = if (try self.compactTryApplyGlobalCompactCallSources(slot, code, state, &ip, argc)) |direct|
                        direct
                    else blk: {
                        var args_buf: [max_direct_apply_args]Value = undefined;
                        const args = try self.compactReadOwnedArgs(code, state, &ip, argc, &args_buf);
                        break :blk try self.compactApplyGlobalCallOwned(slot, args);
                    };
                    if (compactCallStoresLocal(flags)) {
                        try self.compactStoreLocal(state, try compactReadByte(code, &ip), result);
                    } else {
                        try compactPush(state, result);
                    }
                },
                ck_call_global_stack_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const flags = try compactReadByte(code, &ip);
                    const argc = compactCallArgc(flags);
                    if (compactCallStoresLocal(flags)) return error.Internal;
                    if (compactCallIsTail(flags)) {
                        const cell = try self.loadGlobalCell(slot);
                        if (codeForGlobalCellCall(cell, argc)) |next_code| {
                            var next_state = CodeState{};
                            try compactInitOwnedStackArgs(&next_state, next_code, state, argc);
                            if (comptime enable_probe_instrumentation) {
                                self.debug_code_global_call_count += 1;
                                self.debug_code_global_call_direct_count += 1;
                                self.debug_code_tail_continue_count += 1;
                            }
                            self.compactReleaseState(state);
                            compactMoveState(state, &next_state);
                            code = next_code;
                            ip = 0;
                            continue;
                        }
                        var args_buf: [max_direct_apply_args]Value = undefined;
                        const args = try compactPopOwnedStackArgs(state, argc, &args_buf);
                        const result = try self.compactApplyGlobalCallOwned(slot, args);
                        self.compactReleaseState(state);
                        return result;
                    }
                    var args_buf: [max_direct_apply_args]Value = undefined;
                    const args = try compactPopOwnedStackArgs(state, argc, &args_buf);
                    try compactPush(state, try self.compactApplyGlobalCallOwned(slot, args));
                },
                ck_call_global_derived_slots_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const kind: DerivedVerbKind = @enumFromInt(try compactReadByte(code, &ip));
                    const argc = try compactReadByte(code, &ip);
                    var args_buf: [max_direct_apply_args]Value = undefined;
                    const args = try self.compactReadOwnedArgs(code, state, &ip, argc, &args_buf);
                    try compactPush(state, try self.compactApplyGlobalDerivedCallOwned(slot, kind, args));
                },
                ck_call_global_derived_stack_u8 => {
                    const slot = try compactReadByte(code, &ip);
                    const kind: DerivedVerbKind = @enumFromInt(try compactReadByte(code, &ip));
                    const argc = try compactReadByte(code, &ip);
                    var args_buf: [max_direct_apply_args]Value = undefined;
                    const args = try compactPopOwnedStackArgs(state, argc, &args_buf);
                    try compactPush(state, try self.compactApplyGlobalDerivedCallOwned(slot, kind, args));
                },
                ck_add_local_local, ck_sub_local_local, ck_mul_local_local, ck_minimum_local_local, ck_maximum_local_local, ck_less_local_local, ck_more_local_local, ck_equal_local_local => {
                    const left = try compactBorrowLocal(state, try compactReadByte(code, &ip));
                    const right = try compactBorrowLocal(state, try compactReadByte(code, &ip));
                    try compactPush(state, try self.compactDyadBorrowed(switch (raw) {
                        ck_add_local_local => .add,
                        ck_sub_local_local => .sub,
                        ck_mul_local_local => .mul,
                        ck_minimum_local_local => .minimum,
                        ck_maximum_local_local => .maximum,
                        ck_less_local_local => .less,
                        ck_more_local_local => .more,
                        ck_equal_local_local => .equal,
                        else => unreachable,
                    }, left, right));
                },
                ck_add_local_const_i64, ck_sub_local_const_i64, ck_mul_local_const_i64, ck_minimum_local_const_i64, ck_maximum_local_const_i64, ck_less_local_const_i64, ck_more_local_const_i64, ck_equal_local_const_i64 => {
                    const slot = try compactReadByte(code, &ip);
                    const rhs = try compactReadI64(code, &ip);
                    const left = try compactBorrowLocal(state, slot);
                    const op: BuiltinId = switch (raw) {
                        ck_add_local_const_i64 => .add,
                        ck_sub_local_const_i64 => .sub,
                        ck_mul_local_const_i64 => .mul,
                        ck_minimum_local_const_i64 => .minimum,
                        ck_maximum_local_const_i64 => .maximum,
                        ck_less_local_const_i64 => .less,
                        ck_more_local_const_i64 => .more,
                        ck_equal_local_const_i64 => .equal,
                        else => unreachable,
                    };
                    const result = if (try self.compactTryInlineLocalConstDyad(left, op, rhs, false)) |direct|
                        direct
                    else switch (raw) {
                        ck_add_local_const_i64, ck_sub_local_const_i64, ck_mul_local_const_i64 => try self.applyLocalConstOpValue(left, op, rhs),
                        ck_minimum_local_const_i64, ck_maximum_local_const_i64, ck_less_local_const_i64, ck_more_local_const_i64, ck_equal_local_const_i64 => try self.applyLocalConstDyadValue(left, op, rhs),
                        else => unreachable,
                    };
                    try compactPush(state, result);
                },
                ck_add_const_local_i64, ck_sub_const_local_i64, ck_minimum_const_local_i64, ck_maximum_const_local_i64, ck_less_const_local_i64, ck_more_const_local_i64, ck_equal_const_local_i64 => {
                    const lhs = try compactReadI64(code, &ip);
                    const right = try compactBorrowLocal(state, try compactReadByte(code, &ip));
                    const op: BuiltinId = switch (raw) {
                        ck_add_const_local_i64 => .add,
                        ck_sub_const_local_i64 => .sub,
                        ck_minimum_const_local_i64 => .minimum,
                        ck_maximum_const_local_i64 => .maximum,
                        ck_less_const_local_i64 => .less,
                        ck_more_const_local_i64 => .more,
                        ck_equal_const_local_i64 => .equal,
                        else => unreachable,
                    };
                    const result = if (try self.compactTryInlineLocalConstDyad(right, op, lhs, true)) |direct|
                        direct
                    else switch (raw) {
                        ck_add_const_local_i64, ck_sub_const_local_i64 => try self.applyConstLocalOpValue(lhs, op, right),
                        ck_minimum_const_local_i64, ck_maximum_const_local_i64, ck_less_const_local_i64, ck_more_const_local_i64, ck_equal_const_local_i64 => try self.applyConstLocalDyadValue(lhs, op, right),
                        else => unreachable,
                    };
                    try compactPush(state, result);
                },
                ck_store_local_add_local_const_i64, ck_store_local_sub_local_const_i64, ck_store_local_mul_local_const_i64 => {
                    const dst = try compactReadByte(code, &ip);
                    const src = try compactReadByte(code, &ip);
                    const rhs = try compactReadI64(code, &ip);
                    const left = try compactBorrowLocal(state, src);
                    const op: BuiltinId = switch (raw) {
                        ck_store_local_add_local_const_i64 => .add,
                        ck_store_local_sub_local_const_i64 => .sub,
                        ck_store_local_mul_local_const_i64 => .mul,
                        else => unreachable,
                    };
                    const result = if (try self.compactTryInlineLocalConstDyad(left, op, rhs, false)) |direct|
                        direct
                    else
                        try self.applyLocalConstOpValue(left, op, rhs);
                    try self.compactStoreLocal(state, dst, result);
                },
                ck_make_vector_u8 => {
                    const count = try compactReadByte(code, &ip);
                    const total: usize = count;
                    if (state.stack_len < total) return error.Internal;
                    const start = state.stack_len - total;
                    const vector = try self.makeArrayFromValues(state.stack[start..state.stack_len]);
                    errdefer self.releaseValue(vector);
                    while (state.stack_len > start) {
                        state.stack_len -= 1;
                        self.releaseValue(state.stack[state.stack_len]);
                    }
                    try compactPush(state, vector);
                },
                ck_make_projection_u8 => {
                    const slot_count = try compactReadByte(code, &ip);
                    const hole_mask: u64 = @bitCast(try compactReadI64(code, &ip));
                    try self.compactMakeProjectionStack(state, slot_count, hole_mask);
                },
                ck_amend_u8, ck_deep_amend_u8 => {
                    const mode = std.meta.intToEnum(AmendMode, try compactReadByte(code, &ip)) catch return error.Internal;
                    try self.compactApplyAmendStack(state, mode, raw == ck_deep_amend_u8);
                },
                ck_call_stack_u8 => {
                    const flags = try compactReadByte(code, &ip);
                    const argc = compactCallArgc(flags);
                    if (compactCallStoresLocal(flags)) return error.Internal;
                    var args_buf: [max_direct_apply_args]Value = undefined;
                    const args = try compactPopOwnedStackArgs(state, argc, &args_buf);
                    const callee = try compactPop(state);
                    const result = try self.compactApplyCallOwned(callee, args);
                    if (compactCallIsTail(flags)) {
                        self.compactReleaseState(state);
                        return result;
                    }
                    try compactPush(state, result);
                },
                ck_call_builtin_derived2_u8 => {
                    const builtin: BuiltinId = @enumFromInt(try compactReadByte(code, &ip));
                    const kind: DerivedVerbKind = @enumFromInt(try compactReadByte(code, &ip));
                    const right = try compactPop(state);
                    const left = try compactPop(state);
                    const left_release = if (valueNumericHandle(left)) |handle| Value.array(@constCast(handle)) else left;
                    const right_release = if (valueNumericHandle(right)) |handle| Value.array(@constCast(handle)) else right;
                    errdefer self.releaseCanonicalManagedNumericValue(left_release);
                    errdefer self.releaseCanonicalManagedNumericValue(right_release);
                    const captures = [_]Value{Value.builtin(builtin)};
                    const result = try self.applyDerivedKind(kind, &captures, &[_]Value{ left, right });
                    self.releaseCanonicalManagedNumericValue(left_release);
                    self.releaseCanonicalManagedNumericValue(right_release);
                    try compactPush(state, result);
                },
                ck_make_adverb_u8 => {
                    const kind: DerivedVerbKind = @enumFromInt(try compactReadByte(code, &ip));
                    const base = try compactPop(state);
                    errdefer self.releaseValue(base);
                    const derived = switch (base.tag()) {
                        .int, .bool, .float, .float32, .builtin, .closure, .array => Value.closure(try self.allocDerivedClosure(kind, base)),
                    };
                    self.releaseValue(base);
                    try compactPush(state, derived);
                },
                else => return error.Internal,
            }
        }
    }

    fn runCode(self: *Session, code: *const Code, args: []const Value) KError!Value {
        return try self.runCodeMode(code, args, true);
    }

    fn runCodeMode(self: *Session, code: *const Code, args: []const Value, root_results: bool) KError!Value {
        if (!codeCanRunWithArgLen(code, args.len)) return error.Arity;
        _ = self.scratch_arena.reset(.retain_capacity);
        self.dropStackFrom(0);
        self.stack_len = 0;
        const result = try self.runCodeBorrowed(code, args);
        if (!root_results) return result;
        const escaped = if (valueMayNeedRelease(result)) try self.retainEscapedValue(result) else result;
        if (valueMayNeedRelease(result)) self.releaseValue(result);
        return try self.finishResult(escaped);
    }

    fn runClosureMode(self: *Session, closure: *const Closure, args: []const Value, root_results: bool) KError!Value {
        if (codeForRunnablePlainClosureArgs(closure, args)) |compact| {
            const result = try self.runCodeBorrowed(compact, codeRunArgs(compact, args));
            return if (root_results) try self.finishResult(result) else result;
        }
        return error.Unsupported;
    }

    fn tryFastLocalConstDyadValue(self: *Session, left: Value, op: BuiltinId, rhs_const: i64, const_first: bool) KError!?Value {
        if (inlineIntBoolValue(left)) |left_value| {
            if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
            const lhs = if (const_first) rhs_const else left_value;
            const rhs = if (const_first) left_value else rhs_const;
            const result: ?Value = switch (op) {
                .add => blk: {
                    const added = @addWithOverflow(lhs, rhs);
                    if (added[1] != 0) break :blk null;
                    break :blk try self.intValue(added[0]);
                },
                .sub => blk: {
                    const subbed = @subWithOverflow(lhs, rhs);
                    if (subbed[1] != 0) break :blk null;
                    break :blk try self.intValue(subbed[0]);
                },
                .mul => blk: {
                    const multiplied = @mulWithOverflow(lhs, rhs);
                    if (multiplied[1] != 0) break :blk null;
                    break :blk try self.intValue(multiplied[0]);
                },
                .div => try self.floatValue(@as(f64, @floatFromInt(lhs)) / @as(f64, @floatFromInt(rhs))),
                .minimum => try self.intValue(@min(lhs, rhs)),
                .maximum => try self.intValue(@max(lhs, rhs)),
                .less => Value.fromBool(lhs < rhs),
                .more => Value.fromBool(lhs > rhs),
                .equal => Value.fromBool(lhs == rhs),
                else => null,
            };
            if (comptime enable_probe_instrumentation) {
                if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
            }
            return result;
        }

        const left_float = inlineNumericFloatValue(left) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
        const rhs_float: f64 = @floatFromInt(rhs_const);
        const lhs = if (const_first) rhs_float else left_float;
        const rhs = if (const_first) left_float else rhs_float;
        const result_kind = scalarFloatStorageKind(left) orelse .float64;
        const float_result = struct {
            fn value(session: *Session, kind: HostFloatStorageKind, raw: f64) KError!Value {
                return switch (kind) {
                    .float32 => try session.float32Value(@floatCast(raw)),
                    .float64 => try session.floatValue(raw),
                };
            }
        }.value;
        const result: ?Value = switch (op) {
            .add => try float_result(self, result_kind, lhs + rhs),
            .sub => try float_result(self, result_kind, lhs - rhs),
            .mul => try float_result(self, result_kind, lhs * rhs),
            .div => try float_result(self, result_kind, lhs / rhs),
            .minimum => try float_result(self, result_kind, @min(lhs, rhs)),
            .maximum => try float_result(self, result_kind, @max(lhs, rhs)),
            .less => Value.fromBool(lhs < rhs),
            .more => Value.fromBool(lhs > rhs),
            .equal => Value.fromBool(lhs == rhs),
            else => null,
        };
        if (comptime enable_probe_instrumentation) {
            if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
        }
        return result;
    }

    fn applyLocalConstOpValue(self: *Session, left: Value, op: BuiltinId, rhs: i64) KError!Value {
        if (try self.tryFastLocalConstDyadValue(left, op, rhs, false)) |result| return result;
        if (scalarIntLikeValue(left)) |lhs| {
            switch (op) {
                .add => {
                    const result = @addWithOverflow(lhs, rhs);
                    if (result[1] == 0) return try self.intValue(result[0]);
                },
                .sub => {
                    const result = @subWithOverflow(lhs, rhs);
                    if (result[1] == 0) return try self.intValue(result[0]);
                },
                .mul => {
                    const result = @mulWithOverflow(lhs, rhs);
                    if (result[1] == 0) return try self.intValue(result[0]);
                },
                else => return error.Unsupported,
            }
        }

        const right = try self.intValue(rhs);
        defer self.releaseValue(right);
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            else => error.Unsupported,
        };
    }

    fn applyConstLocalOpValue(self: *Session, lhs: i64, op: BuiltinId, right: Value) KError!Value {
        if (try self.tryFastLocalConstDyadValue(right, op, lhs, true)) |result| return result;
        const left = try self.intValue(lhs);
        defer self.releaseValue(left);
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            else => error.Unsupported,
        };
    }

    fn applyBorrowedDyadValue(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        if (try self.tryFastInlineScalarDyad(op, left, right)) |result| return result;
        return switch (op) {
            .add => try self.addValues(left, right),
            .sub => try self.subValues(left, right),
            .mul => try self.mulValues(left, right),
            .div => try self.divValues(left, right),
            .minimum => try self.minimumValues(left, right),
            .maximum => try self.maximumValues(left, right),
            .less => try self.lessValues(left, right),
            .more => try self.moreValues(left, right),
            .equal => try self.equalValues(left, right),
            else => error.Unsupported,
        };
    }

    fn applyShapedBorrowedDyadValue(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        return try self.applyBorrowedDyadValue(op, left, right);
    }

    fn applyLocalConstDyadValue(self: *Session, left: Value, op: BuiltinId, rhs: i64) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        if (try self.tryFastLocalConstDyadValue(left, op, rhs, false)) |result| return result;
        const right = try self.intValue(rhs);
        defer self.releaseValue(right);
        return try self.applyBorrowedDyadValue(op, left, right);
    }

    fn applyConstLocalDyadValue(self: *Session, lhs: i64, op: BuiltinId, right: Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_shaped_scalar_dyad_count += 1;
        if (try self.tryFastLocalConstDyadValue(right, op, lhs, true)) |result| return result;
        const left = try self.intValue(lhs);
        defer self.releaseValue(left);
        return try self.applyBorrowedDyadValue(op, left, right);
    }

    inline fn directReadI64(bytes: []const u8, start: usize) ?i64 {
        const end = start + 8;
        if (end > bytes.len) return null;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, bytes[start + idx]) << @intCast(idx * 8);
        }
        return @bitCast(value);
    }

    inline fn directReadU16(bytes: []const u8, start: usize) ?u16 {
        const end = start + 2;
        if (end > bytes.len) return null;
        return @as(u16, bytes[start]) | (@as(u16, bytes[start + 1]) << 8);
    }

    fn valueIsMaximumFoldCallable(value: Value) bool {
        return switch (value.tag()) {
            .closure => blk: {
                const closure = value.asClosure();
                if (closureDerivedKind(closure) != .fold) break :blk false;
                if (closure.captures.len != 1) break :blk false;
                if (closure.captures[0].tag() != .builtin) break :blk false;
                break :blk closure.captures[0].asBuiltin() == .maximum;
            },
            .builtin => value.asBuiltin() == .maximum,
            else => false,
        };
    }

    fn compactMaximumFoldCallableLen(bytes: []const u8, constants: []const Value) ?usize {
        if (bytes.len >= 4 and
            bytes[0] == ck_const_builtin_u8 and
            bytes[1] == @intFromEnum(BuiltinId.maximum) and
            bytes[2] == ck_make_adverb_u8 and
            bytes[3] == @intFromEnum(DerivedVerbKind.fold))
        {
            return 4;
        }
        if (bytes.len >= 1 and compactIsConstValueOpcode(bytes[0])) {
            const slot = bytes[0] - ck_const_value_base;
            if (slot < constants.len and valueIsMaximumFoldCallable(constants[slot])) return 1;
        }
        if (bytes.len >= 2 and bytes[0] == ck_const_value_u8) {
            const slot = bytes[1];
            if (slot < constants.len and valueIsMaximumFoldCallable(constants[slot])) return 2;
        }
        return null;
    }

    fn compactZeroConstLen(bytes: []const u8) ?usize {
        if (bytes.len >= 2 and bytes[0] == ck_const_i8 and bytes[1] == 0) return 2;
        if (bytes.len >= 9 and bytes[0] == ck_const_i64) {
            const zero = directReadI64(bytes, 1) orelse return null;
            if (zero == 0) return 9;
        }
        return null;
    }

    fn compactArgmaxBytecodeOperandLen(bytes: []const u8, constants: []const Value) ?usize {
        const call1_flags = compactCallFlags(1, false, false);
        const find_op = ckDyad(ckd_find);
        var operand_len: usize = 1;
        while (operand_len < bytes.len) : (operand_len += 1) {
            const middle_len = compactMaximumFoldCallableLen(bytes[operand_len..], constants) orelse continue;
            const right_start = operand_len + middle_len;
            const right_end = right_start + operand_len;
            const call_start = right_end;
            if (call_start + 3 != bytes.len) continue;
            if (bytes[call_start] != ck_call_stack_u8 or bytes[call_start + 1] != call1_flags or bytes[call_start + 2] != find_op) continue;
            if (std.mem.eql(u8, bytes[0..operand_len], bytes[right_start..right_end])) return operand_len;
        }

        const grade_down = ckMonad(ckm_grade_down);
        operand_len = 1;
        while (operand_len < bytes.len) : (operand_len += 1) {
            if (bytes[operand_len] != grade_down) continue;
            const zero_start = operand_len + 1;
            const zero_len = compactZeroConstLen(bytes[zero_start..]) orelse continue;
            const call_start = zero_start + zero_len;
            if (call_start + 2 != bytes.len) continue;
            if (bytes[call_start] == ck_call_stack_u8 and bytes[call_start + 1] == call1_flags) return operand_len;
        }

        return null;
    }

    const DirectConditionalAtom = enum {
        arg0,
        arg1,
        zero,
    };

    const DirectConditionalCompare = struct {
        lhs: DirectConditionalAtom,
        rhs: DirectConditionalAtom,
        cmp: BuiltinId,
    };

    const DenseElementwiseKind = union(enum) {
        dyad: struct {
            op: BuiltinId,
            swap: bool,
        },
        keep_left_if_more,
    };

    const CompactUnarySelfTransform = enum {
        grade_up,
        grade_down,
    };

    const CompactUnaryLiftedKind = struct {
        base: Value,
        transform: CompactUnarySelfTransform,
    };

    fn classifyDenseBuiltin(op: BuiltinId) ?DenseElementwiseKind {
        return switch (op) {
            .add, .sub, .mul, .div, .pow, .minimum, .maximum, .less, .more => .{ .dyad = .{ .op = op, .swap = false } },
            else => null,
        };
    }

    fn applyDenseElementwiseKind(self: *Session, kind: DenseElementwiseKind, arg0: Value, arg1: Value) KError!Value {
        return switch (kind) {
            .dyad => |dyad| blk: {
                const left = if (dyad.swap) arg1 else arg0;
                const right = if (dyad.swap) arg0 else arg1;
                break :blk switch (dyad.op) {
                    .add => try self.addValues(left, right),
                    .sub => try self.subValues(left, right),
                    .mul => try self.mulValues(left, right),
                    .div => try self.divValues(left, right),
                    .pow => try self.powValues(left, right),
                    .minimum => blk2: {
                        const mask = try self.lessValues(left, right);
                        defer self.releaseValue(mask);
                        const delta = try self.subValues(left, right);
                        defer self.releaseValue(delta);
                        const kept = try self.mulValues(mask, delta);
                        defer self.releaseValue(kept);
                        break :blk2 try self.addValues(right, kept);
                    },
                    .maximum => blk2: {
                        const mask = try self.moreValues(left, right);
                        defer self.releaseValue(mask);
                        const delta = try self.subValues(left, right);
                        defer self.releaseValue(delta);
                        const kept = try self.mulValues(mask, delta);
                        defer self.releaseValue(kept);
                        break :blk2 try self.addValues(right, kept);
                    },
                    .less => try self.lessValues(left, right),
                    .more => try self.moreValues(left, right),
                    else => return error.Internal,
                };
            },
            .keep_left_if_more => blk: {
                const mask = try self.moreValues(arg0, arg1);
                defer self.releaseValue(mask);
                break :blk try self.mulValues(arg0, mask);
            },
        };
    }

    fn compactLocalReadSlot(raw: u8) ?u8 {
        if (raw >= ck_load_local_base and raw < ck_load_local_base + ck_range_width) return raw - ck_load_local_base;
        if (raw >= ck_take_local_base and raw < ck_take_local_base + ck_range_width) return raw - ck_take_local_base;
        return null;
    }

    fn compactReadConditionalAtom(bytes: []const u8, idx: *usize) ?DirectConditionalAtom {
        if (idx.* >= bytes.len) return null;
        const raw = bytes[idx.*];
        if (compactLocalReadSlot(raw)) |slot| {
            idx.* += 1;
            return directConditionalAtomFromSlot(slot);
        }
        if (raw == ck_const_false) {
            idx.* += 1;
            return .zero;
        }
        if (raw == ck_const_i8 and idx.* + 1 < bytes.len and bytes[idx.* + 1] == 0) {
            idx.* += 2;
            return .zero;
        }
        return null;
    }

    fn compactReadConditionalCompare(bytes: []const u8, idx: *usize) ?DirectConditionalCompare {
        if (idx.* >= bytes.len) return null;
        const raw = bytes[idx.*];
        switch (raw) {
            ck_more_local_local, ck_less_local_local => {
                if (idx.* + 3 > bytes.len) return null;
                const lhs = directConditionalAtomFromSlot(bytes[idx.* + 1]) orelse return null;
                const rhs = directConditionalAtomFromSlot(bytes[idx.* + 2]) orelse return null;
                idx.* += 3;
                return .{
                    .lhs = lhs,
                    .rhs = rhs,
                    .cmp = if (raw == ck_more_local_local) BuiltinId.more else BuiltinId.less,
                };
            },
            else => {
                const lhs = compactReadConditionalAtom(bytes, idx) orelse return null;
                const rhs = compactReadConditionalAtom(bytes, idx) orelse return null;
                if (idx.* >= bytes.len or !compactIsDyadOpcode(bytes[idx.*])) return null;
                const cmp = switch (bytes[idx.*] - ck_dyad_base) {
                    ckd_more => BuiltinId.more,
                    ckd_less => BuiltinId.less,
                    else => return null,
                };
                idx.* += 1;
                return .{ .lhs = lhs, .rhs = rhs, .cmp = cmp };
            },
        }
    }

    fn classifyCompactDenseConditionalClosure2(bytes: []const u8) ?DenseElementwiseKind {
        if (bytes.len < 2 or bytes[bytes.len - 1] != ck_return) return null;

        var idx: usize = 0;
        const compare = compactReadConditionalCompare(bytes, &idx) orelse return null;
        if (compare.lhs != .arg0 or compare.rhs != .arg1) return null;

        if (idx + 2 > bytes.len or bytes[idx] != ck_jump_if_false_u8) return null;
        const false_target = bytes[idx + 1];
        idx += 2;

        const when_true = compactReadConditionalAtom(bytes, &idx) orelse return null;
        if (idx + 2 > bytes.len or bytes[idx] != ck_jump_u8) return null;
        const end_target = bytes[idx + 1];
        idx += 2;
        if (false_target != idx) return null;

        const when_false = compactReadConditionalAtom(bytes, &idx) orelse return null;
        if (end_target != idx or idx >= bytes.len or bytes[idx] != ck_return or idx + 1 != bytes.len) return null;

        return switch (when_true) {
            .arg0 => switch (when_false) {
                .arg1 => switch (compare.cmp) {
                    .more => .{ .dyad = .{ .op = .maximum, .swap = false } },
                    .less => .{ .dyad = .{ .op = .minimum, .swap = false } },
                    else => null,
                },
                .zero => if (compare.cmp == .more) .keep_left_if_more else null,
                else => null,
            },
            else => null,
        };
    }

    fn compactDenseFixedDyad(raw: u8) ?BuiltinId {
        return switch (raw) {
            ck_add_local_local => .add,
            ck_sub_local_local => .sub,
            ck_mul_local_local => .mul,
            ck_minimum_local_local => .minimum,
            ck_maximum_local_local => .maximum,
            ck_less_local_local => .less,
            ck_more_local_local => .more,
            else => null,
        };
    }

    fn compactDenseDyadRange(raw: u8) ?BuiltinId {
        if (!compactIsDyadOpcode(raw)) return null;
        return switch (raw - ck_dyad_base) {
            ckd_add => .add,
            ckd_sub => .sub,
            ckd_mul => .mul,
            ckd_div => .div,
            ckd_minimum => .minimum,
            ckd_maximum => .maximum,
            ckd_less => .less,
            ckd_more => .more,
            else => null,
        };
    }

    fn classifyCompactDenseElementwiseClosure(closure: *const Closure) ?DenseElementwiseKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const compact = closure.code;
        const bytes = compact.bytes;
        if (bytes.len < 2 or bytes[bytes.len - 1] != ck_return) return null;

        if (bytes.len == 4) {
            if (compactDenseFixedDyad(bytes[0])) |op| {
                const left_slot = bytes[1];
                const right_slot = bytes[2];
                if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
                return .{ .dyad = .{ .op = op, .swap = left_slot == 1 } };
            }
            if (compactLocalReadSlot(bytes[0])) |left_slot| {
                if (compactLocalReadSlot(bytes[1])) |right_slot| {
                    if (!((left_slot == 0 and right_slot == 1) or (left_slot == 1 and right_slot == 0))) return null;
                    const op = compactDenseDyadRange(bytes[2]) orelse return null;
                    return .{ .dyad = .{ .op = op, .swap = left_slot == 1 } };
                }
            }
        }

        return classifyCompactDenseConditionalClosure2(bytes);
    }

    fn directConditionalAtomFromSlot(slot: u8) ?DirectConditionalAtom {
        return switch (slot) {
            0 => .arg0,
            1 => .arg1,
            else => null,
        };
    }

    fn compactReadClosureBaseValue(self: *Session, closure: *const Closure, bytes: []const u8, idx: *usize) KError!?Value {
        if (idx.* >= bytes.len) return null;
        const raw = bytes[idx.*];
        if (compactIsConstValueOpcode(raw)) {
            const slot: usize = raw - ck_const_value_base;
            if (slot >= closure.code.constants.len) return null;
            idx.* += 1;
            return closure.code.constants[slot];
        }
        return switch (raw) {
            ck_const_builtin_u8 => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const builtin: BuiltinId = @enumFromInt(bytes[idx.* + 1]);
                idx.* += 2;
                break :blk Value.builtin(builtin);
            },
            ck_const_value_u8 => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const slot = bytes[idx.* + 1];
                if (slot >= closure.code.constants.len) return null;
                idx.* += 2;
                break :blk closure.code.constants[slot];
            },
            ck_load_global_u8 => blk: {
                if (idx.* + 2 > bytes.len) return null;
                const slot = bytes[idx.* + 1];
                idx.* += 2;
                break :blk try self.loadGlobalSlot(slot);
            },
            else => null,
        };
    }

    fn classifyCompactDenseElementwiseWrapperClosure(self: *Session, closure: *const Closure) KError!?DenseElementwiseKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const compact = closure.code;
        const bytes = compact.bytes;
        if (bytes.len < 6 or bytes[bytes.len - 1] != ck_return) return null;

        var idx: usize = 0;
        const base_value = (try self.compactReadClosureBaseValue(closure, bytes, &idx)) orelse return null;
        if (idx + 7 != bytes.len) return null;
        if (bytes[idx] != ck_make_adverb_u8 or bytes[idx + 1] != @intFromEnum(DerivedVerbKind.each)) return null;
        idx += 2;
        const left_slot = compactLocalReadSlot(bytes[idx]) orelse return null;
        idx += 1;
        const right_slot = compactLocalReadSlot(bytes[idx]) orelse return null;
        idx += 1;
        if (left_slot != 0 or right_slot != 1) return null;
        if ((compactReadCallStackArgc(bytes, &idx) orelse return null) != 2) return null;
        if (idx >= bytes.len or bytes[idx] != ck_return or idx + 1 != bytes.len) return null;

        return try self.classifyDenseElementwiseBaseRuntime(base_value);
    }

    fn classifyDenseElementwiseClosureRuntime(self: *Session, closure: *const Closure) KError!?DenseElementwiseKind {
        if (classifyCompactDenseElementwiseClosure(closure)) |kind| return kind;
        return try self.classifyCompactDenseElementwiseWrapperClosure(closure);
    }

    fn classifyDenseElementwiseBaseRuntime(self: *Session, base: Value) KError!?DenseElementwiseKind {
        return switch (base.tag()) {
            .builtin => classifyDenseBuiltin(base.asBuiltin()),
            .closure => try self.classifyDenseElementwiseClosureRuntime(base.asClosure()),
            else => null,
        };
    }

    fn compactReadUnarySelfTransform(bytes: []const u8, idx: *usize) ?CompactUnarySelfTransform {
        if (idx.* + 2 > bytes.len) return null;
        if ((compactLocalReadSlot(bytes[idx.*]) orelse return null) != 0) return null;
        const raw = bytes[idx.* + 1];
        if (!compactIsMonadOpcode(raw)) return null;
        idx.* += 2;
        return switch (raw - ck_monad_base) {
            ckm_grade_up => .grade_up,
            ckm_grade_down => .grade_down,
            else => null,
        };
    }

    fn compactReadCallStackArgc(bytes: []const u8, idx: *usize) ?u8 {
        if (idx.* + 2 > bytes.len or bytes[idx.*] != ck_call_stack_u8) return null;
        const flags = bytes[idx.* + 1];
        if (compactCallStoresLocal(flags)) return null;
        idx.* += 2;
        return compactCallArgc(flags);
    }

    fn classifyCompactUnaryLiftedClosure(self: *Session, closure: *const Closure) KError!?CompactUnaryLiftedKind {
        if (closure.header.owner != .frozen or closure.captures.len != 0) return null;
        const compact = closure.code;
        const bytes = compact.bytes;
        if (bytes.len < 8 or bytes[bytes.len - 1] != ck_return) return null;

        var idx: usize = 0;
        const base_value = (try self.compactReadClosureBaseValue(closure, bytes, &idx)) orelse return null;
        if (idx + 2 > bytes.len or bytes[idx] != ck_make_adverb_u8) return null;
        const kind: DerivedVerbKind = @enumFromInt(bytes[idx + 1]);
        if (kind != .each_right) return null;
        idx += 2;

        const transform = compactReadUnarySelfTransform(bytes, &idx) orelse return null;
        const second = compactReadUnarySelfTransform(bytes, &idx) orelse return null;
        if (transform != second) return null;

        if (idx + 3 != bytes.len) return null;
        if ((compactReadCallStackArgc(bytes, &idx) orelse return null) != 2) return null;
        if (bytes[idx] != ck_return) return null;

        _ = try self.classifyDenseElementwiseBaseRuntime(base_value) orelse return null;
        return .{ .base = base_value, .transform = transform };
    }

    fn applyCompactUnaryLiftedKind(self: *Session, kind: CompactUnaryLiftedKind, arg0: Value) KError!Value {
        const transformed = switch (kind.transform) {
            .grade_up => try self.gradeValue(arg0, true),
            .grade_down => try self.gradeValue(arg0, false),
        };
        defer self.releaseValue(transformed);
        return try self.applyEachRightDerived(kind.base, &[_]Value{ transformed, transformed });
    }

    fn hostStringListItemValue(self: *Session, list: *const HostStringList, idx: usize) KError!Value {
        if (idx >= list.len) return error.Type;
        if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_value_count += 1;
        const item = switch (list.storage) {
            .eager => |items| switch (items[idx]) {
                .owned => |text| blk: {
                    if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_eager_owned_count += 1;
                    break :blk try self.retainEscapedValue(Value.array(text));
                },
                .view => |view| blk: {
                    if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_eager_view_count += 1;
                    const base = list.base orelse return error.Internal;
                    break :blk try self.managedHostStringViewWithReason(base, view, .string_list_eager_view);
                },
            },
            .split_scalar => |lazy| blk: {
                if (comptime enable_probe_instrumentation) self.debug_host_string_list_item_split_scalar_count += 1;
                const base = list.base orelse return error.Internal;
                const src = hostTextBytes(base);
                var piece_idx: usize = 0;
                var start: usize = 0;
                var scanned_bytes: usize = 0;
                var scanned_seps: usize = 0;
                while (std.mem.indexOfScalarPos(u8, src, start, lazy.sep)) |sep_idx| {
                    scanned_bytes += sep_idx - start + 1;
                    scanned_seps += 1;
                    if (piece_idx == idx) {
                        if (comptime enable_probe_instrumentation) {
                            self.debug_host_string_list_item_split_scalar_scan_byte_count += scanned_bytes;
                            self.debug_host_string_list_item_split_scalar_scan_sep_count += scanned_seps;
                        }
                        break :blk try self.managedHostStringViewWithReason(base, .{
                            .start = start,
                            .len = sep_idx - start,
                        }, .string_list_split_scalar);
                    }
                    piece_idx += 1;
                    start = sep_idx + 1;
                }
                if (piece_idx != idx) return error.Type;
                scanned_bytes += src.len - start;
                if (comptime enable_probe_instrumentation) {
                    self.debug_host_string_list_item_split_scalar_scan_byte_count += scanned_bytes;
                    self.debug_host_string_list_item_split_scalar_scan_sep_count += scanned_seps;
                }
                break :blk try self.managedHostStringViewWithReason(base, .{
                    .start = start,
                    .len = src.len - start,
                }, .string_list_split_scalar);
            },
        };
        if (list.display == .split_list) {
            if (stringBytes(item)) |bytes| {
                if (bytes.len == 1) {
                    const vector = try self.managedHostCharVector(bytes);
                    self.releaseValue(item);
                    return vector;
                }
            }
        }
        return item;
    }

    fn hostSymbolListItemValue(self: *Session, list: *const HostStringList, idx: usize) KError!Value {
        return try self.managedHostSymbol(try hostStringListItemBytes(list, idx));
    }

    fn hostTextListItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        if (stringSourceInfo(value)) |source| return try self.stringIndexScalarValue(source, @intCast(idx));
        if (value.tag() != .array) return error.Type;
        return switch (value.arrayKind()) {
            .host_string_list => try self.hostStringListItemValue(value.asHostStringList(), idx),
            .host_symbol_list => try self.hostSymbolListItemValue(value.asHostStringList(), idx),
            else => error.Type,
        };
    }

    fn derivedSequenceLen(value: Value) ?usize {
        if (value.tag() != .array) return null;
        if (value.arrayKind() == .host_keyed_store) return null;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank == 0) return null;
            return @intCast(handle.shape[0]);
        }
        if (numericVectorLen(value)) |len| return len;
        if (value.arraySubkind() == .host_string_list) return value.asHostStringList().len;
        if (value.arraySubkind() == .host_symbol_list) return value.asHostStringList().len;
        if (value.arraySubkind() == .host_boxed_array) {
            return value.asHostBoxedArray().len();
        }
        return null;
    }

    fn derivedSequenceItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        if (value.tag() != .array) return error.Type;
        if (value.arrayKind() == .host_keyed_store) return error.Type;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank > 1) {
                return (try numericValueScalarIndexValue(self, value, @intCast(idx))) orelse error.Type;
            }
        }
        if (valueNumericMatrixShape(value) != null) {
            return (try numericValueScalarIndexValue(self, value, @intCast(idx))) orelse error.Type;
        }
        if (numericVectorLen(value) != null) {
            return try self.derivedDenseVectorItemValue(value, idx);
        }
        if (value.arraySubkind() == .host_string_list) {
            return try self.hostStringListItemValue(value.asHostStringList(), idx);
        }
        if (value.arraySubkind() == .host_symbol_list) {
            return try self.hostSymbolListItemValue(value.asHostStringList(), idx);
        }
        if (value.arraySubkind() == .host_boxed_array) {
            return try self.hostBoxedArrayIndexScalar(value.asHostBoxedArray(), @intCast(idx));
        }
        return error.Type;
    }

    fn derivedDenseVectorItemValue(self: *Session, value: Value, idx: usize) KError!Value {
        const view = try hostDenseView(self, value);
        return switch (valueNumericMode(value) orelse return error.Type) {
            .int => switch (view) {
                .scalar_int => |item| blk: {
                    if (idx != 0) return error.Internal;
                    break :blk try self.intValue(item);
                },
                .int_array => |items| try self.intValue(try hostIntDenseViewItem(items, idx)),
                else => error.Type,
            },
            .float => switch (view) {
                .scalar_float => |item| blk: {
                    if (idx != 0) return error.Internal;
                    break :blk switch (valueFloatStorageKind(value) orelse .float64) {
                        .float32 => try self.float32Value(@floatCast(item)),
                        .float64 => try self.floatValue(item),
                    };
                },
                .float_array => |items| blk: {
                    const item = try hostFloatDenseViewItem(items, idx);
                    break :blk switch (valueFloatStorageKind(value) orelse .float64) {
                        .float32 => try self.float32Value(@floatCast(item)),
                        .float64 => try self.floatValue(item),
                    };
                },
                else => error.Type,
            },
        };
    }

    fn releaseDerivedStepArgs(self: *Session, source_args: []const Value, step_args: []const Value, start_idx: usize) void {
        for (source_args[start_idx..], start_idx..) |arg, arg_idx| {
            if (derivedSequenceLen(arg) != null) self.releaseValue(step_args[arg_idx]);
        }
    }

    fn createManagedArrayLikeFromValues(self: *Session, values: []const Value) KError!Value {
        return try self.makeArrayFromValues(values);
    }

    fn nextSamplingProfileCodeId(self: *Session) u16 {
        if (comptime !enable_sampling_profile) {
            return sampling_profile_no_code;
        }
        if (self.next_profile_code_id >= sampling_profile_max_code_count) return sampling_profile_no_code;
        const id = self.next_profile_code_id;
        self.next_profile_code_id += 1;
        return id;
    }

    fn rememberSamplingProfileCodeInfo(self: *Session, id: u16, kind: SamplingProfileCodeKind, source: []const u8) void {
        if (comptime !enable_sampling_profile) {
            return;
        }
        if (id == sampling_profile_no_code) return;
        if (staticSamplingProfileCodeInfo(id) != null) return;
        if (id >= self.profile_dynamic_code_used.len) return;
        self.profile_dynamic_code_infos[id] = .{
            .id = id,
            .kind = kind,
            .source = source,
        };
        self.profile_dynamic_code_used[id] = true;
    }

    fn invokeValueInCurrentRun(self: *Session, callee: Value, args: []const Value) KError!Value {
        _ = self;
        _ = callee;
        _ = args;
        return error.Unsupported;
    }

    fn invokeClosureInCurrentRun(self: *Session, callee: Value, closure: *const Closure, args: []const Value) KError!Value {
        _ = self;
        _ = callee;
        if (closure.code.arity != args.len) return error.Arity;
        return error.Unsupported;
    }

    fn applyDerivedBase(self: *Session, callee: Value, args: []const Value) KError!Value {
        if (try self.tryApplyAllAxisCallableProjection(callee, args)) |projection| return projection;
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), args),
            .array => try self.applyArrayCall(callee, args),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.tryProjectPlainClosureUnderApplication(callee, closure, args)) |projection| break :blk projection;
                if (codeForRunnablePlainClosureArgs(closure, args)) |compact| break :blk try self.runCodeBorrowed(compact, codeRunArgs(compact, args));
                if (try self.tryApplyOwnedClosureArgs(closure, args)) |result| break :blk result;
                break :blk try self.invokeClosureInCurrentRun(callee, closure, args);
            },
            else => error.Type,
        };
    }

    fn projectionInfoFromClosure(self: *Session, closure: *const Closure) KError!?ProjectionInfo {
        _ = self;
        if (!closureIsProjection(closure)) return null;
        if (closure.captures.len < 3) return error.Internal;
        const slot_count_i64 = scalarIntLikeValue(closure.captures[1]) orelse return error.Internal;
        const hole_mask_i64 = scalarIntLikeValue(closure.captures[2]) orelse return error.Internal;
        if (slot_count_i64 < 0) return error.Internal;
        const slot_count = std.math.cast(usize, slot_count_i64) orelse return error.Internal;
        if (slot_count > 63) return error.Unsupported;
        const hole_mask = std.math.cast(u64, hole_mask_i64) orelse return error.Internal;
        if ((hole_mask >> @intCast(slot_count)) != 0) return error.Internal;
        if (closure.captures.len != 3 + slot_count) return error.Internal;
        return .{
            .callee = closure.captures[0],
            .slot_count = slot_count,
            .hole_mask = hole_mask,
            .slot_values = closure.captures[3..],
        };
    }

    fn innerProductInfoFromClosure(self: *Session, closure: *const Closure) KError!?InnerProductInfo {
        _ = self;
        if (!closureIsInnerProduct(closure)) return null;
        if (closure.captures.len != 2) return error.Internal;
        if (closure.captures[0].tag() != .builtin or closure.captures[1].tag() != .builtin) return error.Internal;
        return .{
            .reduce = closure.captures[0].asBuiltin(),
            .map = closure.captures[1].asBuiltin(),
        };
    }

    fn compositionInfoFromClosure(self: *Session, closure: *const Closure) KError!?CompositionInfo {
        _ = self;
        if (closure.kind != .composition) return null;
        if (closure.captures.len != 2) return error.Internal;
        return .{
            .outer = closure.captures[0],
            .inner = closure.captures[1],
        };
    }

    fn tryApplyStructuredDerivedClosure2(self: *Session, closure: *const Closure, arg0: Value, arg1: Value) KError!?Value {
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            if (info.reduce != .add or info.map != .mul) return null;
            if (numericVectorLen(arg0) == null or numericVectorLen(arg1) == null) return null;
            if (self.debugDetailedProbeActive()) self.debug_structured_derived2_hit_count += 1;
            return try self.applyMatmulValues(arg0, arg1);
        }

        const kind = closureDerivedKind(closure) orelse return null;
        if (kind != .each_left or closure.captures.len != 1) return null;
        const base = closure.captures[0];
        if (base.tag() != .closure) return null;
        const base_info = (try self.innerProductInfoFromClosure(base.asClosure())) orelse return null;
        if (base_info.reduce != .add or base_info.map != .mul) return null;
        if (!valueIsRenderableMatrixLike(arg0)) return null;
        if (self.debugDetailedProbeActive()) self.debug_structured_derived2_hit_count += 1;
        return try self.applyMatmulValues(arg0, arg1);
    }

    fn materializeSequenceItems(self: *Session, value: Value) KError![]Value {
        var items = std.ArrayList(Value).empty;
        errdefer {
            for (items.items) |item| self.releaseValue(item);
            items.deinit(self.allocator);
        }

        if (derivedSequenceLen(value)) |len| {
            try items.ensureTotalCapacity(self.allocator, len);
            for (0..len) |idx| try items.append(self.allocator, try self.derivedSequenceItemValue(value, idx));
        } else {
            try items.append(self.allocator, try self.retainEscapedValue(value));
        }

        return try items.toOwnedSlice(self.allocator);
    }

    fn deepIndexValue(self: *Session, base: Value, selectors: []const Value) KError!Value {
        if (selectors.len == 0) return self.shareValue(base);
        if (isAllAxisSelectorValue(selectors[0])) {
            if (selectors.len == 1) return self.shareValue(base);
            return try self.deepIndexAllAxisValue(base, selectors[1..]);
        }
        var current = try self.applyArrayCall1(base, selectors[0]);
        var idx: usize = 1;
        while (idx < selectors.len) : (idx += 1) {
            if (isAllAxisSelectorValue(selectors[idx])) {
                if (idx + 1 == selectors.len) return current;
                const next = try self.deepIndexAllAxisValue(current, selectors[idx + 1 ..]);
                self.releaseValue(current);
                return next;
            }
            const next = try self.applyArrayCall1(current, selectors[idx]);
            self.releaseValue(current);
            current = next;
        }
        return current;
    }

    fn deepIndexAllAxisValue(self: *Session, base: Value, rest: []const Value) KError!Value {
        const items = try self.materializeTopLevelItems(base);
        defer {
            for (items) |value| self.releaseValue(value);
            self.allocator.free(items);
        }

        for (items, 0..) |item, idx| {
            const selected = try self.deepIndexValue(item, rest);
            self.releaseValue(items[idx]);
            items[idx] = selected;
        }

        const result = try self.makeArrayFromValues(items);
        if (try self.promoteRenderableMatrixValue(result)) |promoted| {
            if (promoted.raw != result.raw and isManagedValue(result)) self.releaseValue(result);
            return promoted;
        }
        return result;
    }

    const AmendKind = enum {
        unary,
        assign,
        binary,
        deep_unary,
        deep_assign,
        deep_binary,
    };

    const IndexedAssignTarget = union(enum) {
        global: u16,
        local: u8,
    };

    const SymbolTargetName = struct {
        bytes: []const u8,
        owned: bool = false,
    };

    fn releaseSymbolTargetName(self: *Session, name: SymbolTargetName) void {
        if (name.owned) self.allocator.free(name.bytes);
    }

    fn symbolTargetName(self: *Session, value: Value) KError!?SymbolTargetName {
        if (symbolBytes(value)) |name| return .{ .bytes = name };
        if (value.tag() != .array or value.arrayKind() != .host_symbol_list) return null;
        const list = value.asHostStringList();
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);
        for (0..list.len) |idx| {
            if (idx != 0) try out.append(self.allocator, '.');
            try out.appendSlice(self.allocator, try hostStringListItemBytes(list, idx));
        }
        return .{ .bytes = try out.toOwnedSlice(self.allocator), .owned = true };
    }

    fn namespaceChildForParent(parent_path: []const u8, global_name: []const u8) ?[]const u8 {
        if (parent_path.len == 0) {
            if (std.mem.indexOfScalar(u8, global_name, '.') != null) return null;
            return global_name;
        }

        const dot_index = std.mem.lastIndexOfScalar(u8, global_name, '.') orelse return null;
        if (!std.mem.eql(u8, global_name[0..dot_index], parent_path)) return null;
        return global_name[dot_index + 1 ..];
    }

    fn namespaceKeysValue(self: *Session, value: Value) KError!?Value {
        const name = (try self.symbolTargetName(value)) orelse return null;
        defer self.releaseSymbolTargetName(name);

        var children = std.ArrayList([]const u8).empty;
        defer children.deinit(self.allocator);

        for (self.global_names.items, 0..) |global_name, idx| {
            if (idx >= self.global_cells.items.len or !self.global_cells.items[idx].initialized) continue;
            const child = namespaceChildForParent(name.bytes, global_name) orelse continue;
            var seen = false;
            for (children.items) |existing| {
                if (std.mem.eql(u8, existing, child)) {
                    seen = true;
                    break;
                }
            }
            if (!seen) try children.append(self.allocator, child);
        }

        return try self.createManagedHostSymbolListFromSlices(children.items);
    }

    fn tryApplySymbolTargetAmend(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!?Value {
        const mode: ShallowAmendMode = switch (kind) {
            .deep_unary => .unary,
            .deep_assign => .assign,
            .deep_binary => .binary,
            else => return null,
        };
        const name = (try self.symbolTargetName(base)) orelse return null;
        defer self.releaseSymbolTargetName(name);

        const selectors = try self.materializeSelectorPath(selector);
        defer self.releaseArgs(selectors);

        const slot = try self.internGlobalSlot(name.bytes);
        const amended = if (selectors.len == 0 and mode == .assign)
            try self.applyWholeAmend(Value.fromBool(false), mode, func_or_value, arg)
        else blk: {
            const current = try self.loadGlobalSlot(slot);
            break :blk try self.applyDeepAmend(current, selectors, mode, func_or_value, arg);
        };
        errdefer self.releaseValue(amended);
        try self.storeGlobalSlot(slot, amended);
        return amended;
    }

    fn applyAmend(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!Value {
        if (try self.tryApplyCallableTryAmend(base, selector, kind, func_or_value)) |result| return result;
        if (try self.tryApplySymbolTargetAmend(base, selector, kind, func_or_value, arg)) |amended| return amended;
        if (try self.tryApplyIndexedSelectorPathAmend(base, selector, kind, func_or_value, arg)) |amended| return amended;
        return switch (kind) {
            .unary => try self.applyShallowAmend(base, selector, .unary, func_or_value, arg),
            .assign => try self.applyShallowAmend(base, selector, .assign, func_or_value, arg),
            .binary => try self.applyShallowAmend(base, selector, .binary, func_or_value, arg),
            .deep_unary, .deep_assign, .deep_binary => blk: {
                const mode: ShallowAmendMode = switch (kind) {
                    .deep_unary => .unary,
                    .deep_assign => .assign,
                    .deep_binary => .binary,
                    else => unreachable,
                };
                const selectors = try self.materializeSelectorPath(selector);
                defer self.releaseArgs(selectors);
                break :blk try self.applyDeepAmend(base, selectors, mode, func_or_value, arg);
            },
        };
    }

    fn tryApplyCallableTryAmend(self: *Session, base: Value, selector: Value, kind: AmendKind, handler: Value) KError!?Value {
        switch (kind) {
            .unary, .deep_unary => {},
            .assign, .binary, .deep_assign, .deep_binary => return null,
        }
        switch (base.tag()) {
            .builtin, .closure => {},
            else => return null,
        }
        return self.applyDot(base, selector) catch |err| switch (err) {
            error.OutOfMemory, error.Internal => err,
            else => try self.retainEscapedValue(handler),
        };
    }

    fn applyAmendOwned(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_owned_amend_count += 1;
        errdefer self.releaseCanonicalManagedNumericValue(base);
        const result = try self.applyAmend(base, selector, kind, func_or_value, arg);
        self.releaseCanonicalManagedNumericValue(base);
        return result;
    }

    const ShallowAmendMode = enum {
        unary,
        assign,
        binary,
    };

    fn materializeIndexedSelectorPath(self: *Session, selector: Value) KError!?[]Value {
        const boxed = boxedArrayItems(selector) orelse return null;
        if (boxed.len == 0 or !isSelectorPathMarkerValue(boxed[0])) return null;
        const items = try self.allocator.alloc(Value, boxed.len - 1);
        errdefer self.allocator.free(items);
        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |value| self.releaseValue(value);
        }
        for (boxed[1..], 0..) |value, idx| {
            items[idx] = try self.retainEscapedValue(value);
            initialized += 1;
        }
        return items;
    }

    fn tryApplyIndexedSelectorPathAmend(self: *Session, base: Value, selector: Value, kind: AmendKind, func_or_value: Value, arg: Value) KError!?Value {
        const mode: ShallowAmendMode = switch (kind) {
            .unary, .deep_unary => .unary,
            .assign, .deep_assign => .assign,
            .binary, .deep_binary => .binary,
        };
        const selectors = (try self.materializeIndexedSelectorPath(selector)) orelse return null;
        defer self.releaseArgs(selectors);
        return try self.applyDeepAmend(base, selectors, mode, func_or_value, arg);
    }

    fn materializeSelectorPath(self: *Session, selector: Value) KError![]Value {
        var items = std.ArrayList(Value).empty;
        errdefer {
            for (items.items) |value| self.releaseValue(value);
            items.deinit(self.allocator);
        }

        switch (selector.tag()) {
            .int, .bool => {
                try items.append(self.allocator, try self.retainEscapedValue(selector));
            },
            .array => if (boxedArrayItems(selector)) |boxed| {
                for (boxed) |value| try items.append(self.allocator, try self.retainEscapedValue(value));
            } else switch (selector.arrayKind()) {
                .host_dense_array, .backend_array, .numeric_array => {
                    if (valueNonVectorNumericShape(selector) != null) {
                        const rows = try self.materializeTopLevelItems(selector);
                        defer self.releaseArgs(rows);
                        for (rows) |value| try items.append(self.allocator, try self.retainEscapedValue(value));
                    } else {
                        const array = try numericHostArrayValue(self, selector);
                        const len = array.len();
                        for (0..len) |idx| {
                            try items.append(self.allocator, try self.hostDenseIndexScalar(array, @intCast(idx)));
                        }
                    }
                },
                else => return error.Type,
            },
            else => return error.Type,
        }

        return try items.toOwnedSlice(self.allocator);
    }

    fn applyDeepAmend(self: *Session, base: Value, selectors: []const Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        if (selectors.len == 0) return try self.applyWholeAmend(base, mode, func_or_value, arg);
        if (isAllAxisSelectorValue(selectors[0])) {
            if (selectors.len == 1) return try self.applyShallowAmend(base, selectors[0], mode, func_or_value, arg);
            return try self.applyDeepAmendAllAxis(base, selectors[1..], mode, func_or_value, arg);
        }
        if (selectors.len == 1) return try self.applyShallowAmend(base, selectors[0], mode, func_or_value, arg);

        const selected = try self.applyArrayCall1(base, selectors[0]);
        defer self.releaseValue(selected);
        const amended = try self.applyDeepAmend(selected, selectors[1..], mode, func_or_value, arg);
        defer self.releaseValue(amended);
        return try self.applyShallowAmend(base, selectors[0], .assign, amended, Value.fromBool(false));
    }

    fn applyDeepAmendAllAxis(self: *Session, base: Value, rest: []const Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        const items = try self.materializeTopLevelItems(base);
        defer {
            for (items) |value| self.releaseValue(value);
            self.allocator.free(items);
        }

        var rhs_items: ?[]Value = null;
        defer if (rhs_items) |values| {
            for (values) |value| self.releaseValue(value);
            self.allocator.free(values);
        };
        if (mode != .unary) {
            const rhs_source = if (mode == .assign) func_or_value else arg;
            if (rhs_source.tag() == .array) {
                const maybe = try self.tryMaterializeTopLevelItems(rhs_source);
                if (maybe) |values| {
                    if (values.len == items.len) rhs_items = values else {
                        for (values) |value| self.releaseValue(value);
                        self.allocator.free(values);
                    }
                }
            }
        }

        for (items, 0..) |item, idx| {
            const child_func_or_value = if (mode == .assign)
                if (rhs_items) |values| values[idx] else func_or_value
            else
                func_or_value;
            const child_arg = if (mode == .binary)
                if (rhs_items) |values| values[idx] else arg
            else
                arg;
            const amended = try self.applyDeepAmend(item, rest, mode, child_func_or_value, child_arg);
            self.releaseValue(items[idx]);
            items[idx] = amended;
        }

        return try self.rebuildTopLevelItems(base, items);
    }

    const DenseAssignRhs = union(enum) {
        int_scalar: i64,
        float_scalar: f64,
        int_vector: HostIntArrayView,
        float_vector: []const f64,
    };

    const DenseAssignTargets = union(enum) {
        scalar: usize,
        slice: []const usize,
    };

    fn amendCloneOwner(base: Value) HeapOwner {
        std.debug.assert(base.tag() == .array);
        return switch (base.arrayOwner()) {
            .scratch => .scratch,
            .managed, .frozen => .managed,
        };
    }

    fn hostIntKindCanRepresent(kind: HostIntStorageKind, value: i64) bool {
        return switch (kind) {
            .bit => value == 0 or value == 1,
            .int8 => std.math.cast(i8, value) != null,
            .int16 => std.math.cast(i16, value) != null,
            .int32 => std.math.cast(i32, value) != null,
            .int64 => true,
        };
    }

    fn denseAssignRhs(self: *Session, rhs_source: Value, selectors_len: usize) KError!?DenseAssignRhs {
        if (scalarIntLikeValue(rhs_source)) |value| return .{ .int_scalar = value };
        if (rhs_source.tag() == .float) return .{ .float_scalar = rhs_source.asFloat() };
        if (rhs_source.tag() != .array) return null;
        if (valueNonVectorNumericShape(rhs_source) != null) return null;
        const rhs_array = try numericHostArrayValue(self, rhs_source);
        if (rhs_array.len() != selectors_len) return null;
        return switch (hostDenseNumericMode(rhs_array)) {
            .int => .{ .int_vector = hostIntArrayView(rhs_array) orelse return null },
            .float => switch (rhs_array.storage) {
                .float64 => |items| .{ .float_vector = hostDenseLogicalItems(f64, rhs_array, items) },
                else => null,
            },
        };
    }

    fn denseAssignRhsFitsIntKind(kind: HostIntStorageKind, selectors_len: usize, rhs: DenseAssignRhs) bool {
        return switch (rhs) {
            .int_scalar => |value| hostIntKindCanRepresent(kind, value),
            .float_scalar => |value| blk: {
                const int_value = exactIntFromFloat(value) orelse break :blk false;
                break :blk hostIntKindCanRepresent(kind, int_value);
            },
            .int_vector => |view| blk: {
                std.debug.assert(hostIntArrayViewLen(view) == selectors_len);
                for (0..selectors_len) |idx| {
                    if (!hostIntKindCanRepresent(kind, hostIntViewItem(view, idx))) break :blk false;
                }
                break :blk true;
            },
            .float_vector => |items| blk: {
                std.debug.assert(items.len == selectors_len);
                for (items) |item| {
                    const int_value = exactIntFromFloat(item) orelse break :blk false;
                    if (!hostIntKindCanRepresent(kind, int_value)) break :blk false;
                }
                break :blk true;
            },
        };
    }

    fn denseAssignTargetsLen(targets: DenseAssignTargets) usize {
        return switch (targets) {
            .scalar => 1,
            .slice => |selectors| selectors.len,
        };
    }

    fn recordFastDenseAssignHit(self: *Session, targets: DenseAssignTargets, rhs: DenseAssignRhs, reused: bool) void {
        if (comptime !enable_probe_instrumentation) return;
        self.debug_fast_dense_assign_hit_count += 1;
        if (reused) self.debug_fast_dense_assign_reuse_count += 1;
        self.debug_fast_dense_assign_target_element_count += denseAssignTargetsLen(targets);
        switch (targets) {
            .scalar => self.debug_fast_dense_assign_scalar_target_count += 1,
            .slice => self.debug_fast_dense_assign_vector_target_count += 1,
        }
        switch (rhs) {
            .int_scalar, .float_scalar => self.debug_fast_dense_assign_scalar_rhs_count += 1,
            .int_vector, .float_vector => self.debug_fast_dense_assign_vector_rhs_count += 1,
        }
    }

    fn denseAssignIntScalarValue(rhs: DenseAssignRhs) KError!i64 {
        return switch (rhs) {
            .int_scalar => |value| value,
            .float_scalar => |value| exactIntFromFloat(value) orelse return error.Unsupported,
            .int_vector => |view| blk: {
                std.debug.assert(hostIntArrayViewLen(view) == 1);
                break :blk hostIntViewItem(view, 0);
            },
            .float_vector => |items| blk: {
                std.debug.assert(items.len == 1);
                break :blk exactIntFromFloat(items[0]) orelse return error.Unsupported;
            },
        };
    }

    fn denseAssignFloatScalarValue(rhs: DenseAssignRhs) f64 {
        return switch (rhs) {
            .int_scalar => |value| @as(f64, @floatFromInt(value)),
            .float_scalar => |value| value,
            .int_vector => |view| blk: {
                std.debug.assert(hostIntArrayViewLen(view) == 1);
                break :blk @as(f64, @floatFromInt(hostIntViewItem(view, 0)));
            },
            .float_vector => |items| blk: {
                std.debug.assert(items.len == 1);
                break :blk items[0];
            },
        };
    }

    fn denseAssignScalarIntLike(rhs_source: Value) ?i64 {
        if (scalarIntLikeValue(rhs_source)) |value| return value;
        if (rhs_source.tag() == .float) return exactIntFromFloat(rhs_source.asFloat());
        return null;
    }

    fn denseAssignScalarFloatLike(rhs_source: Value) ?f64 {
        if (scalarIntLikeValue(rhs_source)) |value| return @floatFromInt(value);
        if (rhs_source.tag() == .float) return rhs_source.asFloat();
        return null;
    }

    fn applyDenseAssignIntScalar(out: *HostIntResult, target_idx: usize, item_value: i64) KError!void {
        switch (out.*) {
            .bit => |*bits| switch (item_value) {
                0 => bitSet(bits.words, target_idx, false),
                1 => bitSet(bits.words, target_idx, true),
                else => return error.Unsupported,
            },
            .int8 => |*items| items.items[target_idx] = std.math.cast(i8, item_value) orelse return error.Unsupported,
            .int16 => |*items| items.items[target_idx] = std.math.cast(i16, item_value) orelse return error.Unsupported,
            .int32 => |*items| items.items[target_idx] = std.math.cast(i32, item_value) orelse return error.Unsupported,
            .int64 => |*items| items.items[target_idx] = item_value,
        }
    }

    fn applyDenseAssignIntRhs(out: *HostIntResult, targets: DenseAssignTargets, rhs: DenseAssignRhs) KError!void {
        switch (targets) {
            .scalar => |target_idx| try applyDenseAssignIntScalar(out, target_idx, try denseAssignIntScalarValue(rhs)),
            .slice => |selectors| switch (rhs) {
                .int_scalar => |value| {
                    for (selectors) |target_idx| try applyDenseAssignIntScalar(out, target_idx, value);
                },
                .float_scalar => |value| {
                    const int_value = exactIntFromFloat(value) orelse return error.Unsupported;
                    for (selectors) |target_idx| try applyDenseAssignIntScalar(out, target_idx, int_value);
                },
                .int_vector => |view| {
                    std.debug.assert(hostIntArrayViewLen(view) == selectors.len);
                    for (selectors, 0..) |target_idx, idx| try applyDenseAssignIntScalar(out, target_idx, hostIntViewItem(view, idx));
                },
                .float_vector => |items| {
                    std.debug.assert(items.len == selectors.len);
                    for (selectors, 0..) |target_idx, idx| {
                        const int_value = exactIntFromFloat(items[idx]) orelse return error.Unsupported;
                        try applyDenseAssignIntScalar(out, target_idx, int_value);
                    }
                },
            },
        }
    }

    fn applyDenseAssignFloatRhs(out: []f64, targets: DenseAssignTargets, rhs: DenseAssignRhs) void {
        switch (targets) {
            .scalar => |target_idx| out[target_idx] = denseAssignFloatScalarValue(rhs),
            .slice => |selectors| switch (rhs) {
                .int_scalar => |value| {
                    const float_value = @as(f64, @floatFromInt(value));
                    for (selectors) |target_idx| out[target_idx] = float_value;
                },
                .float_scalar => |value| {
                    for (selectors) |target_idx| out[target_idx] = value;
                },
                .int_vector => |view| {
                    std.debug.assert(hostIntArrayViewLen(view) == selectors.len);
                    for (selectors, 0..) |target_idx, idx| out[target_idx] = @as(f64, @floatFromInt(hostIntViewItem(view, idx)));
                },
                .float_vector => |items| {
                    std.debug.assert(items.len == selectors.len);
                    for (selectors, 0..) |target_idx, idx| out[target_idx] = items[idx];
                },
            },
        }
    }

    fn prepareReusableHostDenseForMutation(self: *Session, source: Value) bool {
        const handle = valueNumericHandle(source) orelse return true;
        const mutable_handle = @constCast(handle);
        if (numericBackendAttachment(handle) != null) {
            if (mutable_handle.header.owner != .managed) return false;
            self.evictBackendAttachment(mutable_handle);
        }
        mutable_handle.preferred = .host;
        syncNumericArrayChildren(mutable_handle);
        return true;
    }

    fn recordFastDenseAssignMiss(self: *Session) void {
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_miss_count += 1;
    }

    fn recordFastDenseAssignClone(self: *Session, base: Value) void {
        if (comptime !enable_probe_instrumentation) return;
        self.debug_fast_dense_assign_clone_count += 1;

        if (mutableNumericHandle(base)) |handle| {
            switch (handle.header.owner) {
                .managed => {
                    if (handle.header.ref_count != 1) {
                        self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.non_unique)] += 1;
                        return;
                    }
                },
                .frozen => {
                    self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.frozen)] += 1;
                    return;
                },
                .scratch => {},
            }
        } else if (hostDenseIfPresent(base)) |host| {
            switch (host.header.owner) {
                .managed => {
                    if (host.header.ref_count != 1) {
                        self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.non_unique)] += 1;
                        return;
                    }
                },
                .frozen => {
                    self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.frozen)] += 1;
                    return;
                },
                .scratch => {},
            }
        }

        self.debug_fast_dense_assign_clone_reason_counts[@intFromEnum(DebugFastDenseAssignCloneReason.other)] += 1;
    }

    fn finishFastDenseScalarIntAssign(self: *Session, target_idx: usize, rhs: DenseAssignRhs, out: *HostIntResult, reused: bool) KError!Value {
        const host = out.arrayPtr();
        hostDenseSetFlags(host, host_dense_flag_normalized);
        self.invalidateHostDenseCachesForMutation(host);
        const value = try out.value(self);
        self.recordFastDenseAssignHit(.{ .scalar = target_idx }, rhs, reused);
        return if (reused) self.shareValue(value) else value;
    }

    fn finishFastDenseScalarFloatAssign(self: *Session, target_idx: usize, rhs: DenseAssignRhs, out: HostFloatResult, reused: bool) KError!Value {
        hostDenseSetFlags(out.array, host_dense_flag_normalized);
        self.invalidateHostDenseCachesForMutation(out.array);
        const value = try out.value(self);
        self.recordFastDenseAssignHit(.{ .scalar = target_idx }, rhs, reused);
        return if (reused) self.shareValue(value) else value;
    }

    fn tryFastDenseScalarAssignDirect(self: *Session, base: Value, target_idx: usize, rhs_source: Value) KError!?Value {
        if (valueNumericMode(base) == null) return null;
        if (valueNonVectorNumericShape(base) != null) return null;
        const base_array = try numericHostArrayValue(self, base);

        switch (base_array.storage) {
            .bit => {
                const rhs_int = denseAssignScalarIntLike(rhs_source) orelse return null;
                if (rhs_int != 0 and rhs_int != 1) return null;
                if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;

                var reused = false;
                var out = if (self.tryReuseHostIntArrayResult(base, .bit)) |existing| blk: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk existing;
                } else blk: {
                    self.recordFastDenseAssignClone(base);
                    var allocated = try self.allocOwnedHostIntCloneResult(amendCloneOwner(base), .bit, base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.arrayPtr()));
                    @memcpy(allocated.bit.words, hostDenseLogicalBitWords(base_array, base_array.storage.bit));
                    break :blk allocated;
                };
                try applyDenseAssignIntScalar(&out, target_idx, rhs_int);
                return try self.finishFastDenseScalarIntAssign(target_idx, .{ .int_scalar = rhs_int }, &out, reused);
            },
            .int8, .int16, .int32, .int64 => {
                const rhs_int = denseAssignScalarIntLike(rhs_source) orelse return null;
                const view = hostIntArrayView(base_array) orelse return null;
                const kind = hostIntArrayViewKind(view);
                if (!hostIntKindCanRepresent(kind, rhs_int)) return null;
                if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;

                var reused = false;
                var out = if (self.tryReuseHostIntArrayResult(base, kind)) |existing| blk: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk existing;
                } else blk: {
                    self.recordFastDenseAssignClone(base);
                    var allocated = try self.allocOwnedHostIntCloneResult(amendCloneOwner(base), kind, base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.arrayPtr()));
                    try copyHostIntViewToResult(&allocated, view);
                    break :blk allocated;
                };
                try applyDenseAssignIntScalar(&out, target_idx, rhs_int);
                return try self.finishFastDenseScalarIntAssign(target_idx, .{ .int_scalar = rhs_int }, &out, reused);
            },
            .float32 => return null,
            .float64 => |base_items| {
                const rhs_float = denseAssignScalarFloatLike(rhs_source) orelse return null;
                const rhs: DenseAssignRhs = if (scalarIntLikeValue(rhs_source)) |rhs_int|
                    .{ .int_scalar = rhs_int }
                else
                    .{ .float_scalar = rhs_float };
                if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;

                var reused = false;
                const out = if (self.tryReuseHostFloatArrayResult(base)) |existing| blk: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk existing;
                } else blk: {
                    self.recordFastDenseAssignClone(base);
                    const allocated = try self.allocOwnedHostFloatResult(amendCloneOwner(base), base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.array));
                    @memcpy(allocated.items, base_items);
                    break :blk allocated;
                };
                out.items[target_idx] = rhs_float;
                return try self.finishFastDenseScalarFloatAssign(target_idx, rhs, out, reused);
            },
        }
    }

    fn tryFastDenseAssignAmendImpl(self: *Session, base: Value, targets: DenseAssignTargets, rhs_source: Value) KError!?Value {
        const targets_len = denseAssignTargetsLen(targets);
        if (targets_len == 0) {
            self.recordFastDenseAssignMiss();
            return null;
        }
        if (valueNumericMode(base) == null) {
            self.recordFastDenseAssignMiss();
            return null;
        }
        if (valueNonVectorNumericShape(base) != null) {
            self.recordFastDenseAssignMiss();
            return null;
        }

        const rhs = (try self.denseAssignRhs(rhs_source, targets_len)) orelse {
            self.recordFastDenseAssignMiss();
            return null;
        };
        const base_array = try numericHostArrayValue(self, base);

        return switch (hostDenseNumericMode(base_array)) {
            .int => blk: {
                const view = hostIntArrayView(base_array) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                const kind = hostIntArrayViewKind(view);
                if (!denseAssignRhsFitsIntKind(kind, targets_len, rhs)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }

                var reused = false;
                var out = if (self.tryReuseHostIntArrayResult(base, kind)) |existing| blk_out: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk_out existing;
                } else blk_out: {
                    self.recordFastDenseAssignClone(base);
                    var allocated = try self.allocOwnedHostIntCloneResult(amendCloneOwner(base), kind, base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.arrayPtr()));
                    try copyHostIntViewToResult(&allocated, view);
                    break :blk_out allocated;
                };
                try applyDenseAssignIntRhs(&out, targets, rhs);
                const host = out.arrayPtr();
                hostDenseSetFlags(host, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(host);
                const value = try out.value(self);
                self.recordFastDenseAssignHit(targets, rhs, reused);
                break :blk if (reused) self.shareValue(value) else value;
            },
            .float => blk: {
                const base_items = base_array.storage.float64;
                var reused = false;
                var out = if (self.tryReuseHostFloatArrayResult(base)) |existing| blk_out: {
                    if (!self.prepareReusableHostDenseForMutation(base)) {
                        self.recordFastDenseAssignMiss();
                        return null;
                    }
                    reused = true;
                    break :blk_out existing;
                } else blk_out: {
                    self.recordFastDenseAssignClone(base);
                    const allocated = try self.allocOwnedHostFloatResult(amendCloneOwner(base), base_array.len());
                    errdefer self.releaseValue(Value.array(allocated.array));
                    @memcpy(allocated.items, base_items);
                    break :blk_out allocated;
                };
                applyDenseAssignFloatRhs(out.items, targets, rhs);
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(out.array);
                const value = try out.value(self);
                self.recordFastDenseAssignHit(targets, rhs, reused);
                break :blk if (reused) self.shareValue(value) else value;
            },
        };
    }

    fn tryFastDenseAssignScalarAmend(self: *Session, base: Value, target_idx: usize, rhs_source: Value) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        return try self.tryFastDenseAssignAmendImpl(base, .{ .scalar = target_idx }, rhs_source);
    }

    fn tryFastIndexedDenseScalarAssignOwned(self: *Session, base: Value, selector: Value, rhs_source: Value) KError!?Value {
        if (base.tag() != .array) return null;
        const raw_index = scalarIntLikeValue(selector) orelse return null;
        errdefer self.releaseCanonicalManagedNumericValue(base);
        const target_idx = try normalizeIndex(raw_index, try self.topLevelLen(base));
        if (try self.tryFastDenseScalarAssignDirect(base, target_idx, rhs_source)) |amended| {
            if (comptime enable_probe_instrumentation) self.debug_owned_amend_count += 1;
            self.releaseCanonicalManagedNumericValue(base);
            return amended;
        }
        const amended = (try self.tryFastDenseAssignScalarAmend(base, target_idx, rhs_source)) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_owned_amend_count += 1;
        self.releaseCanonicalManagedNumericValue(base);
        return amended;
    }

    const DirectGlobalIndexedAssignResult = struct {
        result: ?Value = null,
    };

    fn tryFastGlobalDenseScalarAssignInPlace(
        self: *Session,
        slot: u16,
        selector: Value,
        rhs_source: Value,
        want_result: bool,
    ) KError!?DirectGlobalIndexedAssignResult {
        const cell = try self.loadGlobalCell(slot);
        const base = cell.value;
        if (!cell.class.isArray()) return null;
        const raw_index = scalarIntLikeValue(selector) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        if (valueNonVectorNumericShape(base) != null) {
            self.recordFastDenseAssignMiss();
            return null;
        }
        const base_array = hostDenseIfPresent(base) orelse {
            self.recordFastDenseAssignMiss();
            return null;
        };
        const target_idx = try normalizeIndex(raw_index, base_array.len());
        const rhs = (try self.denseAssignRhs(rhs_source, 1)) orelse {
            self.recordFastDenseAssignMiss();
            return null;
        };

        switch (hostDenseNumericMode(base_array)) {
            .int => {
                const view = hostIntArrayView(base_array) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                const kind = hostIntArrayViewKind(view);
                if (!denseAssignRhsFitsIntKind(kind, 1, rhs)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }
                var out = self.tryReuseHostIntArrayResult(base, kind) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                if (!self.prepareReusableHostDenseForMutation(base)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }
                try applyDenseAssignIntRhs(&out, .{ .scalar = target_idx }, rhs);
                const host = out.arrayPtr();
                hostDenseSetFlags(host, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(host);
            },
            .float => {
                const out = self.tryReuseHostFloatArrayResult(base) orelse {
                    self.recordFastDenseAssignMiss();
                    return null;
                };
                if (!self.prepareReusableHostDenseForMutation(base)) {
                    self.recordFastDenseAssignMiss();
                    return null;
                }
                applyDenseAssignFloatRhs(out.items, .{ .scalar = target_idx }, rhs);
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
                self.invalidateHostDenseCachesForMutation(out.array);
            },
        }

        cell.class = classifyGlobalValue(base);
        if (comptime enable_probe_instrumentation) {
            self.recordFastDenseAssignHit(.{ .scalar = target_idx }, rhs, true);
            self.debug_owned_amend_count += 1;
        }
        return .{
            .result = if (want_result) try self.applyArrayCall1Scalar(base, raw_index) else null,
        };
    }

    fn tryFastDenseAssignAmend(self: *Session, base: Value, selectors: []const usize, rhs_source: Value) KError!?Value {
        if (comptime enable_probe_instrumentation) self.debug_fast_dense_assign_attempt_count += 1;
        return try self.tryFastDenseAssignAmendImpl(base, .{ .slice = selectors }, rhs_source);
    }

    fn applyWholeAmend(self: *Session, base: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        return switch (mode) {
            .assign => try self.retainEscapedValue(func_or_value),
            .unary => try self.applyValue(func_or_value, &[_]Value{base}),
            .binary => try self.applyValue(func_or_value, &[_]Value{ base, arg }),
        };
    }

    fn tryApplyGroupedShallowAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!?Value {
        var owned_groups: ?[]Value = null;
        defer if (owned_groups) |values| {
            for (values) |value| self.releaseValue(value);
            self.allocator.free(values);
        };
        const groups = boxedArrayItems(selector) orelse blk: {
            if (valueNonVectorNumericShape(selector) == null) return null;
            owned_groups = try self.materializeTopLevelItems(selector);
            break :blk owned_groups.?;
        };
        if (groups.len == 0) return try self.retainEscapedValue(base);

        var rhs_items: ?[]Value = null;
        defer if (rhs_items) |values| {
            for (values) |value| self.releaseValue(value);
            self.allocator.free(values);
        };

        if (mode != .unary) {
            const rhs_source = if (mode == .assign) func_or_value else arg;
            if (rhs_source.tag() == .array) {
                const maybe = try self.tryMaterializeTopLevelItems(rhs_source);
                if (maybe) |values| rhs_items = values;
            }
        }

        var current = try self.retainEscapedValue(base);
        errdefer self.releaseValue(current);

        for (groups, 0..) |group, idx| {
            const group_func_or_value = if (mode == .assign)
                if (rhs_items) |values| if (values.len == groups.len) values[idx] else func_or_value else func_or_value
            else
                func_or_value;
            const group_arg = if (mode == .binary)
                if (rhs_items) |values| if (values.len == groups.len) values[idx] else arg else arg
            else
                arg;
            const amended = try self.applyShallowAmend(current, group, mode, group_func_or_value, group_arg);
            self.releaseValue(current);
            current = amended;
        }

        return current;
    }

    fn findKeyIndexInItems(self: *Session, keys: []const Value, key: Value) KError!?usize {
        for (keys, 0..) |candidate, idx| {
            if (try self.valueMatchEqual(candidate, key)) return idx;
        }
        return null;
    }

    fn createKeyArrayFromValues(self: *Session, keys: []const Value) KError!Value {
        var symbol_slices = std.ArrayList([]const u8).empty;
        defer symbol_slices.deinit(self.allocator);
        try symbol_slices.ensureTotalCapacity(self.allocator, keys.len);
        for (keys) |key| {
            const bytes = symbolBytes(key) orelse break;
            try symbol_slices.append(self.allocator, bytes);
        }
        if (symbol_slices.items.len == keys.len) return try self.createManagedHostSymbolListFromSlices(symbol_slices.items);
        return try self.makeArrayFromValues(keys);
    }

    fn missingDictAmendValue(self: *Session, func: Value, rhs: Value) KError!Value {
        if (func.tag() == .builtin) {
            return switch (func.asBuiltin()) {
                .add, .sub => if (rhs.tag() == .float) try self.floatValue(0) else try self.intValue(0),
                .mul, .div => if (rhs.tag() == .float) try self.floatValue(1) else try self.intValue(1),
                else => try self.prototypeLikeValue(rhs),
            };
        }
        return try self.prototypeLikeValue(rhs);
    }

    fn tryApplyDictShallowAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!?Value {
        if (base.tag() != .array or base.arrayKind() != .host_keyed_store) return null;
        const store = base.asHostKeyedStore();
        if (store.layout != .dict) return null;

        const selector_items = try self.materializeSequenceItems(selector);
        defer self.releaseArgs(selector_items);
        if (selector_items.len == 0) return try self.retainEscapedValue(base);

        var keys = std.ArrayList(Value).empty;
        var values = std.ArrayList(Value).empty;
        defer {
            for (keys.items) |value| self.releaseValue(value);
            for (values.items) |value| self.releaseValue(value);
            keys.deinit(self.allocator);
            values.deinit(self.allocator);
        }

        const existing_len = keyedStoreNameCount(store);
        try keys.ensureTotalCapacity(self.allocator, existing_len + selector_items.len);
        try values.ensureTotalCapacity(self.allocator, existing_len + selector_items.len);
        for (0..existing_len) |idx| {
            try keys.append(self.allocator, try self.keyedStoreNameValue(store, idx));
            try values.append(self.allocator, try self.keyedStoreValueAt(store, idx));
        }

        var rhs_items: ?[]Value = null;
        defer if (rhs_items) |items| {
            for (items) |value| self.releaseValue(value);
            self.allocator.free(items);
        };

        const rhs_source = switch (mode) {
            .assign => func_or_value,
            .binary => arg,
            .unary => Value.fromBool(false),
        };
        const selector_is_scalar = derivedSequenceLen(selector) == null;
        if (mode != .unary and rhs_source.tag() == .array) {
            const maybe = try self.tryMaterializeTopLevelItems(rhs_source);
            if (maybe) |items| rhs_items = items;
        }

        for (selector_items, 0..) |key, idx| {
            const rhs = if (rhs_items) |items|
                if (!selector_is_scalar and items.len == selector_items.len) items[idx] else rhs_source
            else
                rhs_source;

            const existing = try self.findKeyIndexInItems(keys.items, key);
            const target_idx = existing orelse blk: {
                try keys.append(self.allocator, try self.retainEscapedValue(key));
                const placeholder = switch (mode) {
                    .assign => try self.retainEscapedValue(rhs),
                    .unary => try self.prototypeLikeValue(store.values),
                    .binary => try self.missingDictAmendValue(func_or_value, rhs),
                };
                try values.append(self.allocator, placeholder);
                break :blk values.items.len - 1;
            };

            const current = values.items[target_idx];
            const next = switch (mode) {
                .assign => if (existing == null) try self.retainEscapedValue(current) else try self.retainEscapedValue(rhs),
                .unary => try self.applyValue(func_or_value, &[_]Value{current}),
                .binary => try self.applyValue(func_or_value, &[_]Value{ current, rhs }),
            };
            self.releaseValue(values.items[target_idx]);
            values.items[target_idx] = next;
        }

        const keys_value = try self.createKeyArrayFromValues(keys.items);
        defer self.releaseValue(keys_value);
        const values_value = try self.makeArrayFromValues(values.items);
        defer self.releaseValue(values_value);
        return try self.createHostDictValueFromKeySequenceValue("", keys_value, values_value);
    }

    fn retainedTableColumnData(self: *Session, store: *const HostKeyedStore, column_idx: usize) KError!Value {
        return try self.retainEscapedValue(tableColumnData(store, column_idx));
    }

    fn buildTableColumnFromValue(self: *Session, name: Value, value: Value, row_count: usize) KError!HostTableColumn {
        const spec = try self.classifyDictTableColumn(value);
        return try self.buildDictTableColumn(name, spec, row_count);
    }

    fn tryApplyTableColumnAssign(self: *Session, store: *const HostKeyedStore, selector: Value, rhs: Value) KError!?Value {
        const name = keyedLookupNameBytes(selector) orelse return null;
        const existing_idx = store.lookup.get(name);
        const old_count = keyedStoreNameCount(store);
        const new_count = old_count + if (existing_idx == null) @as(usize, 1) else 0;
        const columns = try self.allocator.alloc(HostTableColumn, new_count);
        var built: usize = 0;
        errdefer {
            for (columns[0..built]) |column| {
                self.releaseValue(column.name);
                self.releaseValue(column.data);
                if (column.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        const metadata = keyedStoreTableMetadata(store);
        for (0..old_count) |idx| {
            const column_name = try self.keyedStoreNameValue(store, idx);
            errdefer self.releaseValue(column_name);
            if (existing_idx != null and existing_idx.? == idx) {
                columns[built] = try self.buildTableColumnFromValue(column_name, rhs, store.row_count);
            } else {
                columns[built] = .{
                    .name = try self.retainEscapedValue(column_name),
                    .data = try self.retainedTableColumnData(store, idx),
                    .validity = if (metadata[idx].validity) |mask| try self.retainEscapedValue(mask) else null,
                    .kind = metadata[idx].kind,
                };
            }
            self.releaseValue(column_name);
            built += 1;
        }

        if (existing_idx == null) {
            const column_name = try self.managedHostSymbol(name);
            errdefer self.releaseValue(column_name);
            columns[built] = try self.buildTableColumnFromValue(column_name, rhs, store.row_count);
            self.releaseValue(column_name);
            built += 1;
        }

        return try self.createManagedHostTable(store.row_count, columns);
    }

    fn tableRowAssignColumnRhs(self: *Session, rhs: Value, column_name: []const u8) KError!Value {
        if (rhs.tag() != .array or rhs.arrayKind() != .host_keyed_store) return error.Type;
        const rhs_store = rhs.asHostKeyedStore();
        return switch (rhs_store.layout) {
            .dict => try self.keyedStoreLookupValue(rhs_store, column_name),
            .table => try self.keyedStoreLookupValue(rhs_store, column_name),
        };
    }

    fn tryApplyTableRowAssign(self: *Session, base: Value, store: *const HostKeyedStore, selector: Value, rhs: Value) KError!?Value {
        const row_indices = self.collectSelectorIndices(base, selector) catch |err| switch (err) {
            error.Type => return null,
            else => return err,
        };
        defer self.allocator.free(row_indices);
        if (row_indices.len == 0) return try self.retainEscapedValue(base);

        const column_count = keyedStoreNameCount(store);
        const columns = try self.allocator.alloc(HostTableColumn, column_count);
        var built: usize = 0;
        errdefer {
            for (columns[0..built]) |column| {
                self.releaseValue(column.name);
                self.releaseValue(column.data);
                if (column.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        for (0..column_count) |column_idx| {
            const column_name = try self.keyedStoreNameValue(store, column_idx);
            errdefer self.releaseValue(column_name);
            const column_name_bytes = keyedLookupNameBytes(column_name) orelse return error.Type;
            const rhs_column = try self.tableRowAssignColumnRhs(rhs, column_name_bytes);
            defer self.releaseValue(rhs_column);

            var rhs_items: ?[]Value = null;
            defer if (rhs_items) |items| {
                for (items) |value| self.releaseValue(value);
                self.allocator.free(items);
            };
            if (rhs_column.tag() == .array) {
                const maybe = try self.tryMaterializeTopLevelItems(rhs_column);
                if (maybe) |items| rhs_items = items;
            }

            const row_values = try self.allocator.alloc(Value, store.row_count);
            defer self.allocator.free(row_values);
            var initialized: usize = 0;
            defer {
                for (row_values[0..initialized]) |value| self.releaseValue(value);
            }

            for (0..store.row_count) |row| {
                row_values[row] = try self.tableCellScalarValue(store, column_idx, row);
                initialized += 1;
            }

            for (row_indices, 0..) |row, row_pos| {
                const replacement = if (rhs_items) |items|
                    if (items.len == row_indices.len) items[row_pos] else rhs_column
                else
                    rhs_column;
                self.releaseValue(row_values[row]);
                row_values[row] = try self.retainEscapedValue(replacement);
            }

            const column_value = try self.makeArrayFromValues(row_values);
            defer self.releaseValue(column_value);
            columns[built] = try self.buildTableColumnFromValue(column_name, column_value, store.row_count);
            self.releaseValue(column_name);
            built += 1;
        }

        return try self.createManagedHostTable(store.row_count, columns);
    }

    fn tryApplyTableShallowAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!?Value {
        _ = arg;
        if (base.tag() != .array or base.arrayKind() != .host_keyed_store) return null;
        const store = base.asHostKeyedStore();
        if (store.layout != .table) return null;
        if (mode != .assign) return null;
        if (try self.tryApplyTableColumnAssign(store, selector, func_or_value)) |table| return table;
        return try self.tryApplyTableRowAssign(base, store, selector, func_or_value);
    }

    fn applyShallowAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!Value {
        if (base.tag() != .array) return error.Type;
        if (try self.tryApplyDictShallowAmend(base, selector, mode, func_or_value, arg)) |dict| return dict;
        if (try self.tryApplyTableShallowAmend(base, selector, mode, func_or_value, arg)) |table| return table;
        if (try self.tryApplyGroupedShallowAmend(base, selector, mode, func_or_value, arg)) |grouped| return grouped;
        var tried_scalar_fast_assign = false;
        if (mode == .assign and valueNumericMode(base) != null) {
            if (scalarIntLikeValue(selector)) |raw_index| {
                tried_scalar_fast_assign = true;
                const target_idx = try normalizeIndex(raw_index, try self.topLevelLen(base));
                if (try self.tryFastDenseAssignScalarAmend(base, target_idx, func_or_value)) |fast| return fast;
            }
        }
        const selectors = self.collectSelectorIndices(base, selector) catch |err| switch (err) {
            error.Type => if (try self.tryApplyNumericMatrixColumnAmend(base, selector, mode, func_or_value, arg)) |matrix| return matrix else return err,
            else => return err,
        };
        defer self.allocator.free(selectors);

        if (mode == .assign and !tried_scalar_fast_assign) {
            if (try self.tryFastDenseAssignAmend(base, selectors, func_or_value)) |fast| return fast;
        }

        if (selectors.len == 0) return try self.retainEscapedValue(base);

        const items = try self.materializeTopLevelItems(base);
        defer {
            for (items) |value| self.releaseValue(value);
            self.allocator.free(items);
        }

        var rhs_items: ?[]Value = null;
        defer if (rhs_items) |values| {
            for (values) |value| self.releaseValue(value);
            self.allocator.free(values);
        };

        const rhs_source = switch (mode) {
            .assign => func_or_value,
            .binary => arg,
            .unary => Value.fromBool(false),
        };
        const selector_is_scalar = selector.tag() == .int or selector.tag() == .bool;
        if (mode != .unary and rhs_source.tag() == .array) {
            const maybe = try self.tryMaterializeTopLevelItems(rhs_source);
            if (maybe) |values| rhs_items = values;
        }

        var idx: usize = 0;
        while (idx < selectors.len) : (idx += 1) {
            const target_idx = selectors[idx];
            const current = items[target_idx];
            const next = switch (mode) {
                .assign => if (rhs_items) |values|
                    if (!selector_is_scalar and values.len == selectors.len) try self.retainEscapedValue(values[idx]) else try self.retainEscapedValue(func_or_value)
                else
                    try self.retainEscapedValue(func_or_value),
                .unary => try self.applyValue(func_or_value, &[_]Value{current}),
                .binary => blk: {
                    const rhs = if (rhs_items) |values|
                        if (!selector_is_scalar and values.len == selectors.len) values[idx] else arg
                    else
                        arg;
                    break :blk try self.applyValue(func_or_value, &[_]Value{ current, rhs });
                },
            };
            self.releaseValue(items[target_idx]);
            items[target_idx] = next;
        }

        return try self.rebuildTopLevelItems(base, items);
    }

    fn collectSelectorIndices(self: *Session, base: Value, selector: Value) KError![]usize {
        return try self.collectSelectorIndicesForLen(try self.topLevelLen(base), selector);
    }

    fn collectSelectorIndicesForLen(self: *Session, top_len: usize, selector: Value) KError![]usize {
        var indices = std.ArrayList(usize).empty;
        defer indices.deinit(self.allocator);

        if (isAllAxisSelectorValue(selector)) {
            try indices.ensureTotalCapacity(self.allocator, top_len);
            for (0..top_len) |idx| try indices.append(self.allocator, idx);
            return try indices.toOwnedSlice(self.allocator);
        }

        switch (selector.tag()) {
            .int, .bool => {
                try indices.append(self.allocator, try normalizeIndex(scalarIntLikeValue(selector).?, top_len));
            },
            .array => {
                if (stringBytes(selector)) |bytes| {
                    try indices.ensureTotalCapacity(self.allocator, bytes.len);
                    for (bytes) |byte| try indices.append(self.allocator, try normalizeIndex(@intCast(byte), top_len));
                } else if (valueHostIntStructuralView(selector)) |view| switch (view) {
                    .dense => |dense| switch (dense) {
                        .bit => |bits| {
                            if (bits.len != top_len) return error.Type;
                            for (0..bits.len) |idx| {
                                if (!bitGet(bits.words, idx)) continue;
                                try indices.append(self.allocator, idx);
                            }
                        },
                        else => {
                            const len = hostIntArrayViewLen(dense);
                            try indices.ensureTotalCapacity(self.allocator, len);
                            for (0..len) |idx| {
                                try indices.append(self.allocator, try normalizeIndex(hostIntViewItem(dense, idx), top_len));
                            }
                        },
                    },
                    else => {
                        const len = hostIntDenseViewLen(view);
                        try indices.ensureTotalCapacity(self.allocator, len);
                        for (0..len) |idx| {
                            try indices.append(self.allocator, try normalizeIndex(try hostIntDenseViewItem(view, idx), top_len));
                        }
                    },
                } else return error.Type;
            },
            else => return error.Type,
        }

        return try indices.toOwnedSlice(self.allocator);
    }

    fn matrixCellValue(self: *Session, value: Value, row: usize, col: usize) KError!Value {
        const row_value = try self.applyArrayCall1Scalar(value, @intCast(row));
        defer self.releaseValue(row_value);
        return try self.applyArrayCall1Scalar(row_value, @intCast(col));
    }

    fn tryApplyNumericMatrixColumnAmend(self: *Session, base: Value, selector: Value, mode: ShallowAmendMode, func_or_value: Value, arg: Value) KError!?Value {
        const shape = valueNumericMatrixShape(base) orelse return null;
        const rows = shape.rows;
        const cols = shape.cols;
        const col_indices = self.collectSelectorIndicesForLen(cols, selector) catch |err| switch (err) {
            error.Type => return null,
            else => return err,
        };
        defer self.allocator.free(col_indices);
        if (col_indices.len == 0) return try self.retainEscapedValue(base);

        const total = rows * cols;
        const items = try self.allocator.alloc(Value, total);
        defer self.allocator.free(items);
        var initialized: usize = 0;
        defer {
            for (items[0..initialized]) |value| self.releaseValue(value);
        }

        switch (valueNumericMode(base) orelse return null) {
            .int => for (0..total) |idx| {
                items[idx] = try self.intValue(try numericIntAt(base, idx));
                initialized += 1;
            },
            .float => for (0..total) |idx| {
                items[idx] = try self.floatValue(try numericFloatAt(base, idx));
                initialized += 1;
            },
        }

        const rhs_source = switch (mode) {
            .assign => func_or_value,
            .binary => arg,
            .unary => Value.fromBool(false),
        };
        const rhs_matrix_shape = if (mode != .unary) valueNumericMatrixShape(rhs_source) else null;
        const rhs_is_matrix = if (rhs_matrix_shape) |rhs_shape|
            rhs_shape.rows == rows and rhs_shape.cols == col_indices.len
        else
            false;

        for (0..rows) |row| {
            for (col_indices, 0..) |col, col_pos| {
                const flat_idx = row * cols + col;
                const current = items[flat_idx];
                var rhs_cell: ?Value = null;
                defer if (rhs_cell) |value| self.releaseValue(value);
                const rhs = if (rhs_is_matrix) blk: {
                    rhs_cell = try self.matrixCellValue(rhs_source, row, col_pos);
                    break :blk rhs_cell.?;
                } else rhs_source;

                const next = switch (mode) {
                    .assign => try self.retainEscapedValue(rhs),
                    .unary => try self.applyValue(func_or_value, &[_]Value{current}),
                    .binary => try self.applyValue(func_or_value, &[_]Value{ current, rhs }),
                };
                self.releaseValue(items[flat_idx]);
                items[flat_idx] = next;
            }
        }

        const rebuilt = try self.makeArrayFromValues(items);
        return try applyNonVectorNumericShapeToValue(self, rebuilt, numericShapeSnapshotMatrix(rows, cols));
    }

    fn topLevelLen(self: *Session, value: Value) KError!usize {
        _ = self;
        if (value.tag() != .array) return error.Type;
        if (stringSourceInfo(value)) |source| return source.bytes().len;
        if (value.arrayKind() == .host_keyed_store) {
            const store = value.asHostKeyedStore();
            return switch (store.layout) {
                .dict => keyedStoreNameCount(store),
                .table => store.row_count,
            };
        }
        if (derivedSequenceLen(value)) |len| return len;
        return error.Type;
    }

    fn materializeTopLevelItems(self: *Session, value: Value) KError![]Value {
        const len = try self.topLevelLen(value);
        const items = try self.allocator.alloc(Value, len);
        errdefer self.allocator.free(items);
        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |item| self.releaseValue(item);
        }

        if (stringSourceInfo(value)) |source| {
            for (0..len) |idx| {
                items[idx] = try self.stringIndexScalarValue(source, @intCast(idx));
                initialized += 1;
            }
        } else if (value.arrayKind() == .host_keyed_store) {
            const store = value.asHostKeyedStore();
            switch (store.layout) {
                .dict => for (0..len) |idx| {
                    items[idx] = try self.keyedStoreValueAt(store, idx);
                    initialized += 1;
                },
                .table => for (0..len) |idx| {
                    items[idx] = try self.tableRowDictValue(store, idx);
                    initialized += 1;
                },
            }
        } else {
            for (0..len) |idx| {
                items[idx] = try self.derivedSequenceItemValue(value, idx);
                initialized += 1;
            }
        }
        return items;
    }

    fn tryMaterializeTopLevelItems(self: *Session, value: Value) KError!?[]Value {
        if (value.tag() != .array) return null;
        return try self.materializeTopLevelItems(value);
    }

    fn rebuildTopLevelItems(self: *Session, base: Value, items: []const Value) KError!Value {
        if (stringSourceInfo(base) != null) {
            var text_values = std.ArrayList(Value).empty;
            defer {
                for (text_values.items) |value| self.releaseValue(value);
                text_values.deinit(self.allocator);
            }
            try text_values.ensureTotalCapacity(self.allocator, items.len);

            var all_text = true;
            for (items) |item| {
                if (stringBytes(item) != null) {
                    try text_values.append(self.allocator, try self.retainEscapedValue(item));
                } else if (item.tag() == .array and item.arrayKind() == .host_string_list) {
                    try text_values.append(self.allocator, try self.joinHostStringList(item.asHostStringList(), &.{}));
                } else {
                    all_text = false;
                    break;
                }
            }

            if (all_text) {
                var all_unit_strings = true;
                for (text_values.items) |item| {
                    const bytes = stringBytes(item) orelse return error.Internal;
                    if (bytes.len != 1) {
                        all_unit_strings = false;
                        break;
                    }
                }
                if (all_unit_strings) {
                    const out = try self.allocator.alloc(u8, text_values.items.len);
                    defer self.allocator.free(out);
                    for (text_values.items, 0..) |item, idx| out[idx] = stringBytes(item).?[0];
                    return try self.managedHostString(out);
                }
                return try self.createManagedHostStringList(text_values.items);
            }
        }

        if (base.tag() == .array and base.arrayKind() == .host_boxed_array) {
            if (scalarNumericItemsHaveSingleClass(items)) return try self.makeArrayFromValues(items);
            return try self.createManagedHostBoxedArrayWithPrototype(items, base.asHostBoxedArray().prototype);
        }

        if (stringSourceInfo(base) != null) {
            var all_unit_strings = true;
            for (items) |item| {
                const bytes = stringBytes(item) orelse {
                    all_unit_strings = false;
                    break;
                };
                if (bytes.len != 1) {
                    all_unit_strings = false;
                    break;
                }
            }
            if (all_unit_strings) {
                const out = try self.allocator.alloc(u8, items.len);
                defer self.allocator.free(out);
                for (items, 0..) |item, idx| out[idx] = stringBytes(item).?[0];
                return try self.managedHostString(out);
            }
        }

        if (base.tag() == .array and base.arrayKind() == .host_string_list) {
            var all_text = true;
            for (items) |item| {
                if (stringBytes(item) == null and symbolBytes(item) == null) {
                    all_text = false;
                    break;
                }
            }
            if (all_text) return try self.createManagedHostTextListFromValues(items);
        }

        if (base.tag() == .array and base.arrayKind() == .host_symbol_list) {
            var slices = std.ArrayList([]const u8).empty;
            defer slices.deinit(self.allocator);
            try slices.ensureTotalCapacity(self.allocator, items.len);
            for (items) |item| {
                const bytes = symbolBytes(item) orelse break;
                try slices.append(self.allocator, bytes);
            }
            if (slices.items.len == items.len) return try self.createManagedHostSymbolListFromSlices(slices.items);
        }

        const rebuilt = try self.makeArrayFromValues(items);
        if (try self.promoteRenderableMatrixValue(rebuilt)) |promoted| {
            if (promoted.raw != rebuilt.raw and isManagedValue(rebuilt)) self.releaseValue(rebuilt);
            return promoted;
        }
        if (valueNumericMatrixShape(base)) |shape| {
            return try applyNonVectorNumericShapeToValue(self, rebuilt, numericShapeSnapshotMatrix(shape.rows, shape.cols));
        }
        return rebuilt;
    }

    fn applyDot(self: *Session, left: Value, right: Value) KError!Value {
        const items = try self.materializeSequenceItems(right);
        defer self.releaseArgs(items);
        if (items.len > max_direct_apply_args) return error.Unsupported;
        return try self.applyValue(left, items);
    }

    fn applyProjectionClosure(self: *Session, info: ProjectionInfo, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_projection);
        defer profile_scope.end();
        if (self.debugDetailedProbeActive()) self.debug_apply_projection_count += 1;
        if (try self.tryApplyDirectBuiltinProjection(info, args)) |value| return value;
        const full_slot_values = try self.scratch_arena.allocator().alloc(Value, info.slot_count);
        var next_hole_mask: u64 = 0;
        var arg_idx: usize = 0;

        for (0..info.slot_count) |slot_idx| {
            if (((info.hole_mask >> @intCast(slot_idx)) & 1) != 0) {
                if (arg_idx < args.len) {
                    full_slot_values[slot_idx] = args[arg_idx];
                    arg_idx += 1;
                } else {
                    full_slot_values[slot_idx] = Value.fromBool(false);
                    next_hole_mask |= (@as(u64, 1) << @intCast(slot_idx));
                }
            } else {
                full_slot_values[slot_idx] = info.slot_values[slot_idx];
            }
        }

        if (next_hole_mask != 0) {
            return try self.allocManagedProjectionClosure(
                info.callee,
                std.math.cast(u8, info.slot_count) orelse return error.Unsupported,
                next_hole_mask,
                full_slot_values,
            );
        }

        const extra_count = args.len - arg_idx;
        const apply_args = try self.scratch_arena.allocator().alloc(Value, info.slot_count + extra_count);
        @memcpy(apply_args[0..info.slot_count], full_slot_values);
        for (args[arg_idx..], 0..) |arg, idx| apply_args[info.slot_count + idx] = arg;
        return try self.applyValue(info.callee, apply_args);
    }

    fn tryApplyDirectBuiltinProjection(self: *Session, info: ProjectionInfo, args: []const Value) KError!?Value {
        if (info.callee.tag() != .builtin) return null;
        if (info.slot_count == 0 or info.slot_count > max_direct_apply_args) return null;
        const hole_count: usize = @intCast(@popCount(info.hole_mask));
        if (args.len != hole_count) return null;

        const op = info.callee.asBuiltin();
        if (!builtinUsesGenericArityDispatch(op)) return null;

        var apply_args: [max_direct_apply_args]Value = undefined;
        var arg_idx: usize = 0;
        for (0..info.slot_count) |slot_idx| {
            if (((info.hole_mask >> @intCast(slot_idx)) & 1) != 0) {
                apply_args[slot_idx] = args[arg_idx];
                arg_idx += 1;
            } else {
                apply_args[slot_idx] = info.slot_values[slot_idx];
            }
        }

        return switch (info.slot_count) {
            1 => try self.applyMonad(op, apply_args[0]),
            2 => try self.applyDyad(dyadicBuiltinForGenericCall(op), apply_args[0], apply_args[1]),
            3 => if (op == .unique or op == .find) try self.insertValue(apply_args[0], apply_args[1], apply_args[2]) else error.Arity,
            else => error.Arity,
        };
    }

    fn applyCompositionClosure(self: *Session, info: CompositionInfo, args: []const Value) KError!Value {
        const inner_result = try self.applyValue(info.inner, args);
        defer self.releaseValue(inner_result);
        return try self.applyValue(info.outer, &[_]Value{inner_result});
    }

    fn applyDerivedClosure(self: *Session, closure: *const Closure, args: []const Value) KError!?Value {
        if (!closureMayUseDerivedApply(closure)) return null;
        if (self.debugDetailedProbeActive()) self.debug_apply_derived_closure_count += 1;
        if (try self.projectionInfoFromClosure(closure)) |info| {
            return try self.applyProjectionClosure(info, args);
        }
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            return try self.applyInnerProductClosure(info, args);
        }
        if (try self.compositionInfoFromClosure(closure)) |info| {
            return try self.applyCompositionClosure(info, args);
        }
        const kind = closureDerivedKind(closure) orelse return null;
        return try self.applyDerivedKind(kind, closure.captures, args);
    }

    fn builtinSupportsMonad(op: BuiltinId) bool {
        return switch (op) {
            .identity,
            .add,
            .sub,
            .mul,
            .div,
            .exp,
            .log,
            .sin,
            .cos,
            .tanh,
            .sigmoid,
            .iota,
            .minimum,
            .maximum,
            .reverse,
            .less,
            .more,
            .grade_up,
            .grade_down,
            .not,
            .count,
            .floor,
            .null_fill_without,
            .sort,
            .equal,
            .stringify,
            .bytes,
            .utf8,
            .char,
            .type_of,
            .unique,
            .eval_string,
            .load,
            .sql,
            .rotcacheview,
            .layernorm,
            .gelu,
            .geluapprox,
            .softmax,
            => true,
            .concat, .take, .drop, .reshape, .cast, .contains, .split, .join, .find, .grad, .valuegrad, .prng, .save, .register, .rotcache, .rotcacheupdate, .rope, .ropeflat, .ropecisflat, .rmsnorm, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .pow, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => false,
        };
    }

    fn builtinSupportsDyad(op: BuiltinId) bool {
        return switch (op) {
            .identity,
            .add,
            .sub,
            .mul,
            .div,
            .pow,
            .minimum,
            .maximum,
            .less,
            .more,
            .not,
            .concat,
            .count,
            .floor,
            .null_fill_without,
            .sort,
            .equal,
            .stringify,
            .contains,
            .split,
            .join,
            .unique,
            .load,
            .save,
            .register,
            .rotcache,
            .rotcacheupdate,
            => true,
            .exp, .log, .sin, .cos, .tanh, .sigmoid, .iota, .reverse, .grade_up, .grade_down, .take, .drop, .reshape, .cast, .find, .bytes, .utf8, .char, .type_of, .eval_string, .grad, .valuegrad, .prng, .sql, .rotcacheview, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => false,
        };
    }

    fn convergeUsesMonadicBase(base: Value) bool {
        return switch (base.tag()) {
            .builtin => builtinSupportsMonad(base.asBuiltin()) and !builtinSupportsDyad(base.asBuiltin()),
            .closure => blk: {
                const closure = base.asClosure();
                if (projectionHoleCount(closure)) |hole_count| break :blk hole_count == 1;
                if (closureDerivedKind(closure)) |kind| {
                    break :blk derivedClosureSupportsMonadicScanBase(kind, closure);
                }
                break :blk closure.code.arity == 1;
            },
            .array => true,
            else => false,
        };
    }

    fn derivedClosureSupportsMonadicScanBase(kind: DerivedVerbKind, closure: *const Closure) bool {
        return switch (kind) {
            .each_prior => closure.captures.len == 1 and eachPriorRollingBaseSupportsDyad(closure.captures[0]),
            .each, .fold, .scan, .each_right, .each_left, .grad, .valuegrad => false,
        };
    }

    fn eachPriorRollingBaseSupportsDyad(base: Value) bool {
        return switch (base.tag()) {
            .builtin => builtinSupportsDyad(base.asBuiltin()),
            .closure => blk: {
                const closure = base.asClosure();
                if (projectionHoleCount(closure)) |hole_count| break :blk hole_count == 2;
                if (closureDerivedKind(closure) != null) break :blk false;
                break :blk closure.code.arity == 2;
            },
            else => false,
        };
    }

    fn projectionHoleCount(closure: *const Closure) ?u8 {
        if (!closureIsProjection(closure)) return null;
        if (closure.captures.len < 3) return null;
        const slot_count_i64 = scalarIntLikeValue(closure.captures[1]) orelse return null;
        const hole_mask_i64 = scalarIntLikeValue(closure.captures[2]) orelse return null;
        if (slot_count_i64 < 0 or slot_count_i64 > 63 or hole_mask_i64 < 0) return null;
        const slot_count: u6 = @intCast(slot_count_i64);
        const hole_mask: u64 = @intCast(hole_mask_i64);
        if ((hole_mask >> slot_count) != 0) return null;
        if (closure.captures.len != 3 + @as(usize, slot_count)) return null;
        return @intCast(@popCount(hole_mask));
    }

    fn valueIsCallable(value: Value) bool {
        return switch (value.tag()) {
            .builtin, .closure, .array => true,
            else => false,
        };
    }

    fn eachPriorUsesMonadicBase(base: Value) bool {
        return switch (base.tag()) {
            .builtin => builtinSupportsMonad(base.asBuiltin()) and !builtinSupportsDyad(base.asBuiltin()),
            .closure => blk: {
                const closure = base.asClosure();
                if (closureDerivedKind(closure)) |kind| {
                    break :blk switch (kind) {
                        .each => closure.captures.len == 1 and eachPriorUsesMonadicBase(closure.captures[0]),
                        .fold, .scan, .each_right, .each_left, .each_prior, .grad, .valuegrad => true,
                    };
                }
                break :blk closure.code.arity == 1;
            },
            else => false,
        };
    }

    fn eachPriorImplicitSeedValue(self: *Session, base: Value, vector: Value) KError!Value {
        return switch (base.tag()) {
            .builtin => switch (base.asBuiltin()) {
                .add, .sub => try self.intValue(0),
                .mul, .div => try self.intValue(1),
                .minimum, .maximum => try self.derivedSequenceItemValue(vector, 0),
                .concat => try self.createManagedHostBoxedArray(&.{}),
                else => try self.floatValue(std.math.nan(f64)),
            },
            else => try self.derivedSequenceItemValue(vector, 0),
        };
    }

    fn applyDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!Value {
        if (try self.tryApplyStringDerivedKind(kind, captures, args)) |value| return value;
        if (try self.tryApplyNumericEncodeDecodeDerivedKind(kind, captures, args)) |value| return value;
        return switch (kind) {
            .each => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachDerived(captures[0], args);
            },
            .fold => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk if (args.len == 1 and convergeUsesMonadicBase(captures[0]))
                    try self.applyConvergeDerived(captures[0], args[0], false)
                else
                    try self.applyFoldDerived(captures[0], args, false);
            },
            .scan => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk if (args.len == 1 and convergeUsesMonadicBase(captures[0]))
                    try self.applyConvergeDerived(captures[0], args[0], true)
                else
                    try self.applyFoldDerived(captures[0], args, true);
            },
            .each_right => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachRightDerived(captures[0], args);
            },
            .each_left => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachLeftDerived(captures[0], args);
            },
            .each_prior => blk: {
                if (captures.len != 1) return error.Internal;
                break :blk try self.applyEachPriorDerived(captures[0], args);
            },
            .grad => try self.applyAutogradDerived(.grad, captures, args),
            .valuegrad => try self.applyAutogradDerived(.valuegrad, captures, args),
        };
    }

    fn tryApplyStringDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!?Value {
        if (captures.len != 1) return null;
        if (captures[0].tag() == .builtin and captures[0].asBuiltin() == .concat) {
            return switch (kind) {
                .fold => try self.tryApplyStringJoinDerived(args),
                .scan => try self.tryApplyStringSplitDerived(args),
                else => null,
            };
        }
        if (stringDelimiterBytes(captures[0]) != null) {
            return switch (kind) {
                .fold => if (args.len == 1 and isJoinableStringSequence(args[0]))
                    try self.joinValues(captures[0], args[0])
                else
                    null,
                .scan => if (args.len == 1 and stringBytes(args[0]) != null)
                    try self.splitValues(captures[0], args[0])
                else
                    null,
                else => null,
            };
        }
        return switch (kind) {
            else => null,
        };
    }

    fn tryApplyStringJoinDerived(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 1) {
            if (!isJoinableStringSequence(args[0])) return null;
            const empty = try self.frozenHostString(&.{});
            defer self.releaseValue(empty);
            return try self.joinValues(empty, args[0]);
        }
        if (args.len == 2 and stringDelimiterBytes(args[0]) != null and isJoinableStringSequence(args[1])) {
            return try self.joinValues(args[0], args[1]);
        }
        return null;
    }

    fn tryApplyNumericEncodeDecodeDerivedKind(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!?Value {
        if (captures.len != 1 or args.len != 1) return null;
        if (valueNumericMode(captures[0]) != .int) return null;
        return switch (kind) {
            .fold => try self.decodeNumericValues(captures[0], args[0]),
            .scan => try self.encodeNumericValues(captures[0], args[0]),
            else => null,
        };
    }

    fn tryApplyStringSplitDerived(self: *Session, args: []const Value) KError!?Value {
        if (args.len == 2 and stringDelimiterBytes(args[0]) != null and stringBytes(args[1]) != null) {
            return try self.splitValues(args[0], args[1]);
        }
        return null;
    }

    fn valuesExactlyEqual(self: *Session, left: Value, right: Value) KError!bool {
        if (left.tag() != .array and right.tag() != .array) {
            const eq = try self.equalValues(left, right);
            return eq.asBool();
        }
        if (left.tag() != .array or right.tag() != .array) return false;

        const left_vector_len = numericVectorLen(left);
        const right_vector_len = numericVectorLen(right);
        if (left_vector_len != null and right_vector_len != null and left_vector_len.? != right_vector_len.?) return false;

        const left_shape = valueNonVectorNumericShape(left);
        const right_shape = valueNonVectorNumericShape(right);
        if (left_shape == null and right_shape != null) return false;
        if (left_shape != null and right_shape == null) return false;
        if (left_shape) |lhs| {
            const rhs = right_shape.?;
            if (lhs.rank != rhs.rank or !std.mem.eql(i32, lhs.shapeSlice(), rhs.shapeSlice())) return false;
        }

        if (valueNumericMode(left) != null and valueNumericMode(right) != null) {
            const left_len = left_vector_len orelse return false;
            const right_len = right_vector_len orelse return false;
            if (left_len != right_len) return false;
            for (0..left_len) |idx| {
                if (try numericFloatAt(left, idx) != try numericFloatAt(right, idx)) return false;
            }
            return true;
        }

        const left_array = try numericHostArrayValue(self, left);
        const right_array = try numericHostArrayValue(self, right);
        if (left_array.len() != right_array.len()) return false;
        for (0..left_array.len()) |idx| {
            const lhs = try self.hostDenseIndexScalar(left_array, @intCast(idx));
            const rhs = try self.hostDenseIndexScalar(right_array, @intCast(idx));
            defer self.releaseValue(lhs);
            defer self.releaseValue(rhs);
            if (!(try self.valuesExactlyEqual(lhs, rhs))) return false;
        }
        return true;
    }

    fn applyConvergeDerived(self: *Session, base: Value, input: Value, collect: bool) KError!Value {
        const initial = self.shareValue(input);
        defer self.releaseValue(initial);

        var current = self.shareValue(input);
        errdefer self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) try results.append(self.allocator, self.shareValue(current));

        while (true) {
            const next = try self.applyDerivedBase(base, &[_]Value{current});
            const converged = (try self.valuesExactlyEqual(current, next)) or (try self.valuesExactlyEqual(initial, next));
            if (converged) {
                self.releaseValue(current);
                if (!collect) return next;
                self.releaseValue(next);
                return try self.createManagedArrayLikeFromValues(results.items);
            }
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }
    }

    fn tryApplyControlledFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (args.len != 2 or !convergeUsesMonadicBase(base)) return null;
        if (scalarIntLikeValue(args[0])) |count| {
            return try self.applyCountedOverDerived(base, count, args[1], collect);
        }
        if (valueIsCallable(args[0])) {
            return try self.applyWhileOverDerived(base, args[0], args[1], collect);
        }
        return null;
    }

    fn applyCountedOverDerived(self: *Session, base: Value, raw_count: i64, input: Value, collect: bool) KError!Value {
        const count: usize = if (raw_count <= 0)
            0
        else
            std.math.cast(usize, raw_count) orelse return error.Unsupported;

        var current = self.shareValue(input);
        var current_owned = true;
        errdefer if (current_owned) self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) {
            try results.ensureTotalCapacity(self.allocator, std.math.add(usize, count, 1) catch return error.Unsupported);
            try results.append(self.allocator, self.shareValue(current));
        }

        for (0..count) |_| {
            const next = try self.applyDerivedBase(base, &[_]Value{current});
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }

        if (collect) {
            current_owned = false;
            defer self.releaseValue(current);
            return try self.createManagedArrayLikeFromValues(results.items);
        }
        current_owned = false;
        return current;
    }

    fn applyWhileOverDerived(self: *Session, base: Value, predicate: Value, input: Value, collect: bool) KError!Value {
        var current = self.shareValue(input);
        var current_owned = true;
        errdefer if (current_owned) self.releaseValue(current);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        if (collect) try results.append(self.allocator, self.shareValue(current));

        while (true) {
            const condition = try self.applyDerivedBase(predicate, &[_]Value{current});
            const keep_going = branchTruthValue(condition) orelse {
                self.releaseValue(condition);
                return error.Type;
            };
            self.releaseValue(condition);
            if (!keep_going) break;

            const next = try self.applyDerivedBase(base, &[_]Value{current});
            self.releaseValue(current);
            current = next;
            if (collect) try results.append(self.allocator, self.shareValue(current));
        }

        if (collect) {
            current_owned = false;
            defer self.releaseValue(current);
            return try self.createManagedArrayLikeFromValues(results.items);
        }
        current_owned = false;
        return current;
    }

    fn applyEachDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each);
        defer profile_scope.end();
        if (try self.tryFastTransposeEachDerived(base, args)) |value| return value;
        if (try self.tryFastBatchedMatmulEachDerived(base, args)) |value| return value;
        if (try self.tryFastUnaryLiftedEachDerived(base, args)) |value| return value;
        if (try self.tryFastBackendMatrixRowFoldEachDerived(base, args)) |value| return value;
        if (try self.tryFastHostMatrixRowAddScanEach(base, args)) |value| return value;
        if (try self.tryFastHostMatrixRowMinMaxScanEach(base, args)) |value| return value;
        if (try self.tryFastDenseEachDerived(base, args)) |value| return value;
        var len: ?usize = null;
        var saw_array = false;
        for (args) |arg| {
            if (derivedSequenceLen(arg)) |arg_len| {
                saw_array = true;
                if (len) |existing| {
                    if (existing != arg_len) return error.Type;
                } else {
                    len = arg_len;
                }
            }
        }
        if (!saw_array) return try self.applyDerivedBase(base, args);
        if (comptime enable_probe_instrumentation) self.debug_apply_each_generic_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }

        const out_len = len.?;
        try results.ensureTotalCapacity(self.allocator, out_len);
        for (0..out_len) |idx| {
            var step_args_buf: [8]Value = undefined;
            if (args.len > step_args_buf.len) return error.Unsupported;
            for (args, 0..) |arg, arg_idx| {
                step_args_buf[arg_idx] = if (derivedSequenceLen(arg) != null) try self.derivedSequenceItemValue(arg, idx) else arg;
            }
            const result = blk: {
                defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 0);
                break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastTransposeEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 1 or base.tag() != .builtin or base.asBuiltin() != .add) return null;
        const handle = shapedNumericHandle(args[0]) orelse return null;
        if (handle.rank < 3 or valueNumericMode(args[0]) == null) return null;
        return try self.transposeDenseNumericValueSwapAxes(args[0], handle, 1, 2);
    }

    fn tryFastBatchedMatmulEachDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 2 or base.tag() != .closure) return null;
        const closure = base.asClosure();
        if (try self.innerProductInfoFromClosure(closure)) |info| {
            if (info.reduce == .add and info.map == .mul) {
                return try self.applyBatchedMatmulValues(args[0], args[1]);
            }
        }
        if (closureDerivedKind(closure) != .each_left or closure.captures.len != 1) return null;
        const inner = closure.captures[0];
        if (inner.tag() != .closure) return null;
        const info = (try self.innerProductInfoFromClosure(inner.asClosure())) orelse return null;
        if (info.reduce != .add or info.map != .mul) return null;
        return try self.applyBatchedMatmulValues(args[0], args[1]);
    }

