    fn fastHostAddScanIntMaybeSeed(self: *Session, source_value: Value, view: HostIntArrayView, seed: ?i64) KError!Value {
        const analysis = try analyzeAddScanIntView(view, seed);
        const len = hostIntArrayViewLen(view);
        var plan = try self.planHostIntUnaryOutput(
            source_value,
            hostIntArrayViewKind(view),
            analysis.kind,
            len,
            true,
            true,
        );
        fillAddScanIntResult(&plan.output, view, seed);
        return try self.finishHostIntOutput(plan, analysis.flags);
    }

