    fn minMaxScanCanReturnInput(op: BuiltinId, flags: u8) bool {
        const mono = monotonicFlags(flags);
        return switch (op) {
            .minimum => (mono & host_dense_flag_dsc) != 0,
            .maximum => (mono & host_dense_flag_asc) != 0,
            else => false,
        };
    }

    fn minMaxScanNeedsFirstPrefix(op: BuiltinId, flags: u8) bool {
        const mono = monotonicFlags(flags);
        return switch (op) {
            .minimum => (mono & host_dense_flag_asc) != 0,
            .maximum => (mono & host_dense_flag_dsc) != 0,
            else => false,
        };
    }

    fn repeatFirstAxisFirstCell(self: *Session, source: Value, shape: NumericShapeSnapshot) KError!?Value {
        if (shape.rank <= 1 or shape.shape[0] <= 0) return null;
        const rows: usize = @intCast(shape.shape[0]);
        const row_indices = try newRangeIotaValueWithParams(self, .managed, rows, 0, 0);
        defer self.releaseValue(row_indices);
        return try newFirstAxisIndexValue(self, source, row_indices);
    }

    fn tryFastHostMinMaxScanOrderedInt(self: *Session, op: BuiltinId, vector: Value, view: HostIntDenseView, shape: ?NumericShapeSnapshot) KError!?Value {
        const flags = hostIntDenseValueFlags(vector, view);
        const len = hostIntDenseViewLen(view);
        if (len == 0) return null;
        if (minMaxScanCanReturnInput(op, flags)) return self.shareValue(vector);
        if (!minMaxScanNeedsFirstPrefix(op, flags)) return null;
        if (shape) |snapshot| return try self.repeatFirstAxisFirstCell(vector, snapshot);

        const first = try hostIntDenseViewItem(view, 0);
        return try newRangeIotaValueWithParams(self, .managed, len, first, 0);
    }

    fn tryFastHostMinMaxScanOrderedFloat(self: *Session, op: BuiltinId, vector: Value, view: HostFloatDenseView, shape: ?NumericShapeSnapshot) KError!?Value {
        const flags = hostFloatDenseValueFlags(vector, view);
        const len = hostFloatDenseViewLen(view);
        if (len == 0) return null;
        if (minMaxScanCanReturnInput(op, flags)) return self.shareValue(vector);
        if (!minMaxScanNeedsFirstPrefix(op, flags)) return null;
        if (shape) |snapshot| return try self.repeatFirstAxisFirstCell(vector, snapshot);

        const first = try hostFloatDenseViewItem(view, 0);
        const count = std.math.cast(i64, len) orelse return error.Unsupported;
        const scalar = switch (valueFloatStorageKind(vector) orelse .float64) {
            .float32 => try self.float32Value(@floatCast(first)),
            .float64 => try self.floatValue(first),
        };
        return try self.takeScalarValue(count, scalar);
    }

    fn tryFastHostMinMaxScanConstantBit(self: *Session, vector: Value) KError!?Value {
        const array = hostDenseIfPresent(vector) orelse return null;
        switch (array.storage) {
            .bit => {},
            else => return null,
        }
        const range = hostDenseCachedIntRange(array) orelse return null;
        if (range.min != range.max) return null;
        return self.shareValue(vector);
    }

    fn builtinFoldIdentityInt(op: BuiltinId) ?i64 {
        return switch (op) {
            .add => 0,
            .mul => 1,
            else => null,
        };
    }

    fn emptyNumericFoldResult(self: *Session, op: BuiltinId, seed: ?Value, template: Value) KError!Value {
        const identity = builtinFoldIdentityInt(op) orelse return error.Type;
        const mode = valueNumericMode(template) orelse return error.Type;
        const out_shape = if (valueNumericHandle(template)) |handle|
            numericShapeTailSnapshot(handle)
        else
            null;
        const want_float = mode == .float or if (seed) |seed_value|
            scalarIntLikeValue(seed_value) == null
        else
            false;

        if (want_float) {
            const fill = if (seed) |seed_value|
                try scalarNumericValue(seed_value)
            else
                @as(f64, @floatFromInt(identity));
            if (out_shape) |shape| {
                const len = try numericShapeSnapshotElementCount(shape);
                const out = try self.allocator.alloc(f64, len);
                defer self.allocator.free(out);
                @memset(out, fill);
                const value = try self.createManagedHostFloatArray(out);
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            }
            return try self.floatValue(fill);
        }

        const fill = if (seed) |seed_value|
            scalarIntLikeValue(seed_value) orelse return error.Type
        else
            identity;
        if (out_shape) |shape| {
            const len = try numericShapeSnapshotElementCount(shape);
            const out = try self.allocator.alloc(i64, len);
            defer self.allocator.free(out);
            @memset(out, fill);
            const value = try self.createManagedHostIntArray(out);
            return try applyNonVectorNumericShapeToValue(self, value, shape);
        }
        return try self.intValue(fill);
    }

    fn emptyNumericPrototypeFoldResult(self: *Session, op: BuiltinId, seed: ?Value, prototype: Value) KError!Value {
        const identity = builtinFoldIdentityInt(op) orelse return error.Type;
        const mode = valueNumericMode(prototype) orelse return error.Type;
        const flat_len = numericFlatLen(prototype) orelse return try self.emptyNumericFoldResult(op, seed, prototype);
        const out_shape = valueNonVectorNumericShape(prototype);
        const want_float = mode == .float or if (seed) |seed_value|
            scalarIntLikeValue(seed_value) == null
        else
            false;

        if (want_float) {
            const fill = if (seed) |seed_value|
                try scalarNumericValue(seed_value)
            else
                @as(f64, @floatFromInt(identity));
            const out = try self.allocator.alloc(f64, flat_len);
            defer self.allocator.free(out);
            @memset(out, fill);
            const value = try self.createManagedHostFloatArray(out);
            return try applyNonVectorNumericShapeToValue(self, value, out_shape);
        }

        const fill = if (seed) |seed_value|
            scalarIntLikeValue(seed_value) orelse return error.Type
        else
            identity;
        const out = try self.allocator.alloc(i64, flat_len);
        defer self.allocator.free(out);
        @memset(out, fill);
        const value = try self.createManagedHostIntArray(out);
        return try applyNonVectorNumericShapeToValue(self, value, out_shape);
    }

    fn tryEmptyBuiltinFoldScanResult(self: *Session, base: Value, args: []const Value, collect: bool, template: Value) KError!?Value {
        if (base.tag() != .builtin) return null;
        const op = base.asBuiltin();
        const identity = builtinFoldIdentityInt(op) orelse return null;

        if (collect) return self.shareValue(template);
        if (args.len == 1 and template.tag() == .array and template.arrayKind() == .host_boxed_array) {
            const array = template.asHostBoxedArray();
            if (array.len() == 0) {
                if (array.prototype) |prototype| {
                    if (valueNumericMode(prototype) != null) return try self.emptyNumericPrototypeFoldResult(op, null, prototype);
                } else {
                    return self.shareValue(template);
                }
            }
        }

        if (valueNumericMode(template) != null) {
            return try self.emptyNumericFoldResult(op, if (args.len >= 2) args[0] else null, template);
        }
        if (args.len >= 2) return self.shareValue(args[0]);
        return try self.intValue(identity);
    }

    fn appendDerivedScanResult(self: *Session, results: *std.ArrayList(Value), value: Value) KError!void {
        const retained = try self.retainEscapedValue(value);
        errdefer self.releaseValue(retained);
        try results.append(self.allocator, retained);
    }

    fn tryApplyIdentityFoldScan(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (base.tag() != .builtin or base.asBuiltin() != .identity or args.len != 1) return null;
        const value = args[0];

        if (stringSourceInfo(value)) |source| {
            const bytes = source.bytes();
            if (collect) return self.shareValue(value);
            if (bytes.len == 0) return try self.managedHostString(" ");
            return try self.stringIndexScalarValue(source, @intCast(bytes.len - 1));
        }

        return null;
    }

    fn tryApplyKeyedDictFoldScan(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        const store_value = switch (args.len) {
            1 => args[0],
            2 => args[1],
            else => return null,
        };
        if (store_value.tag() != .array or store_value.arrayKind() != .host_keyed_store) return null;
        const store = store_value.asHostKeyedStore();
        if (store.layout != .dict) return null;

        const folded = if (args.len == 1)
            try self.applyFoldDerived(base, &[_]Value{store.values}, collect)
        else
            try self.applyFoldDerived(base, &[_]Value{ args[0], store.values }, collect);
        errdefer self.releaseValue(folded);

        if (!collect) return folded;
        defer self.releaseValue(folded);
        return try self.createHostDictValueFromKeySequenceValue(store.path, store.names, folded);
    }

    fn tryApplyConcatScan(self: *Session, base: Value, args: []const Value, collect: bool) KError!?Value {
        if (!collect or args.len != 1 or base.tag() != .builtin or base.asBuiltin() != .concat) return null;
        const vector = args[0];
        const len = derivedSequenceLen(vector) orelse return null;

        var acc = try self.createManagedHostBoxedArray(&.{});
        errdefer self.releaseValue(acc);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(vector, idx);
            const next = blk: {
                defer self.releaseValue(item);
                break :blk try self.concatValues(acc, item);
            };
            self.releaseValue(acc);
            acc = next;
            try self.appendDerivedScanResult(&results, acc);
        }

        defer self.releaseValue(acc);
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyFoldDerived(self: *Session, base: Value, args: []const Value, collect: bool) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(if (collect) .apply_scan else .apply_fold);
        defer profile_scope.end();
        if (args.len == 0) return error.Arity;
        if (try self.tryFastBackendFoldDerived(base, args, collect)) |value| return value;
        if (try self.tryFastStructuralFoldDerived(base, args, collect)) |value| return value;
        if (try self.tryFastHostFoldDerived(base, args, collect)) |value| {
            self.noteHostFoldScanFast(collect);
            return value;
        }
        if (base.tag() == .builtin) {
            self.noteHostFoldScanMiss(self.classifyHostFoldScanMiss(base.asBuiltin(), args, collect));
        }
        if (try self.tryApplyControlledFoldDerived(base, args, collect)) |value| return value;
        if (try self.tryApplyIdentityFoldScan(base, args, collect)) |value| return value;
        if (try self.tryApplyKeyedDictFoldScan(base, args, collect)) |value| return value;
        if (try self.tryApplyConcatScan(base, args, collect)) |value| return value;
        if (comptime enable_probe_instrumentation) {
            if (collect) {
                self.debug_apply_scan_generic_count += 1;
            } else {
                self.debug_apply_fold_generic_count += 1;
            }
        }

        if (args.len == 1) {
            const vector = args[0];
            const len = derivedSequenceLen(vector) orelse {
                if (!collect) return self.shareValue(vector);
                return error.Type;
            };
            if (len == 0) {
                if (try self.tryEmptyBuiltinFoldScanResult(base, args, collect, vector)) |value| return value;
                return error.Type;
            }

            var acc = try self.derivedSequenceItemValue(vector, 0);
            if (!collect) {
                for (1..len) |idx| {
                    const item = try self.derivedSequenceItemValue(vector, idx);
                    const next = blk: {
                        defer self.releaseValue(item);
                        break :blk try self.applyDerivedBase(base, &[_]Value{ acc, item });
                    };
                    self.releaseValue(acc);
                    acc = next;
                }
                return acc;
            }

            var results = std.ArrayList(Value).empty;
            defer {
                for (results.items) |value| self.releaseValue(value);
                results.deinit(self.allocator);
            }
            try results.ensureTotalCapacity(self.allocator, len);
            try self.appendDerivedScanResult(&results, acc);
            for (1..len) |idx| {
                const item = try self.derivedSequenceItemValue(vector, idx);
                const next = blk: {
                    defer self.releaseValue(item);
                    break :blk try self.applyDerivedBase(base, &[_]Value{ acc, item });
                };
                self.releaseValue(acc);
                acc = next;
                try self.appendDerivedScanResult(&results, acc);
            }
            defer self.releaseValue(acc);
            return try self.createManagedArrayLikeFromValues(results.items);
        }

        var len: ?usize = null;
        var sequence_template: ?Value = null;
        for (args[1..]) |arg| {
            const arg_len = derivedSequenceLen(arg) orelse {
                if (len == null) continue;
                return error.Type;
            };
            if (len) |existing| {
                if (existing != arg_len) return error.Type;
            } else {
                len = arg_len;
                sequence_template = arg;
            }
        }

        if (len == null) {
            if (!collect) return try self.applyDerivedBase(base, args);
            return try self.applyDerivedBase(base, args);
        }
        if (len.? == 0) {
            if (sequence_template) |template| {
                if (try self.tryEmptyBuiltinFoldScanResult(base, args, collect, template)) |value| return value;
            }
            return error.Type;
        }

        var acc = self.shareValue(args[0]);
        if (!collect) {
            for (0..len.?) |idx| {
                var step_args_buf: [8]Value = undefined;
                if (args.len > step_args_buf.len) return error.Unsupported;
                step_args_buf[0] = acc;
                for (args[1..], 1..) |arg, arg_idx| step_args_buf[arg_idx] = try self.derivedSequenceItemValue(arg, idx);
                const next = blk: {
                    defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 1);
                    break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
                };
                self.releaseValue(acc);
                acc = next;
            }
            return acc;
        }

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len.?);
        for (0..len.?) |idx| {
            var step_args_buf: [8]Value = undefined;
            if (args.len > step_args_buf.len) return error.Unsupported;
            step_args_buf[0] = acc;
            for (args[1..], 1..) |arg, arg_idx| step_args_buf[arg_idx] = try self.derivedSequenceItemValue(arg, idx);
            const next = blk: {
                defer self.releaseDerivedStepArgs(args, step_args_buf[0..args.len], 1);
                break :blk try self.applyDerivedBase(base, step_args_buf[0..args.len]);
            };
            self.releaseValue(acc);
            acc = next;
            try self.appendDerivedScanResult(&results, acc);
        }
        defer self.releaseValue(acc);
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyEachRightDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each_right);
        defer profile_scope.end();
        if (args.len != 2) return error.Arity;
        if (try self.tryFastHostEachRightStringContains(base, args[0], args[1])) |value| {
            if (comptime enable_probe_instrumentation) self.debug_apply_each_right_fast_string_contains_count += 1;
            return value;
        }
        if (try self.tryFastDenseEachRightDerived(base, args)) |value| return value;
        if (comptime enable_probe_instrumentation) self.debug_apply_each_right_generic_count += 1;
        const len = derivedSequenceLen(args[1]) orelse return error.Type;
        const preserved_left = try self.retainEscapedValue(args[0]);
        defer self.releaseValue(preserved_left);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[1], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDerivedBase(base, &[_]Value{ preserved_left, item });
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastDenseEachRightDerived(self: *Session, base: Value, args: []const Value) KError!?Value {
        if (args.len != 2) return null;
        if (args[1].tag() != .array) {
            self.noteDenseEachRightMiss(.non_vector_right);
            return null;
        }
        if (valueNonVectorNumericShape(args[1]) != null) {
            self.noteDenseEachRightMiss(.non_vector_right);
            return null;
        }
        const kind = try self.classifyDenseElementwiseBaseRuntime(base) orelse {
            self.noteDenseEachRightMiss(.unsupported_base);
            return null;
        };
        const len = derivedSequenceLen(args[1]) orelse return null;
        const preserved_left = try self.retainEscapedValue(args[0]);
        defer self.releaseValue(preserved_left);
        if (self.debugDetailedProbeActive()) self.debug_apply_each_right_fast_dense_count += 1;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[1], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDenseElementwiseKind(kind, preserved_left, item);
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastHostEachRightStringContains(self: *Session, base: Value, left: Value, right: Value) KError!?Value {
        if (base.tag() != .builtin or base.asBuiltin() != .contains) return null;
        const needle = stringBytes(left) orelse {
            if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_left_count += 1;
            return null;
        };
        if (right.tag() != .array) {
            if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_right_count += 1;
            return null;
        }
        return switch (right.arrayKind()) {
            .host_string_list => try self.fastHostStringListContainsEachRight(needle, right.asHostStringList()),
            .host_boxed_array => try self.fastHostBoxedStringContainsEachRight(needle, right.asHostBoxedArray().items),
            else => blk: {
                if (self.debugDetailedProbeActive()) self.debug_each_right_fast_string_contains_miss_non_string_right_count += 1;
                break :blk null;
            },
        };
    }

    fn fastHostStringListContainsEachRight(self: *Session, needle: []const u8, list: *const HostStringList) KError!Value {
        const out = try self.allocator.alloc(bool, list.len);
        defer self.allocator.free(out);
        if (needle.len == 0) {
            @memset(out, true);
            return try self.createManagedHostBitArray(out);
        }
        switch (list.storage) {
            .eager => |items| {
                for (items, 0..) |item, idx| {
                    out[idx] = std.mem.indexOf(u8, hostStringPieceBytes(list.base, item), needle) != null;
                }
            },
            .split_scalar => |lazy| {
                const base = list.base orelse return error.Internal;
                const src = hostTextBytes(base);
                var piece_idx: usize = 0;
                var start: usize = 0;
                while (piece_idx < out.len) {
                    const sep_idx = std.mem.indexOfScalarPos(u8, src, start, lazy.sep) orelse break;
                    out[piece_idx] = std.mem.indexOf(u8, src[start..sep_idx], needle) != null;
                    piece_idx += 1;
                    start = sep_idx + 1;
                }
                if (piece_idx < out.len) out[piece_idx] = std.mem.indexOf(u8, src[start..], needle) != null;
            },
        }
        return try self.createManagedHostBitArray(out);
    }

    fn fastHostBoxedStringContainsEachRight(self: *Session, needle: []const u8, items: []const Value) KError!?Value {
        const out = try self.allocator.alloc(bool, items.len);
        defer self.allocator.free(out);
        if (needle.len == 0) {
            @memset(out, true);
            return try self.createManagedHostBitArray(out);
        }
        for (items, 0..) |item, idx| {
            const haystack = stringBytes(item) orelse return null;
            out[idx] = std.mem.indexOf(u8, haystack, needle) != null;
        }
        return try self.createManagedHostBitArray(out);
    }

    fn tryFastRowListInnerProductEachLeft(self: *Session, left: Value, right: Value) KError!?Value {
        if (left.tag() != .array or left.arraySubkind() != .host_boxed_array) return null;
        const rows = left.asHostBoxedArray();
        if (rows.len() == 0) return null;

        const right_len = numericVectorLen(right) orelse return null;
        var result_mode = valueNumericMode(right) orelse return null;
        for (rows.items) |row| {
            const row_len = numericVectorLen(row) orelse return null;
            if (row_len != right_len) return error.Type;
            const row_mode = valueNumericMode(row) orelse return null;
            if (row_mode == .float) result_mode = .float;
        }

        const right_view = try hostDenseView(self, right);
        if (result_mode == .float) {
            const out = try self.allocManagedHostFloatResult(rows.len());
            for (rows.items, 0..) |row, row_idx| {
                const row_view = try hostDenseView(self, row);
                var acc: f64 = 0.0;
                for (0..right_len) |col_idx| {
                    acc += (try hostDenseViewFloatItem(row_view, col_idx)) *
                        (try hostDenseViewFloatItem(right_view, col_idx));
                }
                out.items[row_idx] = acc;
            }
            return try out.value(self);
        }

        var out = try self.allocManagedHostIntResult(.int64, rows.len());
        for (rows.items, 0..) |row, row_idx| {
            const row_view = try hostDenseView(self, row);
            var acc: i128 = 0;
            for (0..right_len) |col_idx| {
                acc += @as(i128, try hostDenseViewIntItem(row_view, col_idx)) *
                    @as(i128, try hostDenseViewIntItem(right_view, col_idx));
            }
            try out.set(row_idx, std.math.cast(i64, acc) orelse return error.Unsupported);
        }
        return try out.value(self);
    }

    fn applyEachLeftDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_each_left);
        defer profile_scope.end();
        if (args.len != 2) return error.Arity;
        if (base.tag() == .closure) {
            if (try self.innerProductInfoFromClosure(base.asClosure())) |info| {
                if (info.reduce == .add and info.map == .mul and valueIsRenderableMatrixLike(args[0])) {
                    return try self.applyMatmulValues(args[0], args[1]);
                }
                if (info.reduce == .add and info.map == .mul) {
                    if (try self.tryFastRowListInnerProductEachLeft(args[0], args[1])) |result| return result;
                }
            }
        }
        if (comptime enable_probe_instrumentation) self.debug_apply_each_left_generic_count += 1;
        const len = derivedSequenceLen(args[0]) orelse return error.Type;
        const preserved_right = try self.retainEscapedValue(args[1]);
        defer self.releaseValue(preserved_right);

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(args[0], idx);
            const result = blk: {
                defer self.releaseValue(item);
                break :blk try self.applyDerivedBase(base, &[_]Value{ item, preserved_right });
            };
            try results.append(self.allocator, result);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyRollingEachPriorDerived(self: *Session, base: Value, seed: Value, vector: Value) KError!Value {
        if (try self.tryFastBitRollingEachPriorDerived(base, seed, vector)) |result| return result;

        const len = derivedSequenceLen(vector) orelse return error.Type;
        if (comptime enable_probe_instrumentation) {
            self.debug_apply_each_prior_generic_count += 1;
            self.debug_apply_each_prior_generic_element_count += len;
        }
        if (len == 0) return try self.createManagedHostIntArray(&.{});

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, len);

        var prior = try self.retainEscapedValue(seed);
        for (0..len) |idx| {
            const current = try self.derivedSequenceItemValue(vector, idx);
            errdefer self.releaseValue(current);
            const value = try self.applyDerivedBase(base, &[_]Value{ current, prior });
            self.releaseValue(prior);
            prior = current;
            try results.append(self.allocator, value);
        }
        defer self.releaseValue(prior);
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn tryFastBitRollingEachPriorDerived(self: *Session, base: Value, seed: Value, vector: Value) KError!?Value {
        if (base.tag() != .builtin) return null;
        const op = base.asBuiltin();
        switch (op) {
            .minimum, .mul, .maximum, .equal => {},
            else => return null,
        }
        const len = numericVectorLen(vector) orelse return null;
        const bits = valueNumericBitSlice(vector) orelse return null;
        if (bits.len != len) return error.Type;
        const BitSeedInfo = struct {
            bit: bool,
            force_first_false: bool,
        };
        const seed_info: BitSeedInfo = blk: {
            if (scalarIntLikeValue(seed)) |seed_int| {
                if (seed_int != 0 and seed_int != 1) {
                    if (op == .equal) break :blk .{ .bit = false, .force_first_false = true };
                    return null;
                }
                break :blk .{ .bit = seed_int == 1, .force_first_false = false };
            }
            if (op != .equal) return null;
            const seed_numeric = scalarNumericValue(seed) catch return null;
            if (seed_numeric == 0.0) break :blk .{ .bit = false, .force_first_false = false };
            if (seed_numeric == 1.0) break :blk .{ .bit = true, .force_first_false = false };
            break :blk .{ .bit = false, .force_first_false = true };
        };

        if (comptime enable_probe_instrumentation) {
            self.debug_apply_each_prior_fast_bit_count += 1;
            self.debug_apply_each_prior_fast_bit_element_count += len;
        }

        const out = try self.allocHostBitArrayUninitialized(.managed, bits.len);
        var carry: u64 = @intFromBool(seed_info.bit);
        for (bits.words, 0..) |_, word_idx| {
            const word = bitWordMasked(bits.words, bits.len, word_idx);
            const prior = (word << 1) | carry;
            var result = switch (op) {
                .minimum, .mul => word & prior,
                .maximum => word | prior,
                .equal => ~(word ^ prior),
                else => unreachable,
            };
            if (word_idx == 0 and seed_info.force_first_false) result &= ~@as(u64, 1);
            out.words[word_idx] = result;
            carry = word >> 63;
        }
        bitClearUnusedTail(out.words, out.len);
        return try self.finishManagedHostBitAlloc(out, host_dense_flag_normalized, .{ .min = 0, .max = 1 });
    }

    fn applyStencilEachPriorDerived(self: *Session, base: Value, left: Value, vector: Value) KError!Value {
        const raw_window_len = scalarIntLikeValue(left) orelse return error.Type;
        if (raw_window_len < 0) return error.Type;
        const sequence_len = derivedSequenceLen(vector) orelse return error.Type;
        const window_len: usize = @intCast(raw_window_len);
        const result_len: usize = if (window_len == 0)
            sequence_len + 1
        else if (window_len > sequence_len)
            0
        else
            sequence_len + 1 - window_len;

        var results = std.ArrayList(Value).empty;
        defer {
            for (results.items) |value| self.releaseValue(value);
            results.deinit(self.allocator);
        }
        try results.ensureTotalCapacity(self.allocator, result_len);

        const count_value = try self.intValue(raw_window_len);
        defer self.releaseValue(count_value);

        for (0..result_len) |start| {
            const start_i64 = std.math.cast(i64, start) orelse return error.Unsupported;
            const start_value = try self.intValue(start_i64);
            defer self.releaseValue(start_value);
            const dropped = try self.dropValues(start_value, vector);
            defer self.releaseValue(dropped);
            const window = try self.takeValues(count_value, dropped);
            const value = blk: {
                defer self.releaseValue(window);
                break :blk try self.applyDerivedBase(base, &[_]Value{window});
            };
            try results.append(self.allocator, value);
        }
        return try self.createManagedArrayLikeFromValues(results.items);
    }

    fn applyEachPriorDerived(self: *Session, base: Value, args: []const Value) KError!Value {
        return switch (args.len) {
            1 => blk: {
                if (eachPriorUsesMonadicBase(base)) return error.Arity;
                const sequence_len = derivedSequenceLen(args[0]) orelse return error.Type;
                if (sequence_len == 0) return try self.createManagedHostIntArray(&.{});
                const seed = try self.eachPriorImplicitSeedValue(base, args[0]);
                defer self.releaseValue(seed);
                break :blk try self.applyRollingEachPriorDerived(base, seed, args[0]);
            },
            2 => if (eachPriorUsesMonadicBase(base))
                try self.applyStencilEachPriorDerived(base, args[0], args[1])
            else
                try self.applyRollingEachPriorDerived(base, args[0], args[1]),
            else => error.Arity,
        };
    }

    fn classifyHostFoldScanMiss(self: *Session, op: BuiltinId, args: []const Value, collect: bool) DebugHostFoldScanMiss {
        if (args.len == 0 or args.len > 2) return .unsupported_input;
        if (collect and op != .add and op != .minimum and op != .maximum) return .unsupported_builtin;
        switch (op) {
            .add, .sub, .mul, .minimum, .maximum => {},
            else => return .unsupported_builtin,
        }
        if (self.dense_backend_override == .mlx) return .backend_override;

        const value = args[args.len - 1];
        if (!collect) {
            if (shapedNumericHandle(value)) |handle| {
                if (planDenseRegionDecision(.reduce, denseReduceScanFacts(value)).backend != .host) return .planner_non_host;
                const outer_len: usize = @intCast(handle.shape[0]);
                if (outer_len <= 1) return .preserve_generic_semantics;
                return .unsupported_input;
            }
        }

        if (valueNonVectorNumericShape(value) != null) return .non_numeric_or_shape;
        if ((op == .minimum or op == .maximum) and planDenseRegionDecision(.reduce, denseReduceScanFacts(value)).backend != .host) {
            return .planner_non_host;
        }

        if (value.tag() == .array and value.arrayKind() == .numeric_array) {
            const handle = value.asNumericArray();
            if (numericArrayIsVectorRangeIota(handle)) {
                if (numericArrayRangeLen(handle) <= 1) return .preserve_generic_semantics;
                return .unsupported_input;
            }
        }

        const array = hostDenseIfPresent(value) orelse return .unsupported_input;
        if (array.len() <= 1) return .preserve_generic_semantics;
        return .unsupported_input;
    }

    fn checkedSelectorDyad(op: BuiltinId, left: i64, right: i64) KError!i64 {
        const result = switch (op) {
            .add => @addWithOverflow(left, right),
            .sub => @subWithOverflow(left, right),
            else => return error.Type,
        };
        if (result[1] != 0) return error.Type;
        return result[0];
    }

    fn recordIndexedAssign(self: *Session, target: IndexedAssignTarget) void {
        if (comptime enable_probe_instrumentation) {
            self.debug_indexed_assign_count += 1;
            switch (target) {
                .global => self.debug_indexed_assign_global_count += 1,
                .local => self.debug_indexed_assign_local_count += 1,
            }
        }
    }

    fn releaseOwnedValues(self: *Session, values: []const Value) void {
        for (values) |value| self.releaseValue(value);
    }

    fn tryApplyOwnedClosureArgs(self: *Session, closure: *const Closure, args: []const Value) KError!?Value {
        const may_derived = closureMayUseDerivedApply(closure);
        switch (args.len) {
            1 => {
                if (may_derived) {
                    if (try self.applyDerivedClosure(closure, args)) |result| return result;
                }
                return null;
            },
            2 => {
                if (may_derived) {
                    if (try self.tryApplyStructuredDerivedClosure2(closure, args[0], args[1])) |result| return result;
                    if (try self.applyDerivedClosure(closure, args)) |result| return result;
                }
                return null;
            },
            3 => {
                if (may_derived) {
                    if (try self.applyDerivedClosure(closure, args)) |result| return result;
                }
                return null;
            },
            else => return if (may_derived) try self.applyDerivedClosure(closure, args) else null,
        }
    }

    fn applyGlobalIndexArrayValue(self: *Session, callee: Value, selector: Value) KError!?Value {
        if (callee.tag() != .array) return null;
        if (callee.arrayKind() == .host_keyed_store and callee.asHostKeyedStore().layout == .dict) {
            return try self.applyArrayCall1(callee, selector);
        }
        if (scalarIntLikeValue(selector)) |raw_index| return try self.applyArrayCall1Scalar(callee, raw_index);
        return try self.applyArrayCall1(callee, selector);
    }

    fn execDyad(self: *Session, op: BuiltinId) KError!void {
        const op_start = stringPerfNow();
        const right = self.pop();
        const left = self.pop();
        errdefer self.releaseCanonicalManagedNumericValue(left);
        errdefer self.releaseCanonicalManagedNumericValue(right);
        if (try self.tryFastInlineScalarDyad(op, left, right)) |fast| {
            self.releaseCanonicalManagedNumericValue(left);
            self.releaseCanonicalManagedNumericValue(right);
            try self.push(fast);
            return;
        }
        const value = try self.applyDyad(op, left, right);
        self.releaseCanonicalManagedNumericValue(left);
        self.releaseCanonicalManagedNumericValue(right);
        try self.push(value);
        if (comptime enable_string_instrumentation) switch (op) {
            .contains => {
                self.string_perf.contains_calls += 1;
                stringPerfAdd(&self.string_perf.contains_opcode_ns, op_start);
            },
            .split => {
                self.string_perf.split_calls += 1;
                stringPerfAdd(&self.string_perf.split_opcode_ns, op_start);
            },
            .join => {
                self.string_perf.join_calls += 1;
                stringPerfAdd(&self.string_perf.join_opcode_ns, op_start);
            },
            else => {},
        };
    }

    fn execContainsOpcode(self: *Session) KError!void {
        const op_start = stringPerfNow();
        const right = self.pop();
        const left = self.pop();
        errdefer self.releaseCanonicalManagedNumericValue(left);
        errdefer self.releaseCanonicalManagedNumericValue(right);
        const value = if (stringBytes(left) != null and stringBytes(right) != null)
            try self.containsValues(left, right)
        else
            try self.applyDyad(.contains, left, right);
        self.releaseCanonicalManagedNumericValue(left);
        self.releaseCanonicalManagedNumericValue(right);
        try self.push(value);
        if (comptime enable_string_instrumentation) {
            self.string_perf.contains_calls += 1;
            stringPerfAdd(&self.string_perf.contains_opcode_ns, op_start);
        }
    }

    fn execSplitOpcode(self: *Session) KError!void {
        const op_start = stringPerfNow();
