    const InsertBounds = struct {
        start: usize,
        end: usize,
    };

    fn insertBoundsFromSelector(selector: Value, len: usize) KError!InsertBounds {
        if (scalarIntLikeValue(selector)) |raw| {
            if (raw < 0 or raw > @as(i64, @intCast(len))) return error.Type;
            const idx: usize = @intCast(raw);
            return .{ .start = idx, .end = idx };
        }

        const selector_len = numericVectorLen(selector) orelse return error.Type;
        if (selector_len != 2) return error.Type;
        const start_raw = try numericIntAt(selector, 0);
        const end_raw = try numericIntAt(selector, 1);
        if (start_raw < 0 or end_raw < start_raw or end_raw > @as(i64, @intCast(len))) return error.Type;
        return .{ .start = @intCast(start_raw), .end = @intCast(end_raw) };
    }

    fn insertNumericValueCount(value: Value) KError!usize {
        if (numericVectorLen(value)) |len| return len;
        if (scalarNumericFloatValue(value) != null or value.tag() == .float32) return 1;
        return error.Type;
    }

    fn insertNumericFloatAt(value: Value, idx: usize) KError!f64 {
        if (numericVectorLen(value) != null) {
            return switch (valueNumericMode(value) orelse return error.Type) {
                .int => @floatFromInt(try numericIntAt(value, idx)),
                .float => try numericFloatAt(value, idx),
            };
        }
        return switch (value.tag()) {
            .int => @floatFromInt(value.asInt()),
            .bool => @floatFromInt(@intFromBool(value.asBool())),
            .float32 => @floatCast(value.asFloat32()),
            .float => value.asFloat(),
            else => error.Type,
        };
    }

    fn insertNumericIntAt(value: Value, idx: usize) KError!i64 {
        if (numericVectorLen(value) != null) return try numericIntAt(value, idx);
        return scalarIntLikeValue(value) orelse error.Type;
    }

    fn insertNumericValue(self: *Session, source: Value, selector: Value, replacement: Value) KError!Value {
        const source_len = numericVectorLen(source) orelse return error.Type;
        const bounds = try insertBoundsFromSelector(selector, source_len);
        const replacement_len = try insertNumericValueCount(replacement);
        const out_len = source_len - (bounds.end - bounds.start) + replacement_len;
        const source_mode = valueNumericMode(source) orelse return error.Type;
        const replacement_mode = valueNumericMode(replacement) orelse return error.Type;
        const out_mode: HostDenseElem = if (source_mode == .float or replacement_mode == .float) .float else .int;

        switch (out_mode) {
            .int => {
                const out = try self.allocator.alloc(i64, out_len);
                defer self.allocator.free(out);
                var out_idx: usize = 0;
                for (0..bounds.start) |idx| {
                    out[out_idx] = try numericIntAt(source, idx);
                    out_idx += 1;
                }
                for (0..replacement_len) |idx| {
                    out[out_idx] = try insertNumericIntAt(replacement, idx);
                    out_idx += 1;
                }
                for (bounds.end..source_len) |idx| {
                    out[out_idx] = try numericIntAt(source, idx);
                    out_idx += 1;
                }
                return try self.createManagedHostIntArray(out);
            },
            .float => {
                const out = try self.allocator.alloc(f64, out_len);
                defer self.allocator.free(out);
                var out_idx: usize = 0;
                for (0..bounds.start) |idx| {
                    out[out_idx] = try insertNumericFloatAt(source, idx);
                    out_idx += 1;
                }
                for (0..replacement_len) |idx| {
                    out[out_idx] = try insertNumericFloatAt(replacement, idx);
                    out_idx += 1;
                }
                for (bounds.end..source_len) |idx| {
                    out[out_idx] = try insertNumericFloatAt(source, idx);
                    out_idx += 1;
                }
                return try self.createManagedHostFloatArray(out);
            },
        }
    }

    fn tryFastHostMinMaxScan(self: *Session, op: BuiltinId, args: []const Value) KError!?Value {
        if (!enable_host_minmax_scan_fast_path) return null;
        if (args.len == 0 or args.len > 2) return null;
        if (self.dense_backend_override == .mlx) return null;

        const vector = args[args.len - 1];
        const shape = valueNonVectorNumericShape(vector);
        if (args.len == 1) {
            if (try self.tryFastHostMinMaxScanConstantBit(vector)) |result| {
                noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                return result;
            }
        }

        const view = hostDenseView(self, vector) catch return null;
        const len = switch (view) {
            .int_array => |items| hostIntDenseViewLen(items),
            .float_array => |items| hostFloatDenseViewLen(items),
            else => return null,
        };
        if (args.len == 1 and len == 0) return error.Type;
        if (len <= 1) return null;
        if (args.len == 1) {
            switch (view) {
                .int_array => |items| {
                    if (try self.tryFastHostMinMaxScanOrderedInt(op, vector, items, shape)) |result| {
                        noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                        return result;
                    }
                },
                .float_array => |items| {
                    if (try self.tryFastHostMinMaxScanOrderedFloat(op, vector, items, shape)) |result| {
                        noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                        return result;
                    }
                },
                else => {},
            }
        }
        if (shape != null and args.len == 1) {
            switch (view) {
                .int_array => |items| {
                    if (hostIntDenseViewBitSlice(items)) |bits| {
                        const handle = shapedNumericHandle(vector) orelse return null;
                        noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                        return try self.fastHostFirstAxisBitMinMaxScan(handle, bits, op);
                    }
                    const range = hostIntDenseValueRange(vector, items);
                    if (range.min >= 0 and range.max <= 1) {
                        const handle = shapedNumericHandle(vector) orelse return null;
                        noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                        const host = numericHostArrayValue(self, vector) catch null;
                        if (host) |array| switch (array.storage) {
                            .bit => |words| {
                                const bits = HostBitSlice{ .words = hostDenseLogicalBitWords(array, words), .len = array.logical_len };
                                return try self.fastHostFirstAxisBitMinMaxScan(handle, bits, op);
                            },
                            else => {},
                        };
                        return try self.fastHostFirstAxisBitLikeMinMaxScan(handle, items, op);
                    }
                },
                else => {},
            }
        }
        if (shape != null) return null;

        switch (view) {
            .int_array => |items| {
                if (hostIntDenseViewBitSlice(items)) |bits| {
                    if (args.len == 1) {
                        noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                        return try self.fastHostBitMinMaxScan(op, bits, null);
                    }
                    if (scalarIntLikeValue(args[0])) |seed_int| {
                        if (bitMinMaxScanResultIsBit(op, seed_int)) {
                            noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                            return try self.fastHostBitMinMaxScan(op, bits, seed_int);
                        }
                        noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                        return try self.fastHostMinMaxScanInt(items, op, seed_int);
                    }
                    const seed_float = scalarNumericValue(args[0]) catch return null;
                    noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                    return try self.fastHostMinMaxScanFloatFromInt(items, op, seed_float);
                }

                if (args.len == 1) {
                    noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                    return try self.fastHostMinMaxScanInt(items, op, null);
                }
                if (scalarIntLikeValue(args[0])) |seed_int| {
                    noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                    return try self.fastHostMinMaxScanInt(items, op, seed_int);
                }
                const seed_float = scalarNumericValue(args[0]) catch return null;
                noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                return try self.fastHostMinMaxScanFloatFromInt(items, op, seed_float);
            },
            .float_array => |items| {
                if (args.len == 1) {
                    noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                    return try self.fastHostMinMaxScanFloat(items, op, null);
                }
                const seed = scalarNumericValue(args[0]) catch return null;
                noteDensePlanDecision(self, .scan, .host, .host, .host_fast_kernel);
                return try self.fastHostMinMaxScanFloat(items, op, seed);
            },
            else => return null,
        }
    }

    fn insertStringValue(self: *Session, source: Value, selector: Value, replacement: Value) KError!Value {
        const source_bytes = stringBytes(source) orelse return error.Type;
        const replacement_bytes = stringBytes(replacement) orelse return error.Type;
        const bounds = try insertBoundsFromSelector(selector, source_bytes.len);
        const out_len = source_bytes.len - (bounds.end - bounds.start) + replacement_bytes.len;
        const out = try self.allocator.alloc(u8, out_len);
        defer self.allocator.free(out);
        @memcpy(out[0..bounds.start], source_bytes[0..bounds.start]);
        @memcpy(out[bounds.start .. bounds.start + replacement_bytes.len], replacement_bytes);
        @memcpy(out[bounds.start + replacement_bytes.len ..], source_bytes[bounds.end..]);
        if (out.len == 1) return try self.managedHostCharVector(out);
        return try self.managedHostString(out);
    }

    fn insertSymbolReplacementCount(value: Value) KError!usize {
        if (symbolBytes(value) != null) return 1;
        if (value.tag() == .array and value.arrayKind() == .host_symbol_list) return value.asHostStringList().len;
        return error.Type;
    }

    fn insertSymbolReplacementBytes(value: Value, idx: usize) KError![]const u8 {
        if (symbolBytes(value)) |bytes| {
            if (idx != 0) return error.Internal;
            return bytes;
        }
        if (value.tag() == .array and value.arrayKind() == .host_symbol_list) return try hostStringListItemBytes(value.asHostStringList(), idx);
        return error.Type;
    }

    fn insertSymbolListValue(self: *Session, source: Value, selector: Value, replacement: Value) KError!Value {
        if (source.tag() != .array or source.arrayKind() != .host_symbol_list) return error.Type;
        const source_list = source.asHostStringList();
        const bounds = try insertBoundsFromSelector(selector, source_list.len);
        const replacement_len = try insertSymbolReplacementCount(replacement);
        const out_len = source_list.len - (bounds.end - bounds.start) + replacement_len;
        const out = try self.allocator.alloc([]const u8, out_len);
        defer self.allocator.free(out);
        var out_idx: usize = 0;
        for (0..bounds.start) |idx| {
            out[out_idx] = try hostStringListItemBytes(source_list, idx);
            out_idx += 1;
        }
        for (0..replacement_len) |idx| {
            out[out_idx] = try insertSymbolReplacementBytes(replacement, idx);
            out_idx += 1;
        }
        for (bounds.end..source_list.len) |idx| {
            out[out_idx] = try hostStringListItemBytes(source_list, idx);
            out_idx += 1;
        }
        return try self.createManagedHostSymbolListFromSlices(out);
    }

    fn insertBoxedReplacementCount(value: Value) usize {
        if (value.tag() == .array and value.arrayKind() == .host_boxed_array) return value.asHostBoxedArray().len();
        return 1;
    }

    fn insertBoxedReplacementValue(self: *Session, value: Value, idx: usize) KError!Value {
        if (value.tag() == .array and value.arrayKind() == .host_boxed_array) return try self.hostBoxedArrayIndexScalar(value.asHostBoxedArray(), @intCast(idx));
        if (idx != 0) return error.Internal;
        return try self.retainEscapedValue(value);
    }

    fn insertBoxedValue(self: *Session, source: Value, selector: Value, replacement: Value) KError!Value {
        if (source.tag() != .array or source.arrayKind() != .host_boxed_array) return error.Type;
        const source_array = source.asHostBoxedArray();
        const bounds = try insertBoundsFromSelector(selector, source_array.len());
        const replacement_len = insertBoxedReplacementCount(replacement);
        const out_len = source_array.len() - (bounds.end - bounds.start) + replacement_len;
        const out = try self.allocator.alloc(Value, out_len);
        defer self.allocator.free(out);
        var initialized: usize = 0;
        defer {
            for (out[0..initialized]) |value| self.releaseValue(value);
        }

        for (0..bounds.start) |idx| {
            out[initialized] = try self.hostBoxedArrayIndexScalar(source_array, @intCast(idx));
            initialized += 1;
        }
        for (0..replacement_len) |idx| {
            out[initialized] = try self.insertBoxedReplacementValue(replacement, idx);
            initialized += 1;
        }
        for (bounds.end..source_array.len()) |idx| {
            out[initialized] = try self.hostBoxedArrayIndexScalar(source_array, @intCast(idx));
            initialized += 1;
        }
        return try self.createManagedHostBoxedArray(out);
    }

    fn tableRangeValue(self: *Session, store: *const HostKeyedStore, start: usize, end: usize) KError!Value {
        if (end < start or end > store.row_count) return error.Type;
        const row_indices = try self.allocator.alloc(usize, end - start);
        defer self.allocator.free(row_indices);
        for (row_indices, start..) |*idx, row| idx.* = row;
        return try self.tableSelectRows(store, row_indices);
    }

    fn insertTableValue(self: *Session, source: Value, selector: Value, replacement: Value) KError!Value {
        if (source.tag() != .array or source.arrayKind() != .host_keyed_store) return error.Type;
        const source_store = source.asHostKeyedStore();
        if (source_store.layout != .table) return error.Type;
        const bounds = try insertBoundsFromSelector(selector, source_store.row_count);

        const replacement_table = blk: {
            if (replacement.tag() != .array or replacement.arrayKind() != .host_keyed_store) return error.Type;
            const replacement_store = replacement.asHostKeyedStore();
            break :blk switch (replacement_store.layout) {
                .table => try self.retainEscapedValue(replacement),
                .dict => try self.flipValue(replacement),
            };
        };
        defer self.releaseValue(replacement_table);
        const replacement_store = replacement_table.asHostKeyedStore();
        if (replacement_store.layout != .table) return error.Type;

        const prefix = try self.tableRangeValue(source_store, 0, bounds.start);
        defer self.releaseValue(prefix);
        const suffix = try self.tableRangeValue(source_store, bounds.end, source_store.row_count);
        defer self.releaseValue(suffix);

        const left = try self.concatTableValues(prefix.asHostKeyedStore(), replacement_store);
        defer self.releaseValue(left);
        return try self.concatTableValues(left.asHostKeyedStore(), suffix.asHostKeyedStore());
    }

    fn insertValue(self: *Session, source: Value, selector: Value, replacement: Value) KError!Value {
        if (stringBytes(source) != null) return try self.insertStringValue(source, selector, replacement);
        if (source.tag() == .array) {
            return switch (source.arrayKind()) {
                .host_symbol_list => try self.insertSymbolListValue(source, selector, replacement),
                .host_boxed_array => try self.insertBoxedValue(source, selector, replacement),
                .host_keyed_store => try self.insertTableValue(source, selector, replacement),
                else => if (valueNumericMode(source) != null)
                    try self.insertNumericValue(source, selector, replacement)
                else
                    error.Type,
            };
        }
        return error.Type;
    }

    fn builtinUsesGenericArityDispatch(op: BuiltinId) bool {
        return switch (op) {
            .prng,
            .grad,
            .valuegrad,
            .rope,
            .ropeflat,
            .ropecisflat,
            .rmsnorm,
            .layernorm,
            .gelu,
            .geluapprox,
            .mlpdense,
            .conv2d,
            .convtranspose2d,
            .upsamplenearest2d,
            .groupnorm,
            .softmax,
            .sdpa,
            .sam3boxrpb,
            .sdpamask,
            .sdpaflat,
            => false,
            else => true,
        };
    }

    fn applyBuiltinCall(self: *Session, op: BuiltinId, args: []const Value) KError!Value {
        var profile_scope = self.beginSamplingProfileScope(.apply_builtin);
        defer profile_scope.end();
        if (op == .prng) return try self.applyPrngBuiltin(args);
        if (op == .grad or op == .valuegrad) return try self.applyAutogradBuiltin(op, args);
        if (op == .rope) return try self.applyRopeBuiltin(args);
        if (op == .ropeflat) return try self.applyRopeFlatBuiltin(args);
        if (op == .ropecisflat) return try self.applyRopeCisFlatBuiltin(args);
        if (op == .rmsnorm) return try self.applyRmsNormBuiltin(args);
        if (op == .layernorm) return try self.applyLayerNormBuiltin(args);
        if (op == .gelu) return try self.applyGeluBuiltin(args);
        if (op == .geluapprox) return try self.applyGeluApproxBuiltin(args);
        if (op == .mlpdense) return try self.applyMlpDenseBuiltin(args);
        if (op == .conv2d) return try self.applyConv2dBuiltin(args);
        if (op == .convtranspose2d) return try self.applyConvTranspose2dBuiltin(args);
        if (op == .upsamplenearest2d) return try self.applyUpsampleNearest2dBuiltin(args);
        if (op == .groupnorm) return try self.applyGroupNormBuiltin(args);
        if (op == .softmax) return try self.applySoftmaxBuiltin(args);
        if (op == .sdpa) return try self.applySdpaBuiltin(args);
        if (op == .sam3boxrpb) return try self.applySam3BoxRpbBuiltin(args);
        if (op == .sdpamask) return try self.applySdpaMaskBuiltin(args);
        if (op == .sdpaflat) return try self.applySdpaFlatBuiltin(args);
        return switch (args.len) {
            0 => error.Arity,
            1 => self.applyMonad(op, args[0]),
            2 => self.applyDyad(dyadicBuiltinForGenericCall(op), args[0], args[1]),
            3 => if (op == .unique or op == .find) self.insertValue(args[0], args[1], args[2]) else error.Arity,
            else => error.Arity,
        };
    }

    fn applyArrayCall(self: *Session, callee: Value, args: []const Value) KError!Value {
        if (args.len == 0) return error.Arity;
        if (args.len == 1) return try self.applyArrayCall1(callee, args[0]);
        return try self.deepIndexValue(callee, args);
    }

    fn dyadicBuiltinForGenericCall(op: BuiltinId) BuiltinId {
        return switch (op) {
            .count => .take,
            .floor => .drop,
            .sort => .reshape,
            .stringify => .cast,
            .unique => .find,
            else => op,
        };
    }

    fn applyArrayCall1Scalar(self: *Session, callee: Value, raw_index: i64) KError!Value {
        if (callee.tag() != .array) return error.Type;
        if (callee.arrayKind() == .host_keyed_store and callee.asHostKeyedStore().layout == .dict) {
            const key = try self.intValue(raw_index);
            defer self.releaseValue(key);
            return try self.keyedStoreLookupValueByKey(callee.asHostKeyedStore(), key);
        }
        if (stringSourceInfo(callee)) |source| return try self.stringIndexScalarValue(source, raw_index);
        if (try numericValueScalarIndexValue(self, callee, raw_index)) |result| return result;
        if (valueRangeIotaHandle(callee)) |handle| {
            return (try numericStructuralScalarIndexValue(self, .{ .handle = handle }, raw_index)).?;
        }
        if (valueNonVectorNumericShape(callee) == null) {
            if (hostDenseIfPresent(callee)) |array| return try self.hostDenseIndexScalar(array, raw_index);
        }
        if (valueNumericHandle(callee)) |handle| {
            return try self.hostDenseIndexScalar(try hostStructuralArrayForHandle(self, @constCast(handle)), raw_index);
        }
        return switch (callee.arrayKind()) {
            .host_dense_array, .backend_array => try self.hostDenseIndexScalar(try numericHostArrayValue(self, callee), raw_index),
            .host_boxed_array => try self.hostBoxedArrayIndexScalar(callee.asHostBoxedArray(), raw_index),
            .host_string_list => if (normalizeIndexOrNull(raw_index, callee.asHostStringList().len)) |idx|
                try self.hostStringListItemValue(callee.asHostStringList(), idx)
            else
                try self.managedHostString(&.{}),
            .host_symbol_list => if (normalizeIndexOrNull(raw_index, callee.asHostStringList().len)) |idx|
                try self.hostSymbolListItemValue(callee.asHostStringList(), idx)
            else
                try self.emptySymbolValue(),
            .host_relation => error.Type,
            .host_keyed_store => blk: {
                const store = callee.asHostKeyedStore();
                if (store.layout != .table) break :blk error.Type;
                break :blk try self.tableRowDictValue(store, try normalizeIndex(raw_index, store.row_count));
            },
            else => error.Internal,
        };
    }

    fn stringIndexScalarValue(self: *Session, source: HostStringSource, raw_index: i64) KError!Value {
        const bytes = source.bytes();
        if (raw_index >= 0 and raw_index < @as(i64, @intCast(bytes.len))) {
            const idx: usize = @intCast(raw_index);
            return try self.managedHostStringViewWithReason(source.base, .{
                .start = source.span.start + idx,
                .len = 1,
            }, .generic);
        }
        return try self.managedHostString(&[_]u8{' '});
    }

    fn allocManagedHostStringUninitialized(self: *Session, len: usize) !HostStringAlloc {
        const buf = try hostTextAllocSlice(self.allocator, len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = len,
        };
        return .{
            .value = Value.array(text),
            .bytes = hostTextBytesFromAlloc(buf, len),
        };
    }

    fn gatherTypedStringIndexInBounds(comptime SelT: type, out: []u8, bytes: []const u8, selector: []const SelT) void {
        const src: [*]const u8 = bytes.ptr;
        var dst: [*]u8 = out.ptr;
        var idx: usize = 0;
        while (idx + 8 <= selector.len) : (idx += 8) {
            dst[0] = src[@as(usize, @intCast(selector[idx + 0]))];
            dst[1] = src[@as(usize, @intCast(selector[idx + 1]))];
            dst[2] = src[@as(usize, @intCast(selector[idx + 2]))];
            dst[3] = src[@as(usize, @intCast(selector[idx + 3]))];
            dst[4] = src[@as(usize, @intCast(selector[idx + 4]))];
            dst[5] = src[@as(usize, @intCast(selector[idx + 5]))];
            dst[6] = src[@as(usize, @intCast(selector[idx + 6]))];
            dst[7] = src[@as(usize, @intCast(selector[idx + 7]))];
            dst += 8;
        }
        while (idx < selector.len) : (idx += 1) {
            dst[0] = src[@as(usize, @intCast(selector[idx]))];
            dst += 1;
        }
    }

    fn gatherStringIndexInBounds(out: []u8, bytes: []const u8, selector: HostIntArrayView) void {
        switch (selector) {
            .bit => unreachable,
            .int8 => |items| gatherTypedStringIndexInBounds(i8, out, bytes, items),
            .int16 => |items| gatherTypedStringIndexInBounds(i16, out, bytes, items),
            .int32 => |items| gatherTypedStringIndexInBounds(i32, out, bytes, items),
            .int64 => |items| gatherTypedStringIndexInBounds(i64, out, bytes, items),
        }
    }

    fn stringIndexDenseInBoundsValue(self: *Session, source: HostStringSource, selector: HostIntArrayView) KError!Value {
        const len = hostIntArrayViewLen(selector);
        const bytes = source.bytes();
        if (len == 1) {
            const selected = [_]u8{bytes[@intCast(hostIntViewItem(selector, 0))]};
            return try self.managedHostCharVector(&selected);
        }
        const out = try self.allocManagedHostStringUninitialized(len);
        gatherStringIndexInBounds(out.bytes, bytes, selector);
        return out.value;
    }

    fn stringIndexValue(self: *Session, source: HostStringSource, selector: Value) KError!Value {
        const bytes = source.bytes();
        if (hostDenseIfPresent(selector)) |array| {
            if (hostIntArrayView(array)) |dense_view| switch (dense_view) {
                .bit => {},
                else => if (denseSelectorCachedRangeFitsSource(array, bytes.len))
                    return try self.stringIndexDenseInBoundsValue(source, dense_view),
            };
        }

        const view = valueHostIntStructuralView(selector) orelse return error.Type;
        const len = hostIntDenseViewLen(view);
        if (len == 1) {
            const raw_index = try hostIntDenseViewItem(view, 0);
            const selected = [_]u8{if (raw_index >= 0 and raw_index < @as(i64, @intCast(bytes.len)))
                bytes[@intCast(raw_index)]
            else
                ' '};
            return try self.managedHostCharVector(&selected);
        }
        const out = try self.allocManagedHostStringUninitialized(len);
        errdefer self.releaseValue(out.value);
        for (0..len) |idx| {
            const raw_index = try hostIntDenseViewItem(view, idx);
            out.bytes[idx] = if (raw_index >= 0 and raw_index < @as(i64, @intCast(bytes.len)))
                bytes[@intCast(raw_index)]
            else
                ' ';
        }
        return out.value;
    }

    fn stringIndexWhereBitMaskValue(self: *Session, source: HostStringSource, mask: HostBitSlice) KError!Value {
        const bytes = source.bytes();
        const len = bitCountTrue(mask);
        const out = try self.allocManagedHostStringUninitialized(len);
        errdefer self.releaseValue(out.value);

        if (mask.len <= bytes.len) {
            if (comptime enable_string_mask_neon) {
                const written = kiwi_string_mask_compress_neon(out.bytes.ptr, out.bytes.len, bytes.ptr, mask.words.ptr, mask.len);
                std.debug.assert(written == out.bytes.len);
            } else {
                copyStringWhereBitMaskBytesInBounds(out.bytes, bytes, mask);
            }
        } else {
            copyStringWhereBitMaskScalarPadded(out.bytes, bytes, mask);
        }

        if (len == 1) {
            const result = try self.managedHostCharVector(out.bytes);
            self.releaseValue(out.value);
            return result;
        }
        return out.value;
    }

    fn stringRejectWhereBitMaskValue(self: *Session, source: HostStringSource, mask: HostBitSlice) KError!Value {
        const bytes = source.bytes();
        if (mask.len != bytes.len) return error.Type;

        const inverted_words = try self.allocator.alloc(u64, bitWordCount(mask.len));
        defer self.allocator.free(inverted_words);
        fillBitNotWords(inverted_words, mask);
        return try self.stringIndexWhereBitMaskValue(source, .{ .words = inverted_words, .len = mask.len });
    }

    fn invertedHostBitMaskValue(self: *Session, mask: HostBitSlice) KError!Value {
        const out = try self.allocHostBitArrayUninitialized(.managed, mask.len);
        fillBitNotWords(out.words, mask);
        const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
        return try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
    }

    fn applyWhereMaskCall(self: *Session, callee: Value, mask_value: Value) KError!Value {
        if (valueNumericBitSlice(mask_value)) |bits| {
            if (callee.tag() == .array) {
                if (stringSourceInfo(callee)) |source| {
                    return try self.stringIndexWhereBitMaskValue(source, bits);
                }
                if (derivedSequenceLen(callee)) |source_len| {
                    if (bits.len == source_len) return try self.applyArrayCall1(callee, mask_value);
                }
            }
        }

        const selector = try self.whereValue(mask_value);
        defer self.releaseValue(selector);
        return try self.applyValue(callee, &[_]Value{selector});
    }

    fn applyArrayCall1(self: *Session, callee: Value, selector: Value) KError!Value {
        if (callee.tag() != .array) return error.Type;
        if (isAllAxisSelectorValue(selector)) return self.shareValue(callee);
        if (callee.arrayKind() == .host_keyed_store and callee.asHostKeyedStore().layout == .dict) {
            const store = callee.asHostKeyedStore();
            if (derivedSequenceLen(selector) != null) return try self.keyedStoreLookupSequenceValue(store, selector);
            return try self.keyedStoreLookupValueByKey(store, selector);
        }
        if (scalarIntLikeValue(selector)) |raw_index| return try self.applyArrayCall1Scalar(callee, raw_index);
        if (stringSourceInfo(callee)) |source| return try self.stringIndexValue(source, selector);
        switch (selector.tag()) {
            .array => if (try numericValueArithmeticSelectorSlice(callee, selector)) |slice| {
                if (try numericValueArithmeticSliceValue(self, callee, slice)) |result| return result;
                if (try numericValueFirstAxisArithmeticSliceValue(self, callee, slice)) |result| return result;
            },
            else => {},
        }
        if (selector.tag() == .array) {
            if (try numericValueFirstAxisIndexSelectorValue(self, callee, selector)) |result| return result;
            if (try tryApplyBackendBoolMaskIndex(self, callee, selector)) |result| return result;
        }
        if (valueRangeIotaHandle(callee)) |handle| return try self.applyRangeIotaIndex(handle, selector);
        if (valueNumericHandle(callee)) |handle| return try self.applyHostArrayIndex(try hostStructuralArrayForHandle(self, @constCast(handle)), selector);
        return switch (callee.arrayKind()) {
            .host_dense_array, .backend_array => try self.applyHostArrayIndex(try numericHostArrayValue(self, callee), selector),
            .host_boxed_array => try self.applyHostBoxedArrayIndex(callee.asHostBoxedArray(), selector),
            .host_symbol => if (std.mem.eql(u8, hostTextBytes(callee.asHostSymbol()), "j"))
                try self.jsonEncodeValue(selector)
            else
                error.Type,
            .host_string_list => switch (selector.tag()) {
                .int, .bool => if (normalizeIndexOrNull(scalarIntLikeValue(selector).?, callee.asHostStringList().len)) |idx|
                    try self.hostStringListItemValue(callee.asHostStringList(), idx)
                else
                    try self.managedHostString(&.{}),
                .array => blk: {
                    const indices = try self.collectSelectorIndicesForLen(callee.asHostStringList().len, selector);
                    defer self.allocator.free(indices);
                    break :blk try self.selectHostStringListBySourceIndices(callee.asHostStringList(), indices);
                },
                else => error.Type,
            },
            .host_symbol_list => switch (selector.tag()) {
                .int, .bool => if (normalizeIndexOrNull(scalarIntLikeValue(selector).?, callee.asHostStringList().len)) |idx|
                    try self.hostSymbolListItemValue(callee.asHostStringList(), idx)
                else
                    try self.emptySymbolValue(),
                .array => blk: {
                    const indices = try self.collectSelectorIndicesForLen(callee.asHostStringList().len, selector);
                    defer self.allocator.free(indices);
                    break :blk try self.selectHostSymbolListBySourceIndices(callee.asHostStringList(), indices);
                },
                else => error.Type,
            },
            .host_relation => blk: {
                const name = keyedLookupNameBytes(selector) orelse break :blk error.Type;
                break :blk try self.materializeRelationColumn(callee.asHostRelation(), name);
            },
            .host_keyed_store => blk: {
                const store = callee.asHostKeyedStore();
                if (store.layout == .dict) {
                    if (derivedSequenceLen(selector) != null) break :blk try self.keyedStoreLookupSequenceValue(store, selector);
                    break :blk try self.keyedStoreLookupValueByKey(store, selector);
                }
                if (keyedLookupNameBytes(selector)) |name| break :blk try self.keyedStoreLookupValue(store, name);
                if (store.layout == .table) {
                    if (valueHostIntStructuralView(selector)) |view| {
                        break :blk try self.tableSelectRowsBySelector(store, view);
                    }
                }
                break :blk error.Type;
            },
            else => error.Internal,
        };
    }

    fn applyValue(self: *Session, callee: Value, args: []const Value) KError!Value {
        if (try self.tryApplyAllAxisCallableProjection(callee, args)) |projection| return projection;
        return switch (callee.tag()) {
            .builtin => try self.applyBuiltinCall(callee.asBuiltin(), args),
            .closure => blk: {
                const closure = callee.asClosure();
                if (try self.applyDerivedClosure(closure, args)) |result| break :blk result;
                if (try self.tryProjectPlainClosureUnderApplication(callee, closure, args)) |projection| break :blk projection;
                if (codeForRunnablePlainClosureArgs(closure, args)) |compact| break :blk try self.runCodeBorrowed(compact, codeRunArgs(compact, args));
                if (closure.code.arity != args.len) return error.Arity;
                break :blk try self.runClosureMode(closure, args, false);
            },
            .array => try self.applyArrayCall(callee, args),
            else => error.Type,
        };
    }

    fn argsContainAllAxisSelector(args: []const Value) bool {
        for (args) |arg| {
            if (isAllAxisSelectorValue(arg)) return true;
        }
        return false;
    }

    fn tryApplyAllAxisCallableProjection(self: *Session, callee: Value, args: []const Value) KError!?Value {
        switch (callee.tag()) {
            .builtin, .closure => {},
            else => return null,
        }
        if (!argsContainAllAxisSelector(args)) return null;
        if (args.len > 63) return error.Unsupported;

        const slot_values = try self.scratch_arena.allocator().alloc(Value, args.len);
        var hole_mask: u64 = 0;
        for (args, 0..) |arg, idx| {
            if (isAllAxisSelectorValue(arg)) {
                slot_values[idx] = Value.fromBool(false);
                hole_mask |= @as(u64, 1) << @intCast(idx);
            } else {
                slot_values[idx] = arg;
            }
        }
        return try self.allocManagedProjectionClosure(callee, @intCast(args.len), hole_mask, slot_values);
    }

    fn tryProjectPlainClosureUnderApplication(self: *Session, callee: Value, closure: *const Closure, args: []const Value) KError!?Value {
        if (!closureIsCompactPlainGlobal(closure)) return null;
        const code = closure.code;
        if (args.len >= code.arity) return null;
        if (codeCanRunWithArgLen(code, args.len)) return null;
        if (code.arity > 63) return error.Unsupported;

        const slot_count: usize = code.arity;
        const slot_values = try self.scratch_arena.allocator().alloc(Value, slot_count);
        var hole_mask: u64 = 0;
        for (0..slot_count) |idx| {
            if (idx < args.len) {
                slot_values[idx] = args[idx];
            } else {
                slot_values[idx] = Value.fromBool(false);
                hole_mask |= @as(u64, 1) << @intCast(idx);
            }
        }
        return try self.allocManagedProjectionClosure(callee, code.arity, hole_mask, slot_values);
    }

    const AutogradTargetBackend = enum {
        host,
        mlx,
    };

    const dense_autodiff_max_nodes = 16;
    const DenseAutodiffNodeIndex = u8;
    const dense_autodiff_no_slot = std.math.maxInt(u8);

    pub const DebugDenseAutodiffLowering = enum {
        ok,
        wrong_arity,
        non_vector_target,
        non_scalar_result,
        unsupported_opcode,
        unsupported_shape_flow,
        unsupported_builtin,
        capture_or_global_dependency,
        non_dense_operand,
    };
    const debug_dense_autodiff_lowering_count = @typeInfo(DebugDenseAutodiffLowering).@"enum".fields.len;

    const DenseAutodiffNode = union(enum) {
        input,
        const_scalar: f64,
        scan_add: DenseAutodiffNodeIndex,
        unary_map: struct {
            op: BuiltinId,
            src: DenseAutodiffNodeIndex,
        },
        neg: DenseAutodiffNodeIndex,
        add: struct {
            left: DenseAutodiffNodeIndex,
            right: DenseAutodiffNodeIndex,
        },
        sub: struct {
            left: DenseAutodiffNodeIndex,
            right: DenseAutodiffNodeIndex,
        },
        mul: struct {
            left: DenseAutodiffNodeIndex,
            right: DenseAutodiffNodeIndex,
        },
        reduce_add: DenseAutodiffNodeIndex,
    };

    const DenseAutodiffNodeKind = enum {
        vector,
        scalar,
    };

    const DenseAutodiffProgram = struct {
        nodes: [dense_autodiff_max_nodes]DenseAutodiffNode = undefined,
        kinds: [dense_autodiff_max_nodes]DenseAutodiffNodeKind = undefined,
        len: DenseAutodiffNodeIndex = 0,
        root: DenseAutodiffNodeIndex = 0,

        fn push(self: *DenseAutodiffProgram, node: DenseAutodiffNode, kind: DenseAutodiffNodeKind) DenseAutodiffNodeIndex {
            std.debug.assert(self.len < dense_autodiff_max_nodes);
            const idx = self.len;
            self.nodes[idx] = node;
            self.kinds[idx] = kind;
            self.len += 1;
            return idx;
        }
    };

    const DenseAutodiffExecPlan = struct {
        forward_slots: [dense_autodiff_max_nodes]u8 = [_]u8{dense_autodiff_no_slot} ** dense_autodiff_max_nodes,
        adjoint_slots: [dense_autodiff_max_nodes]u8 = [_]u8{dense_autodiff_no_slot} ** dense_autodiff_max_nodes,
        forward_slot_count: u8 = 0,
        adjoint_slot_count: u8 = 0,
    };

    const DenseAutodiffExecBackend = enum {
        host,
        mlx,
    };

    const DenseAutodiffCacheKey = struct {
        closure: *const Closure,
        input_kind: DenseAutodiffNodeKind,
    };

    const DenseAutodiffLowerResult = union(enum) {
        program: DenseAutodiffProgram,
        reject: DebugDenseAutodiffLowering,
    };

    const DenseAutodiffLowerStackItem = union(enum) {
        node: DenseAutodiffNodeIndex,
        derived_add_fold,
        derived_add_scan,
        builtin: BuiltinId,
    };

    const AutogradTarget = struct {
        values: []f64,
        shape: []i32,
        is_scalar: bool,
        backend: AutogradTargetBackend,
    };

    fn applyAutogradBuiltin(self: *Session, op: BuiltinId, args: []const Value) KError!Value {
        if (args.len == 0 or args.len > 2) return error.Arity;
        switch (args[0].tag()) {
            .builtin, .closure => {},
            else => return error.Type,
        }

        var captures_buf: [2]Value = .{ args[0], Value.fromBool(false) };
        var capture_len: usize = 1;
        if (args.len == 2) {
            const arg_index = scalarIntLikeValue(args[1]) orelse return error.Type;
            if (arg_index < 0) return error.Type;
            captures_buf[1] = try self.intValue(arg_index);
            capture_len = 2;
        }

        const kind: DerivedVerbKind = if (op == .grad) .grad else .valuegrad;
        if (self.debugDetailedProbeActive()) switch (op) {
            .grad => self.debug_autograd_builtin_grad_count += 1,
            .valuegrad => self.debug_autograd_builtin_valuegrad_count += 1,
            else => {},
        };
        const closure = try self.allocFrozenDerivedClosureWithCaptures(kind, captures_buf[0..capture_len]);
        return Value.closure(closure);
    }

    fn applyAutogradDerived(self: *Session, kind: DerivedVerbKind, captures: []const Value, args: []const Value) KError!Value {
        if (captures.len == 0 or captures.len > 2) return error.Internal;

        const base = captures[0];
        const arg_index: usize = if (captures.len == 2) blk: {
            const raw = scalarIntLikeValue(captures[1]) orelse return error.Internal;
            if (raw < 0) return error.Internal;
            break :blk @intCast(raw);
        } else 0;
        if (arg_index >= args.len) return error.Arity;

        if (try self.tryFastDenseAutograd(kind, base, args, arg_index)) |value| return value;
        if (self.debugDetailedProbeActive()) self.debug_autograd_slow_finite_difference_count += 1;

        var sibling = try self.initSiblingSession();
        defer sibling.deinit();

        const sibling_args = try sibling.retainArgs(args);
        defer sibling.releaseArgs(sibling_args);
        const original = try sibling.applyValue(base, sibling_args);
        const original_scalar = try self.scalarNumericAutogradResult(original);
        sibling.releaseValue(original);

        const target = try materializeAutogradTarget(self.allocator, args[arg_index]);
        defer self.allocator.free(target.values);
        defer self.allocator.free(target.shape);

        const grad = try self.allocator.alloc(f64, target.values.len);
        defer self.allocator.free(grad);

        const eps = 0.25;
        for (0..target.values.len) |idx| {
            const p2 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, 2.0 * eps);
            const p1 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, eps);
            const m1 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, -eps);
            const m2 = try sibling.evalAutogradPerturbed(base, args, arg_index, target, idx, -2.0 * eps);
            grad[idx] = (-p2 + 8.0 * p1 - 8.0 * m1 + m2) / (12.0 * eps);
        }

        const grad_value = if (target.is_scalar)
            try self.floatValue(grad[0])
        else switch (target.backend) {
            .host => try self.createManagedHostFloatArray(grad),
            .mlx => blk: {
                const items = try self.allocator.alloc(f32, grad.len);
                defer self.allocator.free(items);
                for (grad, 0..) |item, idx| items[idx] = @floatCast(item);
                break :blk try self.wrapManagedBackendArray(mlx.Array.fromFloatSlice(items, target.shape));
            },
        };

        if (kind == .grad) return grad_value;

        const rooted_original = try self.numericScalarValueFromF64(original_scalar);
        defer self.releaseValue(rooted_original);
        defer self.releaseValue(grad_value);
        const pair = [_]Value{ rooted_original, grad_value };
        return try self.createManagedHostBoxedArray(&pair);
    }

    fn tryFastDenseAutograd(self: *Session, kind: DerivedVerbKind, base: Value, args: []const Value, arg_index: usize) KError!?Value {
        if (args.len != 1 or arg_index != 0) return null;
        const scratch = self.scratch_arena.allocator();
        const target = try materializeAutogradTarget(scratch, args[0]);
        if (!target.is_scalar and target.shape.len != 1) return null;
        const input_kind: DenseAutodiffNodeKind = if (target.is_scalar) .scalar else .vector;
        const program = self.detectDenseAutodiffProgramForInput(base, input_kind) orelse return null;
        self.last_dense_autodiff_exec_backend = null;

        if (!target.is_scalar and self.chooseDenseAutodiffExecBackend(&program, args[0]) == .mlx) {
            if (try self.tryFastDenseAutogradBackend(kind, &program, args[0])) |value| return value;
        }

        const grad = try scratch.alloc(f64, target.values.len);

        const original_scalar = try executeDenseAutodiffProgram(scratch, &program, target.values, grad);

        const grad_value = try self.autogradGradientValue(target, grad);
        if (comptime enable_probe_instrumentation) self.last_dense_autodiff_exec_backend = .host;
        if (kind == .grad) return grad_value;

        const original_value = try self.numericScalarValueFromF64(original_scalar);
        defer self.releaseValue(original_value);
        defer self.releaseValue(grad_value);
        const pair = [_]Value{ original_value, grad_value };
        return try self.createManagedHostBoxedArray(&pair);
    }

    fn tryFastDenseAutogradBackend(self: *Session, kind: DerivedVerbKind, program: *const DenseAutodiffProgram, value: Value) KError!?Value {
        return runtime_backend_autodiff.tryFastDenseAutogradBackend(.{
            .Session = Session,
            .Value = Value,
            .BuiltinId = BuiltinId,
            .DerivedVerbKind = DerivedVerbKind,
            .DenseAutodiffProgram = DenseAutodiffProgram,
            .DenseAutodiffNodeKind = DenseAutodiffNodeKind,
            .KError = KError,
            .c = c,
            .mlx = mlx,
            .dense_autodiff_max_nodes = dense_autodiff_max_nodes,
            .enable_probe_instrumentation = enable_probe_instrumentation,
            .mapMlxError = mapMlxError,
            .backendContext = Session.backendContext,
            .materializeBackendArray = Session.materializeBackendArray,
            .wrapManagedBackendArray = Session.wrapManagedBackendArray,
            .numericScalarValueFromF64 = Session.numericScalarValueFromF64,
            .createManagedHostBoxedArray = Session.createManagedHostBoxedArray,
            .releaseValue = Session.releaseValue,
        }, self, kind, program, value);
    }

    fn chooseDenseAutodiffExecBackend(self: *Session, program: *const DenseAutodiffProgram, value: Value) DenseAutodiffExecBackend {
        _ = program;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return .host;
        return switch (planDenseAutodiffBackend(self, value)) {
            .host => .host,
            .mlx => .mlx,
        };
    }

    fn autogradGradientValue(self: *Session, target: AutogradTarget, grad: []const f64) KError!Value {
        if (target.is_scalar) return try self.floatValue(grad[0]);
        return switch (target.backend) {
            .host => try self.createManagedHostFloatArray(grad),
            .mlx => blk: {
                const items = try self.allocator.alloc(f32, grad.len);
                defer self.allocator.free(items);
                for (grad, 0..) |item, idx| items[idx] = @floatCast(item);
                break :blk try self.wrapManagedBackendArray(mlx.Array.fromFloatSlice(items, target.shape));
            },
        };
    }

    fn numericScalarValueFromF64(self: *Session, value: f64) KError!Value {
        const rounded = @round(value);
        if (rounded == value) {
            const as_i64 = std.math.lossyCast(i64, rounded);
            if (@as(f64, @floatFromInt(as_i64)) == value) return try self.intValue(as_i64);
        }
        return try self.floatValue(value);
    }

    fn initSiblingSession(self: *Session) !Session {
        var sibling = try Session.initWithDevice(self.allocator, self.device_preference);
        errdefer sibling.deinit();
        try self.cloneGlobalsInto(&sibling);
        return sibling;
    }

    fn cloneGlobalsInto(self: *Session, sibling: *Session) !void {
        try sibling.global_cells.resize(self.allocator, self.global_cells.items.len);
        try sibling.global_names.resize(self.allocator, self.global_names.items.len);
        for (sibling.global_cells.items) |*cell| {
            cell.* = .{
                .value = Value.fromBool(false),
                .initialized = false,
                .class = .uninitialized,
                .code = null,
            };
        }
        for (self.global_names.items, 0..) |name, idx| {
            sibling.global_names.items[idx] = try sibling.arena.allocator().dupe(u8, name);
        }

        var it = self.global_slots.iterator();
        while (it.next()) |entry| {
            try sibling.global_slots.put(sibling.global_names.items[entry.value_ptr.*], entry.value_ptr.*);
        }

        for (self.global_cells.items, 0..) |cell, idx| {
            if (!cell.initialized) continue;
            const value = try sibling.retainEscapedValue(cell.value);
            sibling.global_cells.items[idx] = .{
                .value = value,
                .initialized = true,
                .class = classifyGlobalValue(value),
                .code = codeForStoredGlobal(value),
            };
        }
    }

    fn retainArgs(self: *Session, args: []const Value) ![]Value {
        const retained = try self.allocator.alloc(Value, args.len);
        errdefer self.allocator.free(retained);
        var initialized: usize = 0;
        errdefer {
            for (retained[0..initialized]) |value| self.releaseValue(value);
        }
        for (args, 0..) |arg, idx| {
            retained[idx] = try self.retainEscapedValue(arg);
            initialized += 1;
        }
        return retained;
    }

    fn releaseArgs(self: *Session, args: []Value) void {
        for (args) |value| self.releaseValue(value);
        self.allocator.free(args);
    }

    fn evalAutogradPerturbed(self: *Session, base: Value, args: []const Value, arg_index: usize, target: AutogradTarget, perturb_index: usize, delta: f64) KError!f64 {
        var call_args = try self.allocator.alloc(Value, args.len);
        defer self.allocator.free(call_args);
        var initialized: usize = 0;
        defer {
            for (call_args[0..initialized]) |value| self.releaseValue(value);
        }

        for (args, 0..) |arg, idx| {
            call_args[idx] = if (idx == arg_index)
                try self.makePerturbedArgument(arg, target, perturb_index, delta)
            else
                try self.retainEscapedValue(arg);
            initialized += 1;
        }

        const value = try self.applyValue(base, call_args);
        defer self.releaseValue(value);
        return try self.scalarNumericAutogradResult(value);
    }

    fn makePerturbedArgument(self: *Session, original: Value, target: AutogradTarget, perturb_index: usize, delta: f64) KError!Value {
        if (target.is_scalar) return try self.floatValue(target.values[0] + delta);

        const items = try self.allocator.dupe(f64, target.values);
        defer self.allocator.free(items);
        items[perturb_index] += delta;
        _ = original;
        return switch (target.backend) {
            .host => try self.createManagedHostFloatArray(items),
            .mlx => blk: {
                const converted = try self.allocator.alloc(f32, items.len);
                defer self.allocator.free(converted);
                for (items, 0..) |item, idx| converted[idx] = @floatCast(item);
                break :blk try self.wrapManagedBackendArray(mlx.Array.fromFloatSlice(converted, target.shape));
            },
        };
    }

    fn scalarNumericAutogradResult(self: *Session, value: Value) KError!f64 {
        _ = self;
        return switch (value.tag()) {
            .int, .bool, .float => try scalarNumericValue(value),
            .array => switch (value.activeArrayKind()) {
                .backend_array => blk: {
                    var owned = value.asBackendArray().array.clone() catch |err| return mapMlxError(err);
                    defer owned.deinit();
                    owned.eval() catch |err| return mapMlxError(err);
                    if (owned.ndim() != 0) return error.Type;
                    break :blk switch (owned.dtype()) {
                        c.MLX_BOOL => @floatFromInt(@intFromBool(owned.boolItem() catch |err| return mapMlxError(err))),
                        c.MLX_INT32, c.MLX_INT64, c.MLX_UINT32 => @floatFromInt(owned.intItem() catch |err| return mapMlxError(err)),
                        c.MLX_FLOAT16, c.MLX_FLOAT32, c.MLX_FLOAT64, c.MLX_BFLOAT16 => owned.floatItem() catch |err| return mapMlxError(err),
                        else => return error.Type,
                    };
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    pub fn debugDenseAutodiffLowering(self: *Session, value: Value) Session.DebugDenseAutodiffLowering {
        return switch (self.detectDenseAutodiffProgramDetailedForInput(value, .vector)) {
            .program => .ok,
            .reject => |reason| reason,
        };
    }

    fn detectDenseAutodiffProgram(self: *Session, base: Value) ?DenseAutodiffProgram {
        return self.detectDenseAutodiffProgramForInput(base, .vector);
    }

    fn detectDenseAutodiffProgramForInput(self: *Session, base: Value, input_kind: DenseAutodiffNodeKind) ?DenseAutodiffProgram {
        return switch (self.detectDenseAutodiffProgramDetailedForInput(base, input_kind)) {
            .program => |program| blk: {
                if (self.debugDetailedProbeActive()) self.debug_dense_autodiff_lower_success_count += 1;
                break :blk program;
            },
            .reject => |reason| blk: {
                self.noteDenseAutodiffReject(reason);
                break :blk null;
            },
        };
    }

    fn detectDenseAutodiffProgramDetailed(self: *Session, base: Value) DenseAutodiffLowerResult {
        return self.detectDenseAutodiffProgramDetailedForInput(base, .vector);
    }

    fn detectDenseAutodiffProgramDetailedForInput(self: *Session, base: Value, input_kind: DenseAutodiffNodeKind) DenseAutodiffLowerResult {
        if (base.tag() != .closure) return .{ .reject = .unsupported_shape_flow };
        const closure = base.asClosure();
        const cacheable = closure.header.owner == .frozen;
        const cache_key = DenseAutodiffCacheKey{
            .closure = closure,
            .input_kind = input_kind,
        };
        if (cacheable) {
            if (self.dense_autodiff_cache.get(cache_key)) |cached| {
                if (self.debugDetailedProbeActive()) self.debug_dense_autodiff_cache_hit_count += 1;
                return cached;
            }
            if (self.debugDetailedProbeActive()) self.debug_dense_autodiff_cache_miss_count += 1;
        } else if (closure.header.owner != .scratch) {
            return .{ .reject = .capture_or_global_dependency };
        }
        if (closure.captures.len != 0 or closure.code.references_globals) {
            const result: DenseAutodiffLowerResult = .{ .reject = .capture_or_global_dependency };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }
        if (closure.code.arity != 1) {
            const result: DenseAutodiffLowerResult = .{ .reject = .wrong_arity };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }

        var program = DenseAutodiffProgram{};
        const input = program.push(.input, input_kind);

        var stack: [dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem = undefined;
        var stack_len: usize = 0;

        const compact = closure.code;
        var ip: usize = 0;
        while (ip < compact.bytes.len) {
            const raw = compact.bytes[ip];
            ip += 1;

            if (compactIsConstValueOpcode(raw)) {
                const slot: usize = raw - ck_const_value_base;
                if (slot >= compact.constants.len) return .{ .reject = .unsupported_shape_flow };
                if (denseAutodiffPushConstantOrDerived(&program, &stack, &stack_len, compact.constants[slot])) |reject| return .{ .reject = reject };
                continue;
            }
            if (raw >= ck_load_local_base and raw < ck_load_local_base + ck_range_width) {
                if (raw - ck_load_local_base != 0) return .{ .reject = .wrong_arity };
                denseAutodiffPushStack(&stack, &stack_len, .{ .node = input }) orelse return .{ .reject = .unsupported_shape_flow };
                continue;
            }
            if (raw >= ck_take_local_base and raw < ck_take_local_base + ck_range_width) {
                if (raw - ck_take_local_base != 0) return .{ .reject = .wrong_arity };
                denseAutodiffPushStack(&stack, &stack_len, .{ .node = input }) orelse return .{ .reject = .unsupported_shape_flow };
                continue;
            }
            if (raw >= ck_store_local_base and raw < ck_store_local_base + ck_range_width) return .{ .reject = .unsupported_opcode };

            if (compactIsMonadOpcode(raw)) {
                switch (raw - ck_monad_base) {
                    ckm_identity => {},
                    ckm_sub => {
                        const item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                        const src = denseAutodiffNodeFromStackItem(item) orelse return .{ .reject = .unsupported_builtin };
                        const node = program.push(.{ .neg = src }, program.kinds[src]);
                        denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                    },
                    else => return .{ .reject = .unsupported_builtin },
                }
                continue;
            }

            if (compactIsDyadOpcode(raw)) {
                const tag: DenseAutodiffBinaryTag = switch (raw - ck_dyad_base) {
                    ckd_add => .add,
                    ckd_sub => .sub,
                    ckd_mul => .mul,
                    else => return .{ .reject = .unsupported_builtin },
                };
                const right_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                const left_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                const left = denseAutodiffNodeFromStackItem(left_item) orelse return .{ .reject = .unsupported_builtin };
                const right = denseAutodiffNodeFromStackItem(right_item) orelse return .{ .reject = .unsupported_builtin };
                const node = denseAutodiffPushBinary(&program, tag, left, right);
                denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                continue;
            }

            switch (raw) {
                ck_const_i8 => {
                    const value: i8 = @bitCast(denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow });
                    const node = program.push(.{ .const_scalar = @floatFromInt(value) }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_const_i64 => {
                    const value = denseAutodiffReadI64(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const node = program.push(.{ .const_scalar = @floatFromInt(value) }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_const_false => {
                    const node = program.push(.{ .const_scalar = 0.0 }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_const_true => {
                    const node = program.push(.{ .const_scalar = 1.0 }, .scalar);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_const_value_u8 => {
                    const slot = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (slot >= compact.constants.len) return .{ .reject = .unsupported_shape_flow };
                    if (denseAutodiffPushConstantOrDerived(&program, &stack, &stack_len, compact.constants[slot])) |reject| return .{ .reject = reject };
                },
                ck_const_builtin_u8 => {
                    const raw_builtin = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const builtin: BuiltinId = @enumFromInt(raw_builtin);
                    switch (builtin) {
                        .add, .exp, .log, .sin, .cos, .tanh, .sigmoid => {
                            denseAutodiffPushStack(&stack, &stack_len, .{ .builtin = builtin }) orelse return .{ .reject = .unsupported_shape_flow };
                        },
                        else => return .{ .reject = .unsupported_builtin },
                    }
                },
                ck_make_adverb_u8 => {
                    const raw_kind = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const kind: DerivedVerbKind = @enumFromInt(raw_kind);
                    const base_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    switch (base_item) {
                        .builtin => |builtin| switch (builtin) {
                            .add => switch (kind) {
                                .fold => denseAutodiffPushStack(&stack, &stack_len, .derived_add_fold) orelse return .{ .reject = .unsupported_shape_flow },
                                .scan => denseAutodiffPushStack(&stack, &stack_len, .derived_add_scan) orelse return .{ .reject = .unsupported_shape_flow },
                                else => return .{ .reject = .unsupported_builtin },
                            },
                            else => return .{ .reject = .unsupported_builtin },
                        },
                        else => return .{ .reject = .unsupported_builtin },
                    }
                },
                ck_add_local_local, ck_sub_local_local, ck_mul_local_local => {
                    const left_slot = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const right_slot = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (left_slot != 0 or right_slot != 0) return .{ .reject = .wrong_arity };
                    const node = denseAutodiffPushBinary(&program, switch (raw) {
                        ck_add_local_local => .add,
                        ck_sub_local_local => .sub,
                        ck_mul_local_local => .mul,
                        else => unreachable,
                    }, input, input);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_add_local_const_i64, ck_sub_local_const_i64, ck_mul_local_const_i64 => {
                    const slot = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const rhs_value = denseAutodiffReadI64(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (slot != 0) return .{ .reject = .wrong_arity };
                    const rhs = program.push(.{ .const_scalar = @floatFromInt(rhs_value) }, .scalar);
                    const node = denseAutodiffPushBinary(&program, switch (raw) {
                        ck_add_local_const_i64 => .add,
                        ck_sub_local_const_i64 => .sub,
                        ck_mul_local_const_i64 => .mul,
                        else => unreachable,
                    }, input, rhs);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_add_const_local_i64, ck_sub_const_local_i64 => {
                    const lhs_value = denseAutodiffReadI64(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    const slot = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (slot != 0) return .{ .reject = .wrong_arity };
                    const lhs = program.push(.{ .const_scalar = @floatFromInt(lhs_value) }, .scalar);
                    const node = denseAutodiffPushBinary(&program, if (raw == ck_add_const_local_i64) .add else .sub, lhs, input);
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_discard => _ = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow },
                ck_call_stack_u8 => {
                    const flags = denseAutodiffReadByte(compact.bytes, &ip) orelse return .{ .reject = .unsupported_shape_flow };
                    if (compactCallArgc(flags) != 1 or compactCallStoresLocal(flags)) return .{ .reject = .unsupported_opcode };
                    const first_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };
                    const second_item = denseAutodiffPopStack(&stack, &stack_len) orelse return .{ .reject = .unsupported_shape_flow };

                    var arg = denseAutodiffNodeFromStackItem(first_item);
                    var callee_item = second_item;
                    if (arg == null and denseAutodiffNodeFromStackItem(second_item) != null) {
                        arg = denseAutodiffNodeFromStackItem(second_item);
                        callee_item = first_item;
                    }
                    const node_arg = arg orelse return .{ .reject = .unsupported_builtin };
                    const node = switch (callee_item) {
                        .derived_add_fold => blk: {
                            if (program.kinds[node_arg] != .vector) return .{ .reject = .non_vector_target };
                            break :blk program.push(.{ .reduce_add = node_arg }, .scalar);
                        },
                        .derived_add_scan => blk: {
                            if (program.kinds[node_arg] != .vector) return .{ .reject = .non_vector_target };
                            break :blk program.push(.{ .scan_add = node_arg }, .vector);
                        },
                        .builtin => |builtin| switch (builtin) {
                            .exp, .log, .sin, .cos, .tanh, .sigmoid => program.push(.{ .unary_map = .{ .op = builtin, .src = node_arg } }, program.kinds[node_arg]),
                            else => return .{ .reject = .unsupported_builtin },
                        },
                        else => return .{ .reject = .unsupported_builtin },
                    };
                    denseAutodiffPushStack(&stack, &stack_len, .{ .node = node }) orelse return .{ .reject = .unsupported_shape_flow };
                },
                ck_return => break,
                else => return .{ .reject = .unsupported_opcode },
            }
        }

        if (stack_len != 1) {
            const result: DenseAutodiffLowerResult = .{ .reject = .unsupported_shape_flow };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }
        const root_item = stack[0];
        const root = denseAutodiffNodeFromStackItem(root_item) orelse {
            const result: DenseAutodiffLowerResult = .{ .reject = .unsupported_builtin };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        };
        if (program.kinds[root] != .scalar) {
            const result: DenseAutodiffLowerResult = .{ .reject = .non_scalar_result };
            if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
            return result;
        }
        program.root = root;
        const result: DenseAutodiffLowerResult = .{ .program = program };
        if (cacheable) self.dense_autodiff_cache.put(cache_key, result) catch {};
        return result;
    }

    fn denseAutodiffPushConstantOrDerived(
        program: *DenseAutodiffProgram,
        stack: *[dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem,
        stack_len: *usize,
        value: Value,
    ) ?DebugDenseAutodiffLowering {
        if (denseAutodiffScalarConstFromValue(value)) |scalar| {
            const node = program.push(.{ .const_scalar = scalar }, .scalar);
            denseAutodiffPushStack(stack, stack_len, .{ .node = node }) orelse return .unsupported_shape_flow;
        } else if (isDerivedBuiltinClosure(value, .fold, .add)) {
            denseAutodiffPushStack(stack, stack_len, .derived_add_fold) orelse return .unsupported_shape_flow;
        } else if (isDerivedBuiltinClosure(value, .scan, .add)) {
            denseAutodiffPushStack(stack, stack_len, .derived_add_scan) orelse return .unsupported_shape_flow;
        } else {
            return .unsupported_builtin;
        }
        return null;
    }

    fn denseAutodiffReadByte(bytes: []const u8, ip: *usize) ?u8 {
        if (ip.* >= bytes.len) return null;
        const value = bytes[ip.*];
        ip.* += 1;
        return value;
    }

    fn denseAutodiffReadI64(bytes: []const u8, ip: *usize) ?i64 {
        const end = ip.* + 8;
        if (end > bytes.len) return null;
        var value: u64 = 0;
        var idx: usize = 0;
        while (idx < 8) : (idx += 1) {
            value |= @as(u64, bytes[ip.* + idx]) << @intCast(idx * 8);
        }
        ip.* = end;
        return @bitCast(value);
    }

    fn denseAutodiffScalarConstFromValue(value: Value) ?f64 {
        return switch (value.tag()) {
            .int => @floatFromInt(value.asInt()),
            .bool => @floatFromInt(@intFromBool(value.asBool())),
            .float32 => @floatCast(value.asFloat32()),
            .float => value.asFloat(),
            else => null,
        };
    }

    fn denseAutodiffLowerLocalNode(program: *DenseAutodiffProgram, bytes: []const u8, ip: *usize, input: DenseAutodiffNodeIndex) ?DenseAutodiffNodeIndex {
        _ = program;
        const slot = denseAutodiffReadByte(bytes, ip) orelse return null;
        if (slot != 0) return null;
        return input;
    }

    fn denseAutodiffPushStack(stack: *[dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem, len: *usize, item: DenseAutodiffLowerStackItem) ?void {
        if (len.* >= stack.len) return null;
        stack[len.*] = item;
        len.* += 1;
    }

    fn denseAutodiffPopStack(stack: *[dense_autodiff_max_nodes * 2]DenseAutodiffLowerStackItem, len: *usize) ?DenseAutodiffLowerStackItem {
        if (len.* == 0) return null;
        len.* -= 1;
        return stack[len.*];
    }

    fn denseAutodiffNodeFromStackItem(item: DenseAutodiffLowerStackItem) ?DenseAutodiffNodeIndex {
        return switch (item) {
            .node => |node| node,
            else => null,
        };
    }

    const DenseAutodiffBinaryTag = enum { add, sub, mul };

    fn denseAutodiffPushBinary(program: *DenseAutodiffProgram, tag: DenseAutodiffBinaryTag, left: DenseAutodiffNodeIndex, right: DenseAutodiffNodeIndex) DenseAutodiffNodeIndex {
        const kind: DenseAutodiffNodeKind = if (program.kinds[left] == .vector or program.kinds[right] == .vector) .vector else .scalar;
        return program.push(switch (tag) {
            .add => .{ .add = .{ .left = left, .right = right } },
            .sub => .{ .sub = .{ .left = left, .right = right } },
            .mul => .{ .mul = .{ .left = left, .right = right } },
        }, kind);
    }

    fn isDerivedBuiltinClosure(value: Value, kind: DerivedVerbKind, builtin: BuiltinId) bool {
        if (value.tag() != .closure) return false;
        const closure = value.asClosure();
        return closure.header.owner == .frozen and
            closureDerivedKind(closure) == kind and
            closure.captures.len == 1 and
            closure.captures[0].tag() == .builtin and
            closure.captures[0].asBuiltin() == builtin;
    }

    fn evalSourceIsolated(self: *Session, source: []const u8) KError!Value {
        var sibling = try self.initSiblingSession();
        defer sibling.deinit();
        const value = try sibling.evalSource(source);
        return try self.retainEscapedValue(value);
    }

    fn setNumericMatrixShapeOnValue(self: *Session, value: Value, rows: usize, cols: usize) !Value {
        const logical = try ensureLogicalNumericValue(self, value);
        numericArraySetMatrixShape(logical.handle, rows, cols);
        syncNumericArrayChildren(logical.handle);
        return logical.value;
    }

    fn hostNumericMatrixRow(self: *Session, array: *const HostDenseArray, row_idx: usize, cols: usize) KError!Value {
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_row_copy_count += 1;
        const start = row_idx * cols;
        return switch (array.storage) {
            .bit => blk: {
                const out = try self.allocHostBitArray(.managed, cols);
                bitCopyRange(out.words, 0, .{ .words = array.storage.bit, .len = array.logical_len }, start, cols);
                break :blk try self.finishManagedHostBitAlloc(out, host_dense_flag_normalized, .{ .min = 0, .max = 1 });
            },
            .float64 => |items| try self.createManagedHostFloatArray(hostDenseLogicalItems(f64, array, items)[start .. start + cols]),
            else => blk: {
                const view = hostIntArrayView(array) orelse return error.Type;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, cols);
                for (0..cols) |col| try out.append(self.allocator, hostIntViewItem(view, start + col));
                break :blk try self.createManagedHostIntArray(out.items);
            },
        };
    }

    fn createManagedHostNumericMatrixRows(self: *Session, array: *const HostDenseArray, row_indices: []const usize, cols: usize) KError!Value {
        const shape = numericShapeSnapshotMatrix(row_indices.len, cols);
        switch (array.storage) {
            .bit => {
                const total = row_indices.len * cols;
                const out = try self.allocHostBitArray(.managed, total);
                for (row_indices, 0..) |row_idx, out_row_idx| {
                    const src_start = row_idx * cols;
                    const dst_start = out_row_idx * cols;
                    bitCopyRange(out.words, dst_start, .{ .words = array.storage.bit, .len = array.logical_len }, src_start, cols);
                }
                const value = try self.finishManagedHostBitAlloc(out, host_dense_flag_normalized, .{ .min = 0, .max = 1 });
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            },
            .float64 => |items| {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, row_indices.len * cols);
                for (row_indices) |row_idx| {
                    const base = row_idx * cols;
                    try out.appendSlice(self.allocator, items[base .. base + cols]);
                }
                const value = try self.createManagedHostFloatArray(out.items);
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            },
            else => {
                const view = hostIntArrayView(array) orelse return error.Type;
                var out = std.ArrayList(i64).empty;
                defer out.deinit(self.allocator);
                try out.ensureTotalCapacity(self.allocator, row_indices.len * cols);
                for (row_indices) |row_idx| {
                    const base = row_idx * cols;
                    for (0..cols) |col| try out.append(self.allocator, hostIntViewItem(view, base + col));
                }
                const value = try self.createManagedHostIntArray(out.items);
                return try applyNonVectorNumericShapeToValue(self, value, shape);
            },
        }
    }

    fn copyBitMatrixRowsByDenseSelector(
        dst_words: []u64,
        source: HostBitSlice,
        selector: HostIntDenseView,
        source_rows: usize,
        cols: usize,
    ) KError!void {
        for (0..hostIntDenseViewLen(selector)) |out_row_idx| {
            const source_row = try normalizeIndex(try hostIntDenseViewItem(selector, out_row_idx), source_rows);
            bitCopyRange(dst_words, out_row_idx * cols, source, source_row * cols, cols);
        }
    }

    fn copyBitMatrixRowsByMask(dst_words: []u64, source: HostBitSlice, mask: HostBitSlice, cols: usize) void {
        var out_row_idx: usize = 0;
        for (mask.words, 0..) |_, word_idx| {
            const row_base = word_idx * host_bit_word_bits;
            var selected = bitWordMasked(mask.words, mask.len, word_idx);
            while (selected != 0) {
                const bit_idx: usize = @intCast(@ctz(selected));
                const source_row = row_base + bit_idx;
                bitCopyRange(dst_words, out_row_idx * cols, source, source_row * cols, cols);
                out_row_idx += 1;
                selected &= selected - 1;
            }
        }
    }

    fn hostNumericMatrixIndexByIntVector(self: *Session, array: *const HostDenseArray, selector: HostIntArrayView, rows: usize, cols: usize) KError!Value {
        if (std.meta.activeTag(array.storage) == .bit) {
            if (comptime enable_probe_instrumentation) self.debug_host_matrix_index_copy_count += 1;
            const selected_rows = hostIntArrayViewLen(selector);
            const total = selected_rows * cols;
            const out = try self.allocHostBitArray(.managed, total);
            try copyBitMatrixRowsByDenseSelector(
                out.words,
                .{ .words = array.storage.bit, .len = array.logical_len },
                .{ .dense = selector },
                rows,
                cols,
            );
            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
            const value = try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
            return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(selected_rows, cols));
        }
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_index_copy_count += 1;
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(selector));
        for (0..hostIntArrayViewLen(selector)) |sel_idx| {
            try row_indices.append(self.allocator, try normalizeIndex(hostIntViewItem(selector, sel_idx), rows));
        }
        return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
    }

    fn hostNumericMatrixIndexByIntDenseView(self: *Session, array: *const HostDenseArray, selector: HostIntDenseView, rows: usize, cols: usize) KError!Value {
        if (std.meta.activeTag(array.storage) == .bit) {
            if (comptime enable_probe_instrumentation) self.debug_host_matrix_index_copy_count += 1;
            const selected_rows = hostIntDenseViewLen(selector);
            const total = selected_rows * cols;
            const out = try self.allocHostBitArray(.managed, total);
            try copyBitMatrixRowsByDenseSelector(
                out.words,
                .{ .words = array.storage.bit, .len = array.logical_len },
                selector,
                rows,
                cols,
            );
            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
            const value = try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
            return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(selected_rows, cols));
        }
        if (selector == .dense) return try self.hostNumericMatrixIndexByIntVector(array, selector.dense, rows, cols);
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_index_copy_count += 1;
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, hostIntDenseViewLen(selector));
        for (0..hostIntDenseViewLen(selector)) |sel_idx| {
            try row_indices.append(self.allocator, try normalizeIndex(try hostIntDenseViewItem(selector, sel_idx), rows));
        }
        return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
    }

    fn hostNumericMatrixIndexMask(self: *Session, array: *const HostDenseArray, mask: HostBitSlice, rows: usize, cols: usize) KError!Value {
        if (mask.len != rows) return error.Type;
        if (hostBitSliceContiguousTrueRun(mask)) |run| return try createManagedHostNumericMatrixRowRange(self, array, run.start, run.len, cols);
        if (std.meta.activeTag(array.storage) == .bit) {
            if (comptime enable_probe_instrumentation) self.debug_host_matrix_mask_copy_count += 1;
            const selected_rows = bitCountTrue(mask);
            const total = selected_rows * cols;
            const out = try self.allocHostBitArray(.managed, total);
            copyBitMatrixRowsByMask(out.words, .{ .words = array.storage.bit, .len = array.logical_len }, mask, cols);
            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
            const value = try self.finishManagedHostBitAlloc(out, metadata.flags, metadata.range);
            return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(selected_rows, cols));
        }
        if (comptime enable_probe_instrumentation) self.debug_host_matrix_mask_copy_count += 1;
        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        for (0..rows) |row| {
            if (!bitGet(mask.words, row)) continue;
            try row_indices.append(self.allocator, row);
        }
        return try self.createManagedHostNumericMatrixRows(array, row_indices.items, cols);
    }

    fn applyHostArrayIndex(self: *Session, array: *const HostDenseArray, selector: Value) KError!Value {
        return switch (selector.tag()) {
            .int, .bool => try self.hostDenseIndexScalar(array, scalarIntLikeValue(selector).?),
            .array => switch (selector.arrayKind()) {
                .host_dense_array, .backend_array, .numeric_array => if (hostDenseIfPresent(selector)) |selector_array|
                    try self.hostDenseIndexVector(array, selector_array)
                else if (valueHostIntStructuralView(selector)) |view|
                    try self.hostDenseIndexDenseSelector(array, view)
                else
                    error.Type,
                else => error.Internal,
            },
            else => error.Type,
        };
    }

    fn applyHostBoxedArrayIndex(self: *Session, array: *const HostBoxedArray, selector: Value) KError!Value {
        return switch (selector.tag()) {
            .int, .bool => try self.hostBoxedArrayIndexScalar(array, scalarIntLikeValue(selector).?),
            .array => switch (selector.arrayKind()) {
                .host_dense_array, .backend_array, .numeric_array => if (hostDenseIfPresent(selector)) |selector_array|
                    try self.hostBoxedArrayIndexVector(array, selector_array)
                else if (valueHostIntStructuralView(selector)) |view|
                    try self.hostBoxedArrayIndexDenseSelector(array, view)
                else
                    error.Type,
                else => error.Internal,
            },
            else => error.Type,
        };
    }

    fn hostDenseIndexScalar(self: *Session, array: *const HostDenseArray, raw_index: i64) KError!Value {
        if (hostDenseShapeHandle(array)) |handle| {
            if (handle.rank > 1) return try numericValueScalarIndexValue(self, Value.array(@constCast(handle)), raw_index) orelse error.Type;
        }
        const idx = normalizeIndexOrNull(raw_index, array.len()) orelse return try self.hostDensePrototypeScalarValue(array);
        return switch (array.storage) {
            .bit => |words| Value.fromBool(bitGet(words, idx)),
            .int8, .int16, .int32, .int64 => try self.intValue(hostIntViewItem(hostIntArrayView(array).?, idx)),
            .float32 => |items| try self.float32Value(items[idx]),
            .float64 => |items| try self.floatValue(items[idx]),
        };
    }

    fn hostBoxedArrayIndexScalar(self: *Session, array: *const HostBoxedArray, raw_index: i64) KError!Value {
        const idx = normalizeIndexOrNull(raw_index, array.len()) orelse {
            if (array.len() == 0) return try self.managedHostString(&.{});
            return try self.prototypeLikeValue(array.items[0]);
        };
        return self.shareValue(array.items[idx]);
    }

    fn hostDenseIndexVector(self: *Session, array: *const HostDenseArray, selector: *const HostDenseArray) KError!Value {
        if (hostIntArrayView(selector)) |selector_view| {
            return switch (selector_view) {
                .bit => |bits| try self.hostDenseIndexMask(array, bits),
                else => blk: {
                    if (denseSelectorCachedRangeFitsSource(selector, array.logical_len)) {
                        if (comptime enable_probe_instrumentation) self.debug_host_index_in_bounds_fast_count += 1;
                        break :blk switch (array.storage) {
                            .bit => try self.gatherManagedHostBitArraySelectionInBounds(.{ .words = array.storage.bit, .len = array.logical_len }, selector_view),
                            .float32 => |items| try self.gatherManagedHostFloat32ArraySelectionInBounds(items, selector_view),
                            .float64 => |items| try self.gatherManagedHostFloatArraySelectionInBounds(items, selector_view),
                            else => try self.gatherManagedHostIntArraySelectionInBounds(hostIntArrayView(array).?, selector_view),
                        };
                    }
                    if (comptime enable_probe_instrumentation) self.debug_host_index_in_bounds_fallback_count += 1;
                    break :blk try self.hostDenseIndexByIntVector(array, selector_view);
                },
            };
        }
        return error.Type;
    }

    fn hostBoxedArrayIndexVector(self: *Session, array: *const HostBoxedArray, selector: *const HostDenseArray) KError!Value {
        if (hostIntArrayView(selector)) |selector_view| {
            return switch (selector_view) {
                .bit => |bits| try self.hostBoxedArrayIndexMask(array, bits),
                else => try self.hostBoxedArrayIndexByIntVector(array, selector_view),
            };
        }
        return error.Type;
    }

    fn hostDenseIndexDenseSelector(self: *Session, array: *const HostDenseArray, selector: HostIntDenseView) KError!Value {
        return switch (selector) {
            .dense => |view| switch (view) {
                .bit => |bits| try self.hostDenseIndexMask(array, bits),
                else => try self.hostDenseIndexByIntVector(array, view),
            },
            .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => try self.hostDenseIndexByIntDenseView(array, selector),
        };
    }

    fn hostBoxedArrayIndexDenseSelector(self: *Session, array: *const HostBoxedArray, selector: HostIntDenseView) KError!Value {
        return switch (selector) {
            .dense => |view| switch (view) {
                .bit => |bits| try self.hostBoxedArrayIndexMask(array, bits),
                else => try self.hostBoxedArrayIndexByIntVector(array, view),
            },
            .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => try self.hostBoxedArrayIndexByIntDenseView(array, selector),
        };
    }

    fn copyDenseItemsByMask(comptime T: type, out: []T, source: []const T, mask: HostBitSlice) void {
        var out_idx: usize = 0;
        for (mask.words, 0..) |_, word_idx| {
            const word_base = word_idx * host_bit_word_bits;
            const active = bitWordActiveLen(mask.len, word_idx, mask.words.len);
            const active_mask = bitLowMask(active);
            var selected = bitWordMasked(mask.words, mask.len, word_idx);
            if (selected == 0) continue;
            if (selected == active_mask) {
                @memcpy(out[out_idx..][0..active], source[word_base..][0..active]);
                out_idx += active;
                continue;
            }
            while (selected != 0) {
                const bit_idx: usize = @intCast(@ctz(selected));
                out[out_idx] = source[word_base + bit_idx];
                out_idx += 1;
                selected &= selected - 1;
            }
        }
        std.debug.assert(out_idx == out.len);
    }

    fn firstSelectedBitIndex(mask: HostBitSlice) ?usize {
        for (mask.words, 0..) |_, word_idx| {
            const selected = bitWordMasked(mask.words, mask.len, word_idx);
            if (selected == 0) continue;
            return word_idx * host_bit_word_bits + @as(usize, @intCast(@ctz(selected)));
        }
        return null;
    }

    fn lastSelectedBitIndex(mask: HostBitSlice) ?usize {
        var word_idx = mask.words.len;
        while (word_idx != 0) {
            word_idx -= 1;
            const selected = bitWordMasked(mask.words, mask.len, word_idx);
            if (selected == 0) continue;
            const bit_idx: usize = @intCast(63 - @clz(selected));
            return word_idx * host_bit_word_bits + bit_idx;
        }
        return null;
    }

    fn maskSelectedIntPreservedStats(view: HostIntArrayView, mask: HostBitSlice, selected_len: usize, source_flags: u8) ?DenseIntGatherStats {
        if (selected_len == 0) {
            return .{
                .flags = host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc,
                .range = .{ .min = 0, .max = 0 },
            };
        }
        if ((source_flags & host_dense_flag_normalized) == 0) return null;
        var mono = monotonicFlags(source_flags);
        if (selected_len <= 1) mono = host_dense_flag_asc | host_dense_flag_dsc;
        if (mono == 0) return null;

        const first_idx = firstSelectedBitIndex(mask) orelse return null;
        const last_idx = lastSelectedBitIndex(mask) orelse return null;
        const first_value = hostIntViewItem(view, first_idx);
        const last_value = hostIntViewItem(view, last_idx);
        const range = if ((mono & host_dense_flag_asc) != 0 and (mono & host_dense_flag_dsc) == 0)
            HostIntRange{ .min = first_value, .max = last_value }
        else if ((mono & host_dense_flag_dsc) != 0 and (mono & host_dense_flag_asc) == 0)
            HostIntRange{ .min = last_value, .max = first_value }
        else
            HostIntRange{ .min = @min(first_value, last_value), .max = @max(first_value, last_value) };
        return .{
            .flags = host_dense_flag_normalized | mono,
            .range = range,
        };
    }

    fn maskSelectedFloatPreservedFlags(mask: HostBitSlice, selected_len: usize, source_flags: u8) ?u8 {
        _ = mask;
        if ((source_flags & host_dense_flag_normalized) == 0) return null;
        var mono = monotonicFlags(source_flags);
        if (selected_len <= 1) mono = host_dense_flag_asc | host_dense_flag_dsc;
        if (mono == 0) return null;
        return host_dense_flag_normalized | mono;
    }

    fn copyI32ItemsByMaskNeon(out: []i32, source: []const i32, mask: HostBitSlice) bool {
        if (comptime !enable_host_mask_compress_neon) return false;
        if (mask.len < host_mask_compress_vector_min_len) return false;
        if (out.len * 8 < mask.len) return false;
        const written = kiwi_host_mask_compress_i32_neon(out.ptr, out.len, source.ptr, mask.words.ptr, mask.len);
        std.debug.assert(written == out.len);
        return true;
    }

    fn copyIntItemsByMask(comptime T: type, out: []T, source: []const T, mask: HostBitSlice) DenseIntGatherStats {
        var asc = true;
        var dsc = true;
        var min_value: i64 = 0;
        var max_value: i64 = 0;
        var prev: i64 = 0;
        var out_idx: usize = 0;

        for (mask.words, 0..) |_, word_idx| {
            const word_base = word_idx * host_bit_word_bits;
            var selected = bitWordMasked(mask.words, mask.len, word_idx);
            while (selected != 0) {
                const bit_idx: usize = @intCast(@ctz(selected));
                const item = source[word_base + bit_idx];
                const item_i64: i64 = @intCast(item);
                out[out_idx] = item;
                if (out_idx == 0) {
                    min_value = item_i64;
                    max_value = item_i64;
                } else {
                    min_value = @min(min_value, item_i64);
                    max_value = @max(max_value, item_i64);
                    if (prev > item_i64) asc = false;
                    if (prev < item_i64) dsc = false;
                }
                prev = item_i64;
                out_idx += 1;
                selected &= selected - 1;
            }
        }
        std.debug.assert(out_idx == out.len);

        return .{
            .flags = host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
            .range = if (out.len == 0)
                .{ .min = 0, .max = 0 }
            else
                .{ .min = min_value, .max = max_value },
        };
    }

    fn hostDenseFullMaskCopy(self: *Session, array: *const HostDenseArray) KError!Value {
        switch (array.storage) {
            .bit => {
                const out = try self.allocHostBitArrayUninitialized(.managed, array.logical_len);
                @memcpy(out.words, array.storage.bit[0..out.words.len]);
                const value = try self.finishManagedHostBitAlloc(out, array.flags, sourceHostIntRange(hostDenseSourceValue(array), array));
                return value;
            },
            .float64 => |items| {
                var out = try self.allocManagedHostFloatResult(array.logical_len);
                @memcpy(out.items, items[0..array.logical_len]);
                const value = try out.value(self);
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), array.flags);
                return value;
            },
            .float32 => |items| {
                var out = try self.allocManagedHostFloat32Result(array.logical_len);
                @memcpy(out.items, items[0..array.logical_len]);
                const value = try out.value(self);
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), array.flags);
                return value;
            },
            else => {
                const view = hostIntArrayView(array).?;
                var out = try self.allocManagedHostIntResult(hostIntArrayViewKind(view), array.logical_len);
                switch (view) {
                    .bit => unreachable,
                    .int8 => |source| switch (out) {
                        .int8 => |*dest| @memcpy(dest.items, source[0..array.logical_len]),
                        else => unreachable,
                    },
                    .int16 => |source| switch (out) {
                        .int16 => |*dest| @memcpy(dest.items, source[0..array.logical_len]),
                        else => unreachable,
                    },
                    .int32 => |source| switch (out) {
                        .int32 => |*dest| @memcpy(dest.items, source[0..array.logical_len]),
                        else => unreachable,
                    },
                    .int64 => |source| switch (out) {
                        .int64 => |*dest| @memcpy(dest.items, source[0..array.logical_len]),
                        else => unreachable,
                    },
                }
                const value = try out.value(self);
                const host = try mutableNumericHostArrayValue(self, value);
                hostDenseSetFlags(host, array.flags);
                hostDenseSetCachedIntRange(host, sourceHostIntRange(hostDenseSourceValue(array), array));
                return value;
            },
        }
    }

    fn hostDenseIndexMask(self: *Session, array: *const HostDenseArray, mask: HostBitSlice) KError!Value {
        if (hostDenseNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return try self.hostNumericMatrixIndexMask(array, mask, @intCast(shape.shape[0]), @intCast(shape.shape[1]));
        }
        if (mask.len != array.len()) return error.Type;
        if (comptime enable_probe_instrumentation) self.debug_host_mask_copy_count += 1;
        if (bitWordsAllTrue(mask)) return try self.hostDenseFullMaskCopy(array);
        switch (array.storage) {
            .bit => {
                const selected_len = bitCountTrue(mask);
                var out = try self.allocHostBitArray(.managed, selected_len);
                const stats = compressBitSliceByMask(&out, .{ .words = array.storage.bit, .len = array.logical_len }, mask);
                return try self.finishManagedHostBitAlloc(out, stats.flags, stats.range);
            },
            .float64 => |items| {
                const selected_len = bitCountTrue(mask);
                var out = try self.allocManagedHostFloatResult(selected_len);
                copyDenseItemsByMask(f64, out.items, items, mask);
                const value = try out.value(self);
                const flags = maskSelectedFloatPreservedFlags(mask, selected_len, array.flags) orelse analyzeFloatSlice(out.items).flags;
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), flags);
                return value;
            },
            .float32 => |items| {
                const selected_len = bitCountTrue(mask);
                var out = try self.allocManagedHostFloat32Result(selected_len);
                copyDenseItemsByMask(f32, out.items, items, mask);
                const value = try out.value(self);
                const flags = maskSelectedFloatPreservedFlags(mask, selected_len, array.flags) orelse analyzeFloatSlice32(out.items).flags;
                hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), flags);
                return value;
            },
            else => {
                const view = hostIntArrayView(array).?;
                const selected_len = bitCountTrue(mask);
                var out = try self.allocManagedHostIntResult(hostIntArrayViewKind(view), selected_len);
                const preserved_stats = maskSelectedIntPreservedStats(view, mask, selected_len, array.flags);
                const stats = switch (view) {
                    .bit => unreachable,
                    .int8 => |source| switch (out) {
                        .int8 => |*dest| blk: {
                            copyDenseItemsByMask(i8, dest.items, source, mask);
                            break :blk preserved_stats orelse denseIntGatherStatsFromAnalysis(analyzeIntSliceTyped(i8, dest.items));
                        },
                        else => unreachable,
                    },
                    .int16 => |source| switch (out) {
                        .int16 => |*dest| blk: {
                            copyDenseItemsByMask(i16, dest.items, source, mask);
                            break :blk preserved_stats orelse denseIntGatherStatsFromAnalysis(analyzeIntSliceTyped(i16, dest.items));
                        },
                        else => unreachable,
                    },
                    .int32 => |source| switch (out) {
                        .int32 => |*dest| blk: {
                            if (!copyI32ItemsByMaskNeon(dest.items, source, mask)) {
                                copyDenseItemsByMask(i32, dest.items, source, mask);
                            }
                            break :blk preserved_stats orelse denseIntGatherStatsFromAnalysis(analyzeIntSliceTyped(i32, dest.items));
                        },
                        else => unreachable,
                    },
                    .int64 => |source| switch (out) {
                        .int64 => |*dest| blk: {
                            copyDenseItemsByMask(i64, dest.items, source, mask);
                            break :blk preserved_stats orelse denseIntGatherStatsFromAnalysis(analyzeIntSliceTyped(i64, dest.items));
                        },
                        else => unreachable,
                    },
                };
                const value = try out.value(self);
                const host = try mutableNumericHostArrayValue(self, value);
                hostDenseSetFlags(host, stats.flags);
                hostDenseSetCachedIntRange(host, stats.range);
                return value;
            },
        }
    }

    fn hostBoxedArrayIndexMask(self: *Session, array: *const HostBoxedArray, mask: HostBitSlice) KError!Value {
        if (mask.len != array.len()) return error.Type;
        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        for (0..mask.len) |idx| {
            if (!bitGet(mask.words, idx)) continue;
            try out.append(self.allocator, array.items[idx]);
        }
        return try self.createManagedHostBoxedArray(out.items);
    }

    const DenseIntGatherStats = struct {
        flags: u8,
        range: HostIntRange,
    };

    fn denseIntGatherStatsFromAnalysis(analysis: HostIntAnalysis) DenseIntGatherStats {
        return .{ .flags = analysis.flags, .range = analysis.range };
    }

    fn compressBitSliceByMask(out: *HostBitAlloc, source: HostBitSlice, mask: HostBitSlice) DenseIntGatherStats {
        var asc = true;
        var dsc = true;
        var saw_zero = out.len == 0;
        var saw_one = false;
        var prev = false;
        var out_count: usize = 0;
        var out_word_idx: usize = 0;
        var out_bit_idx: usize = 0;
        var out_word: u64 = 0;

        for (mask.words, 0..) |_, word_idx| {
            const word_base = word_idx * host_bit_word_bits;
            var selected = bitWordMasked(mask.words, mask.len, word_idx);
            while (selected != 0) {
                const bit_idx: usize = @intCast(@ctz(selected));
                const item = bitGet(source.words, word_base + bit_idx);
                if (item) out_word |= @as(u64, 1) << @intCast(out_bit_idx);
                if (out_count == 0) {
                    saw_zero = !item;
                    saw_one = item;
                } else {
                    if (item) saw_one = true else saw_zero = true;
                    if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                    if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                }
                prev = item;
                out_count += 1;
                out_bit_idx += 1;
                if (out_bit_idx == host_bit_word_bits) {
                    out.words[out_word_idx] = out_word;
                    out_word_idx += 1;
                    out_bit_idx = 0;
                    out_word = 0;
                }
                selected &= selected - 1;
            }
        }
        if (out_bit_idx != 0) out.words[out_word_idx] = out_word;

        return .{
            .flags = host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
            .range = .{
                .min = if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            },
        };
    }

    fn denseSelectorCachedRangeFitsSource(selector: *const HostDenseArray, source_len: usize) bool {
        const range = hostDenseCachedIntRange(selector) orelse return false;
        if (range.min < 0) return false;
        if (selector.logical_len == 0) return true;
        const source_len_i64 = std.math.cast(i64, source_len) orelse return false;
        return range.max < source_len_i64;
    }

    fn gatherTypedBitDenseSelectionUnchecked(
        comptime SelT: type,
        out: *HostBitAlloc,
        source: HostBitSlice,
        selector: []const SelT,
    ) DenseIntGatherStats {
        const src = source.words;
        var selector_ptr: [*]const SelT = selector.ptr;
        var saw_zero = false;
        var saw_one = false;

        for (0..out.words.len) |word_idx| {
            const active_len = bitWordActiveLen(out.len, word_idx, out.words.len);
            const active_mask = bitLowMask(active_len);
            var word: u64 = 0;
            var bit_idx: usize = 0;
            while (bit_idx + 8 <= active_len) : (bit_idx += 8) {
                const chunk =
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[0]))))) << 0) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[1]))))) << 1) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[2]))))) << 2) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[3]))))) << 3) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[4]))))) << 4) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[5]))))) << 5) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[6]))))) << 6) |
                    (@as(u64, @intFromBool(bitGet(src, @as(usize, @intCast(selector_ptr[7]))))) << 7);
                word |= chunk << @intCast(bit_idx);
                selector_ptr += 8;
            }
            while (bit_idx < active_len) : (bit_idx += 1) {
                if (bitGet(src, @as(usize, @intCast(selector_ptr[0])))) {
                    word |= @as(u64, 1) << @intCast(bit_idx);
                }
                selector_ptr += 1;
            }
            out.words[word_idx] = word;
            const masked = word & active_mask;
            if (masked != 0) saw_one = true;
            if (masked != active_mask) saw_zero = true;
        }

        return .{
            .flags = host_dense_flag_normalized |
                (if (out.len <= 1) host_dense_flag_asc | host_dense_flag_dsc else 0),
            .range = .{
                .min = if (!saw_one) 0 else if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            },
        };
    }

    fn gatherBitDenseSelectionUnchecked(
        out: *HostBitAlloc,
        source: HostBitSlice,
        selector: HostIntArrayView,
    ) DenseIntGatherStats {
        return switch (selector) {
            .bit => unreachable,
            .int8 => |items| gatherTypedBitDenseSelectionUnchecked(i8, out, source, items),
            .int16 => |items| gatherTypedBitDenseSelectionUnchecked(i16, out, source, items),
            .int32 => |items| gatherTypedBitDenseSelectionUnchecked(i32, out, source, items),
            .int64 => |items| gatherTypedBitDenseSelectionUnchecked(i64, out, source, items),
        };
    }

    fn gatherTypedIntDenseSelectionUnchecked(
        comptime T: type,
        comptime SelT: type,
        out: []T,
        source: []const T,
        selector: []const SelT,
    ) void {
        const src: [*]const T = source.ptr;
        var dst: [*]T = out.ptr;
        var idx: usize = 0;
        while (idx + 8 <= selector.len) : (idx += 8) {
            dst[0] = src[@as(usize, @intCast(selector[idx + 0]))];
            dst[1] = src[@as(usize, @intCast(selector[idx + 1]))];
            dst[2] = src[@as(usize, @intCast(selector[idx + 2]))];
            dst[3] = src[@as(usize, @intCast(selector[idx + 3]))];
            dst[4] = src[@as(usize, @intCast(selector[idx + 4]))];
            dst[5] = src[@as(usize, @intCast(selector[idx + 5]))];
            dst[6] = src[@as(usize, @intCast(selector[idx + 6]))];
            dst[7] = src[@as(usize, @intCast(selector[idx + 7]))];
            dst += 8;
        }
        while (idx < selector.len) : (idx += 1) {
            dst[0] = src[@as(usize, @intCast(selector[idx]))];
            dst += 1;
        }
    }

    fn gatherIntDenseSelectionUnchecked(
        comptime T: type,
        out: []T,
        source: []const T,
        selector: HostIntArrayView,
    ) void {
        switch (selector) {
            .bit => unreachable,
            .int8 => |items| gatherTypedIntDenseSelectionUnchecked(T, i8, out, source, items),
            .int16 => |items| gatherTypedIntDenseSelectionUnchecked(T, i16, out, source, items),
            .int32 => |items| gatherTypedIntDenseSelectionUnchecked(T, i32, out, source, items),
            .int64 => |items| gatherTypedIntDenseSelectionUnchecked(T, i64, out, source, items),
        }
    }

    fn gatherTypedFloatDenseSelectionUnchecked(
        comptime FloatT: type,
        comptime SelT: type,
        out: []FloatT,
        source: []const FloatT,
        selector: []const SelT,
    ) void {
        for (selector, 0..) |raw_idx, out_idx| {
            out[out_idx] = source[@as(usize, @intCast(raw_idx))];
        }
    }

    fn gatherFloatDenseSelectionUnchecked(comptime FloatT: type, out: []FloatT, source: []const FloatT, selector: HostIntArrayView) void {
        switch (selector) {
            .bit => unreachable,
            .int8 => |items| gatherTypedFloatDenseSelectionUnchecked(FloatT, i8, out, source, items),
            .int16 => |items| gatherTypedFloatDenseSelectionUnchecked(FloatT, i16, out, source, items),
            .int32 => |items| gatherTypedFloatDenseSelectionUnchecked(FloatT, i32, out, source, items),
            .int64 => |items| gatherTypedFloatDenseSelectionUnchecked(FloatT, i64, out, source, items),
        }
    }

    fn gatherManagedHostBitArraySelectionInBounds(self: *Session, source: HostBitSlice, selector: HostIntArrayView) KError!Value {
        const len = hostIntArrayViewLen(selector);
        var out = try self.allocManagedHostIntResult(.bit, len);
        const stats = switch (out) {
            .bit => |*result| gatherBitDenseSelectionUnchecked(result, source, selector),
            else => unreachable,
        };

        const value = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, stats.flags);
        hostDenseSetCachedIntRange(host, stats.range);
        return value;
    }

    fn gatherManagedHostBitArraySelection(self: *Session, source: HostBitSlice, selector: HostIntArrayView) KError!Value {
        const len = hostIntArrayViewLen(selector);
        var out = try self.allocManagedHostIntResult(.bit, len);

        var asc = true;
        var dsc = true;
        var saw_zero = len == 0;
        var saw_one = false;
        var prev = false;

        switch (out) {
            .bit => |*result| {
                for (0..len) |idx| {
                    const source_idx = try normalizeIndex(hostIntViewItem(selector, idx), source.len);
                    const item = bitGet(source.words, source_idx);
                    bitSet(result.words, idx, item);
                    if (idx == 0) {
                        saw_zero = !item;
                        saw_one = item;
                    } else {
                        if (item) saw_one = true else saw_zero = true;
                        if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                        if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                    }
                    prev = item;
                }
            },
            else => unreachable,
        }

        const value = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostDenseSetCachedIntRange(host, .{
            .min = if (saw_zero) 0 else 1,
            .max = if (saw_one) 1 else 0,
        });
        return value;
    }

    fn gatherManagedHostFloatArraySelection(self: *Session, source: []const f64, selector: HostIntArrayView) KError!Value {
        const len = hostIntArrayViewLen(selector);
        var out = try self.allocManagedHostFloatResult(len);
        for (0..len) |idx| {
            const source_idx = try normalizeIndex(hostIntViewItem(selector, idx), source.len);
            out.items[idx] = source[source_idx];
        }

        const value = try out.value(self);
        const analysis = analyzeFloatSlice(out.items);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), analysis.flags);
        return value;
    }

    fn gatherManagedHostFloat32ArraySelection(self: *Session, source: []const f32, selector: HostIntArrayView) KError!Value {
        const len = hostIntArrayViewLen(selector);
