    fn hostDenseIndexByIntVector(self: *Session, array: *const HostDenseArray, selector: HostIntArrayView) KError!Value {
        if (hostDenseNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return try self.hostNumericMatrixIndexByIntVector(array, selector, @intCast(shape.shape[0]), @intCast(shape.shape[1]));
        }
        if (comptime enable_probe_instrumentation) self.debug_host_index_copy_count += 1;
        switch (array.storage) {
            .bit => {
                return try self.gatherManagedHostBitArraySelection(.{ .words = array.storage.bit, .len = array.logical_len }, selector);
            },
            .float64 => |items| {
                return try self.gatherManagedHostFloatArraySelection(items, selector);
            },
            .float32 => |items| {
                return try self.gatherManagedHostFloat32ArraySelection(items, selector);
            },
            else => {
                const view = hostIntArrayView(array).?;
                return try self.gatherManagedHostIntArraySelection(view, selector);
            },
        }
    }

    fn hostBoxedArrayIndexByIntVector(self: *Session, array: *const HostBoxedArray, selector: HostIntArrayView) KError!Value {
        const len = hostIntArrayViewLen(selector);
        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        for (0..len) |sel_idx| {
            const idx = try normalizeIndex(hostIntViewItem(selector, sel_idx), array.len());
            try out.append(self.allocator, array.items[idx]);
        }
        return try self.createManagedHostBoxedArray(out.items);
    }

    fn hostDenseIndexByIntDenseView(self: *Session, array: *const HostDenseArray, selector: HostIntDenseView) KError!Value {
        if (selector == .dense) return try self.hostDenseIndexByIntVector(array, selector.dense);
        if (hostDenseNonVectorShape(array)) |shape| {
            if (shape.rank != 2) return error.Unsupported;
            return try self.hostNumericMatrixIndexByIntDenseView(array, selector, @intCast(shape.shape[0]), @intCast(shape.shape[1]));
        }
        if (comptime enable_probe_instrumentation) self.debug_host_index_copy_count += 1;
        switch (array.storage) {
            .bit => {
                return try self.gatherManagedHostBitSelection(.{ .words = array.storage.bit, .len = array.logical_len }, selector);
            },
            .float64 => |items| {
                return try self.gatherManagedHostFloatSelection(items, selector);
            },
            .float32 => |items| {
                return try self.gatherManagedHostFloat32Selection(items, selector);
            },
            else => {
                const view = hostIntArrayView(array).?;
                return try self.gatherManagedHostIntSelection(view, selector);
            },
        }
    }

    fn hostBoxedArrayIndexByIntDenseView(self: *Session, array: *const HostBoxedArray, selector: HostIntDenseView) KError!Value {
        if (selector == .dense) return try self.hostBoxedArrayIndexByIntVector(array, selector.dense);
        const len = hostIntDenseViewLen(selector);
        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const source_idx = try normalizeIndex(try hostIntDenseViewItem(selector, idx), array.len());
            try out.append(self.allocator, array.items[source_idx]);
        }
        return try self.createManagedHostBoxedArray(out.items);
    }

    fn applyRangeIotaIndex(self: *Session, handle: *const NumericArray, selector: Value) KError!Value {
        const structural = NumericStructuralView{ .handle = handle };
        return switch (selector.tag()) {
            .int, .bool => (try numericStructuralScalarIndexValue(self, structural, scalarIntLikeValue(selector).?)).?,
            .array => if (valueHostIntStructuralView(selector)) |view|
                if (handle.rank > 1) blk: {
                    const outer_len: usize = @intCast(handle.shape[0]);
                    if (try hostIntDenseViewArithmeticSlice(view, outer_len)) |slice| {
                        break :blk (try numericStructuralArithmeticSliceValue(self, structural, slice)).?;
                    }
                    break :blk try self.applyHostArrayIndex(try hostStructuralArrayForHandle(self, @constCast(handle)), selector);
                } else switch (view) {
                    .dense => |dense| switch (dense) {
                        .bit => |bits| blk: {
                            if (bits.len != numericArrayRangeLen(handle)) return error.Type;
                            var out = std.ArrayList(i64).empty;
                            defer out.deinit(self.allocator);
                            for (0..bits.len) |idx| {
                                if (!bitGet(bits.words, idx)) continue;
                                try out.append(self.allocator, try numericArrayRangeIotaValueAt(handle, idx));
                            }
                            break :blk try self.createManagedHostIntArray(out.items);
                        },
                        else => blk: {
                            var out = std.ArrayList(i64).empty;
                            defer out.deinit(self.allocator);
                            try out.ensureTotalCapacity(self.allocator, hostIntArrayViewLen(dense));
                            for (0..hostIntArrayViewLen(dense)) |idx| {
                                const source_idx = try normalizeIndex(hostIntViewItem(dense, idx), numericArrayRangeLen(handle));
                                try out.append(self.allocator, try numericArrayRangeIotaValueAt(handle, source_idx));
                            }
                            break :blk try self.createManagedHostIntArray(out.items);
                        },
                    },
                    .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => blk: {
                        var out = std.ArrayList(i64).empty;
                        defer out.deinit(self.allocator);
                        try out.ensureTotalCapacity(self.allocator, hostIntDenseViewLen(view));
                        for (0..hostIntDenseViewLen(view)) |idx| {
                            const source_idx = try normalizeIndex(try hostIntDenseViewItem(view, idx), numericArrayRangeLen(handle));
                            try out.append(self.allocator, try numericArrayRangeIotaValueAt(handle, source_idx));
                        }
                        break :blk try self.createManagedHostIntArray(out.items);
                    },
                }
            else
                error.Type,
            else => error.Type,
        };
    }

    fn typeValue(self: *Session, value: Value) KError!Value {
        return try self.managedHostSymbol(typeSymbolBytesForValue(value));
    }

    fn typeSymbolBytesForValue(value: Value) []const u8 {
        return switch (value.tag()) {
            .int, .bool => "i",
            .float32 => "e",
            .float => "f",
            .builtin => "v",
            .closure => closureTypeSymbolBytes(value.asClosure()),
            .array => switch (value.arrayKind()) {
                .host_string, .host_string_view => blk: {
                    const bytes = stringBytes(value) orelse break :blk "C";
                    break :blk if (bytes.len == 1) "c" else "C";
                },
                .host_symbol => "s",
                .host_string_list => if (value.asHostStringList().display == .split_list) "A" else "C",
                .host_symbol_list => "S",
                .host_boxed_array => boxedArrayTypeSymbolBytes(value.asHostBoxedArray().items),
                .host_keyed_store => if (value.asHostKeyedStore().layout == .table) "M" else "m",
                .host_relation, .host_table_scalar => "M",
                .numeric_array, .host_dense_array, .backend_array => switch (valueNumericMode(value) orelse return "A") {
                    .int => "I",
                    .float => if (valueFloatStorageKind(value) == .float32) "E" else "F",
                },
                else => "A",
            },
        };
    }

    fn boxedArrayTypeSymbolBytes(items: []const Value) []const u8 {
        if (items.len == 0) return "A";
        var result: ?[]const u8 = null;
        for (items) |item| {
            const item_result: []const u8 = switch (item.tag()) {
                .int, .bool => "I",
                .float32 => "E",
                .float => "F",
                .array => blk: {
                    if (stringBytes(item)) |bytes| {
                        if (bytes.len == 1) break :blk "C";
                        break :blk "A";
                    }
                    if (symbolBytes(item) != null) break :blk "S";
                    break :blk "A";
                },
                else => "A",
            };
            if (std.mem.eql(u8, item_result, "A")) return "A";
            if (result) |current| {
                if (!std.mem.eql(u8, current, item_result)) return "A";
            } else {
                result = item_result;
            }
        }
        return result orelse "A";
    }

    fn closureTypeSymbolBytes(closure: *const Closure) []const u8 {
        return switch (closure.kind) {
            .plain => "o",
            .projection => "p",
            .inner_product, .composition => "q",
            .each, .fold, .scan, .each_right, .each_left, .each_prior, .grad, .valuegrad => "r",
        };
    }

    fn applyMonad(self: *Session, op: BuiltinId, value: Value) KError!Value {
        return switch (op) {
            .identity => self.shareValue(value),
            .pow => error.Arity,
            .add => try self.flipValue(value),
            .sub => blk: {
                if (try self.tryScalarIntBoolMonad(.sub, value)) |result| break :blk result;
                if (try self.textByteNumericMonadValue(.sub, value)) |result| break :blk result;
                break :blk switch (value.tag()) {
                    .float32 => try self.float32Value(-value.asFloat32()),
                    .float => try self.floatValue(-value.asFloat()),
                    .array => try self.applyNumericMonad(.sub, value),
                    else => error.Type,
                };
            },
            .div => blk: {
                if (try self.tryScalarIntBoolMonad(.div, value)) |result| break :blk result;
                if (try self.textByteNumericMonadValue(.div, value)) |result| break :blk result;
                break :blk switch (value.tag()) {
                    .float32 => try self.float32Value(@floatCast(std.math.sqrt(@as(f64, @floatCast(value.asFloat32()))))),
                    .float => try self.floatValue(std.math.sqrt(value.asFloat())),
                    .array => try self.applyNumericMonad(.div, value),
                    else => error.Type,
                };
            },
            .mul => switch (value.tag()) {
                .int, .bool, .float, .float32 => self.shareValue(value),
                .array => switch (value.arrayKind()) {
                    .host_symbol, .host_table_scalar => self.shareValue(value),
                    .host_keyed_store => blk: {
                        const store = value.asHostKeyedStore();
                        if (store.layout != .dict) break :blk try self.applyArrayCall1Scalar(value, 0);
                        if (keyedStoreNameCount(store) == 0) break :blk try self.managedHostString(&.{});
                        break :blk try self.keyedStoreValueAt(store, 0);
                    },
                    else => try self.applyArrayCall1Scalar(value, 0),
                },
                else => error.Type,
            },
            .exp, .log, .sin, .cos, .tanh, .sigmoid => blk: {
                if (scalarIntLikeValue(value)) |int_value| break :blk try self.floatValue(applyFloatMonadOp(op, @floatFromInt(int_value)));
                break :blk switch (value.tag()) {
                    .float32 => try self.float32Value(@floatCast(applyFloatMonadOp(op, @floatCast(value.asFloat32())))),
                    .float => try self.floatValue(applyFloatMonadOp(op, value.asFloat())),
                    .array => try self.applyNumericMonad(op, value),
                    else => error.Type,
                };
            },
            .iota => try self.iotaValue(value),
            .minimum => try self.whereValue(value),
            .maximum => try self.reverseValue(value),
            .reverse => try self.reverseValue(value),
            .less => try self.gradeValue(value, true),
            .more => try self.gradeValue(value, false),
            .grade_up => try self.gradeValue(value, true),
            .grade_down => try self.gradeValue(value, false),
            .not => try self.notValue(value),
            .concat => try self.enlistValue(value),
            .count => try self.countValue(value),
            .take => error.Arity,
            .floor => try self.floorValue(value),
            .drop => error.Arity,
            .null_fill_without => try self.nullValue(value),
            .sort => try self.sortValue(value),
            .equal => try self.groupOrUnitMatrixValue(value),
            .reshape => error.Arity,
            .stringify => try self.stringifyValue(value),
            .cast => error.Arity,
            .contains => error.Arity,
            .split => error.Arity,
            .join => error.Arity,
            .type_of => try self.typeValue(value),
            .bytes => try self.bytesValue(value),
            .utf8 => try self.utf8Value(value),
            .char => try self.charValue(value),
            .unique => if (scalarRandomCountValue(value)) |count|
                try self.randomUniformValue(count)
            else
                try self.uniqueValue(value),
            .find => error.Arity,
            .eval_string => try self.evalStringValue(value),
            .load => try self.loadValue(value),
            .sql => try self.sqlValue(value),
            .rotcacheview => try self.rotcacheViewValue(value),
            .grad, .valuegrad => error.Type,
            .save, .register => error.Arity,
            .prng, .rotcache, .rotcacheupdate, .rope, .ropeflat, .ropecisflat, .rmsnorm, .layernorm, .gelu, .geluapprox, .mlpdense, .conv2d, .convtranspose2d, .upsamplenearest2d, .groupnorm, .softmax, .sdpa, .sam3boxrpb, .sdpamask, .sdpaflat => error.Arity,
        };
    }

    fn bangValues(self: *Session, left: Value, right: Value) KError!Value {
        if (try self.promoteRenderableNumericDyadOperands(left, right)) |operands| {
            return try self.bangValues(operands.left, operands.right);
        }
        if (scalarIntLikeValue(left)) |left_value| {
            if (scalarIntLikeValue(right)) |right_value| return try self.intValue(bangIntOp(left_value, right_value));
            if (right.tag() == .float) return try self.floatValue(bangFloatOp(left_value, right.asFloat()));
            if (right.tag() == .array and valueNumericMode(right) != null and valueNumericMode(right) != .float) {
                return try self.applyHostArrayDyad(.iota, left, right);
            }
            return error.Type;
        }
        if (keyedLookupNameBytes(left) != null and derivedSequenceLen(left) == null) {
            if (derivedSequenceLen(right) != null) return error.Type;
            const key_value = try self.enlistValue(left);
            defer self.releaseValue(key_value);
            const value_value = try self.enlistValue(right);
            defer self.releaseValue(value_value);
            return try self.createHostDictValueFromKeySequenceValue("", key_value, value_value);
        }

        if (left.tag() == .array and left.arrayKind() == .host_string_list) {
            if (derivedSequenceLen(right)) |value_len| {
                if (value_len != left.asHostStringList().len) return error.Type;
                const values_value = try self.retainEscapedValue(right);
                errdefer self.releaseValue(values_value);
                return try self.createHostDictValueFromDenseTextKeys("", left.asHostStringList(), values_value);
            }
        }

        if (derivedSequenceLen(left)) |key_len| {
            if (derivedSequenceLen(right)) |value_len| {
                if (value_len != key_len) return error.Type;
                return try self.createHostDictValueFromKeySequenceValue("", left, right);
            }
            return error.Type;
        }

        return error.Type;
    }

    fn boolNumericVectorValue(self: *Session, value: Value) KError!bool {
        if (value.tag() != .array or valueNumericMode(value) != .int) return false;
        _ = numericVectorLen(value) orelse return false;
        return switch ((try numericHostArrayValue(self, value)).storage) {
            .bit => true,
            else => false,
        };
    }

    fn valueIsTableTextAtom(value: Value) bool {
        return value.tag() == .array and value.arrayKind() == .host_symbol;
    }

    fn valueIsTableTextItem(value: Value) bool {
        if (value.tag() != .array) return false;
        return switch (value.arrayKind()) {
            .host_string, .host_symbol, .host_string_view => true,
            else => false,
        };
    }

    fn classifyDictTableColumn(self: *Session, value: Value) KError!DictTableColumnSpec {
        if (value.tag() == .bool) return .{
            .kind = .boolean,
            .len = 1,
            .scalar_extend = true,
            .source = .{ .scalar_bool = value.asBool() },
        };
        if (value.tag() == .int) return .{
            .kind = .int,
            .len = 1,
            .scalar_extend = true,
            .source = .{ .scalar_int = value.asInt() },
        };
        if (value.tag() == .float) return .{
            .kind = .float,
            .len = 1,
            .scalar_extend = true,
            .source = .{ .scalar_float = value.asFloat() },
        };
        if (valueIsTableTextAtom(value)) return .{
            .kind = .string,
            .len = 1,
            .scalar_extend = true,
            .source = .{ .scalar_text = value },
        };
        if (stringSourceInfo(value)) |source| return .{
            .kind = .string,
            .len = source.bytes().len,
            .scalar_extend = false,
            .source = .{ .retained = value },
        };

        if (value.tag() == .array and
            (value.arrayKind() == .host_string_list or value.arrayKind() == .host_symbol_list))
            return .{
                .kind = .string,
                .len = value.asHostStringList().len,
                .scalar_extend = false,
                .source = .{ .retained = value },
            };

        if (numericVectorLen(value)) |len| {
            return .{
                .kind = if (try self.boolNumericVectorValue(value)) .boolean else switch (valueNumericMode(value).?) {
                    .int => .int,
                    .float => .float,
                },
                .len = len,
                .scalar_extend = false,
                .source = .{ .retained = value },
            };
        }

        if (boxedArrayItems(value)) |items| {
            if (items.len == 0) return error.Type;

            var all_bool = true;
            var all_int = true;
            var all_float = true;
            var all_text = true;
            for (items) |item| {
                if (item.tag() != .bool) all_bool = false;
                if (scalarIntLikeValue(item) == null) all_int = false;
                if (!(item.tag() == .float or scalarIntLikeValue(item) != null)) all_float = false;
                if (!valueIsTableTextItem(item)) all_text = false;
            }

            if (all_bool) return .{
                .kind = .boolean,
                .len = items.len,
                .scalar_extend = false,
                .source = .{ .boxed_values = items },
            };
            if (all_int) return .{
                .kind = .int,
                .len = items.len,
                .scalar_extend = false,
                .source = .{ .boxed_values = items },
            };
            if (all_float) return .{
                .kind = .float,
                .len = items.len,
                .scalar_extend = false,
                .source = .{ .boxed_values = items },
            };
            if (all_text) return .{
                .kind = .string,
                .len = items.len,
                .scalar_extend = false,
                .source = .{ .boxed_values = items },
            };
        }

        return error.Type;
    }

    fn dictTableRowCount(specs: []const DictTableColumnSpec) KError!usize {
        var row_count: ?usize = null;
        for (specs) |spec| {
            if (spec.scalar_extend) continue;
            if (row_count == null) {
                row_count = spec.len;
            } else if (row_count.? != spec.len) {
                return error.Type;
            }
        }
        return row_count orelse if (specs.len == 0) 0 else 1;
    }

    fn createManagedHostTextListFromValues(self: *Session, values: []const Value) !Value {
        const buf = try hostStringListAllocSlice(self.allocator, values.len);
        errdefer self.allocator.free(buf);
        const list = hostStringListFromAlloc(buf);
        const items = hostStringListItemsFromAlloc(buf, values.len);

        var bytes_len: usize = 0;
        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |piece| self.releaseHostStringPiece(piece);
        }

        for (values, 0..) |value, idx| {
            const piece: HostStringPiece = switch (value.tag()) {
                .array => switch (value.arrayKind()) {
                    .host_string => blk: {
                        const retained = try self.retainEscapedValue(value);
                        break :blk .{ .owned = @constCast(retained.asHostString()) };
                    },
                    .host_symbol => blk: {
                        const retained = try self.retainEscapedValue(value);
                        break :blk .{ .owned = @constCast(retained.asHostSymbol()) };
                    },
                    .host_string_view => blk: {
                        const copied = try self.managedHostString(hostStringViewBytes(value.asHostStringView()));
                        break :blk .{ .owned = @constCast(copied.asHostString()) };
                    },
                    else => return error.Type,
                },
                else => return error.Type,
            };
            items[idx] = piece;
            bytes_len = std.math.add(usize, bytes_len, hostStringPieceBytes(null, piece).len) catch return error.Unsupported;
            initialized += 1;
        }

        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = values.len,
            .bytes_len = bytes_len,
            .base = null,
            .storage = .{ .eager = items },
            .display = .list,
        };
        return Value.array(list);
    }

    fn buildDictTableColumn(self: *Session, name: Value, spec: DictTableColumnSpec, row_count: usize) KError!HostTableColumn {
        const column_name = try self.retainEscapedValue(name);
        errdefer self.releaseValue(column_name);

        const data = switch (spec.source) {
            .retained => |value| blk: {
                const retained = try self.retainEscapedValue(value);
                errdefer self.releaseValue(retained);
                if (spec.kind != .string) {
                    if (valueNumericHandle(retained)) |handle| {
                        _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle)) orelse return error.Type;
                    }
                }
                break :blk retained;
            },
            .boxed_values => |items| switch (spec.kind) {
                .boolean => blk: {
                    var out = try self.allocator.alloc(bool, items.len);
                    defer self.allocator.free(out);
                    for (items, 0..) |item, idx| out[idx] = item.asBool();
                    break :blk try self.createManagedHostBitArray(out);
                },
                .int => try self.createManagedHostIntArrayFromValues(items),
                .float => try self.createManagedHostFloatArrayFromValues(items),
                .string => try self.createManagedHostTextListFromValues(items),
                else => unreachable,
            },
            .scalar_bool => |scalar| blk: {
                const out = try self.allocator.alloc(bool, row_count);
                defer self.allocator.free(out);
                @memset(out, scalar);
                break :blk try self.createManagedHostBitArray(out);
            },
            .scalar_int => |scalar| blk: {
                const out = try self.allocator.alloc(i64, row_count);
                defer self.allocator.free(out);
                @memset(out, scalar);
                break :blk try self.createManagedHostIntArray(out);
            },
            .scalar_float => |scalar| blk: {
                const out = try self.allocator.alloc(f64, row_count);
                defer self.allocator.free(out);
                @memset(out, scalar);
                break :blk try self.createManagedHostFloatArray(out);
            },
            .scalar_text => |scalar| blk: {
                const out = try self.allocator.alloc(Value, row_count);
                defer self.allocator.free(out);
                for (out) |*slot| slot.* = scalar;
                break :blk try self.createManagedHostTextListFromValues(out);
            },
        };
        errdefer self.releaseValue(data);

        return .{
            .name = column_name,
            .data = data,
            .validity = null,
            .kind = spec.kind,
        };
    }

    fn keyedStoreColumnLen(value: Value) ?usize {
        if (stringSourceInfo(value)) |source| return source.bytes().len;
        if (value.tag() == .array and value.arrayKind() == .host_string_list) return value.asHostStringList().len;
        if (value.tag() == .array and value.arrayKind() == .host_symbol_list) return value.asHostStringList().len;
        return numericVectorLen(value);
    }

    fn keyedStoreColumnMatchesKind(value: Value, kind: HostTableColumnKind) bool {
        return switch (kind) {
            .string => stringSourceInfo(value) != null or
                (value.tag() == .array and
                    (value.arrayKind() == .host_string_list or value.arrayKind() == .host_symbol_list)),
            else => keyedStoreColumnLen(value) != null,
        };
    }

    fn keyedStoreMetadataRowCount(store: *const HostKeyedStore, values: []const Value, metadata: []const HostKeyedColumnMetadata) KError!usize {
        if (values.len != metadata.len or values.len != keyedStoreNameCount(store)) return error.Type;
        var row_count: ?usize = null;
        for (values, metadata) |value, entry| {
            if (!keyedStoreColumnMatchesKind(value, entry.kind)) return error.Type;
            const len = keyedStoreColumnLen(value) orelse return error.Type;
            if (row_count == null) {
                row_count = len;
            } else if (row_count.? != len) {
                return error.Type;
            }
            if (entry.validity) |mask| {
                const mask_len = keyedStoreColumnLen(mask) orelse return error.Type;
                if (mask_len != len) return error.Type;
            }
        }
        return row_count orelse 0;
    }

    fn retainKeyedStoreColumnMetadataFromTable(self: *Session, columns: []const HostTableColumn) ![]HostKeyedColumnMetadata {
        const metadata = try self.allocator.alloc(HostKeyedColumnMetadata, columns.len);
        var initialized: usize = 0;
        errdefer {
            for (metadata[0..initialized]) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(metadata);
        }

        for (columns, 0..) |column, idx| {
            metadata[idx] = .{
                .kind = column.kind,
                .validity = if (column.validity) |mask| try self.retainEscapedValue(mask) else null,
            };
            initialized += 1;
        }
        return metadata;
    }

    fn retainKeyedStoreColumnMetadata(self: *Session, source: []const HostKeyedColumnMetadata) ![]HostKeyedColumnMetadata {
        const metadata = try self.allocator.alloc(HostKeyedColumnMetadata, source.len);
        var initialized: usize = 0;
        errdefer {
            for (metadata[0..initialized]) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(metadata);
        }

        for (source, 0..) |entry, idx| {
            metadata[idx] = .{
                .kind = entry.kind,
                .validity = if (entry.validity) |mask| try self.retainEscapedValue(mask) else null,
            };
            initialized += 1;
        }
        return metadata;
    }

    fn cloneKeyedStoreView(self: *Session, store: *const HostKeyedStore, layout: HostKeyedLayout, row_count: usize) KError!Value {
        const owned_path = try self.allocator.dupe(u8, store.path);
        errdefer self.allocator.free(owned_path);
        const names = try self.retainEscapedValue(store.names);
        errdefer self.releaseValue(names);
        const values = try self.retainEscapedValue(store.values);
        errdefer self.releaseValue(values);
        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const metadata = if (store.column_metadata) |column_metadata|
            try self.retainKeyedStoreColumnMetadata(column_metadata)
        else
            null;
        errdefer if (metadata) |items| {
            for (items) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(items);
        };

        return try self.createManagedKeyedStore(owned_path, true, names, values, metadata, layout, row_count, lookup);
    }

    fn projectKeyedStoreNames(self: *Session, store: *const HostKeyedStore, source_indices: []const usize) KError!Value {
        return switch (store.names.arrayKind()) {
            .host_boxed_array => blk: {
                const names = try self.allocator.alloc(Value, source_indices.len);
                defer self.allocator.free(names);
                var initialized: usize = 0;
                errdefer {
                    for (names[0..initialized]) |value| self.releaseValue(value);
                }
                for (source_indices, 0..) |source_idx, out_idx| {
                    names[out_idx] = try self.keyedStoreNameValue(store, source_idx);
                    initialized += 1;
                }
                break :blk try self.createManagedHostBoxedArray(names);
            },
            .host_string_list => blk: {
                const names = try self.allocator.alloc([]const u8, source_indices.len);
                defer self.allocator.free(names);
                for (source_indices, 0..) |source_idx, out_idx| {
                    names[out_idx] = try hostStringListItemBytes(store.names.asHostStringList(), source_idx);
                }
                break :blk try self.createManagedHostStringListFromSlices(names);
            },
            .host_symbol_list => blk: {
                const names = try self.allocator.alloc([]const u8, source_indices.len);
                defer self.allocator.free(names);
                for (source_indices, 0..) |source_idx, out_idx| {
                    names[out_idx] = try hostStringListItemBytes(store.names.asHostStringList(), source_idx);
                }
                break :blk try self.createManagedHostSymbolListFromSlices(names);
            },
            else => blk: {
                const names = try self.allocator.alloc(Value, source_indices.len);
                defer self.allocator.free(names);
                var initialized: usize = 0;
                errdefer {
                    for (names[0..initialized]) |value| self.releaseValue(value);
                }
                for (source_indices, 0..) |source_idx, out_idx| {
                    names[out_idx] = try self.keyedStoreNameValue(store, source_idx);
                    initialized += 1;
                }
                break :blk try self.makeArrayFromValues(names);
            },
        };
    }

    fn projectKeyedStore(self: *Session, store: *const HostKeyedStore, source_indices: []const usize) KError!Value {
        const projected_values = try self.allocator.alloc(Value, source_indices.len);
        defer self.allocator.free(projected_values);
        var initialized_values: usize = 0;
        defer {
            for (projected_values[0..initialized_values]) |value| self.releaseValue(value);
        }

        for (source_indices, 0..) |source_idx, out_idx| {
            if (source_idx >= keyedStoreNameCount(store)) return error.Internal;
            projected_values[out_idx] = try self.keyedStoreValueAt(store, source_idx);
            initialized_values += 1;
        }

        const names = try self.projectKeyedStoreNames(store, source_indices);
        errdefer self.releaseValue(names);
        const lookup = try self.createKeyedStoreLookupFromNamesValueOptions(names, true);
        const values = if (keyedStoreUsesDenseValueFastPath(store))
            try self.makeArrayFromValues(projected_values)
        else
            try self.createManagedHostBoxedArray(projected_values);
        errdefer self.releaseValue(values);

        const metadata = if (store.column_metadata) |source_metadata| blk: {
            const projected_metadata = try self.allocator.alloc(HostKeyedColumnMetadata, source_indices.len);
            var initialized: usize = 0;
            errdefer {
                for (projected_metadata[0..initialized]) |entry| {
                    if (entry.validity) |mask| self.releaseValue(mask);
                }
                self.allocator.free(projected_metadata);
            }

            for (source_indices, 0..) |source_idx, out_idx| {
                if (source_idx >= source_metadata.len) return error.Internal;
                const source_entry = source_metadata[source_idx];
                projected_metadata[out_idx] = .{
                    .kind = source_entry.kind,
                    .validity = if (source_entry.validity) |mask| try self.retainEscapedValue(mask) else null,
                };
                initialized += 1;
            }
            break :blk projected_metadata;
        } else null;
        errdefer if (metadata) |items| {
            for (items) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(items);
        };

        const owned_path = try self.allocator.dupe(u8, store.path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(
            owned_path,
            true,
            names,
            values,
            metadata,
            store.layout,
            if (store.layout == .table) store.row_count else 0,
            lookup,
        );
    }

    fn reverseTableStore(self: *Session, store: *const HostKeyedStore) KError!Value {
        if (store.values.tag() != .array or store.values.arrayKind() != .host_boxed_array) return error.Internal;
        const source_values = store.values.asHostBoxedArray().items;
        if (source_values.len != keyedStoreNameCount(store)) return error.Internal;
        const source_metadata = store.column_metadata orelse return error.Internal;
        if (source_metadata.len != source_values.len) return error.Internal;

        const reversed_values = try self.allocator.alloc(Value, source_values.len);
        defer self.allocator.free(reversed_values);
        var initialized_values: usize = 0;
        defer {
            for (reversed_values[0..initialized_values]) |value| self.releaseValue(value);
        }

        for (source_values, 0..) |value, idx| {
            reversed_values[idx] = try self.reverseValue(value);
            initialized_values += 1;
        }

        const names = try self.retainEscapedValue(store.names);
        errdefer self.releaseValue(names);
        const values = try self.createManagedHostBoxedArray(reversed_values);
        errdefer self.releaseValue(values);
        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const metadata = try self.allocator.alloc(HostKeyedColumnMetadata, source_metadata.len);
        var initialized_metadata: usize = 0;
        errdefer {
            for (metadata[0..initialized_metadata]) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(metadata);
        }

        for (source_metadata, 0..) |entry, idx| {
            metadata[idx] = .{
                .kind = entry.kind,
                .validity = if (entry.validity) |mask| try self.reverseValue(mask) else null,
            };
            initialized_metadata += 1;
        }

        const owned_path = try self.allocator.dupe(u8, store.path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(
            owned_path,
            true,
            names,
            values,
            metadata,
            .table,
            store.row_count,
            lookup,
        );
    }

    fn reverseKeyedStore(self: *Session, store: *const HostKeyedStore) KError!Value {
        return switch (store.layout) {
            .dict => blk: {
                const key_count = keyedStoreNameCount(store);
                const source_indices = try self.allocator.alloc(usize, key_count);
                defer self.allocator.free(source_indices);

                var idx = key_count;
                var out_idx: usize = 0;
                while (idx > 0) {
                    idx -= 1;
                    source_indices[out_idx] = idx;
                    out_idx += 1;
                }
                break :blk try self.projectKeyedStore(store, source_indices);
            },
            .table => try self.reverseTableStore(store),
        };
    }

    fn keyedDictTakeValue(self: *Session, raw_count: i64, store: *const HostKeyedStore) KError!Value {
        std.debug.assert(store.layout == .dict);
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) return try self.projectKeyedStore(store, &.{});
        const len = keyedStoreNameCount(store);
        if (len == 0) return error.Type;

        const source_indices = try self.allocator.alloc(usize, count);
        defer self.allocator.free(source_indices);

        const start = takeCyclicStart(raw_count, count, len);
        for (0..count) |idx| source_indices[idx] = (start + idx) % len;

        return try self.projectKeyedStore(store, source_indices);
    }

    fn keyedDictDropValue(self: *Session, raw_count: i64, store: *const HostKeyedStore) KError!Value {
        std.debug.assert(store.layout == .dict);
        const len = keyedStoreNameCount(store);
        const bounds = dropSliceBounds(raw_count, len);

        const source_indices = try self.allocator.alloc(usize, bounds.end - bounds.start);
        defer self.allocator.free(source_indices);
        for (bounds.start..bounds.end, 0..) |idx, out_idx| source_indices[out_idx] = idx;
        return try self.projectKeyedStore(store, source_indices);
    }

    fn keyedDictDeleteKeys(self: *Session, store: *const HostKeyedStore, keys: Value) KError!Value {
        std.debug.assert(store.layout == .dict);

        const key_items = try self.materializeSequenceItems(keys);
        defer self.releaseArgs(key_items);

        const len = keyedStoreNameCount(store);
        const remove = try self.allocator.alloc(bool, len);
        defer self.allocator.free(remove);
        @memset(remove, false);

        var removed_count: usize = 0;
        for (key_items) |key| {
            const idx = (try self.keyedStoreLookupIndexByKey(store, key)) orelse continue;
            if (!remove[idx]) {
                remove[idx] = true;
                removed_count += 1;
            }
        }

        if (removed_count == 0) return self.shareValue(Value.array(@constCast(store)));

        const source_indices = try self.allocator.alloc(usize, len - removed_count);
        defer self.allocator.free(source_indices);
        var write_idx: usize = 0;
        for (remove, 0..) |should_remove, idx| {
            if (should_remove) continue;
            source_indices[write_idx] = idx;
            write_idx += 1;
        }
        return try self.projectKeyedStore(store, source_indices);
    }

    fn tryProjectKeyedStoreByKeys(self: *Session, left: Value, right: Value) KError!?Value {
        if (right.tag() != .array or right.arrayKind() != .host_keyed_store) return null;
        if (left.tag() != .array) return null;
        _ = derivedSequenceLen(left) orelse return null;

        const store = right.asHostKeyedStore();
        const key_items = try self.materializeSequenceItems(left);
        defer self.releaseArgs(key_items);

        const source_indices = try self.allocator.alloc(?usize, key_items.len);
        defer self.allocator.free(source_indices);
        var saw_missing = false;
        for (key_items, 0..) |item, idx| {
            source_indices[idx] = try self.keyedStoreLookupIndexByKey(store, item);
            if (source_indices[idx] == null) saw_missing = true;
        }

        if (!saw_missing) {
            const projected_indices = try self.allocator.alloc(usize, key_items.len);
            defer self.allocator.free(projected_indices);
            for (source_indices, projected_indices) |source_idx, *projected_idx| projected_idx.* = source_idx.?;
            return try self.projectKeyedStore(store, projected_indices);
        }

        if (store.layout != .dict) return error.Name;

        const values = try self.allocator.alloc(Value, key_items.len);
        defer self.allocator.free(values);
        var initialized_values: usize = 0;
        defer {
            for (values[0..initialized_values]) |value| self.releaseValue(value);
        }
        for (source_indices, values) |source_idx, *value| {
            value.* = if (source_idx) |idx|
                try self.keyedStoreValueAt(store, idx)
            else
                try self.prototypeLikeValue(store.values);
            initialized_values += 1;
        }

        const names = try self.makeArrayFromValues(key_items);
        errdefer self.releaseValue(names);
        const lookup = try self.createKeyedStoreLookupFromNamesValueOptions(names, true);
        const projected_values = if (keyedStoreUsesDenseValueFastPath(store))
            try self.makeArrayFromValues(values)
        else
            try self.createManagedHostBoxedArray(values);
        errdefer self.releaseValue(projected_values);

        const owned_path = try self.allocator.dupe(u8, store.path);
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(
            owned_path,
            true,
            names,
            projected_values,
            null,
            store.layout,
            0,
            lookup,
        );
    }

    fn tableFromKeyedStoreMetadata(self: *Session, store: *const HostKeyedStore, values: []const Value, metadata: []const HostKeyedColumnMetadata) KError!Value {
        const row_count = try keyedStoreMetadataRowCount(store, values, metadata);
        return try self.cloneKeyedStoreView(store, .table, row_count);
    }

    fn tableFromDictValue(self: *Session, store: *const HostKeyedStore) KError!Value {
        const key_count = keyedStoreNameCount(store);
        const values = try self.allocator.alloc(Value, key_count);
        defer self.allocator.free(values);
        var initialized_values: usize = 0;
        defer {
            for (values[0..initialized_values]) |value| self.releaseValue(value);
        }
        for (0..key_count) |idx| {
            values[idx] = try self.keyedStoreValueAt(store, idx);
            initialized_values += 1;
        }
        if (store.column_metadata) |metadata| {
            return try self.tableFromKeyedStoreMetadata(store, values, metadata);
        }
        const specs = try self.allocator.alloc(DictTableColumnSpec, values.len);
        defer self.allocator.free(specs);

        for (values, 0..) |value, idx| specs[idx] = try self.classifyDictTableColumn(value);
        const row_count = try dictTableRowCount(specs);

        const columns = try self.allocator.alloc(HostTableColumn, values.len);
        var built_columns: usize = 0;
        errdefer {
            for (columns[0..built_columns]) |column| {
                self.releaseValue(column.name);
                self.releaseValue(column.data);
                if (column.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        for (values, 0..) |_, idx| {
            const name = try self.keyedStoreNameValue(store, idx);
            errdefer self.releaseValue(name);
            columns[idx] = try self.buildDictTableColumn(name, specs[idx], row_count);
            self.releaseValue(name);
            built_columns += 1;
        }

        return try self.createManagedHostTable(row_count, columns);
    }

    fn flipValue(self: *Session, value: Value) KError!Value {
        if (value.tag() == .array and value.arrayKind() == .host_keyed_store) {
            const store = value.asHostKeyedStore();
            return switch (store.layout) {
                .dict => try self.tableFromDictValue(store),
                .table => try self.cloneKeyedStoreView(store, .dict, 0),
            };
        }
        if (valueNumericMode(value) != null and valueNumericMatrixShape(value) != null) {
            return try newTransposeViewValue(self, value);
        }
        const transposed: ?Value = self.transposeValue(value) catch |err| switch (err) {
            error.Type => null,
            else => return err,
        };
        if (transposed) |result| return result;

        if (numericVectorLen(value)) |len| {
            return try newReshapeViewValue(self, value, numericShapeSnapshotMatrix(1, len));
        }

        return switch (value.tag()) {
            .int, .bool => blk: {
                const items = [_]Value{value};
                const singleton = try self.createManagedHostIntArrayFromValues(&items);
                break :blk try newReshapeViewValue(self, singleton, numericShapeSnapshotMatrix(1, 1));
            },
            .float => blk: {
                const items = [_]Value{value};
                const singleton = try self.createManagedHostFloatArrayFromValues(&items);
                break :blk try newReshapeViewValue(self, singleton, numericShapeSnapshotMatrix(1, 1));
            },
            .float32 => blk: {
                const items = [_]Value{value};
                const singleton = try self.createManagedHostFloat32ArrayFromValues(&items);
                break :blk try newReshapeViewValue(self, singleton, numericShapeSnapshotMatrix(1, 1));
            },
            .array => switch (value.arrayKind()) {
                .host_boxed_array => blk: {
                    break :blk try self.createManagedHostBoxedArray(&[_]Value{value});
                },
                .host_string, .host_string_view => try self.createManagedHostBoxedArray(&[_]Value{value}),
                .host_symbol => blk: {
                    const inner = try self.createManagedHostBoxedArray(&[_]Value{value});
                    errdefer self.releaseValue(inner);
                    const outer = try self.createManagedHostBoxedArray(&[_]Value{inner});
                    self.releaseValue(inner);
                    break :blk outer;
                },
                else => error.Type,
            },
            else => error.Type,
        };
    }

    fn negateValue(self: *Session, value: Value) KError!Value {
        if (try self.tryScalarIntBoolMonad(.sub, value)) |result| return result;
        if (try self.textByteNumericMonadValue(.sub, value)) |result| return result;
        return switch (value.tag()) {
            .float32 => try self.float32Value(-value.asFloat32()),
            .float => try self.floatValue(-value.asFloat()),
            .array => try self.applyNumericMonad(.sub, value),
            else => error.Type,
        };
    }

    fn sqrtValue(self: *Session, value: Value) KError!Value {
        if (try self.tryScalarIntBoolMonad(.div, value)) |result| return result;
        if (try self.textByteNumericMonadValue(.div, value)) |result| return result;
        return switch (value.tag()) {
            .float32 => try self.float32Value(@floatCast(std.math.sqrt(@as(f64, @floatCast(value.asFloat32()))))),
            .float => try self.floatValue(std.math.sqrt(value.asFloat())),
            .array => try self.applyNumericMonad(.div, value),
            else => error.Type,
        };
    }

    fn textByteNumericMonadValue(self: *Session, op: BuiltinId, value: Value) KError!?Value {
        switch (op) {
            .sub, .div => {},
            else => return null,
        }

        const is_text = stringBytes(value) != null or
            (value.tag() == .array and value.arrayKind() == .host_string_list);
        if (!is_text) return null;

        const casted = try self.castValueToInt(value);
        defer self.releaseValue(casted);
        return try self.applyMonad(op, casted);
    }

    fn tableScalarValue(value: Value) ?*const HostTableScalar {
        if (value.tag() != .array or value.arrayKind() != .host_table_scalar) return null;
        return valueAsHostTableScalar(value);
    }

    fn scalarIntLikeValue(value: Value) ?i64 {
        if (tableScalarValue(value)) |scalar| {
            if (scalar.is_null) return null;
            return scalarIntLikeValue(scalar.value);
        }
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag, Value.boxed_int_tag => value.asInt(),
            Value.bool_tag => @intFromBool(value.asBool()),
            else => null,
        };
    }

    fn inlineIntBoolValue(value: Value) ?i64 {
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag => value.asInt(),
            Value.bool_tag => @intFromBool(value.asBool()),
            else => null,
        };
    }

    fn inlineExactIntNumericValue(value: Value) ?i64 {
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag => value.asInt(),
            Value.bool_tag => @intFromBool(value.asBool()),
            else => switch (value.tag()) {
                .float, .float32 => exactIntFromFloat(value.asFloat()),
                else => null,
            },
        };
    }

    fn inlineNumericFloatValue(value: Value) ?f64 {
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag => @floatFromInt(value.asInt()),
            Value.bool_tag => @floatFromInt(@intFromBool(value.asBool())),
            else => switch (value.tag()) {
                .float, .float32 => value.asFloat(),
                else => null,
            },
        };
    }

    fn tryFastInlineScalarDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!?Value {
        const left_int = inlineIntBoolValue(left);
        const right_int = inlineIntBoolValue(right);
        if (left_int != null and right_int != null) {
            if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
            const lhs = left_int.?;
            const rhs = right_int.?;
            const result: ?Value = switch (op) {
                .add => try self.addIntValue(lhs, rhs),
                .sub => try self.subIntValue(lhs, rhs),
                .mul => try self.mulIntValue(lhs, rhs),
                .div => try self.floatValue(@as(f64, @floatFromInt(lhs)) / @as(f64, @floatFromInt(rhs))),
                .pow => try self.intValue(try intPowLikeMlx(lhs, rhs)),
                .iota => try self.intValue(bangIntOp(lhs, rhs)),
                .minimum => if (left.tag() == .bool and right.tag() == .bool)
                    Value.fromBool(left.asBool() and right.asBool())
                else
                    try self.intValue(@min(lhs, rhs)),
                .maximum => if (left.tag() == .bool and right.tag() == .bool)
                    Value.fromBool(left.asBool() or right.asBool())
                else
                    try self.intValue(@max(lhs, rhs)),
                .less => Value.fromBool(lhs < rhs),
                .more => Value.fromBool(lhs > rhs),
                .equal => Value.fromBool(lhs == rhs),
                else => null,
            };
            if (comptime enable_probe_instrumentation) {
                if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
            }
            return result;
        }

        const left_float = inlineNumericFloatValue(left) orelse return null;
        const right_float = inlineNumericFloatValue(right) orelse return null;
        if (comptime enable_probe_instrumentation) self.debug_inline_scalar_dyad_attempt_count += 1;
        const result_kind = scalarNumericResultStorageKind(left, right);
        const float_result = struct {
            fn value(session: *Session, kind: HostFloatStorageKind, raw: f64) KError!Value {
                return switch (kind) {
                    .float32 => try session.float32Value(@floatCast(raw)),
                    .float64 => try session.floatValue(raw),
                };
            }
        }.value;
        const result: ?Value = switch (op) {
            .add => try float_result(self, result_kind, left_float + right_float),
            .sub => try float_result(self, result_kind, left_float - right_float),
            .mul => try float_result(self, result_kind, left_float * right_float),
            .div => try float_result(self, result_kind, left_float / right_float),
            .minimum => try float_result(self, result_kind, @min(left_float, right_float)),
            .maximum => try float_result(self, result_kind, @max(left_float, right_float)),
            .less => Value.fromBool(left_float < right_float),
            .more => Value.fromBool(left_float > right_float),
            .equal => Value.fromBool(left_float == right_float),
            .pow => try float_result(self, result_kind, std.math.pow(f64, left_float, right_float)),
            else => null,
        };
        if (comptime enable_probe_instrumentation) {
            if (result != null) self.debug_inline_scalar_dyad_hit_count += 1 else self.debug_inline_scalar_dyad_fallback_count += 1;
        }
        return result;
    }

    fn tryScalarIntBoolDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!?Value {
        const left_value = scalarIntLikeValue(left) orelse return null;
        const right_value = scalarIntLikeValue(right) orelse return null;
        return switch (op) {
            .add => try self.addIntValue(left_value, right_value),
            .sub => try self.subIntValue(left_value, right_value),
            .mul => try self.mulIntValue(left_value, right_value),
            .div => try self.floatValue(@as(f64, @floatFromInt(left_value)) / @as(f64, @floatFromInt(right_value))),
            .pow => try self.intValue(try intPowLikeMlx(left_value, right_value)),
            .iota => try self.intValue(bangIntOp(left_value, right_value)),
            .minimum => try self.intValue(@min(left_value, right_value)),
            .maximum => try self.intValue(@max(left_value, right_value)),
            .less => Value.fromBool(left_value < right_value),
            .more => Value.fromBool(left_value > right_value),
            else => return error.Unsupported,
        };
    }

    fn numericStructuralAffineOffsetValue(self: *Session, value: Value, offset: i64) KError!?Value {
        const handle = valueNumericHandle(value) orelse return null;
        if (!numericArrayIsRangeIota(handle)) return null;
        const start = try checkedIntOp(.add, numericArrayRangeIota(handle).start, offset);
        return try newRangeIotaValueWithShape(
            self,
            .managed,
            numericArrayRangeLen(handle),
            start,
            numericArrayRangeIota(handle).step,
            numericShapeSnapshotFromHandle(handle),
        );
    }

    fn tryAffineRangeAddValues(self: *Session, left: Value, right: Value) KError!?Value {
        if (scalarIntLikeValue(left)) |offset| {
            if (try self.numericStructuralAffineOffsetValue(right, offset)) |result| return result;
        }
        if (scalarIntLikeValue(right)) |offset| {
            if (try self.numericStructuralAffineOffsetValue(left, offset)) |result| return result;
        }
        return null;
    }

    fn tryScalarIntBoolMonad(self: *Session, op: BuiltinId, value: Value) KError!?Value {
        const int_value = scalarIntLikeValue(value) orelse return null;
        return switch (op) {
            .add => try self.intValue(int_value),
            .sub => try self.negateIntValue(int_value),
            .mul => return error.Unsupported,
            .div => try self.floatValue(std.math.sqrt(@as(f64, @floatFromInt(int_value)))),
            else => return error.Unsupported,
        };
    }

    fn loadPathBytes(value: Value) ?[]const u8 {
        return stringBytes(value);
    }

    fn keyedLookupNameBytes(value: Value) ?[]const u8 {
        return symbolBytes(value) orelse stringBytes(value);
    }

    fn keyedStoreValueAt(self: *Session, store: *const HostKeyedStore, index: usize) KError!Value {
        const len = derivedSequenceLen(store.values) orelse return error.Internal;
        if (index >= len) return error.Internal;
        return try self.derivedSequenceItemValue(store.values, index);
    }

    fn keyedStoreLookupValue(self: *Session, store: *const HostKeyedStore, name: []const u8) KError!Value {
        if (store.lookup.get(name)) |idx| return try self.keyedStoreValueAt(store, idx);
        return error.Name;
    }

    fn keyedStoreLookupIndexByKey(self: *Session, store: *const HostKeyedStore, key: Value) KError!?usize {
        if (keyedLookupNameBytes(key)) |name| {
            if (store.lookup.get(name)) |idx| return idx;
        }

        const len = keyedStoreNameCount(store);
        for (0..len) |idx| {
            const candidate = try self.keyedStoreNameValue(store, idx);
            defer self.releaseValue(candidate);
            if (try self.valueMatchEqual(candidate, key)) return idx;
        }
        return null;
    }

    fn keyedStoreLookupValueByKey(self: *Session, store: *const HostKeyedStore, key: Value) KError!Value {
        const idx = (try self.keyedStoreLookupIndexByKey(store, key)) orelse return error.Name;
        return try self.keyedStoreValueAt(store, idx);
    }

    fn keyedStoreLookupSequenceValue(self: *Session, store: *const HostKeyedStore, selector: Value) KError!Value {
        const key_items = try self.materializeSequenceItems(selector);
        defer self.releaseArgs(key_items);

        var out = std.ArrayList(Value).empty;
        defer {
            for (out.items) |value| self.releaseValue(value);
            out.deinit(self.allocator);
        }
        try out.ensureTotalCapacity(self.allocator, key_items.len);

        for (key_items) |key| {
            try out.append(self.allocator, try self.keyedStoreLookupValueByKey(store, key));
        }
        return try self.makeArrayFromValues(out.items);
    }

    fn tableNullScalarValue(self: *Session, kind: HostTableColumnKind) KError!Value {
        return try self.createManagedHostTableScalar(kind, Value.fromBool(false), true);
    }

    fn tableCellScalarValue(self: *Session, store: *const HostKeyedStore, column_idx: usize, row: usize) KError!Value {
        std.debug.assert(store.layout == .table);
        const kind = keyedStoreTableMetadata(store)[column_idx].kind;
        if (!keyedStoreTableCellIsValid(store, column_idx, row)) return try self.tableNullScalarValue(kind);

        const data = tableColumnData(store, column_idx);
        return switch (kind) {
            .boolean => Value.fromBool((try numericIntAt(data, @intCast(row))) != 0),
            .int => try self.intValue(try numericIntAt(data, @intCast(row))),
            .float => try self.floatValue(try numericFloatAt(data, @intCast(row))),
            .string => try self.hostTextListItemValue(data, row),
            .date,
            .time,
            .time_ns,
            .time_tz,
            .timestamp,
            .timestamp_s,
            .timestamp_ms,
            .timestamp_ns,
            .timestamp_tz,
            => try self.createManagedHostTableScalar(kind, try self.intValue(try numericIntAt(data, @intCast(row))), false),
        };
    }

    fn tableRowDictValue(self: *Session, store: *const HostKeyedStore, row: usize) KError!Value {
        std.debug.assert(store.layout == .table);
        const key_count = keyedStoreNameCount(store);
        const keys = try self.allocator.alloc([]const u8, key_count);
        defer self.allocator.free(keys);
        const values = try self.allocator.alloc(Value, key_count);
        defer self.allocator.free(values);
        var initialized: usize = 0;
        defer {
            for (values[0..initialized]) |value| self.releaseValue(value);
        }

        for (0..key_count) |idx| {
            keys[idx] = keyedStoreColumnNameBytes(store, idx);
            values[idx] = try self.tableCellScalarValue(store, idx, row);
            initialized += 1;
        }

        const names = try self.createManagedHostSymbolListFromSlices(keys);
        defer self.releaseValue(names);
        const row_values = try self.makeArrayFromValues(values);
        defer self.releaseValue(row_values);
        return try self.createHostDictValueFromKeySequenceValue("", names, row_values);
    }

    fn tableRowIndicesFromSelector(self: *Session, selector: HostIntDenseView, row_count: usize) KError![]usize {
        var row_indices = std.ArrayList(usize).empty;
        errdefer row_indices.deinit(self.allocator);

        switch (selector) {
            .dense => |dense| switch (dense) {
                .bit => |bits| {
                    if (bits.len != row_count) return error.Type;
                    try row_indices.ensureTotalCapacity(self.allocator, bits.len);
                    for (0..bits.len) |idx| {
                        if (!bitGet(bits.words, idx)) continue;
                        try row_indices.append(self.allocator, idx);
                    }
                },
                else => {
                    const len = hostIntArrayViewLen(dense);
                    try row_indices.ensureTotalCapacity(self.allocator, len);
                    for (0..len) |idx| {
                        try row_indices.append(self.allocator, try normalizeIndex(hostIntViewItem(dense, idx), row_count));
                    }
                },
            },
            else => {
                const len = hostIntDenseViewLen(selector);
                try row_indices.ensureTotalCapacity(self.allocator, len);
                for (0..len) |idx| {
                    try row_indices.append(self.allocator, try normalizeIndex(try hostIntDenseViewItem(selector, idx), row_count));
                }
            },
        }

        return try row_indices.toOwnedSlice(self.allocator);
    }

    fn tableSelectValidityRows(self: *Session, validity: Value, row_indices: []const usize) KError!Value {
        const out = try self.allocator.alloc(bool, row_indices.len);
        defer self.allocator.free(out);
        for (row_indices, 0..) |row, idx| out[idx] = (try numericIntAt(validity, @intCast(row))) != 0;
        return try self.createManagedHostBitArray(out);
    }

    fn tableSelectStringRows(self: *Session, data: Value, row_indices: []const usize) KError!Value {
        const values = try self.allocator.alloc(Value, row_indices.len);
        defer self.allocator.free(values);
        var initialized: usize = 0;
        defer {
            for (values[0..initialized]) |value| self.releaseValue(value);
        }

        for (row_indices, 0..) |row, idx| {
            values[idx] = try self.hostTextListItemValue(data, row);
            initialized += 1;
        }
        return try self.createManagedHostTextListFromValues(values);
    }

    fn tableSelectColumnRows(self: *Session, store: *const HostKeyedStore, column_idx: usize, row_indices: []const usize) KError!Value {
        std.debug.assert(store.layout == .table);
        const kind = keyedStoreTableMetadata(store)[column_idx].kind;
        const data = tableColumnData(store, column_idx);
        return switch (kind) {
            .boolean => blk: {
                const out = try self.allocator.alloc(bool, row_indices.len);
                defer self.allocator.free(out);
                for (row_indices, 0..) |row, idx| out[idx] = (try numericIntAt(data, @intCast(row))) != 0;
                break :blk try self.createManagedHostBitArray(out);
            },
            .float => blk: {
                const out = try self.allocator.alloc(f64, row_indices.len);
                defer self.allocator.free(out);
                for (row_indices, 0..) |row, idx| out[idx] = try numericFloatAt(data, @intCast(row));
                break :blk try self.createManagedHostFloatArray(out);
            },
            .string => try self.tableSelectStringRows(data, row_indices),
            .int,
            .date,
            .time,
            .time_ns,
            .time_tz,
            .timestamp,
            .timestamp_s,
            .timestamp_ms,
            .timestamp_ns,
            .timestamp_tz,
            => blk: {
                const out = try self.allocator.alloc(i64, row_indices.len);
                defer self.allocator.free(out);
                for (row_indices, 0..) |row, idx| out[idx] = try numericIntAt(data, @intCast(row));
                break :blk try self.createManagedHostIntArray(out);
            },
        };
    }

    fn tableSelectRows(self: *Session, store: *const HostKeyedStore, row_indices: []const usize) KError!Value {
        std.debug.assert(store.layout == .table);
        const metadata = keyedStoreTableMetadata(store);
        const column_count = keyedStoreNameCount(store);
        const columns = try self.allocator.alloc(HostTableColumn, column_count);
        var built_columns: usize = 0;
        errdefer {
            for (columns[0..built_columns]) |column| {
                self.releaseValue(column.name);
                self.releaseValue(column.data);
                if (column.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        for (0..column_count) |idx| {
            const name = try self.keyedStoreNameValue(store, idx);
            errdefer self.releaseValue(name);
            columns[idx] = .{
                .name = try self.retainEscapedValue(name),
                .data = try self.tableSelectColumnRows(store, idx, row_indices),
                .validity = if (metadata[idx].validity) |mask| try self.tableSelectValidityRows(mask, row_indices) else null,
                .kind = metadata[idx].kind,
            };
            self.releaseValue(name);
            built_columns += 1;
        }

        return try self.createManagedHostTable(row_indices.len, columns);
    }

    fn tableSelectRowsBySelector(self: *Session, store: *const HostKeyedStore, selector: HostIntDenseView) KError!Value {
        const row_indices = try self.tableRowIndicesFromSelector(selector, store.row_count);
        defer self.allocator.free(row_indices);
        return try self.tableSelectRows(store, row_indices);
    }

    fn tableTakeValue(self: *Session, raw_count: i64, store: *const HostKeyedStore) KError!Value {
        std.debug.assert(store.layout == .table);
        const count: usize = @intCast(@abs(raw_count));
        if (count == 0) return try self.tableSelectRows(store, &.{});
        if (store.row_count == 0) return error.Type;

        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, count);

        const start = takeCyclicStart(raw_count, count, store.row_count);
        for (0..count) |idx| try row_indices.append(self.allocator, (start + idx) % store.row_count);

        return try self.tableSelectRows(store, row_indices.items);
    }

    fn tableDropValue(self: *Session, raw_count: i64, store: *const HostKeyedStore) KError!Value {
        std.debug.assert(store.layout == .table);
        const bounds = dropSliceBounds(raw_count, store.row_count);

        var row_indices = std.ArrayList(usize).empty;
        defer row_indices.deinit(self.allocator);
        try row_indices.ensureTotalCapacity(self.allocator, bounds.end - bounds.start);
        for (bounds.start..bounds.end) |idx| try row_indices.append(self.allocator, idx);
        return try self.tableSelectRows(store, row_indices.items);
    }

    fn concatTableValidity(self: *Session, left: ?Value, right: ?Value, left_rows: usize, right_rows: usize) KError!?Value {
        if (left == null and right == null) return null;

        const out = try self.allocator.alloc(bool, left_rows + right_rows);
        defer self.allocator.free(out);
        for (0..left_rows) |idx| {
            out[idx] = if (left) |mask| (try numericIntAt(mask, @intCast(idx))) != 0 else true;
        }
        for (0..right_rows) |idx| {
            out[left_rows + idx] = if (right) |mask| (try numericIntAt(mask, @intCast(idx))) != 0 else true;
        }
        return try self.createManagedHostBitArray(out);
    }

    fn concatTableStringColumns(self: *Session, left: Value, right: Value, left_rows: usize, right_rows: usize) KError!Value {
        const values = try self.allocator.alloc(Value, left_rows + right_rows);
        defer self.allocator.free(values);
        var initialized: usize = 0;
        defer {
            for (values[0..initialized]) |value| self.releaseValue(value);
        }

        for (0..left_rows) |idx| {
            values[initialized] = try self.hostTextListItemValue(left, idx);
            initialized += 1;
        }
        for (0..right_rows) |idx| {
            values[initialized] = try self.hostTextListItemValue(right, idx);
            initialized += 1;
        }
        return try self.createManagedHostTextListFromValues(values);
    }

    fn concatTableColumnData(self: *Session, kind: HostTableColumnKind, left: Value, right: Value, left_rows: usize, right_rows: usize) KError!Value {
        return switch (kind) {
            .boolean => blk: {
                const out = try self.allocator.alloc(bool, left_rows + right_rows);
                defer self.allocator.free(out);
                for (0..left_rows) |idx| out[idx] = (try numericIntAt(left, @intCast(idx))) != 0;
                for (0..right_rows) |idx| out[left_rows + idx] = (try numericIntAt(right, @intCast(idx))) != 0;
                break :blk try self.createManagedHostBitArray(out);
            },
            .float => blk: {
                const out = try self.allocator.alloc(f64, left_rows + right_rows);
                defer self.allocator.free(out);
                for (0..left_rows) |idx| out[idx] = try numericFloatAt(left, @intCast(idx));
                for (0..right_rows) |idx| out[left_rows + idx] = try numericFloatAt(right, @intCast(idx));
                break :blk try self.createManagedHostFloatArray(out);
            },
            .string => try self.concatTableStringColumns(left, right, left_rows, right_rows),
            .int,
            .date,
            .time,
            .time_ns,
            .time_tz,
            .timestamp,
            .timestamp_s,
            .timestamp_ms,
            .timestamp_ns,
            .timestamp_tz,
            => blk: {
                const out = try self.allocator.alloc(i64, left_rows + right_rows);
                defer self.allocator.free(out);
                for (0..left_rows) |idx| out[idx] = try numericIntAt(left, @intCast(idx));
                for (0..right_rows) |idx| out[left_rows + idx] = try numericIntAt(right, @intCast(idx));
                break :blk try self.createManagedHostIntArray(out);
            },
        };
    }

    fn concatTableValues(self: *Session, left: *const HostKeyedStore, right: *const HostKeyedStore) KError!Value {
        if (left.layout != .table or right.layout != .table) return error.Type;
        const column_count = keyedStoreNameCount(left);
        if (column_count != keyedStoreNameCount(right)) return error.Type;

        const left_metadata = keyedStoreTableMetadata(left);
        const right_metadata = keyedStoreTableMetadata(right);
        for (0..column_count) |idx| {
            if (!std.mem.eql(u8, keyedStoreColumnNameBytes(left, idx), keyedStoreColumnNameBytes(right, idx))) return error.Type;
            if (left_metadata[idx].kind != right_metadata[idx].kind) return error.Type;
        }

        const columns = try self.allocator.alloc(HostTableColumn, column_count);
        var built_columns: usize = 0;
        errdefer {
            for (columns[0..built_columns]) |column| {
                self.releaseValue(column.name);
                self.releaseValue(column.data);
                if (column.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        for (0..column_count) |idx| {
            const name = try self.keyedStoreNameValue(left, idx);
            errdefer self.releaseValue(name);
            columns[idx] = .{
                .name = try self.retainEscapedValue(name),
                .data = try self.concatTableColumnData(
                    left_metadata[idx].kind,
                    tableColumnData(left, idx),
                    tableColumnData(right, idx),
                    left.row_count,
                    right.row_count,
                ),
                .validity = try self.concatTableValidity(left_metadata[idx].validity, right_metadata[idx].validity, left.row_count, right.row_count),
                .kind = left_metadata[idx].kind,
            };
            self.releaseValue(name);
            built_columns += 1;
        }

        return try self.createManagedHostTable(left.row_count + right.row_count, columns);
    }

    const KeyedMergeSource = struct {
        store: *const HostKeyedStore,
        source_idx: usize,
        key: []const u8,
    };

    fn concatKeyedDictValues(self: *Session, left: *const HostKeyedStore, right: *const HostKeyedStore) KError!Value {
        if (left.layout != .dict or right.layout != .dict) return error.Type;

        const left_count = keyedStoreNameCount(left);
        const right_count = keyedStoreNameCount(right);
        const merged = try self.allocator.alloc(KeyedMergeSource, left_count + right_count);
        defer self.allocator.free(merged);
        var merged_len: usize = 0;

        for (0..left_count) |idx| {
            const key = keyedStoreColumnNameBytes(left, idx);
            merged[merged_len] = .{
                .store = if (right.lookup.get(key) != null) right else left,
                .source_idx = right.lookup.get(key) orelse idx,
                .key = key,
            };
            merged_len += 1;
        }
        for (0..right_count) |idx| {
            const key = keyedStoreColumnNameBytes(right, idx);
            if (left.lookup.get(key) != null) continue;
            merged[merged_len] = .{
                .store = right,
                .source_idx = idx,
                .key = key,
            };
            merged_len += 1;
        }

        const name_bytes = try self.allocator.alloc([]const u8, merged_len);
        defer self.allocator.free(name_bytes);
        const merged_values = try self.allocator.alloc(Value, merged_len);
        defer self.allocator.free(merged_values);
        var initialized_values: usize = 0;
        defer {
            for (merged_values[0..initialized_values]) |value| self.releaseValue(value);
        }

        for (merged[0..merged_len], 0..) |source, out_idx| {
            name_bytes[out_idx] = source.key;
            merged_values[out_idx] = try self.keyedStoreValueAt(source.store, source.source_idx);
            initialized_values += 1;
        }

        const names = try self.createManagedHostStringListFromSlices(name_bytes);
        errdefer self.releaseValue(names);
        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);
        const values = if (keyedStoreUsesDenseValueFastPath(left) and keyedStoreUsesDenseValueFastPath(right))
            try self.makeArrayFromValues(merged_values)
        else
            try self.createManagedHostBoxedArray(merged_values);
        errdefer self.releaseValue(values);

        const metadata = blk: {
            const left_metadata = left.column_metadata;
            const right_metadata = right.column_metadata;
            for (merged[0..merged_len]) |source| {
                const source_metadata = source.store.column_metadata orelse break :blk null;
                if (source.source_idx >= source_metadata.len) return error.Internal;
            }

            const out = try self.allocator.alloc(HostKeyedColumnMetadata, merged_len);
            var initialized: usize = 0;
            errdefer {
                for (out[0..initialized]) |entry| {
                    if (entry.validity) |mask| self.releaseValue(mask);
                }
                self.allocator.free(out);
            }

            _ = left_metadata;
            _ = right_metadata;
            for (merged[0..merged_len], 0..) |source, out_idx| {
                const source_metadata = source.store.column_metadata orelse return error.Internal;
                const source_entry = source_metadata[source.source_idx];
                out[out_idx] = .{
                    .kind = source_entry.kind,
                    .validity = if (source_entry.validity) |mask| try self.retainEscapedValue(mask) else null,
                };
                initialized += 1;
            }
            break :blk out;
        };
        errdefer if (metadata) |items| {
            for (items) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(items);
        };

        const owned_path = try self.allocator.dupe(u8, "");
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(
            owned_path,
            true,
            names,
            values,
            metadata,
            .dict,
            0,
            lookup,
        );
    }

    fn ensureLoadedSafetensors(self: *Session, path: []const u8) KError!*LoadedSafetensorsStore {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        if (!std.mem.endsWith(u8, path, ".safetensors")) return error.Unsupported;
        const resolved_path = try self.resolveLoadPath(path);
        errdefer self.allocator.free(resolved_path);
        if (self.loaded_safetensors.getPtr(resolved_path)) |store| {
            self.allocator.free(resolved_path);
            return store;
        }

        var parsed = safetensors.parseFileHeader(self.allocator, resolved_path) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => return mapSafetensorsError(err),
        };
        defer parsed.deinit(self.allocator);

        const ctx = try self.backendContext();
        const name_bytes = try self.allocator.alloc([]const u8, parsed.entries.len);
        defer self.allocator.free(name_bytes);
        const tensors = try self.allocator.alloc(Value, parsed.entries.len);
        defer self.allocator.free(tensors);

        var initialized_tensor_count: usize = 0;
        errdefer {
            for (tensors[0..initialized_tensor_count]) |value| self.releaseValue(value);
        }

        for (parsed.entries, 0..) |entry, idx| {
            name_bytes[idx] = entry.name;
            const array = mlx.loadSafetensorTensor(
                self.allocator,
                ctx.*,
                resolved_path,
                entry.shape,
                safetensorMlxDtype(entry.dtype),
                entry.absolute_offset,
            ) catch |err| switch (err) {
                error.OutOfMemory => return error.OutOfMemory,
                else => return mapMlxError(err),
            };
            tensors[idx] = try self.wrapManagedBackendArray(array);
            initialized_tensor_count += 1;
        }

        const names = try self.createManagedHostStringListFromSlices(name_bytes);
        errdefer self.releaseValue(names);
        const values_box = try self.createManagedHostBoxedArray(tensors);
        errdefer self.releaseValue(values_box);
        for (tensors[0..initialized_tensor_count]) |value| self.releaseValue(value);
        initialized_tensor_count = 0;
        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const store_value = try self.createManagedKeyedStore(resolved_path, false, names, values_box, null, .dict, 0, lookup);
        errdefer self.releaseValue(store_value);

        try self.loaded_safetensors.put(resolved_path, .{
            .store = store_value,
        });
        return self.loaded_safetensors.getPtr(resolved_path).?;
    }

    fn ensureLoadedRelation(self: *Session, path: []const u8) KError!*LoadedRelationStore {
        if (comptime !runtime_has_duckdb) return error.Unsupported;
        const resolved_path = try self.resolveLoadPath(path);
        errdefer self.allocator.free(resolved_path);
        const source_kind = duckdb_runtime.SourceKind.detect(resolved_path) orelse return error.Unsupported;
        if (self.loaded_relations.getPtr(resolved_path)) |store| {
            self.allocator.free(resolved_path);
            return store;
        }

        const relation = try self.createManagedFileRelation(source_kind, resolved_path);
        errdefer self.releaseValue(relation);

        try self.loaded_relations.put(resolved_path, .{
            .relation = relation,
        });
        return self.loaded_relations.getPtr(resolved_path).?;
    }

    fn resolveLoadPath(self: *Session, path: []const u8) KError![]u8 {
        if (comptime zig_builtin.target.os.tag == .freestanding or
            zig_builtin.target.os.tag == .watchos or
            zig_builtin.target.cpu.arch == .wasm32)
        {
            return self.allocator.dupe(u8, path);
        }
        return std.fs.realpathAlloc(self.allocator, path) catch |err| switch (err) {
            error.OutOfMemory => error.OutOfMemory,
            else => error.Type,
        };
    }

    fn duckdbConnection(self: *Session) KError!*duckdb_runtime.Connection {
        if (comptime !runtime_has_duckdb) return error.Unsupported;
        if (self.duckdb_conn == null) {
            var diagnostic: ?[]u8 = null;
            self.duckdb_conn = duckdb_runtime.Connection.initWithDiagnostic(self.allocator, null, &diagnostic) catch |err| {
                self.setOwnedDuckDbErrorText(diagnostic);
                return mapDuckDbError(err);
            };
        }
        return &self.duckdb_conn.?;
    }

    fn ensureDuckDbKiwiTableScan(self: *Session, conn: *duckdb_runtime.Connection) KError!void {
        if (comptime !runtime_has_duckdb) return error.Unsupported;
        if (self.duckdb_kiwi_scan_registered) return;
        try DuckDbKiwiTableScan.ensureRegistered(self, conn);
        self.duckdb_kiwi_scan_registered = true;
    }

    fn prepareDuckDbStatement(self: *Session, conn: *duckdb_runtime.Connection, sql: []const u8) KError!duckdb_runtime.PreparedStatement {
        var diagnostic: ?[]u8 = null;
        const prepared = duckdb_runtime.PreparedStatement.initWithDiagnostic(conn, sql, &diagnostic) catch |err| {
            self.setOwnedDuckDbErrorText(diagnostic);
            return mapDuckDbError(err);
        };
        return prepared;
    }

    fn executeDuckDbPrepared(self: *Session, prepared: *duckdb_runtime.PreparedStatement) KError!void {
        var diagnostic: ?[]u8 = null;
        prepared.executeWithDiagnostic(&diagnostic) catch |err| {
            self.setOwnedDuckDbErrorText(diagnostic);
            return mapDuckDbError(err);
        };
    }

    fn executeDuckDbPreparedResult(self: *Session, prepared: *duckdb_runtime.PreparedStatement) KError!duckdb_runtime.QueryResult {
        var diagnostic: ?[]u8 = null;
        const result = prepared.executeResultWithDiagnostic(&diagnostic) catch |err| {
            self.setOwnedDuckDbErrorText(diagnostic);
            return mapDuckDbError(err);
        };
        return result;
    }

    fn queryDuckDbPreparedSingleCount(self: *Session, prepared: *duckdb_runtime.PreparedStatement) KError!usize {
        var diagnostic: ?[]u8 = null;
        const count = prepared.querySingleCountWithDiagnostic(&diagnostic) catch |err| {
            self.setOwnedDuckDbErrorText(diagnostic);
            return mapDuckDbError(err);
        };
        return count;
    }

    fn countDuckDbFileRows(self: *Session, conn: *duckdb_runtime.Connection, source_kind: duckdb_runtime.SourceKind, path: []const u8) KError!usize {
        var diagnostic: ?[]u8 = null;
        const count = conn.countFileRowsWithDiagnostic(source_kind, path, &diagnostic) catch |err| {
            self.setOwnedDuckDbErrorText(diagnostic);
            return mapDuckDbError(err);
        };
        return count;
    }

    fn closeDuckDbAppender(self: *Session, appender: *duckdb_runtime.Appender) KError!void {
        var diagnostic: ?[]u8 = null;
        appender.closeWithDiagnostic(&diagnostic) catch |err| {
            self.setOwnedDuckDbErrorText(diagnostic);
            return mapDuckDbError(err);
        };
    }

    fn executeDuckDbSql(self: *Session, conn: *duckdb_runtime.Connection, sql: []const u8) KError!void {
        var prepared = try self.prepareDuckDbStatement(conn, sql);
        defer prepared.deinit();
        try self.executeDuckDbPrepared(&prepared);
    }

    fn trimSqlText(text: []const u8) []const u8 {
        var start: usize = 0;
        var end = text.len;
        while (start < end and std.ascii.isWhitespace(text[start])) : (start += 1) {}
        while (end > start and std.ascii.isWhitespace(text[end - 1])) : (end -= 1) {}
        while (end > start and text[end - 1] == ';') {
            end -= 1;
            while (end > start and std.ascii.isWhitespace(text[end - 1])) : (end -= 1) {}
        }
        return text[start..end];
    }

    fn sqlQueryBytes(value: Value) ?[]const u8 {
        return stringBytes(value);
    }

    fn registrationNameBytes(value: Value) ?[]const u8 {
        return symbolBytes(value) orelse stringBytes(value);
    }

    fn normalizedSqlParameterName(raw: []const u8) ?[]const u8 {
        if (raw.len == 0) return null;
        const trimmed = switch (raw[0]) {
            '$', ':', '@' => raw[1..],
            else => raw,
        };
        if (trimmed.len == 0) return null;
        if (std.ascii.isDigit(trimmed[0])) return null;
        return trimmed;
    }

    fn loadGlobalNamedValue(self: *Session, name: []const u8) KError!Value {
        const slot = self.global_slots.get(name) orelse return error.Name;
        return try self.loadGlobalSlot(slot);
    }

    fn retainSqlParameterValue(self: *Session, value: Value) KError!Value {
        return switch (value.tag()) {
            .int, .bool, .float => try self.retainEscapedValue(value),
            .array => if (stringBytes(value) != null or symbolBytes(value) != null)
                try self.retainEscapedValue(value)
            else
                error.Type,
            else => error.Type,
        };
    }

    fn freeCapturedRelationParams(self: *Session, params: []HostRelationParam) void {
        for (params) |param| {
            self.allocator.free(param.name);
            self.releaseValue(param.value);
        }
        self.allocator.free(params);
    }

    fn findRelationParamValue(params: []const HostRelationParam, name: []const u8) ?Value {
        for (params) |param| {
            if (std.mem.eql(u8, param.name, name)) return param.value;
        }
        return null;
    }

    fn capturePreparedSqlParams(self: *Session, prepared: *duckdb_runtime.PreparedStatement) KError![]HostRelationParam {
        var params = std.ArrayList(HostRelationParam).empty;
        errdefer {
            for (params.items) |param| {
                self.allocator.free(param.name);
                self.releaseValue(param.value);
            }
            params.deinit(self.allocator);
        }

        for (0..prepared.paramCount()) |idx| {
            const raw_name = prepared.parameterName(self.allocator, idx) catch |err| return mapDuckDbError(err);
            defer self.allocator.free(raw_name);
            const name = normalizedSqlParameterName(raw_name) orelse return error.Unsupported;
            if (findRelationParamValue(params.items, name) != null) continue;

            {
                const global_value = try self.loadGlobalNamedValue(name);
                const retained = try self.retainSqlParameterValue(global_value);
                errdefer self.releaseValue(retained);

                const owned_name = try self.allocator.dupe(u8, name);
                errdefer self.allocator.free(owned_name);

                try params.append(self.allocator, .{
                    .name = owned_name,
                    .value = retained,
                });
            }
        }

        return try params.toOwnedSlice(self.allocator);
    }

    fn bindPreparedSqlScalar(prepared: *duckdb_runtime.PreparedStatement, index: usize, value: Value) KError!void {
        switch (value.tag()) {
            .bool => prepared.bindBoolean(index, value.asBool()) catch |err| return mapDuckDbError(err),
            .int => prepared.bindInt64(index, value.asInt()) catch |err| return mapDuckDbError(err),
            .float => prepared.bindDouble(index, value.asFloat()) catch |err| return mapDuckDbError(err),
            .array => if (stringBytes(value)) |text| {
                prepared.bindVarchar(index, text) catch |err| return mapDuckDbError(err);
            } else if (symbolBytes(value)) |text| {
                prepared.bindVarchar(index, text) catch |err| return mapDuckDbError(err);
            } else {
                return error.Type;
            },
            else => return error.Type,
        }
    }

    fn bindPreparedRelationParams(self: *Session, prepared: *duckdb_runtime.PreparedStatement, params: []const HostRelationParam) KError!void {
        for (0..prepared.paramCount()) |idx| {
            const raw_name = prepared.parameterName(self.allocator, idx) catch |err| return mapDuckDbError(err);
            defer self.allocator.free(raw_name);
            const name = normalizedSqlParameterName(raw_name) orelse return error.Unsupported;
            const value = findRelationParamValue(params, name) orelse return error.Name;
            try bindPreparedSqlScalar(prepared, idx, value);
        }
    }

    fn relationRegistrationSql(self: *Session, name: []const u8, relation: *const HostRelation) KError![]u8 {
        const ident = duckdb_runtime.sqlIdentifier(self.allocator, name) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(ident);

        return switch (relation.origin) {
            .file => |file| blk: {
                const quoted_path = duckdb_runtime.sqlStringLiteral(self.allocator, file.path) catch |err| return mapDuckDbError(err);
                defer self.allocator.free(quoted_path);
                const source_sql = switch (file.source_kind) {
                    .csv => try std.fmt.allocPrint(self.allocator, "read_csv_auto({s})", .{quoted_path}),
                    .parquet => try std.fmt.allocPrint(self.allocator, "read_parquet({s})", .{quoted_path}),
                };
                defer self.allocator.free(source_sql);
                break :blk try std.fmt.allocPrint(
                    self.allocator,
                    "create or replace temp view {s} as select * from {s}",
                    .{ ident, source_sql },
                );
            },
            .sql => |sql_info| try std.fmt.allocPrint(
                self.allocator,
                "create or replace temp view {s} as {s}",
                .{ ident, sql_info.text },
            ),
        };
    }

    fn dropRegisteredObjectIfExists(self: *Session, conn: *duckdb_runtime.Connection, name: []const u8) KError!void {
        const ident = duckdb_runtime.sqlIdentifier(self.allocator, name) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(ident);

        const drop_view = try std.fmt.allocPrint(self.allocator, "drop view if exists {s}", .{ident});
        defer self.allocator.free(drop_view);
        try self.executeDuckDbSql(conn, drop_view);

        const drop_table = try std.fmt.allocPrint(self.allocator, "drop table if exists {s}", .{ident});
        defer self.allocator.free(drop_table);
        try self.executeDuckDbSql(conn, drop_table);
    }

    fn registerRelationNamed(self: *Session, conn: *duckdb_runtime.Connection, name: []const u8, relation_value: Value) KError!Value {
        const relation = relation_value.asHostRelation();
        switch (relation.origin) {
            .file => {},
            .sql => |sql_info| if (sql_info.params.len != 0) return error.Unsupported,
        }
        try self.dropRegisteredObjectIfExists(conn, name);
        const registration_sql = try self.relationRegistrationSql(name, relation);
        defer self.allocator.free(registration_sql);

        try self.executeDuckDbSql(conn, registration_sql);
        self.forgetRegisteredDuckDbTable(name);
        return self.shareValue(relation_value);
    }

    fn tableRegistrationTypeSql(kind: HostTableColumnKind) []const u8 {
        return switch (kind) {
            .boolean => "BOOLEAN",
            .int => "BIGINT",
            .float => "DOUBLE",
            .string => "VARCHAR",
            .date => "DATE",
            .time => "TIME",
            .time_ns => "TIME_NS",
            .time_tz => "TIMETZ",
            .timestamp => "TIMESTAMP",
            .timestamp_s => "TIMESTAMP_S",
            .timestamp_ms => "TIMESTAMP_MS",
            .timestamp_ns => "TIMESTAMP_NS",
            .timestamp_tz => "TIMESTAMPTZ",
        };
    }

    fn tableRegistrationSql(self: *Session, name: []const u8, table: *const HostKeyedStore) KError![]u8 {
        std.debug.assert(table.layout == .table);
        const ident = duckdb_runtime.sqlIdentifier(self.allocator, name) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(ident);

        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);

        try out.writer(self.allocator).print("create temp table {s} (", .{ident});
        const metadata = keyedStoreTableMetadata(table);
        for (0..keyedStoreNameCount(table)) |idx| {
            if (idx != 0) try out.appendSlice(self.allocator, ", ");
            const column_ident = duckdb_runtime.sqlIdentifier(self.allocator, keyedStoreColumnNameBytes(table, idx)) catch |err| return mapDuckDbError(err);
            defer self.allocator.free(column_ident);
            try out.writer(self.allocator).print("{s} {s}", .{ column_ident, tableRegistrationTypeSql(metadata[idx].kind) });
        }
        try out.append(self.allocator, ')');
        return try out.toOwnedSlice(self.allocator);
    }

    fn appendTableCellToDuckDbAppender(
        self: *Session,
        appender: *duckdb_runtime.Appender,
        table: *const HostKeyedStore,
        column_idx: usize,
        row: usize,
    ) KError!void {
        std.debug.assert(table.layout == .table);
        if (!keyedStoreTableCellIsValid(table, column_idx, row)) {
            appender.appendNull() catch |err| return mapDuckDbError(err);
            return;
        }

        const kind = keyedStoreTableMetadata(table)[column_idx].kind;
        const data = tableColumnData(table, column_idx);
        switch (kind) {
            .boolean => appender.appendBool((try numericIntAt(data, @intCast(row))) != 0) catch |err| return mapDuckDbError(err),
            .int => appender.appendInt64(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .float => appender.appendDouble(try numericFloatAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .string => {
                const value = try self.hostStringListItemValue(data.asHostStringList(), row);
                defer self.releaseValue(value);
                const text = symbolBytes(value) orelse stringBytes(value) orelse return error.Internal;
                appender.appendVarchar(text) catch |err| return mapDuckDbError(err);
            },
            .date => {
                const days = std.math.cast(i32, try numericIntAt(data, @intCast(row))) orelse return error.Unsupported;
                appender.appendDate(days) catch |err| return mapDuckDbError(err);
            },
            .time => appender.appendTime(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .time_ns => appender.appendTimeNs(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .time_tz => appender.appendTimeTz(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .timestamp => appender.appendTimestamp(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .timestamp_s => appender.appendTimestampS(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .timestamp_ms => appender.appendTimestampMs(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .timestamp_ns => appender.appendTimestampNs(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
            .timestamp_tz => appender.appendTimestampTz(try numericIntAt(data, @intCast(row))) catch |err| return mapDuckDbError(err),
        }
    }

    fn registerTableNamedEager(self: *Session, conn: *duckdb_runtime.Connection, name: []const u8, table_value: Value) KError!Value {
        const table = table_value.asHostKeyedStore();
        if (table.layout != .table) return error.Type;
        try self.dropRegisteredObjectIfExists(conn, name);

        const registration_sql = try self.tableRegistrationSql(name, table);
        defer self.allocator.free(registration_sql);
        try self.executeDuckDbSql(conn, registration_sql);

        var appender = duckdb_runtime.Appender.init(conn, name) catch |err| return mapDuckDbError(err);
        defer appender.deinit();

        for (0..table.row_count) |row| {
            for (0..keyedStoreNameCount(table)) |column_idx| try self.appendTableCellToDuckDbAppender(&appender, table, column_idx, row);
            appender.endRow() catch |err| return mapDuckDbError(err);
        }

        try self.closeDuckDbAppender(&appender);
        return self.shareValue(table_value);
    }

    fn forgetRegisteredDuckDbTable(self: *Session, name: []const u8) void {
        const removed = self.registered_duckdb_tables.fetchRemove(name) orelse return;
        self.releaseValue(removed.value.table);
        self.allocator.free(removed.key);
    }

    fn rememberRegisteredDuckDbTable(self: *Session, name: []const u8, table_value: Value) KError!void {
        const retained = try self.retainEscapedValue(table_value);
        errdefer self.releaseValue(retained);

        if (self.registered_duckdb_tables.getPtr(name)) |entry| {
            self.releaseValue(entry.table);
            entry.table = retained;
            return;
        }

        const owned_name = try self.allocator.dupe(u8, name);
        errdefer self.allocator.free(owned_name);

        try self.registered_duckdb_tables.put(owned_name, .{
            .table = retained,
        });
    }

    fn tableScanRegistrationSql(self: *Session, name: []const u8) KError![]u8 {
        const ident = duckdb_runtime.sqlIdentifier(self.allocator, name) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(ident);

        const quoted_name = duckdb_runtime.sqlStringLiteral(self.allocator, name) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(quoted_name);

        return try std.fmt.allocPrint(
            self.allocator,
            "create or replace temp view {s} as select * from kiwi_scan({s})",
            .{ ident, quoted_name },
        );
    }

    fn registerTableNamedLazy(self: *Session, conn: *duckdb_runtime.Connection, name: []const u8, table_value: Value) KError!Value {
        try self.ensureDuckDbKiwiTableScan(conn);
        try self.rememberRegisteredDuckDbTable(name, table_value);
        try self.dropRegisteredObjectIfExists(conn, name);

        const registration_sql = try self.tableScanRegistrationSql(name);
        defer self.allocator.free(registration_sql);
        try self.executeDuckDbSql(conn, registration_sql);
        return self.shareValue(table_value);
    }

    fn registerValue(self: *Session, name_value: Value, registered_value: Value) KError!Value {
        const name = registrationNameBytes(name_value) orelse return error.Type;
        if (name.len == 0) return error.Type;
        if (registered_value.tag() != .array) return error.Type;

        const conn = try self.duckdbConnection();
        return switch (registered_value.arrayKind()) {
            .host_relation => try self.registerRelationNamed(conn, name, registered_value),
            .host_keyed_store => if (registered_value.asHostKeyedStore().layout == .table)
                try self.registerTableNamedLazy(conn, name, registered_value)
            else
                error.Type,
            else => error.Type,
        };
    }

    fn saveValue(self: *Session, path_value: Value, saved_value: Value) KError!Value {
        if (comptime !runtime_has_mlx) return error.Unsupported;

        const path = loadPathBytes(path_value) orelse return error.Type;
        if (!std.ascii.eqlIgnoreCase(std.fs.path.extension(path), ".safetensors")) return error.Unsupported;

        var names = std.ArrayList([]const u8).empty;
        defer names.deinit(self.allocator);
        var arrays = std.ArrayList(mlx.Array).empty;
        defer {
            for (arrays.items) |*array| array.deinit();
            arrays.deinit(self.allocator);
        }

        if (saved_value.tag() == .array and saved_value.arrayKind() == .host_keyed_store) {
            const store = saved_value.asHostKeyedStore();
            if (store.layout != .dict) return error.Type;

            const count = keyedStoreNameCount(store);
            try names.ensureTotalCapacity(self.allocator, count);
            try arrays.ensureTotalCapacity(self.allocator, count);
            for (0..count) |idx| {
                const name = (try self.keyedStoreNamesValueBytesAt(store.names, idx)) orelse return error.Type;
                const item = try self.keyedStoreValueAt(store, idx);
                defer self.releaseValue(item);
                _ = valueNumericMode(item) orelse return error.Type;
                names.appendAssumeCapacity(name);
                arrays.appendAssumeCapacity(try self.materializeBackendArray(item));
            }
        } else {
            _ = valueNumericMode(saved_value) orelse return error.Type;
            try names.append(self.allocator, "value");
            try arrays.append(self.allocator, try self.materializeBackendArray(saved_value));
        }

        mlx.saveSafetensors(self.allocator, path, names.items, arrays.items) catch |err| return mapMlxError(err);
        return self.shareValue(saved_value);
    }

    fn sqlValue(self: *Session, value: Value) KError!Value {
        const sql_text = sqlQueryBytes(value) orelse return error.Type;
        const trimmed = trimSqlText(sql_text);
        if (trimmed.len == 0) return error.Parse;

        const conn = try self.duckdbConnection();
        var prepared = try self.prepareDuckDbStatement(conn, trimmed);
        defer prepared.deinit();

        const params = try self.capturePreparedSqlParams(&prepared);
        errdefer self.freeCapturedRelationParams(params);

        try self.bindPreparedRelationParams(&prepared, params);
        return try self.createManagedSqlRelation(trimmed, params);
    }

    fn relationRowCount(self: *Session, relation: *HostRelation) KError!usize {
        if (relation.cached_row_count_known) return relation.cached_row_count;
        const conn = try self.duckdbConnection();

        relation.cached_row_count = switch (relation.origin) {
            .file => |file| try self.countDuckDbFileRows(conn, file.source_kind, file.path),
            .sql => |sql_info| blk: {
                const wrapped = try std.fmt.allocPrint(
                    self.allocator,
                    "select count(*) as n from ({s}) as kiwi_relation",
                    .{sql_info.text},
                );
                defer self.allocator.free(wrapped);

                var prepared = try self.prepareDuckDbStatement(conn, wrapped);
                defer prepared.deinit();
                try self.bindPreparedRelationParams(&prepared, sql_info.params);
                break :blk try self.queryDuckDbPreparedSingleCount(&prepared);
            },
        };
        relation.cached_row_count_known = true;
        return relation.cached_row_count;
    }

    fn tableColumnKindFromDuckDbType(type_id: duckdb_runtime.TypeId) KError!HostTableColumnKind {
        if (comptime !build_options.runtime_has_duckdb) return error.Unsupported;
        return switch (type_id) {
            .boolean => .boolean,
            .tinyint, .smallint, .integer, .bigint, .utinyint, .usmallint, .uinteger, .ubigint => .int,
            .float, .double => .float,
            .varchar => .string,
            .date => .date,
            .time => .time,
            .time_ns => .time_ns,
            .time_tz => .time_tz,
            .timestamp => .timestamp,
            .timestamp_s => .timestamp_s,
            .timestamp_ms => .timestamp_ms,
            .timestamp_ns => .timestamp_ns,
            .timestamp_tz => .timestamp_tz,
            else => error.Unsupported,
        };
    }

    fn deinitTableColumnBuilder(self: *Session, builder: *TableColumnBuilder) void {
        switch (builder.kind) {
            .boolean => builder.bool_values.deinit(self.allocator),
            .int, .date, .time, .time_ns, .time_tz, .timestamp, .timestamp_s, .timestamp_ms, .timestamp_ns, .timestamp_tz => builder.int_values.deinit(self.allocator),
            .float => {
                builder.float32_values.deinit(self.allocator);
                builder.float_values.deinit(self.allocator);
            },
            .string => {
                for (builder.string_values.items) |item| self.allocator.free(item);
                builder.string_values.deinit(self.allocator);
            },
        }
        builder.validity.deinit(self.allocator);
    }

    fn tableColumnBuilderEnsureValueCapacity(self: *Session, builder: *TableColumnBuilder, additional: usize) KError!void {
        switch (builder.kind) {
            .boolean => try builder.bool_values.ensureUnusedCapacity(self.allocator, additional),
            .int, .date, .time, .time_ns, .time_tz, .timestamp, .timestamp_s, .timestamp_ms, .timestamp_ns, .timestamp_tz => try builder.int_values.ensureUnusedCapacity(self.allocator, additional),
            .float => switch (builder.source_type) {
                .float => try builder.float32_values.ensureUnusedCapacity(self.allocator, additional),
                .double => try builder.float_values.ensureUnusedCapacity(self.allocator, additional),
                else => return error.Unsupported,
            },
            .string => try builder.string_values.ensureUnusedCapacity(self.allocator, additional),
        }
    }

    fn tableColumnBuilderEnsureValidityLen(self: *Session, builder: *TableColumnBuilder, target_len: usize) KError!void {
        if (!builder.saw_null) builder.saw_null = true;
        if (builder.validity.items.len >= target_len) return;
        try builder.validity.ensureUnusedCapacity(self.allocator, target_len - builder.validity.items.len);
        while (builder.validity.items.len < target_len) builder.validity.appendAssumeCapacity(true);
    }

    fn tableColumnBuilderAppendValidity(
        self: *Session,
        builder: *TableColumnBuilder,
        row_offset: usize,
        valid: bool,
    ) KError!void {
        if (valid and !builder.saw_null) return;
        const absolute_row = builder.row_count + row_offset;
        try self.tableColumnBuilderEnsureValidityLen(builder, absolute_row);
        try builder.validity.append(self.allocator, valid);
    }

    fn duckDbValidityBit(validity: ?[*]const u64, row: usize) bool {
        const words = validity orelse return true;
        const entry_idx = row / 64;
        const idx_in_entry = row % 64;
        return (words[entry_idx] & (@as(u64, 1) << @intCast(idx_in_entry))) != 0;
    }

    fn analyzeIntSliceTyped(comptime T: type, items: []const T) HostIntAnalysis {
        if (items.len == 0) {
            return .{
                .range = .{ .min = 0, .max = 0 },
                .kind = .int8,
                .flags = host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc,
            };
        }

        var min_value: i64 = @intCast(items[0]);
        var max_value: i64 = @intCast(items[0]);
        var asc = true;
        var dsc = true;
        var prev: i64 = @intCast(items[0]);
        for (items[1..]) |raw_item| {
            const item: i64 = @intCast(raw_item);
            min_value = @min(min_value, item);
            max_value = @max(max_value, item);
            if (prev > item) asc = false;
            if (prev < item) dsc = false;
            prev = item;
        }

        return .{
            .range = .{ .min = min_value, .max = max_value },
            .kind = hostIntStorageKindForRange(min_value, max_value),
            .flags = host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
        };
    }

    fn directTableColumnStorageArray(storage: *const DirectTableColumnStorage) *HostDenseArray {
        return switch (storage.*) {
            .boolean => |out| out.array,
            .int8 => |out| out.array,
            .int16 => |out| out.array,
            .int32 => |out| out.array,
            .int64 => |out| out.array,
            .float32 => |out| out.array,
            .float64 => |out| out.array,
        };
    }

    fn recycleDirectTableColumnStorage(self: *Session, storage: DirectTableColumnStorage) void {
        self.recycleManagedHostArray(directTableColumnStorageArray(&storage));
    }

    fn initDirectTableColumnBuilder(
        self: *Session,
        name: Value,
        source_type: duckdb_runtime.TypeId,
        kind: HostTableColumnKind,
        total_rows: usize,
    ) KError!?DirectTableColumnBuilder {
        const storage: DirectTableColumnStorage = switch (source_type) {
            .boolean => .{ .boolean = try self.allocHostBitArray(.managed, total_rows) },
            .tinyint => .{ .int8 = try self.allocHostArrayTyped(i8, .int8, .managed, total_rows) },
            .smallint => .{ .int16 = try self.allocHostArrayTyped(i16, .int16, .managed, total_rows) },
            .integer => .{ .int32 = try self.allocHostArrayTyped(i32, .int32, .managed, total_rows) },
            .bigint => .{ .int64 = try self.allocHostArrayTyped(i64, .int64, .managed, total_rows) },
            .utinyint => .{ .int16 = try self.allocHostArrayTyped(i16, .int16, .managed, total_rows) },
            .usmallint => .{ .int32 = try self.allocHostArrayTyped(i32, .int32, .managed, total_rows) },
            .uinteger, .ubigint => .{ .int64 = try self.allocHostArrayTyped(i64, .int64, .managed, total_rows) },
            .float => .{ .float32 = try self.allocManagedHostFloat32Result(total_rows) },
            .double => .{ .float64 = try self.allocManagedHostFloatResult(total_rows) },
            .date => .{ .int32 = try self.allocHostArrayTyped(i32, .int32, .managed, total_rows) },
            .time,
            .time_ns,
            .time_tz,
            .timestamp,
            .timestamp_s,
            .timestamp_ms,
            .timestamp_ns,
            .timestamp_tz,
            => .{ .int64 = try self.allocHostArrayTyped(i64, .int64, .managed, total_rows) },
            else => return null,
        };
        var wrapped = false;
        errdefer if (!wrapped) self.recycleDirectTableColumnStorage(storage);
        const data = try wrapOwnedHostArrayValue(self, directTableColumnStorageArray(&storage));
        wrapped = true;
        return .{
            .name = name,
            .source_type = source_type,
            .kind = kind,
            .storage = storage,
            .data = data,
            .total_rows = total_rows,
        };
    }

    fn deinitDirectTableColumnBuilder(self: *Session, builder: *DirectTableColumnBuilder) void {
        if (builder.validity) |mask| self.releaseValue(mask);
        if (builder.data) |data| self.releaseValue(data);
        builder.validity = null;
        builder.data = null;
    }

    fn ensureDirectTableColumnValidity(self: *Session, builder: *DirectTableColumnBuilder) KError!void {
        if (builder.validity != null) return;
        const storage = try self.allocHostBitArray(.managed, builder.total_rows);
        var wrapped = false;
        errdefer if (!wrapped) self.recycleManagedHostArray(storage.array);
        bitFill(storage.words, builder.total_rows, true);
        const value = try wrapOwnedHostArrayValue(self, storage.array);
        wrapped = true;
        builder.validity_storage = storage;
        builder.validity = value;
    }

    fn markDirectTableColumnInvalid(self: *Session, builder: *DirectTableColumnBuilder, absolute_row: usize) KError!void {
        try self.ensureDirectTableColumnValidity(builder);
        bitSet(builder.validity_storage.?.words, absolute_row, false);
    }

    fn directWriteBitRun(words: []u64, start: usize, bits: u64, len: usize) void {
        if (len == 0) return;
        const word_idx = start / host_bit_word_bits;
        const bit_offset = start % host_bit_word_bits;
        std.debug.assert(bit_offset + len <= host_bit_word_bits);
        const mask = bitLowMask(len) << @intCast(bit_offset);
        const shifted = (bits & bitLowMask(len)) << @intCast(bit_offset);
        words[word_idx] = (words[word_idx] & ~mask) | (shifted & mask);
    }

    fn readU64Unaligned(ptr: [*]const u8) u64 {
        const typed: *align(1) const u64 = @ptrCast(ptr);
        return typed.*;
    }

    fn packBool8Bytes(src: [*]const u8) u8 {
        const bits = readU64Unaligned(src) & 0x0101_0101_0101_0101;
        return @truncate((bits *% 0x0102_0408_1020_4080) >> 56);
    }

    fn packBool64Bytes(src: [*]const u8) u64 {
        var bits: u64 = 0;
        inline for (0..8) |idx| {
            bits |= @as(u64, packBool8Bytes(src + idx * 8)) << @intCast(idx * 8);
        }
        return bits;
    }

    fn fillDirectBooleanColumn(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        dst: []u64,
        src: [*]const bool,
        validity: ?[*]const u64,
        start: usize,
        rows: usize,
    ) KError!void {
        var source_row: usize = 0;
        var absolute_row = start;
        var remaining = rows;
        const src_bytes: [*]const u8 = @ptrCast(src);

        while (remaining >= host_bit_word_bits and absolute_row % host_bit_word_bits == 0 and source_row % host_bit_word_bits == 0) {
            var packed_bits = packBool64Bytes(src_bytes + source_row);
            if (validity) |validity_words| {
                const valid_bits = validity_words[source_row / host_bit_word_bits];
                if (valid_bits != std.math.maxInt(u64)) {
                    try self.ensureDirectTableColumnValidity(builder);
                    builder.validity_storage.?.words[absolute_row / host_bit_word_bits] = valid_bits;
                    packed_bits &= valid_bits;
                }
            }
            dst[absolute_row / host_bit_word_bits] = packed_bits;
            source_row += host_bit_word_bits;
            absolute_row += host_bit_word_bits;
            remaining -= host_bit_word_bits;
        }

        while (remaining != 0) {
            const dst_offset = absolute_row % host_bit_word_bits;
            const validity_offset = source_row % host_bit_word_bits;
            var take = @min(remaining, host_bit_word_bits - dst_offset);
            if (validity != null) take = @min(take, host_bit_word_bits - validity_offset);

            var packed_bits: u64 = 0;
            for (0..take) |idx| {
                packed_bits |= @as(u64, @intFromBool(src[source_row + idx])) << @intCast(idx);
            }

            if (validity) |validity_words| {
                const valid_bits = (validity_words[source_row / host_bit_word_bits] >> @intCast(validity_offset)) & bitLowMask(take);
                if (valid_bits != bitLowMask(take)) {
                    try self.ensureDirectTableColumnValidity(builder);
                    directWriteBitRun(builder.validity_storage.?.words, absolute_row, valid_bits, take);
                    packed_bits &= valid_bits;
                }
            }

            directWriteBitRun(dst, absolute_row, packed_bits, take);
            source_row += take;
            absolute_row += take;
            remaining -= take;
        }
    }

    fn directDateValue(item: duckdb_runtime.c.duckdb_date) i32 {
        return item.days;
    }

    fn directTemporalValue(comptime T: type, item: T) i64 {
        return switch (T) {
            duckdb_runtime.c.duckdb_time => item.micros,
            duckdb_runtime.c.duckdb_time_ns => item.nanos,
            duckdb_runtime.c.duckdb_time_tz => @bitCast(item.bits),
            duckdb_runtime.c.duckdb_timestamp => item.micros,
            duckdb_runtime.c.duckdb_timestamp_s => item.seconds,
            duckdb_runtime.c.duckdb_timestamp_ms => item.millis,
            duckdb_runtime.c.duckdb_timestamp_ns => item.nanos,
            else => unreachable,
        };
    }

    fn fillDirectSignedColumn(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        comptime SrcT: type,
        comptime DstT: type,
        dst: []DstT,
        src: [*]const SrcT,
        validity: ?[*]const u64,
        start: usize,
        rows: usize,
    ) KError!void {
        if (validity == null and SrcT == DstT) {
            @memcpy(dst[start .. start + rows], src[0..rows]);
            return;
        }
        for (0..rows) |row| {
            const absolute_row = start + row;
            const valid = duckDbValidityBit(validity, row);
            const stored: DstT = if (valid) @intCast(src[row]) else 0;
            if (!valid) {
                try self.markDirectTableColumnInvalid(builder, absolute_row);
            }
            dst[absolute_row] = stored;
        }
    }

    fn fillDirectUnsignedColumn(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        comptime SrcT: type,
        comptime DstT: type,
        dst: []DstT,
        src: [*]const SrcT,
        validity: ?[*]const u64,
        start: usize,
        rows: usize,
    ) KError!void {
        for (0..rows) |row| {
            const absolute_row = start + row;
            const valid = duckDbValidityBit(validity, row);
            const stored: DstT = if (valid) std.math.cast(DstT, src[row]) orelse return error.Unsupported else 0;
            if (!valid) {
                try self.markDirectTableColumnInvalid(builder, absolute_row);
            }
            dst[absolute_row] = stored;
        }
    }

    fn fillDirectFloatColumn(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        comptime T: type,
        dst: []T,
        src: [*]const T,
        validity: ?[*]const u64,
        start: usize,
        rows: usize,
    ) KError!void {
        if (validity == null) {
            @memcpy(dst[start .. start + rows], src[0..rows]);
            return;
        }
        for (0..rows) |row| {
            const absolute_row = start + row;
            const valid = duckDbValidityBit(validity, row);
            const stored: T = if (valid) src[row] else 0;
            if (!valid) {
                try self.markDirectTableColumnInvalid(builder, absolute_row);
            }
            dst[absolute_row] = stored;
        }
    }

    fn fillDirectDateColumn(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        dst: []i32,
        src: [*]const duckdb_runtime.c.duckdb_date,
        validity: ?[*]const u64,
        start: usize,
        rows: usize,
    ) KError!void {
        for (0..rows) |row| {
            const absolute_row = start + row;
            const valid = duckDbValidityBit(validity, row);
            const stored = if (valid) directDateValue(src[row]) else 0;
            if (!valid) {
                try self.markDirectTableColumnInvalid(builder, absolute_row);
            }
            dst[absolute_row] = stored;
        }
    }

    fn fillDirectTemporalColumn(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        comptime SrcT: type,
        dst: []i64,
        src: [*]const SrcT,
        validity: ?[*]const u64,
        start: usize,
        rows: usize,
    ) KError!void {
        for (0..rows) |row| {
            const absolute_row = start + row;
            const valid = duckDbValidityBit(validity, row);
            const stored = if (valid) directTemporalValue(SrcT, src[row]) else 0;
            if (!valid) {
                try self.markDirectTableColumnInvalid(builder, absolute_row);
            }
            dst[absolute_row] = stored;
        }
    }

    fn appendDirectTableColumnChunk(
        self: *Session,
        builder: *DirectTableColumnBuilder,
        chunk: *const duckdb_runtime.DataChunk,
        column_idx: usize,
    ) KError!void {
        if (comptime !runtime_has_duckdb) return error.Unsupported;
        const rows = chunk.rowCount();
        if (builder.row_count + rows > builder.total_rows) return error.Internal;
        const start = builder.row_count;
        const validity = chunk.validity(column_idx);
        const data = chunk.vectorData(column_idx) catch |err| return mapDuckDbError(err);

        switch (builder.source_type) {
            .boolean => {
                const src: [*]const bool = @ptrCast(@alignCast(data));
                try self.fillDirectBooleanColumn(builder, builder.storage.boolean.words, src, validity, start, rows);
            },
            .tinyint => try self.fillDirectSignedColumn(builder, i8, i8, builder.storage.int8.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .smallint => try self.fillDirectSignedColumn(builder, i16, i16, builder.storage.int16.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .integer => try self.fillDirectSignedColumn(builder, i32, i32, builder.storage.int32.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .bigint => try self.fillDirectSignedColumn(builder, i64, i64, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .utinyint => try self.fillDirectUnsignedColumn(builder, u8, i16, builder.storage.int16.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .usmallint => try self.fillDirectUnsignedColumn(builder, u16, i32, builder.storage.int32.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .uinteger => try self.fillDirectUnsignedColumn(builder, u32, i64, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .ubigint => try self.fillDirectUnsignedColumn(builder, u64, i64, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .float => try self.fillDirectFloatColumn(builder, f32, builder.storage.float32.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .double => try self.fillDirectFloatColumn(builder, f64, builder.storage.float64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .date => try self.fillDirectDateColumn(builder, builder.storage.int32.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .time => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_time, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .time_ns => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_time_ns, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .time_tz => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_time_tz, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .timestamp, .timestamp_tz => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_timestamp, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .timestamp_s => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_timestamp_s, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .timestamp_ms => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_timestamp_ms, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            .timestamp_ns => try self.fillDirectTemporalColumn(builder, duckdb_runtime.c.duckdb_timestamp_ns, builder.storage.int64.items, @ptrCast(@alignCast(data)), validity, start, rows),
            else => return error.Unsupported,
        }

        builder.row_count += rows;
    }

    fn finishDirectTableColumnBuilder(self: *Session, builder: *DirectTableColumnBuilder) KError!HostTableColumn {
        _ = self;
        switch (builder.storage) {
            .boolean => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
            .int8 => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
            .int16 => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
            .int32 => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
            .int64 => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
            .float32 => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
            .float64 => |out| {
                hostDenseSetFlags(out.array, host_dense_flag_normalized);
            },
        }

        if (builder.validity_storage) |mask| {
            const metadata = analyzeBitSlice(.{ .words = mask.words, .len = mask.len });
            hostDenseSetFlags(mask.array, metadata.flags);
            hostDenseSetCachedIntRange(mask.array, metadata.range);
        }

        if (builder.row_count != builder.total_rows) return error.Internal;
        const data = builder.data orelse return error.Internal;
        const validity = builder.validity;
        builder.data = null;
        builder.validity = null;
        return .{
            .name = builder.name,
            .data = data,
            .validity = validity,
            .kind = builder.kind,
        };
    }

    fn appendTableColumnBuilderRow(
        self: *Session,
        builder: *TableColumnBuilder,
        chunk: *const duckdb_runtime.DataChunk,
        column_idx: usize,
        row_idx: usize,
    ) KError!void {
        if (comptime !runtime_has_duckdb) return error.Unsupported;
        const valid = chunk.rowIsValid(column_idx, row_idx);
        try self.tableColumnBuilderAppendValidity(builder, 0, valid);

        switch (builder.kind) {
            .boolean => try builder.bool_values.append(
                self.allocator,
                if (valid)
                    chunk.rowBool(column_idx, row_idx) catch |err| return mapDuckDbError(err)
                else
                    false,
            ),
            .int => try builder.int_values.append(
                self.allocator,
                if (valid)
                    chunk.rowInt(column_idx, row_idx, builder.source_type) catch |err| return mapDuckDbError(err)
                else
                    0,
            ),
            .date, .time, .time_ns, .time_tz, .timestamp, .timestamp_s, .timestamp_ms, .timestamp_ns, .timestamp_tz => try builder.int_values.append(
                self.allocator,
                if (valid)
                    chunk.rowTemporalInt(column_idx, row_idx, builder.source_type) catch |err| return mapDuckDbError(err)
                else
                    0,
            ),
            .float => switch (builder.source_type) {
                .float => try builder.float32_values.append(
                    self.allocator,
                    if (valid)
                        @floatCast(chunk.rowFloat(column_idx, row_idx, builder.source_type) catch |err| return mapDuckDbError(err))
                    else
                        0,
                ),
                .double => try builder.float_values.append(
                    self.allocator,
                    if (valid)
                        chunk.rowFloat(column_idx, row_idx, builder.source_type) catch |err| return mapDuckDbError(err)
                    else
                        0,
                ),
                else => return error.Unsupported,
            },
            .string => try builder.string_values.append(
                self.allocator,
                if (valid)
                    chunk.rowString(self.allocator, column_idx, row_idx) catch |err| return mapDuckDbError(err)
                else
                    try self.allocator.dupe(u8, ""),
            ),
        }
        builder.row_count += 1;
    }

    fn appendTableColumnBuilderChunk(
        self: *Session,
        builder: *TableColumnBuilder,
        chunk: *const duckdb_runtime.DataChunk,
        column_idx: usize,
    ) KError!void {
        if (comptime !runtime_has_duckdb) return error.Unsupported;
        const rows = chunk.rowCount();
        try self.tableColumnBuilderEnsureValueCapacity(builder, rows);
        if (builder.saw_null) try builder.validity.ensureUnusedCapacity(self.allocator, rows);

        const validity = chunk.validity(column_idx);
        switch (builder.kind) {
            .boolean => {
                const items: [*]const bool = @ptrCast(@alignCast(chunk.vectorData(column_idx) catch |err| return mapDuckDbError(err)));
                for (0..rows) |row_idx| {
                    const valid = duckDbValidityBit(validity, row_idx);
                    try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                    builder.bool_values.appendAssumeCapacity(if (valid) items[row_idx] else false);
                }
            },
            .int => {
                const data = chunk.vectorData(column_idx) catch |err| return mapDuckDbError(err);
                switch (builder.source_type) {
                    .tinyint => {
                        const items: [*]const i8 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .smallint => {
                        const items: [*]const i16 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .integer => {
                        const items: [*]const i32 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .bigint => {
                        const items: [*]const i64 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .utinyint => {
                        const items: [*]const u8 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .usmallint => {
                        const items: [*]const u16 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .uinteger => {
                        const items: [*]const u32 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .ubigint => {
                        const items: [*]const u64 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.int_values.appendAssumeCapacity(if (valid)
                                std.math.cast(i64, items[row_idx]) orelse return error.Unsupported
                            else
                                0);
                        }
                    },
                    else => return error.Unsupported,
                }
            },
            .float => {
                const data = chunk.vectorData(column_idx) catch |err| return mapDuckDbError(err);
                switch (builder.source_type) {
                    .float => {
                        const items: [*]const f32 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.float32_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    .double => {
                        const items: [*]const f64 = @ptrCast(@alignCast(data));
                        for (0..rows) |row_idx| {
                            const valid = duckDbValidityBit(validity, row_idx);
                            try self.tableColumnBuilderAppendValidity(builder, row_idx, valid);
                            builder.float_values.appendAssumeCapacity(if (valid) items[row_idx] else 0);
                        }
                    },
                    else => return error.Unsupported,
                }
            },
            .date, .time, .time_ns, .time_tz, .timestamp, .timestamp_s, .timestamp_ms, .timestamp_ns, .timestamp_tz, .string => {
                for (0..rows) |row_idx| {
                    try self.appendTableColumnBuilderRow(builder, chunk, column_idx, row_idx);
                }
                return;
            },
        }
        builder.row_count += rows;
    }

    fn finalizeTableColumnBuilder(self: *Session, builder: *TableColumnBuilder) KError!HostTableColumn {
        const data = switch (builder.kind) {
            .boolean => try self.createManagedHostBitArray(builder.bool_values.items),
            .int, .date, .time, .time_ns, .time_tz, .timestamp, .timestamp_s, .timestamp_ms, .timestamp_ns, .timestamp_tz => try self.createManagedHostIntArray(builder.int_values.items),
            .float => switch (builder.source_type) {
                .float => try self.createManagedHostFloat32Array(builder.float32_values.items),
                .double => try self.createManagedHostFloatArray(builder.float_values.items),
                else => return error.Unsupported,
            },
            .string => try self.createManagedHostStringListFromSlices(builder.string_values.items),
        };
        errdefer self.releaseValue(data);

        const validity = if (builder.saw_null)
            try self.createManagedHostBitArray(builder.validity.items)
        else
            null;
        errdefer if (validity) |mask| self.releaseValue(mask);

        return .{
            .name = builder.name,
            .data = data,
            .validity = validity,
            .kind = builder.kind,
        };
    }

    fn tryMaterializeQueryResultTableDirect(self: *Session, result: *duckdb_runtime.QueryResult) KError!?Value {
        const row_count_hint = result.rowCount();
        if (row_count_hint == 0) return null;

        const column_count = result.columnCount();
        const builders = try self.allocator.alloc(DirectTableColumnBuilder, column_count);
        defer self.allocator.free(builders);

        var initialized_builders: usize = 0;
        errdefer {
            for (0..initialized_builders) |idx| self.deinitDirectTableColumnBuilder(&builders[idx]);
        }

        for (0..column_count) |idx| {
            const name_bytes = result.columnName(idx) catch |err| return mapDuckDbError(err);
            defer self.allocator.free(name_bytes);
            const type_id = result.columnTypeId(idx) catch |err| return mapDuckDbError(err);
            const kind = try tableColumnKindFromDuckDbType(type_id);
            builders[idx] = (try self.initDirectTableColumnBuilder(
                try self.frozenHostSymbol(name_bytes),
                type_id,
                kind,
                row_count_hint,
            )) orelse {
                for (0..initialized_builders) |builder_idx| self.deinitDirectTableColumnBuilder(&builders[builder_idx]);
                return null;
            };
            initialized_builders += 1;
        }

        var row_count: usize = 0;
        while (true) {
            var chunk = result.fetchChunk() orelse break;
            defer chunk.deinit();

            row_count += chunk.rowCount();
            if (row_count > row_count_hint) return error.Internal;
            for (0..column_count) |column_idx| {
                try self.appendDirectTableColumnChunk(&builders[column_idx], &chunk, column_idx);
            }
        }
        if (row_count != row_count_hint) return error.Internal;

        const columns = try self.allocator.alloc(HostTableColumn, column_count);
        var built_columns: usize = 0;
        errdefer {
            for (0..built_columns) |idx| {
                self.releaseValue(columns[idx].name);
                self.releaseValue(columns[idx].data);
                if (columns[idx].validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        for (0..column_count) |idx| {
            columns[idx] = try self.finishDirectTableColumnBuilder(&builders[idx]);
            built_columns += 1;
            self.deinitDirectTableColumnBuilder(&builders[idx]);
        }
        initialized_builders = 0;

        return try self.createManagedHostTable(row_count, columns);
    }

    fn materializeQueryResultTable(self: *Session, result: *duckdb_runtime.QueryResult) KError!Value {
        if (try self.tryMaterializeQueryResultTableDirect(result)) |table| return table;

        const column_count = result.columnCount();
        const builders = try self.allocator.alloc(TableColumnBuilder, column_count);
        defer self.allocator.free(builders);

        var initialized_builders: usize = 0;
        errdefer {
            for (0..initialized_builders) |idx| self.deinitTableColumnBuilder(&builders[idx]);
        }

        for (0..column_count) |idx| {
            const name_bytes = result.columnName(idx) catch |err| return mapDuckDbError(err);
            defer self.allocator.free(name_bytes);
            const type_id = result.columnTypeId(idx) catch |err| return mapDuckDbError(err);
            builders[idx] = .{
                .name = try self.frozenHostSymbol(name_bytes),
                .source_type = type_id,
                .kind = try tableColumnKindFromDuckDbType(type_id),
            };
            initialized_builders += 1;
        }

        const row_count_hint = result.rowCount();
        if (row_count_hint != 0) {
            for (0..column_count) |idx| {
                try self.tableColumnBuilderEnsureValueCapacity(&builders[idx], row_count_hint);
            }
        }

        var row_count: usize = 0;
        while (true) {
            var chunk = result.fetchChunk() orelse break;
            defer chunk.deinit();

            row_count += chunk.rowCount();
            for (0..column_count) |column_idx| {
                try self.appendTableColumnBuilderChunk(&builders[column_idx], &chunk, column_idx);
            }
        }

        const columns = try self.allocator.alloc(HostTableColumn, column_count);
        var built_columns: usize = 0;
        errdefer {
            for (0..built_columns) |idx| {
                self.releaseValue(columns[idx].name);
                self.releaseValue(columns[idx].data);
                if (columns[idx].validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        for (0..column_count) |idx| {
            columns[idx] = try self.finalizeTableColumnBuilder(&builders[idx]);
            built_columns += 1;
            self.deinitTableColumnBuilder(&builders[idx]);
        }
        initialized_builders = 0;

        return try self.createManagedHostTable(row_count, columns);
    }

    fn tryMaterializeQueryResultColumnDirect(self: *Session, result: *duckdb_runtime.QueryResult) KError!?Value {
        if (result.columnCount() != 1) return error.Internal;
        const row_count_hint = result.rowCount();
        if (row_count_hint == 0) return null;

        const name_bytes = result.columnName(0) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(name_bytes);
        const type_id = result.columnTypeId(0) catch |err| return mapDuckDbError(err);
        const kind = try tableColumnKindFromDuckDbType(type_id);

        var builder = (try self.initDirectTableColumnBuilder(
            try self.frozenHostSymbol(name_bytes),
            type_id,
            kind,
            row_count_hint,
        )) orelse return null;
        defer self.deinitDirectTableColumnBuilder(&builder);

        var row_count: usize = 0;
        while (true) {
            var chunk = result.fetchChunk() orelse break;
            defer chunk.deinit();

            row_count += chunk.rowCount();
            if (row_count > row_count_hint) return error.Internal;
            try self.appendDirectTableColumnChunk(&builder, &chunk, 0);
        }
        if (row_count != row_count_hint) return error.Internal;

        const column = try self.finishDirectTableColumnBuilder(&builder);
        self.releaseValue(column.name);
        if (column.validity) |mask| self.releaseValue(mask);
        return column.data;
    }

    fn materializeQueryResultColumn(self: *Session, result: *duckdb_runtime.QueryResult) KError!Value {
        if (result.columnCount() != 1) return error.Internal;
        if (try self.tryMaterializeQueryResultColumnDirect(result)) |column| return column;

        const name_bytes = result.columnName(0) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(name_bytes);
        const type_id = result.columnTypeId(0) catch |err| return mapDuckDbError(err);

        var builder: TableColumnBuilder = .{
            .name = try self.frozenHostSymbol(name_bytes),
            .source_type = type_id,
            .kind = try tableColumnKindFromDuckDbType(type_id),
        };
        defer self.deinitTableColumnBuilder(&builder);

        const row_count_hint = result.rowCount();
        if (row_count_hint != 0) try self.tableColumnBuilderEnsureValueCapacity(&builder, row_count_hint);

        while (true) {
            var chunk = result.fetchChunk() orelse break;
            defer chunk.deinit();

            try self.appendTableColumnBuilderChunk(&builder, &chunk, 0);
        }

        const column = try self.finalizeTableColumnBuilder(&builder);
        self.releaseValue(column.name);
        if (column.validity) |mask| self.releaseValue(mask);
        return column.data;
    }

    fn relationTakeSql(self: *Session, relation: *const HostRelation, count: ?usize) KError![]u8 {
        return switch (relation.origin) {
            .file => |file| blk: {
                const quoted_path = duckdb_runtime.sqlStringLiteral(self.allocator, file.path) catch |err| return mapDuckDbError(err);
                defer self.allocator.free(quoted_path);
                const source_sql = switch (file.source_kind) {
                    .csv => try std.fmt.allocPrint(self.allocator, "read_csv_auto({s})", .{quoted_path}),
                    .parquet => try std.fmt.allocPrint(self.allocator, "read_parquet({s})", .{quoted_path}),
                };
                defer self.allocator.free(source_sql);
                break :blk if (count) |limit|
                    try std.fmt.allocPrint(
                        self.allocator,
                        "select * from {s} limit {d}",
                        .{ source_sql, limit },
                    )
                else
                    try std.fmt.allocPrint(
                        self.allocator,
                        "select * from {s}",
                        .{source_sql},
                    );
            },
            .sql => |sql_info| if (count) |limit|
                try std.fmt.allocPrint(
                    self.allocator,
                    "select * from ({s}) as kiwi_relation limit {d}",
                    .{ sql_info.text, limit },
                )
            else
                try self.allocator.dupe(u8, sql_info.text),
        };
    }

    fn relationColumnSql(self: *Session, relation: *const HostRelation, name: []const u8) KError![]u8 {
        const ident = duckdb_runtime.sqlIdentifier(self.allocator, name) catch |err| return mapDuckDbError(err);
        defer self.allocator.free(ident);

        return switch (relation.origin) {
            .file => |file| blk: {
                const quoted_path = duckdb_runtime.sqlStringLiteral(self.allocator, file.path) catch |err| return mapDuckDbError(err);
                defer self.allocator.free(quoted_path);
                const source_sql = switch (file.source_kind) {
                    .csv => try std.fmt.allocPrint(self.allocator, "read_csv_auto({s})", .{quoted_path}),
                    .parquet => try std.fmt.allocPrint(self.allocator, "read_parquet({s})", .{quoted_path}),
                };
                defer self.allocator.free(source_sql);
                break :blk try std.fmt.allocPrint(
                    self.allocator,
                    "select {s} from {s}",
                    .{ ident, source_sql },
                );
            },
            .sql => |sql_info| try std.fmt.allocPrint(
                self.allocator,
                "select {s} from ({s}) as kiwi_relation",
                .{ ident, sql_info.text },
            ),
        };
    }

    fn materializeRelationTake(self: *Session, raw_count: i64, relation: *const HostRelation) KError!Value {
        const count: ?usize = if (isKiwiIntNull(raw_count))
            null
        else blk: {
            if (raw_count < 0) return error.Unsupported;
            break :blk @as(usize, @intCast(raw_count));
        };
        const sql = try self.relationTakeSql(relation, count);
        defer self.allocator.free(sql);

        const conn = try self.duckdbConnection();
        var prepared = try self.prepareDuckDbStatement(conn, sql);
        defer prepared.deinit();

        switch (relation.origin) {
            .file => {},
            .sql => |sql_info| try self.bindPreparedRelationParams(&prepared, sql_info.params),
        }

        var result = try self.executeDuckDbPreparedResult(&prepared);
        defer result.deinit();
        return try self.materializeQueryResultTable(&result);
    }

    fn materializeRelationColumn(self: *Session, relation: *const HostRelation, name: []const u8) KError!Value {
        const sql = try self.relationColumnSql(relation, name);
        defer self.allocator.free(sql);

        const conn = try self.duckdbConnection();
        var prepared = try self.prepareDuckDbStatement(conn, sql);
        defer prepared.deinit();

        switch (relation.origin) {
            .file => {},
            .sql => |sql_info| try self.bindPreparedRelationParams(&prepared, sql_info.params),
        }

        var result = try self.executeDuckDbPreparedResult(&prepared);
        defer result.deinit();
        return try self.materializeQueryResultColumn(&result);
    }

    fn loadValue(self: *Session, value: Value) KError!Value {
        const path = loadPathBytes(value) orelse return error.Type;
        if (duckdb_runtime.SourceKind.detect(path) != null) {
            const store = try self.ensureLoadedRelation(path);
            return self.shareValue(store.relation);
        }
        const store = try self.ensureLoadedSafetensors(path);
        return self.shareValue(store.store);
    }

    fn scalarRandomCountValue(value: Value) ?i64 {
        return switch (value.raw & Value.tag_mask) {
            Value.int_tag, Value.boxed_int_tag => value.asInt(),
            else => null,
        };
    }

    fn containsValues(self: *Session, left: Value, right: Value) KError!Value {
        const helper_start = stringPerfNow();
        const needle = stringBytes(left) orelse return error.Type;
        const haystack = stringBytes(right) orelse return error.Type;
        const result = if (needle.len == 0)
            Value.fromBool(true)
        else
            Value.fromBool(std.mem.indexOf(u8, haystack, needle) != null);
        if (comptime enable_string_instrumentation) {
            stringPerfAdd(&self.string_perf.contains_helper_ns, helper_start);
        }
        return result;
    }

    fn bytesValue(self: *Session, value: Value) KError!Value {
        const src_info = stringSourceInfo(value) orelse return error.Type;
        const src = src_info.bytes();

        var parts = std.ArrayList(HostStringPiece).empty;
        defer parts.deinit(self.allocator);
        try parts.ensureTotalCapacity(self.allocator, src.len);
        for (0..src.len) |idx| {
            try parts.append(self.allocator, .{
                .view = .{
                    .start = src_info.span.start + idx,
                    .len = 1,
                },
            });
        }
        return try self.createManagedHostStringListPieces(src_info.base, parts.items);
    }

    fn utf8Value(self: *Session, value: Value) KError!Value {
        const src_info = stringSourceInfo(value) orelse return error.Type;
        const src = src_info.bytes();
        const view = std.unicode.Utf8View.init(src) catch return error.Type;
        var it = view.iterator();

        var parts = std.ArrayList(HostStringPiece).empty;
        defer parts.deinit(self.allocator);
        while (it.nextCodepointSlice()) |slice| {
            const rel_start = @intFromPtr(slice.ptr) - @intFromPtr(src.ptr);
            try parts.append(self.allocator, .{
                .view = .{
                    .start = src_info.span.start + rel_start,
                    .len = slice.len,
                },
            });
        }
        return try self.createManagedHostStringListPieces(src_info.base, parts.items);
    }

    fn charValue(self: *Session, value: Value) KError!Value {
        const int_value = scalarIntLikeValue(value) orelse return error.Type;
        if (int_value < 0 or int_value > 255) return error.Type;
        const bytes = [_]u8{@intCast(int_value)};
        return try self.managedHostString(&bytes);
    }

    fn checkedDecodeStep(base: i64, digit: i64, acc: i64) KError!i64 {
        const product = std.math.mul(i64, base, acc) catch return error.Unsupported;
        return std.math.add(i64, product, digit) catch return error.Unsupported;
    }

    fn checkedAbsRadix(base: i64) KError!i64 {
        if (base == std.math.minInt(i64)) return error.Unsupported;
        return if (base < 0) -base else base;
    }

    fn decodeNumericBaseAt(left: Value, left_scalar: ?i64, row: usize) KError!i64 {
        return left_scalar orelse try numericIntAt(left, row);
    }

    fn decodeNumericValues(self: *Session, left: Value, right: Value) KError!Value {
        if (valueNumericMode(right) != .int) return error.Type;
        const left_scalar = scalarIntLikeValue(left);
        const left_len = if (left_scalar == null) numericVectorLen(left) orelse return error.Type else null;

        if (scalarIntLikeValue(right)) |digit| {
            const rows = left_len orelse 1;
            var acc: i64 = 0;
            for (0..rows) |row| {
                acc = try checkedDecodeStep(try decodeNumericBaseAt(left, left_scalar, row), digit, acc);
            }
            return try self.intValue(acc);
        }

        if (valueNumericMatrixShape(right)) |shape| {
            if (left_len) |len| {
                if (len != shape.rows) return error.Type;
            }
            const out = try self.allocator.alloc(i64, shape.cols);
            defer self.allocator.free(out);
            for (0..shape.cols) |col| {
                var acc: i64 = 0;
                for (0..shape.rows) |row| {
                    const digit = try numericIntAt(right, row * shape.cols + col);
                    acc = try checkedDecodeStep(try decodeNumericBaseAt(left, left_scalar, row), digit, acc);
                }
                out[col] = acc;
            }
            return try self.createManagedHostIntArray(out);
        }

        const right_len = numericVectorLen(right) orelse return error.Type;
        const rows = if (left_len) |len| blk: {
            if (len != right_len) return error.Type;
            break :blk len;
        } else right_len;

        var acc: i64 = 0;
        for (0..rows) |row| {
            const digit = try numericIntAt(right, row);
            acc = try checkedDecodeStep(try decodeNumericBaseAt(left, left_scalar, row), digit, acc);
        }
        return try self.intValue(acc);
    }

    fn appendPositiveRadixDigits(self: *Session, out: *std.ArrayList(i64), base: i64, value: i64) KError!void {
        if (base == 1) return;
        if (base == 0) {
            if (value == 0) return;
            try out.append(self.allocator, if (value < 0) -1 else 0);
            try out.append(self.allocator, value);
            return;
        }

        var quotients = std.ArrayList(i64).empty;
        defer quotients.deinit(self.allocator);

        var current = value;
        while (true) {
            try quotients.append(self.allocator, current);
            if (quotients.items.len > 1024) return error.Unsupported;
            const next = @divFloor(current, base);
            if (next == current) break;
            current = next;
        }

        var first = true;
        var idx = quotients.items.len;
        while (idx > 0) {
            idx -= 1;
            var digit = @mod(quotients.items[idx], base);
            if (first and digit == 0) {
                first = false;
                continue;
            }
            if (first and value < 0) digit = -digit;
            first = false;
            try out.append(self.allocator, digit);
        }
    }

    fn appendNegativeRadixDigits(self: *Session, out: *std.ArrayList(i64), base: i64, value: i64) KError!void {
        if (base == -1) {
            if (value != 0) try out.append(self.allocator, 0);
            return;
        }

        const abs_base = try checkedAbsRadix(base);
        var reversed = std.ArrayList(i64).empty;
        defer reversed.deinit(self.allocator);

        var current: i128 = value;
        const base_i128: i128 = base;
        const abs_i128: i128 = abs_base;
        while (current != 0) {
            if (reversed.items.len > 1024) return error.Unsupported;
            const digit_i128 = @mod(current, abs_i128);
            const digit = std.math.cast(i64, digit_i128) orelse return error.Unsupported;
            try reversed.append(self.allocator, digit);
            current = @divExact(current - digit_i128, base_i128);
        }

        var idx = reversed.items.len;
        while (idx > 0) {
            idx -= 1;
            try out.append(self.allocator, reversed.items[idx]);
        }
    }

    fn encodeNumericScalarBaseValue(self: *Session, base: i64, value: i64) KError![]i64 {
        var digits = std.ArrayList(i64).empty;
        errdefer digits.deinit(self.allocator);

        if (base >= 0) {
            try self.appendPositiveRadixDigits(&digits, base, value);
        } else {
            try self.appendNegativeRadixDigits(&digits, base, value);
        }
        return try digits.toOwnedSlice(self.allocator);
    }

    fn encodeFixedNumericBaseInto(bases: Value, base_len: usize, value: i64, out: []i64, col: usize, cols: usize) KError!void {
        var current: i128 = value;
        var rev = base_len;
        while (rev > 0) {
            rev -= 1;
            const base = try numericIntAt(bases, rev);
            const abs_base = try checkedAbsRadix(base);
            if (base == 0) {
                out[rev * cols + col] = std.math.cast(i64, current) orelse return error.Unsupported;
                continue;
            }
            if (abs_base == 1) {
                out[rev * cols + col] = 0;
                continue;
            }
            const digit_i128 = @mod(current, @as(i128, abs_base));
            const digit = std.math.cast(i64, digit_i128) orelse return error.Unsupported;
            out[rev * cols + col] = digit;
            current = @divExact(current - digit_i128, @as(i128, base));
        }
    }

    fn encodeNumericFixedBaseValues(self: *Session, left: Value, base_len: usize, right: Value) KError!Value {
        if (base_len == 0) return error.Type;
        if (scalarIntLikeValue(right)) |value| {
            const out = try self.allocator.alloc(i64, base_len);
            defer self.allocator.free(out);
            try encodeFixedNumericBaseInto(left, base_len, value, out, 0, 1);
            return try self.createManagedHostIntArray(out);
        }

        const cols = numericVectorLen(right) orelse return error.Type;
        const out = try self.allocator.alloc(i64, base_len * cols);
        defer self.allocator.free(out);
        for (0..cols) |col| {
            try encodeFixedNumericBaseInto(left, base_len, try numericIntAt(right, col), out, col, cols);
        }
        const value = try self.createManagedHostIntArray(out);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(base_len, cols));
    }

    fn encodeNumericScalarBaseVector(self: *Session, base: i64, right: Value, cols: usize) KError!Value {
        var flat_digits = std.ArrayList(i64).empty;
        defer flat_digits.deinit(self.allocator);
        var starts = std.ArrayList(usize).empty;
        defer starts.deinit(self.allocator);
        var lens = std.ArrayList(usize).empty;
        defer lens.deinit(self.allocator);

        var rows: usize = 0;
        for (0..cols) |col| {
            const digits = try self.encodeNumericScalarBaseValue(base, try numericIntAt(right, col));
            defer self.allocator.free(digits);
            try starts.append(self.allocator, flat_digits.items.len);
            try lens.append(self.allocator, digits.len);
            rows = @max(rows, digits.len);
            try flat_digits.appendSlice(self.allocator, digits);
        }

        const out = try self.allocator.alloc(i64, rows * cols);
        defer self.allocator.free(out);
        @memset(out, 0);

        const abs_base = try checkedAbsRadix(base);
        for (0..cols) |col| {
            const start = starts.items[col];
            const len = lens.items[col];
            const digits = flat_digits.items[start .. start + len];
            if (len == 0) continue;

            if (base > 1 and digits[0] < 0 and len < rows) {
                out[col] = digits[0];
                for (1..(rows - len + 1)) |row| out[row * cols + col] = abs_base - 1;
                for (digits[1..], rows - len + 1..) |digit, row| out[row * cols + col] = digit;
            } else {
                const pad = rows - len;
                for (digits, 0..) |digit, idx| out[(pad + idx) * cols + col] = digit;
            }
        }

        const value = try self.createManagedHostIntArray(out);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(rows, cols));
    }

    fn encodeNumericScalarBaseValues(self: *Session, base: i64, right: Value) KError!Value {
        if (scalarIntLikeValue(right)) |value| {
            const digits = try self.encodeNumericScalarBaseValue(base, value);
            defer self.allocator.free(digits);
            return try self.createManagedHostIntArray(digits);
        }
        const cols = numericVectorLen(right) orelse return error.Type;
        return try self.encodeNumericScalarBaseVector(base, right, cols);
    }

    fn encodeNumericValues(self: *Session, left: Value, right: Value) KError!Value {
        if (valueNumericMode(right) != .int) return error.Type;
        if (scalarIntLikeValue(left)) |base| return try self.encodeNumericScalarBaseValues(base, right);
        const base_len = numericVectorLen(left) orelse return error.Type;
        return try self.encodeNumericFixedBaseValues(left, base_len, right);
    }

    fn splitValues(self: *Session, left: Value, right: Value) KError!Value {
        const helper_start = stringPerfNow();
        const sep = stringDelimiterBytes(left) orelse return error.Type;
        const src_info = stringSourceInfo(right) orelse return error.Type;
        const src = src_info.bytes();
        if (sep.len == 0) return error.Type;

        if (sep.len == 1 and src_info.span.start == 0 and src_info.span.len == src_info.base.len) {
            const search_start = stringPerfNow();
            const stats = countScalarSplits(src, sep[0]);
            if (comptime enable_string_instrumentation) {
                stringPerfAdd(&self.string_perf.split_search_ns, search_start);
            }
            const result_start = stringPerfNow();
            const result = try self.createManagedHostStringListLazyScalarWithDisplay(src_info.base, sep[0], stats.parts, stats.bytes_len, .split_list);
            if (comptime enable_string_instrumentation) {
                stringPerfAdd(&self.string_perf.split_result_ns, result_start);
                stringPerfAdd(&self.string_perf.split_helper_ns, helper_start);
            }
            return result;
        }

        var parts = std.ArrayList(HostStringPiece).empty;
        defer parts.deinit(self.allocator);

        var start: usize = 0;
        while (true) {
            const search_start = stringPerfNow();
            const maybe_idx = std.mem.indexOfPos(u8, src, start, sep);
            if (comptime enable_string_instrumentation) {
                stringPerfAdd(&self.string_perf.split_search_ns, search_start);
            }
            const idx = maybe_idx orelse break;
            const append_start = stringPerfNow();
            try parts.append(self.allocator, .{
                .view = .{
                    .start = src_info.span.start + start,
                    .len = idx - start,
                },
            });
            if (comptime enable_string_instrumentation) {
                stringPerfAdd(&self.string_perf.split_append_ns, append_start);
            }
            start = idx + sep.len;
        }
        if (src.len != start or (!isGrowlerLineSeparatorBytes(sep) and parts.items.len != 0)) {
            const tail_append_start = stringPerfNow();
            try parts.append(self.allocator, .{
                .view = .{
                    .start = src_info.span.start + start,
                    .len = src.len - start,
                },
            });
            if (comptime enable_string_instrumentation) {
                stringPerfAdd(&self.string_perf.split_append_ns, tail_append_start);
            }
        }
        const result_start = stringPerfNow();
        const result = try self.createManagedHostStringListPiecesWithDisplay(src_info.base, parts.items, .split_list);
        if (comptime enable_string_instrumentation) {
            stringPerfAdd(&self.string_perf.split_result_ns, result_start);
            stringPerfAdd(&self.string_perf.split_helper_ns, helper_start);
        }
        return result;
    }

    fn valueIsTextSequence(value: Value) bool {
        if (stringBytes(value) != null) return true;
        return value.tag() == .array and value.arrayKind() == .host_string_list;
    }

    fn appendTextSequenceItems(self: *Session, out: *std.ArrayList(Value), value: Value) KError!void {
        if (stringBytes(value) != null) {
            try out.append(self.allocator, try self.retainEscapedValue(value));
            return;
        }
        if (value.tag() != .array or value.arrayKind() != .host_string_list) return error.Type;

        const list = value.asHostStringList();
        for (0..list.len) |idx| try out.append(self.allocator, try self.hostStringListItemValue(list, idx));
    }

    fn concatTextSequenceValues(self: *Session, left: Value, right: Value) KError!Value {
        var values = std.ArrayList(Value).empty;
        defer values.deinit(self.allocator);
        defer {
            for (values.items) |item| self.releaseValue(item);
        }

        try self.appendTextSequenceItems(&values, left);
        try self.appendTextSequenceItems(&values, right);
        return try self.createManagedHostTextListFromValues(values.items);
    }

    fn joinValues(self: *Session, left: Value, right: Value) KError!Value {
        const helper_start = stringPerfNow();
        const sep = stringDelimiterBytes(left) orelse return error.Type;
        if (right.tag() != .array) return error.Type;

        switch (right.arrayKind()) {
            .host_string_list => {
                const result = try self.joinHostStringList(right.asHostStringList(), sep);
                if (comptime enable_string_instrumentation) {
                    stringPerfAdd(&self.string_perf.join_helper_ns, helper_start);
                }
                return result;
            },
            .host_boxed_array => {
                const boxed = right.asHostBoxedArray().items;
                var bytes_len: usize = 0;
                for (boxed) |item| {
                    const piece = stringBytes(item) orelse return error.Type;
                    bytes_len = std.math.add(usize, bytes_len, piece.len) catch return error.Unsupported;
                }
                const result = try self.joinBoxedStringValues(boxed, sep, bytes_len);
                if (comptime enable_string_instrumentation) {
                    stringPerfAdd(&self.string_perf.join_helper_ns, helper_start);
                }
                return result;
            },
            else => return error.Type,
        }
    }

    fn isJoinableStringSequence(value: Value) bool {
        if (value.tag() != .array) return false;
        return switch (value.arrayKind()) {
            .host_string_list => true,
            .host_boxed_array => blk: {
                for (value.asHostBoxedArray().items) |item| {
                    if (stringBytes(item) == null) break :blk false;
                }
                break :blk true;
            },
            else => false,
        };
    }

    fn joinHostStringList(self: *Session, list: *const HostStringList, sep: []const u8) KError!Value {
        if (sep.len == 0 and hostStringListIsContiguousBaseViews(list)) {
            return try self.retainEscapedValue(Value.array(list.base.?));
        }
        return switch (list.storage) {
            .eager => |items| self.joinHostStringPiecesKnownTotal(list.base, sep, items, list.bytes_len),
            .split_scalar => |lazy| self.joinLazyScalarSplit(list, lazy.sep, sep),
        };
    }

    fn joinLazyScalarSplit(self: *Session, list: *const HostStringList, split_sep: u8, join_sep: []const u8) KError!Value {
        const base = list.base orelse unreachable;
        const sep_count = list.len -| 1;
        const total_len = std.math.add(usize, list.bytes_len, sep_count * join_sep.len) catch return error.Unsupported;
        if (join_sep.len == 1 and join_sep[0] == split_sep and total_len == base.len) return try self.retainEscapedValue(Value.array(base));

        const result_start = stringPerfNow();
        const buf = try hostTextAllocSlice(self.allocator, total_len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        const payload = hostTextBytesFromAlloc(buf, total_len);

        const src = hostTextBytes(base);
        var offset: usize = 0;
        var start: usize = 0;
        var piece_idx: usize = 0;
        while (piece_idx < list.len) : (piece_idx += 1) {
            const sep_idx = std.mem.indexOfScalarPos(u8, src, start, split_sep);
            const end = sep_idx orelse src.len;
            if (piece_idx != 0) {
                @memcpy(payload[offset .. offset + join_sep.len], join_sep);
                offset += join_sep.len;
            }
            const piece = src[start..end];
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
            start = if (sep_idx) |idx| idx + 1 else src.len;
        }
        std.debug.assert(offset == total_len);
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = total_len,
        };
        if (comptime enable_string_instrumentation) {
            stringPerfAdd(&self.string_perf.join_result_ns, result_start);
        }
        return Value.array(text);
    }

    fn joinHostStringPieces(self: *Session, base: ?*const HostText, sep: []const u8, items: []const HostStringPiece) KError!Value {
        var bytes_len: usize = 0;
        for (items) |item| {
            const piece = hostStringPieceBytes(base, item);
            bytes_len = std.math.add(usize, bytes_len, piece.len) catch return error.Unsupported;
        }
        return self.joinHostStringPiecesKnownTotal(base, sep, items, bytes_len);
    }

    fn joinCopyHostStringPiecesSep0(payload: []u8, base: ?*const HostText, items: []const HostStringPiece) void {
        var offset: usize = 0;
        for (items) |item| {
            const piece = hostStringPieceBytes(base, item);
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyHostStringPiecesSep1(payload: []u8, base: ?*const HostText, sep: u8, items: []const HostStringPiece) void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = hostStringPieceBytes(base, item);
            if (idx != 0) {
                payload[offset] = sep;
                offset += 1;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyHostStringPiecesSep2(payload: []u8, base: ?*const HostText, sep0: u8, sep1: u8, items: []const HostStringPiece) void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = hostStringPieceBytes(base, item);
            if (idx != 0) {
                payload[offset] = sep0;
                payload[offset + 1] = sep1;
                offset += 2;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinHostStringPiecesKnownTotal(self: *Session, base: ?*const HostText, sep: []const u8, items: []const HostStringPiece, bytes_len: usize) KError!Value {
        const total_len = std.math.add(usize, bytes_len, (items.len -| 1) * sep.len) catch return error.Unsupported;

        const result_start = stringPerfNow();
        const buf = try hostTextAllocSlice(self.allocator, total_len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        const payload = hostTextBytesFromAlloc(buf, total_len);

        if (sep.len == 0) {
            joinCopyHostStringPiecesSep0(payload, base, items);
        } else if (sep.len == 1) {
            joinCopyHostStringPiecesSep1(payload, base, sep[0], items);
        } else if (sep.len == 2) {
            joinCopyHostStringPiecesSep2(payload, base, sep[0], sep[1], items);
        } else {
            var offset: usize = 0;
            for (items, 0..) |item, idx| {
                const piece = hostStringPieceBytes(base, item);
                if (idx != 0) {
                    @memcpy(payload[offset .. offset + sep.len], sep);
                    offset += sep.len;
                }
                @memcpy(payload[offset .. offset + piece.len], piece);
                offset += piece.len;
            }
            std.debug.assert(offset == total_len);
        }
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = total_len,
        };
        if (comptime enable_string_instrumentation) {
            stringPerfAdd(&self.string_perf.join_result_ns, result_start);
        }
        return Value.array(text);
    }

    fn joinCopyBoxedStringValuesSep0(payload: []u8, items: []const Value) KError!void {
        var offset: usize = 0;
        for (items) |item| {
            const piece = stringBytes(item) orelse return error.Type;
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyBoxedStringValuesSep1(payload: []u8, sep: u8, items: []const Value) KError!void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = stringBytes(item) orelse return error.Type;
            if (idx != 0) {
                payload[offset] = sep;
                offset += 1;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinCopyBoxedStringValuesSep2(payload: []u8, sep0: u8, sep1: u8, items: []const Value) KError!void {
        var offset: usize = 0;
        for (items, 0..) |item, idx| {
            const piece = stringBytes(item) orelse return error.Type;
            if (idx != 0) {
                payload[offset] = sep0;
                payload[offset + 1] = sep1;
                offset += 2;
            }
            @memcpy(payload[offset .. offset + piece.len], piece);
            offset += piece.len;
        }
        std.debug.assert(offset == payload.len);
    }

    fn joinBoxedStringValues(self: *Session, items: []const Value, sep: []const u8, bytes_len: usize) KError!Value {
        const total_len = std.math.add(usize, bytes_len, (items.len -| 1) * sep.len) catch return error.Unsupported;

        const result_start = stringPerfNow();
        const buf = try hostTextAllocSlice(self.allocator, total_len);
        errdefer self.allocator.free(buf);
        const text = hostTextFromAlloc(buf);
        const payload = hostTextBytesFromAlloc(buf, total_len);

        if (sep.len == 0) {
            try joinCopyBoxedStringValuesSep0(payload, items);
        } else if (sep.len == 1) {
            try joinCopyBoxedStringValuesSep1(payload, sep[0], items);
        } else if (sep.len == 2) {
            try joinCopyBoxedStringValuesSep2(payload, sep[0], sep[1], items);
        } else {
            var offset: usize = 0;
            for (items, 0..) |item, idx| {
                const piece = stringBytes(item) orelse return error.Type;
                if (idx != 0) {
                    @memcpy(payload[offset .. offset + sep.len], sep);
                    offset += sep.len;
                }
                @memcpy(payload[offset .. offset + piece.len], piece);
                offset += piece.len;
            }
            std.debug.assert(offset == total_len);
        }
        text.* = .{
            .header = HeapHeader.init(.host_string, .managed),
            .len = total_len,
        };
        if (comptime enable_string_instrumentation) {
            stringPerfAdd(&self.string_perf.join_result_ns, result_start);
        }
        return Value.array(text);
    }

    fn applyDyad(self: *Session, op: BuiltinId, left: Value, right: Value) KError!Value {
        return switch (op) {
            .identity => self.shareValue(right),
            .add => self.addValues(left, right),
            .sub => self.subValues(left, right),
            .mul => self.mulValues(left, right),
            .div => self.divValues(left, right),
            .pow => self.powValues(left, right),
            .iota => self.bangValues(left, right),
            .minimum => self.minimumValues(left, right),
            .maximum => self.maximumValues(left, right),
            .concat => self.concatValues(left, right),
            .take => self.takeValues(left, right),
            .drop => self.dropValues(left, right),
            .null_fill_without => self.fillWithoutValues(left, right),
            .less => self.lessValues(left, right),
            .more => self.moreValues(left, right),
            .not => self.matchValues(left, right),
            .equal => self.equalValues(left, right),
            .reshape => self.reshapeValues(left, right),
            .cast => self.castValues(left, right),
            .contains => self.containsValues(left, right),
            .split => self.splitValues(left, right),
            .join => self.joinValues(left, right),
            .load => error.Arity,
            .save => self.saveValue(left, right),
            .register => self.registerValue(left, right),
            .rotcache => self.rotcacheInitValue(left, right),
            .rotcacheupdate => self.rotcacheUpdateValue(left, right),
            .find => if (scalarRandomCountValue(left)) |count|
                self.randomDyadValue(count, right)
            else
                self.findValues(left, right),
            .prng => error.Arity,
            .rope => error.Arity,
            .ropeflat => error.Arity,
            .ropecisflat => error.Arity,
            .rmsnorm => error.Arity,
            .layernorm => error.Arity,
            .gelu => error.Arity,
            .geluapprox => error.Arity,
            .mlpdense => error.Arity,
            .conv2d => error.Arity,
            .convtranspose2d => error.Arity,
            .upsamplenearest2d => error.Arity,
            .groupnorm => error.Arity,
            .softmax => error.Arity,
            .sdpa => error.Arity,
            .sam3boxrpb => error.Arity,
            .sdpamask => error.Arity,
            .sdpaflat => error.Arity,
            else => error.Arity,
        };
    }

    fn boolLikeValue(value: Value) ?bool {
        if (tableScalarValue(value)) |scalar| {
            if (scalar.is_null) return null;
            return boolLikeValue(scalar.value);
        }
        return switch (value.tag()) {
            .bool => value.asBool(),
            .int => value.asInt() != 0,
            .float32 => value.asFloat32() != 0.0,
            .float => value.asFloat() != 0.0,
            else => null,
        };
    }

    fn branchTruthArrayLen(value: Value) ?usize {
        std.debug.assert(value.tag() == .array);
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank == 0) return null;
            return @intCast(handle.shape[0]);
        }
        if (stringBytes(value)) |bytes| return bytes.len;
        return switch (value.arrayKind()) {
            .host_dense_array => blk: {
                const array = value.asHostDenseArray();
                if (hostDenseShapeHandle(array)) |handle| {
                    if (handle.rank == 0) break :blk null;
                    break :blk @as(usize, @intCast(handle.shape[0]));
                }
                break :blk array.len();
            },
            .backend_array => blk: {
                const array = value.asBackendArray().array;
                if (array.ndim() == 0) break :blk null;
                const shape = array.shape();
                if (shape.len == 0) break :blk null;
                break :blk @as(usize, @intCast(shape[0]));
            },
            .host_boxed_array => value.asHostBoxedArray().len(),
            .host_symbol => hostTextBytes(value.asHostSymbol()).len,
            .host_string_list, .host_symbol_list => value.asHostStringList().len,
            .host_keyed_store => blk: {
                const store = value.asHostKeyedStore();
                break :blk switch (store.layout) {
                    .dict => derivedSequenceLen(store.names),
                    .table => store.row_count,
                };
            },
            .host_relation => blk: {
                const relation = value.asHostRelation();
                break :blk if (relation.cached_row_count_known) relation.cached_row_count else null;
            },
            .numeric_array,
            .host_string,
            .host_string_view,
            .host_table_scalar,
            => null,
            else => null,
        };
    }

    fn branchTruthValue(value: Value) ?bool {
        if (tableScalarValue(value)) |scalar| {
            if (scalar.is_null) return null;
            return branchTruthValue(scalar.value);
        }
        return switch (value.tag()) {
            .bool => value.asBool(),
            .int => value.asInt() != 0,
            .float32 => value.asFloat32() != 0.0,
            .float => value.asFloat() != 0.0,
            .builtin, .closure => true,
            .array => (branchTruthArrayLen(value) orelse return null) != 0,
        };
    }

    fn scalarNumericFloatValue(value: Value) ?f64 {
        if (tableScalarValue(value)) |scalar| {
            if (scalar.is_null) return null;
            return scalarNumericFloatValue(scalar.value);
        }
        return switch (value.tag()) {
            .int => @floatFromInt(value.asInt()),
            .bool => @floatFromInt(@intFromBool(value.asBool())),
            .float => value.asFloat(),
            else => null,
        };
    }

    fn applyRopeBuiltin(self: *Session, args: []const Value) KError!Value {
        if (args.len != 4) return error.Arity;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;

        _ = valueNumericMode(args[0]) orelse return error.Type;
        const dims_i64 = scalarIntLikeValue(args[1]) orelse return error.Type;
        const offset_i64 = scalarIntLikeValue(args[3]) orelse return error.Type;
        if (dims_i64 <= 0 or @mod(dims_i64, 2) != 0) return error.Type;

        const dims: i32 = std.math.cast(i32, dims_i64) orelse return error.Unsupported;
        const offset: i32 = std.math.cast(i32, offset_i64) orelse return error.Unsupported;

        var x = try self.materializeBackendArray(args[0]);
        defer x.deinit();
        if (x.ndim() < 3) return error.Type;
        if (dims > x.shape()[x.ndim() - 1]) return error.Type;

        const ctx = try self.backendContext();
        const out = if (scalarNumericFloatValue(args[2])) |base|
            mlx.Array.rope(ctx.*, x, dims, @floatCast(base), offset) catch |err| return mapMlxError(err)
        else blk: {
            _ = valueNumericMode(args[2]) orelse return error.Type;
            var freqs = try self.materializeBackendArray(args[2]);
            defer freqs.deinit();
            if (freqs.ndim() != 1 or freqs.shape()[0] != @divExact(dims, 2)) return error.Type;
            break :blk mlx.Array.ropeFreqs(ctx.*, x, dims, freqs, offset) catch |err| return mapMlxError(err);
        };
        return try self.wrapManagedBackendArray(out);
    }

    fn applyRopeFlatBuiltin(self: *Session, args: []const Value) KError!Value {
        if (args.len != 5) return error.Arity;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;

        _ = valueNumericMode(args[0]) orelse return error.Type;
        const heads_i64 = scalarIntLikeValue(args[1]) orelse return error.Type;
        const dims_i64 = scalarIntLikeValue(args[2]) orelse return error.Type;
        const offset_i64 = scalarIntLikeValue(args[4]) orelse return error.Type;
        if (heads_i64 <= 0 or dims_i64 <= 0 or @mod(dims_i64, 2) != 0) return error.Type;

        const heads: i32 = std.math.cast(i32, heads_i64) orelse return error.Unsupported;
        const dims: i32 = std.math.cast(i32, dims_i64) orelse return error.Unsupported;
        const offset: i32 = std.math.cast(i32, offset_i64) orelse return error.Unsupported;

        var x = try self.materializeBackendArray(args[0]);
        defer x.deinit();
        if (x.ndim() != 2) return error.Type;
        if (@mod(x.shape()[0], heads) != 0) return error.Type;

        const tokens = @divExact(x.shape()[0], heads);
        const width = x.shape()[1];
        if (dims > width) return error.Type;

        const ctx = try self.backendContext();
        const shape = [_]i32{ 1, tokens, heads, width };
        var x4 = mlx.Array.reshape(ctx.*, x, &shape) catch |err| return mapMlxError(err);
        defer x4.deinit();
        var x_native_view = mlx.Array.swapAxes(ctx.*, x4, 1, 2) catch |err| return mapMlxError(err);
        defer x_native_view.deinit();
        // MLX fast::rope matches the explicit 4-D path when the head-major input is
        // materialized first. Passing the swapped view directly can scramble multi-head
        // flat inputs at nonzero offsets.
        var x_native = mlx.Array.copy(ctx.*, x_native_view) catch |err| return mapMlxError(err);
        defer x_native.deinit();
        var out_native = if (scalarNumericFloatValue(args[3])) |base|
            mlx.Array.rope(ctx.*, x_native, dims, @floatCast(base), offset) catch |err| return mapMlxError(err)
        else blk: {
            _ = valueNumericMode(args[3]) orelse return error.Type;
            var freqs = try self.materializeBackendArray(args[3]);
            defer freqs.deinit();
            if (freqs.ndim() != 1 or freqs.shape()[0] != @divExact(dims, 2)) return error.Type;
            break :blk mlx.Array.ropeFreqs(ctx.*, x_native, dims, freqs, offset) catch |err| return mapMlxError(err);
        };
        defer out_native.deinit();
        var out4_view = mlx.Array.swapAxes(ctx.*, out_native, 1, 2) catch |err| return mapMlxError(err);
        defer out4_view.deinit();
        // Reshaping a swapped view can preserve the pre-swap physical layout instead of
        // the logical token-major order we need for flat head rows. Force a copy first.
        var out4 = mlx.Array.copy(ctx.*, out4_view) catch |err| return mapMlxError(err);
        defer out4.deinit();
        const out_shape = [_]i32{ tokens * heads, width };
        const out = mlx.Array.reshape(ctx.*, out4, &out_shape) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn applyRopeCisFlatBuiltin(self: *Session, args: []const Value) KError!Value {
        if (args.len != 3) return error.Arity;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;

        _ = valueNumericMode(args[0]) orelse return error.Type;
        _ = valueNumericMode(args[1]) orelse return error.Type;
        _ = valueNumericMode(args[2]) orelse return error.Type;

        var x = try self.materializeBackendArray(args[0]);
        defer x.deinit();
        var rr = try self.materializeBackendArray(args[1]);
        defer rr.deinit();
        var ri = try self.materializeBackendArray(args[2]);
        defer ri.deinit();

        if (x.ndim() != 2 or rr.ndim() != 2 or ri.ndim() != 2) return error.Type;
        if (rr.shape()[0] != ri.shape()[0] or rr.shape()[1] != ri.shape()[1]) return error.Type;
        if (x.shape()[0] != rr.shape()[0]) return error.Type;

        const rows = x.shape()[0];
        const pair_cols = rr.shape()[1];
        const rotated_cols = pair_cols * 2;
        if (rotated_cols > x.shape()[1]) return error.Type;

        const ctx = try self.backendContext();
        const even_start = [_]i32{ 0, 0 };
        const even_stop = [_]i32{ rows, rotated_cols };
        const odd_start = [_]i32{ 0, 1 };
        const odd_stop = [_]i32{ rows, rotated_cols };
        const strides = [_]i32{ 1, 2 };

        var even = mlx.Array.slice(ctx.*, x, &even_start, &even_stop, &strides) catch |err| return mapMlxError(err);
        defer even.deinit();
        var odd = mlx.Array.slice(ctx.*, x, &odd_start, &odd_stop, &strides) catch |err| return mapMlxError(err);
        defer odd.deinit();

        var even_rr = mlx.Array.mul(ctx.*, even, rr) catch |err| return mapMlxError(err);
        defer even_rr.deinit();
        var odd_ri = mlx.Array.mul(ctx.*, odd, ri) catch |err| return mapMlxError(err);
        defer odd_ri.deinit();
        var re = mlx.Array.sub(ctx.*, even_rr, odd_ri) catch |err| return mapMlxError(err);
        defer re.deinit();

        var even_ri = mlx.Array.mul(ctx.*, even, ri) catch |err| return mapMlxError(err);
        defer even_ri.deinit();
        var odd_rr = mlx.Array.mul(ctx.*, odd, rr) catch |err| return mapMlxError(err);
        defer odd_rr.deinit();
        var im = mlx.Array.add(ctx.*, even_ri, odd_rr) catch |err| return mapMlxError(err);
        defer im.deinit();

        if (rotated_cols == x.shape()[1]) {
            const pieces = [_]mlx.Array{ re, im };
            var stacked = mlx.Array.stack(ctx.*, &pieces) catch |err| return mapMlxError(err);
            defer stacked.deinit();
            var swapped0 = mlx.Array.swapAxes(ctx.*, stacked, 0, 1) catch |err| return mapMlxError(err);
            defer swapped0.deinit();
            var swapped = mlx.Array.swapAxes(ctx.*, swapped0, 1, 2) catch |err| return mapMlxError(err);
            defer swapped.deinit();
            // As with ropeflat, reshaping a swapped view can preserve the old
            // physical layout, so force a concrete copy before flattening.
            var concrete = mlx.Array.copy(ctx.*, swapped) catch |err| return mapMlxError(err);
            defer concrete.deinit();
            const out_shape = [_]i32{ rows, rotated_cols };
            const out = mlx.Array.reshape(ctx.*, concrete, &out_shape) catch |err| return mapMlxError(err);
            return try self.wrapManagedBackendArray(out);
        }

        var out0 = mlx.Array.copy(ctx.*, x) catch |err| return mapMlxError(err);
        defer out0.deinit();
        var out1 = mlx.Array.sliceUpdate(ctx.*, out0, re, &even_start, &even_stop, &strides) catch |err| return mapMlxError(err);
        defer out1.deinit();
        const out = mlx.Array.sliceUpdate(ctx.*, out1, im, &odd_start, &odd_stop, &strides) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn applyRmsNormBuiltin(self: *Session, args: []const Value) KError!Value {
        if (args.len != 3) return error.Arity;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;

        const eps = scalarNumericFloatValue(args[2]) orelse return error.Type;
        _ = valueNumericMode(args[0]) orelse return error.Type;
        _ = valueNumericMode(args[1]) orelse return error.Type;

        var x = try self.materializeBackendArray(args[0]);
        defer x.deinit();
        var w = try self.materializeBackendArray(args[1]);
        defer w.deinit();

        if (x.ndim() == 0) return error.Type;
        if (w.ndim() != 1) return error.Type;
        if (w.shape()[0] != x.shape()[x.ndim() - 1]) return error.Type;

        const ctx = try self.backendContext();
        const out = mlx.Array.rmsNorm(ctx.*, x, w, @floatCast(eps)) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn applyLayerNormBuiltin(self: *Session, args: []const Value) KError!Value {
        if (args.len != 4) return error.Arity;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;

        const eps = scalarNumericFloatValue(args[3]) orelse return error.Type;
        _ = valueNumericMode(args[0]) orelse return error.Type;
        _ = valueNumericMode(args[1]) orelse return error.Type;
        _ = valueNumericMode(args[2]) orelse return error.Type;

        var x = try self.materializeBackendArray(args[0]);
        defer x.deinit();
        var w = try self.materializeBackendArray(args[1]);
        defer w.deinit();
        var b = try self.materializeBackendArray(args[2]);
        defer b.deinit();

        if (x.ndim() == 0) return error.Type;
        if (w.ndim() != 1 or b.ndim() != 1) return error.Type;
        const width = x.shape()[x.ndim() - 1];
        if (w.shape()[0] != width or b.shape()[0] != width) return error.Type;

        const ctx = try self.backendContext();
        const out = mlx.Array.layerNorm(ctx.*, x, w, b, @floatCast(eps)) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

