    fn applyMlpDenseBuiltin(self: *Session, args: []const Value) KError!Value {
        if (args.len != 4) return error.Arity;
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;

        for (args) |arg| _ = valueNumericMode(arg) orelse return error.Type;

        var x = try self.materializeBackendArray(args[0]);
        defer x.deinit();
        var gate_w = try self.materializeBackendArray(args[1]);
        defer gate_w.deinit();
        var up_w = try self.materializeBackendArray(args[2]);
        defer up_w.deinit();
        var down_w = try self.materializeBackendArray(args[3]);
        defer down_w.deinit();

        if (x.ndim() == 0 or gate_w.ndim() != 2 or up_w.ndim() != 2 or down_w.ndim() != 2) return error.Type;
        if (x.shape()[x.ndim() - 1] != gate_w.shape()[0]) return error.Type;
        if (x.shape()[x.ndim() - 1] != up_w.shape()[0]) return error.Type;
        if (gate_w.shape()[1] != up_w.shape()[1]) return error.Type;
        if (down_w.shape()[0] != gate_w.shape()[1]) return error.Type;

        const ctx = try self.backendContext();
        const out = mlx.Array.mlpDense(ctx.*, x, gate_w, up_w, down_w) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn stringBytes(value: Value) ?[]const u8 {
        return if (stringSourceInfo(value)) |source| source.bytes() else null;
    }

    fn stringDelimiterBytes(value: Value) ?[]const u8 {
        if (stringBytes(value)) |bytes| return bytes;
        if (boxedSingletonCharSourceInfo(value)) |source| return source.bytes();
        return null;
    }

    fn symbolBytes(value: Value) ?[]const u8 {
        if (value.tag() != .array or value.arrayKind() != .host_symbol) return null;
        return hostTextBytes(value.asHostSymbol());
    }

    fn isAllAxisSelectorValue(value: Value) bool {
        const bytes = symbolBytes(value) orelse return false;
        return std.mem.eql(u8, bytes, all_axis_selector_symbol);
    }

    fn allAxisSelectorValue(self: *Session) KError!Value {
        return try self.frozenHostSymbol(all_axis_selector_symbol);
    }

    fn isSelectorPathMarkerValue(value: Value) bool {
        const bytes = symbolBytes(value) orelse return false;
        return std.mem.eql(u8, bytes, selector_path_marker_symbol);
    }

    fn selectorPathMarkerValue(self: *Session) KError!Value {
        return try self.frozenHostSymbol(selector_path_marker_symbol);
    }

    pub fn displayMimeBundleForValue(self: *Session, value: Value) ?DisplayMimeBundle {
        const raw = stringBytes(value) orelse return null;
        if (self.rawJsonLooksLikeVegaLite(raw)) {
            return .{ .mime = vega_lite_mime, .data = raw };
        }
        return null;
    }

    fn rawJsonLooksLikeVegaLite(self: *Session, raw: []const u8) bool {
        var parsed = std.json.parseFromSlice(std.json.Value, self.allocator, raw, .{}) catch return false;
        defer parsed.deinit();
        return jsonValueLooksLikeVegaLite(parsed.value);
    }

    fn jsonValueLooksLikeVegaLite(value: std.json.Value) bool {
        const object = switch (value) {
            .object => |object| object,
            else => return false,
        };
        const schema_value = object.get("$schema") orelse return false;
        const schema = switch (schema_value) {
            .string => |schema| schema,
            else => return false,
        };
        return std.mem.indexOf(u8, schema, "vega-lite") != null;
    }

    fn floatMatchEqual(left: f64, right: f64) bool {
        if (std.math.isNan(left) and std.math.isNan(right)) return true;
        return left == right;
    }

    fn numericArrayMatchEqual(self: *Session, left: Value, right: Value) KError!?bool {
        if (left.tag() != .array or right.tag() != .array) return null;
        const left_mode = valueNumericMode(left) orelse return null;
        const right_mode = valueNumericMode(right) orelse return null;
        if (left_mode != right_mode) return false;

        const left_shape = valueNumericBuilderShape(left) orelse return false;
        const right_shape = valueNumericBuilderShape(right) orelse return false;
        if (!numericShapeSnapshotEqual(left_shape, right_shape)) return false;

        const len = try numericShapeSnapshotElementCount(left_shape);
        const right_len = try numericShapeSnapshotElementCount(right_shape);
        if (len != right_len) return false;

        switch (left_mode) {
            .int => for (0..len) |idx| {
                if (try numericIntAt(left, idx) != try numericIntAt(right, idx)) return false;
            },
            .float => for (0..len) |idx| {
                if (!floatMatchEqual(try numericFloatAt(left, idx), try numericFloatAt(right, idx))) return false;
            },
        }
        _ = self;
        return true;
    }

    fn derivedSequenceMatchEqual(self: *Session, left: Value, right: Value) KError!?bool {
        const left_len = derivedSequenceLen(left) orelse return null;
        const right_len = derivedSequenceLen(right) orelse return null;
        if (left_len != right_len) return false;
        for (0..left_len) |idx| {
            const left_item = try self.derivedSequenceItemValue(left, idx);
            defer self.releaseValue(left_item);
            const right_item = try self.derivedSequenceItemValue(right, idx);
            defer self.releaseValue(right_item);
            if (!try self.valueMatchEqual(left_item, right_item)) return false;
        }
        return true;
    }

    fn valueMatchEqual(self: *Session, left: Value, right: Value) KError!bool {
        if (tableScalarValue(left)) |scalar| {
            if (scalar.is_null) return tableScalarValue(right) != null and valueAsHostTableScalar(right).is_null and scalar.kind == valueAsHostTableScalar(right).kind;
            return try self.valueMatchEqual(scalar.value, right);
        }
        if (tableScalarValue(right)) |scalar| {
            if (scalar.is_null) return false;
            return try self.valueMatchEqual(left, scalar.value);
        }

        if (left.tag() == .array and right.tag() == .array) {
            if (try self.numericArrayMatchEqual(left, right)) |matched| return matched;
            if (try self.derivedSequenceMatchEqual(left, right)) |matched| return matched;
        }

        if (left.tag() != right.tag()) {
            const lhs = scalarIntLikeValue(left) orelse return false;
            const rhs = scalarIntLikeValue(right) orelse return false;
            return lhs == rhs;
        }

        return switch (left.tag()) {
            .int => left.asInt() == right.asInt(),
            .float32 => floatMatchEqual(left.asFloat(), right.asFloat()),
            .float => floatMatchEqual(left.asFloat(), right.asFloat()),
            .bool => left.asBool() == right.asBool(),
            .builtin => left.asBuiltin() == right.asBuiltin(),
            .closure => left.asClosure() == right.asClosure(),
            .array => switch (left.arrayKind()) {
                .host_table_scalar => blk: {
                    if (right.arrayKind() != .host_table_scalar) break :blk false;
                    const lhs = valueAsHostTableScalar(left);
                    const rhs = valueAsHostTableScalar(right);
                    if (lhs.kind != rhs.kind or lhs.is_null != rhs.is_null) break :blk false;
                    if (lhs.is_null) break :blk true;
                    break :blk try self.valueMatchEqual(lhs.value, rhs.value);
                },
                .host_string, .host_string_view => if (stringBytes(right)) |right_text|
                    std.mem.eql(u8, stringBytes(left).?, right_text)
                else
                    false,
                .host_symbol => right.arrayKind() == .host_symbol and std.mem.eql(u8, hostTextBytes(left.asHostSymbol()), hostTextBytes(right.asHostSymbol())),
                .host_boxed_array => blk: {
                    if (right.arrayKind() != .host_boxed_array) break :blk false;
                    const left_items = left.asHostBoxedArray().items;
                    const right_items = right.asHostBoxedArray().items;
                    if (left_items.len != right_items.len) break :blk false;
                    for (left_items, right_items) |left_item, right_item| {
                        if (!try self.valueMatchEqual(left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                .host_string_list => blk: {
                    if (right.arrayKind() != .host_string_list) break :blk false;
                    const left_list = left.asHostStringList();
                    const right_list = right.asHostStringList();
                    if (left_list.len != right_list.len) break :blk false;
                    for (0..left_list.len) |idx| {
                        const left_item = try self.hostStringListItemValue(left_list, idx);
                        const right_item = try self.hostStringListItemValue(right_list, idx);
                        if (!try self.valueMatchEqual(left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                .host_symbol_list => blk: {
                    if (right.arrayKind() != .host_symbol_list) break :blk false;
                    const left_list = left.asHostStringList();
                    const right_list = right.asHostStringList();
                    if (left_list.len != right_list.len) break :blk false;
                    for (0..left_list.len) |idx| {
                        const left_item = try hostStringListItemBytes(left_list, idx);
                        const right_item = try hostStringListItemBytes(right_list, idx);
                        if (!std.mem.eql(u8, left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                .host_dense_array, .backend_array, .numeric_array => blk: {
                    switch (right.arrayKind()) {
                        .host_dense_array, .backend_array, .numeric_array => {},
                        else => break :blk false,
                    }
                    const lhs = try numericHostArrayValue(self, left);
                    const rhs = try numericHostArrayValue(self, right);
                    if (lhs.len() != rhs.len()) break :blk false;
                    var lhs_dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
                    var rhs_dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
                    if (!std.mem.eql(i32, hostDenseShapeDims(lhs, &lhs_dims_buf), hostDenseShapeDims(rhs, &rhs_dims_buf))) break :blk false;
                    for (0..lhs.len()) |idx| {
                        const left_item = try self.hostDenseIndexScalar(lhs, @intCast(idx));
                        const right_item = try self.hostDenseIndexScalar(rhs, @intCast(idx));
                        if (!try self.valueMatchEqual(left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                .host_keyed_store => blk: {
                    if (right.arrayKind() != .host_keyed_store) break :blk false;
                    const lhs = left.asHostKeyedStore();
                    const rhs = right.asHostKeyedStore();
                    if (lhs.layout != rhs.layout or lhs.row_count != rhs.row_count) break :blk false;
                    const count = keyedStoreNameCount(lhs);
                    if (count != keyedStoreNameCount(rhs)) break :blk false;
                    for (0..count) |idx| {
                        const left_name = try self.keyedStoreNameValue(lhs, idx);
                        const right_name = try self.keyedStoreNameValue(rhs, idx);
                        if (!try self.valueMatchEqual(left_name, right_name)) break :blk false;
                        const left_value = try self.keyedStoreValueAt(lhs, idx);
                        const right_value = try self.keyedStoreValueAt(rhs, idx);
                        if (!try self.valueMatchEqual(left_value, right_value)) break :blk false;
                    }
                    break :blk true;
                },
                .host_relation => false,
                else => false,
            },
        };
    }

    fn matchValues(self: *Session, left: Value, right: Value) KError!Value {
        return Value.fromBool(try self.valueMatchEqual(left, right));
    }

    fn valueStructuralEqual(self: *Session, left: Value, right: Value) KError!bool {
        if (left.tag() != right.tag()) {
            if ((left.tag() == .int or left.tag() == .bool or left.tag() == .float or left.tag() == .float32) and
                (right.tag() == .int or right.tag() == .bool or right.tag() == .float or right.tag() == .float32))
            {
                if (left.tag() == .float or left.tag() == .float32 or right.tag() == .float or right.tag() == .float32) {
                    const lhs = switch (left.tag()) {
                        .float, .float32 => left.asFloat(),
                        .int => @as(f64, @floatFromInt(left.asInt())),
                        .bool => @as(f64, @floatFromInt(@intFromBool(left.asBool()))),
                        else => unreachable,
                    };
                    const rhs = switch (right.tag()) {
                        .float, .float32 => right.asFloat(),
                        .int => @as(f64, @floatFromInt(right.asInt())),
                        .bool => @as(f64, @floatFromInt(@intFromBool(right.asBool()))),
                        else => unreachable,
                    };
                    return lhs == rhs;
                }
                return scalarIntLikeValue(left).? == scalarIntLikeValue(right).?;
            }
            return false;
        }
        return switch (left.tag()) {
            .int => left.asInt() == right.asInt(),
            .float32 => left.asFloat() == right.asFloat(),
            .float => left.asFloat() == right.asFloat(),
            .bool => left.asBool() == right.asBool(),
            .builtin => left.asBuiltin() == right.asBuiltin(),
            .closure => left.asClosure() == right.asClosure(),
            .array => switch (left.arrayKind()) {
                .host_table_scalar => blk: {
                    if (right.arrayKind() != .host_table_scalar) break :blk false;
                    const lhs = valueAsHostTableScalar(left);
                    const rhs = valueAsHostTableScalar(right);
                    if (lhs.kind != rhs.kind or lhs.is_null != rhs.is_null) break :blk false;
                    if (lhs.is_null) break :blk true;
                    break :blk try self.valueStructuralEqual(lhs.value, rhs.value);
                },
                .host_string, .host_string_view => if (stringBytes(right)) |right_text|
                    std.mem.eql(u8, stringBytes(left).?, right_text)
                else
                    false,
                .host_symbol => right.arrayKind() == .host_symbol and std.mem.eql(u8, hostTextBytes(left.asHostSymbol()), hostTextBytes(right.asHostSymbol())),
                .host_symbol_list => blk: {
                    if (right.arrayKind() != .host_symbol_list) break :blk false;
                    const left_list = left.asHostStringList();
                    const right_list = right.asHostStringList();
                    if (left_list.len != right_list.len) break :blk false;
                    for (0..left_list.len) |idx| {
                        const left_item = try hostStringListItemBytes(left_list, idx);
                        const right_item = try hostStringListItemBytes(right_list, idx);
                        if (!std.mem.eql(u8, left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                .host_boxed_array => blk: {
                    if (right.arrayKind() != .host_boxed_array) break :blk false;
                    const left_items = left.asHostBoxedArray().items;
                    const right_items = right.asHostBoxedArray().items;
                    if (left_items.len != right_items.len) break :blk false;
                    for (left_items, right_items) |left_item, right_item| {
                        if (!try self.valueStructuralEqual(left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                .host_dense_array, .backend_array, .numeric_array => blk: {
                    switch (right.arrayKind()) {
                        .host_dense_array, .backend_array, .numeric_array => {},
                        else => break :blk false,
                    }
                    const lhs = try numericHostArrayValue(self, left);
                    const rhs = try numericHostArrayValue(self, right);
                    if (lhs.len() != rhs.len()) break :blk false;
                    if (left.arraySubkind() != .host_boxed_array and right.arraySubkind() != .host_boxed_array) {
                        var lhs_dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
                        var rhs_dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
                        if (!std.mem.eql(i32, hostDenseShapeDims(lhs, &lhs_dims_buf), hostDenseShapeDims(rhs, &rhs_dims_buf))) break :blk false;
                        for (0..lhs.len()) |idx| {
                            if (try numericFloatAt(left, idx) != try numericFloatAt(right, idx)) break :blk false;
                        }
                        break :blk true;
                    }
                    for (0..lhs.len()) |idx| {
                        const left_item = try self.hostDenseIndexScalar(lhs, @intCast(idx));
                        const right_item = try self.hostDenseIndexScalar(rhs, @intCast(idx));
                        if (!try self.valueStructuralEqual(left_item, right_item)) break :blk false;
                    }
                    break :blk true;
                },
                else => false,
            },
        };
    }

    fn stringifyValue(self: *Session, value: Value) KError!Value {
        if (stringSourceInfo(value) != null) {
            return try self.bytesValue(value);
        }
        if (derivedSequenceLen(value)) |len| {
            return try self.stringifySequenceValue(value, len);
        }
        return try self.stringifyScalarValue(value);
    }

    fn jsonEncodeValue(self: *Session, value: Value) KError!Value {
        var out: std.io.Writer.Allocating = .init(self.allocator);
        errdefer out.deinit();
        var stringify: std.json.Stringify = .{
            .writer = &out.writer,
            .options = .{},
        };
        self.appendJsonValue(&stringify, value, 0) catch |err| return mapJsonEncodeError(err);
        const text = try out.toOwnedSlice();
        defer self.allocator.free(text);
        return try self.managedHostString(text);
    }

    const JsonEncodeError = KError || error{WriteFailed};

    fn mapJsonEncodeError(err: JsonEncodeError) KError {
        return switch (err) {
            error.Parse => error.Parse,
            error.Name => error.Name,
            error.Type => error.Type,
            error.Arity => error.Arity,
            error.Unsupported => error.Unsupported,
            error.OutOfMemory => error.OutOfMemory,
            error.Internal, error.WriteFailed => error.Internal,
        };
    }

    fn appendJsonValue(self: *Session, stringify: *std.json.Stringify, value: Value, depth: usize) JsonEncodeError!void {
        if (depth > json_encode_max_depth) return error.Type;
        if (tableScalarValue(value)) |scalar| {
            if (scalar.is_null) return try stringify.write(null);
            return try self.appendJsonValue(stringify, scalar.value, depth + 1);
        }

        switch (value.tag()) {
            .int => try stringify.write(value.asInt()),
            .float32 => {
                const raw = value.asFloat32();
                if (std.math.isFinite(raw)) {
                    try stringify.write(raw);
                } else {
                    try stringify.write(null);
                }
            },
            .float => {
                const raw = value.asFloat();
                if (std.math.isFinite(raw)) {
                    try stringify.write(raw);
                } else {
                    try stringify.write(null);
                }
            },
            .bool => try stringify.write(value.asBool()),
            .builtin, .closure => return error.Type,
            .array => {
                if (stringBytes(value)) |text| return try stringify.write(text);
                if (symbolBytes(value)) |text| return try stringify.write(text);
                if (value.arrayKind() == .host_keyed_store) {
                    return try self.appendJsonKeyedStore(stringify, value.asHostKeyedStore(), depth + 1);
                }
                if (derivedSequenceLen(value)) |len| {
                    try stringify.beginArray();
                    for (0..len) |idx| {
                        const item = try self.derivedSequenceItemValue(value, idx);
                        defer self.releaseValue(item);
                        try self.appendJsonValue(stringify, item, depth + 1);
                    }
                    return try stringify.endArray();
                }
                return error.Type;
            },
        }
    }

    fn appendJsonKeyedStore(self: *Session, stringify: *std.json.Stringify, store: *const HostKeyedStore, depth: usize) JsonEncodeError!void {
        if (depth > json_encode_max_depth) return error.Type;
        return switch (store.layout) {
            .dict => try self.appendJsonDict(stringify, store, depth + 1),
            .table => try self.appendJsonTable(stringify, store, depth + 1),
        };
    }

    fn appendJsonDict(self: *Session, stringify: *std.json.Stringify, store: *const HostKeyedStore, depth: usize) JsonEncodeError!void {
        try stringify.beginObject();
        for (0..keyedStoreNameCount(store)) |idx| {
            const name_value = try self.keyedStoreNameValue(store, idx);
            defer self.releaseValue(name_value);
            const name = keyedLookupNameBytes(name_value) orelse return error.Type;
            const item = try self.keyedStoreValueAt(store, idx);
            defer self.releaseValue(item);
            try stringify.objectField(name);
            try self.appendJsonValue(stringify, item, depth + 1);
        }
        return try stringify.endObject();
    }

    fn appendJsonTable(self: *Session, stringify: *std.json.Stringify, store: *const HostKeyedStore, depth: usize) JsonEncodeError!void {
        try stringify.beginArray();
        for (0..store.row_count) |row| {
            try stringify.beginObject();
            for (0..keyedStoreNameCount(store)) |column_idx| {
                try stringify.objectField(keyedStoreColumnNameBytes(store, column_idx));
                const cell = try self.tableCellScalarValue(store, column_idx, row);
                defer self.releaseValue(cell);
                try self.appendJsonValue(stringify, cell, depth + 1);
            }
            try stringify.endObject();
        }
        return try stringify.endArray();
    }

    fn stringifySequenceValue(self: *Session, value: Value, len: usize) KError!Value {
        if (len == 0) return try self.createManagedHostTextListFromValues(&.{});

        var out = std.ArrayList(Value).empty;
        defer {
            for (out.items) |item| self.releaseValue(item);
            out.deinit(self.allocator);
        }
        try out.ensureTotalCapacity(self.allocator, len);
        for (0..len) |idx| {
            const item = try self.derivedSequenceItemValue(value, idx);
            defer self.releaseValue(item);
            try out.append(self.allocator, try self.stringifyValue(item));
        }
        return try self.makeArrayFromValues(out.items);
    }

    fn stringifyScalarValue(self: *Session, value: Value) KError!Value {
        switch (value.tag()) {
            .int => {
                const rendered = try std.fmt.allocPrint(self.allocator, "{d}", .{value.asInt()});
                defer self.allocator.free(rendered);
                return try self.managedHostString(rendered);
            },
            .float => {
                const rendered = try formatFloat(self.allocator, value.asFloat());
                defer self.allocator.free(rendered);
                return try self.managedHostString(rendered);
            },
            .float32 => {
                const rendered = try formatFloat32Scalar(self.allocator, value.asFloat32());
                defer self.allocator.free(rendered);
                return try self.managedHostString(rendered);
            },
            .bool => return try self.managedHostString(if (value.asBool()) "1" else "0"),
            .builtin => {
                const bytes = [_]u8{builtinChar(value.asBuiltin())};
                return try self.managedHostString(&bytes);
            },
            .closure => {
                if (try self.stringifyCallableTextValue(value)) |text_value| return text_value;
            },
            .array => {
                if (symbolBytes(value)) |text| return try self.managedHostString(text);
            },
        }
        const rendered = self.renderValue(value) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => return error.Internal,
        };
        defer self.allocator.free(rendered);
        return try self.managedHostString(rendered);
    }

    fn stringifyCallableTextValue(self: *Session, value: Value) KError!?Value {
        var out = std.ArrayList(u8).empty;
        errdefer out.deinit(self.allocator);
        if (!try self.appendCallableText(&out, value)) return null;
        const text = try out.toOwnedSlice(self.allocator);
        defer self.allocator.free(text);
        return try self.managedHostString(text);
    }

    fn appendCallableText(self: *Session, out: *std.ArrayList(u8), value: Value) KError!bool {
        switch (value.tag()) {
            .builtin => {
                try out.append(self.allocator, builtinChar(value.asBuiltin()));
                return true;
            },
            .closure => {
                const closure = value.asClosure();
                if (closureIsInnerProduct(closure)) {
                    const info = try self.innerProductInfoFromClosure(closure) orelse return false;
                    try out.append(self.allocator, builtinChar(info.reduce));
                    try out.append(self.allocator, '/');
                    try out.append(self.allocator, builtinChar(info.map));
                    return true;
                }
                if (try self.compositionInfoFromClosure(closure)) |info| {
                    if (!try self.appendCallableText(out, info.outer)) return false;
                    try out.append(self.allocator, ':');
                    if (!try self.appendCallableText(out, info.inner)) return false;
                    return true;
                }
                if (closureIsProjection(closure)) {
                    return try self.appendProjectionClosureText(out, closure);
                }
                if (closureDerivedKind(closure)) |kind| {
                    if (closure.captures.len != 1) return false;
                    if (!try self.appendCallableText(out, closure.captures[0])) return false;
                    try self.appendDerivedVerbText(out, kind);
                    return true;
                }
                if (closure.code.profile_source.len != 0) {
                    if (closure.code.profile_kind == .lambda) try out.append(self.allocator, '{');
                    try out.appendSlice(self.allocator, closure.code.profile_source);
                    if (closure.code.profile_kind == .lambda) try out.append(self.allocator, '}');
                    return true;
                }
                return false;
            },
            else => return false,
        }
    }

    fn appendDerivedVerbText(self: *Session, out: *std.ArrayList(u8), kind: DerivedVerbKind) !void {
        try out.appendSlice(self.allocator, switch (kind) {
            .each => "'",
            .fold => "/",
            .scan => "\\",
            .each_right => "/:",
            .each_left => "\\:",
            .each_prior => "':",
            .grad => "grad",
            .valuegrad => "valuegrad",
        });
    }

    fn appendProjectionClosureText(self: *Session, out: *std.ArrayList(u8), closure: *const Closure) KError!bool {
        const info = try self.projectionInfoFromClosure(closure) orelse return false;
        if (info.slot_count == 2 and info.hole_mask == 0b10) {
            switch (info.callee.tag()) {
                .builtin => {
                    const builtin = info.callee.asBuiltin();
                    if (builtin != .identity) {
                        try self.appendProjectionSlotText(out, info.slot_values[0]);
                        try out.append(self.allocator, builtinChar(builtin));
                        return true;
                    }
                },
                .closure => {
                    const callee_closure = info.callee.asClosure();
                    if (closureIsInnerProduct(callee_closure) or closureDerivedKind(callee_closure) != null) {
                        try self.appendProjectionSlotText(out, info.slot_values[0]);
                        if (!try self.appendCallableText(out, info.callee)) return false;
                        return true;
                    }
                },
                else => {},
            }
        }
        if (!try self.appendCallableText(out, info.callee)) return false;
        try out.append(self.allocator, '[');
        for (0..info.slot_count) |idx| {
            if (idx != 0) try out.append(self.allocator, ';');
            if (((info.hole_mask >> @intCast(idx)) & 1) == 0) {
                try self.appendProjectionSlotText(out, info.slot_values[idx]);
            }
        }
        try out.append(self.allocator, ']');
        return true;
    }

    fn appendProjectionSlotText(self: *Session, out: *std.ArrayList(u8), value: Value) KError!void {
        const rendered = self.renderValue(value) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => return error.Internal,
        };
        defer self.allocator.free(rendered);
        out.appendSlice(self.allocator, rendered) catch return error.OutOfMemory;
    }

    fn castTagBytes(value: Value) ?[]const u8 {
        return symbolBytes(value) orelse stringBytes(value);
    }

    fn castTagBackendDtype(tag: []const u8) ?c.mlx_dtype {
        if (std.mem.eql(u8, tag, "f16") or std.mem.eql(u8, tag, "float16")) return c.MLX_FLOAT16;
        if (std.mem.eql(u8, tag, "f32") or std.mem.eql(u8, tag, "float32")) return c.MLX_FLOAT32;
        if (std.mem.eql(u8, tag, "f64") or std.mem.eql(u8, tag, "float64")) return c.MLX_FLOAT64;
        if (std.mem.eql(u8, tag, "bf16") or std.mem.eql(u8, tag, "bfloat16")) return c.MLX_BFLOAT16;
        return null;
    }

    fn createManagedEmptyIntMatrix(self: *Session) KError!Value {
        const value = try self.createManagedHostIntArray(&.{});
        errdefer self.releaseValue(value);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(0, 0));
    }

    fn createManagedEmptyFloatMatrix(self: *Session) KError!Value {
        const value = try self.createManagedHostFloatArray(&.{});
        errdefer self.releaseValue(value);
        return try applyNonVectorNumericShapeToValue(self, value, numericShapeSnapshotMatrix(0, 0));
    }

    fn truncFloatToInt64(value: f64) KError!i64 {
        if (!std.math.isFinite(value)) return error.Type;
        const truncated = @trunc(value);
        const min_i64_f64 = @as(f64, @floatFromInt(std.math.minInt(i64)));
        const max_i64_f64 = @as(f64, @floatFromInt(std.math.maxInt(i64)));
        if (truncated < min_i64_f64 or truncated > max_i64_f64) return error.Unsupported;
        return @intFromFloat(truncated);
    }

    fn castValueToInt(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| {
            if (text.len == 1) return try self.intValue(castByteToSignedInt(text[0]));
            var out = std.ArrayList(i64).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, text.len);
            for (text) |byte| try out.append(self.allocator, castByteToSignedInt(byte));
            return try self.createManagedHostIntArray(out.items);
        }

        if (value.tag() == .array and value.arrayKind() == .host_string_list) {
            return try self.castHostStringListToInt(value.asHostStringList());
        }

        if (boxedArrayItems(value)) |items| {
            if (items.len == 0) return try self.createManagedEmptyIntMatrix();
            const out = try self.allocator.alloc(Value, items.len);
            var initialized: usize = 0;
            defer {
                for (out[0..initialized]) |item| self.releaseValue(item);
                self.allocator.free(out);
            }
            for (items, 0..) |item, idx| {
                out[idx] = try self.castValueToInt(item);
                initialized += 1;
            }
            return try self.makeArrayFromValues(out);
        }

        if (scalarIntLikeValue(value)) |int_value| return try self.intValue(int_value);
        if (value.tag() == .float32) return try self.intValue(try truncFloatToInt64(value.asFloat()));
        if (value.tag() == .float) return try self.intValue(try truncFloatToInt64(value.asFloat()));

        const mode = valueNumericMode(value) orelse return error.Type;
        const len = numericFlatLen(value) orelse return error.Type;
        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        switch (mode) {
            .int => for (0..len) |idx| try out.append(self.allocator, try numericIntAt(value, idx)),
            .float => for (0..len) |idx| try out.append(self.allocator, try truncFloatToInt64(try numericFloatAt(value, idx))),
        }
        const casted = try self.createManagedHostIntArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, casted, valueNonVectorNumericShape(value));
    }

    fn parseIntTextOrNull(text: []const u8) i64 {
        return std.fmt.parseInt(i64, text, 10) catch kiwi_int_null;
    }

    fn castValueToParsedInt(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| {
            return try self.intValue(parseIntTextOrNull(text));
        }

        if (value.tag() == .array and value.arrayKind() == .host_string_list) {
            const list = value.asHostStringList();
            var out = std.ArrayList(i64).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, list.len);
            for (0..list.len) |idx| {
                const text = try hostStringListItemBytes(list, idx);
                try out.append(self.allocator, parseIntTextOrNull(text));
            }
            return try self.createManagedHostIntArray(out.items);
        }

        const items = boxedArrayItems(value) orelse return error.Type;
        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, items.len);
        for (items) |item| {
            const text = stringBytes(item) orelse return error.Type;
            try out.append(self.allocator, parseIntTextOrNull(text));
        }
        return try self.createManagedHostIntArray(out.items);
    }

    fn parseFloatTextOrNull(text: []const u8) f64 {
        if (text.len == 0 or std.mem.eql(u8, text, "0n")) return kiwiFloatNull();
        if (std.mem.eql(u8, text, "0w")) return std.math.inf(f64);
        if (std.mem.eql(u8, text, "-0w")) return -std.math.inf(f64);
        return std.fmt.parseFloat(f64, text) catch kiwiFloatNull();
    }

    fn castIntToByte(value: i64) u8 {
        return @truncate(@as(u64, @bitCast(value)));
    }

    fn castByteToSignedInt(value: u8) i64 {
        return signedByteToInt(value);
    }

    fn castHostStringListToInt(self: *Session, list: *const HostStringList) KError!Value {
        if (list.len == 0) return try self.createManagedHostIntArray(&.{});

        const first = try hostStringListItemBytes(list, 0);
        const cols = first.len;
        const total = std.math.mul(usize, list.len, cols) catch return error.Unsupported;

        var out = std.ArrayList(i64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, total);

        for (0..list.len) |row| {
            const text = try hostStringListItemBytes(list, row);
            if (text.len != cols) return error.Type;
            for (text) |byte| try out.append(self.allocator, castByteToSignedInt(byte));
        }

        const casted = try self.createManagedHostIntArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, casted, numericShapeSnapshotMatrix(list.len, cols));
    }

    fn castHostStringListToFloatBytes(self: *Session, list: *const HostStringList) KError!Value {
        if (list.len == 0) return try self.createManagedHostFloatArray(&.{});

        const first = try hostStringListItemBytes(list, 0);
        const cols = first.len;
        const total = std.math.mul(usize, list.len, cols) catch return error.Unsupported;

        var out = std.ArrayList(f64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, total);

        for (0..list.len) |row| {
            const text = try hostStringListItemBytes(list, row);
            if (text.len != cols) return error.Type;
            for (text) |byte| try out.append(self.allocator, @floatFromInt(castByteToSignedInt(byte)));
        }

        const casted = try self.createManagedHostFloatArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, casted, numericShapeSnapshotMatrix(list.len, cols));
    }

    fn castHostStringListToParsedFloat(self: *Session, list: *const HostStringList) KError!Value {
        var out = std.ArrayList(f64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, list.len);
        for (0..list.len) |idx| {
            const text = try hostStringListItemBytes(list, idx);
            try out.append(self.allocator, parseFloatTextOrNull(text));
        }
        return try self.createManagedHostFloatArray(out.items);
    }

    fn castNumericMatrixToCharRows(self: *Session, value: Value, shape: NumericShapeSnapshot, mode: HostDenseElem, len: usize) KError!Value {
        const rows: usize = @intCast(shape.shape[0]);
        const cols: usize = @intCast(shape.shape[1]);
        const total = std.math.mul(usize, rows, cols) catch return error.Unsupported;
        if (total != len) return error.Internal;

        const bytes = try self.allocator.alloc(u8, total);
        defer self.allocator.free(bytes);
        switch (mode) {
            .int => {
                for (0..len) |idx| bytes[idx] = castIntToByte(try numericIntAt(value, idx));
            },
            .float => {
                for (0..len) |idx| bytes[idx] = castIntToByte(try truncFloatToInt64(try numericFloatAt(value, idx)));
            },
        }

        const row_slices = try self.allocator.alloc([]const u8, rows);
        defer self.allocator.free(row_slices);
        for (0..rows) |row| {
            const start = row * cols;
            row_slices[row] = bytes[start .. start + cols];
        }
        return try self.createManagedHostStringRowsFromSlices(row_slices);
    }

    fn boxedItemsToCharScalarString(self: *Session, items: []const Value) KError!?Value {
        if (items.len == 0) return null;
        var out = std.ArrayList(u8).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, items.len);
        for (items) |item| {
            if (scalarIntLikeValue(item)) |int_value| {
                try out.append(self.allocator, castIntToByte(int_value));
            } else if (item.tag() == .float or item.tag() == .float32) {
                try out.append(self.allocator, castIntToByte(try truncFloatToInt64(item.asFloat())));
            } else if (stringBytes(item)) |text| {
                if (text.len != 1) return null;
                try out.append(self.allocator, text[0]);
            } else {
                return null;
            }
        }
        return try self.managedHostString(out.items);
    }

    fn castValueToChar(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| return try self.managedHostString(text);

        if (scalarIntLikeValue(value)) |int_value| {
            const bytes = [_]u8{castIntToByte(int_value)};
            return try self.managedHostString(&bytes);
        }
        if (value.tag() == .float or value.tag() == .float32) {
            const bytes = [_]u8{castIntToByte(try truncFloatToInt64(value.asFloat()))};
            return try self.managedHostString(&bytes);
        }

        if (boxedArrayItems(value)) |items| {
            if (items.len == 0) return try self.createManagedHostBoxedArray(&.{});
            if (try self.boxedItemsToCharScalarString(items)) |scalar_string| return scalar_string;

            const out = try self.allocator.alloc(Value, items.len);
            var initialized: usize = 0;
            defer {
                for (out[0..initialized]) |item| self.releaseValue(item);
                self.allocator.free(out);
            }
            for (items, 0..) |item, idx| {
                out[idx] = try self.castValueToChar(item);
                initialized += 1;
            }
            return try self.makeArrayFromValues(out);
        }

        const mode = valueNumericMode(value) orelse return error.Type;
        const len = numericFlatLen(value) orelse return error.Type;
        if (valueNonVectorNumericShape(value)) |shape| {
            if (shape.rank == 2) return try self.castNumericMatrixToCharRows(value, shape, mode, len);
        }

        var out = std.ArrayList(u8).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        switch (mode) {
            .int => for (0..len) |idx| try out.append(self.allocator, castIntToByte(try numericIntAt(value, idx))),
            .float => for (0..len) |idx| try out.append(self.allocator, castIntToByte(try truncFloatToInt64(try numericFloatAt(value, idx)))),
        }
        return try self.managedHostString(out.items);
    }

    fn castValueToFloat(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| {
            if (text.len == 1) return try self.floatValue(@floatFromInt(castByteToSignedInt(text[0])));
            var out = std.ArrayList(f64).empty;
            defer out.deinit(self.allocator);
            try out.ensureTotalCapacity(self.allocator, text.len);
            for (text) |byte| try out.append(self.allocator, @floatFromInt(castByteToSignedInt(byte)));
            return try self.createManagedHostFloatArray(out.items);
        }

        if (value.tag() == .array and value.arrayKind() == .host_string_list) {
            return try self.castHostStringListToFloatBytes(value.asHostStringList());
        }

        if (boxedArrayItems(value)) |items| {
            if (items.len == 0) return try self.createManagedEmptyFloatMatrix();
            const out = try self.allocator.alloc(Value, items.len);
            var initialized: usize = 0;
            defer {
                for (out[0..initialized]) |item| self.releaseValue(item);
                self.allocator.free(out);
            }
            for (items, 0..) |item, idx| {
                out[idx] = try self.castValueToFloat(item);
                initialized += 1;
            }
            return try self.makeArrayFromValues(out);
        }

        if (scalarIntLikeValue(value)) |int_value| {
            return try self.floatValue(if (isKiwiIntNull(int_value)) kiwiFloatNull() else @as(f64, @floatFromInt(int_value)));
        }
        if (value.tag() == .float32) return try self.floatValue(value.asFloat());
        if (value.tag() == .float) return try self.floatValue(value.asFloat());

        const mode = valueNumericMode(value) orelse return error.Type;
        const len = numericFlatLen(value) orelse return error.Type;
        var out = std.ArrayList(f64).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        switch (mode) {
            .int => for (0..len) |idx| {
                const int_value = try numericIntAt(value, idx);
                try out.append(self.allocator, if (isKiwiIntNull(int_value)) kiwiFloatNull() else @as(f64, @floatFromInt(int_value)));
            },
            .float => for (0..len) |idx| try out.append(self.allocator, try numericFloatAt(value, idx)),
        }
        const casted = try self.createManagedHostFloatArray(out.items);
        return try applyNonVectorNumericShapeToValue(self, casted, valueNonVectorNumericShape(value));
    }

    fn castValueToFloat32(self: *Session, value: Value) KError!Value {
        if (scalarIntLikeValue(value)) |int_value| {
            return try self.float32Value(if (isKiwiIntNull(int_value)) kiwiFloat32Null() else @as(f32, @floatFromInt(int_value)));
        }
        if (value.tag() == .float32) return self.shareValue(value);
        if (value.tag() == .float) return try self.float32Value(@floatCast(value.asFloat()));

        const mode = valueNumericMode(value) orelse return error.Type;
        const len = numericFlatLen(value) orelse return error.Type;
        var out = std.ArrayList(f32).empty;
        defer out.deinit(self.allocator);
        try out.ensureTotalCapacity(self.allocator, len);
        switch (mode) {
            .int => for (0..len) |idx| {
                const int_value = try numericIntAt(value, idx);
                try out.append(self.allocator, if (isKiwiIntNull(int_value)) kiwiFloat32Null() else @as(f32, @floatFromInt(int_value)));
            },
            .float => for (0..len) |idx| try out.append(self.allocator, @floatCast(try numericFloatAt(value, idx))),
        }
        const casted = try self.createManagedHostFloat32Array(out.items);
        return try applyNonVectorNumericShapeToValue(self, casted, valueNonVectorNumericShape(value));
    }

    fn castValueToParsedFloat(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| {
            return try self.floatValue(parseFloatTextOrNull(text));
        }

        if (value.tag() == .array and value.arrayKind() == .host_string_list) {
            return try self.castHostStringListToParsedFloat(value.asHostStringList());
        }

        if (boxedArrayItems(value)) |items| {
            if (items.len == 0) return try self.createManagedHostFloatArray(&.{});
            const out = try self.allocator.alloc(Value, items.len);
            var initialized: usize = 0;
            defer {
                for (out[0..initialized]) |item| self.releaseValue(item);
                self.allocator.free(out);
            }
            for (items, 0..) |item, idx| {
                out[idx] = try self.castValueToParsedFloat(item);
                initialized += 1;
            }
            return try self.makeArrayFromValues(out);
        }

        return try self.castValueToFloat(value);
    }

    fn castValueToSymbol(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| return try self.managedHostSymbol(text);
        if (symbolBytes(value)) |text| return try self.managedHostSymbol(text);

        if (value.tag() == .array and value.arrayKind() == .host_string_list) {
            const list = value.asHostStringList();
            const slices = try self.allocator.alloc([]const u8, list.len);
            defer self.allocator.free(slices);
            for (0..list.len) |idx| slices[idx] = try hostStringListItemBytes(list, idx);
            return try self.createManagedHostSymbolListFromSlices(slices);
        }
        if (value.tag() == .array and value.arrayKind() == .host_symbol_list) {
            const list = value.asHostStringList();
            const slices = try self.allocator.alloc([]const u8, list.len);
            defer self.allocator.free(slices);
            for (0..list.len) |idx| slices[idx] = try hostStringListItemBytes(list, idx);
            return try self.createManagedHostSymbolListFromSlices(slices);
        }

        if (boxedArrayItems(value)) |items| {
            if (items.len == 0) return try self.createManagedHostSymbolListFromSlices(&.{});
            if (items.len == 1) {
                if (stringBytes(items[0]) != null or symbolBytes(items[0]) != null) return try self.castValueToSymbol(items[0]);
            }

            const slices = try self.allocator.alloc([]const u8, items.len);
            defer self.allocator.free(slices);
            for (items, 0..) |item, idx| {
                slices[idx] = stringBytes(item) orelse symbolBytes(item) orelse return error.Type;
            }
            return try self.createManagedHostSymbolListFromSlices(slices);
        }

        return error.Type;
    }

    fn castValueToBackendDtype(self: *Session, value: Value, target_dtype: c.mlx_dtype) KError!Value {
        if (valueNumericMode(value) == null) return error.Type;
        var array = try self.materializeBackendArray(value);
        errdefer array.deinit();
        try self.castOwnedBackendArrayToDtype(&array, target_dtype);
        return try self.wrapManagedBackendArray(array);
    }

    fn castValues(self: *Session, left: Value, right: Value) KError!Value {
        const kind = castTagBytes(left) orelse return error.Type;
        if (std.mem.eql(u8, kind, "i") or std.mem.eql(u8, kind, "int") or std.mem.eql(u8, kind, "int32")) {
            return try self.castValueToInt(right);
        }
        if (std.mem.eql(u8, kind, "I")) {
            return try self.castValueToParsedInt(right);
        }
        if (std.mem.eql(u8, kind, "F")) {
            return try self.castValueToParsedFloat(right);
        }
        if (std.mem.eql(u8, kind, "c") or std.mem.eql(u8, kind, "char")) {
            return try self.castValueToChar(right);
        }
        if (std.mem.eql(u8, kind, "n") or std.mem.eql(u8, kind, "f") or std.mem.eql(u8, kind, "float")) {
            return try self.castValueToFloat(right);
        }
        if (std.mem.eql(u8, kind, "e") or std.mem.eql(u8, kind, "real")) {
            return try self.castValueToFloat32(right);
        }
        if (kind.len == 0 or std.mem.eql(u8, kind, "s") or std.mem.eql(u8, kind, "symbol")) {
            return try self.castValueToSymbol(right);
        }
        if (castTagBackendDtype(kind)) |target_dtype| {
            return try self.castValueToBackendDtype(right, target_dtype);
        }
        return error.Unsupported;
    }

    fn evalStringValue(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| return try self.evalSourceIsolated(text);
        if (symbolBytes(value)) |name| return self.retainValue(try self.loadGlobalNamedValue(name));
        if (value.tag() == .array and value.arrayKind() == .host_symbol_list) {
            const name = (try self.symbolTargetName(value)) orelse return error.Type;
            defer self.releaseSymbolTargetName(name);
            return self.retainValue(try self.loadGlobalNamedValue(name.bytes));
        }
        return error.Type;
    }

    fn uniqueValue(self: *Session, value: Value) KError!Value {
        if (stringBytes(value)) |text| {
            var out = std.ArrayList(u8).empty;
            defer out.deinit(self.allocator);
            var seen = [_]bool{false} ** 256;
            for (text) |ch| {
                if (seen[ch]) continue;
                seen[ch] = true;
                try out.append(self.allocator, ch);
            }
            return try self.managedHostString(out.items);
        }
        if (valueNumericMatrixView(value)) |matrix| {
            if (numericArrayIsRangeIota(matrix.handle)) {
                if (matrix.shape.rows <= 1 or numericArrayRangeIota(matrix.handle).step != 0) return self.shareValue(value);
                return (try numericValueFirstAxisContiguousSliceValue(self, value, .{ .start = 0, .len = 1 })) orelse error.Type;
            }
            if (matrix.shape.rows == 0) return self.shareValue(value);
            var row_indices = std.ArrayList(usize).empty;
            defer row_indices.deinit(self.allocator);
            for (0..matrix.shape.rows) |row_idx| {
                var seen = false;
                for (row_indices.items) |existing| {
                    if (try numericMatrixRowsEqual(self, matrix, row_idx, existing)) {
                        seen = true;
                        break;
                    }
                }
                if (!seen) try row_indices.append(self.allocator, row_idx);
            }
            return try numericValueMatrixSelectRows(self, value, row_indices.items);
        }
        if (valueNumericMode(value)) |mode| {
            const len = numericFlatLen(value) orelse return error.Type;
            if (len == 0) return self.shareValue(value);
            if (mode == .float) {
                var out = std.ArrayList(f64).empty;
                defer out.deinit(self.allocator);
                for (0..len) |idx| {
                    const item = try numericFloatAt(value, idx);
                    var seen = false;
                    for (out.items) |existing| {
                        if (existing == item) {
                            seen = true;
                            break;
                        }
                    }
                    if (!seen) try out.append(self.allocator, item);
                }
                return try self.createManagedHostFloatArray(out.items);
            }
            var out = std.ArrayList(i64).empty;
            defer out.deinit(self.allocator);
            for (0..len) |idx| {
                const item = try numericIntAt(value, idx);
                var seen = false;
                for (out.items) |existing| {
                    if (existing == item) {
                        seen = true;
                        break;
                    }
                }
                if (!seen) try out.append(self.allocator, item);
            }
            return try self.createManagedHostIntArray(out.items);
        }
        const items = boxedArrayItems(value) orelse return error.Type;
        var out = std.ArrayList(Value).empty;
        defer out.deinit(self.allocator);
        for (items) |item| {
            var seen = false;
            for (out.items) |existing| {
                if (try self.valueStructuralEqual(existing, item)) {
                    seen = true;
                    break;
                }
            }
            if (!seen) try out.append(self.allocator, item);
        }
        return try self.createManagedHostBoxedArray(out.items);
    }

    fn randomCountParts(count_value: i64) KError!struct { count: usize, distinct: bool } {
        if (count_value >= 0) return .{ .count = @intCast(count_value), .distinct = false };
        if (count_value == std.math.minInt(i64)) return error.Type;
        return .{ .count = @intCast(-count_value), .distinct = true };
    }

    fn prngStateValue(self: *Session) KError!Value {
        const words = self.prng.publicState();
        const state = [_]i64{
            @bitCast(words[0]),
            @bitCast(words[1]),
            @bitCast(words[2]),
            @bitCast(words[3]),
        };
        return try self.createManagedHostIntArray(&state);
    }

    fn setPrngState(self: *Session, words: [4]u64) KError!void {
        try self.prng.setPublicState(words);
    }

    fn setPrngFromValue(self: *Session, value: Value) KError!void {
        if (scalarIntLikeValue(value)) |seed| {
            self.prng.seedFromInt(seed);
            return;
        }
        if (valueNumericMode(value) == .int) {
            const len = numericFlatLen(value) orelse return error.Type;
            if (len != 4) return error.Type;
            var state: [4]u64 = undefined;
            for (0..4) |idx| state[idx] = @bitCast(try numericIntAt(value, idx));
            try self.setPrngState(state);
            return;
        }
        return error.Type;
    }

    fn applyPrngBuiltin(self: *Session, args: []const Value) KError!Value {
        switch (args.len) {
            0 => return try self.prngStateValue(),
            1 => {
                try self.setPrngFromValue(args[0]);
                return try self.prngStateValue();
            },
            else => return error.Arity,
        }
    }

    const rotcache_state_len = 3;
    const rotcache_payload_index = 0;
    const rotcache_max_index = 1;
    const rotcache_offset_index = 2;

    const RotCacheState = struct {
        array: *HostBoxedArray,
        payload: Value,
        max_size: usize,
        offset: usize,
    };

    fn rotcachePayloadRows(value: Value) KError!usize {
        const handle = shapedNumericHandle(value) orelse return error.Type;
        if (handle.rank == 0) return error.Type;
        return @intCast(handle.shape[0]);
    }

    fn rotcachePayloadMatches(left: Value, right: Value) KError!void {
        const left_handle = shapedNumericHandle(left) orelse return error.Type;
        const right_handle = shapedNumericHandle(right) orelse return error.Type;
        if (left_handle.rank == 0 or right_handle.rank == 0) return error.Type;
        if (left_handle.rank != right_handle.rank) return error.Type;
        if (valueNumericMode(left) == null or valueNumericMode(right) == null) return error.Type;
        if (!std.mem.eql(i32, left_handle.shape[1..left_handle.rank], right_handle.shape[1..right_handle.rank])) return error.Type;
    }

    fn parseRotcacheState(value: Value) KError!RotCacheState {
        if (value.tag() != .array or value.arrayKind() != .host_boxed_array) return error.Type;
        const array = @constCast(value.asHostBoxedArray());
        if (array.header.owner != .managed or array.items.len != rotcache_state_len) return error.Type;
        const payload = array.items[rotcache_payload_index];
        _ = try rotcachePayloadRows(payload);
        const max_i64 = scalarIntLikeValue(array.items[rotcache_max_index]) orelse return error.Type;
        const offset_i64 = scalarIntLikeValue(array.items[rotcache_offset_index]) orelse return error.Type;
        if (max_i64 <= 0 or offset_i64 < 0) return error.Type;
        const max_size: usize = @intCast(max_i64);
        if ((try rotcachePayloadRows(payload)) > max_size) return error.Type;
        return .{
            .array = array,
            .payload = payload,
            .max_size = max_size,
            .offset = @intCast(offset_i64),
        };
    }

    fn replaceManagedHostBoxedArrayItem(self: *Session, array: *HostBoxedArray, idx: usize, value: Value) KError!void {
        if (array.header.owner != .managed or idx >= array.items.len) return error.Type;
        const retained = try self.retainEscapedValue(value);
        const old = array.items[idx];
        array.items[idx] = retained;
        self.releaseValue(old);
    }

    fn rotcacheWantsBackend(value: Value) bool {
        if (!runtime_has_mlx or !mlx.supports_full_ops) return false;
        if (isBackendArrayValue(value) or hasBackendRealization(value)) return true;
        const handle = valueNumericHandle(value) orelse return false;
        return handle.preferred == .mlx;
    }

    fn rotcacheHasFixedBackendBuffer(state: RotCacheState) bool {
        if (!runtime_has_mlx) return false;
        if (!rotcacheWantsBackend(state.payload)) return false;
        const rows = rotcachePayloadRows(state.payload) catch return false;
        return rows == state.max_size;
    }

    fn sliceBackendAxis0Value(self: *Session, value: Value, start: usize, count: usize) KError!Value {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        const handle = shapedNumericHandle(value) orelse return error.Type;
        if (handle.rank == 0) return error.Type;

        var source_array = try self.materializeBackendArray(value);
        defer source_array.deinit();

        var start_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        var stop_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        var stride_buf: [numeric_array_max_rank]i32 = [_]i32{1} ** numeric_array_max_rank;
        for (0..handle.rank) |idx| stop_buf[idx] = handle.shape[idx];
        start_buf[0] = std.math.cast(i32, start) orelse return error.Unsupported;
        stop_buf[0] = std.math.cast(i32, start + count) orelse return error.Unsupported;

        const ctx = try self.backendContext();
        const out = mlx.Array.slice(
            ctx.*,
            source_array,
            start_buf[0..handle.rank],
            stop_buf[0..handle.rank],
            stride_buf[0..handle.rank],
        ) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn zeroBackendAxis0LikeValue(self: *Session, value: Value, rows: usize) KError!Value {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        const handle = shapedNumericHandle(value) orelse return error.Type;
        if (handle.rank == 0) return error.Type;

        var source_array = try self.materializeBackendArray(value);
        defer source_array.deinit();

        var dims_buf: [numeric_array_max_rank]i32 = handle.shape;
        dims_buf[0] = std.math.cast(i32, rows) orelse return error.Unsupported;

        const out = mlx.Array.zeros((try self.backendContext()).*, dims_buf[0..handle.rank], source_array.dtype()) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn sliceUpdateBackendAxis0Value(self: *Session, value: Value, start: usize, update: Value) KError!Value {
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;
        const value_handle = shapedNumericHandle(value) orelse return error.Type;
        if (value_handle.rank == 0) return error.Type;
        try rotcachePayloadMatches(value, update);
        const update_rows = try rotcachePayloadRows(update);
        if (update_rows == 0) return self.shareValue(value);
        if (start + update_rows > @as(usize, @intCast(value_handle.shape[0]))) return error.Type;

        var source_array = try self.materializeBackendArray(value);
        defer source_array.deinit();
        var update_array = try self.materializeBackendArray(update);
        defer update_array.deinit();

        var start_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        var stop_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
        var stride_buf: [numeric_array_max_rank]i32 = [_]i32{1} ** numeric_array_max_rank;
        for (0..value_handle.rank) |idx| stop_buf[idx] = value_handle.shape[idx];
        start_buf[0] = std.math.cast(i32, start) orelse return error.Unsupported;
        stop_buf[0] = std.math.cast(i32, start + update_rows) orelse return error.Unsupported;

        const out = mlx.Array.sliceUpdate(
            (try self.backendContext()).*,
            source_array,
            update_array,
            start_buf[0..value_handle.rank],
            stop_buf[0..value_handle.rank],
            stride_buf[0..value_handle.rank],
        ) catch |err| return mapMlxError(err);
        return try self.wrapManagedBackendArray(out);
    }

    fn concatBackendAxis0Values(self: *Session, left: Value, right: Value) KError!Value {
        if (comptime !runtime_has_mlx) return error.Unsupported;
        var arrays = [_]mlx.Array{
            try self.materializeBackendArray(left),
            try self.materializeBackendArray(right),
        };
        defer arrays[0].deinit();
        defer arrays[1].deinit();
        const out = try mlxConcatAxis0((try self.backendContext()).*, arrays[0..]);
        return try self.wrapManagedBackendArray(out);
    }

    fn rotcacheTailValue(self: *Session, value: Value, max_size: usize) KError!Value {
        const rows = try rotcachePayloadRows(value);
        if (rows <= max_size) return self.shareValue(value);
        const start = rows - max_size;
        if (rotcacheWantsBackend(value)) return try self.sliceBackendAxis0Value(value, start, max_size);
        return (try numericValueFirstAxisContiguousSliceValue(self, value, .{ .start = start, .len = max_size })) orelse error.Type;
    }

    fn rotcacheConcatAndTailValue(self: *Session, left: Value, right: Value, max_size: usize) KError!Value {
        const left_rows = try rotcachePayloadRows(left);
        const right_rows = try rotcachePayloadRows(right);
        if (right_rows == 0) return self.shareValue(left);

        const combined_rows = std.math.add(usize, left_rows, right_rows) catch return error.Unsupported;
        if (rotcacheWantsBackend(left) or rotcacheWantsBackend(right)) {
            const combined = try self.concatBackendAxis0Values(left, right);
            errdefer self.releaseValue(combined);
            if (combined_rows <= max_size) return combined;
            const trimmed = try self.sliceBackendAxis0Value(combined, combined_rows - max_size, max_size);
            self.releaseValue(combined);
            return trimmed;
        }

        const combined = try self.concatValues(left, right);
        errdefer self.releaseValue(combined);
        if (combined_rows <= max_size) return combined;
        const trimmed = (try numericValueFirstAxisContiguousSliceValue(
            self,
            combined,
            .{ .start = combined_rows - max_size, .len = max_size },
        )) orelse return error.Type;
        self.releaseValue(combined);
        return trimmed;
    }

    fn rotcacheInitBackendValue(self: *Session, left: Value, max_size: usize, max_i64: i64) KError!Value {
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;
        const payload = try self.rotcacheTailValue(left, max_size);
        defer self.releaseValue(payload);
        const payload_rows = try rotcachePayloadRows(payload);

        const buffer = if (payload_rows == max_size)
            self.shareValue(payload)
        else blk: {
            const zeros = try self.zeroBackendAxis0LikeValue(payload, max_size);
            errdefer self.releaseValue(zeros);
            if (payload_rows == 0) break :blk zeros;
            const filled = try self.sliceUpdateBackendAxis0Value(zeros, 0, payload);
            self.releaseValue(zeros);
            break :blk filled;
        };
        defer self.releaseValue(buffer);

        return try self.createManagedHostBoxedArray(&[_]Value{
            buffer,
            try self.intValue(max_i64),
            try self.intValue(@intCast(payload_rows)),
        });
    }

    fn rotcacheViewBackendValue(self: *Session, payload: Value, max_size: usize, offset: usize) KError!Value {
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;
        const used = @min(offset, max_size);
        if (used == 0) return try self.sliceBackendAxis0Value(payload, 0, 0);
        if (offset < max_size) return try self.sliceBackendAxis0Value(payload, 0, used);

        const write_pos = offset % max_size;
        if (write_pos == 0) return self.shareValue(payload);

        const head = try self.sliceBackendAxis0Value(payload, write_pos, max_size - write_pos);
        defer self.releaseValue(head);
        const tail = try self.sliceBackendAxis0Value(payload, 0, write_pos);
        defer self.releaseValue(tail);
        return try self.concatBackendAxis0Values(head, tail);
    }

    fn rotcacheUpdateBackendValue(self: *Session, state: RotCacheState, right: Value) KError!Value {
        if (comptime !runtime_has_mlx or !mlx.supports_full_ops) return error.Unsupported;
        const right_rows = try rotcachePayloadRows(right);
        if (right_rows == 0) return try self.rotcacheViewBackendValue(state.payload, state.max_size, state.offset);

        if (right_rows >= state.max_size) {
            const tail = try self.rotcacheTailValue(right, state.max_size);
            try self.replaceManagedHostBoxedArrayItem(state.array, rotcache_payload_index, tail);
            try self.replaceManagedHostBoxedArrayItem(state.array, rotcache_offset_index, try self.intValue(@intCast(state.max_size)));
            return tail;
        }

        const write_pos = if (state.offset < state.max_size) state.offset else state.offset % state.max_size;
        const updated = if (write_pos + right_rows <= state.max_size)
            try self.sliceUpdateBackendAxis0Value(state.payload, write_pos, right)
        else blk: {
            const first_len = state.max_size - write_pos;
            const second_len = right_rows - first_len;

            const head = try self.sliceBackendAxis0Value(right, 0, first_len);
            defer self.releaseValue(head);
            const head_written = try self.sliceUpdateBackendAxis0Value(state.payload, write_pos, head);
            errdefer self.releaseValue(head_written);

            const tail = try self.sliceBackendAxis0Value(right, first_len, second_len);
            defer self.releaseValue(tail);
            const wrapped = try self.sliceUpdateBackendAxis0Value(head_written, 0, tail);
            self.releaseValue(head_written);
            break :blk wrapped;
        };
        errdefer self.releaseValue(updated);

        const new_offset = std.math.add(usize, state.offset, right_rows) catch return error.Unsupported;
        try self.replaceManagedHostBoxedArrayItem(state.array, rotcache_payload_index, updated);
        try self.replaceManagedHostBoxedArrayItem(state.array, rotcache_offset_index, try self.intValue(@intCast(new_offset)));

        const view = try self.rotcacheViewBackendValue(updated, state.max_size, new_offset);
        return view;
    }

    fn rotcacheInitValue(self: *Session, left: Value, right: Value) KError!Value {
        const max_i64 = scalarIntLikeValue(right) orelse return error.Type;
        if (max_i64 <= 0) return error.Type;
        const max_size: usize = @intCast(max_i64);
        if (rotcacheWantsBackend(left)) return try self.rotcacheInitBackendValue(left, max_size, max_i64);
        const payload = try self.rotcacheTailValue(left, max_size);
        defer self.releaseValue(payload);
        return try self.createManagedHostBoxedArray(&[_]Value{
            payload,
            try self.intValue(max_i64),
            try self.intValue(@intCast(try rotcachePayloadRows(payload))),
        });
    }

    fn rotcacheUpdateValue(self: *Session, left: Value, right: Value) KError!Value {
        const state = try parseRotcacheState(left);
        try rotcachePayloadMatches(state.payload, right);
        if (rotcacheHasFixedBackendBuffer(state)) return try self.rotcacheUpdateBackendValue(state, right);
        const new_payload = try self.rotcacheConcatAndTailValue(state.payload, right, state.max_size);
        const new_offset = std.math.add(usize, state.offset, try rotcachePayloadRows(right)) catch return error.Unsupported;
        try self.replaceManagedHostBoxedArrayItem(state.array, rotcache_payload_index, new_payload);
        try self.replaceManagedHostBoxedArrayItem(state.array, rotcache_offset_index, try self.intValue(@intCast(new_offset)));
        return new_payload;
    }

    fn rotcacheViewValue(self: *Session, value: Value) KError!Value {
        const state = try parseRotcacheState(value);
        if (rotcacheHasFixedBackendBuffer(state)) return try self.rotcacheViewBackendValue(state.payload, state.max_size, state.offset);
        return self.shareValue(state.payload);
    }

    fn randomUniformValue(self: *Session, count_value: i64) KError!Value {
        if (count_value < 0) return error.Type;
        const count: usize = @intCast(count_value);
        const out = try self.allocator.alloc(f64, count);
        defer self.allocator.free(out);
        for (out) |*item| item.* = self.prng.nextFloat01();
        return try self.createManagedHostFloatArray(out);
    }

    fn randomWordBelow(self: *Session, limit: usize) usize {
        const limit_u64: u64 = @intCast(limit);
        var random = self.prng.random();
        if ((limit_u64 >> 32) != 0) return @intCast(random.uintLessThan(u64, limit_u64));
        return @intCast(random.uintLessThan(u32, @intCast(limit_u64)));
    }

    fn randomIndices(self: *Session, count: usize, limit: usize, distinct: bool, full_range_when_zero: bool) KError![]i64 {
        const out = try self.allocator.alloc(i64, count);
        errdefer self.allocator.free(out);

        if (!distinct) {
            if (limit == 0) {
                if (!full_range_when_zero and count != 0) return error.Type;
                const raw = try self.allocator.alloc(u64, count);
                defer self.allocator.free(raw);
                self.prng.copyFreshWords(raw);
                for (out, raw) |*item, word| item.* = @bitCast(word);
                return out;
            }
            for (out) |*item| item.* = @intCast(self.randomWordBelow(limit));
            return out;
        }

        if (count > limit) return error.Type;
        if (count == 0) return out;

        const pool = try self.allocator.alloc(i64, limit);
        defer self.allocator.free(pool);
        for (pool, 0..) |*item, idx| item.* = @intCast(idx);
        for (0..count) |idx| {
            const choice = idx + self.randomWordBelow(limit - idx);
            std.mem.swap(i64, &pool[idx], &pool[choice]);
            out[idx] = pool[idx];
        }
        return out;
    }

    fn randomSelectableLen(value: Value) ?usize {
        if (value.tag() != .array) return null;
        if (stringBytes(value)) |text| return text.len;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank != 0) return @intCast(handle.shape[0]);
        }
        return switch (value.arrayKind()) {
            .host_dense_array => value.asHostDenseArray().len(),
            .backend_array => @intCast(value.asBackendArray().array.shape()[0]),
            .numeric_array => null,
            else => null,
        };
    }

    fn randomSelectStringValue(self: *Session, count_value: i64, text: []const u8) KError!Value {
        const parts = try randomCountParts(count_value);
        if (text.len == 0) {
            if (parts.count == 0) return try self.managedHostString(&.{});
            if (parts.distinct) return error.Type;
            const spaces = try self.allocator.alloc(u8, parts.count);
            defer self.allocator.free(spaces);
            @memset(spaces, ' ');
            return try self.managedHostString(spaces);
        }
        const indices = try self.randomIndices(parts.count, text.len, parts.distinct, false);
        defer self.allocator.free(indices);
        const out = try self.allocator.alloc(u8, parts.count);
        defer self.allocator.free(out);
        for (indices, 0..) |idx, out_idx| out[out_idx] = text[@intCast(idx)];
        return try self.managedHostString(out);
    }

    fn randomScaleFloatValue(self: *Session, count_value: i64, scale: f64) KError!Value {
        const parts = try randomCountParts(count_value);
        if (parts.distinct) return error.Type;
        const out = try self.allocator.alloc(f64, parts.count);
        defer self.allocator.free(out);
        for (out) |*item| item.* = self.prng.nextFloat01() * scale;
        return try self.createManagedHostFloatArray(out);
    }

    fn randomIntValue(self: *Session, count_value: i64, bound: i64) KError!Value {
        if (bound < 0) return error.Type;
        const parts = try randomCountParts(count_value);
        const limit: usize = @intCast(bound);
        const values = try self.randomIndices(parts.count, limit, parts.distinct, true);
        defer self.allocator.free(values);
        return try self.createManagedHostIntArray(values);
    }

    fn randomSelectValue(self: *Session, count_value: i64, value: Value) KError!Value {
        const len = randomSelectableLen(value) orelse return error.Type;
        const parts = try randomCountParts(count_value);
        if (len == 0 and parts.count != 0) return error.Type;
        const indices = try self.randomIndices(parts.count, len, parts.distinct, false);
        defer self.allocator.free(indices);
        const selector = try self.createManagedHostIntArray(indices);
        defer self.releaseValue(selector);
        return try self.applyValue(value, &[_]Value{selector});
    }

    fn randomDyadValue(self: *Session, count_value: i64, right: Value) KError!Value {
        return switch (right.tag()) {
            .int => try self.randomIntValue(count_value, right.asInt()),
            .float32 => try self.randomScaleFloatValue(count_value, right.asFloat()),
            .float => try self.randomScaleFloatValue(count_value, right.asFloat()),
            .array => if (stringBytes(right)) |text|
                try self.randomSelectStringValue(count_value, text)
            else switch (right.arrayKind()) {
                .host_dense_array, .backend_array, .numeric_array => try self.randomSelectValue(count_value, right),
                else => error.Type,
            },
            .bool, .builtin, .closure => error.Type,
        };
    }

    fn numericRowQueryLen(value: Value) ?usize {
        if (valueNumericMode(value) == null) return null;
        if (valueNumericHandle(value)) |handle| {
            if (handle.rank == 0) return 1;
        }
        if (value.tag() != .array) return 1;
        if (valueNonVectorNumericShape(value)) |shape| {
            if (shape.rank == 2 and shape.shape[0] == 1) return @intCast(shape.shape[1]);
            return null;
        }
        return numericFlatLen(value);
    }

    fn numericValuesEqualAt(left: Value, left_idx: usize, right: Value, right_idx: usize) KError!bool {
        const left_mode = valueNumericMode(left) orelse return error.Type;
        const right_mode = valueNumericMode(right) orelse return error.Type;
        if (left_mode == .float or right_mode == .float) {
            return try numericFloatAt(left, left_idx) == try numericFloatAt(right, right_idx);
        }
        return try numericIntAt(left, left_idx) == try numericIntAt(right, right_idx);
    }

    fn lowerBoundAscFloat(items: []const f64, query: f64) usize {
        var low: usize = 0;
        var high: usize = items.len;
        while (low < high) {
            const mid = low + (high - low) / 2;
            if (items[mid] < query) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    fn lowerBoundDscFloat(items: []const f64, query: f64) usize {
        var low: usize = 0;
        var high: usize = items.len;
        while (low < high) {
            const mid = low + (high - low) / 2;
            if (items[mid] > query) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    fn fillSortedAscFloatDenseMonotoneQueries(left_items: []const f64, right_items: []const f64, out: []i64, miss_index: usize) KError!void {
        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        if (right_items.len == 0) return;

        const first = left_items[0];
        const last = left_items[left_items.len - 1];
        const first_query = right_items[0];
        if (first_query != first_query or first_query > last) {
            @memset(out, miss_i64);
            return;
        }

        var left_idx: usize = 0;
        var query_idx: usize = 0;
        while (query_idx < right_items.len) : (query_idx += 1) {
            const query = right_items[query_idx];
            if (query != query) {
                out[query_idx] = miss_i64;
                continue;
            }
            if (query < first) {
                out[query_idx] = miss_i64;
                continue;
            }
            if (query > last) {
                @memset(out[query_idx..], miss_i64);
                return;
            }
            while (left_idx < left_items.len and left_items[left_idx] < query) : (left_idx += 1) {}
            out[query_idx] = if (left_idx < left_items.len and left_items[left_idx] == query)
                std.math.cast(i64, left_idx) orelse return error.Unsupported
            else
                miss_i64;
        }
    }

    fn fillSortedDscFloatDenseMonotoneQueries(left_items: []const f64, right_items: []const f64, out: []i64, miss_index: usize) KError!void {
        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        if (right_items.len == 0) return;

        const first = left_items[0];
        const last = left_items[left_items.len - 1];
        const first_query = right_items[0];
        if (first_query != first_query or first_query < last) {
            @memset(out, miss_i64);
            return;
        }

        var left_idx: usize = 0;
        var query_idx: usize = 0;
        while (query_idx < right_items.len) : (query_idx += 1) {
            const query = right_items[query_idx];
            if (query != query) {
                out[query_idx] = miss_i64;
                continue;
            }
            if (query > first) {
                out[query_idx] = miss_i64;
                continue;
            }
            if (query < last) {
                @memset(out[query_idx..], miss_i64);
                return;
            }
            while (left_idx < left_items.len and left_items[left_idx] > query) : (left_idx += 1) {}
            out[query_idx] = if (left_idx < left_items.len and left_items[left_idx] == query)
                std.math.cast(i64, left_idx) orelse return error.Unsupported
            else
                miss_i64;
        }
    }

    fn lowerBoundAscInt(view: HostIntDenseView, query: i64) KError!usize {
        var low: usize = 0;
        var high: usize = hostIntDenseViewLen(view);
        while (low < high) {
            const mid = low + (high - low) / 2;
            if (try hostIntDenseViewItem(view, mid) < query) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    fn lowerBoundDscInt(view: HostIntDenseView, query: i64) KError!usize {
        var low: usize = 0;
        var high: usize = hostIntDenseViewLen(view);
        while (low < high) {
            const mid = low + (high - low) / 2;
            if (try hostIntDenseViewItem(view, mid) > query) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    fn hostFloatDenseValueFlags(value: Value, view: HostFloatDenseView) u8 {
        return switch (view) {
            .dense => switch (value.arrayKind()) {
                .host_dense_array => value.asHostDenseArray().flags,
                .numeric_array => blk: {
                    const handle = value.asNumericArray();
                    if (numericHostAttachment(handle)) |array| break :blk array.flags;
                    break :blk 0;
                },
                .backend_array => blk: {
                    const handle = valueNumericHandle(value) orelse break :blk 0;
                    if (numericHostAttachment(handle)) |array| break :blk array.flags;
                    break :blk 0;
                },
                else => 0,
            },
            else => blk: {
                const len = hostFloatDenseViewLen(view);
                if (len <= 1) break :blk host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc;
                var prev = hostFloatDenseViewItem(view, 0) catch unreachable;
                var asc = true;
                var dsc = true;
                for (1..len) |idx| {
                    const item = hostFloatDenseViewItem(view, idx) catch unreachable;
                    if (prev > item) asc = false;
                    if (prev < item) dsc = false;
                    prev = item;
                }
                break :blk host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc);
            },
        };
    }

    fn findFirstEqualDenseFloatSlice(items: []const f64, query: f64) ?usize {
        if (comptime enable_host_find_vectorized) {
            if (items.len >= host_find_vector_min_len) {
                const found = kiwi_host_find_f64(items.ptr, items.len, query);
                return if (found < items.len) found else null;
            }
        }

        const lane_count = dense_host_simd_bytes / @sizeOf(f64);
        const Vec = @Vector(lane_count, f64);
        const query_vec: Vec = @splat(query);

        var idx: usize = 0;
        const vector_limit = items.len - (items.len % lane_count);
        while (idx < vector_limit) : (idx += lane_count) {
            const chunk: Vec = items[idx..][0..lane_count].*;
            const matches = chunk == query_vec;
            if (@reduce(.Or, matches)) {
                inline for (0..lane_count) |lane| {
                    if (matches[lane]) return idx + lane;
                }
            }
        }
        while (idx < items.len) : (idx += 1) {
            if (items[idx] == query) return idx;
        }
        return null;
    }

    fn findFirstEqualDenseIntSlice(comptime T: type, items: []const T, query: T) ?usize {
        if (comptime enable_host_find_vectorized) {
            if (items.len >= host_find_vector_min_len) {
                const found = if (comptime T == i8)
                    kiwi_host_find_i8(items.ptr, items.len, query)
                else if (comptime T == i16)
                    kiwi_host_find_i16(items.ptr, items.len, query)
                else if (comptime T == i32)
                    kiwi_host_find_i32(items.ptr, items.len, query)
                else if (comptime T == i64)
                    kiwi_host_find_i64(items.ptr, items.len, query)
                else
                    @compileError("unsupported dense int find type");
                return if (found < items.len) found else null;
            }
        }

        const lane_count = dense_host_simd_bytes / @sizeOf(T);
        const Vec = @Vector(lane_count, T);
        const query_vec: Vec = @splat(query);

        var idx: usize = 0;
        const vector_limit = items.len - (items.len % lane_count);
        while (idx < vector_limit) : (idx += lane_count) {
            const chunk: Vec = items[idx..][0..lane_count].*;
            const matches = chunk == query_vec;
            if (@reduce(.Or, matches)) {
                inline for (0..lane_count) |lane| {
                    if (matches[lane]) return idx + lane;
                }
            }
        }
        while (idx < items.len) : (idx += 1) {
            if (items[idx] == query) return idx;
        }
        return null;
    }

    fn findFirstEqualBitSlice(items: HostBitSlice, query: bool) ?usize {
        for (items.words, 0..) |_, word_idx| {
            const active_mask = if (word_idx + 1 == items.words.len) bitTailMask(items.len) else std.math.maxInt(u64);
            const word = items.words[word_idx] & active_mask;
            const matches = if (query) word else (~word) & active_mask;
            if (matches != 0) {
                return word_idx * host_bit_word_bits + @as(usize, @intCast(@ctz(matches)));
            }
        }
        return null;
    }

    fn findFirstEqualDenseIntView(view: HostIntArrayView, query: i64) ?usize {
        return switch (view) {
            .bit => |items| switch (query) {
                0 => findFirstEqualBitSlice(items, false),
                1 => findFirstEqualBitSlice(items, true),
                else => null,
            },
            .int8 => |items| findFirstEqualDenseIntSlice(i8, items, std.math.cast(i8, query) orelse return null),
            .int16 => |items| findFirstEqualDenseIntSlice(i16, items, std.math.cast(i16, query) orelse return null),
            .int32 => |items| findFirstEqualDenseIntSlice(i32, items, std.math.cast(i32, query) orelse return null),
            .int64 => |items| findFirstEqualDenseIntSlice(i64, items, query),
        };
    }

    fn findFirstEqualHostFlatSliceIntView(view: HostFlatSliceView, query: i64) ?usize {
        const array = view.source_host orelse return null;
        const end = std.math.add(usize, view.start, view.len) catch return null;
        switch (array.storage) {
            .bit => |words| {
                if (end > array.logical_len) return null;
                const want = switch (query) {
                    0 => false,
                    1 => true,
                    else => return null,
                };
                for (0..view.len) |idx| {
                    if (bitGet(words, view.start + idx) == want) return idx;
                }
                return null;
            },
            .int8 => |items| {
                const logical_items = hostDenseLogicalItems(i8, array, items);
                if (end > logical_items.len) return null;
                return findFirstEqualDenseIntSlice(i8, logical_items[view.start..end], std.math.cast(i8, query) orelse return null);
            },
            .int16 => |items| {
                const logical_items = hostDenseLogicalItems(i16, array, items);
                if (end > logical_items.len) return null;
                return findFirstEqualDenseIntSlice(i16, logical_items[view.start..end], std.math.cast(i16, query) orelse return null);
            },
            .int32 => |items| {
                const logical_items = hostDenseLogicalItems(i32, array, items);
                if (end > logical_items.len) return null;
                return findFirstEqualDenseIntSlice(i32, logical_items[view.start..end], std.math.cast(i32, query) orelse return null);
            },
            .int64 => |items| {
                const logical_items = hostDenseLogicalItems(i64, array, items);
                if (end > logical_items.len) return null;
                return findFirstEqualDenseIntSlice(i64, logical_items[view.start..end], query);
            },
            .float32, .float64 => return null,
        }
    }

    fn findFirstEqualHostFlatSliceFloatView(view: HostFlatSliceView, query: f64) ?usize {
        const array = view.source_host orelse return null;
        const items = switch (array.storage) {
            .float64 => |items| hostDenseLogicalItems(f64, array, items),
            else => return null,
        };
        const end = std.math.add(usize, view.start, view.len) catch return null;
        if (end > items.len) return null;
        return findFirstEqualDenseFloatSlice(items[view.start..end], query);
    }

    fn findFirstEqualStructuralIntView(view: HostIntDenseView, query: i64) KError!?usize {
        if (view == .flat_slice) {
            if (findFirstEqualHostFlatSliceIntView(view.flat_slice, query)) |idx| return idx;
        }
        for (0..hostIntDenseViewLen(view)) |idx| {
            if ((try hostIntDenseViewItem(view, idx)) == query) return idx;
        }
        return null;
    }

    fn findFirstEqualStructuralFloatView(view: HostFloatDenseView, query: f64) KError!?usize {
        if (view == .flat_slice) {
            if (findFirstEqualHostFlatSliceFloatView(view.flat_slice, query)) |idx| return idx;
        }
        for (0..hostFloatDenseViewLen(view)) |idx| {
            if ((try hostFloatDenseViewItem(view, idx)) == query) return idx;
        }
        return null;
    }

    fn tryFastHostFloatVectorFindScalar(left: Value, view: HostFloatDenseView, query: f64, miss_index: usize) KError!?usize {
        if (query != query) return miss_index;
        const items = switch (view) {
            .dense => |dense_items| dense_items,
            else => return (try findFirstEqualStructuralFloatView(view, query)) orelse miss_index,
        };
        if (items.len == 0) return miss_index;

        const mono = monotonicFlags(hostFloatDenseValueFlags(left, view));
        if (mono != 0) {
            const first = items[0];
            const last = items[items.len - 1];
            if (first == first and last == last) {
                if ((mono & host_dense_flag_asc) != 0) {
                    if (query < first or query > last) return miss_index;
                    const idx = lowerBoundAscFloat(items, query);
                    if (idx < items.len and items[idx] == query) return idx;
                    return miss_index;
                }
                if ((mono & host_dense_flag_dsc) != 0) {
                    if (query < last or query > first) return miss_index;
                    const idx = lowerBoundDscFloat(items, query);
                    if (idx < items.len and items[idx] == query) return idx;
                    return miss_index;
                }
            }
        }
        return findFirstEqualDenseFloatSlice(items, query) orelse miss_index;
    }

    fn tryFastHostIntVectorFindScalar(left: Value, view: HostIntDenseView, query: i64, miss_index: usize) KError!?usize {
        switch (view) {
            .range_iota => |items| {
                const len = hostRangeIotaViewLen(items);
                if (len == 0) return miss_index;
                const start = numericArrayRangeIota(items.handle).start;
                const step = numericArrayRangeIota(items.handle).step;
                if (step == 0) return if (query == start) 0 else miss_index;

                const delta = query - start;
                const step_abs = if (step < 0) -step else step;
                if (@mod(delta, step_abs) != 0) return miss_index;
                const idx_i64 = @divTrunc(delta, step);
                if (idx_i64 < 0) return miss_index;
                const idx = std.math.cast(usize, idx_i64) orelse return miss_index;
                return if (idx < len) idx else miss_index;
            },
            .dense => |items| {
                const mono = monotonicFlags(hostIntDenseValueFlags(left, view));
                if (mono != 0 and std.meta.activeTag(items) != .bit) {
                    const len = hostIntDenseViewLen(view);
                    if (len == 0) return miss_index;
                    const bounds = hostIntDenseValueRange(left, view);
                    if (query < bounds.min or query > bounds.max) return miss_index;

                    if ((mono & host_dense_flag_asc) != 0) {
                        const idx = try lowerBoundAscInt(view, query);
                        if (idx < len and (try hostIntDenseViewItem(view, idx)) == query) return idx;
                        return miss_index;
                    }
                    if ((mono & host_dense_flag_dsc) != 0) {
                        const idx = try lowerBoundDscInt(view, query);
                        if (idx < len and (try hostIntDenseViewItem(view, idx)) == query) return idx;
                        return miss_index;
                    }
                }
                return findFirstEqualDenseIntView(items, query) orelse miss_index;
            },
            else => return (try findFirstEqualStructuralIntView(view, query)) orelse miss_index,
        }
    }

    fn tryFastHostNumericVectorFindScalarIndex(self: *Session, left: Value, right: Value, miss_index: usize) KError!?usize {
        const right_mode = valueNumericMode(right) orelse return null;
        const left_view = hostDenseView(self, left) catch return null;
        return switch (left_view) {
            .float_array => |items| try tryFastHostFloatVectorFindScalar(left, items, try numericFloatAt(right, 0), miss_index),
            .int_array => |items| blk: {
                const query = switch (right_mode) {
                    .int => try numericIntAt(right, 0),
                    .float => exactIntFromFloat(try numericFloatAt(right, 0)) orelse break :blk miss_index,
                };
                break :blk try tryFastHostIntVectorFindScalar(left, items, query, miss_index);
            },
            else => null,
        };
    }

    const find_bulk_num_bruteforce_threshold: usize = 255;
    const find_int_small_range_max_span: usize = 1 << 16;

    fn preferBruteForceNumericFind(left_len: usize, query_len: usize) bool {
        const left_u128: u128 = left_len;
        const query_u128: u128 = query_len;
        const threshold_u128: u128 = find_bulk_num_bruteforce_threshold;
        return 2 * left_u128 < threshold_u128 or
            2 * query_u128 < threshold_u128 or
            left_u128 * query_u128 <= threshold_u128 * threshold_u128;
    }

    fn floatFindHashKey(value: f64) ?u64 {
        if (value != value) return null;
        const normalized = if (value == 0.0) @as(f64, 0.0) else value;
        return @as(u64, @bitCast(normalized));
    }

    fn intFindHashKey(value: i64) u64 {
        return @as(u64, @bitCast(value));
    }

    fn denseFindLookupHash(key: u64) u64 {
        var mixed = key +% 0x9e3779b97f4a7c15;
        mixed = (mixed ^ (mixed >> 30)) *% 0xbf58476d1ce4e5b9;
        mixed = (mixed ^ (mixed >> 27)) *% 0x94d049bb133111eb;
        return mixed ^ (mixed >> 31);
    }

    fn denseFindLookupCapacity(item_count: usize) ?usize {
        var capacity: usize = 8;
        const target = blk: {
            if (item_count <= 4) break :blk @as(usize, 8);
            break :blk std.math.mul(usize, item_count, 2) catch return null;
        };
        while (capacity < target) {
            if (capacity > std.math.maxInt(usize) / 2) return null;
            capacity *= 2;
        }
        return capacity;
    }

    fn denseFindLookupSlotIndex(mask: usize, key: u64) usize {
        return @as(usize, @intCast(denseFindLookupHash(key) & mask));
    }

    fn denseFindLookupInsert(keys: []u64, slots: []usize, mask: usize, key: u64, idx: usize) void {
        var slot = denseFindLookupSlotIndex(mask, key);
        while (true) {
            if (slots[slot] == 0) {
                keys[slot] = key;
                slots[slot] = idx + 1;
                return;
            }
            if (keys[slot] == key) return;
            slot = (slot + 1) & mask;
        }
    }

    fn denseFindLookupGet(keys: []const u64, slots: []const usize, mask: usize, key: u64) ?usize {
        var slot = denseFindLookupSlotIndex(mask, key);
        while (true) {
            const found = slots[slot];
            if (found == 0) return null;
            if (keys[slot] == key) return found - 1;
            slot = (slot + 1) & mask;
        }
    }

    const DenseFindLookup = struct {
        allocator: std.mem.Allocator,
        keys: []u64,
        slots: []usize,
        mask: usize,

        fn init(allocator: std.mem.Allocator, item_count: usize) !DenseFindLookup {
            const capacity = denseFindLookupCapacity(item_count) orelse return error.Unsupported;
            const keys = try allocator.alloc(u64, capacity);
            errdefer allocator.free(keys);
            const slots = try allocator.alloc(usize, capacity);
            errdefer allocator.free(slots);
            @memset(slots, 0);
            return .{
                .allocator = allocator,
                .keys = keys,
                .slots = slots,
                .mask = capacity - 1,
            };
        }

        fn deinit(self: *DenseFindLookup) void {
            self.allocator.free(self.keys);
            self.allocator.free(self.slots);
        }

        fn insertFirst(self: *DenseFindLookup, key: u64, idx: usize) void {
            denseFindLookupInsert(self.keys, self.slots, self.mask, key, idx);
        }

        fn get(self: *const DenseFindLookup, key: u64) ?usize {
            return denseFindLookupGet(self.keys, self.slots, self.mask, key);
        }

        fn slotIndex(self: *const DenseFindLookup, key: u64) usize {
            return denseFindLookupSlotIndex(self.mask, key);
        }
    };

    pub const DebugFloatFindLookupFlavor = enum {
        dense,
        generic,
    };

    pub const DebugFloatFindLookup = union(DebugFloatFindLookupFlavor) {
        dense: DenseFindLookup,
        generic: std.AutoHashMap(u64, usize),

        pub fn deinit(self: *DebugFloatFindLookup) void {
            switch (self.*) {
                .dense => |*lookup| lookup.deinit(),
                .generic => |*lookup| lookup.deinit(),
            }
        }

        pub fn probe(self: *const DebugFloatFindLookup, right_items: []const f64, out: []i64, miss_index: usize) KError!void {
            const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
            switch (self.*) {
                .dense => |*lookup| {
                    for (right_items, 0..) |query, query_idx| {
                        if (floatFindHashKey(query)) |key| {
                            out[query_idx] = if (lookup.get(key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        } else {
                            out[query_idx] = miss_i64;
                        }
                    }
                },
                .generic => |*lookup| {
                    for (right_items, 0..) |query, query_idx| {
                        if (floatFindHashKey(query)) |key| {
                            out[query_idx] = if (lookup.get(key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        } else {
                            out[query_idx] = miss_i64;
                        }
                    }
                },
            }
        }
    };

    fn managedHostDenseArrayForFindCache(value: Value) ?*HostDenseArray {
        if (value.tag() != .array) return null;
        const array: *const HostDenseArray = if (valueNumericHandle(value)) |handle|
            numericHostAttachment(handle) orelse return null
        else switch (value.arrayKind()) {
            .host_dense_array => value.asHostDenseArray(),
            else => return null,
        };
        return if (numericPayloadOwner(array) == .managed) @constCast(array) else null;
    }

    fn ensureManagedHostFloatFindCache(self: *Session, array: *HostDenseArray, items: []const f64) KError!bool {
        if (numericPayloadOwner(array) != .managed) return false;
        if (array.find_cache) |cache| {
            if (cache.kind == .float and cache.keys != null and cache.slots != null) return true;
        }

        self.clearManagedHostDenseFindCache(array);

        const capacity = denseFindLookupCapacity(items.len) orelse return error.Unsupported;
        const keys = try self.allocator.alloc(u64, capacity);
        errdefer self.allocator.free(keys);
        const slots = try self.allocator.alloc(usize, capacity);
        errdefer self.allocator.free(slots);
        @memset(slots, 0);

        var bounds_known = false;
        var min_value: f64 = 0.0;
        var max_value: f64 = 0.0;
        for (items, 0..) |item, idx| {
            if (item == item) {
                if (!bounds_known) {
                    min_value = item;
                    max_value = item;
                    bounds_known = true;
                } else {
                    if (item < min_value) min_value = item;
                    if (item > max_value) max_value = item;
                }
            }
            const key = floatFindHashKey(item) orelse continue;
            denseFindLookupInsert(keys, slots, capacity - 1, key, idx);
        }

        const cache = try self.ensureManagedHostDenseFindCache(array);
        cache.kind = .float;
        cache.keys = keys;
        cache.slots = slots;
        cache.mask = capacity - 1;
        cache.float_bounds_known = bounds_known;
        cache.float_bounds_min = min_value;
        cache.float_bounds_max = max_value;
        return true;
    }

    fn ensureManagedHostIntFindCache(self: *Session, array: *HostDenseArray) KError!bool {
        if (numericPayloadOwner(array) != .managed) return false;
        if (array.find_cache) |cache| {
            if (cache.kind == .int and cache.keys != null and cache.slots != null) return true;
        }

        self.clearManagedHostDenseFindCache(array);

        const item_count = array.len();
        const capacity = denseFindLookupCapacity(item_count) orelse return error.Unsupported;
        const keys = try self.allocator.alloc(u64, capacity);
        errdefer self.allocator.free(keys);
        const slots = try self.allocator.alloc(usize, capacity);
        errdefer self.allocator.free(slots);
        @memset(slots, 0);

        switch (array.storage) {
            .bit => |items| {
                for (0..array.logical_len) |idx| {
                    denseFindLookupInsert(keys, slots, capacity - 1, intFindHashKey(@intFromBool(bitGet(items, idx))), idx);
                }
            },
            .int8 => |items| for (hostDenseLogicalItems(i8, array, items), 0..) |item, idx| denseFindLookupInsert(keys, slots, capacity - 1, intFindHashKey(item), idx),
            .int16 => |items| for (hostDenseLogicalItems(i16, array, items), 0..) |item, idx| denseFindLookupInsert(keys, slots, capacity - 1, intFindHashKey(item), idx),
            .int32 => |items| for (hostDenseLogicalItems(i32, array, items), 0..) |item, idx| denseFindLookupInsert(keys, slots, capacity - 1, intFindHashKey(item), idx),
            .int64 => |items| for (hostDenseLogicalItems(i64, array, items), 0..) |item, idx| denseFindLookupInsert(keys, slots, capacity - 1, intFindHashKey(item), idx),
            .float32, .float64 => return false,
        }

        const cache = try self.ensureManagedHostDenseFindCache(array);
        cache.kind = .int;
        cache.keys = keys;
        cache.slots = slots;
        cache.mask = capacity - 1;
        return true;
    }

    fn buildGenericFloatFindLookup(self: *Session, left_items: []const f64) KError!std.AutoHashMap(u64, usize) {
        var lookup = std.AutoHashMap(u64, usize).init(self.allocator);
        errdefer lookup.deinit();
        try lookup.ensureTotalCapacity(std.math.cast(u32, left_items.len) orelse return error.Unsupported);
        for (left_items, 0..) |item, idx| {
            const key = floatFindHashKey(item) orelse continue;
            if (lookup.get(key) == null) try lookup.put(key, idx);
        }
        return lookup;
    }

    pub fn debugBuildFloatFindLookup(self: *Session, flavor: DebugFloatFindLookupFlavor, left_items: []const f64) KError!DebugFloatFindLookup {
        return switch (flavor) {
            .dense => blk: {
                var lookup = try DenseFindLookup.init(self.allocator, left_items.len);
                errdefer lookup.deinit();
                for (left_items, 0..) |item, idx| {
                    const key = floatFindHashKey(item) orelse continue;
                    lookup.insertFirst(key, idx);
                }
                break :blk .{ .dense = lookup };
            },
            .generic => .{ .generic = try self.buildGenericFloatFindLookup(left_items) },
        };
    }

    pub fn debugRunFloatFindLookupBuildProbe(
        self: *Session,
        flavor: DebugFloatFindLookupFlavor,
        left_items: []const f64,
        right_items: []const f64,
        out: []i64,
        miss_index: usize,
    ) KError!void {
        switch (flavor) {
            .dense => try fillFloatFindDenseHashedFloatQueries(self, out, null, left_items, right_items, miss_index),
            .generic => {
                var lookup = try self.buildGenericFloatFindLookup(left_items);
                defer lookup.deinit();
                const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
                for (right_items, 0..) |query, query_idx| {
                    if (floatFindHashKey(query)) |key| {
                        out[query_idx] = if (lookup.get(key)) |found_idx|
                            std.math.cast(i64, found_idx) orelse return error.Unsupported
                        else
                            miss_i64;
                    } else {
                        out[query_idx] = miss_i64;
                    }
                }
            },
        }
    }

    fn fillFloatFindDenseHashedFloatQueries(
        self: *Session,
        out: []i64,
        left_array: ?*HostDenseArray,
        left_items: []const f64,
        right_items: []const f64,
        miss_index: usize,
    ) KError!void {
        if (left_array) |array| {
            if (try self.ensureManagedHostFloatFindCache(array, left_items)) {
                const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
                const cache = array.find_cache.?;
                if (!cache.float_bounds_known) {
                    @memset(out, miss_i64);
                    return;
                }
                var all_outside = true;
                for (right_items) |query| {
                    if (query == query and query >= cache.float_bounds_min and query <= cache.float_bounds_max) {
                        all_outside = false;
                        break;
                    }
                }
                if (all_outside) {
                    @memset(out, miss_i64);
                    return;
                }
                const keys = cache.keys.?;
                const slots = cache.slots.?;
                for (right_items, 0..) |query, query_idx| {
                    if (floatFindHashKey(query)) |key| {
                        out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, key)) |found_idx|
                            std.math.cast(i64, found_idx) orelse return error.Unsupported
                        else
                            miss_i64;
                    } else {
                        out[query_idx] = miss_i64;
                    }
                }
                return;
            }
        }

        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        if (tryFillFloatDenseAllMissByBounds(out, left_items, right_items, miss_i64)) return;

        var lookup = try DenseFindLookup.init(self.allocator, left_items.len);
        defer lookup.deinit();
        for (left_items, 0..) |item, idx| {
            const key = floatFindHashKey(item) orelse continue;
            lookup.insertFirst(key, idx);
        }

        for (right_items, 0..) |query, query_idx| {
            if (floatFindHashKey(query)) |key| {
                out[query_idx] = if (lookup.get(key)) |found_idx|
                    std.math.cast(i64, found_idx) orelse return error.Unsupported
                else
                    miss_i64;
            } else {
                out[query_idx] = miss_i64;
            }
        }
    }

    fn tryFillFloatDenseAllMissByBounds(
        out: []i64,
        left_items: []const f64,
        right_items: []const f64,
        miss_i64: i64,
    ) bool {
        var have_left = false;
        var min_value: f64 = 0.0;
        var max_value: f64 = 0.0;
        for (left_items) |item| {
            if (item != item) continue;
            if (!have_left) {
                min_value = item;
                max_value = item;
                have_left = true;
                continue;
            }
            if (item < min_value) min_value = item;
            if (item > max_value) max_value = item;
        }
        if (!have_left) {
            @memset(out, miss_i64);
            return true;
        }

        for (right_items) |query| {
            if (query == query and query >= min_value and query <= max_value) return false;
        }

        @memset(out, miss_i64);
        return true;
    }

    fn fillFloatFindDenseHashedIntQueries(
        self: *Session,
        out: []i64,
        left_array: ?*HostDenseArray,
        left_items: []const f64,
        right_items: HostIntArrayView,
        miss_index: usize,
    ) KError!void {
        if (left_array) |array| {
            if (try self.ensureManagedHostFloatFindCache(array, left_items)) {
                const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
                const cache = array.find_cache.?;
                const keys = cache.keys.?;
                const slots = cache.slots.?;
                switch (right_items) {
                    .bit => |items| {
                        for (0..items.len) |query_idx| {
                            const query = @as(f64, @floatFromInt(@intFromBool(bitGet(items.words, query_idx))));
                            const key = floatFindHashKey(query) orelse unreachable;
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int8 => |items| {
                        for (items, 0..) |query, query_idx| {
                            const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int16 => |items| {
                        for (items, 0..) |query, query_idx| {
                            const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int32 => |items| {
                        for (items, 0..) |query, query_idx| {
                            const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int64 => |items| {
                        for (items, 0..) |query, query_idx| {
                            const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, key)) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                }
                return;
            }
        }

        var lookup = try DenseFindLookup.init(self.allocator, left_items.len);
        defer lookup.deinit();
        for (left_items, 0..) |item, idx| {
            const key = floatFindHashKey(item) orelse continue;
            lookup.insertFirst(key, idx);
        }

        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        switch (right_items) {
            .bit => |items| {
                for (0..items.len) |query_idx| {
                    const query = @as(f64, @floatFromInt(@intFromBool(bitGet(items.words, query_idx))));
                    const key = floatFindHashKey(query) orelse unreachable;
                    out[query_idx] = if (lookup.get(key)) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int8 => |items| {
                for (items, 0..) |query, query_idx| {
                    const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                    out[query_idx] = if (lookup.get(key)) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int16 => |items| {
                for (items, 0..) |query, query_idx| {
                    const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                    out[query_idx] = if (lookup.get(key)) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int32 => |items| {
                for (items, 0..) |query, query_idx| {
                    const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                    out[query_idx] = if (lookup.get(key)) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int64 => |items| {
                for (items, 0..) |query, query_idx| {
                    const key = floatFindHashKey(@as(f64, @floatFromInt(query))) orelse unreachable;
                    out[query_idx] = if (lookup.get(key)) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
        }
    }

    fn fillIntFindDenseHashedIntQueries(
        self: *Session,
        out: []i64,
        left_array: ?*HostDenseArray,
        left_items: HostIntArrayView,
        right_items: HostIntArrayView,
        miss_index: usize,
    ) KError!void {
        if (left_array) |array| {
            if (try self.ensureManagedHostIntFindCache(array)) {
                const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
                const cache = array.find_cache.?;
                const keys = cache.keys.?;
                const slots = cache.slots.?;
                switch (right_items) {
                    .bit => |items| {
                        for (0..items.len) |query_idx| {
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, intFindHashKey(@intFromBool(bitGet(items.words, query_idx))))) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int8 => |items| {
                        for (items, 0..) |query, query_idx| {
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, intFindHashKey(query))) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int16 => |items| {
                        for (items, 0..) |query, query_idx| {
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, intFindHashKey(query))) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int32 => |items| {
                        for (items, 0..) |query, query_idx| {
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, intFindHashKey(query))) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                    .int64 => |items| {
                        for (items, 0..) |query, query_idx| {
                            out[query_idx] = if (denseFindLookupGet(keys, slots, cache.mask, intFindHashKey(query))) |found_idx|
                                std.math.cast(i64, found_idx) orelse return error.Unsupported
                            else
                                miss_i64;
                        }
                    },
                }
                return;
            }
        }

        const left_len = hostIntArrayViewLen(left_items);
        var lookup = try DenseFindLookup.init(self.allocator, left_len);
        defer lookup.deinit();
        switch (left_items) {
            .bit => |items| {
                for (0..items.len) |idx| lookup.insertFirst(intFindHashKey(@intFromBool(bitGet(items.words, idx))), idx);
            },
            .int8 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
            .int16 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
            .int32 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
            .int64 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
        }

        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        switch (right_items) {
            .bit => |items| {
                for (0..items.len) |query_idx| {
                    out[query_idx] = if (lookup.get(intFindHashKey(@intFromBool(bitGet(items.words, query_idx))))) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int8 => |items| {
                for (items, 0..) |query, query_idx| {
                    out[query_idx] = if (lookup.get(intFindHashKey(query))) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int16 => |items| {
                for (items, 0..) |query, query_idx| {
                    out[query_idx] = if (lookup.get(intFindHashKey(query))) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int32 => |items| {
                for (items, 0..) |query, query_idx| {
                    out[query_idx] = if (lookup.get(intFindHashKey(query))) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
            .int64 => |items| {
                for (items, 0..) |query, query_idx| {
                    out[query_idx] = if (lookup.get(intFindHashKey(query))) |found_idx|
                        std.math.cast(i64, found_idx) orelse return error.Unsupported
                    else
                        miss_i64;
                }
            },
        }
    }

    fn fillIntFindDenseHashedFloatQueries(
        self: *Session,
        out: []i64,
        left_array: ?*HostDenseArray,
        left_items: HostIntArrayView,
        right_items: []const f64,
        miss_index: usize,
    ) KError!void {
        if (left_array) |array| {
            if (try self.ensureManagedHostIntFindCache(array)) {
                const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
                const cache = array.find_cache.?;
                const keys = cache.keys.?;
                const slots = cache.slots.?;
                for (right_items, 0..) |query, query_idx| {
                    const query_int = exactIntFromFloat(query);
                    out[query_idx] = if (query_int) |value|
                        if (denseFindLookupGet(keys, slots, cache.mask, intFindHashKey(value))) |found_idx|
                            std.math.cast(i64, found_idx) orelse return error.Unsupported
                        else
                            miss_i64
                    else
                        miss_i64;
                }
                return;
            }
        }

        const left_len = hostIntArrayViewLen(left_items);
        var lookup = try DenseFindLookup.init(self.allocator, left_len);
        defer lookup.deinit();
        switch (left_items) {
            .bit => |items| {
                for (0..items.len) |idx| lookup.insertFirst(intFindHashKey(@intFromBool(bitGet(items.words, idx))), idx);
            },
            .int8 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
            .int16 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
            .int32 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
            .int64 => |items| for (items, 0..) |item, idx| lookup.insertFirst(intFindHashKey(item), idx),
        }

        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        for (right_items, 0..) |query, query_idx| {
            const query_int = exactIntFromFloat(query);
            out[query_idx] = if (query_int) |value|
                if (lookup.get(intFindHashKey(value))) |found_idx|
                    std.math.cast(i64, found_idx) orelse return error.Unsupported
                else
                    miss_i64
            else
                miss_i64;
        }
    }

    fn fillFloatFindBruteForceFloatQueries(
        out: []i64,
        left_items: HostFloatDenseView,
        right_items: HostFloatDenseView,
        miss_index: usize,
    ) KError!void {
        const left_len = hostFloatDenseViewLen(left_items);
        const miss_i64 = std.math.cast(i64, miss_index) orelse return error.Unsupported;
        for (0..out.len) |query_idx| {
            const query = try hostFloatDenseViewItem(right_items, query_idx);
            if (query != query) {
                out[query_idx] = miss_i64;
                continue;
            }
            var found_idx = miss_i64;
            for (0..left_len) |idx| {
                if ((try hostFloatDenseViewItem(left_items, idx)) == query) {
                    found_idx = std.math.cast(i64, idx) orelse return error.Unsupported;
                    break;
                }
            }
            out[query_idx] = found_idx;
        }
    }

    fn fillFloatFindBruteForceIntQueries(
        out: []i64,
        left_items: HostFloatDenseView,
        right_items: HostIntDenseView,
