        while (scan > 0) {
            const run_end = scan;
            const run_value = items[run_end - 1];
            scan -= 1;
            while (scan > 0 and items[scan - 1] == run_value) : (scan -= 1) {
                unique = false;
            }
            for (scan..run_end) |idx| {
                out[out_idx] = idx;
                out_idx += 1;
            }
        }
        return unique;
