    fn materializeBackendArrayFromHandle(self: *Session, handle: *NumericArray) KError!mlx.Array {
        if (comptime runtime_has_mlx) {
            var profile_scope = self.beginSamplingProfileScope(.mlx_realization);
            defer profile_scope.end();
            if (try tryEnsureManagedBackendRealizationForHandle(self, handle)) |owned| {
                return owned.array.clone() catch |err| return mapMlxError(err);
            }
            if (numericArrayIsRangeIota(handle)) return try createBackendArrayFromRangeIota(self, handle);
            if (numericArrayIsFlatSlice(handle)) return try createBackendArrayFromFlatSlice(self, handle);
            if (numericArrayIsFlatConcat(handle)) return try createBackendArrayFromFlatConcat(self, handle);
            if (numericArrayIsFlatSegments(handle)) return try createBackendArrayFromFlatSegments(self, handle);
            if (numericArrayIsFirstAxisSlice(handle)) return try createBackendArrayFromFirstAxisSlice(self, handle);
            if (numericArrayIsFirstAxisIndex(handle)) return try createBackendArrayFromFirstAxisIndex(self, handle);
            if (numericArrayIsFirstAxisConcat(handle)) return try createBackendArrayFromFirstAxisConcat(self, handle);
            if (numericArrayIsReshapeView(handle)) return try createBackendArrayFromReshapeView(self, handle);
            if (numericArrayIsTransposeView(handle)) return try createBackendArrayFromTransposeView(self, handle);
            return try createBackendArrayFromHostArray(self, try hostStructuralArrayForHandle(self, handle));
        }
        return error.Unsupported;
    }

    fn materializeBackendArray(self: *Session, value: Value) KError!mlx.Array {
        return switch (value.tag()) {
            .int => blk: {
                const item = std.math.cast(i32, value.asInt()) orelse return error.Unsupported;
                break :blk mlx.Array.fromInt(item);
            },
            .float32 => mlx.Array.fromFloat(value.asFloat32()),
            .float => mlx.Array.fromFloat64(value.asFloat()),
            .bool => mlx.Array.fromInt(@intFromBool(value.asBool())),
            .array => blk: {
                if (valueNumericHandle(value)) |handle| break :blk try self.materializeBackendArrayFromHandle(@constCast(handle));
                break :blk switch (value.arraySubkind()) {
                    .host_dense_array => try createBackendArrayFromHostArray(self, value.asHostDenseArray()),
                    .backend_array => value.asBackendArray().array.clone() catch |err| return mapMlxError(err),
                    else => error.Internal,
                };
            },
            else => error.Type,
        };
    }

    fn negateIntValue(self: *Session, value: i64) KError!Value {
        const result = @subWithOverflow(@as(i64, 0), value);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn addIntValue(self: *Session, left: i64, right: i64) KError!Value {
        const result = @addWithOverflow(left, right);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn subIntValue(self: *Session, left: i64, right: i64) KError!Value {
        const result = @subWithOverflow(left, right);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn mulIntValue(self: *Session, left: i64, right: i64) KError!Value {
        const result = @mulWithOverflow(left, right);
        if (result[1] != 0) return error.Unsupported;
        return try self.intValue(result[0]);
    }

    fn classifyGlobalValue(value: Value) GlobalValueClass {
        return switch (value.tag()) {
            .int, .float, .float32, .bool => .scalar,
            .builtin => .builtin,
            .closure => .closure,
            .array => blk: {
                if (valueNonVectorNumericShape(value) == null) {
                    if (hostDenseIfPresent(value)) |host| {
                        break :blk switch (hostDenseNumericMode(host)) {
                            .int => .dense_int_vector,
                            .float => .dense_float_vector,
                        };
                    }
                }
                break :blk .array;
            },
        };
    }

    fn codeForStoredGlobal(value: Value) ?*const Code {
        if (value.tag() != .closure) return null;
        const closure = value.asClosure();
        if (closure.kind != .plain or closure.captures.len != 0) return null;
        return closure.code;
    }

    fn internGlobalSlot(self: *Session, name: []const u8) !u16 {
        if (self.global_slots.get(name)) |slot| return slot;

        const slot = std.math.cast(u16, self.global_cells.items.len) orelse return error.Unsupported;
        const owned_name = try self.arena.allocator().dupe(u8, name);
        try self.global_cells.append(self.allocator, .{});
        try self.global_names.append(self.allocator, owned_name);
        try self.debug_global_call_counts.append(self.allocator, 0);
        try self.global_slots.put(owned_name, slot);
        return slot;
    }

    fn storeGlobalSlot(self: *Session, slot: u16, value: Value) !void {
        if (slot >= self.global_cells.items.len) return error.Internal;
        const cell = &self.global_cells.items[slot];
        if (cell.initialized) self.releaseValue(cell.value);
        const stored = try self.retainGlobalStoredValue(value);
        const code = codeForStoredGlobal(stored);
        cell.* = .{
            .value = stored,
            .initialized = true,
            .class = classifyGlobalValue(stored),
            .code = code,
        };
    }

    pub fn debugGlobalIsFrozenClosure(self: *Session, name: []const u8) !bool {
        const slot = self.global_slots.get(name) orelse return error.Name;
        const value = try self.loadGlobalSlot(slot);
        return value.tag() == .closure and value.asClosure().header.owner == .frozen;
    }

    pub fn debugGlobalValue(self: *Session, name: []const u8) !Value {
        const slot = self.global_slots.get(name) orelse return error.Name;
        return try self.loadGlobalSlot(slot);
    }

    pub fn debugGlobalSlotCount(self: *const Session) usize {
        if (comptime !enable_probe_instrumentation) return 0;
        return self.global_names.items.len;
    }

    pub fn debugGlobalNameAt(self: *const Session, slot: usize) ?[]const u8 {
        if (comptime !enable_probe_instrumentation) return null;
        if (slot >= self.global_names.items.len) return null;
        return self.global_names.items[slot];
    }

    pub fn debugGlobalCallCountAt(self: *const Session, slot: usize) usize {
        if (comptime !enable_probe_instrumentation) return 0;
        if (slot >= self.debug_global_call_counts.items.len) return 0;
        return self.debug_global_call_counts.items[slot];
    }

    pub fn debugMakeManagedHostIntVector(self: *Session, data: []const i64) !Value {
        var min_value: i64 = 0;
        var max_value: i64 = 0;
        if (data.len != 0) {
            min_value = data[0];
            max_value = data[0];
            for (data[1..]) |item| {
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
        }
        var out = try self.allocManagedHostIntResult(hostIntStorageKindForRange(min_value, max_value), data.len);
        for (data, 0..) |item, idx| try out.set(idx, item);
        return try out.value(self);
    }

    pub fn debugMaterializeBackendArrayValue(self: *Session, value: Value) !void {
        var array = try self.materializeBackendArray(value);
        array.deinit();
    }

    pub fn debugEnsureHostRealizationValue(self: *Session, value: Value) !void {
        _ = try tryEnsureHostRealization(self, value) orelse return error.Unsupported;
    }

    pub const DebugHostCompareIntFloatStage = enum {
        views,
        scratch_kernel,
        managed_finish,
        full_fast,
        array_compare,
    };

    pub fn debugRunHostCompareIntFloatStage(
        self: *Session,
        stage: DebugHostCompareIntFloatStage,
        left: Value,
        right: Value,
        scratch_words: []u64,
    ) KError!void {
        switch (stage) {
            .views => {
                const prepared = (try self.prepareFastHostCompareIntFloat(.less, left, right)) orelse return error.Unsupported;
                std.mem.doNotOptimizeAway(prepared.len);
                std.mem.doNotOptimizeAway(prepared.int_ptr.width);
                std.mem.doNotOptimizeAway(prepared.int_left);
            },
            .scratch_kernel => {
                const prepared = (try self.prepareFastHostCompareIntFloat(.less, left, right)) orelse return error.Unsupported;
                if (scratch_words.len < bitWordCount(prepared.len)) return error.Type;
                kiwi_host_compare_int_f64_array(
                    scratch_words.ptr,
                    prepared.int_ptr.ptr,
                    prepared.int_ptr.width,
                    prepared.float_items.ptr,
                    prepared.len,
                    if (prepared.int_left) 1 else 0,
                    prepared.op_code,
                );
                var summary: HostCompareSummary = undefined;
                kiwi_host_compare_last_summary(&summary);
                std.mem.doNotOptimizeAway(summary);
                std.mem.doNotOptimizeAway(scratch_words[0]);
            },
            .managed_finish => {
                const prepared = (try self.prepareFastHostCompareIntFloat(.less, left, right)) orelse return error.Unsupported;
                const out = try self.allocHostBitArrayUninitialized(.managed, prepared.len);
                kiwi_host_compare_int_f64_array(
                    out.words.ptr,
                    prepared.int_ptr.ptr,
                    prepared.int_ptr.width,
                    prepared.float_items.ptr,
                    prepared.len,
                    if (prepared.int_left) 1 else 0,
                    prepared.op_code,
                );
                const value = try self.finishFastHostCompareResult(out, prepared.shape);
                defer self.discardValue(value);
                try self.forceValue(value);
            },
            .full_fast => {
                const shape = try nonVectorNumericShapeForDyad(left, right);
                const value = (try self.tryFastHostDenseCompare(.less, left, right, shape)) orelse return error.Unsupported;
                defer self.discardValue(value);
                try self.forceValue(value);
            },
            .array_compare => {
                const value = try self.compareNumericArrayValues(.less, left, right);
                defer self.discardValue(value);
                try self.forceValue(value);
            },
        }
    }

    fn loadGlobalSlot(self: *Session, slot: u16) KError!Value {
        return (try self.loadGlobalCell(slot)).value;
    }

    fn loadGlobalCell(self: *Session, slot: u16) KError!*GlobalCell {
        if (slot >= self.global_cells.items.len) return error.Internal;
        const cell = &self.global_cells.items[slot];
        if (!cell.initialized) return error.Name;
        return cell;
    }

    fn takeGlobalSlot(self: *Session, slot: u16) KError!Value {
        const cell = try self.loadGlobalCell(slot);
        const value = cell.value;
        cell.value = Value.fromBool(false);
        cell.class = classifyGlobalValue(cell.value);
        cell.code = null;
        return value;
    }

    fn noteGlobalCall(self: *Session, slot: u16) void {
        if (!self.debugDetailedProbeActive()) return;
        const idx: usize = slot;
        if (idx >= self.debug_global_call_counts.items.len) return;
        self.debug_global_call_counts.items[idx] += 1;
    }

    inline fn pop(self: *Session) Value {
        self.stack_len -= 1;
        return self.stack[self.stack_len];
    }

    inline fn peek(self: *Session) Value {
        return self.stack[self.stack_len - 1];
    }

    inline fn push(self: *Session, value: Value) KError!void {
        if (self.stack_len >= self.stack.len) return error.Unsupported;
        self.stack[self.stack_len] = value;
        self.stack_len += 1;
    }

    fn createOwnedHostIntArray(self: *Session, owner: HeapOwner, items: []const i64) !Value {
        const analysis = analyzeIntSlice(items);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, items.len);
        for (items, 0..) |item, idx| try out.set(idx, item);
        const value = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, analysis.flags);
        hostDenseSetCachedIntRange(host, analysis.range);
        return value;
    }

    fn createManagedHostIntArray(self: *Session, items: []const i64) !Value {
        return try self.createOwnedHostIntArray(.managed, items);
    }

    fn createOwnedHostBitArray(self: *Session, owner: HeapOwner, items: []const bool) !Value {
        var asc = true;
        var dsc = true;
        var saw_zero = items.len == 0;
        var saw_one = false;
        if (items.len != 0) {
            if (items[0]) saw_one = true else saw_zero = true;
            var prev = items[0];
            for (items[1..]) |item| {
                if (item) saw_one = true else saw_zero = true;
                if (@intFromBool(prev) > @intFromBool(item)) asc = false;
                if (@intFromBool(prev) < @intFromBool(item)) dsc = false;
                prev = item;
            }
        }

        var out = try self.allocOwnedHostIntResult(owner, .bit, items.len);
        for (items, 0..) |item, idx| try out.set(idx, @intFromBool(item));
        const value = try out.value(self);
        const host = try mutableNumericHostArrayValue(self, value);
        hostDenseSetFlags(host, host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostDenseSetCachedIntRange(host, .{
            .min = if (saw_zero) 0 else 1,
            .max = if (saw_one) 1 else 0,
        });
        return value;
    }

    fn createManagedHostBitArray(self: *Session, items: []const bool) !Value {
        return try self.createOwnedHostBitArray(.managed, items);
    }

    fn createOwnedHostFloatArray(self: *Session, owner: HeapOwner, items: []const f64) !Value {
        const analysis = analyzeFloatSlice(items);
        const out = try self.allocOwnedHostFloatResult(owner, items.len);
        @memcpy(out.items, items);
        const value = try out.value(self);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), analysis.flags);
        return value;
    }

    fn createOwnedHostFloat32Array(self: *Session, owner: HeapOwner, items: []const f32) !Value {
        const analysis = analyzeFloatSlice32(items);
        const out = try self.allocOwnedHostFloat32Result(owner, items.len);
        @memcpy(out.items, items);
        const value = try out.value(self);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), analysis.flags);
        return value;
    }

    fn createManagedHostFloatArray(self: *Session, items: []const f64) !Value {
        return try self.createOwnedHostFloatArray(.managed, items);
    }

    fn createManagedHostFloat32Array(self: *Session, items: []const f32) !Value {
        return try self.createOwnedHostFloat32Array(.managed, items);
    }

    fn createOwnedHostIntArrayFromValues(self: *Session, owner: HeapOwner, values: []const Value) !Value {
        if (values.len == 0) {
            var out = try self.allocOwnedHostIntResult(owner, .bit, 0);
            const value = try out.value(self);
            const host = try mutableNumericHostArrayValue(self, value);
            hostDenseSetFlags(host, host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc);
            hostDenseSetCachedIntRange(host, .{ .min = 0, .max = 0 });
            return value;
        }
        var all_bool = true;
        for (values) |value| {
            if (value.tag() != .bool) {
                all_bool = false;
                break;
            }
        }
        if (all_bool) {
            var bools = try self.allocator.alloc(bool, values.len);
            defer self.allocator.free(bools);
            for (values, 0..) |value, idx| bools[idx] = value.asBool();
            return try self.createOwnedHostBitArray(owner, bools);
        }
        var min_value = switch (values[0].tag()) {
            .int => values[0].asInt(),
            .bool => @intFromBool(values[0].asBool()),
            else => unreachable,
        };
        var max_value = min_value;
        var asc = true;
        var dsc = true;
        var prev = min_value;
        for (values[1..]) |value| {
            const int_value = switch (value.tag()) {
                .int => value.asInt(),
                .bool => @intFromBool(value.asBool()),
                else => unreachable,
            };
            min_value = @min(min_value, int_value);
            max_value = @max(max_value, int_value);
            if (prev > int_value) asc = false;
            if (prev < int_value) dsc = false;
            prev = int_value;
        }
        var out = try self.allocOwnedHostIntResult(owner, hostIntStorageKindForRange(min_value, max_value), values.len);
        for (values, 0..) |value, idx| {
            try out.set(idx, switch (value.tag()) {
                .int => value.asInt(),
                .bool => @intFromBool(value.asBool()),
                else => unreachable,
            });
        }
        const result = try out.value(self);
        const result_host = try mutableNumericHostArrayValue(self, result);
        hostDenseSetFlags(result_host, host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        hostDenseSetCachedIntRange(result_host, .{ .min = min_value, .max = max_value });
        return result;
    }

    fn createManagedHostIntArrayFromValues(self: *Session, values: []const Value) !Value {
        return try self.createOwnedHostIntArrayFromValues(.managed, values);
    }

    fn createOwnedHostFloatArrayFromValues(self: *Session, owner: HeapOwner, values: []const Value) !Value {
        if (values.len == 0) {
            const out = try self.allocOwnedHostFloatResult(owner, 0);
            const value = try out.value(self);
            hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc);
            return value;
        }

        var asc = true;
        var dsc = true;
        var prev = switch (values[0].tag()) {
            .int => @as(f64, @floatFromInt(values[0].asInt())),
            .bool => @as(f64, @floatFromInt(@intFromBool(values[0].asBool()))),
            .float32 => @as(f64, @floatCast(values[0].asFloat32())),
            .float => values[0].asFloat(),
            else => unreachable,
        };
        const out = try self.allocOwnedHostFloatResult(owner, values.len);
        for (values, 0..) |value, idx| {
            const float_value = switch (value.tag()) {
                .int => @as(f64, @floatFromInt(value.asInt())),
                .bool => @as(f64, @floatFromInt(@intFromBool(value.asBool()))),
                .float32 => @as(f64, @floatCast(value.asFloat32())),
                .float => value.asFloat(),
                else => unreachable,
            };
            out.items[idx] = float_value;
            if (idx != 0) {
                if (prev > float_value) asc = false;
                if (prev < float_value) dsc = false;
                prev = float_value;
            }
        }

        const result = try out.value(self);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        return result;
    }

    fn createOwnedHostFloat32ArrayFromValues(self: *Session, owner: HeapOwner, values: []const Value) !Value {
        if (values.len == 0) {
            const out = try self.allocOwnedHostFloat32Result(owner, 0);
            const value = try out.value(self);
            hostDenseSetFlags(try mutableNumericHostArrayValue(self, value), host_dense_flag_normalized | host_dense_flag_asc | host_dense_flag_dsc);
            return value;
        }

        var asc = true;
        var dsc = true;
        var prev = switch (values[0].tag()) {
            .int => @as(f32, @floatFromInt(values[0].asInt())),
            .bool => @as(f32, @floatFromInt(@intFromBool(values[0].asBool()))),
            .float32 => values[0].asFloat32(),
            .float => @as(f32, @floatCast(values[0].asFloat())),
            else => unreachable,
        };
        const out = try self.allocOwnedHostFloat32Result(owner, values.len);
        for (values, 0..) |value, idx| {
            const float_value = switch (value.tag()) {
                .int => @as(f32, @floatFromInt(value.asInt())),
                .bool => @as(f32, @floatFromInt(@intFromBool(value.asBool()))),
                .float32 => value.asFloat32(),
                .float => @as(f32, @floatCast(value.asFloat())),
                else => unreachable,
            };
            out.items[idx] = float_value;
            if (idx != 0) {
                if (prev > float_value) asc = false;
                if (prev < float_value) dsc = false;
                prev = float_value;
            }
        }

        const result = try out.value(self);
        hostDenseSetFlags(try mutableNumericHostArrayValue(self, result), host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc));
        return result;
    }

    fn createManagedHostFloatArrayFromValues(self: *Session, values: []const Value) !Value {
        return try self.createOwnedHostFloatArrayFromValues(.managed, values);
    }

    fn createManagedHostFloat32ArrayFromValues(self: *Session, values: []const Value) !Value {
        return try self.createOwnedHostFloat32ArrayFromValues(.managed, values);
    }

    fn ownedValueForOwner(self: *Session, owner: HeapOwner, value: Value) !Value {
        return switch (owner) {
            .managed => try self.retainEscapedValue(value),
            .frozen => try self.freezeConstantValue(value),
            .scratch => value,
        };
    }

    fn createOwnedHostBoxedArrayWithPrototype(self: *Session, owner: HeapOwner, values: []const Value, prototype: ?Value) !Value {
        const allocator = switch (owner) {
            .managed => self.allocator,
            .scratch => self.scratch_arena.allocator(),
            .frozen => self.arena.allocator(),
        };
        const array = if (owner == .managed and self.free_host_boxed_array_len != 0) blk: {
            self.free_host_boxed_array_len -= 1;
            break :blk self.free_host_boxed_arrays[self.free_host_boxed_array_len].?;
        } else try allocator.create(HostBoxedArray);
        errdefer allocator.destroy(array);
        const items = try allocator.alloc(Value, values.len);
        errdefer allocator.free(items);
        for (values, 0..) |value, idx| {
            items[idx] = try self.ownedValueForOwner(owner, value);
        }
        const stored_prototype = if (prototype) |item| try self.ownedValueForOwner(owner, item) else null;
        array.* = .{
            .header = HeapHeader.init(.host_boxed_array, owner),
            .logical_len = values.len,
            .items = items,
            .prototype = stored_prototype,
        };
        return Value.array(array);
    }

    fn createOwnedHostBoxedArray(self: *Session, owner: HeapOwner, values: []const Value) !Value {
        return try self.createOwnedHostBoxedArrayWithPrototype(owner, values, null);
    }

    fn createManagedHostBoxedArray(self: *Session, values: []const Value) !Value {
        return try self.createOwnedHostBoxedArray(.managed, values);
    }

    fn createManagedHostBoxedArrayWithPrototype(self: *Session, values: []const Value, prototype: ?Value) !Value {
        return try self.createOwnedHostBoxedArrayWithPrototype(.managed, values, prototype);
    }

    fn createManagedHostTableScalar(self: *Session, kind: HostTableColumnKind, value: Value, is_null: bool) !Value {
        const scalar = try self.allocator.create(HostTableScalar);
        errdefer self.allocator.destroy(scalar);
        scalar.* = .{
            .header = HeapHeader.init(.host_table_scalar, .managed),
            .kind = kind,
            .value = try self.retainEscapedValue(value),
            .is_null = is_null,
        };
        return Value.array(scalar);
    }

    fn createManagedFileRelation(self: *Session, source_kind: duckdb_runtime.SourceKind, path: []const u8) !Value {
        const relation = try self.allocator.create(HostRelation);
        errdefer self.allocator.destroy(relation);
        const owned_path = try self.allocator.dupe(u8, path);
        errdefer self.allocator.free(owned_path);
        relation.* = .{
            .header = HeapHeader.init(.host_relation, .managed),
            .origin = .{ .file = .{
                .source_kind = source_kind,
                .path = owned_path,
            } },
        };
        return Value.array(relation);
    }

    fn createManagedHostTable(self: *Session, row_count: usize, columns: []HostTableColumn) !Value {
        const name_values = try self.allocator.alloc(Value, columns.len);
        defer self.allocator.free(name_values);
        const data_values = try self.allocator.alloc(Value, columns.len);
        defer self.allocator.free(data_values);

        for (columns, 0..) |column, idx| {
            name_values[idx] = column.name;
            data_values[idx] = column.data;
        }

        const names = try self.createManagedHostBoxedArray(name_values);
        errdefer self.releaseValue(names);
        const values = try self.createManagedHostBoxedArray(data_values);
        errdefer self.releaseValue(values);
        const lookup = try self.createKeyedStoreLookupFromNamesValue(names);

        const metadata = try self.retainKeyedStoreColumnMetadataFromTable(columns);
        errdefer {
            for (metadata) |entry| {
                if (entry.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(metadata);
        }

        defer {
            for (columns) |column| {
                self.releaseValue(column.name);
                self.releaseValue(column.data);
                if (column.validity) |mask| self.releaseValue(mask);
            }
            self.allocator.free(columns);
        }

        const owned_path = try self.allocator.dupe(u8, "");
        errdefer self.allocator.free(owned_path);
        return try self.createManagedKeyedStore(owned_path, true, names, values, metadata, .table, row_count, lookup);
    }

    fn createManagedKeyedStore(
        self: *Session,
        path: []const u8,
        owns_path: bool,
        names: Value,
        values: Value,
        column_metadata: ?[]HostKeyedColumnMetadata,
        layout: HostKeyedLayout,
        row_count: usize,
        lookup: std.StringHashMapUnmanaged(usize),
    ) !Value {
        const store = try self.allocator.create(HostKeyedStore);
        errdefer self.allocator.destroy(store);
        store.* = .{
            .header = HeapHeader.init(.host_keyed_store, .managed),
            .layout = layout,
            .row_count = row_count,
            .path = path,
            .owns_path = owns_path,
            .names = names,
            .values = values,
            .column_metadata = column_metadata,
            .lookup = lookup,
        };
        return Value.array(store);
    }

    fn createManagedSqlRelation(self: *Session, sql_text: []const u8, params: []HostRelationParam) !Value {
        const relation = try self.allocator.create(HostRelation);
        errdefer self.allocator.destroy(relation);
        const owned_sql = try self.allocator.dupe(u8, sql_text);
        errdefer self.allocator.free(owned_sql);
        relation.* = .{
            .header = HeapHeader.init(.host_relation, .managed),
            .origin = .{ .sql = .{
                .text = owned_sql,
                .params = params,
            } },
        };
        return Value.array(relation);
    }

    fn createOwnedHostStringList(self: *Session, owner: HeapOwner, values: []const Value) !Value {
        const slices = try self.allocator.alloc([]const u8, values.len);
        defer self.allocator.free(slices);
        for (values, 0..) |value, idx| {
            slices[idx] = stringBytes(value) orelse return error.Type;
        }
        return try self.createOwnedHostStringListFromSlices(owner, slices);
    }

    fn createManagedHostStringList(self: *Session, values: []const Value) !Value {
        return try self.createOwnedHostStringList(.managed, values);
    }

    fn createOwnedHostTextListFromSlicesKind(
        self: *Session,
        owner: HeapOwner,
        list_kind: HeapKind,
        text_kind: HeapKind,
        display: HostStringListDisplay,
        items: []const []const u8,
    ) !Value {
        std.debug.assert(list_kind == .host_string_list or list_kind == .host_symbol_list);
        std.debug.assert(text_kind == .host_string or text_kind == .host_symbol);
        const allocator = switch (owner) {
            .managed => self.allocator,
            .scratch => self.scratch_arena.allocator(),
            .frozen => self.arena.allocator(),
        };
        const buf = try hostStringListAllocSlice(allocator, items.len);
        errdefer allocator.free(buf);
        const list = hostStringListFromAlloc(buf);
        const pieces = hostStringListItemsFromAlloc(buf, items.len);
        var bytes_len: usize = 0;

        for (items) |item| {
            bytes_len = std.math.add(usize, bytes_len, item.len) catch return error.Unsupported;
        }

        const base: ?*HostText = if (items.len == 0) null else blk: {
            const base_buf = try hostTextAllocSlice(allocator, bytes_len);
            errdefer allocator.free(base_buf);
            const text = hostTextFromAlloc(base_buf);
            const payload = hostTextBytesFromAlloc(base_buf, bytes_len);
            var offset: usize = 0;
            for (items, 0..) |item, idx| {
                @memcpy(payload[offset .. offset + item.len], item);
                pieces[idx] = .{ .view = .{
                    .start = offset,
                    .len = item.len,
                } };
                offset += item.len;
            }
            std.debug.assert(offset == bytes_len);
            text.* = .{
                .header = HeapHeader.init(text_kind, owner),
                .len = bytes_len,
            };
            break :blk text;
        };
        list.* = .{
            .header = HeapHeader.init(list_kind, owner),
            .len = items.len,
            .bytes_len = bytes_len,
            .base = base,
            .storage = .{ .eager = pieces },
            .display = display,
        };
        return Value.array(list);
    }

    fn createOwnedHostStringListFromSlices(self: *Session, owner: HeapOwner, items: []const []const u8) !Value {
        return try self.createOwnedHostTextListFromSlicesKind(owner, .host_string_list, .host_string, .list, items);
    }

    fn createOwnedHostStringRowsFromSlices(self: *Session, owner: HeapOwner, items: []const []const u8) !Value {
        return try self.createOwnedHostTextListFromSlicesKind(owner, .host_string_list, .host_string, .char_rows, items);
    }

    fn createOwnedHostSymbolListFromSlices(self: *Session, owner: HeapOwner, items: []const []const u8) !Value {
        return try self.createOwnedHostTextListFromSlicesKind(owner, .host_symbol_list, .host_symbol, .list, items);
    }

    fn createManagedHostStringListPiecesWithDisplay(self: *Session, base: ?*HostText, pieces: []const HostStringPiece, display: HostStringListDisplay) !Value {
        const buf = try hostStringListAllocSlice(self.allocator, pieces.len);
        errdefer self.allocator.free(buf);
        const list = hostStringListFromAlloc(buf);
        const items = hostStringListItemsFromAlloc(buf, pieces.len);
        var bytes_len: usize = 0;

        if (base) |shared| _ = self.retainValue(Value.array(shared));
        errdefer if (base) |shared| self.releaseValue(Value.array(shared));

        var initialized: usize = 0;
        errdefer {
            for (items[0..initialized]) |item| self.releaseHostStringPiece(item);
        }
        for (pieces, 0..) |piece, idx| {
            items[idx] = piece;
            self.retainHostStringPiece(piece);
            bytes_len = std.math.add(usize, bytes_len, hostStringPieceBytes(base, piece).len) catch return error.Unsupported;
            initialized += 1;
        }
        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = pieces.len,
            .bytes_len = bytes_len,
            .base = base,
            .storage = .{ .eager = items },
            .display = display,
        };
        return Value.array(list);
    }

    fn createManagedHostStringListPieces(self: *Session, base: ?*HostText, pieces: []const HostStringPiece) !Value {
        return try self.createManagedHostStringListPiecesWithDisplay(base, pieces, .list);
    }

    fn createManagedHostStringListLazyScalarWithDisplay(self: *Session, base: *HostText, sep: u8, count: usize, bytes_len: usize, display: HostStringListDisplay) !Value {
        const list = try self.allocator.create(HostStringList);
        errdefer self.allocator.destroy(list);
        _ = self.retainValue(Value.array(base));
        errdefer self.releaseValue(Value.array(base));
        list.* = .{
            .header = HeapHeader.init(.host_string_list, .managed),
            .len = count,
            .bytes_len = bytes_len,
            .base = base,
            .storage = .{ .split_scalar = .{ .sep = sep } },
            .display = display,
        };
        return Value.array(list);
    }

    fn createManagedHostStringListLazyScalar(self: *Session, base: *HostText, sep: u8, count: usize, bytes_len: usize) !Value {
        return try self.createManagedHostStringListLazyScalarWithDisplay(base, sep, count, bytes_len, .list);
    }

    fn createManagedHostStringListFromSlices(self: *Session, items: []const []const u8) !Value {
        return try self.createOwnedHostStringListFromSlices(.managed, items);
    }

    fn createManagedHostStringRowsFromSlices(self: *Session, items: []const []const u8) !Value {
        return try self.createOwnedHostStringRowsFromSlices(.managed, items);
    }

    fn createManagedHostSymbolListFromSlices(self: *Session, items: []const []const u8) !Value {
        return try self.createOwnedHostSymbolListFromSlices(.managed, items);
    }

    fn retainHostStringPiece(self: *Session, piece: HostStringPiece) void {
        switch (piece) {
            .owned => |text| _ = self.retainValue(Value.array(text)),
            .view => {},
        }
    }

    fn releaseHostStringPiece(self: *Session, piece: HostStringPiece) void {
        switch (piece) {
            .owned => |text| self.releaseValue(Value.array(text)),
            .view => {},
        }
    }
};

const CompiledSource = struct {
    source: []const u8,
    code: *const Code,
};

const HostIntArrayView = union(HostIntStorageKind) {
    bit: HostBitSlice,
    int8: []const i8,
    int16: []const i16,
    int32: []const i32,
    int64: []const i64,
};

const HostIntResult = union(HostIntStorageKind) {
    bit: HostBitAlloc,
    int8: HostDenseAlloc(i8),
    int16: HostDenseAlloc(i16),
    int32: HostDenseAlloc(i32),
    int64: HostDenseAlloc(i64),

    fn set(self: *HostIntResult, idx: usize, item_value: i64) KError!void {
        switch (self.*) {
            .bit => |*out| switch (item_value) {
                0 => bitSet(out.words, idx, false),
                1 => bitSet(out.words, idx, true),
                else => return error.Unsupported,
            },
            .int8 => |*out| out.items[idx] = std.math.cast(i8, item_value) orelse return error.Unsupported,
            .int16 => |*out| out.items[idx] = std.math.cast(i16, item_value) orelse return error.Unsupported,
            .int32 => |*out| out.items[idx] = std.math.cast(i32, item_value) orelse return error.Unsupported,
            .int64 => |*out| out.items[idx] = item_value,
        }
    }

    fn value(self: *const HostIntResult, session: *Session) !Value {
        return try wrapOwnedHostArrayValue(session, self.arrayPtr());
    }

    fn arrayPtr(self: *const HostIntResult) *HostDenseArray {
        return switch (self.*) {
            .bit => |out| out.array,
            .int8 => |out| out.array,
            .int16 => |out| out.array,
            .int32 => |out| out.array,
            .int64 => |out| out.array,
        };
    }
};

const HostFloatResult = struct {
    array: *HostDenseArray,
    items: []f64,

    fn value(self: HostFloatResult, session: *Session) !Value {
        return try wrapOwnedHostArrayValue(session, self.array);
    }
};

const HostFloat32Result = struct {
    array: *HostDenseArray,
    items: []f32,

    fn value(self: HostFloat32Result, session: *Session) !Value {
        return try wrapOwnedHostArrayValue(session, self.array);
    }
};

const DictTableColumnSource = union(enum) {
    scalar_bool: bool,
    scalar_int: i64,
    scalar_float: f64,
    scalar_text: Value,
    retained: Value,
    boxed_values: []const Value,
};

const DictTableColumnSpec = struct {
    kind: HostTableColumnKind,
    len: usize,
    scalar_extend: bool,
    source: DictTableColumnSource,
};

fn hostIntResultSet(result: *HostIntResult, idx: usize, item_value: i64) KError!void {
    return result.set(idx, item_value);
}

fn hostIntResultArrayPtr(result: *const HostIntResult) *HostDenseArray {
    return result.arrayPtr();
}

fn wasmAcceleratorPayload(self: *Session, value: Value) KError!?*BackendArray {
    if (value.tag() != .array) return null;

    return switch (value.arraySubkind()) {
        .backend_array => @constCast(value.asBackendArray()),
        .numeric_array, .host_dense_array => try tryEnsureManagedBackendRealization(self, value) orelse return null,
        else => null,
    };
}

const HostIntOutputPlan = struct {
    output: HostIntResult,
    kind: HostIntStorageKind,
    reused: bool,
    unchecked_safe: bool,
    shape: ?NumericShapeSnapshot = null,
};

const HostFloatOutputPlan = struct {
    output: HostFloatResult,
    reused: bool,
    shape: ?NumericShapeSnapshot = null,
};

const HostFloat32OutputPlan = struct {
    output: HostFloat32Result,
    reused: bool,
    shape: ?NumericShapeSnapshot = null,
};

const HostFloatStorageKind = enum {
    float32,
    float64,
};

const HostArrayNormalizationPlan = union(enum) {
    int: struct {
        view: HostIntArrayView,
        kind: HostIntStorageKind,
        flags: u8,
    },
    float: struct {
        items: []const f64,
        flags: u8,
    },
    float32: struct {
        items: []const f32,
        flags: u8,
    },
};

fn copyHostIntViewToResult(out: *HostIntResult, view: HostIntArrayView) KError!void {
    switch (out.*) {
        .bit => |*result| switch (view) {
            .bit => |items| {
                std.debug.assert(result.words.len == items.words.len);
                @memcpy(result.words, items.words);
            },
            else => switch (view) {
                .bit => unreachable,
                .int8 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int16 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int32 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int64 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
            },
        },
        .int8 => |*result| switch (view) {
            .int8 => |items| {
                std.debug.assert(result.items.len == items.len);
                @memcpy(result.items, items);
            },
            else => switch (view) {
                .bit => |items| for (0..items.len) |idx| try out.set(idx, @intFromBool(bitGet(items.words, idx))),
                .int8 => unreachable,
                .int16 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int32 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int64 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
            },
        },
        .int16 => |*result| switch (view) {
            .int16 => |items| {
                std.debug.assert(result.items.len == items.len);
                @memcpy(result.items, items);
            },
            else => switch (view) {
                .bit => |items| for (0..items.len) |idx| try out.set(idx, @intFromBool(bitGet(items.words, idx))),
                .int8 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int16 => unreachable,
                .int32 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int64 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
            },
        },
        .int32 => |*result| switch (view) {
            .int32 => |items| {
                std.debug.assert(result.items.len == items.len);
                @memcpy(result.items, items);
            },
            else => switch (view) {
                .bit => |items| for (0..items.len) |idx| try out.set(idx, @intFromBool(bitGet(items.words, idx))),
                .int8 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int16 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int32 => unreachable,
                .int64 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
            },
        },
        .int64 => |*result| switch (view) {
            .int64 => |items| {
                std.debug.assert(result.items.len == items.len);
                @memcpy(result.items, items);
            },
            else => switch (view) {
                .bit => |items| for (0..items.len) |idx| try out.set(idx, @intFromBool(bitGet(items.words, idx))),
                .int8 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int16 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int32 => |items| for (items, 0..) |item, idx| try out.set(idx, item),
                .int64 => unreachable,
            },
        },
    }
}

fn hostIntArrayView(array: *const HostDenseArray) ?HostIntArrayView {
    return switch (array.storage) {
        .bit => |words| .{ .bit = .{ .words = hostDenseLogicalBitWords(array, words), .len = array.logical_len } },
        .int8 => |items| .{ .int8 = hostDenseLogicalItems(i8, array, items) },
        .int16 => |items| .{ .int16 = hostDenseLogicalItems(i16, array, items) },
        .int32 => |items| .{ .int32 = hostDenseLogicalItems(i32, array, items) },
        .int64 => |items| .{ .int64 = hostDenseLogicalItems(i64, array, items) },
        .float32, .float64 => null,
    };
}

fn hostIntArrayViewKind(view: HostIntArrayView) HostIntStorageKind {
    return std.meta.activeTag(view);
}

fn hostIntArrayViewLen(view: HostIntArrayView) usize {
    return switch (view) {
        .bit => |items| items.len,
        .int8 => |items| items.len,
        .int16 => |items| items.len,
        .int32 => |items| items.len,
        .int64 => |items| items.len,
    };
}

fn hostIntArrayViewRange(view: HostIntArrayView) HostIntRange {
    return switch (view) {
        .bit => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var saw_zero = false;
            var saw_one = false;
            if (items.words.len != 0) {
                for (items.words, 0..) |word, idx| {
                    const masked = if (idx + 1 == items.words.len) word & bitTailMask(items.len) else word;
                    if (masked != 0) saw_one = true;
                    const valid_mask = if (idx + 1 == items.words.len) bitTailMask(items.len) else std.math.maxInt(u64);
                    if (masked != valid_mask) saw_zero = true;
                    if (saw_zero and saw_one) break;
                }
            }
            break :blk .{
                .min = if (saw_zero) 0 else 1,
                .max = if (saw_one) 1 else 0,
            };
        },
        .int8 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value: i64 = items[0];
            var max_value: i64 = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, @as(i64, item));
                max_value = @max(max_value, @as(i64, item));
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .int16 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value: i64 = items[0];
            var max_value: i64 = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, @as(i64, item));
                max_value = @max(max_value, @as(i64, item));
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .int32 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value: i64 = items[0];
            var max_value: i64 = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, @as(i64, item));
                max_value = @max(max_value, @as(i64, item));
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .int64 => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = items[0];
            var max_value = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
    };
}

fn hostIntArrayViewEndpointRange(view: HostIntArrayView, flags: u8) ?HostIntRange {
    const mono = monotonicFlags(flags);
    if (mono == 0) return null;
    if (hostIntArrayViewLen(view) == 0) return .{ .min = 0, .max = 0 };
    const first = hostIntViewItem(view, 0);
    const last = hostIntViewItem(view, hostIntArrayViewLen(view) - 1);
    if ((mono & host_dense_flag_asc) != 0) return .{ .min = first, .max = last };
    if ((mono & host_dense_flag_dsc) != 0) return .{ .min = last, .max = first };
    return null;
}

fn hostIntArrayViewStorageRange(view: HostIntArrayView) ?HostIntRange {
    return switch (view) {
        .bit => .{ .min = 0, .max = 1 },
        .int8 => .{ .min = std.math.minInt(i8), .max = std.math.maxInt(i8) },
        .int16 => .{ .min = std.math.minInt(i16), .max = std.math.maxInt(i16) },
        .int32 => .{ .min = std.math.minInt(i32), .max = std.math.maxInt(i32) },
        .int64 => null,
    };
}

fn hostIntAddFoldProofRange(array: *const HostDenseArray, view: HostIntArrayView) ?HostIntRange {
    return hostDenseCachedIntRange(array) orelse hostIntArrayViewEndpointRange(view, array.flags) orelse hostIntArrayViewStorageRange(view);
}

fn hostIntViewItem(view: HostIntArrayView, idx: usize) i64 {
    return switch (view) {
        .bit => |items| @intFromBool(bitGet(items.words, idx)),
        .int8 => |items| items[idx],
        .int16 => |items| items[idx],
        .int32 => |items| items[idx],
        .int64 => |items| items[idx],
    };
}

fn hostRangeIotaViewLen(view: HostRangeIotaView) usize {
    return numericArrayRangeLen(view.handle);
}

fn hostRangeIotaViewBounds(view: HostRangeIotaView) HostIntRange {
    return numericArrayRangeIotaBounds(view.handle);
}

fn hostRangeIotaViewFlags(view: HostRangeIotaView) u8 {
    const len = hostRangeIotaViewLen(view);
    const mono = if (len <= 1)
        host_dense_flag_asc | host_dense_flag_dsc
    else
        orderFlagsFromMonotonic(numericArrayRangeIota(view.handle).step >= 0, numericArrayRangeIota(view.handle).step <= 0);
    return host_dense_flag_normalized | mono;
}

fn hostRangeIotaViewItem(view: HostRangeIotaView, idx: usize) KError!i64 {
    return numericArrayRangeIotaValueAt(view.handle, idx);
}

fn hostIntDenseViewKind(view: HostIntDenseView) HostIntStorageKind {
    return switch (view) {
        .dense => |items| hostIntArrayViewKind(items),
        .range_iota => |items| blk: {
            const bounds = hostRangeIotaViewBounds(items);
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_slice => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_slice = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_stride => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_stride = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_concat => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_concat = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .flat_segments => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .flat_segments = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .first_axis_slice => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .first_axis_slice = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .first_axis_index => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .first_axis_index = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .first_axis_concat => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .first_axis_concat = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
        .transpose => |items| blk: {
            const bounds = hostIntDenseViewRange(.{ .transpose = items });
            break :blk hostIntStorageKindForRange(bounds.min, bounds.max);
        },
    };
}

fn hostIntDenseViewLen(view: HostIntDenseView) usize {
    return switch (view) {
        .dense => |items| hostIntArrayViewLen(items),
        .range_iota => |items| hostRangeIotaViewLen(items),
        .flat_slice => |items| items.len,
        .flat_stride => |items| items.len,
        .flat_concat => |items| items.len,
        .flat_segments => |items| items.len,
        .first_axis_slice => |items| items.len,
        .first_axis_index => |items| items.len,
        .first_axis_concat => |items| items.len,
        .transpose => |items| hostTransposeViewLen(items),
    };
}

fn hostIntDenseViewRange(view: HostIntDenseView) HostIntRange {
    return switch (view) {
        .dense => |items| hostIntArrayViewRange(items),
        .range_iota => |items| hostRangeIotaViewBounds(items),
        .flat_slice => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_slice = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_slice = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .flat_stride => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_stride = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_stride = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .flat_concat => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_concat = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_concat = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .flat_segments => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .flat_segments = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .flat_segments = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .first_axis_slice => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .first_axis_slice = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .first_axis_slice = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .first_axis_index => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .first_axis_index = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .first_axis_index = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .first_axis_concat => |items| blk: {
            if (items.len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .first_axis_concat = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..items.len) |idx| {
                const value = hostIntDenseViewItem(.{ .first_axis_concat = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        .transpose => |items| blk: {
            const len = hostTransposeViewLen(items);
            if (len == 0) break :blk .{ .min = 0, .max = 0 };
            var min_value = hostIntDenseViewItem(.{ .transpose = items }, 0) catch unreachable;
            var max_value = min_value;
            for (1..len) |idx| {
                const value = hostIntDenseViewItem(.{ .transpose = items }, idx) catch unreachable;
                min_value = @min(min_value, value);
                max_value = @max(max_value, value);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
    };
}

fn hostFirstAxisSliceFlatIndex(view: HostFirstAxisSliceView, idx: usize) KError!usize {
    if (idx >= view.len) return error.Internal;
    if (view.row_width == 0) return error.Internal;
    if (view.row_step == 1) return view.start_row * view.row_width + idx;

    const row_idx = idx / view.row_width;
    const col_idx = idx % view.row_width;
    const source_row_i64 = @as(i64, @intCast(view.start_row)) + @as(i64, @intCast(row_idx)) * @as(i64, view.row_step);
    if (source_row_i64 < 0) return error.Internal;
    return @as(usize, @intCast(source_row_i64)) * view.row_width + col_idx;
}

fn hostFirstAxisSliceIntItem(view: HostFirstAxisSliceView, idx: usize) KError!i64 {
    const flat_idx = try hostFirstAxisSliceFlatIndex(view, idx);
    if (view.source_host) |array| return try hostDenseIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

fn hostFirstAxisSliceFloatItem(view: HostFirstAxisSliceView, idx: usize) KError!f64 {
    const flat_idx = try hostFirstAxisSliceFlatIndex(view, idx);
    if (view.source_host) |array| return try hostDenseFloatAt(array, flat_idx);
    return try numericFloatAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexSourceRow(view: HostFirstAxisIndexView, row_pos: usize) KError!usize {
    if (view.row_width == 0) return error.Internal;
    if (row_pos >= view.len / view.row_width) return error.Internal;
    const source_row_i64 = try numericIntAt(view.row_indices, row_pos);
    if (source_row_i64 < 0) return error.Internal;
    return @as(usize, @intCast(source_row_i64));
}

fn hostFirstAxisIndexSourceIntAt(view: HostFirstAxisIndexView, flat_idx: usize) KError!i64 {
    if (view.source_host) |array| return try hostDenseIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexSourceFloatAt(view: HostFirstAxisIndexView, flat_idx: usize) KError!f64 {
    if (view.source_host) |array| return try hostDenseFloatAt(array, flat_idx);
    return try numericFloatAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexFlatIndex(view: HostFirstAxisIndexView, idx: usize) KError!usize {
    if (idx >= view.len) return error.Internal;
    if (view.row_width == 0) return error.Internal;
    const row_pos = idx / view.row_width;
    const col_idx = idx % view.row_width;
    const source_row = try hostFirstAxisIndexSourceRow(view, row_pos);
    return source_row * view.row_width + col_idx;
}

fn hostFirstAxisIndexIntItem(view: HostFirstAxisIndexView, idx: usize) KError!i64 {
    const flat_idx = try hostFirstAxisIndexFlatIndex(view, idx);
    if (view.source_host) |array| return try hostDenseIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

fn hostFirstAxisIndexFloatItem(view: HostFirstAxisIndexView, idx: usize) KError!f64 {
    const flat_idx = try hostFirstAxisIndexFlatIndex(view, idx);
    if (view.source_host) |array| return try hostDenseFloatAt(array, flat_idx);
    return try numericFloatAt(view.source_value, flat_idx);
}

fn hostFirstAxisConcatIntItem(view: HostFirstAxisConcatView, idx: usize) KError!i64 {
    if (idx >= view.len) return error.Internal;
    if (idx < view.left_len) {
        if (view.left_host) |array| return try hostDenseIntAt(array, idx);
        return try numericIntAt(view.left_value, idx);
    }
    const right_idx = idx - view.left_len;
    if (view.right_host) |array| return try hostDenseIntAt(array, right_idx);
    return try numericIntAt(view.right_value, right_idx);
}

fn hostFirstAxisConcatFloatItem(view: HostFirstAxisConcatView, idx: usize) KError!f64 {
    if (idx >= view.len) return error.Internal;
    if (idx < view.left_len) {
        if (view.left_host) |array| return try hostDenseFloatAt(array, idx);
        return try numericFloatAt(view.left_value, idx);
    }
    const right_idx = idx - view.left_len;
    if (view.right_host) |array| return try hostDenseFloatAt(array, right_idx);
    return try numericFloatAt(view.right_value, right_idx);
}

fn hostFlatSliceIntItem(view: HostFlatSliceView, idx: usize) KError!i64 {
    if (idx >= view.len) return error.Internal;
    const flat_idx = view.start + idx;
    if (view.source_host) |array| return try hostDenseIntAt(array, flat_idx);
    return try numericIntAt(view.source_value, flat_idx);
}

