fn hostTransposeViewLen(view: HostTransposeView) usize {
    return view.source_rows * view.source_cols;
}

fn hostTransposeSourceIndex(view: HostTransposeView, idx: usize) KError!usize {
    const len = hostTransposeViewLen(view);
    if (idx >= len) return error.Internal;
    const out_row = idx / view.source_rows;
    const out_col = idx % view.source_rows;
    return out_col * view.source_cols + out_row;
}

fn hostTransposeIntItem(view: HostTransposeView, idx: usize) KError!i64 {
    const source_idx = try hostTransposeSourceIndex(view, idx);
    if (view.source_host) |array| return try hostDenseIntAt(array, source_idx);
    return try numericIntAt(view.source_value, source_idx);
}

