fn hostIntDenseViewItem(view: HostIntDenseView, idx: usize) KError!i64 {
    return switch (view) {
        .dense => |items| hostIntViewItem(items, idx),
        .range_iota => |items| try hostRangeIotaViewItem(items, idx),
        .flat_slice => |items| try hostFlatSliceIntItem(items, idx),
        .flat_stride => |items| try hostFlatStrideIntItem(items, idx),
        .flat_concat => |items| try hostFirstAxisConcatIntItem(items, idx),
        .flat_segments => |items| try hostFlatSegmentsIntItem(items, idx),
        .first_axis_slice => |items| try hostFirstAxisSliceIntItem(items, idx),
        .first_axis_index => |items| try hostFirstAxisIndexIntItem(items, idx),
        .first_axis_concat => |items| try hostFirstAxisConcatIntItem(items, idx),
        .transpose => |items| try hostTransposeIntItem(items, idx),
    };
}

fn hostIntDenseValueFlags(value: Value, view: HostIntDenseView) u8 {
    return switch (view) {
        .dense => switch (value.arrayKind()) {
            .host_dense_array => value.asHostDenseArray().flags,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (numericHostAttachment(handle)) |array| break :blk array.flags;
                if (numericArrayIsRangeIota(handle)) break :blk hostRangeIotaViewFlags(.{ .handle = handle });
                break :blk 0;
            },
            .backend_array => blk: {
                const handle = valueNumericHandle(value) orelse break :blk 0;
                if (numericHostAttachment(handle)) |array| break :blk array.flags;
                break :blk 0;
            },
            else => 0,
        },
        .range_iota => |items| hostRangeIotaViewFlags(items),
        .flat_slice => |items| hostFlatSliceIntFlags(items),
        .flat_stride => |items| hostFlatStrideIntFlags(items),
        .flat_concat => |items| hostFirstAxisConcatIntFlags(items),
        .flat_segments => |items| hostFlatSegmentsIntFlags(items),
        .first_axis_slice => |items| hostFirstAxisSliceIntFlags(items),
        .first_axis_index => |items| hostFirstAxisIndexIntFlags(items),
        .first_axis_concat => |items| hostFirstAxisConcatIntFlags(items),
        .transpose => |items| hostTransposeIntFlags(items),
    };
}

fn hostIntDenseValueRange(value: Value, view: HostIntDenseView) HostIntRange {
    return switch (view) {
        .dense => |items| switch (value.arrayKind()) {
            .host_dense_array => hostDenseCachedIntRange(value.asHostDenseArray()) orelse
                hostIntArrayViewEndpointRange(items, value.asHostDenseArray().flags) orelse
                hostIntArrayViewRange(items),
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (numericHostAttachment(handle)) |array| {
                    break :blk hostDenseCachedIntRange(array) orelse
                        hostIntArrayViewEndpointRange(items, array.flags) orelse
                        hostIntArrayViewRange(items);
                }
                if (numericArrayIsRangeIota(handle)) break :blk numericArrayRangeIotaBounds(handle);
                break :blk hostIntArrayViewRange(items);
            },
            .backend_array => blk: {
                const handle = valueNumericHandle(value) orelse break :blk hostIntArrayViewRange(items);
                if (numericHostAttachment(handle)) |array| {
                    break :blk hostDenseCachedIntRange(array) orelse
                        hostIntArrayViewEndpointRange(items, array.flags) orelse
                        hostIntArrayViewRange(items);
                }
                break :blk hostIntArrayViewRange(items);
            },
            else => hostIntArrayViewRange(items),
        },
        .range_iota => |items| hostRangeIotaViewBounds(items),
        .flat_slice => |_| hostIntDenseViewRange(view),
        .flat_stride => |_| hostIntDenseViewRange(view),
        .flat_concat => |_| hostIntDenseViewRange(view),
        .flat_segments => |_| hostIntDenseViewRange(view),
        .first_axis_slice => |_| hostIntDenseViewRange(view),
        .first_axis_index => |_| hostIntDenseViewRange(view),
        .first_axis_concat => |_| hostIntDenseViewRange(view),
        .transpose => |_| hostIntDenseViewRange(view),
    };
}

fn hostBitSliceContiguousTrueRun(mask: HostBitSlice) ?ContiguousIndexSlice {
    var start: ?usize = null;
    var run_len: usize = 0;
    var saw_gap_after_run = false;
    for (0..mask.len) |idx| {
        const bit = bitGet(mask.words, idx);
        if (bit) {
            if (saw_gap_after_run) return null;
            if (start == null) start = idx;
            run_len += 1;
        } else if (start != null and run_len != 0) {
            saw_gap_after_run = true;
        }
    }
    return .{
        .start = start orelse 0,
        .len = run_len,
    };
}

fn hostRangeIotaViewArithmeticSlice(view: HostRangeIotaView, len: usize) ?ArithmeticIndexSlice {
    const slice_len = hostRangeIotaViewLen(view);
    if (slice_len == 0) return .{ .start = 0, .len = 0, .step = 1 };

    const start_raw = numericArrayRangeIota(view.handle).start;
    const step = std.math.cast(i32, numericArrayRangeIota(view.handle).step) orelse return null;
    if (step == 0) return null;

    const len_i64 = std.math.cast(i64, len) orelse return null;
    if (start_raw < 0 or start_raw >= len_i64) return null;

    const span_i64 = std.math.mul(i64, @as(i64, @intCast(slice_len - 1)), @as(i64, step)) catch return null;
    const last_raw = std.math.add(i64, start_raw, span_i64) catch return null;
    if (last_raw < 0 or last_raw >= len_i64) return null;

    return .{
        .start = @as(usize, @intCast(start_raw)),
        .len = slice_len,
        .step = step,
    };
}

fn hostIntDenseViewArithmeticSlice(view: HostIntDenseView, len: usize) KError!?ArithmeticIndexSlice {
    return switch (view) {
        .dense => |items| switch (items) {
            .bit => |bits| blk: {
                if (bits.len != len) break :blk null;
                const run = hostBitSliceContiguousTrueRun(bits) orelse break :blk null;
                break :blk .{ .start = run.start, .len = run.len, .step = 1 };
            },
            else => blk: {
                const slice_len = hostIntArrayViewLen(items);
                if (slice_len == 0) break :blk .{ .start = 0, .len = 0, .step = 1 };
                const start = try normalizeIndex(hostIntViewItem(items, 0), len);
                if (slice_len == 1) break :blk .{ .start = start, .len = 1, .step = 1 };
                const second = try normalizeIndex(hostIntViewItem(items, 1), len);
                const step_i64 = @as(i64, @intCast(second)) - @as(i64, @intCast(start));
                if (step_i64 == 0) break :blk null;
                const step = std.math.cast(i32, step_i64) orelse break :blk null;
                for (1..slice_len) |idx| {
                    const expected_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(idx)) * @as(i64, step);
                    if (expected_i64 < 0 or expected_i64 >= len) break :blk null;
                    if (try normalizeIndex(hostIntViewItem(items, idx), len) != @as(usize, @intCast(expected_i64))) break :blk null;
                }
                break :blk .{ .start = start, .len = slice_len, .step = step };
            },
        },
        .range_iota => |items| blk: {
            if (hostRangeIotaViewArithmeticSlice(items, len)) |slice| break :blk slice;
            const slice_len = hostIntDenseViewLen(view);
            if (slice_len == 0) break :blk .{ .start = 0, .len = 0, .step = 1 };
            const start = try normalizeIndex(try hostIntDenseViewItem(view, 0), len);
            if (slice_len == 1) break :blk .{ .start = start, .len = 1, .step = 1 };
            const second = try normalizeIndex(try hostIntDenseViewItem(view, 1), len);
            const step_i64 = @as(i64, @intCast(second)) - @as(i64, @intCast(start));
            if (step_i64 == 0) break :blk null;
            const step = std.math.cast(i32, step_i64) orelse break :blk null;
            for (1..slice_len) |idx| {
                const expected_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(idx)) * @as(i64, step);
                if (expected_i64 < 0 or expected_i64 >= len) break :blk null;
                if (try normalizeIndex(try hostIntDenseViewItem(view, idx), len) != @as(usize, @intCast(expected_i64))) break :blk null;
            }
            break :blk .{ .start = start, .len = slice_len, .step = step };
        },
        .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => blk: {
            const slice_len = hostIntDenseViewLen(view);
            if (slice_len == 0) break :blk .{ .start = 0, .len = 0, .step = 1 };
            const start = try normalizeIndex(try hostIntDenseViewItem(view, 0), len);
            if (slice_len == 1) break :blk .{ .start = start, .len = 1, .step = 1 };
            const second = try normalizeIndex(try hostIntDenseViewItem(view, 1), len);
            const step_i64 = @as(i64, @intCast(second)) - @as(i64, @intCast(start));
            if (step_i64 == 0) break :blk null;
            const step = std.math.cast(i32, step_i64) orelse break :blk null;
            for (1..slice_len) |idx| {
                const expected_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(idx)) * @as(i64, step);
                if (expected_i64 < 0 or expected_i64 >= len) break :blk null;
                if (try normalizeIndex(try hostIntDenseViewItem(view, idx), len) != @as(usize, @intCast(expected_i64))) break :blk null;
            }
            break :blk .{ .start = start, .len = slice_len, .step = step };
        },
    };
}

fn hostIntDenseViewContiguousSlice(view: HostIntDenseView, len: usize) KError!?ContiguousIndexSlice {
    if (try hostIntDenseViewArithmeticSlice(view, len)) |slice| {
        if (slice.step == 1) return .{ .start = slice.start, .len = slice.len };
    }
    return null;
}

fn valueHostIntStructuralView(value: Value) ?HostIntDenseView {
    if (value.tag() != .array) return null;
    return switch (value.arraySubkind()) {
        .host_dense_array => if (hostIntArrayView(value.asHostDenseArray())) |view|
            .{ .dense = view }
        else
            null,
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            if (numericArrayIsRangeIota(handle)) break :blk .{ .range_iota = .{ .handle = handle } };
            if (numericArrayIsFlatSlice(handle)) {
                const source = numericArrayFlatSliceSource(handle) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .flat_slice = .{
                    .source_value = source,
                    .source_host = source_host,
                    .start = numericArrayFlatSliceStart(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatConcat(handle)) {
                const left = numericArrayFlatConcatLeft(handle) orelse break :blk null;
                const right = numericArrayFlatConcatRight(handle) orelse break :blk null;
                const left_host = if (hostDenseIfPresent(left)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(left))
                    null
                else
                    break :blk null;
                const right_host = if (hostDenseIfPresent(right)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(right))
                    null
                else
                    break :blk null;
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_concat = .{
                    .left_value = left,
                    .left_host = left_host,
                    .right_value = right,
                    .right_host = right_host,
                    .left_len = numericVectorLen(left) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatSegments(handle)) {
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_segments = .{
                    .values = numericArrayFlatSegmentsValues(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFirstAxisSlice(handle)) {
                const slice = numericArrayFirstAxisSlicePayload(handle) orelse break :blk null;
                if (slice.step != 1) break :blk null;
                const source_handle = shapedNumericHandle(slice.source) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(slice.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(slice.source))
                    null
                else
                    break :blk null;
                break :blk .{ .first_axis_slice = .{
                    .source_value = slice.source,
                    .source_host = source_host,
                    .start_row = slice.start,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                    .row_step = 1,
                } };
            }
            if (numericArrayIsFirstAxisIndex(handle)) {
                const index = numericArrayFirstAxisIndexPayload(handle) orelse break :blk null;
                const source_handle = shapedNumericHandle(index.source) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(index.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(index.source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(index.source) != .int) break :blk null;
                break :blk .{ .first_axis_index = .{
                    .source_value = index.source,
                    .source_host = source_host,
                    .row_indices = index.row_indices,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                } };
            }
            if (numericArrayIsTransposeView(handle)) {
                const source = numericArrayTransposeSource(handle) orelse break :blk null;
                const source_shape = valueNumericMatrixShape(source) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .transpose = .{
                    .source_value = source,
                    .source_host = source_host,
                    .source_rows = source_shape.rows,
                    .source_cols = source_shape.cols,
                } };
            }
            if (numericArrayIsReshapeView(handle)) {
                const source = numericArrayReshapeSource(handle) orelse break :blk null;
                break :blk valueHostIntStructuralView(source);
            }
            if (numericHostAttachment(handle)) |array| {
                if (hostIntArrayView(array)) |view| break :blk .{ .dense = view };
            }
            break :blk null;
        },
        .backend_array => blk: {
            const handle = valueNumericHandle(value) orelse break :blk null;
            if (numericArrayIsRangeIota(handle)) break :blk .{ .range_iota = .{ .handle = handle } };
            if (numericArrayIsFlatSlice(handle)) {
                const source = numericArrayFlatSliceSource(handle) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .flat_slice = .{
                    .source_value = source,
                    .source_host = source_host,
                    .start = numericArrayFlatSliceStart(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatConcat(handle)) {
                const left = numericArrayFlatConcatLeft(handle) orelse break :blk null;
                const right = numericArrayFlatConcatRight(handle) orelse break :blk null;
                const left_host = if (hostDenseIfPresent(left)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(left))
                    null
                else
                    break :blk null;
                const right_host = if (hostDenseIfPresent(right)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(right))
                    null
                else
                    break :blk null;
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_concat = .{
                    .left_value = left,
                    .left_host = left_host,
                    .right_value = right,
                    .right_host = right_host,
                    .left_len = numericVectorLen(left) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFlatSegments(handle)) {
                if (valueNumericMode(value) != .int) break :blk null;
                break :blk .{ .flat_segments = .{
                    .values = numericArrayFlatSegmentsValues(handle) orelse break :blk null,
                    .len = numericFlatLen(value) orelse break :blk null,
                } };
            }
            if (numericArrayIsFirstAxisSlice(handle)) {
                const slice = numericArrayFirstAxisSlicePayload(handle) orelse break :blk null;
                if (slice.step != 1) break :blk null;
                const source_handle = shapedNumericHandle(slice.source) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(slice.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(slice.source))
                    null
                else
                    break :blk null;
                break :blk .{ .first_axis_slice = .{
                    .source_value = slice.source,
                    .source_host = source_host,
                    .start_row = slice.start,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                    .row_step = 1,
                } };
            }
            if (numericArrayIsFirstAxisIndex(handle)) {
                const index = numericArrayFirstAxisIndexPayload(handle) orelse break :blk null;
                const source_handle = shapedNumericHandle(index.source) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(index.source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(index.source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(index.source) != .int) break :blk null;
                break :blk .{ .first_axis_index = .{
                    .source_value = index.source,
                    .source_host = source_host,
                    .row_indices = index.row_indices,
                    .len = numericFlatLen(value) orelse break :blk null,
                    .row_width = numericShapeInnerBlockLen(source_handle),
                } };
            }
            if (numericArrayIsTransposeView(handle)) {
                const source = numericArrayTransposeSource(handle) orelse break :blk null;
                const source_shape = valueNumericMatrixShape(source) orelse break :blk null;
                const source_host = if (hostDenseIfPresent(source)) |array|
                    if (hostIntArrayView(array) != null) array else break :blk null
                else if (numericValueSupportsStructuralFlatItemsWithoutHost(source))
                    null
                else
                    break :blk null;
                if (valueNumericMode(source) != .int) break :blk null;
                break :blk .{ .transpose = .{
                    .source_value = source,
                    .source_host = source_host,
                    .source_rows = source_shape.rows,
                    .source_cols = source_shape.cols,
                } };
            }
            if (numericArrayIsReshapeView(handle)) {
                const source = numericArrayReshapeSource(handle) orelse break :blk null;
                break :blk valueHostIntStructuralView(source);
            }
            if (numericHostAttachment(handle)) |array| {
                if (hostIntArrayView(array)) |view| break :blk .{ .dense = view };
            }
            break :blk null;
        },
        else => null,
    };
}

fn normalizeIndex(raw_index: i64, len: usize) KError!usize {
    if (len == 0) return error.Type;
    var index = raw_index;
    if (index < 0) index += @as(i64, @intCast(len));
    if (index < 0 or index >= @as(i64, @intCast(len))) return error.Type;
    return @intCast(index);
}

fn normalizeIndexOrNull(raw_index: i64, len: usize) ?usize {
    if (len == 0) return null;
    var index = raw_index;
    if (index < 0) index += @as(i64, @intCast(len));
    if (index < 0 or index >= @as(i64, @intCast(len))) return null;
    return @intCast(index);
}

fn hostStorageCopyIntSlice(array: *const HostDenseArray) []const i64 {
    return switch (array.storage) {
        .int64 => |items| hostDenseLogicalItems(i64, array, items),
        .bit, .int8, .int16, .int32, .float64 => unreachable,
        else => unreachable,
    };
}

const DuckDbKiwiTableScan = if (runtime_has_duckdb) struct {
    const callback_allocator = std.heap.c_allocator;

    const BindData = struct {
        table: *const HostKeyedStore,
    };

    const InitData = struct {
        projected_columns: []usize,
        next_row: std.atomic.Value(usize),
    };

    fn cTypeForColumnKind(kind: HostTableColumnKind) duckdb_runtime.c.duckdb_type {
        return @as(duckdb_runtime.c.duckdb_type, switch (kind) {
            .boolean => duckdb_runtime.c.DUCKDB_TYPE_BOOLEAN,
            .int => duckdb_runtime.c.DUCKDB_TYPE_BIGINT,
            .float => duckdb_runtime.c.DUCKDB_TYPE_DOUBLE,
            .string => duckdb_runtime.c.DUCKDB_TYPE_VARCHAR,
            .date => duckdb_runtime.c.DUCKDB_TYPE_DATE,
            .time => duckdb_runtime.c.DUCKDB_TYPE_TIME,
            .time_ns => duckdb_runtime.c.DUCKDB_TYPE_TIME_NS,
            .time_tz => duckdb_runtime.c.DUCKDB_TYPE_TIME_TZ,
            .timestamp => duckdb_runtime.c.DUCKDB_TYPE_TIMESTAMP,
            .timestamp_s => duckdb_runtime.c.DUCKDB_TYPE_TIMESTAMP_S,
            .timestamp_ms => duckdb_runtime.c.DUCKDB_TYPE_TIMESTAMP_MS,
            .timestamp_ns => duckdb_runtime.c.DUCKDB_TYPE_TIMESTAMP_NS,
            .timestamp_tz => duckdb_runtime.c.DUCKDB_TYPE_TIMESTAMP_TZ,
        });
    }

    fn logicalTypeForColumnKind(kind: HostTableColumnKind) duckdb_runtime.c.duckdb_logical_type {
        return duckdb_runtime.c.duckdb_create_logical_type(cTypeForColumnKind(kind));
    }

    fn bindDataDestroy(raw: ?*anyopaque) callconv(.c) void {
        const ptr = raw orelse return;
        const bind_data: *BindData = @ptrCast(@alignCast(ptr));
        callback_allocator.destroy(bind_data);
    }

    fn initDataDestroy(raw: ?*anyopaque) callconv(.c) void {
        const ptr = raw orelse return;
        const init_data: *InitData = @ptrCast(@alignCast(ptr));
        callback_allocator.free(init_data.projected_columns);
        callback_allocator.destroy(init_data);
    }

    fn bindSetError(info: duckdb_runtime.c.duckdb_bind_info, message: [*:0]const u8) void {
        duckdb_runtime.c.duckdb_bind_set_error(info, message);
    }

    fn initSetError(info: duckdb_runtime.c.duckdb_init_info, message: [*:0]const u8) void {
        duckdb_runtime.c.duckdb_init_set_error(info, message);
    }

    fn functionSetError(info: duckdb_runtime.c.duckdb_function_info, message: [*:0]const u8) void {
        duckdb_runtime.c.duckdb_function_set_error(info, message);
    }

    fn lookupRegisteredTable(session: *Session, name: []const u8) ?*const HostKeyedStore {
        const entry = session.registered_duckdb_tables.getPtr(name) orelse return null;
        if (entry.table.arrayKind() != .host_keyed_store) return null;
        const store = entry.table.asHostKeyedStore();
        return if (store.layout == .table) store else null;
    }

    fn bind(info: duckdb_runtime.c.duckdb_bind_info) callconv(.c) void {
        const extra = duckdb_runtime.c.duckdb_bind_get_extra_info(info) orelse {
            bindSetError(info, "kiwi_scan missing session");
            return;
        };
        const session: *Session = @ptrCast(@alignCast(extra));

        if (duckdb_runtime.c.duckdb_bind_get_parameter_count(info) != 1) {
            bindSetError(info, "kiwi_scan expects exactly one table-name argument");
            return;
        }

        var name_value = duckdb_runtime.c.duckdb_bind_get_parameter(info, 0);
        defer duckdb_runtime.c.duckdb_destroy_value(&name_value);

        const raw_name = duckdb_runtime.c.duckdb_get_varchar(name_value);
        defer if (raw_name != null) duckdb_runtime.c.duckdb_free(raw_name);
        if (raw_name == null) {
            bindSetError(info, "kiwi_scan requires a non-null table name");
            return;
        }

        const table = lookupRegisteredTable(session, std.mem.span(raw_name)) orelse {
            bindSetError(info, "unknown kiwi registered table");
            return;
        };

        const metadata = Session.keyedStoreTableMetadata(table);
        for (0..Session.keyedStoreNameCount(table)) |column_idx| {
            var logical_type = logicalTypeForColumnKind(metadata[column_idx].kind);
            if (logical_type == null) {
                bindSetError(info, "failed to build kiwi_scan column type");
                return;
            }
            defer duckdb_runtime.c.duckdb_destroy_logical_type(&logical_type);

            const column_name = callback_allocator.dupeZ(u8, Session.keyedStoreColumnNameBytes(table, column_idx)) catch {
                bindSetError(info, "failed to allocate kiwi_scan column name");
                return;
            };
            defer callback_allocator.free(column_name);

            duckdb_runtime.c.duckdb_bind_add_result_column(info, column_name.ptr, logical_type);
        }

        duckdb_runtime.c.duckdb_bind_set_cardinality(info, @intCast(table.row_count), true);

        const bind_data = callback_allocator.create(BindData) catch {
            bindSetError(info, "failed to allocate kiwi_scan bind state");
            return;
        };
        bind_data.* = .{ .table = table };
        duckdb_runtime.c.duckdb_bind_set_bind_data(info, bind_data, bindDataDestroy);
    }

    fn init(info: duckdb_runtime.c.duckdb_init_info) callconv(.c) void {
        const bind_raw = duckdb_runtime.c.duckdb_init_get_bind_data(info) orelse {
            initSetError(info, "kiwi_scan missing bind state");
            return;
        };
        const bind_data: *const BindData = @ptrCast(@alignCast(bind_raw));

        const projected_count: usize = @intCast(duckdb_runtime.c.duckdb_init_get_column_count(info));
        const projected_columns = callback_allocator.alloc(usize, projected_count) catch {
            initSetError(info, "failed to allocate kiwi_scan projection state");
            return;
        };
        errdefer callback_allocator.free(projected_columns);

        for (0..projected_count) |idx| {
            const column_idx: usize = @intCast(duckdb_runtime.c.duckdb_init_get_column_index(info, @intCast(idx)));
            if (column_idx >= Session.keyedStoreNameCount(bind_data.table)) {
                initSetError(info, "kiwi_scan projection index out of range");
                return;
            }
            projected_columns[idx] = column_idx;
        }

        const init_data = callback_allocator.create(InitData) catch {
            initSetError(info, "failed to allocate kiwi_scan scan state");
            return;
        };
        init_data.* = .{
            .projected_columns = projected_columns,
            .next_row = std.atomic.Value(usize).init(0),
        };
        duckdb_runtime.c.duckdb_init_set_init_data(info, init_data, initDataDestroy);
    }

    fn markInvalid(vector: duckdb_runtime.c.duckdb_vector, row: usize, validity_ptr: *?[*]u64) !void {
        const validity = validity_ptr.* orelse blk: {
            duckdb_runtime.c.duckdb_vector_ensure_validity_writable(vector);
            const raw = duckdb_runtime.c.duckdb_vector_get_validity(vector);
            if (raw == null) return error.Unsupported;
            const casted: [*]u64 = @ptrCast(raw);
            validity_ptr.* = casted;
            break :blk casted;
        };
        duckdb_runtime.c.duckdb_validity_set_row_invalid(validity, @intCast(row));
    }

    fn columnValidityBits(table: *const HostKeyedStore, column_idx: usize) ?HostBitSlice {
        const validity = Session.keyedStoreTableMetadata(table)[column_idx].validity orelse return null;
        const array = hostDenseIfPresent(validity) orelse return null;
        return switch (hostIntArrayView(array) orelse return null) {
            .bit => |bits| bits,
            else => null,
        };
    }

    fn columnIntView(table: *const HostKeyedStore, column_idx: usize) ?HostIntArrayView {
        const array = hostDenseIfPresent(Session.tableColumnData(table, column_idx)) orelse return null;
        return hostIntArrayView(array);
    }

    fn columnFloatSlice(table: *const HostKeyedStore, column_idx: usize) ?[]const f64 {
        const array = hostDenseIfPresent(Session.tableColumnData(table, column_idx)) orelse return null;
        return switch (array.storage) {
            .float64 => |items| hostDenseLogicalItems(f64, array, items),
            else => null,
        };
    }

    fn rowValid(validity_bits: ?HostBitSlice, src_row: usize) bool {
        const bits = validity_bits orelse return true;
        return bitGet(bits.words, src_row);
    }

    fn mapIntIdentity(raw: i64) KError!i64 {
        return raw;
    }

    fn mapBool(raw: i64) KError!bool {
        return raw != 0;
    }

    fn mapDate(raw: i64) KError!duckdb_runtime.c.duckdb_date {
        const days = std.math.cast(i32, raw) orelse return error.Unsupported;
        return .{ .days = days };
    }

    fn mapTime(raw: i64) KError!duckdb_runtime.c.duckdb_time {
        return .{ .micros = raw };
    }

    fn mapTimeNs(raw: i64) KError!duckdb_runtime.c.duckdb_time_ns {
        return .{ .nanos = raw };
    }

    fn mapTimeTz(raw: i64) KError!duckdb_runtime.c.duckdb_time_tz {
        return .{ .bits = @bitCast(raw) };
    }

    fn mapTimestamp(raw: i64) KError!duckdb_runtime.c.duckdb_timestamp {
        return .{ .micros = raw };
    }

    fn mapTimestampS(raw: i64) KError!duckdb_runtime.c.duckdb_timestamp_s {
        return .{ .seconds = raw };
    }

    fn mapTimestampMs(raw: i64) KError!duckdb_runtime.c.duckdb_timestamp_ms {
        return .{ .millis = raw };
    }

    fn mapTimestampNs(raw: i64) KError!duckdb_runtime.c.duckdb_timestamp_ns {
        return .{ .nanos = raw };
    }

    fn writeMappedIntViewRows(
        comptime OutT: type,
        out: [*]OutT,
        view: HostIntArrayView,
        validity_bits: ?HostBitSlice,
        vector: duckdb_runtime.c.duckdb_vector,
        start_row: usize,
        row_count: usize,
        comptime mapValue: fn (i64) KError!OutT,
    ) !void {
        var validity: ?[*]u64 = null;

        switch (view) {
            .bit => |items| {
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (validity_bits != null and !bitGet(validity_bits.?.words, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try mapValue(@intFromBool(bitGet(items.words, src_row)));
                }
            },
            .int8 => |items| {
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (validity_bits != null and !bitGet(validity_bits.?.words, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try mapValue(items[src_row]);
                }
            },
            .int16 => |items| {
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (validity_bits != null and !bitGet(validity_bits.?.words, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try mapValue(items[src_row]);
                }
            },
            .int32 => |items| {
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (validity_bits != null and !bitGet(validity_bits.?.words, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try mapValue(items[src_row]);
                }
            },
            .int64 => |items| {
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (validity_bits != null and !bitGet(validity_bits.?.words, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try mapValue(items[src_row]);
                }
            },
        }
    }

    fn writeFloatSliceRows(
        out: [*]f64,
        items: []const f64,
        validity_bits: ?HostBitSlice,
        vector: duckdb_runtime.c.duckdb_vector,
        start_row: usize,
        row_count: usize,
    ) !void {
        if (validity_bits == null) {
            @memcpy(out[0..row_count], items[start_row .. start_row + row_count]);
            return;
        }

        var validity: ?[*]u64 = null;
        for (0..row_count) |row| {
            const src_row = start_row + row;
            if (!rowValid(validity_bits, src_row)) {
                try markInvalid(vector, row, &validity);
                continue;
            }
            out[row] = items[src_row];
        }
    }

    fn writeColumnRows(
        table: *const HostKeyedStore,
        column_idx: usize,
        vector: duckdb_runtime.c.duckdb_vector,
        start_row: usize,
        row_count: usize,
    ) !void {
        const validity_bits = columnValidityBits(table, column_idx);
        const kind = Session.keyedStoreTableMetadata(table)[column_idx].kind;
        const data_value = Session.tableColumnData(table, column_idx);

        switch (kind) {
            .boolean => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]bool = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(bool, out, view, validity_bits, vector, start_row, row_count, mapBool);
                return;
            },
            .int => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]i64 = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(i64, out, view, validity_bits, vector, start_row, row_count, mapIntIdentity);
                return;
            },
            .float => if (columnFloatSlice(table, column_idx)) |items| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]f64 = @ptrCast(@alignCast(data));
                try writeFloatSliceRows(out, items, validity_bits, vector, start_row, row_count);
                return;
            },
            .string => {
                const list = data_value.asHostStringList();
                var validity: ?[*]u64 = null;
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!rowValid(validity_bits, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    const bytes = try hostStringListItemBytes(list, src_row);
                    duckdb_runtime.c.duckdb_unsafe_vector_assign_string_element_len(vector, @intCast(row), bytes.ptr, @intCast(bytes.len));
                }
                return;
            },
            .date => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_date = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_date, out, view, validity_bits, vector, start_row, row_count, mapDate);
                return;
            },
            .time => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_time = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_time, out, view, validity_bits, vector, start_row, row_count, mapTime);
                return;
            },
            .time_ns => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_time_ns = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_time_ns, out, view, validity_bits, vector, start_row, row_count, mapTimeNs);
                return;
            },
            .time_tz => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_time_tz = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_time_tz, out, view, validity_bits, vector, start_row, row_count, mapTimeTz);
                return;
            },
            .timestamp => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_timestamp, out, view, validity_bits, vector, start_row, row_count, mapTimestamp);
                return;
            },
            .timestamp_s => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp_s = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_timestamp_s, out, view, validity_bits, vector, start_row, row_count, mapTimestampS);
                return;
            },
            .timestamp_ms => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp_ms = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_timestamp_ms, out, view, validity_bits, vector, start_row, row_count, mapTimestampMs);
                return;
            },
            .timestamp_ns => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp_ns = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_timestamp_ns, out, view, validity_bits, vector, start_row, row_count, mapTimestampNs);
                return;
            },
            .timestamp_tz => if (columnIntView(table, column_idx)) |view| {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp = @ptrCast(@alignCast(data));
                try writeMappedIntViewRows(duckdb_runtime.c.duckdb_timestamp, out, view, validity_bits, vector, start_row, row_count, mapTimestamp);
                return;
            },
        }

        var validity: ?[*]u64 = null;

        switch (kind) {
            .boolean => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]bool = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = (try numericIntAt(data_value, src_row)) != 0;
                }
            },
            .int => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]i64 = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try numericIntAt(data_value, src_row);
                }
            },
            .float => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]f64 = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = try numericFloatAt(data_value, src_row);
                }
            },
            .string => {
                const list = data_value.asHostStringList();
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    const bytes = try hostStringListItemBytes(list, src_row);
                    duckdb_runtime.c.duckdb_vector_assign_string_element_len(vector, @intCast(row), bytes.ptr, @intCast(bytes.len));
                }
            },
            .date => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_date = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    const days = std.math.cast(i32, try numericIntAt(data_value, src_row)) orelse return error.Unsupported;
                    out[row] = .{ .days = days };
                }
            },
            .time => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_time = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .micros = try numericIntAt(data_value, src_row) };
                }
            },
            .time_ns => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_time_ns = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .nanos = try numericIntAt(data_value, src_row) };
                }
            },
            .time_tz => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_time_tz = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .bits = @bitCast(try numericIntAt(data_value, src_row)) };
                }
            },
            .timestamp => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .micros = try numericIntAt(data_value, src_row) };
                }
            },
            .timestamp_s => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp_s = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .seconds = try numericIntAt(data_value, src_row) };
                }
            },
            .timestamp_ms => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp_ms = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .millis = try numericIntAt(data_value, src_row) };
                }
            },
            .timestamp_ns => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp_ns = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .nanos = try numericIntAt(data_value, src_row) };
                }
            },
            .timestamp_tz => {
                const data = duckdb_runtime.c.duckdb_vector_get_data(vector) orelse return error.DuckDbUnexpectedResult;
                const out: [*]duckdb_runtime.c.duckdb_timestamp = @ptrCast(@alignCast(data));
                for (0..row_count) |row| {
                    const src_row = start_row + row;
                    if (!Session.keyedStoreTableCellIsValid(table, column_idx, src_row)) {
                        try markInvalid(vector, row, &validity);
                        continue;
                    }
                    out[row] = .{ .micros = try numericIntAt(data_value, src_row) };
                }
            },
        }
    }

    fn scan(info: duckdb_runtime.c.duckdb_function_info, output: duckdb_runtime.c.duckdb_data_chunk) callconv(.c) void {
        const bind_raw = duckdb_runtime.c.duckdb_function_get_bind_data(info) orelse {
            functionSetError(info, "kiwi_scan missing bind state");
            return;
        };
        const init_raw = duckdb_runtime.c.duckdb_function_get_init_data(info) orelse {
            functionSetError(info, "kiwi_scan missing scan state");
            return;
        };

        const bind_data: *const BindData = @ptrCast(@alignCast(bind_raw));
        const init_data: *InitData = @ptrCast(@alignCast(init_raw));
        const table = bind_data.table;

        duckdb_runtime.c.duckdb_data_chunk_reset(output);

        const chunk_capacity: usize = @intCast(duckdb_runtime.c.duckdb_vector_size());
        const start_row = init_data.next_row.fetchAdd(chunk_capacity, .monotonic);
        if (start_row >= table.row_count) {
            duckdb_runtime.c.duckdb_data_chunk_set_size(output, 0);
            return;
        }

        const row_count = @min(chunk_capacity, table.row_count - start_row);
        for (init_data.projected_columns, 0..) |column_idx, out_idx| {
            const vector = duckdb_runtime.c.duckdb_data_chunk_get_vector(output, @intCast(out_idx));
            writeColumnRows(table, column_idx, vector, start_row, row_count) catch {
                functionSetError(info, "kiwi_scan failed while producing a result chunk");
                duckdb_runtime.c.duckdb_data_chunk_set_size(output, 0);
                return;
            };
        }
        duckdb_runtime.c.duckdb_data_chunk_set_size(output, @intCast(row_count));
    }

    fn ensureRegistered(session: *Session, conn: *duckdb_runtime.Connection) KError!void {
        var table_function = duckdb_runtime.c.duckdb_create_table_function();
        if (table_function == null) return error.Unsupported;
        defer duckdb_runtime.c.duckdb_destroy_table_function(&table_function);

        duckdb_runtime.c.duckdb_table_function_set_name(table_function, "kiwi_scan");

        var varchar_type = duckdb_runtime.c.duckdb_create_logical_type(
            @as(duckdb_runtime.c.duckdb_type, duckdb_runtime.c.DUCKDB_TYPE_VARCHAR),
        );
        if (varchar_type == null) return error.Unsupported;
        defer duckdb_runtime.c.duckdb_destroy_logical_type(&varchar_type);

        duckdb_runtime.c.duckdb_table_function_add_parameter(table_function, varchar_type);
        duckdb_runtime.c.duckdb_table_function_set_extra_info(table_function, session, null);
        duckdb_runtime.c.duckdb_table_function_set_bind(table_function, bind);
        duckdb_runtime.c.duckdb_table_function_set_init(table_function, init);
        duckdb_runtime.c.duckdb_table_function_set_function(table_function, scan);
        duckdb_runtime.c.duckdb_table_function_supports_projection_pushdown(table_function, true);

        if (duckdb_runtime.c.duckdb_register_table_function(conn.conn, table_function) == duckdb_runtime.c.DuckDBError) {
            return error.Unsupported;
        }
    }
} else struct {};

fn destroyManagedHostArrayNoPool(allocator: std.mem.Allocator, array: *HostDenseArray) void {
    array.logical_handle = null;
    if (array.find_cache) |cache| {
        if (cache.keys) |keys| allocator.free(keys);
        if (cache.slots) |slots| allocator.free(slots);
        allocator.destroy(cache);
        array.find_cache = null;
    }
    switch (array.storage) {
        .bit => |words| allocator.free(words),
        .int8 => |items| allocator.free(items),
        .int16 => |items| allocator.free(items),
        .int32 => |items| allocator.free(items),
        .int64 => |items| allocator.free(items),
        .float32 => |items| allocator.free(items),
        .float64 => |items| allocator.free(items),
    }
    allocator.destroy(array);
}

fn destroyManagedHostBoxedArrayNoPool(allocator: std.mem.Allocator, array: *HostBoxedArray) void {
    for (array.items) |item| releaseHeapValue(allocator, item);
    if (array.prototype) |prototype| releaseHeapValue(allocator, prototype);
    allocator.free(array.items);
    allocator.destroy(array);
}

fn destroyManagedHostRelationNoPool(allocator: std.mem.Allocator, relation: *HostRelation) void {
    switch (relation.origin) {
        .file => |file| allocator.free(file.path),
        .sql => |sql_info| {
            for (sql_info.params) |param| {
                allocator.free(param.name);
                releaseHeapValue(allocator, param.value);
            }
            allocator.free(sql_info.params);
            allocator.free(sql_info.text);
        },
    }
    allocator.destroy(relation);
}

fn destroyManagedHostKeyedStoreNoPool(allocator: std.mem.Allocator, store: *HostKeyedStore) void {
    releaseHeapValue(allocator, store.names);
    releaseHeapValue(allocator, store.values);
    if (store.column_metadata) |metadata| {
        for (metadata) |entry| {
            if (entry.validity) |mask| releaseHeapValue(allocator, mask);
        }
        allocator.free(metadata);
    }
    store.lookup.deinit(allocator);
    if (store.owns_path) allocator.free(store.path);
    allocator.destroy(store);
}

fn destroyManagedBackendArrayNoPool(allocator: std.mem.Allocator, array: *BackendArray) void {
    array.logical_handle = null;
    array.array.deinit();
    allocator.destroy(array);
}

fn isManagedValue(value: Value) bool {
    return switch (value.raw & Value.tag_mask) {
        Value.boxed_int_tag => value.asBoxedInt().header.owner == .managed,
        Value.closure_tag => value.asClosure().header.owner == .managed,
        Value.array_tag => value.arrayOwner() == .managed,
        else => false,
    };
}

fn valueMayNeedRelease(value: Value) bool {
    return switch (value.raw & Value.tag_mask) {
        Value.boxed_int_tag, Value.closure_tag, Value.array_tag => true,
        else => false,
    };
}

fn releaseManagedNumericHandleNoPool(allocator: std.mem.Allocator, handle: *NumericArray) void {
    std.debug.assert(handle.header.owner == .managed);
    std.debug.assert(handle.header.ref_count != 0);
    handle.header.ref_count -= 1;
    if (handle.header.ref_count == 0) {
        switch (handle.structural) {
            .materialized, .range_iota => {},
            .flat_slice => |slice| releaseHeapValue(allocator, slice.source),
            .flat_concat => |concat| {
                releaseHeapValue(allocator, concat.left);
                releaseHeapValue(allocator, concat.right);
            },
            .flat_segments => |segments| {
                for (segments.values) |item| releaseHeapValue(allocator, item);
                allocator.free(segments.values);
            },
            .first_axis_slice => |slice| releaseHeapValue(allocator, slice.source),
            .first_axis_index => |index| {
                releaseHeapValue(allocator, index.source);
                releaseHeapValue(allocator, index.row_indices);
            },
            .first_axis_concat => |concat| {
                releaseHeapValue(allocator, concat.left);
                releaseHeapValue(allocator, concat.right);
            },
            .reshape_view => |reshape| releaseHeapValue(allocator, reshape.source),
            .transpose_view => |transpose| releaseHeapValue(allocator, transpose.source),
        }
        if (handle.host) |array| destroyManagedHostArrayNoPool(allocator, array);
        if (handle.mlx) |array| destroyManagedBackendArrayNoPool(allocator, array);
        allocator.destroy(handle);
    }
}

fn retainHeapValue(value: Value) void {
    switch (value.raw & Value.tag_mask) {
        Value.boxed_int_tag => {
            const box = @constCast(value.asBoxedInt());
            if (box.header.owner == .managed) box.header.ref_count += 1;
        },
        Value.closure_tag => {
            const closure = @constCast(value.asClosure());
            if (closure.header.owner == .managed) closure.header.ref_count += 1;
        },
        Value.array_tag => {
            switch (value.arraySubkind()) {
                .numeric_array => {
                    const handle = @constCast(value.asNumericArray());
                    if (handle.header.owner == .managed) {
                        handle.header.ref_count += 1;
                    }
                },
                .host_dense_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner == .managed) {
                            handle.header.ref_count += 1;
                        }
                    } else {
                        const array = @constCast(value.asHostDenseArray());
                        if (array.header.owner == .managed) array.header.ref_count += 1;
                    }
                },
                .host_boxed_array => {
                    const array = @constCast(value.asHostBoxedArray());
                    if (array.header.owner == .managed) array.header.ref_count += 1;
                },
                .host_keyed_store => {
                    const store = @constCast(value.asHostKeyedStore());
                    if (store.header.owner == .managed) store.header.ref_count += 1;
                },
                .host_string => {
                    const text = @constCast(value.asHostString());
                    if (text.header.owner == .managed) text.header.ref_count += 1;
                },
                .host_symbol => {
                    const text = @constCast(value.asHostSymbol());
                    if (text.header.owner == .managed) text.header.ref_count += 1;
                },
                .host_string_view => {
                    const view = @constCast(value.asHostStringView());
                    if (view.header.owner == .managed) view.header.ref_count += 1;
                },
                .host_relation => {
                    const relation = @constCast(value.asHostRelation());
                    if (relation.header.owner == .managed) relation.header.ref_count += 1;
                },
                .host_table_scalar => {
                    const scalar = @constCast(valueAsHostTableScalar(value));
                    if (scalar.header.owner == .managed) scalar.header.ref_count += 1;
                },
                .host_string_list, .host_symbol_list => {
                    const list = @constCast(value.asHostStringList());
                    if (list.header.owner == .managed) list.header.ref_count += 1;
                },
                .backend_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner == .managed) {
                            handle.header.ref_count += 1;
                        }
                    } else {
                        const array = @constCast(value.asBackendArray());
                        if (array.header.owner == .managed) array.header.ref_count += 1;
                    }
                },
            }
        },
        else => {},
    }
}

fn releaseHeapValue(allocator: std.mem.Allocator, value: Value) void {
    switch (value.raw & Value.tag_mask) {
        Value.boxed_int_tag => {
            const box = @constCast(value.asBoxedInt());
            if (box.header.owner != .managed) return;
            std.debug.assert(box.header.ref_count != 0);
            box.header.ref_count -= 1;
            if (box.header.ref_count == 0) allocator.destroy(box);
        },
        Value.closure_tag => {
            const closure = @constCast(value.asClosure());
            if (closure.header.owner != .managed) return;
            std.debug.assert(closure.header.ref_count != 0);
            closure.header.ref_count -= 1;
            if (closure.header.ref_count == 0) {
                for (closure.captures) |capture| releaseHeapValue(allocator, capture);
                allocator.free(closure.captures);
                allocator.destroy(closure);
            }
        },
        Value.array_tag => {
            switch (value.arraySubkind()) {
                .numeric_array => {
                    const handle = @constCast(value.asNumericArray());
                    if (handle.header.owner != .managed) return;
                    releaseManagedNumericHandleNoPool(allocator, handle);
                },
                .host_dense_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner != .managed) return;
                        releaseManagedNumericHandleNoPool(allocator, handle);
                    } else {
                        const array = @constCast(value.asHostDenseArray());
                        if (array.header.owner != .managed) return;
                        std.debug.assert(array.header.ref_count != 0);
                        array.header.ref_count -= 1;
                        if (array.header.ref_count == 0) {
                            destroyManagedHostArrayNoPool(allocator, array);
                        }
                    }
                },
                .host_boxed_array => {
                    const array = @constCast(value.asHostBoxedArray());
                    if (array.header.owner != .managed) return;
                    std.debug.assert(array.header.ref_count != 0);
                    array.header.ref_count -= 1;
                    if (array.header.ref_count == 0) {
                        destroyManagedHostBoxedArrayNoPool(allocator, array);
                    }
                },
                .host_keyed_store => {
                    const store = @constCast(value.asHostKeyedStore());
                    if (store.header.owner != .managed) return;
                    std.debug.assert(store.header.ref_count != 0);
                    store.header.ref_count -= 1;
                    if (store.header.ref_count == 0) {
                        destroyManagedHostKeyedStoreNoPool(allocator, store);
                    }
                },
                .host_string, .host_symbol => {
                    const text = switch (value.arrayKind()) {
                        .host_string => @constCast(value.asHostString()),
                        .host_symbol => @constCast(value.asHostSymbol()),
                        else => unreachable,
                    };
                    if (text.header.owner != .managed) return;
                    std.debug.assert(text.header.ref_count != 0);
                    text.header.ref_count -= 1;
                    if (text.header.ref_count == 0) freeHostTextAlloc(allocator, text);
                },
                .host_string_view => {
                    const view = @constCast(value.asHostStringView());
                    if (view.header.owner != .managed) return;
                    std.debug.assert(view.header.ref_count != 0);
                    view.header.ref_count -= 1;
                    if (view.header.ref_count == 0) {
                        releaseHeapValue(allocator, Value.array(view.base));
                        allocator.destroy(view);
                    }
                },
                .host_relation => {
                    const relation = @constCast(value.asHostRelation());
                    if (relation.header.owner != .managed) return;
                    std.debug.assert(relation.header.ref_count != 0);
                    relation.header.ref_count -= 1;
                    if (relation.header.ref_count == 0) {
                        destroyManagedHostRelationNoPool(allocator, relation);
                    }
                },
                .host_table_scalar => {
                    const scalar = @constCast(valueAsHostTableScalar(value));
                    if (scalar.header.owner != .managed) return;
                    std.debug.assert(scalar.header.ref_count != 0);
                    scalar.header.ref_count -= 1;
                    if (scalar.header.ref_count == 0) {
                        releaseHeapValue(allocator, scalar.value);
                        allocator.destroy(scalar);
                    }
                },
                .host_string_list, .host_symbol_list => {
                    const list = @constCast(value.asHostStringList());
                    if (list.header.owner != .managed) return;
                    std.debug.assert(list.header.ref_count != 0);
                    list.header.ref_count -= 1;
                    if (list.header.ref_count == 0) {
                        if (list.base) |base| releaseHeapValue(allocator, Value.array(base));
                        switch (list.storage) {
                            .eager => |items| {
                                for (items) |item| switch (item) {
                                    .owned => |text| releaseHeapValue(allocator, Value.array(text)),
                                    .view => {},
                                };
                                freeHostStringListAlloc(allocator, list);
                            },
                            .split_scalar => allocator.destroy(list),
                        }
                    }
                },
                .backend_array => {
                    if (logicalHandleForNumericPayloadValue(value)) |handle| {
                        if (handle.header.owner != .managed) return;
                        releaseManagedNumericHandleNoPool(allocator, handle);
                    } else {
                        const array = @constCast(value.asBackendArray());
                        if (array.header.owner != .managed) return;
                        std.debug.assert(array.header.ref_count != 0);
                        array.header.ref_count -= 1;
                        if (array.header.ref_count == 0) {
                            destroyManagedBackendArrayNoPool(allocator, array);
                        }
                    }
                },
            }
        },
        else => {},
    }
}

fn allocBoxedInt(allocator: std.mem.Allocator, owner: HeapOwner, value: i64) !Value {
    const box = try allocator.create(BoxedInt);
    box.* = .{
        .header = HeapHeader.init(.boxed_int, owner),
        .value = value,
    };
    return Value.boxedInt(box);
}

fn allocHostText(allocator: std.mem.Allocator, kind: HeapKind, owner: HeapOwner, bytes: []const u8) !Value {
    std.debug.assert(kind == .host_string or kind == .host_symbol);
    const buf = try hostTextAllocSlice(allocator, bytes.len);
    errdefer allocator.free(buf);
    const text = hostTextFromAlloc(buf);
    const payload = hostTextBytesFromAlloc(buf, bytes.len);
    @memcpy(payload, bytes);
    text.* = .{
        .header = HeapHeader.init(kind, owner),
        .len = bytes.len,
    };
    return Value.array(text);
}

fn allocNumericArrayHandle(self: *Session, owner: HeapOwner) !*NumericArray {
    const allocator = switch (owner) {
        .managed => self.allocator,
        .scratch => self.scratch_arena.allocator(),
        .frozen => self.arena.allocator(),
    };
    if (owner == .managed and self.free_numeric_array_len != 0) {
        self.free_numeric_array_len -= 1;
        return self.free_numeric_arrays[self.free_numeric_array_len].?;
    }
    return try allocator.create(NumericArray);
}

fn syncNumericArrayChildren(handle: *NumericArray) void {
    if (handle.host) |host| {
        host.logical_handle = handle;
    }
    if (handle.mlx) |array| {
        array.logical_handle = handle;
    }
}

fn newNumericArrayValue(
    self: *Session,
    owner: HeapOwner,
    preferred: NumericArrayPreferred,
    host: ?*HostDenseArray,
    backend_array: ?*BackendArray,
) !Value {
    const handle = try allocNumericArrayHandle(self, owner);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, owner),
        .preferred = preferred,
        .host = host,
        .mlx = backend_array,
    };
    if (host) |array| {
        numericArraySetVectorShape(handle, array.len());
    } else if (backend_array) |array| {
        numericArraySetShapeFromBackend(handle, array.array);
    }
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    return Value.array(handle);
}

fn newRangeIotaValue(self: *Session, owner: HeapOwner, len: usize) !Value {
    const handle = try allocNumericArrayHandle(self, owner);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, owner),
        .preferred = .host,
    };
    numericArraySetRangeIota(handle, len);
    self.registerManagedNumericHandle(handle);
    return Value.array(handle);
}

fn newRangeIotaValueWithParams(self: *Session, owner: HeapOwner, len: usize, start: i64, step: i64) !Value {
    const value = try newRangeIotaValue(self, owner, len);
    const handle = @constCast(value.asNumericArray());
    handle.structural = .{ .range_iota = .{ .start = start, .step = step } };
    return value;
}

fn newRangeIotaValueWithShape(
    self: *Session,
    owner: HeapOwner,
    len: usize,
    start: i64,
    step: i64,
    shape: ?NumericShapeSnapshot,
) !Value {
    const value = try newRangeIotaValueWithParams(self, owner, len, start, step);
    return try applyNonVectorNumericShapeToValue(self, value, shape);
}

const CollapsedFlatSliceSource = struct {
    source: Value,
    start: usize,
};

fn collapseFlatSliceSource(source: Value, start: usize) KError!CollapsedFlatSliceSource {
    var resolved_source = source;
    var resolved_start = start;

    while (true) {
        const handle = valueNumericHandle(resolved_source) orelse break;
        if (!numericArrayIsFlatSlice(handle)) break;
        if (numericHostAttachment(handle) != null or numericHasBackendAttachment(handle)) break;

        const base_source = numericArrayFlatSliceSource(handle) orelse return error.Type;
        const base_start = numericArrayFlatSliceStart(handle) orelse return error.Type;
        resolved_start = std.math.add(usize, base_start, resolved_start) catch return error.Unsupported;
        resolved_source = base_source;
    }

    return .{ .source = resolved_source, .start = resolved_start };
}

fn newFlatSliceValue(self: *Session, source: Value, start: usize, len: usize) KError!Value {
    const source_len = numericFlatLen(source) orelse return error.Type;
    if (start > source_len or len > source_len - start) return error.Type;

    const collapsed = try collapseFlatSliceSource(source, start);
    const resolved_source_len = numericFlatLen(collapsed.source) orelse return error.Type;
    if (collapsed.start > resolved_source_len or len > resolved_source_len - collapsed.start) return error.Type;

    const retained_source = try self.retainEscapedValue(collapsed.source);
    errdefer self.releaseValue(retained_source);

    const source_handle = valueNumericHandle(collapsed.source);
    const preferred: NumericArrayPreferred = if (source_handle) |handle|
        handle.preferred
    else if (collapsed.source.tag() == .array and collapsed.source.arrayKind() == .backend_array)
        .mlx
    else
        .host;

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .{ .flat_slice = .{ .source = retained_source, .start = collapsed.start } },
        .rank = 1,
        .shape = [_]i32{ @intCast(len), 0, 0, 0 },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.flat_slice);
    return Value.array(handle);
}

fn newFlatConcatPairValue(self: *Session, left: Value, right: Value) KError!Value {
    if (valueNumericMode(left) == null or valueNumericMode(right) == null) return error.Type;
    const left_len = numericVectorLen(left) orelse return error.Type;
    const right_len = numericVectorLen(right) orelse return error.Type;

    const retained_left = try self.retainEscapedValue(left);
    errdefer self.releaseValue(retained_left);
    const retained_right = try self.retainEscapedValue(right);
    errdefer self.releaseValue(retained_right);

    const left_handle = valueNumericHandle(left);
    const right_handle = valueNumericHandle(right);
    const preferred: NumericArrayPreferred = if ((left_handle != null and left_handle.?.preferred == .mlx) or
        (right_handle != null and right_handle.?.preferred == .mlx))
        .mlx
    else
        .host;

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .{ .flat_concat = .{ .left = retained_left, .right = retained_right } },
        .rank = 1,
        .shape = [_]i32{ @intCast(left_len + right_len), 0, 0, 0 },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.flat_concat);
    return Value.array(handle);
}

fn newFlatSegmentsValue(self: *Session, segments: []const FlatNumericSegment) KError!Value {
    if (segments.len < 3) return error.Type;

    const retained = try self.allocator.alloc(Value, segments.len);
    errdefer self.allocator.free(retained);

    var total_len: usize = 0;
    var preferred: NumericArrayPreferred = .host;
    var retained_len: usize = 0;
    errdefer {
        for (retained[0..retained_len]) |value| self.releaseValue(value);
    }
    for (segments, 0..) |segment, idx| {
        retained[idx] = try self.retainEscapedValue(segment.value);
        retained_len += 1;
        total_len += segment.len;
        if (valueNumericHandle(segment.value)) |handle| {
            if (handle.preferred == .mlx) preferred = .mlx;
        } else if (segment.value.tag() == .array and segment.value.arrayKind() == .backend_array) {
            preferred = .mlx;
        }
    }

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .{ .flat_segments = .{ .values = retained } },
        .rank = 1,
        .shape = [_]i32{ @intCast(total_len), 0, 0, 0 },
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.flat_segments);
    return Value.array(handle);
}

fn newFlatConcatValue(self: *Session, left: Value, right: Value) KError!Value {
    var segments = std.ArrayList(FlatNumericSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFlatNumericSegments(self.allocator, left, &segments);
    try collectFlatNumericSegments(self.allocator, right, &segments);
    return try buildFlatNumericComposition(self, segments.items);
}

fn newFirstAxisSliceValueWithStep(self: *Session, source: Value, start: usize, len: usize, step: i32) KError!Value {
    const source_handle = shapedNumericHandle(source) orelse return error.Type;
    const rows: usize = @intCast(source_handle.shape[0]);
    if (step == 0) return error.Type;
    if (len == 0) {
        if (start > rows) return error.Type;
    } else {
        const start_i64 = @as(i64, @intCast(start));
        const last_i64 = start_i64 + @as(i64, @intCast(len - 1)) * @as(i64, step);
        if (start_i64 < 0 or start_i64 >= rows) return error.Type;
        if (last_i64 < 0 or last_i64 >= rows) return error.Type;
    }

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = source_handle.preferred,
        .structural = .{ .first_axis_slice = .{ .source = retained_source, .start = start, .step = step } },
        .rank = source_handle.rank,
        .shape = source_handle.shape,
        .host = null,
        .mlx = null,
    };
    handle.shape[0] = @intCast(len);
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.first_axis_slice);
    return Value.array(handle);
}

fn newFirstAxisSliceValue(self: *Session, source: Value, start: usize, len: usize) KError!Value {
    return try newFirstAxisSliceValueWithStep(self, source, start, len, 1);
}

fn newFirstAxisIndexValue(self: *Session, source: Value, row_indices: Value) KError!Value {
    const source_handle = shapedNumericHandle(source) orelse return error.Type;
    const rows_view = valueHostIntStructuralView(row_indices) orelse return error.Type;
    const row_count = hostIntDenseViewLen(rows_view);
    for (0..row_count) |idx| {
        const row_i64 = try hostIntDenseViewItem(rows_view, idx);
        if (row_i64 < 0 or row_i64 >= @as(i64, @intCast(source_handle.shape[0]))) return error.Type;
    }

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);
    const retained_rows = try self.retainEscapedValue(row_indices);
    errdefer self.releaseValue(retained_rows);

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = source_handle.preferred,
        .structural = .{ .first_axis_index = .{ .source = retained_source, .row_indices = retained_rows } },
        .rank = source_handle.rank,
        .shape = source_handle.shape,
        .host = null,
        .mlx = null,
    };
    handle.shape[0] = @intCast(row_count);
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.first_axis_index);
    return Value.array(handle);
}

fn newFirstAxisConcatValue(self: *Session, left: Value, right: Value, shape: NumericMatrixShape) KError!Value {
    if (valueNumericMode(left) == null or valueNumericMode(right) == null) return error.Type;

    const retained_left = try self.retainEscapedValue(left);
    errdefer self.releaseValue(retained_left);
    const retained_right = try self.retainEscapedValue(right);
    errdefer self.releaseValue(retained_right);

    const left_handle = valueNumericHandle(left);
    const right_handle = valueNumericHandle(right);
    const preferred: NumericArrayPreferred = if ((left_handle != null and left_handle.?.preferred == .mlx) or
        (right_handle != null and right_handle.?.preferred == .mlx))
        .mlx
    else
        .host;

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .{ .first_axis_concat = .{ .left = retained_left, .right = retained_right } },
        .rank = 2,
        .shape = numericShapeSnapshotMatrix(shape.rows, shape.cols).shape,
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.first_axis_concat);
    return Value.array(handle);
}

fn newReshapeViewValue(self: *Session, source: Value, shape: NumericShapeSnapshot) KError!Value {
    if (shape.rank == 0) return error.Type;

    const source_handle = valueNumericHandle(source);
    if (source_handle == null and valueNumericMode(source) == null) return error.Type;
    const retained_source = if (source_handle) |handle|
        if (numericArrayReshapeSource(handle)) |base_source|
            try self.retainEscapedValue(base_source)
        else
            try self.retainEscapedValue(source)
    else
        try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const preferred: NumericArrayPreferred = if (source_handle) |handle|
        handle.preferred
    else switch (source.arrayKind()) {
        .backend_array => .mlx,
        .host_dense_array => .host,
        else => return error.Type,
    };

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = preferred,
        .structural = .{ .reshape_view = .{ .source = retained_source } },
        .rank = shape.rank,
        .shape = shape.shape,
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.reshape_view);
    return Value.array(handle);
}

fn newTransposeViewValue(self: *Session, source: Value) KError!Value {
    const source_handle = shapedNumericHandle(source) orelse return error.Type;
    if (source_handle.rank != 2) return error.Type;

    if (numericArrayIsTransposeView(source_handle)) {
        return self.shareValue(numericArrayTransposeSource(source_handle) orelse return error.Type);
    }

    const retained_source = try self.retainEscapedValue(source);
    errdefer self.releaseValue(retained_source);

    const handle = try allocNumericArrayHandle(self, .managed);
    handle.* = .{
        .header = HeapHeader.init(.numeric_array, .managed),
        .preferred = source_handle.preferred,
        .structural = .{ .transpose_view = .{ .source = retained_source } },
        .rank = 2,
        .shape = numericShapeSnapshotMatrix(@intCast(source_handle.shape[1]), @intCast(source_handle.shape[0])).shape,
        .host = null,
        .mlx = null,
    };
    syncNumericArrayChildren(handle);
    self.registerManagedNumericHandle(handle);
    self.noteNumericStructuralAlloc(.transpose_view);
    return Value.array(handle);
}

fn wrapOwnedHostArrayValue(self: *Session, array: *HostDenseArray) !Value {
    if (array.logical_handle) |handle| return Value.array(handle);
    return try newNumericArrayValue(self, array.header.owner, .host, array, null);
}

fn wrapOwnedBackendArrayValue(self: *Session, array: *BackendArray) !Value {
    if (array.logical_handle) |handle| return Value.array(handle);
    return try newNumericArrayValue(self, array.header.owner, .mlx, null, array);
}

fn hostDenseSourceValue(array: *const HostDenseArray) Value {
    if (array.logical_handle) |handle| return Value.array(handle);
    return Value.array(@constCast(array));
}

const dense_backend_min_len_dyad: usize = 500_000;
const dense_backend_min_len_reduce: usize = 500_000;
const dense_backend_min_len_autodiff: usize = 1024;
const dense_backend_min_len_transpose: usize = 2_048;
const dense_backend_min_len_matmul: usize = 65_536;
const dense_backend_row_host_len_dyad: usize = 512;
const dual_resident_numeric_budget: usize = 8;

const DenseRegionFacts = struct {
    elem_count: usize = 0,
    matrix_rows: usize = 0,
    matrix_cols: usize = 0,
    has_backend_residency: bool = false,
    has_unmaterialized_range: bool = false,
    has_packed_bit_input: bool = false,
    prefer_host_kernel: bool = false,
    prefer_backend_pipeline: bool = false,
    supports_backend: bool = true,
    device_preference: device.DevicePreference = .cpu,
};

const DensePlanDecision = struct {
    backend: DenseExecBackend,
    reason: DensePlanReason,
};

const DenseValuePlanFacts = struct {
    has_backend_residency: bool = false,
    has_unmaterialized_range: bool = false,
    supports_host_dense: bool = false,
    supports_cheap_host_dense: bool = false,
};

fn denseValuePlanFacts(value: Value) DenseValuePlanFacts {
    return .{
        .has_backend_residency = hasBackendRealization(value),
        .has_unmaterialized_range = isUnmaterializedRangeIotaValue(value),
        .supports_host_dense = valueSupportsHostDensePlanning(value),
        .supports_cheap_host_dense = valueSupportsCheapHostDensePlanning(value),
    };
}

fn ensureNumericArrayHandle(self: *Session, value: Value) !*NumericArray {
    std.debug.assert(value.tag() == .array);
    return switch (value.arraySubkind()) {
        .numeric_array => @constCast(value.asNumericArray()),
        .host_dense_array => blk: {
            const array = @constCast(value.asHostDenseArray());
            if (array.logical_handle) |handle| break :blk handle;
            const handle = try allocNumericArrayHandle(self, array.header.owner);
            handle.* = .{
                .header = .{
                    .kind = .numeric_array,
                    .owner = array.header.owner,
                    .ref_count = if (array.header.owner == .managed) array.header.ref_count else 0,
                },
                .preferred = .host,
                .host = array,
                .mlx = null,
            };
            numericArraySetVectorShape(handle, array.len());
            syncNumericArrayChildren(handle);
            self.registerManagedNumericHandle(handle);
            break :blk handle;
        },
        .backend_array => blk: {
            const array = @constCast(value.asBackendArray());
            if (array.logical_handle) |handle| break :blk handle;
            const handle = try allocNumericArrayHandle(self, array.header.owner);
            handle.* = .{
                .header = .{
                    .kind = .numeric_array,
                    .owner = array.header.owner,
                    .ref_count = if (array.header.owner == .managed) array.header.ref_count else 0,
                },
                .preferred = .mlx,
                .host = null,
                .mlx = array,
            };
            numericArraySetShapeFromBackend(handle, array.array);
            syncNumericArrayChildren(handle);
            self.registerManagedNumericHandle(handle);
            break :blk handle;
        },
        else => error.Type,
    };
}

fn hasBackendRealization(value: Value) bool {
    if (value.tag() != .array) return false;
    return switch (value.arraySubkind()) {
        .numeric_array => blk: {
            const handle = value.asNumericArray();
            if (numericHasBackendAttachment(handle)) break :blk true;
            if (numericArrayFlatSliceSource(handle)) |source| break :blk hasBackendRealization(source);
            if (numericArrayFlatConcatLeft(handle)) |left| {
                const right = numericArrayFlatConcatRight(handle) orelse break :blk hasBackendRealization(left);
                break :blk hasBackendRealization(left) or hasBackendRealization(right);
            }
            if (numericArrayFlatSegmentsValues(handle)) |segments| {
                for (segments) |segment| {
                    if (hasBackendRealization(segment)) break :blk true;
                }
            }
            if (numericArrayFirstAxisSliceSource(handle)) |source| break :blk hasBackendRealization(source);
            if (numericArrayFirstAxisIndexSource(handle)) |source| break :blk hasBackendRealization(source);
            if (numericArrayFirstAxisConcatLeft(handle)) |left| {
                const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk hasBackendRealization(left);
                break :blk hasBackendRealization(left) or hasBackendRealization(right);
            }
            if (numericArrayReshapeSource(handle)) |source| break :blk hasBackendRealization(source);
            if (numericArrayTransposeSource(handle)) |source| break :blk hasBackendRealization(source);
            break :blk false;
        },
        .host_dense_array => if (value.asHostDenseArray().logical_handle != null)
            numericHasBackendAttachment(value.asHostDenseArray().logical_handle.?)
        else
            false,
        .backend_array => true,
        else => false,
    };
}

fn numericVectorLen(value: Value) ?usize {
    if (valueNumericHandle(value)) |handle| {
        if (handle.rank != 1) return null;
        return @intCast(handle.shape[0]);
    }
    if (value.tag() != .array) return null;
    return switch (value.arrayKind()) {
        .host_dense_array => value.asHostDenseArray().len(),
        .backend_array => blk: {
            const array = value.asBackendArray().array;
            if (array.ndim() != 1) break :blk null;
            const shape = array.shape();
            if (shape.len != 1) break :blk null;
            break :blk @intCast(shape[0]);
        },
        else => null,
    };
}

fn supportsBackendDyad(op: BuiltinId) bool {
    return switch (op) {
        .add, .sub, .mul, .div, .pow, .minimum, .maximum, .less, .more, .equal => true,
        else => false,
    };
}

fn supportsBackendMonad(op: BuiltinId) bool {
    return switch (op) {
        .add, .sub, .div, .exp, .log, .sin, .cos, .tanh, .sigmoid => true,
        else => false,
    };
}

fn backendSupportsFloatStorageKindOnDevice(self: *Session, value: Value) bool {
    if (self.device_preference != .gpu) return true;
    return valueFloatStorageKind(value) != .float64;
}

fn backendSupportsNumericDyadDtypes(self: *Session, left: Value, right: Value) bool {
    return backendSupportsFloatStorageKindOnDevice(self, left) and
        backendSupportsFloatStorageKindOnDevice(self, right);
}

fn backendSupportsMatmulDtypes(self: *Session, left: Value, right: Value) bool {
    if (!backendSupportsNumericDyadDtypes(self, left, right)) return false;
    const left_mode = valueNumericMode(left) orelse return false;
    const right_mode = valueNumericMode(right) orelse return false;
    return left_mode == .float or right_mode == .float;
}

fn createBackendArrayFromHostArray(self: *Session, array: *const HostDenseArray) KError!mlx.Array {
    var dims_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
    const dims = hostDenseShapeDims(array, &dims_buf);
    return switch (array.storage) {
        .bit => |words| blk: {
            const converted = try self.allocator.alloc(bool, array.logical_len);
            defer self.allocator.free(converted);
            for (0..array.logical_len) |idx| converted[idx] = bitGet(words, idx);
            break :blk mlx.Array.fromBoolSliceChecked(converted, dims) catch |err| return mapMlxError(err);
        },
        .int8 => |items| blk: {
            const logical_items = hostDenseLogicalItems(i8, array, items);
            const converted = try self.allocator.alloc(i32, logical_items.len);
            defer self.allocator.free(converted);
            for (logical_items, 0..) |item, idx| converted[idx] = item;
            break :blk mlx.Array.fromIntSlice(converted, dims);
        },
        .int16 => |items| blk: {
            const logical_items = hostDenseLogicalItems(i16, array, items);
            const converted = try self.allocator.alloc(i32, logical_items.len);
            defer self.allocator.free(converted);
            for (logical_items, 0..) |item, idx| converted[idx] = item;
            break :blk mlx.Array.fromIntSlice(converted, dims);
        },
        .int32 => |items| blk: {
            break :blk mlx.Array.fromIntSliceChecked(hostDenseLogicalItems(i32, array, items), dims) catch |err| return mapMlxError(err);
        },
        .int64 => |items| blk: {
            break :blk mlx.Array.fromInt64SliceChecked(hostDenseLogicalItems(i64, array, items), dims) catch |err| return mapMlxError(err);
        },
        .float32 => |items| blk: {
            break :blk mlx.Array.fromFloatSliceChecked(hostDenseLogicalItems(f32, array, items), dims) catch |err| return mapMlxError(err);
        },
        .float64 => |items| blk: {
            const ctx = try self.backendContext();
            if (ctx.resolved == .gpu) return error.Unsupported;
            break :blk mlx.Array.fromFloat64SliceChecked(hostDenseLogicalItems(f64, array, items), dims) catch |err| return mapMlxError(err);
        },
    };
}

fn backendArrayElementCount(array: mlx.Array) usize {
    if (array.ndim() == 0) return 1;
    var total: usize = 1;
    for (array.shape()) |dim| total *= @as(usize, @intCast(dim));
    return total;
}

fn transposeTileLen(comptime T: type) usize {
    return if (@sizeOf(T) >= 8) 16 else 32;
}

fn reverseTypedSlice(comptime T: type, out: []T, source: []const T) void {
    std.debug.assert(out.len == source.len);
    if (source.len == 0) return;
    var src_idx = source.len;
    var dst_idx: usize = 0;
    while (src_idx > 0) {
        src_idx -= 1;
        out[dst_idx] = source[src_idx];
        dst_idx += 1;
    }
}

fn transposeBlockedTyped(comptime T: type, out: []T, source: []const T, rows: usize, cols: usize) void {
    std.debug.assert(out.len == source.len);
    std.debug.assert(out.len == rows * cols);
    const tile = transposeTileLen(T);

    var row_base: usize = 0;
    while (row_base < rows) : (row_base += tile) {
        const row_end = @min(row_base + tile, rows);
        var col_base: usize = 0;
        while (col_base < cols) : (col_base += tile) {
            const col_end = @min(col_base + tile, cols);
            var row = row_base;
            while (row < row_end) : (row += 1) {
                const source_row_base = row * cols;
                var col = col_base;
                while (col < col_end) : (col += 1) {
                    out[col * rows + row] = source[source_row_base + col];
                }
            }
        }
    }
}

fn transposeBlockedIntResult(comptime T: type, out: *HostDenseAlloc(T), source: []const T, rows: usize, cols: usize) void {
    transposeBlockedTyped(T, out.items, source, rows, cols);
}

fn sourceHostIntRange(value: Value, array: *const HostDenseArray) HostIntRange {
    return if (hostIntArrayView(array)) |view|
        hostIntDenseValueRange(value, .{ .dense = view })
    else
        .{ .min = 0, .max = 0 };
}

fn createHostArrayFromTransposeView(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsTransposeView(handle)) return error.Type;
    const value = Value.array(@constCast(handle));
    const source = numericArrayTransposeSource(handle) orelse return error.Type;
    const source_shape = valueNumericMatrixShape(source) orelse return error.Type;
    const rows = source_shape.rows;
    const cols = source_shape.cols;
    const total_len = rows * cols;
    noteTransposeMaterializationDecision(self, value, total_len, .host);
    const source_host = try ensureNumericHostAttachmentForDenseView(self, source);

    if (source_host) |array| {
        switch (array.storage) {
            .float32 => |items| {
                if (items.len == total_len) {
                    const out = try self.allocOwnedHostFloat32Result(owner, total_len);
                    transposeBlockedTyped(f32, out.items, items, rows, cols);
                    const analysis = analyzeFloatSlice32(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    return out.array;
                }
            },
            .float64 => |items| {
                if (items.len == total_len) {
                    const out = try self.allocOwnedHostFloatResult(owner, total_len);
                    transposeBlockedTyped(f64, out.items, items, rows, cols);
                    const analysis = analyzeFloatSlice(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    return out.array;
                }
            },
            .int8 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i8, .int8, owner, total_len);
                    transposeBlockedIntResult(i8, &out, items, rows, cols);
                    const host = out.array;
                    hostDenseSetFlags(host, host_dense_flag_normalized);
                    hostDenseSetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            .int16 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i16, .int16, owner, total_len);
                    transposeBlockedIntResult(i16, &out, items, rows, cols);
                    const host = out.array;
                    hostDenseSetFlags(host, host_dense_flag_normalized);
                    hostDenseSetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            .int32 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i32, .int32, owner, total_len);
                    transposeBlockedIntResult(i32, &out, items, rows, cols);
                    const host = out.array;
                    hostDenseSetFlags(host, host_dense_flag_normalized);
                    hostDenseSetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            .int64 => |items| {
                if (items.len == total_len) {
                    var out = try self.allocHostArrayTyped(i64, .int64, owner, total_len);
                    transposeBlockedIntResult(i64, &out, items, rows, cols);
                    const host = out.array;
                    hostDenseSetFlags(host, host_dense_flag_normalized);
                    hostDenseSetCachedIntRange(host, sourceHostIntRange(source, array));
                    return host;
                }
            },
            else => {},
        }
    }

    return switch (valueNumericMode(source) orelse return error.Type) {
        .float => blk: {
            const out = try self.allocOwnedHostFloatResult(owner, total_len);
            const transpose_view: HostTransposeView = .{
                .source_value = source,
                .source_host = source_host,
                .source_rows = rows,
                .source_cols = cols,
            };
            for (0..total_len) |idx| out.items[idx] = try hostFloatDenseViewItem(.{ .transpose = .{
                .source_value = transpose_view.source_value,
                .source_host = transpose_view.source_host,
                .source_rows = transpose_view.source_rows,
                .source_cols = transpose_view.source_cols,
            } }, idx);
            const analysis = analyzeFloatSlice(out.items);
            hostDenseSetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        .int => blk: {
            const source_view = valueHostIntStructuralView(source) orelse return error.Type;
            const analysis = .{
                .kind = hostIntDenseViewKind(source_view),
                .range = hostIntDenseValueRange(source, source_view),
            };
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            const transpose_view: HostTransposeView = .{
                .source_value = source,
                .source_host = source_host,
                .source_rows = rows,
                .source_cols = cols,
            };
            for (0..total_len) |idx| try out.set(idx, try hostTransposeIntItem(transpose_view, idx));
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostDenseSetFlags(host, hostTransposeIntFlags(transpose_view));
            hostDenseSetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createBackendArrayFromTransposeView(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsTransposeView(handle)) return error.Type;
    const value = Value.array(@constCast(handle));
    const source = numericArrayTransposeSource(handle) orelse return error.Type;
    noteTransposeMaterializationDecision(self, value, numericArrayElementCount(handle), .mlx);
    var source_array = try self.materializeBackendArray(source);
    defer source_array.deinit();
    const ctx = try self.backendContext();
    return mlx.Array.transpose(ctx.*, source_array) catch |err| return mapMlxError(err);
}

fn createHostArrayFromRangeIota(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsRangeIota(handle)) return error.Type;
    const len = numericArrayRangeLen(handle);
    const bounds = numericArrayRangeIotaBounds(handle);
    const kind = hostIntStorageKindForRange(bounds.min, bounds.max);
    var out = try self.allocOwnedHostIntResult(owner, kind, len);
    for (0..len) |idx| try out.set(idx, try numericArrayRangeIotaValueAt(handle, idx));
    const host = out.arrayPtr();
    if (kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
    hostDenseSetFlags(
        host,
        host_dense_flag_normalized |
            orderFlagsFromMonotonic(numericArrayRangeIota(handle).step >= 0, numericArrayRangeIota(handle).step <= 0),
    );
    hostDenseSetCachedIntRange(host, bounds);
    return host;
}

fn createBackendArrayFromRangeIota(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (comptime !runtime_has_mlx) return error.Unsupported;
    if (!numericArrayIsRangeIota(handle)) return error.Type;
    const len = numericArrayRangeLen(handle);
    const ctx = try self.backendContext();
    if (len == 0) {
        return mlx.Array.zeros(ctx.*, handle.shapeSlice(), c.MLX_INT32) catch |err| return mapMlxError(err);
    }

    const start = numericArrayRangeIota(handle).start;
    const step = numericArrayRangeIota(handle).step;
    if (step == 0) {
        const scalar = std.math.cast(i32, start) orelse return error.Unsupported;
        var base = mlx.Array.zeros(ctx.*, handle.shapeSlice(), c.MLX_INT32) catch |err| return mapMlxError(err);
        defer base.deinit();
        var offset = mlx.Array.fromInt(scalar);
        defer offset.deinit();
        return mlx.Array.add(ctx.*, base, offset) catch |err| return mapMlxError(err);
    }

    const last = try numericArrayRangeIotaValueAt(handle, len - 1);
    _ = std.math.cast(i32, start) orelse return error.Unsupported;
    _ = std.math.cast(i32, last) orelse return error.Unsupported;

    const len_i64 = std.math.cast(i64, len) orelse return error.Unsupported;
    const stop = std.math.add(i64, start, std.math.mul(i64, step, len_i64) catch return error.Unsupported) catch return error.Unsupported;
    var out = mlx.Array.arange(ctx.*, @floatFromInt(start), @floatFromInt(stop), @floatFromInt(step), c.MLX_INT32) catch |err| return mapMlxError(err);
    if (handle.rank == 1) return out;
    const reshaped = mlx.Array.reshape(ctx.*, out, handle.shapeSlice()) catch |err| {
        out.deinit();
        return mapMlxError(err);
    };
    out.deinit();
    return reshaped;
}

fn createHostArrayFromFlatSlice(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsFlatSlice(handle)) return error.Type;
    const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
    const start = numericArrayFlatSliceStart(handle) orelse return error.Type;
    const len = numericVectorLen(Value.array(@constCast(handle))) orelse return error.Type;
    const collapsed = try tryCollapseHostFlatSlice(self, source, start, len);
    if (valueNumericHandle(source)) |source_handle| {
        if (source_handle.host == null and source_handle.mlx != null and
            !numericArrayIsRangeIota(source_handle) and
            !numericArrayIsFlatSlice(source_handle) and
            !numericArrayIsFlatConcat(source_handle) and
            !numericArrayIsFlatSegments(source_handle) and
            !numericArrayIsFirstAxisSlice(source_handle) and
            !numericArrayIsFirstAxisIndex(source_handle) and
            !numericArrayIsFirstAxisConcat(source_handle) and
            !numericArrayIsTransposeView(source_handle) and
            !numericArrayIsReshapeView(source_handle))
        {
            _ = try tryEnsureHostRealizationForHandle(self, @constCast(source_handle)) orelse return error.Type;
        }
    }

    return switch (valueNumericMode(source) orelse return error.Type) {
        .float => blk: {
            if (collapsed) |view| switch (view) {
                .flat_slice => |items| {
                    if (items.source_host) |array| switch (array.storage) {
                        .float32 => |values| {
                            const out = try self.allocHostArrayTyped(f32, .float32, owner, len);
                            @memcpy(out.items, values[items.start .. items.start + len]);
                            const analysis = analyzeFloatSlice32(out.items);
                            hostDenseSetFlags(out.array, analysis.flags);
                            break :blk out.array;
                        },
                        .float64 => |values| {
                            const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                            @memcpy(out.items, values[items.start .. items.start + len]);
                            const analysis = analyzeFloatSlice(out.items);
                            hostDenseSetFlags(out.array, analysis.flags);
                            break :blk out.array;
                        },
                        else => {},
                    };
                    const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                    for (0..len) |idx| out.items[idx] = try hostFlatSliceFloatItem(items, idx);
                    const analysis = analyzeFloatSlice(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
                .flat_stride => |items| {
                    if (items.source_host) |array| switch (array.storage) {
                        .float32 => {
                            const out = try self.allocHostArrayTyped(f32, .float32, owner, len);
                            for (0..len) |idx| out.items[idx] = @floatCast(try hostFlatStrideFloatItem(items, idx));
                            const analysis = analyzeFloatSlice32(out.items);
                            hostDenseSetFlags(out.array, analysis.flags);
                            break :blk out.array;
                        },
                        else => {},
                    };
                    const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                    for (0..len) |idx| out.items[idx] = try hostFlatStrideFloatItem(items, idx);
                    const analysis = analyzeFloatSlice(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
            };
            if (hostDenseIfPresent(source)) |array| switch (array.storage) {
                .float32 => |items| {
                    const out = try self.allocHostArrayTyped(f32, .float32, owner, len);
                    @memcpy(out.items, items[start .. start + len]);
                    const analysis = analyzeFloatSlice32(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
                .float64 => |items| {
                    const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
                    @memcpy(out.items, items[start .. start + len]);
                    const analysis = analyzeFloatSlice(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
                else => {},
            };
            const out = try self.allocHostArrayTyped(f64, .float64, owner, len);
            for (0..len) |idx| out.items[idx] = try numericFloatAt(source, start + idx);
            const analysis = analyzeFloatSlice(out.items);
            hostDenseSetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        .int => blk: {
            if (collapsed) |view| switch (view) {
                .flat_slice => |items| {
                    if (items.source_host) |array| switch (array.storage) {
                        .bit => {
                            const out = try self.allocHostBitArray(owner, len);
                            bitCopyRange(out.words, 0, .{ .words = array.storage.bit, .len = array.logical_len }, items.start, len);
                            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
                            hostDenseSetFlags(out.array, metadata.flags);
                            hostDenseSetCachedIntRange(out.array, metadata.range);
                            break :blk out.array;
                        },
                        else => {},
                    };
                    var values = try self.allocator.alloc(i64, len);
                    defer self.allocator.free(values);
                    for (0..len) |idx| values[idx] = try hostFlatSliceIntItem(items, idx);
                    const analysis = analyzeIntSlice(values);
                    var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
                    for (values, 0..) |item, idx| try out.set(idx, item);
                    const host = out.arrayPtr();
                    if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
                    hostDenseSetFlags(host, analysis.flags);
                    hostDenseSetCachedIntRange(host, analysis.range);
                    break :blk host;
                },
                .flat_stride => |items| {
                    if (items.source_host) |array| switch (array.storage) {
                        .bit => {
                            const out = try self.allocHostBitArray(owner, len);
                            for (0..len) |idx| {
                                bitSet(out.words, idx, bitGet(array.storage.bit, items.start + idx * items.step));
                            }
                            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
                            hostDenseSetFlags(out.array, metadata.flags);
                            hostDenseSetCachedIntRange(out.array, metadata.range);
                            break :blk out.array;
                        },
                        else => {},
                    };
                    var values = try self.allocator.alloc(i64, len);
                    defer self.allocator.free(values);
                    for (0..len) |idx| values[idx] = try hostFlatStrideIntItem(items, idx);
                    const analysis = analyzeIntSlice(values);
                    var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
                    for (values, 0..) |item, idx| try out.set(idx, item);
                    const host = out.arrayPtr();
                    if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
                    hostDenseSetFlags(host, analysis.flags);
                    hostDenseSetCachedIntRange(host, analysis.range);
                    break :blk host;
                },
            };
            if (hostDenseIfPresent(source)) |array| switch (array.storage) {
                .bit => {
                    const out = try self.allocHostBitArray(owner, len);
                    bitCopyRange(out.words, 0, .{ .words = array.storage.bit, .len = array.logical_len }, start, len);
                    const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
                    hostDenseSetFlags(out.array, metadata.flags);
                    hostDenseSetCachedIntRange(out.array, metadata.range);
                    break :blk out.array;
                },
                else => {},
            };
            var values = try self.allocator.alloc(i64, len);
            defer self.allocator.free(values);
            for (0..len) |idx| values[idx] = try numericIntAt(source, start + idx);
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostDenseSetFlags(host, analysis.flags);
            hostDenseSetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createBackendArrayFromFlatSlice(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFlatSlice(handle)) return error.Type;
    const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
    const source_len = numericFlatLen(source) orelse return error.Type;
    const start = numericArrayFlatSliceStart(handle) orelse return error.Type;
    const len = numericVectorLen(Value.array(@constCast(handle))) orelse return error.Type;

    var source_array = try self.materializeBackendArray(source);
    defer source_array.deinit();
    if (source_array.ndim() != 1) {
        const dims = [_]i32{std.math.cast(i32, source_len) orelse return error.Unsupported};
        const reshaped = mlx.Array.reshape((try self.backendContext()).*, source_array, &dims) catch |err| return mapMlxError(err);
        source_array.deinit();
        source_array = reshaped;
    }
    const ctx = try self.backendContext();
    const start_buf = [_]i32{std.math.cast(i32, start) orelse return error.Unsupported};
    const stop_buf = [_]i32{std.math.cast(i32, start + len) orelse return error.Unsupported};
    const stride_buf = [_]i32{1};
    return mlx.Array.slice(ctx.*, source_array, &start_buf, &stop_buf, &stride_buf) catch |err| return mapMlxError(err);
}

fn createHostArrayFromFlatValues(self: *Session, owner: HeapOwner, segments: []const Value) KError!*HostDenseArray {
    if (segments.len == 0) return error.Type;
    const mode = valueNumericMode(segments[0]) orelse return error.Type;
    var total_len: usize = 0;
    var all_int = mode == .int;
    for (segments) |segment| {
        const segment_mode = valueNumericMode(segment) orelse return error.Type;
        if (segment_mode == .float) all_int = false;
        total_len += numericVectorLen(segment) orelse return error.Type;
    }

    if (all_int) {
        var all_bits = true;
        for (segments) |segment| {
            if (valueNumericBitSlice(segment) == null) {
                all_bits = false;
                break;
            }
        }
        if (all_bits) {
            const out = try self.allocHostBitArray(owner, total_len);
            var dst_start: usize = 0;
            for (segments) |segment| {
                const bits = valueNumericBitSlice(segment) orelse return error.Type;
                bitCopyRange(out.words, dst_start, bits, 0, bits.len);
                dst_start += bits.len;
            }
            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
            hostDenseSetFlags(out.array, metadata.flags);
            hostDenseSetCachedIntRange(out.array, metadata.range);
            return out.array;
        }

        var values = try self.allocator.alloc(i64, total_len);
        defer self.allocator.free(values);
        var out_idx: usize = 0;
        for (segments) |segment| {
            const len = numericVectorLen(segment) orelse return error.Type;
            for (0..len) |idx| {
                values[out_idx] = try numericIntAt(segment, idx);
                out_idx += 1;
            }
        }
        const analysis = analyzeIntSlice(values);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
        for (values, 0..) |item, idx| try out.set(idx, item);
        const host = out.arrayPtr();
        if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
        hostDenseSetFlags(host, analysis.flags);
        hostDenseSetCachedIntRange(host, analysis.range);
        return host;
    }

    var all_float32 = true;
    for (segments) |segment| {
        if (valueNumericFloat32Slice(segment) == null) {
            all_float32 = false;
            break;
        }
    }
    if (all_float32) {
        const out = try self.allocOwnedHostFloat32Result(owner, total_len);
        var out_idx: usize = 0;
        for (segments) |segment| {
            const items = valueNumericFloat32Slice(segment) orelse return error.Type;
            @memcpy(out.items[out_idx .. out_idx + items.len], items);
            out_idx += items.len;
        }
        const analysis = analyzeFloatSlice32(out.items);
        hostDenseSetFlags(out.array, analysis.flags);
        return out.array;
    }

    var saw_float32 = false;
    var saw_float64 = false;
    for (segments) |segment| switch (valueFloatStorageKind(segment) orelse continue) {
        .float32 => saw_float32 = true,
        .float64 => saw_float64 = true,
    };
    if (saw_float32 and !saw_float64) {
        const out = try self.allocOwnedHostFloat32Result(owner, total_len);
        var out_idx: usize = 0;
        for (segments) |segment| {
            const len = numericVectorLen(segment) orelse return error.Type;
            for (0..len) |idx| {
                out.items[out_idx] = @floatCast(try numericFloatAt(segment, idx));
                out_idx += 1;
            }
        }
        const analysis = analyzeFloatSlice32(out.items);
        hostDenseSetFlags(out.array, analysis.flags);
        return out.array;
    }

    const out = try self.allocOwnedHostFloatResult(owner, total_len);
    var out_idx: usize = 0;
    for (segments) |segment| {
        const len = numericVectorLen(segment) orelse return error.Type;
        for (0..len) |idx| {
            out.items[out_idx] = try numericFloatAt(segment, idx);
            out_idx += 1;
        }
    }
    const analysis = analyzeFloatSlice(out.items);
    hostDenseSetFlags(out.array, analysis.flags);
    return out.array;
}

fn createBackendArrayFromFlatValues(self: *Session, segments: []const Value) KError!mlx.Array {
    if (segments.len == 0) return error.Type;
    if (flatValuesPreferSingleHostUpload(segments)) {
        const host = try createHostArrayFromFlatValues(self, .scratch, segments);
        return try createBackendArrayFromHostArray(self, host);
    }

    var arrays = try self.allocator.alloc(mlx.Array, segments.len);
    defer self.allocator.free(arrays);
    defer for (arrays[0..segments.len]) |*item| item.deinit();

    for (segments, 0..) |segment, idx| {
        arrays[idx] = try self.materializeBackendArray(segment);
    }
    return try mlxConcatAxis0((try self.backendContext()).*, arrays[0..segments.len]);
}

fn flatValuesPreferSingleHostUpload(segments: []const Value) bool {
    if (segments.len < 8) return false;
    for (segments) |segment| {
        if (hasBackendRealization(segment)) return false;
        if (valueNumericMode(segment) == null) return false;
        if (!sourceSupportsCheapHostDense(segment)) return false;
    }
    return true;
}

fn createHostArrayFromFlatConcat(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsFlatConcat(handle)) return error.Type;
    const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
    const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
    return try createHostArrayFromFlatValues(self, owner, &[_]Value{ left, right });
}

fn createBackendArrayFromFlatConcat(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFlatConcat(handle)) return error.Type;
    const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
    const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
    return try createBackendArrayFromFlatValues(self, &[_]Value{ left, right });
}

fn createHostArrayFromFlatSegments(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsFlatSegments(handle)) return error.Type;
    const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
    return try createHostArrayFromFlatValues(self, owner, segments);
}

fn createBackendArrayFromFlatSegments(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFlatSegments(handle)) return error.Type;
    const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
    return try createBackendArrayFromFlatValues(self, segments);
}

fn createHostArrayFromFirstAxisSlice(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsFirstAxisSlice(handle)) return error.Type;
    const slice = numericArrayFirstAxisSlicePayload(handle) orelse return error.Type;
    const source_handle = shapedNumericHandle(slice.source) orelse return error.Type;
    const row_width = numericShapeInnerBlockLen(source_handle);
    const row_count: usize = @intCast(handle.shape[0]);
    const start = slice.start * row_width;
    const total_len = row_count * row_width;

    if (valueRangeIotaHandle(slice.source)) |range_handle| {
        var values = try self.allocator.alloc(i64, total_len);
        defer self.allocator.free(values);
        var out_idx: usize = 0;
        for (0..row_count) |row| {
            const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
            if (source_row_i64 < 0) return error.Type;
            const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
            for (0..row_width) |col| {
                values[out_idx] = try numericArrayRangeIotaValueAt(range_handle, base_idx + col);
                out_idx += 1;
            }
        }
        const analysis = analyzeIntSlice(values);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
        for (values, 0..) |item, idx| try out.set(idx, item);
        const host = out.arrayPtr();
        if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
        hostDenseSetFlags(host, analysis.flags);
        hostDenseSetCachedIntRange(host, analysis.range);
        return host;
    }

    const source_array = try hostStructuralArrayForHandle(self, try numericHandleRequired(slice.source));
    if (slice.step == 1) switch (source_array.storage) {
        .bit => {
            const out = try self.allocHostBitArray(owner, total_len);
            bitCopyRange(out.words, 0, .{ .words = source_array.storage.bit, .len = source_array.logical_len }, start, total_len);
            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
            hostDenseSetFlags(out.array, metadata.flags);
            hostDenseSetCachedIntRange(out.array, metadata.range);
            return out.array;
        },
        .float32 => |items| {
            const out = try self.allocHostArrayTyped(f32, .float32, owner, total_len);
            @memcpy(out.items, items[start .. start + total_len]);
            const host = out.array;
            host.flags = source_array.flags;
            return host;
        },
        .float64 => |items| {
            const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
            @memcpy(out.items, items[start .. start + total_len]);
            const host = out.array;
            host.flags = source_array.flags;
            return host;
        },
        else => {
            const kind = hostIntArrayViewKind(hostIntArrayView(source_array).?);
            var out = try self.allocOwnedHostIntResult(owner, kind, total_len);
            for (0..total_len) |idx| try out.set(idx, try hostDenseIntAt(source_array, start + idx));
            const host = out.arrayPtr();
            host.flags = source_array.flags;
            host.int_range_known = source_array.int_range_known;
            host.int_range_min = source_array.int_range_min;
            host.int_range_max = source_array.int_range_max;
            return host;
        },
    };

    switch (hostDenseNumericMode(source_array)) {
        .float => switch (source_array.storage) {
            .float32 => {
                const out = try self.allocHostArrayTyped(f32, .float32, owner, total_len);
                var out_idx: usize = 0;
                for (0..row_count) |row| {
                    const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
                    if (source_row_i64 < 0) return error.Type;
                    const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                    for (0..row_width) |col| {
                        out.items[out_idx] = @floatCast(try hostDenseFloatAt(source_array, base_idx + col));
                        out_idx += 1;
                    }
                }
                const analysis = analyzeFloatSlice32(out.items);
                hostDenseSetFlags(out.array, analysis.flags);
                return out.array;
            },
            .float64 => {
                const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
                var out_idx: usize = 0;
                for (0..row_count) |row| {
                    const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
                    if (source_row_i64 < 0) return error.Type;
                    const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                    for (0..row_width) |col| {
                        out.items[out_idx] = try hostDenseFloatAt(source_array, base_idx + col);
                        out_idx += 1;
                    }
                }
                const analysis = analyzeFloatSlice(out.items);
                hostDenseSetFlags(out.array, analysis.flags);
                return out.array;
            },
            else => return error.Type,
        },
        .int => {
            if (std.meta.activeTag(source_array.storage) == .bit) {
                const out = try self.allocHostBitArray(owner, total_len);
                for (0..row_count) |row| {
                    const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
                    if (source_row_i64 < 0) return error.Type;
                    bitCopyRange(
                        out.words,
                        row * row_width,
                        .{ .words = source_array.storage.bit, .len = source_array.logical_len },
                        @as(usize, @intCast(source_row_i64)) * row_width,
                        row_width,
                    );
                }
                const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
                hostDenseSetFlags(out.array, metadata.flags);
                hostDenseSetCachedIntRange(out.array, metadata.range);
                return out.array;
            }
            var values = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(values);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    values[out_idx] = try hostDenseIntAt(source_array, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostDenseSetFlags(host, analysis.flags);
            hostDenseSetCachedIntRange(host, analysis.range);
            return host;
        },
    }
}

fn createBackendArrayFromFirstAxisSlice(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFirstAxisSlice(handle)) return error.Type;
    const slice = numericArrayFirstAxisSlicePayload(handle) orelse return error.Type;
    const source_handle = shapedNumericHandle(slice.source) orelse return error.Type;
    if (source_handle.rank != handle.rank) return error.Type;

    var source_array = try self.materializeBackendArray(slice.source);
    defer source_array.deinit();

    var start_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
    var stop_buf: [numeric_array_max_rank]i32 = [_]i32{0} ** numeric_array_max_rank;
    var stride_buf: [numeric_array_max_rank]i32 = [_]i32{1} ** numeric_array_max_rank;
    for (0..source_handle.rank) |idx| {
        stop_buf[idx] = source_handle.shape[idx];
    }

    const row_count: usize = @intCast(handle.shape[0]);
    const ctx = try self.backendContext();
    if (slice.step == 1) {
        start_buf[0] = std.math.cast(i32, slice.start) orelse return error.Unsupported;
        stop_buf[0] = std.math.cast(i32, slice.start + row_count) orelse return error.Unsupported;
        return mlx.Array.slice(
            ctx.*,
            source_array,
            start_buf[0..source_handle.rank],
            stop_buf[0..source_handle.rank],
            stride_buf[0..source_handle.rank],
        ) catch |err| return mapMlxError(err);
    }

    const idx_dims = [_]i32{std.math.cast(i32, row_count) orelse return error.Unsupported};
    const indices_buf = try self.allocator.alloc(i32, row_count);
    defer self.allocator.free(indices_buf);
    for (0..row_count) |row| {
        const row_idx_i64 = @as(i64, @intCast(slice.start)) + @as(i64, @intCast(row)) * @as(i64, slice.step);
        if (row_idx_i64 < 0) return error.Type;
        indices_buf[row] = std.math.cast(i32, row_idx_i64) orelse return error.Unsupported;
    }
    var indices = mlx.Array.fromIntSlice(indices_buf, &idx_dims);
    defer indices.deinit();
    return mlx.Array.takeAxis(ctx.*, source_array, indices, 0) catch |err| return mapMlxError(err);
}

fn createHostArrayFromFirstAxisIndex(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsFirstAxisIndex(handle)) return error.Type;
    const index = numericArrayFirstAxisIndexPayload(handle) orelse return error.Type;
    const source_handle = shapedNumericHandle(index.source) orelse return error.Type;
    const row_width = numericShapeInnerBlockLen(source_handle);
    const row_count: usize = @intCast(handle.shape[0]);
    const total_len = row_count * row_width;

    return switch (valueNumericMode(index.source) orelse return error.Type) {
        .float => blk: {
            const source_array_maybe = try ensureNumericHostAttachmentForDenseView(self, index.source);
            if (source_array_maybe) |source_array| switch (source_array.storage) {
                .float32 => {
                    const out = try self.allocHostArrayTyped(f32, .float32, owner, total_len);
                    var out_idx: usize = 0;
                    for (0..row_count) |row| {
                        const source_row_i64 = try numericIntAt(index.row_indices, row);
                        if (source_row_i64 < 0) return error.Type;
                        const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                        for (0..row_width) |col| {
                            out.items[out_idx] = @floatCast(try hostDenseFloatAt(source_array, base_idx + col));
                            out_idx += 1;
                        }
                    }
                    const analysis = analyzeFloatSlice32(out.items);
                    hostDenseSetFlags(out.array, analysis.flags);
                    break :blk out.array;
                },
                else => {},
            };
            const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = try numericIntAt(index.row_indices, row);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    out.items[out_idx] = try numericFloatAt(index.source, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeFloatSlice(out.items);
            hostDenseSetFlags(out.array, analysis.flags);
            break :blk out.array;
        },
        .int => blk: {
            if (valueNumericBitSlice(index.source)) |bits| {
                if (valueHostIntStructuralView(index.row_indices)) |view| {
                    const out = try self.allocHostBitArray(owner, total_len);
                    try Session.copyBitMatrixRowsByDenseSelector(out.words, bits, view, @intCast(source_handle.shape[0]), row_width);
                    const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
                    hostDenseSetFlags(out.array, metadata.flags);
                    hostDenseSetCachedIntRange(out.array, metadata.range);
                    break :blk out.array;
                }
            }
            var values = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(values);
            var out_idx: usize = 0;
            for (0..row_count) |row| {
                const source_row_i64 = try numericIntAt(index.row_indices, row);
                if (source_row_i64 < 0) return error.Type;
                const base_idx = @as(usize, @intCast(source_row_i64)) * row_width;
                for (0..row_width) |col| {
                    values[out_idx] = try numericIntAt(index.source, base_idx + col);
                    out_idx += 1;
                }
            }
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostDenseSetFlags(host, analysis.flags);
            hostDenseSetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createBackendArrayFromFirstAxisIndex(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFirstAxisIndex(handle)) return error.Type;
    const index = numericArrayFirstAxisIndexPayload(handle) orelse return error.Type;
    const row_count: usize = @intCast(handle.shape[0]);
    const idx_dims = [_]i32{std.math.cast(i32, row_count) orelse return error.Unsupported};
    const indices_buf = try self.allocator.alloc(i32, row_count);
    defer self.allocator.free(indices_buf);
    for (0..row_count) |row| {
        const row_i64 = try numericIntAt(index.row_indices, row);
        if (row_i64 < 0) return error.Type;
        indices_buf[row] = std.math.cast(i32, row_i64) orelse return error.Unsupported;
    }

    var source_array = try self.materializeBackendArray(index.source);
    defer source_array.deinit();
    var indices = mlx.Array.fromIntSlice(indices_buf, &idx_dims);
    defer indices.deinit();
    const ctx = try self.backendContext();
    return mlx.Array.takeAxis(ctx.*, source_array, indices, 0) catch |err| return mapMlxError(err);
}

fn createHostArrayFromFirstAxisConcat(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsFirstAxisConcat(handle)) return error.Type;
    const cols: usize = @intCast(handle.shape[1]);
    var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFirstAxisMatrixSegments(self.allocator, Value.array(@constCast(handle)), cols, &segments);
    if (segments.items.len == 0) return error.Type;

    const left = segments.items[0].value;
    const left_mode = valueNumericMode(left) orelse return error.Type;
    var right_mode: HostDenseElem = left_mode;
    var total_len: usize = 0;
    for (segments.items) |segment| {
        const mode = valueNumericMode(segment.value) orelse return error.Type;
        if (mode == .float) right_mode = .float;
        total_len += numericFlatLen(segment.value) orelse return error.Type;
    }

    if (left_mode == .int and right_mode == .int) {
        var all_bits = true;
        for (segments.items) |segment| {
            if (valueNumericBitSlice(segment.value) == null) {
                all_bits = false;
                break;
            }
        }
        if (all_bits) {
            const out = try self.allocHostBitArray(owner, total_len);
            var dst_start: usize = 0;
            for (segments.items) |segment| {
                const bits = valueNumericBitSlice(segment.value) orelse return error.Type;
                bitCopyRange(out.words, dst_start, bits, 0, bits.len);
                dst_start += bits.len;
            }
            const metadata = analyzeBitSlice(.{ .words = out.words, .len = out.len });
            hostDenseSetFlags(out.array, metadata.flags);
            hostDenseSetCachedIntRange(out.array, metadata.range);
            return out.array;
        }

        var values = try self.allocator.alloc(i64, total_len);
        defer self.allocator.free(values);
        var out_idx: usize = 0;
        for (segments.items) |segment| {
            const len = numericFlatLen(segment.value) orelse return error.Type;
            for (0..len) |idx| {
                values[out_idx] = try numericIntAt(segment.value, idx);
                out_idx += 1;
            }
        }
        const analysis = analyzeIntSlice(values);
        var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
        for (values, 0..) |item, idx| try out.set(idx, item);
        const host = out.arrayPtr();
        if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
        hostDenseSetFlags(host, analysis.flags);
        hostDenseSetCachedIntRange(host, analysis.range);
        return host;
    }

    var saw_float32 = false;
    var saw_float64 = false;
    for (segments.items) |segment| switch (valueFloatStorageKind(segment.value) orelse continue) {
        .float32 => saw_float32 = true,
        .float64 => saw_float64 = true,
    };
    if (saw_float32 and !saw_float64) {
        const out = try self.allocOwnedHostFloat32Result(owner, total_len);
        var out_idx: usize = 0;
        for (segments.items) |segment| {
            const len = numericFlatLen(segment.value) orelse return error.Type;
            for (0..len) |idx| {
                out.items[out_idx] = @floatCast(try numericFloatAt(segment.value, idx));
                out_idx += 1;
            }
        }
        const analysis = analyzeFloatSlice32(out.items);
        hostDenseSetFlags(out.array, analysis.flags);
        return out.array;
    }

    const out = try self.allocOwnedHostFloatResult(owner, total_len);
    var out_idx: usize = 0;
    for (segments.items) |segment| {
        const len = numericFlatLen(segment.value) orelse return error.Type;
        for (0..len) |idx| {
            out.items[out_idx] = try numericFloatAt(segment.value, idx);
            out_idx += 1;
        }
    }
    const analysis = analyzeFloatSlice(out.items);
    hostDenseSetFlags(out.array, analysis.flags);
    return out.array;
}

fn createMlxConcatOperand(self: *Session, value: Value, cols: usize) KError!mlx.Array {
    var array = try self.materializeBackendArray(value);
    errdefer array.deinit();
    if (valueNumericMatrixShape(value) != null) return array;

    const dims = [_]i32{
        1,
        std.math.cast(i32, cols) orelse return error.Unsupported,
    };
    const ctx = try self.backendContext();
    const reshaped = mlx.Array.reshape(ctx.*, array, &dims) catch |err| return mapMlxError(err);
    array.deinit();
    return reshaped;
}

fn mlxConcatAxis0(ctx: mlx.Context, arrays: []const mlx.Array) KError!mlx.Array {
    if (comptime !runtime_has_mlx) return error.Unsupported;
    if (comptime mlx.backend_kind == .webgpu) {
        return mlx.Array.concat(ctx, arrays) catch |err| return mapMlxError(err);
    }
    const vec = c.mlx_vector_array_new();
    defer _ = c.mlx_vector_array_free(vec);
    for (arrays) |item| {
        mlx.check(c.mlx_vector_array_append_value(vec, item.handle)) catch |err| return mapMlxError(err);
    }
    var out = c.mlx_array_new();
    mlx.check(c.mlx_concatenate_axis(&out, vec, 0, ctx.stream)) catch |err| return mapMlxError(err);
    return .{ .handle = out };
}

fn createBackendArrayFromFirstAxisConcat(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsFirstAxisConcat(handle)) return error.Type;
    if (handle.rank != 2) return error.Type;
    const cols: usize = @intCast(handle.shape[1]);
    var segments = std.ArrayList(FirstAxisMatrixSegment).empty;
    defer segments.deinit(self.allocator);
    try collectFirstAxisMatrixSegments(self.allocator, Value.array(@constCast(handle)), cols, &segments);
    if (segments.items.len == 0) return error.Type;

    var arrays = try self.allocator.alloc(mlx.Array, segments.items.len);
    defer self.allocator.free(arrays);
    defer for (arrays[0..segments.items.len]) |*item| item.deinit();

    for (segments.items, 0..) |segment, idx| {
        arrays[idx] = try createMlxConcatOperand(self, segment.value, cols);
    }

    return try mlxConcatAxis0((try self.backendContext()).*, arrays[0..segments.items.len]);
}

fn createHostArrayFromReshapeView(self: *Session, owner: HeapOwner, handle: *const NumericArray) KError!*HostDenseArray {
    if (!numericArrayIsReshapeView(handle)) return error.Type;
    const source = numericArrayReshapeSource(handle) orelse return error.Type;
    const source_array = try hostStructuralArrayForHandle(self, try numericHandleRequired(source));
    const total_len = numericArrayElementCount(handle);

    return switch (hostDenseNumericMode(source_array)) {
        .float => switch (source_array.storage) {
            .float32 => |items| blk: {
                if (items.len != total_len) return error.Type;
                const out = try self.allocHostArrayTyped(f32, .float32, owner, total_len);
                @memcpy(out.items, items);
                const analysis = analyzeFloatSlice32(out.items);
                hostDenseSetFlags(out.array, analysis.flags);
                break :blk out.array;
            },
            .float64 => |items| blk: {
                if (items.len != total_len) return error.Type;
                const out = try self.allocHostArrayTyped(f64, .float64, owner, total_len);
                @memcpy(out.items, items);
                const analysis = analyzeFloatSlice(out.items);
                hostDenseSetFlags(out.array, analysis.flags);
                break :blk out.array;
            },
            else => error.Type,
        },
        .int => blk: {
            const view = hostIntArrayView(source_array) orelse return error.Type;
            if (hostIntArrayViewLen(view) != total_len) return error.Type;
            if (view == .bit) {
                const source_bits = view.bit;
                const out = try self.allocHostBitArrayUninitialized(owner, total_len);
                @memcpy(out.words, source_bits.words[0..out.words.len]);
                bitClearUnusedTail(out.words, out.len);
                hostDenseSetFlags(out.array, source_array.flags);
                hostDenseSetCachedIntRange(out.array, hostDenseCachedIntRange(source_array) orelse .{ .min = 0, .max = 1 });
                break :blk out.array;
            }
            var values = try self.allocator.alloc(i64, total_len);
            defer self.allocator.free(values);
            for (0..total_len) |idx| values[idx] = hostIntViewItem(view, idx);
            const analysis = analyzeIntSlice(values);
            var out = try self.allocOwnedHostIntResult(owner, analysis.kind, total_len);
            for (values, 0..) |item, idx| try out.set(idx, item);
            const host = out.arrayPtr();
            if (analysis.kind == .bit) bitClearUnusedTail(host.storage.bit, host.logical_len);
            hostDenseSetFlags(host, analysis.flags);
            hostDenseSetCachedIntRange(host, analysis.range);
            break :blk host;
        },
    };
}

fn createBackendArrayFromReshapeView(self: *Session, handle: *const NumericArray) KError!mlx.Array {
    if (!numericArrayIsReshapeView(handle)) return error.Type;
    const source = numericArrayReshapeSource(handle) orelse return error.Type;
    var source_array = try self.materializeBackendArray(source);
    defer source_array.deinit();
    const ctx = try self.backendContext();
    return mlx.Array.reshape(ctx.*, source_array, handle.shapeSlice()) catch |err| return mapMlxError(err);
}

fn createHostDenseArrayFromBackendArray(self: *Session, owner: HeapOwner, array: mlx.Array) KError!*HostDenseArray {
    if (comptime runtime_has_mlx) {
        return runtime_backend_materialize.createHostDenseArrayFromBackendArray(.{
            .Session = Session,
            .HeapOwner = HeapOwner,
            .HostDenseArray = HostDenseArray,
            .KError = KError,
            .mlx = mlx,
            .c = c,
            .mapMlxError = mapMlxError,
            .backendArrayElementCount = backendArrayElementCount,
            .analyzeIntSlice = analyzeIntSlice,
            .analyzeFloatSlice = analyzeFloatSlice,
            .analyzeFloatSlice32 = analyzeFloatSlice32,
            .allocOwnedHostIntResult = Session.allocOwnedHostIntResult,
            .allocOwnedHostFloatResult = Session.allocOwnedHostFloatResult,
            .allocOwnedHostFloat32Result = Session.allocOwnedHostFloat32Result,
            .hostIntResultSet = hostIntResultSet,
            .hostIntResultArrayPtr = hostIntResultArrayPtr,
            .bitClearUnusedTail = bitClearUnusedTail,
            .hostDenseSetFlags = hostDenseSetFlags,
            .hostDenseSetCachedIntRange = hostDenseSetCachedIntRange,
            .host_dense_flag_normalized = host_dense_flag_normalized,
            .orderFlagsFromMonotonic = orderFlagsFromMonotonic,
        }, self, owner, array);
    }
    return error.Unsupported;
}

fn tryEnsureManagedBackendRealizationForHandle(self: *Session, handle: *NumericArray) KError!?*BackendArray {
    if (comptime runtime_has_mlx) {
        return runtime_backend_materialize.tryEnsureManagedBackendRealizationForHandle(.{
            .Session = Session,
            .Value = Value,
            .NumericArray = NumericArray,
            .BackendArray = BackendArray,
            .KError = KError,
            .mlx = mlx,
            .enable_probe_instrumentation = enable_probe_instrumentation,
            .numericArrayIsRangeIota = numericArrayIsRangeIota,
            .numericArrayIsFlatSlice = numericArrayIsFlatSlice,
            .numericArrayIsFlatConcat = numericArrayIsFlatConcat,
            .numericArrayIsFlatSegments = numericArrayIsFlatSegments,
            .numericArrayIsFirstAxisSlice = numericArrayIsFirstAxisSlice,
            .numericArrayIsFirstAxisIndex = numericArrayIsFirstAxisIndex,
            .numericArrayIsFirstAxisConcat = numericArrayIsFirstAxisConcat,
            .numericArrayIsReshapeView = numericArrayIsReshapeView,
            .numericArrayIsTransposeView = numericArrayIsTransposeView,
            .createBackendArrayFromRangeIota = createBackendArrayFromRangeIota,
            .createBackendArrayFromFlatSlice = createBackendArrayFromFlatSlice,
            .createBackendArrayFromFlatConcat = createBackendArrayFromFlatConcat,
            .createBackendArrayFromFlatSegments = createBackendArrayFromFlatSegments,
            .createBackendArrayFromFirstAxisSlice = createBackendArrayFromFirstAxisSlice,
            .createBackendArrayFromFirstAxisIndex = createBackendArrayFromFirstAxisIndex,
            .createBackendArrayFromFirstAxisConcat = createBackendArrayFromFirstAxisConcat,
            .createBackendArrayFromReshapeView = createBackendArrayFromReshapeView,
            .createBackendArrayFromTransposeView = createBackendArrayFromTransposeView,
            .tryEnsureHostRealizationForHandle = tryEnsureHostRealizationForHandle,
            .hostDenseNumericMode = hostDenseNumericMode,
            .createBackendArrayFromHostArray = createBackendArrayFromHostArray,
            .allocManagedBackendPayload = Session.allocManagedBackendPayload,
            .syncNumericArrayChildren = syncNumericArrayChildren,
            .touchBackendAttachment = Session.touchBackendAttachment,
            .enforceDualResidentBudget = Session.enforceDualResidentBudget,
        }, self, handle);
    }
    return null;
}

fn tryEnsureManagedBackendRealization(self: *Session, value: Value) KError!?*BackendArray {
    if (comptime runtime_has_mlx) {
        return runtime_backend_materialize.tryEnsureManagedBackendRealization(.{
            .Session = Session,
            .Value = Value,
            .BackendArray = BackendArray,
            .KError = KError,
            .mutableNumericHandle = mutableNumericHandle,
            .tryEnsureManagedBackendRealizationForHandle = tryEnsureManagedBackendRealizationForHandle,
        }, self, value);
    }
    return null;
}

fn tryEnsureHostRealizationForHandle(self: *Session, handle: *NumericArray) KError!?*HostDenseArray {
    var profile_scope = self.beginSamplingProfileScope(.host_realization);
    defer profile_scope.end();
    if (numericHostAttachment(handle)) |array| {
        if (comptime enable_probe_instrumentation) self.debug_host_realization_reuse_count += 1;
        self.touchHostAttachment(handle);
        return @constCast(array);
    }
    if (handle.header.owner == .frozen) return error.Unsupported;
    const had_mlx_attachment = numericHasBackendAttachment(handle);

    const host = if (numericArrayIsRangeIota(handle))
        try createHostArrayFromRangeIota(self, handle.header.owner, handle)
    else if (numericArrayIsFlatSlice(handle))
        try createHostArrayFromFlatSlice(self, handle.header.owner, handle)
    else if (numericArrayIsFlatConcat(handle))
        try createHostArrayFromFlatConcat(self, handle.header.owner, handle)
    else if (numericArrayIsFlatSegments(handle))
        try createHostArrayFromFlatSegments(self, handle.header.owner, handle)
    else if (numericArrayIsFirstAxisSlice(handle))
        try createHostArrayFromFirstAxisSlice(self, handle.header.owner, handle)
    else if (numericArrayIsFirstAxisIndex(handle))
        try createHostArrayFromFirstAxisIndex(self, handle.header.owner, handle)
    else if (numericArrayIsFirstAxisConcat(handle))
        try createHostArrayFromFirstAxisConcat(self, handle.header.owner, handle)
    else if (numericArrayIsReshapeView(handle))
        try createHostArrayFromReshapeView(self, handle.header.owner, handle)
    else if (numericArrayIsTransposeView(handle))
        try createHostArrayFromTransposeView(self, handle.header.owner, handle)
    else blk: {
        const backend_array = numericBackendAttachment(handle) orelse return null;
        if (handle.rank == 0) numericArraySetShapeFromBackend(handle, backend_array.array);
        break :blk try createHostDenseArrayFromBackendArray(self, handle.header.owner, backend_array.array);
    };
    if (comptime enable_probe_instrumentation) {
        self.debug_host_realization_count += 1;
        if (numericArrayStructuralTag(handle) != .materialized) self.debug_structural_host_realization_count += 1;
        if (had_mlx_attachment) self.debug_host_readback_count += 1;
    }
    handle.host = host;
    syncNumericArrayChildren(handle);
    self.touchHostAttachment(handle);
    if (numericHasBackendAttachment(handle)) self.enforceDualResidentBudget(handle);
    return host;
}

fn tryEnsureHostRealization(self: *Session, value: Value) KError!?*HostDenseArray {
    if (value.tag() != .array) return null;
    if (valueNumericHandle(value)) |handle| {
        return try tryEnsureHostRealizationForHandle(self, @constCast(handle));
    }
    return switch (value.arraySubkind()) {
        .host_dense_array => @constCast(value.asHostDenseArray()),
        else => null,
    };
}

fn hostStructuralArrayForHandle(self: *Session, handle: *NumericArray) KError!*const HostDenseArray {
    return try tryEnsureHostRealizationForHandle(self, handle) orelse return error.Unsupported;
}

fn numericHostArrayValue(self: *Session, value: Value) KError!*const HostDenseArray {
    if (value.tag() != .array) return error.Type;
    if (valueNumericHandle(value)) |handle| {
        return try hostStructuralArrayForHandle(self, @constCast(handle));
    }
    return switch (value.arrayKind()) {
        .host_dense_array => value.asHostDenseArray(),
        else => error.Type,
    };
}

fn mutableNumericHostArrayValue(self: *Session, value: Value) KError!*HostDenseArray {
    return @constCast(try numericHostArrayValue(self, value));
}

fn actualDenseBackend(self: *Session, supports_backend: bool, planned: DenseExecBackend) DenseExecBackend {
    return switch (self.dense_backend_override) {
        .auto => planned,
        .host => .host,
        .mlx => if (supports_backend) .mlx else planned,
    };
}

fn noteDensePlanDecision(self: *Session, kind: DenseRegionKind, planned_backend: DenseExecBackend, actual_backend: DenseExecBackend, reason: DensePlanReason) void {
    if (comptime !enable_probe_instrumentation) {
        return;
    }
    self.debug_dense_plan_counts[@intFromEnum(kind)][@intFromEnum(planned_backend)] += 1;
    self.debug_dense_exec_counts[@intFromEnum(kind)][@intFromEnum(actual_backend)] += 1;
    self.last_dense_plan_region = kind;
    self.last_dense_plan_backend = planned_backend;
    self.last_dense_exec_backend = actual_backend;
    self.last_dense_plan_reason = reason;
    self.last_dense_plan_overridden = planned_backend != actual_backend;
}

fn countDensePlanDecision(self: *Session, kind: DenseRegionKind, planned_backend: DenseExecBackend, actual_backend: DenseExecBackend) void {
    if (comptime !enable_probe_instrumentation) {
        return;
    }
    self.debug_dense_plan_counts[@intFromEnum(kind)][@intFromEnum(planned_backend)] += 1;
    self.debug_dense_exec_counts[@intFromEnum(kind)][@intFromEnum(actual_backend)] += 1;
}

fn planDenseRegionDecision(kind: DenseRegionKind, facts: DenseRegionFacts) DensePlanDecision {
    return switch (kind) {
        .numeric_dyad => if (!facts.supports_backend)
            .{ .backend = .host, .reason = .no_backend_support }
        else if (facts.has_unmaterialized_range and !facts.has_backend_residency)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.prefer_backend_pipeline)
            .{ .backend = .mlx, .reason = .large_problem }
        else if (facts.prefer_host_kernel and facts.elem_count < dense_backend_min_len_dyad)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.has_backend_residency)
            .{ .backend = .mlx, .reason = .already_backend_resident }
        else if (facts.elem_count < dense_backend_min_len_dyad)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .compare_mask => if (!facts.supports_backend)
            .{ .backend = .host, .reason = .no_backend_support }
        else if (facts.has_packed_bit_input and !facts.has_backend_residency)
            .{ .backend = .host, .reason = .packed_mask_host }
        else if (facts.has_unmaterialized_range and
            (facts.device_preference == .gpu or facts.elem_count >= dense_backend_min_len_dyad))
            .{ .backend = .mlx, .reason = .large_problem }
        else if (facts.has_unmaterialized_range)
            .{ .backend = .host, .reason = .small_problem }
        else if (facts.has_backend_residency)
            .{ .backend = .mlx, .reason = .already_backend_resident }
        else
            .{ .backend = .host, .reason = .compare_host_default },
        .reduce, .scan => if (!facts.supports_backend)
            .{ .backend = .host, .reason = .no_backend_support }
        else if (facts.has_unmaterialized_range)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.has_packed_bit_input and !facts.has_backend_residency)
            .{ .backend = .host, .reason = .packed_mask_host }
        else if (facts.prefer_host_kernel and facts.elem_count < dense_backend_min_len_reduce)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if ((!runtime_has_mlx or !mlx.supports_full_ops) and facts.elem_count < dense_backend_min_len_reduce)
            .{ .backend = .host, .reason = .small_problem }
        else if (facts.has_backend_residency)
            .{ .backend = .mlx, .reason = .already_backend_resident }
        else if (facts.elem_count < dense_backend_min_len_reduce)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .matmul => if (!facts.supports_backend)
            .{ .backend = .host, .reason = .no_backend_support }
        else if (facts.prefer_host_kernel and facts.elem_count <= dense_backend_min_len_matmul)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.has_backend_residency)
            .{ .backend = .mlx, .reason = .already_backend_resident }
        else if (facts.elem_count < dense_backend_min_len_matmul)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .transpose => if (!facts.supports_backend)
            .{ .backend = .host, .reason = .no_backend_support }
        else if (facts.device_preference == .gpu and
            facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            (!facts.has_backend_residency or facts.prefer_host_kernel) and
            facts.elem_count <= 16_384 and
            @max(facts.matrix_rows, facts.matrix_cols) <= 128)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.device_preference == .gpu and
            facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            (!facts.has_backend_residency or facts.prefer_host_kernel) and
            facts.elem_count <= 16_384 and
            @min(facts.matrix_rows, facts.matrix_cols) <= 32)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.matrix_rows != 0 and facts.matrix_cols != 0 and facts.prefer_host_kernel and facts.elem_count <= 4_096)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            facts.prefer_host_kernel and
            @min(facts.matrix_rows, facts.matrix_cols) <= 16 and
            facts.elem_count <= 16_384)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.matrix_rows != 0 and facts.matrix_cols != 0 and
            @min(facts.matrix_rows, facts.matrix_cols) <= 8 and
            facts.elem_count <= 32_768)
            .{ .backend = .host, .reason = .host_fast_kernel }
        else if (facts.has_backend_residency)
            .{ .backend = .mlx, .reason = .already_backend_resident }
        else if (facts.elem_count < dense_backend_min_len_transpose)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
        .dense_autodiff => if (!facts.supports_backend)
            .{ .backend = .host, .reason = .no_backend_support }
        else if (facts.has_unmaterialized_range)
            .{ .backend = .host, .reason = .unmaterialized_range_host }
        else if (facts.has_backend_residency)
            .{ .backend = .mlx, .reason = .already_backend_resident }
        else if (facts.elem_count < dense_backend_min_len_autodiff)
            .{ .backend = .host, .reason = .small_problem }
        else
            .{ .backend = .mlx, .reason = .large_problem },
    };
}

fn chooseDenseRegionBackend(self: *Session, kind: DenseRegionKind, facts: DenseRegionFacts) DenseExecBackend {
    const decision = planDenseRegionDecision(kind, facts);
    const actual_backend = actualDenseBackend(self, facts.supports_backend, decision.backend);
    noteDensePlanDecision(self, kind, decision.backend, actual_backend, decision.reason);
    return actual_backend;
}

fn backendResidentSmallVectorDyadPrefersHost(
    self: *Session,
    left: Value,
    right: Value,
    left_facts: DenseValuePlanFacts,
    right_facts: DenseValuePlanFacts,
    elem_count: usize,
) bool {
    if (self.device_preference == .gpu) return false;
    if (elem_count == 0 or elem_count > dense_backend_row_host_len_dyad) return false;
    if (!left_facts.supports_host_dense or !right_facts.supports_host_dense) return false;
    return numericVectorLen(left) != null and numericVectorLen(right) != null;
}

fn planDenseNumericDyadBackend(self: *Session, op: BuiltinId, left: Value, right: Value) DenseExecBackend {
    const left_facts = denseValuePlanFacts(left);
    const right_facts = denseValuePlanFacts(right);
    const elem_count = arrayResultLen(left, right) catch 0;
    const has_backend_residency = left_facts.has_backend_residency or right_facts.has_backend_residency;
    const preserve_mlx_pipeline = has_backend_residency and
        (valueNonVectorNumericShape(left) != null or valueNonVectorNumericShape(right) != null);
    const prefer_small_vector_host_kernel = !preserve_mlx_pipeline and
        has_backend_residency and
        backendResidentSmallVectorDyadPrefersHost(self, left, right, left_facts, right_facts, elem_count);
    return chooseDenseRegionBackend(self, .numeric_dyad, .{
        .elem_count = elem_count,
        .has_backend_residency = has_backend_residency,
        .has_unmaterialized_range = left_facts.has_unmaterialized_range or right_facts.has_unmaterialized_range,
        .prefer_host_kernel = prefer_small_vector_host_kernel or
            (!preserve_mlx_pipeline and
                has_backend_residency and
                left_facts.supports_cheap_host_dense and right_facts.supports_cheap_host_dense),
        .prefer_backend_pipeline = transposePipelinePrefersBackend(self, left) or transposePipelinePrefersBackend(self, right),
        .supports_backend = supportsBackendDyad(op) and backendSupportsNumericDyadDtypes(self, left, right),
    });
}

fn planCompareMaskBackend(self: *Session, op: BuiltinId, left: Value, right: Value) DenseExecBackend {
    const left_facts = denseValuePlanFacts(left);
    const right_facts = denseValuePlanFacts(right);
    return chooseDenseRegionBackend(self, .compare_mask, .{
        .elem_count = arrayResultLen(left, right) catch 0,
        .has_backend_residency = left_facts.has_backend_residency or right_facts.has_backend_residency,
        .has_unmaterialized_range = left_facts.has_unmaterialized_range or right_facts.has_unmaterialized_range,
        .has_packed_bit_input = valueNumericBitSlice(left) != null or valueNumericBitSlice(right) != null,
        .supports_backend = op == .equal or op == .less or op == .more,
        .device_preference = self.device_preference,
    });
}

fn planDenseReduceScanBackend(self: *Session, collect: bool, value: Value) DenseExecBackend {
    return chooseDenseRegionBackend(self, if (collect) .scan else .reduce, denseReduceScanFacts(value));
}

fn denseReduceScanFacts(value: Value) DenseRegionFacts {
    const facts = denseValuePlanFacts(value);
    return .{
        .elem_count = numericVectorLen(value) orelse 0,
        .has_backend_residency = facts.has_backend_residency,
        .has_unmaterialized_range = facts.has_unmaterialized_range,
        .has_packed_bit_input = valueNumericBitSlice(value) != null,
        .prefer_host_kernel = facts.has_backend_residency and facts.supports_cheap_host_dense,
    };
}

fn valueSupportsHostDensePlanning(value: Value) bool {
    return switch (value.tag()) {
        .int, .bool, .float => true,
        .array => switch (value.arraySubkind()) {
            .host_dense_array => true,
            .numeric_array => handleSupportsHostDense(value.asNumericArray()),
            .backend_array => if (value.asBackendArray().logical_handle) |handle|
                handleSupportsHostDense(handle)
            else
                false,
            else => false,
        },
        else => false,
    };
}

fn valueSupportsCheapHostDensePlanning(value: Value) bool {
    return switch (value.tag()) {
        .int, .bool, .float => true,
        .array => switch (value.arraySubkind()) {
            .host_dense_array => true,
            .numeric_array => handleSupportsCheapHostDense(value.asNumericArray()),
            .backend_array => if (value.asBackendArray().logical_handle) |handle|
                handleSupportsCheapHostDense(handle)
            else
                false,
            else => false,
        },
        else => false,
    };
}

fn matmulPrefersHostKernel(left: Value, right: Value, result_rank: usize) bool {
    if (result_rank != 0) return false;
    const left_facts = denseValuePlanFacts(left);
    const right_facts = denseValuePlanFacts(right);
    return left_facts.supports_cheap_host_dense and right_facts.supports_cheap_host_dense;
}

fn planMatmulBackend(self: *Session, left: Value, right: Value) DenseExecBackend {
    const shape = Session.matmulShapeForValues(left, right) catch null;
    const left_facts = denseValuePlanFacts(left);
    const right_facts = denseValuePlanFacts(right);
    const has_backend_residency = left_facts.has_backend_residency or right_facts.has_backend_residency;
    return chooseDenseRegionBackend(self, .matmul, .{
        .elem_count = if (shape) |info| info.result_rows * info.left_cols * info.result_cols else 0,
        .matrix_rows = if (shape) |info| info.result_rows else 0,
        .matrix_cols = if (shape) |info| info.result_cols else 0,
        .has_backend_residency = has_backend_residency,
        .prefer_host_kernel = if (shape) |info| matmulPrefersHostKernel(left, right, info.result_rank) else false,
        .supports_backend = backendSupportsMatmulDtypes(self, left, right),
    });
}

fn planDenseAutodiffBackend(self: *Session, value: Value) DenseExecBackend {
    const facts = denseValuePlanFacts(value);
    return chooseDenseRegionBackend(self, .dense_autodiff, .{
        .elem_count = numericVectorLen(value) orelse 0,
        .has_backend_residency = facts.has_backend_residency,
        .has_unmaterialized_range = facts.has_unmaterialized_range,
    });
}

fn transposeSourceValue(value: Value) Value {
    if (value.tag() != .array) return value;
    const handle = valueNumericHandle(value) orelse return value;
    return numericArrayTransposeSource(handle) orelse value;
}

fn transposeHasFastHostKernel(value: Value) bool {
    const source = transposeSourceValue(value);
    const array = hostDenseIfPresent(source) orelse return false;
    return switch (array.storage) {
        .float64, .int8, .int16, .int32, .int64 => true,
        else => false,
    };
}

fn transposeRegionFacts(self: *Session, value: Value, elem_count: usize) DenseRegionFacts {
    const source = transposeSourceValue(value);
    const shape = valueNumericMatrixShape(value) orelse valueNumericMatrixShape(source);
    const source_facts = denseValuePlanFacts(source);
    const preserve_mlx_pipeline = source_facts.has_backend_residency and shape != null;
    return .{
        .elem_count = elem_count,
        .matrix_rows = if (shape) |matrix| matrix.rows else 0,
        .matrix_cols = if (shape) |matrix| matrix.cols else 0,
        .has_backend_residency = source_facts.has_backend_residency,
        .prefer_host_kernel = !preserve_mlx_pipeline and transposeHasFastHostKernel(value),
        .device_preference = self.device_preference,
    };
}

fn transposePipelinePrefersBackend(self: *Session, value: Value) bool {
    const handle = valueNumericHandle(value) orelse return false;
    if (!numericArrayIsTransposeView(handle)) return false;
    const decision = planDenseRegionDecision(.transpose, transposeRegionFacts(self, value, numericArrayElementCount(handle)));
    return decision.backend == .mlx;
}

fn planTransposeBackend(self: *Session, value: Value, elem_count: usize) DenseExecBackend {
    return chooseDenseRegionBackend(self, .transpose, transposeRegionFacts(self, value, elem_count));
}

fn noteTransposeMaterializationDecision(self: *Session, value: Value, elem_count: usize, actual_backend: DenseExecBackend) void {
    const facts = transposeRegionFacts(self, value, elem_count);
    const decision = planDenseRegionDecision(.transpose, facts);
    noteDensePlanDecision(self, .transpose, decision.backend, actual_backend, decision.reason);
}

fn countTransposeStructuralHostUse(self: *Session, value: Value) void {
    const handle = valueNumericHandle(value) orelse return;
    if (!numericArrayIsTransposeView(handle)) return;
    const decision = planDenseRegionDecision(.transpose, transposeRegionFacts(self, value, numericArrayElementCount(handle)));
    countDensePlanDecision(self, .transpose, decision.backend, .host);
}

fn handleMode(handle: *const NumericArray) ?HostDenseElem {
    if (numericHostAttachment(handle)) |array| return hostDenseNumericMode(array);
    if (numericHasBackendAttachment(handle)) return .float;
    if (numericArrayIsRangeIota(handle)) return .int;
    if (numericArrayFlatSliceSource(handle)) |source| return valueNumericMode(source);
    if (numericArrayFlatConcatLeft(handle)) |left| {
        const right = numericArrayFlatConcatRight(handle) orelse return valueNumericMode(left);
        const left_mode = valueNumericMode(left) orelse return null;
        const right_mode = valueNumericMode(right) orelse return null;
        return if (left_mode == .float or right_mode == .float) .float else .int;
    }
    if (numericArrayFlatSegmentsValues(handle)) |segments| {
        var saw_float = false;
        for (segments) |segment| {
            const segment_mode = valueNumericMode(segment) orelse return null;
            if (segment_mode == .float) saw_float = true;
        }
        return if (saw_float) .float else .int;
    }
    if (numericArrayFirstAxisSliceSource(handle)) |source| return valueNumericMode(source);
    if (numericArrayFirstAxisIndexSource(handle)) |source| return valueNumericMode(source);
    if (numericArrayFirstAxisConcatLeft(handle)) |left| {
        const right = numericArrayFirstAxisConcatRight(handle) orelse return valueNumericMode(left);
        const left_mode = valueNumericMode(left) orelse return null;
        const right_mode = valueNumericMode(right) orelse return null;
        return if (left_mode == .float or right_mode == .float) .float else .int;
    }
    if (numericArrayReshapeSource(handle)) |source| return valueNumericMode(source);
    if (numericArrayTransposeSource(handle)) |source| return valueNumericMode(source);
    return null;
}

fn valueNumericMode(value: Value) ?HostDenseElem {
    return switch (value.tag()) {
        .int, .bool => .int,
        .float, .float32 => .float,
        .array => if (valueNumericHandle(value)) |handle|
            handleMode(handle)
        else switch (value.arrayKind()) {
            .host_dense_array => hostDenseNumericMode(value.asHostDenseArray()),
            .backend_array => .float,
            else => null,
        },
        else => null,
    };
}

fn isBackendArrayValue(value: Value) bool {
    return value.tag() == .array and value.arrayKind() == .backend_array;
}

fn arrayResultMode(op: BuiltinId, left: Value, right: Value) ?HostDenseElem {
    const left_mode = valueNumericMode(left) orelse return null;
    const right_mode = valueNumericMode(right) orelse return null;
    if (op == .div or left_mode == .float or right_mode == .float) return .float;
    return .int;
}

fn denseResultMode(op: BuiltinId, left_mode: HostDenseElem, right_mode: HostDenseElem) HostDenseElem {
    if (op == .div or left_mode == .float or right_mode == .float) return .float;
    return .int;
}

fn numericFlatLen(value: Value) ?usize {
    if (value.tag() != .array) return null;
    if (valueNumericHandle(value)) |handle| {
        if (numericHostAttachment(handle)) |array| return array.len();
        if (handle.rank == 0) return null;
        var total: usize = 1;
        for (handle.shapeSlice()) |dim| total *= @as(usize, @intCast(dim));
        return total;
    }
    return switch (value.arrayKind()) {
        .host_dense_array => value.asHostDenseArray().len(),
        .backend_array => backendArrayElementCount(value.asBackendArray().array),
        else => null,
    };
}

fn arrayResultLen(left: Value, right: Value) KError!usize {
    if (rowwiseMatrixVectorDyad(left, right)) |shape| return shape.rows * shape.cols;
    const left_len = switch (left.tag()) {
        .array => switch (left.arrayKind()) {
            .host_dense_array, .backend_array, .numeric_array => numericFlatLen(left) orelse return error.Type,
            .host_boxed_array => left.asHostBoxedArray().len(),
            else => return error.Type,
        },
        .int, .float, .float32, .bool => null,
        else => return error.Type,
    };
    const right_len = switch (right.tag()) {
        .array => switch (right.arrayKind()) {
            .host_dense_array, .backend_array, .numeric_array => numericFlatLen(right) orelse return error.Type,
            .host_boxed_array => right.asHostBoxedArray().len(),
            else => return error.Type,
        },
        .int, .float, .float32, .bool => null,
        else => return error.Type,
    };

    if (left_len) |llen| {
        if (right_len) |rlen| {
            if (!isGenericArrayValue(left) and !isGenericArrayValue(right)) {
                _ = try nonVectorNumericShapeForDyad(left, right);
            }
            if (llen != rlen) return error.Type;
            return llen;
        }
        return llen;
    }
    return right_len orelse return error.Type;
}

fn isBoxedHostArrayValue(value: Value) bool {
    return boxedArrayItems(value) != null;
}

fn isGenericArrayValue(value: Value) bool {
    return isBoxedHostArrayValue(value);
}

fn shouldUseGenericArrayDyad(left: Value, right: Value) bool {
    if (isBackendArrayValue(left) or isBackendArrayValue(right)) return false;
    if ((left.tag() == .array and left.arrayKind() == .host_table_scalar) or
        (right.tag() == .array and right.arrayKind() == .host_table_scalar))
    {
        return false;
    }
    if ((valueIsRenderableMatrixLike(left) and valueNumericMode(right) != null) or
        (valueIsRenderableMatrixLike(right) and valueNumericMode(left) != null))
    {
        return false;
    }
    return (left.tag() == .array or right.tag() == .array) and
        (valueNumericMode(left) == null or valueNumericMode(right) == null);
}

const HostRangeIotaView = struct {
    handle: *const NumericArray,
};

const HostFlatSliceView = struct {
    source_value: Value,
    source_host: ?*const HostDenseArray = null,
    start: usize,
    len: usize,
};

const HostFlatStrideView = struct {
    source_value: Value,
    source_host: ?*const HostDenseArray = null,
    start: usize,
    len: usize,
    step: usize = 1,
};

const HostFlatSegmentsView = struct {
    values: []const Value,
    len: usize,
};

const HostFirstAxisSliceView = struct {
    source_value: Value,
    source_host: ?*const HostDenseArray = null,
    start_row: usize,
    len: usize,
    row_width: usize = 1,
    row_step: i32 = 1,
};

const HostFirstAxisIndexView = struct {
    source_value: Value,
    source_host: ?*const HostDenseArray = null,
    row_indices: Value,
    len: usize,
    row_width: usize = 1,
};

const HostFirstAxisConcatView = struct {
    left_value: Value,
    left_host: ?*const HostDenseArray = null,
    right_value: Value,
    right_host: ?*const HostDenseArray = null,
    left_len: usize,
    len: usize,
};

const HostTransposeView = struct {
    source_value: Value,
    source_host: ?*const HostDenseArray = null,
    source_rows: usize,
    source_cols: usize,
};

const HostIntDenseView = union(enum) {
    dense: HostIntArrayView,
    range_iota: HostRangeIotaView,
    flat_slice: HostFlatSliceView,
    flat_stride: HostFlatStrideView,
    flat_concat: HostFirstAxisConcatView,
    flat_segments: HostFlatSegmentsView,
    first_axis_slice: HostFirstAxisSliceView,
    first_axis_index: HostFirstAxisIndexView,
    first_axis_concat: HostFirstAxisConcatView,
    transpose: HostTransposeView,
};

const HostFloatDenseView = union(enum) {
    dense: []const f64,
    flat_slice: HostFlatSliceView,
    flat_stride: HostFlatStrideView,
    flat_concat: HostFirstAxisConcatView,
    flat_segments: HostFlatSegmentsView,
    first_axis_slice: HostFirstAxisSliceView,
    first_axis_index: HostFirstAxisIndexView,
    first_axis_concat: HostFirstAxisConcatView,
    transpose: HostTransposeView,
};

const HostDenseView = union(enum) {
    scalar_int: i64,
    scalar_float: f64,
    int_array: HostIntDenseView,
    float_array: HostFloatDenseView,
};

const HostCollapsedFlatSlice = union(enum) {
    flat_slice: HostFlatSliceView,
    flat_stride: HostFlatStrideView,
};

fn hostDenseViewForHostArray(array: *const HostDenseArray) KError!HostDenseView {
    return switch (array.storage) {
        .bit => |words| .{ .int_array = .{ .dense = .{ .bit = .{ .words = hostDenseLogicalBitWords(array, words), .len = array.logical_len } } } },
        .int8 => |items| .{ .int_array = .{ .dense = .{ .int8 = hostDenseLogicalItems(i8, array, items) } } },
        .int16 => |items| .{ .int_array = .{ .dense = .{ .int16 = hostDenseLogicalItems(i16, array, items) } } },
        .int32 => |items| .{ .int_array = .{ .dense = .{ .int32 = hostDenseLogicalItems(i32, array, items) } } },
        .int64 => |items| .{ .int_array = .{ .dense = .{ .int64 = hostDenseLogicalItems(i64, array, items) } } },
        .float32 => .{ .float_array = .{ .flat_slice = .{
            .source_value = hostDenseSourceValue(array),
            .source_host = array,
            .start = 0,
            .len = array.logical_len,
        } } },
        .float64 => |items| .{ .float_array = .{ .dense = hostDenseLogicalItems(f64, array, items) } },
    };
}

fn hostDenseViewForNumericHandle(self: *Session, value: Value, handle: *const NumericArray) KError!HostDenseView {
    if (numericHostAttachment(handle)) |array| return try hostDenseViewForHostArray(array);
    if (numericArrayIsRangeIota(handle)) {
        return .{ .int_array = .{ .range_iota = .{ .handle = handle } } };
    }
    if (numericArrayIsFlatSlice(handle)) {
        const source = numericArrayFlatSliceSource(handle) orelse return error.Type;
        const flat_len = numericFlatLen(value) orelse return error.Type;
        const start = numericArrayFlatSliceStart(handle) orelse return error.Type;
        if (try tryCollapseHostFlatSlice(self, source, start, flat_len)) |collapsed| {
            return switch (valueNumericMode(source) orelse return error.Type) {
                .float => switch (collapsed) {
                    .flat_slice => |items| .{ .float_array = .{ .flat_slice = items } },
                    .flat_stride => |items| .{ .float_array = .{ .flat_stride = items } },
                },
                .int => switch (collapsed) {
                    .flat_slice => |items| .{ .int_array = .{ .flat_slice = items } },
                    .flat_stride => |items| .{ .int_array = .{ .flat_stride = items } },
                },
            };
        }
        const source_host = try ensureNumericHostAttachmentForDenseView(self, source);
        return switch (valueNumericMode(source) orelse return error.Type) {
            .float => .{ .float_array = .{ .flat_slice = .{
                .source_value = source,
                .source_host = source_host,
                .start = start,
                .len = flat_len,
            } } },
            .int => .{ .int_array = .{ .flat_slice = .{
                .source_value = source,
                .source_host = source_host,
                .start = start,
                .len = flat_len,
            } } },
        };
    }
    if (numericArrayIsFlatConcat(handle)) {
        const left = numericArrayFlatConcatLeft(handle) orelse return error.Type;
        const right = numericArrayFlatConcatRight(handle) orelse return error.Type;
        const left_len = numericVectorLen(left) orelse return error.Type;
        const right_len = numericVectorLen(right) orelse return error.Type;
        const left_host = try ensureNumericHostAttachmentForDenseView(self, left);
        const right_host = try ensureNumericHostAttachmentForDenseView(self, right);
        if (comptime enable_probe_instrumentation) self.debug_flat_concat_dense_view_count += 1;
        return switch (valueNumericMode(value) orelse return error.Type) {
            .float => .{ .float_array = .{ .flat_concat = .{
                .left_value = left,
                .left_host = left_host,
                .right_value = right,
                .right_host = right_host,
                .left_len = left_len,
                .len = left_len + right_len,
            } } },
            .int => .{ .int_array = .{ .flat_concat = .{
                .left_value = left,
                .left_host = left_host,
                .right_value = right,
                .right_host = right_host,
                .left_len = left_len,
                .len = left_len + right_len,
            } } },
        };
    }
    if (numericArrayIsFlatSegments(handle)) {
        const segments = numericArrayFlatSegmentsValues(handle) orelse return error.Type;
        const flat_len = numericFlatLen(value) orelse return error.Type;
        return switch (valueNumericMode(value) orelse return error.Type) {
            .float => .{ .float_array = .{ .flat_segments = .{
                .values = segments,
                .len = flat_len,
            } } },
            .int => .{ .int_array = .{ .flat_segments = .{
                .values = segments,
                .len = flat_len,
            } } },
        };
    }
    if (numericArrayIsFirstAxisSlice(handle)) {
        const slice = numericArrayFirstAxisSlicePayload(handle) orelse return error.Type;
        const source_handle = shapedNumericHandle(slice.source) orelse return error.Type;
        const row_width = numericShapeInnerBlockLen(source_handle);
        const row_count: usize = @intCast(handle.shape[0]);
        const flat_len = numericFlatLen(value) orelse return error.Type;
        const source_host = try ensureNumericHostAttachmentForDenseView(self, slice.source);
        if (slice.step == 1 and row_count == 1) {
            const start = slice.start * row_width;
            return switch (valueNumericMode(slice.source) orelse return error.Type) {
                .float => .{ .float_array = .{ .flat_slice = .{
                    .source_value = slice.source,
                    .source_host = source_host,
                    .start = start,
                    .len = flat_len,
                } } },
                .int => .{ .int_array = .{ .flat_slice = .{
                    .source_value = slice.source,
                    .source_host = source_host,
                    .start = start,
                    .len = flat_len,
                } } },
            };
        }
        if (comptime enable_probe_instrumentation) self.debug_first_axis_slice_dense_view_count += 1;
        return switch (valueNumericMode(slice.source) orelse return error.Type) {
            .float => .{ .float_array = .{ .first_axis_slice = .{
                .source_value = slice.source,
                .source_host = source_host,
                .start_row = slice.start,
                .len = flat_len,
                .row_width = row_width,
                .row_step = slice.step,
            } } },
            .int => .{ .int_array = .{ .first_axis_slice = .{
                .source_value = slice.source,
                .source_host = source_host,
                .start_row = slice.start,
                .len = flat_len,
                .row_width = row_width,
                .row_step = slice.step,
            } } },
        };
    }
    if (numericArrayIsFirstAxisIndex(handle)) {
        const index = numericArrayFirstAxisIndexPayload(handle) orelse return error.Type;
        const source_handle = shapedNumericHandle(index.source) orelse return error.Type;
        const row_width = numericShapeInnerBlockLen(source_handle);
        const flat_len = numericFlatLen(value) orelse return error.Type;
        const source_host = try ensureNumericHostAttachmentForDenseView(self, index.source);
        if (comptime enable_probe_instrumentation) self.debug_first_axis_index_dense_view_count += 1;
        return switch (valueNumericMode(index.source) orelse return error.Type) {
            .float => .{ .float_array = .{ .first_axis_index = .{
                .source_value = index.source,
                .source_host = source_host,
                .row_indices = index.row_indices,
                .len = flat_len,
                .row_width = row_width,
            } } },
            .int => .{ .int_array = .{ .first_axis_index = .{
                .source_value = index.source,
                .source_host = source_host,
                .row_indices = index.row_indices,
                .len = flat_len,
                .row_width = row_width,
            } } },
        };
    }
    if (numericArrayIsFirstAxisConcat(handle)) {
        const left = numericArrayFirstAxisConcatLeft(handle) orelse return error.Type;
        const right = numericArrayFirstAxisConcatRight(handle) orelse return error.Type;
        const left_len = numericFlatLen(left) orelse return error.Type;
        const right_len = numericFlatLen(right) orelse return error.Type;
        const left_host = try ensureNumericHostAttachmentForDenseView(self, left);
        const right_host = try ensureNumericHostAttachmentForDenseView(self, right);
        if (comptime enable_probe_instrumentation) self.debug_first_axis_concat_dense_view_count += 1;
        return switch (valueNumericMode(value) orelse return error.Type) {
            .float => .{ .float_array = .{ .first_axis_concat = .{
                .left_value = left,
                .left_host = left_host,
                .right_value = right,
                .right_host = right_host,
                .left_len = left_len,
                .len = left_len + right_len,
            } } },
            .int => .{ .int_array = .{ .first_axis_concat = .{
                .left_value = left,
                .left_host = left_host,
                .right_value = right,
                .right_host = right_host,
                .left_len = left_len,
                .len = left_len + right_len,
            } } },
        };
    }
    if (numericArrayIsTransposeView(handle)) {
        countTransposeStructuralHostUse(self, value);
        const source = numericArrayTransposeSource(handle) orelse return error.Type;
        const source_shape = valueNumericMatrixShape(source) orelse return error.Type;
        const source_host = try ensureNumericHostAttachmentForDenseView(self, source);
        return switch (valueNumericMode(source) orelse return error.Type) {
            .float => .{ .float_array = .{ .transpose = .{
                .source_value = source,
                .source_host = source_host,
                .source_rows = source_shape.rows,
                .source_cols = source_shape.cols,
            } } },
            .int => .{ .int_array = .{ .transpose = .{
                .source_value = source,
                .source_host = source_host,
                .source_rows = source_shape.rows,
                .source_cols = source_shape.cols,
            } } },
        };
    }
    if (numericArrayIsReshapeView(handle)) {
        const source = numericArrayReshapeSource(handle) orelse return error.Type;
        if (valueNumericHandle(source)) |source_handle| {
            if (!numericHasHostAttachment(source_handle) and numericHasBackendAttachment(source_handle) and
                !numericArrayIsRangeIota(source_handle) and
                !numericArrayIsFlatSlice(source_handle) and
                !numericArrayIsFlatConcat(source_handle) and
                !numericArrayIsFlatSegments(source_handle) and
                !numericArrayIsFirstAxisSlice(source_handle) and
                !numericArrayIsFirstAxisIndex(source_handle) and
                !numericArrayIsFirstAxisConcat(source_handle) and
                !numericArrayIsTransposeView(source_handle))
            {
                _ = try tryEnsureHostRealizationForHandle(self, @constCast(source_handle)) orelse return error.Type;
            }
        }
        return try hostDenseView(self, source);
    }
    if (numericHasBackendAttachment(handle)) {
        _ = try tryEnsureHostRealizationForHandle(self, @constCast(handle)) orelse return error.Type;
        return try hostDenseViewForHostArray(numericHostAttachment(handle) orelse return error.Type);
    }
    return error.Type;
}

fn hostDenseView(self: *Session, value: Value) KError!HostDenseView {
    return switch (value.tag()) {
        .int => .{ .scalar_int = value.asInt() },
        .bool => .{ .scalar_int = @intFromBool(value.asBool()) },
        .float32 => .{ .scalar_float = @floatCast(value.asFloat32()) },
        .float => .{ .scalar_float = value.asFloat() },
        .array => blk: {
            if (valueNumericHandle(value)) |handle| break :blk try hostDenseViewForNumericHandle(self, value, handle);
            break :blk switch (value.arrayKind()) {
                .host_dense_array => try hostDenseViewForHostArray(value.asHostDenseArray()),
                .backend_array => error.Type,
                else => error.Internal,
            };
        },
        else => error.Type,
    };
}

fn hostArrayFloatStorageKind(array: *const HostDenseArray) ?HostFloatStorageKind {
    return switch (array.storage) {
        .float32 => .float32,
        .float64 => .float64,
        else => null,
    };
}

fn mergeHostFloatStorageKind(current: ?HostFloatStorageKind, next: ?HostFloatStorageKind) ?HostFloatStorageKind {
    const next_kind = next orelse return current;
    const current_kind = current orelse return next_kind;
    return if (current_kind == .float64 or next_kind == .float64) .float64 else .float32;
}

fn valueFloatStorageKind(value: Value) ?HostFloatStorageKind {
    switch (value.tag()) {
        .float32 => return .float32,
        .float => return .float64,
        else => {},
    }
    if (hostDenseIfPresent(value)) |array| return hostArrayFloatStorageKind(array);
    const handle = valueNumericHandle(value) orelse return null;
    if (valueNumericMode(value) != .float) return null;

    if (numericArrayFlatSliceSource(handle)) |source| return valueFloatStorageKind(source);
    if (numericArrayReshapeSource(handle)) |source| return valueFloatStorageKind(source);
    if (numericArrayTransposeSource(handle)) |source| return valueFloatStorageKind(source);
    if (numericArrayFirstAxisSliceSource(handle)) |source| return valueFloatStorageKind(source);
    if (numericArrayFirstAxisIndexSource(handle)) |source| return valueFloatStorageKind(source);

    if (numericArrayFlatConcatLeft(handle)) |left| {
        const right = numericArrayFlatConcatRight(handle) orelse return valueFloatStorageKind(left);
        return mergeHostFloatStorageKind(valueFloatStorageKind(left), valueFloatStorageKind(right));
    }
    if (numericArrayFirstAxisConcatLeft(handle)) |left| {
        const right = numericArrayFirstAxisConcatRight(handle) orelse return valueFloatStorageKind(left);
        return mergeHostFloatStorageKind(valueFloatStorageKind(left), valueFloatStorageKind(right));
    }
    if (numericArrayFlatSegmentsValues(handle)) |segments| {
        var kind: ?HostFloatStorageKind = null;
        for (segments) |segment| kind = mergeHostFloatStorageKind(kind, valueFloatStorageKind(segment));
        return kind;
    }

    if (numericBackendAttachment(handle)) |backend| {
        return switch (backend.array.dtype()) {
            c.MLX_FLOAT64 => .float64,
            c.MLX_FLOAT16, c.MLX_FLOAT32, c.MLX_BFLOAT16 => .float32,
            else => null,
        };
    }
    return null;
}

fn hostFlatFloatStorageKind(view: HostFlatSliceView) ?HostFloatStorageKind {
    if (view.source_host) |array| return hostArrayFloatStorageKind(array);
    return valueFloatStorageKind(view.source_value);
}

fn hostFlatStrideFloatStorageKind(view: HostFlatStrideView) ?HostFloatStorageKind {
    if (view.source_host) |array| return hostArrayFloatStorageKind(array);
    return valueFloatStorageKind(view.source_value);
}

fn hostFirstAxisFloatStorageKind(source_value: Value, source_host: ?*const HostDenseArray) ?HostFloatStorageKind {
    if (source_host) |array| return hostArrayFloatStorageKind(array);
    return valueFloatStorageKind(source_value);
}

fn hostConcatFloatStorageKind(view: HostFirstAxisConcatView) ?HostFloatStorageKind {
    const left = if (view.left_host) |array| hostArrayFloatStorageKind(array) else valueFloatStorageKind(view.left_value);
    const right = if (view.right_host) |array| hostArrayFloatStorageKind(array) else valueFloatStorageKind(view.right_value);
    return mergeHostFloatStorageKind(left, right);
}

fn hostFloatDenseViewStorageKind(view: HostFloatDenseView) ?HostFloatStorageKind {
    return switch (view) {
        .dense => .float64,
        .flat_slice => |items| hostFlatFloatStorageKind(items),
        .flat_stride => |items| hostFlatStrideFloatStorageKind(items),
        .flat_concat => |items| hostConcatFloatStorageKind(items),
        .flat_segments => |items| blk: {
            var kind: ?HostFloatStorageKind = null;
            for (items.values) |value| kind = mergeHostFloatStorageKind(kind, valueFloatStorageKind(value));
            break :blk kind;
        },
        .first_axis_slice => |items| hostFirstAxisFloatStorageKind(items.source_value, items.source_host),
        .first_axis_index => |items| hostFirstAxisFloatStorageKind(items.source_value, items.source_host),
        .first_axis_concat => |items| hostConcatFloatStorageKind(items),
        .transpose => |items| hostFirstAxisFloatStorageKind(items.source_value, items.source_host),
    };
}

fn hostDenseViewFloatStorageKind(view: HostDenseView) ?HostFloatStorageKind {
    return switch (view) {
        .float_array => |items| hostFloatDenseViewStorageKind(items),
        else => null,
    };
}

fn hostFloatDyadResultStorageKind(left: HostDenseView, right: HostDenseView) HostFloatStorageKind {
    const left_kind = hostDenseViewFloatStorageKind(left);
    const right_kind = hostDenseViewFloatStorageKind(right);
    if (left_kind == .float64 or right_kind == .float64) return .float64;
    if (left_kind == .float32 or right_kind == .float32) return .float32;
    return .float64;
}

fn hostFloatDyadResultStorageKindForValues(left_value: Value, right_value: Value, left: HostDenseView, right: HostDenseView) HostFloatStorageKind {
    const left_kind = mergeHostFloatStorageKind(valueFloatStorageKind(left_value), hostDenseViewFloatStorageKind(left));
    const right_kind = mergeHostFloatStorageKind(valueFloatStorageKind(right_value), hostDenseViewFloatStorageKind(right));
    if (left_kind == .float64 or right_kind == .float64) return .float64;
    if (left_kind == .float32 or right_kind == .float32) return .float32;
    return .float64;
}

fn hostDenseIntKind(view: HostDenseView) ?HostIntStorageKind {
    return switch (view) {
        .scalar_int => |value| hostIntStorageKindForValue(value),
        .int_array => |items| hostIntDenseViewKind(items),
        else => null,
    };
}

fn hostFloatDenseViewLen(view: HostFloatDenseView) usize {
    return switch (view) {
        .dense => |items| items.len,
        .flat_slice => |items| items.len,
        .flat_stride => |items| items.len,
        .flat_concat => |items| items.len,
        .flat_segments => |items| items.len,
        .first_axis_slice => |items| items.len,
        .first_axis_index => |items| items.len,
        .first_axis_concat => |items| items.len,
        .transpose => |items| hostTransposeViewLen(items),
    };
}

fn hostFloatDenseViewItem(view: HostFloatDenseView, idx: usize) KError!f64 {
    return switch (view) {
        .dense => |items| items[idx],
        .flat_slice => |items| try hostFlatSliceFloatItem(items, idx),
        .flat_stride => |items| try hostFlatStrideFloatItem(items, idx),
        .flat_concat => |items| try hostFirstAxisConcatFloatItem(items, idx),
        .flat_segments => |items| try hostFlatSegmentsFloatItem(items, idx),
        .first_axis_slice => |items| try hostFirstAxisSliceFloatItem(items, idx),
        .first_axis_index => |items| try hostFirstAxisIndexFloatItem(items, idx),
        .first_axis_concat => |items| try hostFirstAxisConcatFloatItem(items, idx),
        .transpose => |items| try hostTransposeFloatItem(items, idx),
    };
}

fn hostDenseIntAt(array: *const HostDenseArray, idx: usize) KError!i64 {
    return switch (array.storage) {
        .bit => |words| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk @intFromBool(bitGet(words, idx));
        },
        .int8 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk items[idx];
        },
        .int16 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk items[idx];
        },
        .int32 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk items[idx];
        },
        .int64 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk items[idx];
        },
        .float32 => error.Type,
        .float64 => error.Type,
    };
}

fn hostDenseFloatAt(array: *const HostDenseArray, idx: usize) KError!f64 {
    return switch (array.storage) {
        .bit => |words| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk if (bitGet(words, idx)) 1.0 else 0.0;
        },
        .int8 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk @floatFromInt(items[idx]);
        },
        .int16 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk @floatFromInt(items[idx]);
        },
        .int32 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk @floatFromInt(items[idx]);
        },
        .int64 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk @as(f64, @floatFromInt(items[idx]));
        },
        .float32 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk items[idx];
        },
        .float64 => |items| blk: {
            if (idx >= array.logical_len) return error.Internal;
            break :blk items[idx];
        },
    };
}

fn numericIntAt(value: Value, idx: usize) KError!i64 {
    return switch (value.tag()) {
        .int => value.asInt(),
        .bool => @intFromBool(value.asBool()),
        .array => switch (value.arrayKind()) {
            .host_dense_array => hostDenseIntAt(value.asHostDenseArray(), idx),
            .backend_array => if (valueNumericHandle(value)) |handle|
                if (numericHostAttachment(handle)) |array|
                    hostDenseIntAt(array, idx)
                else
                    error.Type
            else
                error.Type,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (numericHostAttachment(handle)) |array| break :blk hostDenseIntAt(array, idx);
                if (numericArrayIsRangeIota(handle)) break :blk try numericArrayRangeIotaValueAt(handle, idx);
                if (numericArrayIsFlatSlice(handle)) {
                    const source = numericArrayFlatSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFlatSliceStart(handle) orelse break :blk error.Type;
                    break :blk try numericIntAt(source, start + idx);
                }
                if (numericArrayIsFlatConcat(handle)) {
                    const left = numericArrayFlatConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFlatConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericVectorLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericIntAt(left, idx);
                    break :blk try numericIntAt(right, idx - left_len);
                }
                if (numericArrayIsFlatSegments(handle)) {
                    const segments = numericArrayFlatSegmentsValues(handle) orelse break :blk error.Type;
                    var offset: usize = 0;
                    for (segments) |segment| {
                        const len = numericVectorLen(segment) orelse break :blk error.Type;
                        if (idx < offset + len) break :blk try numericIntAt(segment, idx - offset);
                        offset += len;
                    }
                    break :blk error.Type;
                }
                if (numericArrayIsFirstAxisSlice(handle)) {
                    const source = numericArrayFirstAxisSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFirstAxisSliceRowStart(handle) orelse break :blk error.Type;
                    const row_step = numericArrayFirstAxisSliceRowStep(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(row_idx)) * @as(i64, row_step);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericIntAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisIndex(handle)) {
                    const source = numericArrayFirstAxisIndexSource(handle) orelse break :blk error.Type;
                    const row_indices = numericArrayFirstAxisIndexRows(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = try numericIntAt(row_indices, row_idx);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericIntAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisConcat(handle)) {
                    const left = numericArrayFirstAxisConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericFlatLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericIntAt(left, idx);
                    break :blk try numericIntAt(right, idx - left_len);
                }
                if (numericArrayIsTransposeView(handle)) {
                    const source = numericArrayTransposeSource(handle) orelse break :blk error.Type;
                    const source_shape = valueNumericMatrixShape(source) orelse break :blk error.Type;
                    const out_row = idx / source_shape.rows;
                    const out_col = idx % source_shape.rows;
                    break :blk try numericIntAt(source, out_col * source_shape.cols + out_row);
                }
                if (numericArrayIsReshapeView(handle)) {
                    const source = numericArrayReshapeSource(handle) orelse break :blk error.Type;
                    break :blk try numericIntAt(source, idx);
                }
                break :blk error.Type;
            },
            else => error.Internal,
        },
        else => error.Type,
    };
}

fn numericFloatAt(value: Value, idx: usize) KError!f64 {
    return switch (value.tag()) {
        .int => @as(f64, @floatFromInt(value.asInt())),
        .bool => @as(f64, @floatFromInt(@intFromBool(value.asBool()))),
        .float32 => @as(f64, @floatCast(value.asFloat32())),
        .float => value.asFloat(),
        .array => switch (value.arrayKind()) {
            .host_dense_array => hostDenseFloatAt(value.asHostDenseArray(), idx),
            .backend_array => if (valueNumericHandle(value)) |handle|
                if (numericHostAttachment(handle)) |array|
                    hostDenseFloatAt(array, idx)
                else
                    error.Type
            else
                error.Type,
            .numeric_array => blk: {
                const handle = value.asNumericArray();
                if (numericHostAttachment(handle)) |array| break :blk hostDenseFloatAt(array, idx);
                if (numericArrayIsRangeIota(handle)) break :blk @floatFromInt(try numericArrayRangeIotaValueAt(handle, idx));
                if (numericArrayIsFlatSlice(handle)) {
                    const source = numericArrayFlatSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFlatSliceStart(handle) orelse break :blk error.Type;
                    break :blk try numericFloatAt(source, start + idx);
                }
                if (numericArrayIsFlatConcat(handle)) {
                    const left = numericArrayFlatConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFlatConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericVectorLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericFloatAt(left, idx);
                    break :blk try numericFloatAt(right, idx - left_len);
                }
                if (numericArrayIsFlatSegments(handle)) {
                    const segments = numericArrayFlatSegmentsValues(handle) orelse break :blk error.Type;
                    var offset: usize = 0;
                    for (segments) |segment| {
                        const len = numericVectorLen(segment) orelse break :blk error.Type;
                        if (idx < offset + len) break :blk try numericFloatAt(segment, idx - offset);
                        offset += len;
                    }
                    break :blk error.Type;
                }
                if (numericArrayIsFirstAxisSlice(handle)) {
                    const source = numericArrayFirstAxisSliceSource(handle) orelse break :blk error.Type;
                    const start = numericArrayFirstAxisSliceRowStart(handle) orelse break :blk error.Type;
                    const row_step = numericArrayFirstAxisSliceRowStep(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = @as(i64, @intCast(start)) + @as(i64, @intCast(row_idx)) * @as(i64, row_step);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericFloatAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisIndex(handle)) {
                    const source = numericArrayFirstAxisIndexSource(handle) orelse break :blk error.Type;
                    const row_indices = numericArrayFirstAxisIndexRows(handle) orelse break :blk error.Type;
                    const source_handle = shapedNumericHandle(source) orelse break :blk error.Type;
                    const row_width = numericShapeInnerBlockLen(source_handle);
                    const row_idx = idx / row_width;
                    const col_idx = idx % row_width;
                    const source_row_i64 = try numericIntAt(row_indices, row_idx);
                    if (source_row_i64 < 0) break :blk error.Type;
                    break :blk try numericFloatAt(source, @as(usize, @intCast(source_row_i64)) * row_width + col_idx);
                }
                if (numericArrayIsFirstAxisConcat(handle)) {
                    const left = numericArrayFirstAxisConcatLeft(handle) orelse break :blk error.Type;
                    const right = numericArrayFirstAxisConcatRight(handle) orelse break :blk error.Type;
                    const left_len = numericFlatLen(left) orelse break :blk error.Type;
                    if (idx < left_len) break :blk try numericFloatAt(left, idx);
                    break :blk try numericFloatAt(right, idx - left_len);
                }
                if (numericArrayIsTransposeView(handle)) {
                    const source = numericArrayTransposeSource(handle) orelse break :blk error.Type;
                    const source_shape = valueNumericMatrixShape(source) orelse break :blk error.Type;
                    const out_row = idx / source_shape.rows;
                    const out_col = idx % source_shape.rows;
                    break :blk try numericFloatAt(source, out_col * source_shape.cols + out_row);
                }
                if (numericArrayIsReshapeView(handle)) {
                    const source = numericArrayReshapeSource(handle) orelse break :blk error.Type;
                    break :blk try numericFloatAt(source, idx);
                }
                break :blk error.Type;
            },
            else => error.Internal,
        },
        else => error.Type,
    };
}

fn bangIntOp(left: i64, right: i64) i64 {
    if (left > 0) {
        return @intCast(@mod(@as(i128, right), @as(i128, left)));
    }
    if (left < 0) {
        return @intCast(@divFloor(@as(i128, right), -@as(i128, left)));
    }
    return right;
}

fn bangFloatOp(left: i64, right: f64) f64 {
    if (left > 0) {
        return @mod(right, @as(f64, @floatFromInt(left)));
    }
    if (left < 0) {
        return @floor(right / @as(f64, @floatFromInt(-@as(i128, left))));
    }
    return right;
}

fn checkedIntOp(op: BuiltinId, left: i64, right: i64) KError!i64 {
    return switch (op) {
        .add => blk: {
            const result = @addWithOverflow(left, right);
            if (result[1] != 0) return error.Unsupported;
            break :blk result[0];
        },
        .sub => blk: {
            const result = @subWithOverflow(left, right);
            if (result[1] != 0) return error.Unsupported;
            break :blk result[0];
        },
        .iota => bangIntOp(left, right),
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        .mul => blk: {
            const result = @mulWithOverflow(left, right);
            if (result[1] != 0) return error.Unsupported;
            break :blk result[0];
        },
        .pow => try intPowLikeMlx(left, right),
        .div => unreachable,
        else => unreachable,
    };
}

fn applyFloatOp(op: BuiltinId, left: f64, right: f64) f64 {
    return switch (op) {
        .add => left + right,
        .sub => left - right,
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        .mul => left * right,
        .div => left / right,
        .pow => std.math.pow(f64, left, right),
        else => unreachable,
    };
}

fn applyFloatMonadOp(op: BuiltinId, value: f64) f64 {
    return switch (op) {
        .div => std.math.sqrt(value),
        .exp => std.math.exp(value),
        .log => std.math.log(f64, std.math.e, value),
        .sin => std.math.sin(value),
        .cos => std.math.cos(value),
        .tanh => std.math.tanh(value),
        .sigmoid => 1.0 / (1.0 + std.math.exp(-value)),
        else => unreachable,
    };
}

fn applyIntOpUnchecked(op: BuiltinId, left: i64, right: i64) i64 {
    return switch (op) {
        .add => left + right,
        .sub => left - right,
        .iota => bangIntOp(left, right),
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        .mul => left * right,
        .pow => @intFromFloat(@trunc(std.math.pow(f64, @floatFromInt(left), @floatFromInt(right)))),
        .div => unreachable,
        else => unreachable,
    };
}

fn checkedAddAcc(acc: *i64, value: i64) KError!void {
    acc.* = try checkedIntOp(.add, acc.*, value);
}

fn addScanIntFlags(item_range: HostIntRange) u8 {
    return host_dense_flag_normalized | orderFlagsFromMonotonic(item_range.min >= 0, item_range.max <= 0);
}

fn addScanFloatFlags(items: []const f64) u8 {
    var asc = true;
    var dsc = true;
    for (items) |item| {
        if (!std.math.isFinite(item)) {
            asc = false;
            dsc = false;
            break;
        }
        if (item < 0) asc = false;
        if (item > 0) dsc = false;
    }
    return host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc);
}

fn foldAddIntBitSlice(items: HostBitSlice, seed: ?i64) KError!i64 {
    // Packed bool folds can count whole words instead of scalarizing each element.
    const count: i64 = @intCast(bitCountTrue(items));
    var total = seed orelse return count;
    try checkedAddAcc(&total, count);
    return total;
}

fn foldAddIntSlice(comptime T: type, items: []const T, seed: ?i64) KError!i64 {
    var total = seed orelse @as(i64, items[0]);
    const start_idx: usize = if (seed == null) 1 else 0;
    for (items[start_idx..]) |item| try checkedAddAcc(&total, @intCast(item));
    return total;
}

fn hostSumIntSliceUnchecked(comptime T: type, items: []const T) i64 {
    if (comptime enable_host_int_sum_vectorized) {
        if (items.len >= host_int_sum_vector_min_len) {
            const dispatch = kiwi_host_int_sum_dispatch();
            return switch (T) {
                i8 => dispatch.sum_i8(items.ptr, items.len),
                i16 => dispatch.sum_i16(items.ptr, items.len),
                i32 => dispatch.sum_i32(items.ptr, items.len),
                i64 => dispatch.sum_i64(items.ptr, items.len),
                else => unreachable,
            };
        }
    }

    var total: i64 = 0;
    for (items) |item| total += @intCast(item);
    return total;
}

fn foldAddIntSliceUnchecked(comptime T: type, items: []const T, seed: ?i64, vector_item_sum_safe: bool) i64 {
    if (vector_item_sum_safe) {
        return (seed orelse 0) + hostSumIntSliceUnchecked(T, items);
    }

    var total = seed orelse @as(i64, items[0]);
    const start_idx: usize = if (seed == null) 1 else 0;
    for (items[start_idx..]) |item| total += @intCast(item);
    return total;
}

fn foldAddIntBitSliceUnchecked(items: HostBitSlice, seed: ?i64) i64 {
    return (seed orelse 0) + @as(i64, @intCast(bitCountTrue(items)));
}

fn foldAddRangeFitsI64(item_range: HostIntRange, len: usize, seed: ?i64) bool {
    const len_i128: i128 = @intCast(len);
    const seed_i128: i128 = if (seed) |value| value else 0;
    const min_total = @as(i128, item_range.min) * len_i128 + seed_i128;
    const max_total = @as(i128, item_range.max) * len_i128 + seed_i128;
    return min_total >= std.math.minInt(i64) and max_total <= std.math.maxInt(i64);
}

fn foldAddIntView(view: HostIntArrayView, seed: ?i64) KError!i64 {
    return switch (view) {
        .bit => |items| try foldAddIntBitSlice(items, seed),
        .int8 => |items| try foldAddIntSlice(i8, items, seed),
        .int16 => |items| try foldAddIntSlice(i16, items, seed),
        .int32 => |items| try foldAddIntSlice(i32, items, seed),
        .int64 => |items| try foldAddIntSlice(i64, items, seed),
    };
}

fn foldAddIntViewUnchecked(view: HostIntArrayView, seed: ?i64, vector_item_sum_safe: bool) i64 {
    return switch (view) {
        .bit => |items| foldAddIntBitSliceUnchecked(items, seed),
        .int8 => |items| foldAddIntSliceUnchecked(i8, items, seed, vector_item_sum_safe),
        .int16 => |items| foldAddIntSliceUnchecked(i16, items, seed, vector_item_sum_safe),
        .int32 => |items| foldAddIntSliceUnchecked(i32, items, seed, vector_item_sum_safe),
        .int64 => |items| foldAddIntSliceUnchecked(i64, items, seed, vector_item_sum_safe),
    };
}

fn foldAddIntViewMaybeUnchecked(view: HostIntArrayView, known_range: ?HostIntRange, seed: ?i64) KError!i64 {
    if (known_range) |item_range| {
        const len = hostIntArrayViewLen(view);
        if (foldAddRangeFitsI64(item_range, len, seed)) {
            return foldAddIntViewUnchecked(view, seed, foldAddRangeFitsI64(item_range, len, null));
        }
    }
    return try foldAddIntView(view, seed);
}

fn foldAddFloatSlice(items: []const f64, seed: ?f64) f64 {
    var total = seed orelse items[0];
    const start_idx: usize = if (seed == null) 1 else 0;
    for (items[start_idx..]) |item| total += item;
    return total;
}

fn foldAddFloatIntView(view: HostIntArrayView, seed: f64) f64 {
    var total = seed;
    switch (view) {
        .bit => |items| {
            total += @floatFromInt(bitCountTrue(items));
        },
        .int8 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
        .int16 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
        .int32 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
        .int64 => |items| for (items) |item| {
            total += @floatFromInt(item);
        },
    }
    return total;
}

const HostFloatBounds = struct {
    min: f64,
    max: f64,
};

fn hostFloatDenseViewBounds(view: HostFloatDenseView) KError!HostFloatBounds {
    return switch (view) {
        .dense => |items| blk: {
            var min_value = items[0];
            var max_value = items[0];
            for (items[1..]) |item| {
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
        else => blk: {
            const len = hostFloatDenseViewLen(view);
            var min_value = try hostFloatDenseViewItem(view, 0);
            var max_value = min_value;
            for (1..len) |idx| {
                const item = try hostFloatDenseViewItem(view, idx);
                min_value = @min(min_value, item);
                max_value = @max(max_value, item);
            }
            break :blk .{ .min = min_value, .max = max_value };
        },
    };
}

fn analyzeAddScanIntView(view: HostIntArrayView, seed: ?i64) KError!HostAddScanIntAnalysis {
    const len = hostIntArrayViewLen(view);
    std.debug.assert(len > 1);

    var acc = if (seed) |seed_value|
        try checkedIntOp(.add, seed_value, hostIntViewItem(view, 0))
    else
        hostIntViewItem(view, 0);
    var min_value = acc;
    var max_value = acc;

    for (1..len) |idx| {
        try checkedAddAcc(&acc, hostIntViewItem(view, idx));
        min_value = @min(min_value, acc);
        max_value = @max(max_value, acc);
    }

    return .{
        .range = .{ .min = min_value, .max = max_value },
        .kind = hostIntStorageKindForRange(min_value, max_value),
        .flags = addScanIntFlags(hostIntArrayViewRange(view)),
    };
}

fn hostIntDenseViewBitSlice(view: HostIntDenseView) ?HostBitSlice {
    return switch (view) {
        .dense => |items| switch (items) {
            .bit => |bits| bits,
            else => null,
        },
        else => null,
    };
}

fn bitMinMaxScanResultIsBit(op: BuiltinId, seed: i64) bool {
    return switch (op) {
        .minimum => seed >= 0,
        .maximum => seed <= 1,
        else => false,
    };
}

fn minMaxScanIntOp(op: BuiltinId, left: i64, right: i64) i64 {
    return switch (op) {
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        else => unreachable,
    };
}

fn minMaxScanFloatOp(op: BuiltinId, left: f64, right: f64) f64 {
    return switch (op) {
        .minimum => @min(left, right),
        .maximum => @max(left, right),
        else => unreachable,
    };
}

fn fillMinMaxScanInt(out: []i64, view: HostIntDenseView, op: BuiltinId, seed: ?i64) KError!void {
    std.debug.assert(out.len == hostIntDenseViewLen(view));
    std.debug.assert(out.len > 0);

    var acc: i64 = undefined;
    const start_idx: usize = if (seed) |seed_value| blk: {
        acc = seed_value;
        break :blk 0;
    } else blk: {
        acc = try hostIntDenseViewItem(view, 0);
        out[0] = acc;
        break :blk 1;
    };

    for (start_idx..out.len) |idx| {
        acc = minMaxScanIntOp(op, acc, try hostIntDenseViewItem(view, idx));
        out[idx] = acc;
    }
}

fn fillMinMaxScanFloatFromInt(out: []f64, view: HostIntDenseView, op: BuiltinId, seed: f64) KError!void {
    std.debug.assert(out.len == hostIntDenseViewLen(view));
    var acc = seed;
    for (0..out.len) |idx| {
        acc = minMaxScanFloatOp(op, acc, @floatFromInt(try hostIntDenseViewItem(view, idx)));
        out[idx] = acc;
    }
}

fn fillMinMaxScanFloat(out: []f64, view: HostFloatDenseView, op: BuiltinId, seed: ?f64) KError!void {
    std.debug.assert(out.len == hostFloatDenseViewLen(view));
    std.debug.assert(out.len > 0);

    var acc: f64 = undefined;
    const start_idx: usize = if (seed) |seed_value| blk: {
        acc = seed_value;
        break :blk 0;
    } else blk: {
        acc = try hostFloatDenseViewItem(view, 0);
        out[0] = acc;
        break :blk 1;
    };

    for (start_idx..out.len) |idx| {
        acc = minMaxScanFloatOp(op, acc, try hostFloatDenseViewItem(view, idx));
        out[idx] = acc;
    }
}

fn minMaxScanInitialBit(op: BuiltinId) bool {
    return switch (op) {
        .minimum => true,
        .maximum => false,
        else => unreachable,
    };
}

fn minMaxScanBitOp(op: BuiltinId, left: bool, right: bool) bool {
    return switch (op) {
        .minimum => left and right,
        .maximum => left or right,
        else => unreachable,
    };
}

fn fillFirstAxisBitMinMaxScan(out: []u64, bits: HostBitSlice, op: BuiltinId, block_len: usize, outer_len: usize) BitDenseMetadata {
    std.debug.assert(bits.len == block_len * outer_len);
    bitFill(out, bits.len, false);
    var stats = BitSequenceStats{};
    for (0..block_len) |inner_idx| {
        var acc = minMaxScanInitialBit(op);
        for (0..outer_len) |outer_idx| {
            const idx = outer_idx * block_len + inner_idx;
            acc = minMaxScanBitOp(op, acc, bitGet(bits.words, idx));
            bitSet(out, idx, acc);
            stats.note(acc);
        }
    }
    return stats.metadata();
}

fn fillFirstAxisBitLikeMinMaxScan(out: []u64, view: HostIntDenseView, op: BuiltinId, block_len: usize, outer_len: usize) KError!BitDenseMetadata {
    std.debug.assert(hostIntDenseViewLen(view) == block_len * outer_len);
    bitFill(out, hostIntDenseViewLen(view), false);
    var stats = BitSequenceStats{};
    for (0..block_len) |inner_idx| {
        var acc = minMaxScanInitialBit(op);
        for (0..outer_len) |outer_idx| {
            const idx = outer_idx * block_len + inner_idx;
            acc = minMaxScanBitOp(op, acc, try hostIntDenseViewItem(view, idx) != 0);
            bitSet(out, idx, acc);
            stats.note(acc);
        }
    }
    return stats.metadata();
}

fn fillRowBitMinMaxScan(out: []u64, bits: HostBitSlice, op: BuiltinId, rows: usize, cols: usize) BitDenseMetadata {
    std.debug.assert(bits.len == rows * cols);
    bitFill(out, bits.len, false);
    var stats = BitSequenceStats{};
    for (0..rows) |row_idx| {
        var acc = minMaxScanInitialBit(op);
        const row_base = row_idx * cols;
        for (0..cols) |col_idx| {
            const idx = row_base + col_idx;
            acc = minMaxScanBitOp(op, acc, bitGet(bits.words, idx));
            bitSet(out, idx, acc);
            stats.note(acc);
        }
    }
    return stats.metadata();
}

fn fillRowMinMaxScanInt(out: *HostIntResult, view: HostIntDenseView, op: BuiltinId, rows: usize, cols: usize) KError!void {
    std.debug.assert(hostIntDenseViewLen(view) == rows * cols);
    for (0..rows) |row_idx| {
        const row_base = row_idx * cols;
        var acc = try hostIntDenseViewItem(view, row_base);
        try out.set(row_base, acc);
        for (1..cols) |col_idx| {
            const idx = row_base + col_idx;
            acc = minMaxScanIntOp(op, acc, try hostIntDenseViewItem(view, idx));
            try out.set(idx, acc);
        }
    }
}

fn fillRowMinMaxScanFloat(out: []f64, view: HostFloatDenseView, op: BuiltinId, rows: usize, cols: usize) KError!void {
    std.debug.assert(hostFloatDenseViewLen(view) == rows * cols);
    for (0..rows) |row_idx| {
        const row_base = row_idx * cols;
        var acc = try hostFloatDenseViewItem(view, row_base);
        out[row_base] = acc;
        for (1..cols) |col_idx| {
            const idx = row_base + col_idx;
            acc = minMaxScanFloatOp(op, acc, try hostFloatDenseViewItem(view, idx));
            out[idx] = acc;
        }
    }
}

fn fillRowMinMaxScanFloat32(out: []f32, view: HostFloatDenseView, op: BuiltinId, rows: usize, cols: usize) KError!void {
    std.debug.assert(hostFloatDenseViewLen(view) == rows * cols);
    for (0..rows) |row_idx| {
        const row_base = row_idx * cols;
        var acc = try hostFloatDenseViewItem(view, row_base);
        out[row_base] = @floatCast(acc);
        for (1..cols) |col_idx| {
            const idx = row_base + col_idx;
            acc = minMaxScanFloatOp(op, acc, try hostFloatDenseViewItem(view, idx));
            out[idx] = @floatCast(acc);
        }
    }
}

fn fillFirstAxisAddScanInt(out: []i64, view: HostIntDenseView, block_len: usize, outer_len: usize) KError!void {
    std.debug.assert(out.len == hostIntDenseViewLen(view));
    std.debug.assert(out.len == block_len * outer_len);
    for (0..block_len) |inner_idx| {
        var acc: i64 = 0;
        for (0..outer_len) |outer_idx| {
            const idx = outer_idx * block_len + inner_idx;
            try checkedAddAcc(&acc, try hostIntDenseViewItem(view, idx));
            out[idx] = acc;
        }
    }
}

fn fillRowAddScanInt(out: []i64, view: HostIntDenseView, rows: usize, cols: usize) KError!void {
    std.debug.assert(out.len == hostIntDenseViewLen(view));
    std.debug.assert(out.len == rows * cols);
    for (0..rows) |row_idx| {
        const row_base = row_idx * cols;
        var acc: i64 = 0;
        for (0..cols) |col_idx| {
            const idx = row_base + col_idx;
            try checkedAddAcc(&acc, try hostIntDenseViewItem(view, idx));
            out[idx] = acc;
        }
    }
}

fn fillFirstAxisAddScanFloat(out: []f64, view: HostFloatDenseView, block_len: usize, outer_len: usize) KError!void {
    std.debug.assert(out.len == hostFloatDenseViewLen(view));
    std.debug.assert(out.len == block_len * outer_len);
    for (0..block_len) |inner_idx| {
        var acc: f64 = 0;
        for (0..outer_len) |outer_idx| {
            const idx = outer_idx * block_len + inner_idx;
            acc += try hostFloatDenseViewItem(view, idx);
            out[idx] = acc;
        }
    }
}

fn fillRowAddScanFloat(out: []f64, view: HostFloatDenseView, rows: usize, cols: usize) KError!void {
    std.debug.assert(out.len == hostFloatDenseViewLen(view));
    std.debug.assert(out.len == rows * cols);
    for (0..rows) |row_idx| {
        const row_base = row_idx * cols;
        var acc: f64 = 0;
        for (0..cols) |col_idx| {
            const idx = row_base + col_idx;
            acc += try hostFloatDenseViewItem(view, idx);
            out[idx] = acc;
        }
    }
}

fn bitScanWordMetadata(word: u64, active_mask: u64, saw_zero: *bool, saw_one: *bool) void {
    if ((word & active_mask) != 0) saw_one.* = true;
    if ((word & active_mask) != active_mask) saw_zero.* = true;
}

fn finishBitScanMetadata(op: BuiltinId, saw_zero: bool, saw_one: bool) BitDenseMetadata {
    const constant = !saw_zero or !saw_one;
    const asc = constant or op == .maximum;
    const dsc = constant or op == .minimum;
    return .{
        .flags = host_dense_flag_normalized | orderFlagsFromMonotonic(asc, dsc),
        .range = .{
            .min = if (saw_zero) 0 else if (saw_one) 1 else 0,
            .max = if (saw_one) 1 else 0,
        },
    };
}

fn fillBitPrefixOrScan(out: []u64, items: HostBitSlice, initial: bool) BitDenseMetadata {
    std.debug.assert(out.len == items.words.len);
    var carry = initial;
    var saw_zero = false;
    var saw_one = false;

    for (out, 0..) |*out_word, word_idx| {
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        const active_mask = bitLowMask(active);
        const result = if (carry) blk: {
            break :blk active_mask;
        } else blk: {
            const word = bitWordMasked(items.words, items.len, word_idx);
            if (word == 0) break :blk @as(u64, 0);
            const first_one = word & (0 -% word);
            carry = true;
            break :blk (~(first_one -% 1)) & active_mask;
        };
        out_word.* = result;
        bitScanWordMetadata(result, active_mask, &saw_zero, &saw_one);
    }

    return finishBitScanMetadata(.maximum, saw_zero, saw_one);
}

fn fillBitPrefixAndScan(out: []u64, items: HostBitSlice, initial: bool) BitDenseMetadata {
    std.debug.assert(out.len == items.words.len);
    var carry = initial;
    var saw_zero = false;
    var saw_one = false;

    for (out, 0..) |*out_word, word_idx| {
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        const active_mask = bitLowMask(active);
        const result = if (!carry) blk: {
            break :blk @as(u64, 0);
        } else blk: {
            const word = bitWordMasked(items.words, items.len, word_idx);
            const zeroes = (~word) & active_mask;
            if (zeroes == 0) break :blk active_mask;
            const first_zero = zeroes & (0 -% zeroes);
            carry = false;
            break :blk (first_zero -% 1) & active_mask;
        };
        out_word.* = result;
        bitScanWordMetadata(result, active_mask, &saw_zero, &saw_one);
    }

    return finishBitScanMetadata(.minimum, saw_zero, saw_one);
}

fn fillAddScanBitTo(comptime OutT: type, out: []OutT, items: HostBitSlice, seed: ?i64) void {
    var acc = seed orelse 0;
    var saw_value = seed != null;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const item: i64 = @intCast(bits & 1);
            if (!saw_value) {
                acc = item;
                saw_value = true;
            } else {
                acc += item;
            }
            out[out_idx] = @intCast(acc);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillAddScanIntTo(comptime OutT: type, comptime InT: type, out: []OutT, items: []const InT, seed: ?i64) void {
    var acc = seed orelse @as(i64, items[0]);
    const start_idx: usize = if (seed == null) 1 else 0;
    if (seed == null) {
        out[0] = @intCast(acc);
    }
    for (items[start_idx..], start_idx..) |item, idx| {
        if (seed != null or idx != 0) acc += @intCast(item);
        out[idx] = @intCast(acc);
    }
}

fn fillAddScanIntResult(out: *HostIntResult, view: HostIntArrayView, seed: ?i64) void {
    switch (out.*) {
        .bit => unreachable,
        .int8 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i8, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i8, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i8, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i8, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i8, i64, dest.items, items, seed),
        },
        .int16 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i16, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i16, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i16, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i16, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i16, i64, dest.items, items, seed),
        },
        .int32 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i32, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i32, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i32, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i32, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i32, i64, dest.items, items, seed),
        },
        .int64 => |*dest| switch (view) {
            .bit => |items| fillAddScanBitTo(i64, dest.items, items, seed),
            .int8 => |items| fillAddScanIntTo(i64, i8, dest.items, items, seed),
            .int16 => |items| fillAddScanIntTo(i64, i16, dest.items, items, seed),
            .int32 => |items| fillAddScanIntTo(i64, i32, dest.items, items, seed),
            .int64 => |items| fillAddScanIntTo(i64, i64, dest.items, items, seed),
        },
    }
}

fn fillAddScanFloatSlice(out: []f64, items: []const f64, seed: ?f64) void {
    var acc = seed orelse items[0];
    const start_idx: usize = if (seed == null) 1 else 0;
    if (seed == null) out[0] = acc;
    for (items[start_idx..], start_idx..) |item, idx| {
        if (seed != null or idx != 0) acc += item;
        out[idx] = acc;
    }
}

fn fillAddScanFloatBitView(out: []f64, items: HostBitSlice, seed: f64) void {
    var acc = seed;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            acc += @floatFromInt(bits & 1);
            out[out_idx] = acc;
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillAddScanFloatIntTo(comptime InT: type, out: []f64, items: []const InT, seed: f64) void {
    var acc = seed;
    for (items, 0..) |item, idx| {
        acc += @floatFromInt(item);
        out[idx] = acc;
    }
}

fn fillAddScanFloatIntView(out: []f64, view: HostIntArrayView, seed: f64) void {
    switch (view) {
        .bit => |items| fillAddScanFloatBitView(out, items, seed),
        .int8 => |items| fillAddScanFloatIntTo(i8, out, items, seed),
        .int16 => |items| fillAddScanFloatIntTo(i16, out, items, seed),
        .int32 => |items| fillAddScanFloatIntTo(i32, out, items, seed),
        .int64 => |items| fillAddScanFloatIntTo(i64, out, items, seed),
    }
}

fn castDenseInt(comptime T: type, value: anytype) T {
    return @as(T, @intCast(value));
}

fn castCheckedDenseInt(comptime T: type, value: i64) KError!T {
    return std.math.cast(T, value) orelse return error.Unsupported;
}

fn applyIntOpUncheckedTyped(comptime T: type, op: BuiltinId, left: anytype, right: anytype) T {
    const lhs: T = castDenseInt(T, left);
    const rhs: T = castDenseInt(T, right);
    return switch (op) {
        .add => lhs + rhs,
        .sub => lhs - rhs,
        .iota => castDenseInt(T, bangIntOp(@as(i64, @intCast(lhs)), @as(i64, @intCast(rhs)))),
        .minimum => @min(lhs, rhs),
        .maximum => @max(lhs, rhs),
        .mul => lhs * rhs,
        .pow => castDenseInt(T, @as(i64, @intFromFloat(@trunc(std.math.pow(f64, @floatFromInt(lhs), @floatFromInt(rhs)))))),
        .div => unreachable,
        else => unreachable,
    };
}

fn WiderDenseInt(comptime T: type) type {
    return switch (T) {
        i8 => i16,
        i16 => i32,
        i32 => i64,
        i64 => i64,
        else => @compileError("unsupported dense int type"),
    };
}

fn applyIntOpCheckedNarrow(comptime OutT: type, op: BuiltinId, left: anytype, right: anytype) KError!OutT {
    if (OutT == i64) {
        return castDenseInt(OutT, try checkedIntOp(op, @as(i64, @intCast(left)), @as(i64, @intCast(right))));
    }

    const WideT = WiderDenseInt(OutT);
    const lhs: WideT = castDenseInt(WideT, left);
    const rhs: WideT = castDenseInt(WideT, right);
    const result: WideT = switch (op) {
        .add => lhs + rhs,
        .sub => lhs - rhs,
        .iota => return castCheckedDenseInt(OutT, bangIntOp(@as(i64, @intCast(lhs)), @as(i64, @intCast(rhs)))),
        .mul => lhs * rhs,
        .div => unreachable,
        else => unreachable,
    };
    return std.math.cast(OutT, result) orelse error.Unsupported;
}

fn negateCheckedNarrow(comptime OutT: type, value: anytype) KError!OutT {
    if (OutT == i64) {
        return castDenseInt(OutT, try checkedIntOp(.sub, 0, @as(i64, @intCast(value))));
    }

    const WideT = WiderDenseInt(OutT);
    const result: WideT = -castDenseInt(WideT, value);
    return std.math.cast(OutT, result) orelse error.Unsupported;
}

fn toDenseFloat(value: anytype) f64 {
    return switch (@typeInfo(@TypeOf(value))) {
        .float, .comptime_float => value,
        .int, .comptime_int => @floatFromInt(value),
        else => @compileError("unsupported dense numeric type"),
    };
}

const dense_host_simd_bytes = 32;
const enable_dense_float_simd = true;
const enable_packed_bit_simd = true;
const enable_string_byte_simd = true;
const enable_mixed_bit_float_simd = true;
const enable_dense_int_simd = true;

fn denseFloatSimdSupported(op: BuiltinId) bool {
    return switch (op) {
        .add, .sub, .minimum, .maximum, .mul, .div => true,
        else => false,
    };
}

fn denseIntSimdSupported(op: BuiltinId) bool {
    return switch (op) {
        .add, .sub, .minimum, .maximum, .mul => true,
        else => false,
    };
}

fn denseFloatBinaryVec(comptime op: BuiltinId, lhs: anytype, rhs: @TypeOf(lhs)) @TypeOf(lhs) {
    return switch (op) {
        .add => lhs + rhs,
        .sub => lhs - rhs,
        .minimum => @min(lhs, rhs),
        .maximum => @max(lhs, rhs),
        .mul => lhs * rhs,
        .div => lhs / rhs,
        else => unreachable,
    };
}

fn denseIntBinaryVec(comptime op: BuiltinId, lhs: anytype, rhs: @TypeOf(lhs)) @TypeOf(lhs) {
    return switch (op) {
        .add => lhs + rhs,
        .sub => lhs - rhs,
        .minimum => @min(lhs, rhs),
        .maximum => @max(lhs, rhs),
        .mul => lhs * rhs,
        else => unreachable,
    };
}

fn hostDenseDyadOpCode(comptime op: BuiltinId) i32 {
    return switch (op) {
        .add => host_dyad_op_add,
        .sub => host_dyad_op_sub,
        .minimum => host_dyad_op_min,
        .maximum => host_dyad_op_max,
        .mul => host_dyad_op_mul,
        .div => host_dyad_op_div,
        else => unreachable,
    };
}

fn hostDenseDyadIntWidth(comptime T: type) i32 {
    return switch (@sizeOf(T)) {
        1 => 1,
        2 => 2,
        4 => 4,
        8 => 8,
        else => @compileError("unsupported dense host integer width"),
    };
}

fn tryHostDenseDyadFloatArray(comptime op: BuiltinId, out: []f64, left_items: []const f64, right_items: []const f64) bool {
    if (comptime !enable_host_dense_dyad_vectorized) return false;
    if (comptime op == .add or op == .minimum or op == .mul) return false;
    if (left_items.len < host_dense_dyad_vector_min_len) return false;
    return kiwi_host_dyad_f64_array(out.ptr, left_items.ptr, right_items.ptr, left_items.len, hostDenseDyadOpCode(op)) != 0;
}

fn tryHostDenseDyadFloatScalar(comptime op: BuiltinId, out: []f64, scalar: f64, items: []const f64, scalar_left: bool) bool {
    if (comptime !enable_host_dense_dyad_vectorized) return false;
    if (comptime op == .add or op == .minimum or op == .mul) return false;
    if (items.len < host_dense_dyad_vector_min_len) return false;
    return kiwi_host_dyad_f64_scalar(out.ptr, scalar, items.ptr, items.len, if (scalar_left) 1 else 0, hostDenseDyadOpCode(op)) != 0;
}

fn tryHostDenseDyadIntArray(comptime T: type, comptime op: BuiltinId, out: []T, left_items: []const T, right_items: []const T) bool {
    if (comptime !enable_host_dense_dyad_vectorized) return false;
    if (comptime @sizeOf(T) == 8) return false;
    if (left_items.len < host_dense_dyad_vector_min_len) return false;
    return kiwi_host_dyad_int_array(
        @ptrCast(out.ptr),
        @ptrCast(left_items.ptr),
        @ptrCast(right_items.ptr),
        left_items.len,
        hostDenseDyadIntWidth(T),
        hostDenseDyadOpCode(op),
    ) != 0;
}

fn tryHostDenseDyadIntScalar(comptime T: type, comptime op: BuiltinId, out: []T, scalar: T, items: []const T, scalar_left: bool) bool {
    if (comptime !enable_host_dense_dyad_vectorized) return false;
    if (comptime @sizeOf(T) == 8) return false;
    if (items.len < host_dense_dyad_vector_min_len) return false;
    return kiwi_host_dyad_int_scalar(
        @ptrCast(out.ptr),
        @as(i64, @intCast(scalar)),
        @ptrCast(items.ptr),
        items.len,
        hostDenseDyadIntWidth(T),
        if (scalar_left) 1 else 0,
        hostDenseDyadOpCode(op),
    ) != 0;
}

fn denseBitWordSimdSupported(op: BuiltinId) bool {
    return switch (op) {
        .mul, .minimum, .maximum, .equal, .less, .more => true,
        else => false,
    };
}

fn denseBitWordBinaryVec(comptime op: BuiltinId, lhs: anytype, rhs: @TypeOf(lhs)) @TypeOf(lhs) {
    return switch (op) {
        .mul, .minimum => lhs & rhs,
        .maximum => lhs | rhs,
        .equal => ~(lhs ^ rhs),
        .less => (~lhs) & rhs,
        .more => lhs & (~rhs),
        else => unreachable,
    };
}

fn fillBitWordsBinarySimd(comptime op: BuiltinId, out: []u64, left_words: []const u64, right_words: []const u64) void {
    const lane_count = dense_host_simd_bytes / @sizeOf(u64);
    const Vec = @Vector(lane_count, u64);
    var idx: usize = 0;
    const vector_limit = left_words.len - (left_words.len % lane_count);
    while (idx < vector_limit) : (idx += lane_count) {
        const lhs: Vec = left_words[idx..][0..lane_count].*;
        const rhs: Vec = right_words[idx..][0..lane_count].*;
        out[idx..][0..lane_count].* = denseBitWordBinaryVec(op, lhs, rhs);
    }
    while (idx < left_words.len) : (idx += 1) {
        out[idx] = switch (op) {
            .mul, .minimum => left_words[idx] & right_words[idx],
            .maximum => left_words[idx] | right_words[idx],
            .equal => ~(left_words[idx] ^ right_words[idx]),
            .less => (~left_words[idx]) & right_words[idx],
            .more => left_words[idx] & (~right_words[idx]),
            else => unreachable,
        };
    }
}

fn fillBitWordsBinary(out: []u64, op: BuiltinId, left_words: []const u64, right_words: []const u64) void {
    return switch (op) {
        .mul => fillBitWordsBinarySimd(.mul, out, left_words, right_words),
        .minimum => fillBitWordsBinarySimd(.minimum, out, left_words, right_words),
        .maximum => fillBitWordsBinarySimd(.maximum, out, left_words, right_words),
        .equal => fillBitWordsBinarySimd(.equal, out, left_words, right_words),
        .less => fillBitWordsBinarySimd(.less, out, left_words, right_words),
        .more => fillBitWordsBinarySimd(.more, out, left_words, right_words),
        else => unreachable,
    };
}

fn fillIntDenseArrayArraySameTypeSimd(comptime T: type, comptime op: BuiltinId, out: []T, left_items: []const T, right_items: []const T) void {
    if (comptime op == .mul and @sizeOf(T) == 8) {
        for (left_items, 0..) |left_item, idx| {
            out[idx] = applyIntOpUncheckedTyped(T, op, left_item, right_items[idx]);
        }
        return;
    }
    if (tryHostDenseDyadIntArray(T, op, out, left_items, right_items)) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(T);
    const Vec = @Vector(lane_count, T);
    var idx: usize = 0;
    const vector_limit = left_items.len - (left_items.len % lane_count);
    while (idx < vector_limit) : (idx += lane_count) {
        const lhs: Vec = left_items[idx..][0..lane_count].*;
        const rhs: Vec = right_items[idx..][0..lane_count].*;
        out[idx..][0..lane_count].* = denseIntBinaryVec(op, lhs, rhs);
    }
    while (idx < left_items.len) : (idx += 1) {
        out[idx] = applyIntOpUncheckedTyped(T, op, left_items[idx], right_items[idx]);
    }
}

fn fillIntDenseScalarArraySameTypeSimd(comptime T: type, comptime op: BuiltinId, out: []T, scalar: T, items: []const T, scalar_left: bool) void {
    if (comptime op == .mul and @sizeOf(T) == 8) {
        for (items, 0..) |item, idx| {
            out[idx] = if (scalar_left)
                applyIntOpUncheckedTyped(T, op, scalar, item)
            else
                applyIntOpUncheckedTyped(T, op, item, scalar);
        }
        return;
    }
    if (tryHostDenseDyadIntScalar(T, op, out, scalar, items, scalar_left)) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(T);
    const Vec = @Vector(lane_count, T);
    const scalar_vec: Vec = @splat(scalar);
    var idx: usize = 0;
    const vector_limit = items.len - (items.len % lane_count);
    while (idx < vector_limit) : (idx += lane_count) {
        const item_vec: Vec = items[idx..][0..lane_count].*;
        out[idx..][0..lane_count].* = if (scalar_left)
            denseIntBinaryVec(op, scalar_vec, item_vec)
        else
            denseIntBinaryVec(op, item_vec, scalar_vec);
    }
    while (idx < items.len) : (idx += 1) {
        out[idx] = if (scalar_left)
            applyIntOpUncheckedTyped(T, op, scalar, items[idx])
        else
            applyIntOpUncheckedTyped(T, op, items[idx], scalar);
    }
}

fn fillIntDenseArrayArraySameType(comptime T: type, out: []T, op: BuiltinId, left_items: []const T, right_items: []const T) void {
    return switch (op) {
        .add => fillIntDenseArrayArraySameTypeSimd(T, .add, out, left_items, right_items),
        .sub => fillIntDenseArrayArraySameTypeSimd(T, .sub, out, left_items, right_items),
        .minimum => fillIntDenseArrayArraySameTypeSimd(T, .minimum, out, left_items, right_items),
        .maximum => fillIntDenseArrayArraySameTypeSimd(T, .maximum, out, left_items, right_items),
        .mul => fillIntDenseArrayArraySameTypeSimd(T, .mul, out, left_items, right_items),
        else => unreachable,
    };
}

fn fillIntDenseScalarArraySameType(comptime T: type, out: []T, op: BuiltinId, scalar: T, items: []const T, scalar_left: bool) void {
    return switch (op) {
        .add => fillIntDenseScalarArraySameTypeSimd(T, .add, out, scalar, items, scalar_left),
        .sub => fillIntDenseScalarArraySameTypeSimd(T, .sub, out, scalar, items, scalar_left),
        .minimum => fillIntDenseScalarArraySameTypeSimd(T, .minimum, out, scalar, items, scalar_left),
        .maximum => fillIntDenseScalarArraySameTypeSimd(T, .maximum, out, scalar, items, scalar_left),
        .mul => fillIntDenseScalarArraySameTypeSimd(T, .mul, out, scalar, items, scalar_left),
        else => unreachable,
    };
}

fn fillFloatDenseArrayArraySimd(comptime op: BuiltinId, out: []f64, left_items: []const f64, right_items: []const f64) void {
    if (tryHostDenseDyadFloatArray(op, out, left_items, right_items)) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(f64);
    const Vec = @Vector(lane_count, f64);
    var idx: usize = 0;
    const vector_limit = left_items.len - (left_items.len % lane_count);
    while (idx < vector_limit) : (idx += lane_count) {
        const lhs: Vec = left_items[idx..][0..lane_count].*;
        const rhs: Vec = right_items[idx..][0..lane_count].*;
        out[idx..][0..lane_count].* = denseFloatBinaryVec(op, lhs, rhs);
    }
    while (idx < left_items.len) : (idx += 1) {
        out[idx] = applyFloatOp(op, left_items[idx], right_items[idx]);
    }
}

fn fillFloatDenseScalarArraySimd(comptime op: BuiltinId, out: []f64, scalar: f64, items: []const f64, scalar_left: bool) void {
    if (tryHostDenseDyadFloatScalar(op, out, scalar, items, scalar_left)) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(f64);
    const Vec = @Vector(lane_count, f64);
    const scalar_vec: Vec = @splat(scalar);
    var idx: usize = 0;
    const vector_limit = items.len - (items.len % lane_count);
    while (idx < vector_limit) : (idx += lane_count) {
        const item_vec: Vec = items[idx..][0..lane_count].*;
        out[idx..][0..lane_count].* = if (scalar_left)
            denseFloatBinaryVec(op, scalar_vec, item_vec)
        else
            denseFloatBinaryVec(op, item_vec, scalar_vec);
    }
    while (idx < items.len) : (idx += 1) {
        const item = items[idx];
        out[idx] = if (scalar_left) applyFloatOp(op, scalar, item) else applyFloatOp(op, item, scalar);
    }
}

fn bitWordFloatVec(comptime lane_count: usize, bits: u64) @Vector(lane_count, f64) {
    var values: [lane_count]f64 = undefined;
    inline for (0..lane_count) |lane| {
        values[lane] = @floatFromInt((bits >> lane) & 1);
    }
    return values;
}

fn fillFloatScalarBitArraySimd(comptime op: BuiltinId, out: []f64, scalar: f64, items: HostBitSlice, scalar_left: bool) void {
    if (items.len == 0) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(f64);
    const Vec = @Vector(lane_count, f64);
    const scalar_vec: Vec = @splat(scalar);
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        var active = bitWordActiveLen(items.len, word_idx, items.words.len);
        while (active >= lane_count) : (active -= lane_count) {
            const bit_vec = bitWordFloatVec(lane_count, bits);
            out[out_idx..][0..lane_count].* = if (scalar_left)
                denseFloatBinaryVec(op, scalar_vec, bit_vec)
            else
                denseFloatBinaryVec(op, bit_vec, scalar_vec);
            bits >>= lane_count;
            out_idx += lane_count;
        }
        var tail_idx: usize = 0;
        while (tail_idx < active) : (tail_idx += 1) {
            const item = @as(f64, @floatFromInt(@as(u8, @intCast(bits & 1))));
            out[out_idx] = if (scalar_left) applyFloatOp(op, scalar, item) else applyFloatOp(op, item, scalar);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillFloatBitViewsSimd(comptime op: BuiltinId, out: []f64, left_items: HostBitSlice, right_items: HostBitSlice) void {
    if (left_items.len == 0) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(f64);
    var out_idx: usize = 0;
    for (left_items.words, 0..) |_, word_idx| {
        var left_bits = bitWordMasked(left_items.words, left_items.len, word_idx);
        var right_bits = bitWordMasked(right_items.words, right_items.len, word_idx);
        var active = bitWordActiveLen(left_items.len, word_idx, left_items.words.len);
        while (active >= lane_count) : (active -= lane_count) {
            const left_vec = bitWordFloatVec(lane_count, left_bits);
            const right_vec = bitWordFloatVec(lane_count, right_bits);
            out[out_idx..][0..lane_count].* = denseFloatBinaryVec(op, left_vec, right_vec);
            left_bits >>= lane_count;
            right_bits >>= lane_count;
            out_idx += lane_count;
        }
        var tail_idx: usize = 0;
        while (tail_idx < active) : (tail_idx += 1) {
            out[out_idx] = applyFloatOp(
                op,
                @as(f64, @floatFromInt(@as(u8, @intCast(left_bits & 1)))),
                @as(f64, @floatFromInt(@as(u8, @intCast(right_bits & 1)))),
            );
            left_bits >>= 1;
            right_bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillFloatBitViewArraySimd(comptime LeftBit: bool, comptime op: BuiltinId, out: []f64, bit_items: HostBitSlice, other_items: []const f64) void {
    if (bit_items.len == 0) return;
    const lane_count = dense_host_simd_bytes / @sizeOf(f64);
    const Vec = @Vector(lane_count, f64);
    const zero: Vec = @splat(0.0);
    var out_idx: usize = 0;
    for (bit_items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(bit_items.words, bit_items.len, word_idx);
        var active = bitWordActiveLen(bit_items.len, word_idx, bit_items.words.len);
        while (active >= lane_count) : (active -= lane_count) {
            const bit_vec = bitWordFloatVec(lane_count, bits);
            const other_vec: Vec = other_items[out_idx..][0..lane_count].*;
            out[out_idx..][0..lane_count].* = if (op == .mul)
                @select(f64, bit_vec != zero, other_vec, zero)
            else if (LeftBit)
                denseFloatBinaryVec(op, bit_vec, other_vec)
            else
                denseFloatBinaryVec(op, other_vec, bit_vec);
            bits >>= lane_count;
            out_idx += lane_count;
        }
        var tail_idx: usize = 0;
        while (tail_idx < active) : (tail_idx += 1) {
            const bit_value = @as(f64, @floatFromInt(@as(u8, @intCast(bits & 1))));
            out[out_idx] = if (LeftBit) applyFloatOp(op, bit_value, other_items[out_idx]) else applyFloatOp(op, other_items[out_idx], bit_value);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillBitScalarArrayResultGeneric(out: *HostBitAlloc, op: BuiltinId, scalar: i64, items: HostIntArrayView, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (enable_packed_bit_simd and (op == .mul or op == .minimum or op == .maximum) and scalar >= 0 and scalar <= 1 and std.meta.activeTag(items) == .bit) {
        const bit_items = items.bit;
        switch (op) {
            .mul, .minimum => {
                if (scalar == 0) {
                    bitFill(out.words, out.len, false);
                    return;
                }
                if (out.words.ptr != bit_items.words.ptr) @memcpy(out.words, bit_items.words);
                bitClearUnusedTail(out.words, out.len);
                return;
            },
            .maximum => {
                if (scalar == 1) {
                    bitFill(out.words, out.len, true);
                    return;
                }
                if (out.words.ptr != bit_items.words.ptr) @memcpy(out.words, bit_items.words);
                bitClearUnusedTail(out.words, out.len);
                return;
            },
            else => unreachable,
        }
    }

    var generic_out = HostIntResult{ .bit = out.* };
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = hostIntViewItem(items, idx);
        const result = if (unchecked_safe)
            if (scalar_left) applyIntOpUnchecked(op, scalar, item) else applyIntOpUnchecked(op, item, scalar)
        else
            try checkedIntOp(op, if (scalar_left) scalar else item, if (scalar_left) item else scalar);
        try generic_out.set(idx, result);
    }
}

fn fillBitArrayArrayResultGeneric(out: *HostBitAlloc, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView, unchecked_safe: bool) KError!void {
    if (enable_packed_bit_simd and denseBitWordSimdSupported(op) and std.meta.activeTag(left_items) == .bit and std.meta.activeTag(right_items) == .bit) {
        const left_bits = left_items.bit;
        const right_bits = right_items.bit;
        fillBitWordsBinary(out.words, op, left_bits.words, right_bits.words);
        bitClearUnusedTail(out.words, out.len);
        return;
    }

    var generic_out = HostIntResult{ .bit = out.* };
    for (0..hostIntArrayViewLen(left_items)) |idx| {
        const left = hostIntViewItem(left_items, idx);
        const right = hostIntViewItem(right_items, idx);
        const result = if (unchecked_safe)
            applyIntOpUnchecked(op, left, right)
        else
            try checkedIntOp(op, left, right);
        try generic_out.set(idx, result);
    }
}

fn fillIntScalarArrayResultGeneric(out: *HostIntResult, op: BuiltinId, scalar: i64, items: HostIntArrayView, scalar_left: bool, unchecked_safe: bool) KError!void {
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = hostIntViewItem(items, idx);
        const result = if (unchecked_safe)
            if (scalar_left) applyIntOpUnchecked(op, scalar, item) else applyIntOpUnchecked(op, item, scalar)
        else
            try checkedIntOp(op, if (scalar_left) scalar else item, if (scalar_left) item else scalar);
        try out.set(idx, result);
    }
}

fn fillIntArrayArrayResultGeneric(out: *HostIntResult, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView, unchecked_safe: bool) KError!void {
    for (0..hostIntArrayViewLen(left_items)) |idx| {
        const left = hostIntViewItem(left_items, idx);
        const right = hostIntViewItem(right_items, idx);
        const result = if (unchecked_safe)
            applyIntOpUnchecked(op, left, right)
        else
            try checkedIntOp(op, left, right);
        try out.set(idx, result);
    }
}

fn fillIntNegArrayResultGeneric(out: *HostIntResult, items: HostIntArrayView, unchecked_safe: bool) KError!void {
    for (0..hostIntArrayViewLen(items)) |idx| {
        const item = hostIntViewItem(items, idx);
        const result = if (unchecked_safe) -item else try checkedIntOp(.sub, 0, item);
        try out.set(idx, result);
    }
}

fn fillIntScalarBitArrayTo(comptime OutT: type, out: []OutT, op: BuiltinId, scalar: i64, items: HostBitSlice, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (items.len == 0) return;
    const scalar_value: OutT = if (unchecked_safe) castDenseInt(OutT, scalar) else undefined;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const item_value: OutT = @intCast(bits & 1);
            out[out_idx] = if (unchecked_safe)
                if (scalar_left) applyIntOpUncheckedTyped(OutT, op, scalar_value, item_value) else applyIntOpUncheckedTyped(OutT, op, item_value, scalar_value)
            else
                try applyIntOpCheckedNarrow(OutT, op, if (scalar_left) scalar else @as(i64, @intCast(item_value)), if (scalar_left) @as(i64, @intCast(item_value)) else scalar);
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntBitArrayArrayTo(comptime OutT: type, out: []OutT, op: BuiltinId, left_items: HostBitSlice, right_items: HostBitSlice, unchecked_safe: bool) KError!void {
    if (left_items.len == 0) return;
    var out_idx: usize = 0;
    for (left_items.words, 0..) |_, word_idx| {
        var left_bits = bitWordMasked(left_items.words, left_items.len, word_idx);
        var right_bits = bitWordMasked(right_items.words, right_items.len, word_idx);
        const active = bitWordActiveLen(left_items.len, word_idx, left_items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const left_value: OutT = @intCast(left_bits & 1);
            const right_value: OutT = @intCast(right_bits & 1);
            out[out_idx] = if (unchecked_safe)
                applyIntOpUncheckedTyped(OutT, op, left_value, right_value)
            else
                try applyIntOpCheckedNarrow(OutT, op, @as(i64, @intCast(left_value)), @as(i64, @intCast(right_value)));
            left_bits >>= 1;
            right_bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntBitArrayMixedTo(
    comptime OutT: type,
    comptime OtherT: type,
    out: []OutT,
    op: BuiltinId,
    bit_items: HostBitSlice,
    other_items: []const OtherT,
    bit_left: bool,
    unchecked_safe: bool,
) KError!void {
    if (bit_items.len == 0) return;
    var out_idx: usize = 0;
    for (bit_items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(bit_items.words, bit_items.len, word_idx);
        const active = bitWordActiveLen(bit_items.len, word_idx, bit_items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            const bit_value: OutT = @intCast(bits & 1);
            const other_value: OutT = castDenseInt(OutT, other_items[out_idx]);
            out[out_idx] = if (unchecked_safe)
                if (bit_left) applyIntOpUncheckedTyped(OutT, op, bit_value, other_value) else applyIntOpUncheckedTyped(OutT, op, other_value, bit_value)
            else
                try applyIntOpCheckedNarrow(OutT, op, if (bit_left) @as(i64, @intCast(bit_value)) else @as(i64, @intCast(other_items[out_idx])), if (bit_left) @as(i64, @intCast(other_items[out_idx])) else @as(i64, @intCast(bit_value)));
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntNegBitArrayTo(comptime OutT: type, out: []OutT, items: HostBitSlice) void {
    if (items.len == 0) return;
    var out_idx: usize = 0;
    for (items.words, 0..) |_, word_idx| {
        var bits = bitWordMasked(items.words, items.len, word_idx);
        const active = bitWordActiveLen(items.len, word_idx, items.words.len);
        var bit_idx: usize = 0;
        while (bit_idx < active) : (bit_idx += 1) {
            out[out_idx] = -@as(OutT, @intCast(bits & 1));
            bits >>= 1;
            out_idx += 1;
        }
    }
}

fn fillIntScalarArrayTo(comptime OutT: type, comptime InT: type, out: []OutT, op: BuiltinId, scalar: i64, items: []const InT, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (unchecked_safe) {
        const scalar_value: OutT = castDenseInt(OutT, scalar);
        if (enable_dense_int_simd and comptime InT == OutT) {
            if (denseIntSimdSupported(op)) {
                fillIntDenseScalarArraySameType(OutT, out, op, scalar_value, items, scalar_left);
                return;
            }
        }
        for (items, 0..) |item, idx| {
            const item_value: OutT = castDenseInt(OutT, item);
            out[idx] = if (scalar_left)
                applyIntOpUncheckedTyped(OutT, op, scalar_value, item_value)
            else
                applyIntOpUncheckedTyped(OutT, op, item_value, scalar_value);
        }
        return;
    }

    for (items, 0..) |item, idx| {
        const lhs = if (scalar_left) scalar else @as(i64, @intCast(item));
        const rhs = if (scalar_left) @as(i64, @intCast(item)) else scalar;
        out[idx] = try applyIntOpCheckedNarrow(OutT, op, lhs, rhs);
    }
}

fn fillIntArrayArrayTo(comptime OutT: type, comptime LT: type, comptime RT: type, out: []OutT, op: BuiltinId, left_items: []const LT, right_items: []const RT, unchecked_safe: bool) KError!void {
    if (unchecked_safe) {
        if (enable_dense_int_simd and comptime LT == OutT and RT == OutT) {
            if (denseIntSimdSupported(op)) {
                fillIntDenseArrayArraySameType(OutT, out, op, left_items, right_items);
                return;
            }
        }
        for (left_items, 0..) |left_item, idx| {
            out[idx] = applyIntOpUncheckedTyped(OutT, op, left_item, right_items[idx]);
        }
        return;
    }

    for (left_items, 0..) |left_item, idx| {
        out[idx] = try applyIntOpCheckedNarrow(OutT, op, left_item, right_items[idx]);
    }
}

fn fillIntNegArrayTo(comptime OutT: type, comptime InT: type, out: []OutT, items: []const InT, unchecked_safe: bool) KError!void {
    if (unchecked_safe or @bitSizeOf(OutT) > @bitSizeOf(InT)) {
        for (items, 0..) |item, idx| out[idx] = -castDenseInt(OutT, item);
        return;
    }

    for (items, 0..) |item, idx| {
        out[idx] = try negateCheckedNarrow(OutT, item);
    }
}

fn fillIntScalarDenseResult(out: *HostIntResult, op: BuiltinId, scalar: i64, items: HostIntDenseView, scalar_left: bool, unchecked_safe: bool) KError!void {
    switch (items) {
        .dense => |view| try fillIntScalarArrayResult(out, op, scalar, view, scalar_left, unchecked_safe),
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(items)) |idx| {
                const item = try hostIntDenseViewItem(items, idx);
                const lhs = if (scalar_left) scalar else item;
                const rhs = if (scalar_left) item else scalar;
                try out.set(idx, if (unchecked_safe) applyIntOpUnchecked(op, lhs, rhs) else try checkedIntOp(op, lhs, rhs));
            }
        },
    }
}

fn fillIntDenseDenseResult(out: *HostIntResult, op: BuiltinId, left_items: HostIntDenseView, right_items: HostIntDenseView, unchecked_safe: bool) KError!void {
    switch (left_items) {
        .dense => |left_view| switch (right_items) {
            .dense => |right_view| try fillIntArrayArrayResult(out, op, left_view, right_view, unchecked_safe),
            .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
                for (0..hostIntDenseViewLen(left_items)) |idx| {
                    const left_value = try hostIntDenseViewItem(left_items, idx);
                    const right_value = try hostIntDenseViewItem(right_items, idx);
                    try out.set(idx, if (unchecked_safe) applyIntOpUnchecked(op, left_value, right_value) else try checkedIntOp(op, left_value, right_value));
                }
            },
        },
        .range_iota, .flat_slice, .flat_stride, .flat_concat, .flat_segments, .first_axis_slice, .first_axis_index, .first_axis_concat, .transpose => {
            for (0..hostIntDenseViewLen(left_items)) |idx| {
                const left_value = try hostIntDenseViewItem(left_items, idx);
                const right_value = try hostIntDenseViewItem(right_items, idx);
                try out.set(idx, if (unchecked_safe) applyIntOpUnchecked(op, left_value, right_value) else try checkedIntOp(op, left_value, right_value));
            }
        },
    }
}

fn fillIntScalarArrayResult(out: *HostIntResult, op: BuiltinId, scalar: i64, items: HostIntArrayView, scalar_left: bool, unchecked_safe: bool) KError!void {
    if (std.meta.activeTag(out.*) == .bit) {
        return fillBitScalarArrayResultGeneric(&out.bit, op, scalar, items, scalar_left, unchecked_safe);
    }
    if (std.meta.activeTag(items) == .bit) {
        return switch (out.*) {
            .bit => unreachable,
            .int8 => |*dest| fillIntScalarBitArrayTo(i8, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
            .int16 => |*dest| fillIntScalarBitArrayTo(i16, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
            .int32 => |*dest| fillIntScalarBitArrayTo(i32, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
            .int64 => |*dest| fillIntScalarBitArrayTo(i64, dest.items, op, scalar, items.bit, scalar_left, unchecked_safe),
        };
    }
    switch (out.*) {
        .bit => |*dest| try fillBitScalarArrayResultGeneric(dest, op, scalar, items, scalar_left, unchecked_safe),
        .int8 => |*dest| switch (items) {
            .int8 => |slice| try fillIntScalarArrayTo(i8, i8, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int16 => |slice| try fillIntScalarArrayTo(i8, i16, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int32 => |slice| try fillIntScalarArrayTo(i8, i32, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int64 => |slice| try fillIntScalarArrayTo(i8, i64, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .bit => unreachable,
        },
        .int16 => |*dest| switch (items) {
            .int8 => |slice| try fillIntScalarArrayTo(i16, i8, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int16 => |slice| try fillIntScalarArrayTo(i16, i16, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int32 => |slice| try fillIntScalarArrayTo(i16, i32, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int64 => |slice| try fillIntScalarArrayTo(i16, i64, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .bit => unreachable,
        },
        .int32 => |*dest| switch (items) {
            .int8 => |slice| try fillIntScalarArrayTo(i32, i8, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int16 => |slice| try fillIntScalarArrayTo(i32, i16, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int32 => |slice| try fillIntScalarArrayTo(i32, i32, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int64 => |slice| try fillIntScalarArrayTo(i32, i64, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .bit => unreachable,
        },
        .int64 => |*dest| switch (items) {
            .int8 => |slice| try fillIntScalarArrayTo(i64, i8, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int16 => |slice| try fillIntScalarArrayTo(i64, i16, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int32 => |slice| try fillIntScalarArrayTo(i64, i32, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .int64 => |slice| try fillIntScalarArrayTo(i64, i64, dest.items, op, scalar, slice, scalar_left, unchecked_safe),
            .bit => unreachable,
        },
    }
}

fn fillIntArrayArrayResult(out: *HostIntResult, op: BuiltinId, left_items: HostIntArrayView, right_items: HostIntArrayView, unchecked_safe: bool) KError!void {
    if (std.meta.activeTag(out.*) == .bit) {
        return fillBitArrayArrayResultGeneric(&out.bit, op, left_items, right_items, unchecked_safe);
    }
    if (std.meta.activeTag(left_items) == .bit or std.meta.activeTag(right_items) == .bit) {
        return switch (out.*) {
            .bit => unreachable,
            .int8 => |*dest| fillIntArrayArrayResultFromBit(i8, dest.items, op, left_items, right_items, unchecked_safe),
            .int16 => |*dest| fillIntArrayArrayResultFromBit(i16, dest.items, op, left_items, right_items, unchecked_safe),
            .int32 => |*dest| fillIntArrayArrayResultFromBit(i32, dest.items, op, left_items, right_items, unchecked_safe),
            .int64 => |*dest| fillIntArrayArrayResultFromBit(i64, dest.items, op, left_items, right_items, unchecked_safe),
        };
    }
    switch (out.*) {
        .bit => |*dest| try fillBitArrayArrayResultGeneric(dest, op, left_items, right_items, unchecked_safe),
        .int8 => |*dest| switch (left_items) {
            .int8 => |left_slice| switch (right_items) {
                .int8 => |right_slice| try fillIntArrayArrayTo(i8, i8, i8, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int16 => |right_slice| try fillIntArrayArrayTo(i8, i8, i16, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int32 => |right_slice| try fillIntArrayArrayTo(i8, i8, i32, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int64 => |right_slice| try fillIntArrayArrayTo(i8, i8, i64, dest.items, op, left_slice, right_slice, unchecked_safe),
                .bit => unreachable,
            },
            .int16 => |left_slice| switch (right_items) {
                .int8 => |right_slice| try fillIntArrayArrayTo(i8, i16, i8, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int16 => |right_slice| try fillIntArrayArrayTo(i8, i16, i16, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int32 => |right_slice| try fillIntArrayArrayTo(i8, i16, i32, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int64 => |right_slice| try fillIntArrayArrayTo(i8, i16, i64, dest.items, op, left_slice, right_slice, unchecked_safe),
                .bit => unreachable,
            },
            .int32 => |left_slice| switch (right_items) {
                .int8 => |right_slice| try fillIntArrayArrayTo(i8, i32, i8, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int16 => |right_slice| try fillIntArrayArrayTo(i8, i32, i16, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int32 => |right_slice| try fillIntArrayArrayTo(i8, i32, i32, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int64 => |right_slice| try fillIntArrayArrayTo(i8, i32, i64, dest.items, op, left_slice, right_slice, unchecked_safe),
                .bit => unreachable,
            },
            .int64 => |left_slice| switch (right_items) {
                .int8 => |right_slice| try fillIntArrayArrayTo(i8, i64, i8, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int16 => |right_slice| try fillIntArrayArrayTo(i8, i64, i16, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int32 => |right_slice| try fillIntArrayArrayTo(i8, i64, i32, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int64 => |right_slice| try fillIntArrayArrayTo(i8, i64, i64, dest.items, op, left_slice, right_slice, unchecked_safe),
                .bit => unreachable,
            },
            .bit => unreachable,
        },
        .int16 => |*dest| switch (left_items) {
            .int8 => |left_slice| switch (right_items) {
                .int8 => |right_slice| try fillIntArrayArrayTo(i16, i8, i8, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int16 => |right_slice| try fillIntArrayArrayTo(i16, i8, i16, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int32 => |right_slice| try fillIntArrayArrayTo(i16, i8, i32, dest.items, op, left_slice, right_slice, unchecked_safe),
                .int64 => |right_slice| try fillIntArrayArrayTo(i16, i8, i64, dest.items, op, left_slice, right_slice, unchecked_safe),
                .bit => unreachable,
            },
            .int16 => |left_slice| switch (right_items) {
